import React, { useState, useRef, useEffect } from "react";

const ARTICLES = ["[CPN] Article premier : L’infraction que les lois punissent de peines de simple\npolice est une contravention.\nL’infraction que les lois punissent de peines correctionnelles est un délit.\nL’infraction que les lois punissent d’une peine afflictive et infamante est un\ncrime.","[CPN] Art. 2 : Toute tentative de crime qui aura été manifestée par un\ncommencement d’exécution, si elle n’a été suspendue ou si elle n’a manqué\nson effet que par suite de circonstances indépendantes de la volonté de\nson auteur, est considérée comme le crime même.\nLa tentative est punissable alors même que le but recherché ne pouvait\nêtre atteint en raison d’une circonstance de fait ignorée de l’auteur.","[CPN] Art. 3 : Les tentatives de délit ne sont considérées comme délits que dans\nles cas déterminés par une disposition spéciale de la loi.","[CPN] Art. 4 : Nulle contravention, nul délit, nul crime, ne peuvent être punis de\npeines qui n’étaient pas prononcées par la loi avant qu’ils fussent commis.\nLa loi pénale est d’interprétation stricte (Loi n° 2003-25 du 13 juin 2003).\nTITRE I : DES PEINES EN MATIERE CRIMINELLE ET\nCORRECTIONNELLE ET DE LEURS EFFETS","[CPN] Art. 5 : Les peines afflictives et infamantes sont :\n1) la mort;\n2) l’emprisonnement à vie;\n3) l’emprisonnement de dix à trente ans.","[CPN] Art. 6 : Les peines en matière correctionnelle sont :\n1) l’emprisonnement d’une durée supérieure à trente jours et inférieure à\ndix ans, sauf les cas de récidives ou autres où la loi aura déterminé d’autres\nlimites;\n\n2) l’amende;\n3) l’interdiction à temps de certains droits civiques, civils ou de famille.","[CPN] Art. 7 : La durée de toute peine privative de liberté compte du jour où le\ncondamné est détenu en vertu de la condamnation devenue irrévocable qui\nprononce la peine.\nLes jours d’emprisonnement sont des jours complets de vingt-quatre heures.\nLe mois d’emprisonnement est de trente jours.\nLa durée des peines de plusieurs mois ou années d’emprisonnement est\ncalculée date pour date.","[CPN] Art. 8 : Quand il y aura eu détention préventive, cette détention sera\nintégralement déduite de la durée de la peine qu’aura prononcée le jugement\nou l’arrêt de condamnation.","[CPN] Art. 9 : Tout détenu, condamné à une peine correctionnelle ou criminelle à\ntemps, a droit à un pécule.\nLe pécule est proportionnel au nombre de jours de travail. Il lui sera\nintégralement remis le jour de sa libération.","[CPN] Art. 10 : La condamnation aux peines établies par la loi est toujours\nprononcée sans préjudice des restitutions et dommages- intérêts qui peuvent\nêtre dus aux parties.","[CPN] Art. 11 : L’interdiction de séjour, l’amende et la confiscation spéciale, soit\ndu corps du délit, quand la propriété en appartient au condamné, soit des\nchoses produites par le délit, soit de celles qui ont servi ou qui ont été\ndestinées à le commettre, sont des peines communes aux matières criminelle\net correctionnelle.","[CPN] Art. 12 : La non inscription sur la liste électorale ou la radiation de cette\nliste ainsi que l’inéligibilité sont également des peines communes aux\nmatières criminelle et correctionnelle.\n\nCHAPITRE PREMIER : DES PEINES EN MATIERE\nCRIMINELLE","[CPN] Art. 13 : Tout condamné à mort sera fusillé.\nL’exécution ne sera pas publique. Seront seuls admis à y assister les\nfonctionnaires et magistrats désignés à cet effet, un ministre de la religion\ndu condamné ainsi que son ou ses défenseurs.","[CPN] Art. 14 : Si une femme condamnée à mort se déclare, et s’il est vérifié\nqu’elle est enceinte, elle ne subira la peine qu’après la délivrance.","[CPN] Art. 15 : Les corps des condamnés à mort exécutés seront remis à leur\nfamille, si elle les réclame, à charge par elle de les faire inhumer sans\naucun appareil.","[CPN] Art. 16 : Tout condamné à une peine criminelle d’emprisonnement sera\ninterné dans un établissement pénitentiaire.","[CPN] Art. 17 : (Loi n° 62-24 du 20 juillet 1962). Les hommes condamnés à\ndes peines criminelles seront employés aux travaux d’utilité publique les\nplus pénibles.\nLes femmes, les mineurs de moins de 18 ans et les personnes âgées de\nplus de 60 ans, ne seront employés qu’à des travaux à l’intérieur des\nétablissements pénitentiaires (Loi n° 2003- 25 du 13 juin 2003)","[CPN] Art. 18 : Les condamnés à des peines politiques criminelles seront internés\ndans un établissement pénitentiaire.\nIls seront séparés des condamnés de droit commun et non astreints à des\ntravaux de force.","[CPN] Art. 19 : La peine criminelle d’emprisonnement entraîne d’interdiction\nlégale, la dégradation civique, la publication de l’arrêt de condamnation et\nl’interdiction de séjour.","[CPN] Art. 20 : Le condamné en état d’interdiction légale sera, pendant toute la\ndurée de sa peine, privé de l’exercice de ses droits civils. Il lui sera donné\nun tuteur et un subrogé tuteur pour gérer et administrer ses biens, dans les\nformes prescrites par la loi. Ses biens lui seront remis, après qu’il aura subi\nsa peine, et le tuteur lui rendra compte de son administration.\n\nPendant toute la durée de la peine, il ne pourra lui être remis aucune somme,\naucune provision, aucune portion de ses revenus.","[CPN] Art.21 : La dégradation civique sera encourue du jour où la condamnation\nsera devenue irrévocable et, en cas de condamnation par défaut du jour de\nl’affichage de l’extrait de l’arrêt de condamnation.\nElle consiste :\n1) dans la destitution et l’exclusion des condamnés de toutes fonctions,\nemplois, ou offices publiques;\n2) dans la privation du droit de vote, d’élection, d’éligibilité et en général\nde tous droits civiques et politiques et du droit de porter aucune décoration;\n1) dans l’incapacité d’être juré- expert, d’être employé comme témoin\ndans des actes et de déposer en justice autrement que pour y donner de\nsimples renseignements;\n2) dans l’incapacité de faire partie d’aucun conseil de famille et d’être\ntuteur, curateur, subrogé tuteur ou conseil judiciaire, si ce n’est de ses\npropres enfants et sur l’avis conforme de la famille;\n3) dans la privation du droit de port d’arme, de tenir école ou d’enseigner\net d’être employé dans aucun établissement d’instruction, à titre de\nprofesseur, maître ou surveillant.","[CPN] Art. 22 : Les arrêts relatifs à la condamnation à une peine criminelle\nseront imprimés par extraits et affichés à la mairie, ou à défaut aux bureaux\nde la circonscription administrative, du lieu du crime, du lieu d’exécution de\nla sentence et de la résidence du condamné.\nLes cours d’assises pourront, en outre, ordonner que leur décision sera\naffichée en caractères très apparents dans les lieux qu’elles indiquent aux\nfrais du condamné.\nSauf disposition contraire de la loi, cet affichage, sera prononcé pour une\ndurée qui ne pourra excéder deux mois.\nLa suppression, la dissimulation et la lacération totale ou partielle des affiches\napposées conformément au présent article, opérées volontairement, seront\npunies d’une amende de 10.000 à 100.000 francs et d’un emprisonnement\n\nde un à six mois ou de l’une de ces deux peines seulement; il sera procédé\nde nouveau à l’exécution intégrale de l’affichage aux frais du condamné.","[CPN] Art. 23 : Dans tous les cas où la condamnation sera prononcée pour un\ncrime contre la sûreté de l’Etat, commis en temps de guerre, les juridictions\ncompétentes prononceront la confiscation au profit de la nation de tous les\nbiens présents et à venir du condamné de quelque nature qu’ils soient,\nmeubles, immeubles, divis ou indivis.\nL’aliénation des biens confisqués sera poursuivie par l’administration des\ndomaines dans les formes prescrites pour la vente des biens de l’Etat.\nLes biens dévolus à l’Etat par l’effet de la confiscation demeurent grevés\njusqu’à concurrence de leur valeur des dettes légitimes antérieures à la\ncondamnation.\nCHAPITRE II : DES PEINES EN MATIERE\nCORRECTIONNELLE.","[CPN] Art. 24 : Quiconque aura été condamné à une peine correctionnelle\nd’emprisonnement sera interné dans un établissement pénitentiaire. Il y\nsera employé à tous travaux.\nLes condamnés à des peines politiques correctionnelles seront séparés des\nautres condamnés.","[CPN] Art. 25 : Pour une durée de deux ans au moins et de dix ans au plus, les\ntribunaux, jugeant correctionnellement, pourront, dans les cas prévus par la\nloi, interdire en tout ou en partie l’exercice des droits civiques, civils et de\nfamille, tels qu’ils sont énumérés à l’article 21.\nIls pourront, en outre, ordonner l’affichage de leurs décisions dans les\nconditions et sous les peines prévues à l’article 22 alinéas 2, 3 et 4.\n\nCHAPITRE III : DES PEINES ET AUTRES\nCONDAMNATIONS QUI PEUVENT ETRE PRONONCEES\nPOUR CRIME ET DELIT.\nSection 1 : De l’interdiction de séjour.","[CPN] Art. 26 : L’interdiction de séjour consiste dans la défense faite à un\ncondamné de paraître dans certains lieux.\nElle comporte, en outre, des mesures de surveillance.\nSa durée est de un à dix ans en matière correctionnelle.","[CPN] Art. 27 : En matière correctionnelle, les tribunaux n’ordonneront\nl’interdiction de séjour que lorsqu’elle aura été autorisée par une disposition\nparticulière de la loi.\nSauf stipulation contraire de la loi, les tribunaux pourront ne pas la prononcer.","[CPN] Art. 28 : L’interdiction de séjour pourra être prononcée contre quiconque,\nen état de récidive légale, aura été condamné à une peine égale ou\nsupérieure à une année d’emprisonnement.","[CPN] Art. 29 : Sera soumis de plein droit pendant vingt ans à l’interdiction de\nséjour :\n1) tout condamné à une peine criminelle d’emprisonnement après qu’il\naura subi sa peine;\n(Loi n° 71-6 du 29 janvier 1971). Néanmoins l’arrêt de condamnation\npourra réduire la durée de l’interdiction ou même déclarer que le condamné\nn’y sera pas soumis. Si l’arrêt ne contient pas dispense ou réduction de\nl’interdiction, mention sera faite, à peine de nullité, qu’il en a été délibéré;\n2) tout condamné à une peine perpétuelle qui obtient commutation ou\nremise de sa peine, s’il n’en est pas autrement disposé par la décision\ngracieuse;\n3) tout condamné à une vie perpétuelle qui a prescrit sa peine.","[CPN] Art. 30 : La liste des lieux interdits est fixée par décision individuelle du\nprésident de la République ou du ministre par lui délégué.\nLes mesures de surveillance dont le condamné pourra être l’objet seront\ndéterminées par la même décision.\n\nA tout moment de la durée de l’interdiction de séjour, le président de la\nRépublique ou son délégué peut, dans les mêmes formes, modifier la liste\ndes lieux interdits et les mesures de surveillance applicables au condamné.","[CPN] Art. 31 : La décision d’interdiction peut décider qu’il sera sursis à son\nexécution. L’exécution de la décision d’interdiction peut être suspendue à\ntout moment.\nLes mesures de surveillance peuvent être maintenues soit totalement, soit\nen partie, pendant la durée du sursis ou de la suspension.\nLe sursis et la suspension sont révocables à tout moment dans les formes\nprévues pour leur octroi. Le temps pendant lequel le condamné aura\nbénéficié du sursis ou de la suspension sera compté dans la durée de\nl’interdiction de séjour, sauf disposition contraire de la décision de\nrévocation.\nEn cas d’urgence, l’autorisation provisoire de séjourner dans une localité\ninterdite peut être accordée par l’autorité administrative.","[CPN] Art. 32 : L’interdiction est notifiée au condamné qui reçoit, outre un carnet\nanthropométrique, la carte d’identité légale; les décisions prises en\napplication des articles 30 et 31 lui sont également notifiées.\nSi la notification de la décision d’interdiction a été faite au condamné avant\nsa libération définitive ou conditionnelle, l’interdiction part de la date de\ncette libération. Toutefois, en cas de révocation de la libération conditionnelle,\nl’interdiction est suspendue pendant le temps de la nouvelle incarcération.\nIl en est de même en cas de détention pour toute autre cause.\nSi la décision d’interdiction n’a pu lui être notifiée avant sa libération, le\ncondamné doit, à ce moment, faire connaître au régisseur de l’établissement\npénitentiaire où il est détenu le lieu où il a l’intention de fixer sa résidence;\nil est tenu en outre, pendant les trois mois suivant sa libération, de l’aviser\nde tout changement de résidence, et de se rendre à la convocation qui lui\nsera adressée par l’autorité administrative en vue de la notification de la\ndécision d’interdiction.\nS’il satisfait à ces obligations, l’interdiction part de la date de sa libération;\ndans le cas contraire, elle n’a effet que du jour où la notification de la\ndécision d’interdiction aura pu lui être faite.\n\nS’il n’a pas été prononcé de peine privative de liberté sans sursis, ou si\ncette peine est expirée, la notification de la décision d’interdiction est faite\nau condamné dès que le jugement ou l’arrêt portant cond","[CPN] Art. 33 : Sera puni d’un emprisonnement de trois mois à trois ans et d’une\namende de 10.000 à 100.000 francs, ou l’une de ces deux peines seulement,\ntout interdit de séjour qui, en violation de la décision qui lui a été notifiée,\nparait en un lieu qui lui a été interdit.\nSera puni des mêmes peines celui qui se soustrait aux mesures de\nsurveillance prescrites par la décision qui lui a été notifiée ou qui ne défère\npas à la convocation qui lui est adressée par l’autorité administrative, en\nvue de la notification de la décision d’interdiction, dans le cas prévu à\nl’article 32 alinéa 3.\nSection II : Des autres condamnations","[CPN] Art. 34 : Quand il y aura lieu à restitution, le coupable pourra être condamné,\nen outre, envers la partie lésée, si elle le requiert, à des indemnités dont la\ndétermination est laissée à l’appréciation de la juridiction, lorsque la loi ne\nles aura pas réglées.","[CPN] Art. 35 : L’exécution des condamnations à l’amende, aux restitutions et\naux dommages-intérêts et aux frais, pourra être poursuivie par la voie de la\ncontrainte par corps.","[CPN] Art. 36 : En cas de concurrence de l’amende avec les restitutions et les\ndommages-intérêts sur les biens insuffisants du condamné, ces dernières\ncondamnations obtiendront la préférence.","[CPN] Art. 37 : Tous les individus condamnés pour un même crime ou un même\ndélit seront tenus solidairement des amendes, des restitutions, des\ndommages-intérêts et des frais.\n\nCHAPITRE IV : DES EFFETS DES PEINES CRIMINELLES\nET CORRECTIONNELLES EN MATIERE ELECTORALE","[CPN] Art. 38 : Entraînent de plein droit la non inscription sur la liste électorale\nou la radiation de cette liste ainsi que l’inéligibilité :\n- les condamnations pour crime,\n- les condamnations à une peine d’emprisonnement, avec ou sans sursis,\nd’une durée supérieure à deux mois, assortie ou non d’une amende, pour\nvol, escroquerie, abus de confiance, délit puni des peines de vol, escroquerie\nou abus de confiance, soustraction commise par un dépositaire de deniers\npublics, faux témoignage, faux certificat, corruption et trafic d’influence ou\nattentats aux mœurs,\n- les condamnations à plus de six mois d’emprisonnement sans sursis,\nou à plus d’un an avec sursis, pour un délit autre que ceux énumérés à\nl’alinéa précédent, sous réserve des dispositions de l’article 40.","[CPN] Art. 39 : Entraînent de plein droit pendant un délai de cinq années la\nradiation de la liste électorale ou la non inscription sur cette liste, et\nl’inéligibilité, les condamnations, soit pour un délit visé à l’article 38, 3°, à une\npeine d’emprisonnement sans sursis égale ou supérieure à deux mois et\ninférieure ou égale à six mois, ou à une peine d’emprisonnement avec sursis\négale ou supérieure à deux mois et inférieure ou égale à six mois ou à une\npeine d’emprisonnement avec sursis égale ou supérieure à six mois et inférieure\nou égale à un an, soit pour un délit quelconque à une amende sans sursis\nsupérieure à deux cent mille francs sous réserve des disposition de l’article 40.\nToutefois, les tribunaux, en prononçant les condamnations visées au\nprécédent alinéa, pourront relever les condamnés de cette privation\ntemporaire du droit de vote et d’élection.\nLe délai de cinq années visé ci-dessus commencera à courir du jour où les\ncondamnations sont devenues définitives.","[CPN] Art. 40 : N’empêchent pas l’inscription sur la liste électorale et l’éligibilité :\n- les condamnations pour délit d’imprudence hors les cas de délit de fuite\nconcomitant;\n- les condamnations prononcées pour des délits dont la répression n’est\npas subordonnée à la preuve de la mauvaise foi de leurs auteurs et qui ne\nsont passibles que d’une amende.\n\nTITRE II : DE LA RESPONSABILITE ET DE LA MESURE\nDE LA PEINE\nCHAPITRE PREMIER : DE LA RESPONSABILITE\nSection 1 : Des causes de non imputabilité et des causes de justification","[CPN] Art. 41 : Nul n’est responsable pénalement que de son propre fait (Loi\nn° 2003-25 du 13 juin 2003).\nIl n’y a ni crime ni délit ni contravention lorsque le prévenu était en état de\ndémence au temps de l’action ou lorsqu’il a été contraint par une force à\nlaquelle il n’a pu résister (Loi n° 2003- 25 du 13 juin 2003).","[CPN] Art. 42 : (Loi n° 2003-25 du 13 juin 2003) N’est pas pénalement\nresponsable la personne qui accomplit un acte prescrit ou autorisé par des\ndispositions législatives ou règlementaires.\nN’est pas également pénalement responsable la personne qui accomplit un acte\nrecommandé par l’autorité légitime, sauf si cet acte est manifestement illégal.","[CPN] Art. 43 : Il n’y a pas d’infraction lorsque le fait a été commandé par la\nnécessité actuelle de la légitime défense de soi-même ou d’autrui.","[CPN] Art. 44 : Sont compris dans les cas de nécessité actuelle de défense les\ndeux cas suivants :\n1) si l’homicide a été commis, si les blessures ont été faites ou si les coups\nont été portés en repoussant, pendant la nuit, l’escalade ou l’effraction des\nclôtures, murs, ou entrée d’une maison, ou d’un appartement habité ou de\nleurs dépendances;\n2) si le fait a eu lieu en se défendant contre les auteurs de vols, ou pillages\nexécutés avec violence.\nSection II : De la minorité pénale.","[CPN] Art. 45 : Le mineur de moins de treize ans est pénalement irresponsable.","[CPN] Art. 46 : (Loi n° 62-24 du 20 juillet 1962). Lorsque le mineur aura\nmoins de 18 ans, s’il est décidé qu’il a agi sans discernement, il sera acquitté.\nMais il sera, selon les circonstances, l’objet de mesures de protection,\nd’assistance ou de rééducation.","[CPN] Art. 47 : (Loi n° 62-24 du 20 juillet 1962). S’il est décidé qu’il a agi\navec discernement, les peines seront prononcées ainsi qu’il suit :\n\n- s’il a encouru la peine de mort ou la peine criminelle d’emprisonnement à\nvie, il sera condamné à une peine de dix à trente ans ;\n- s’il a encouru une peine criminelle d’emprisonnement de dix à trente ans,\nil sera condamné à une peine de deux à moins de dix ans.\n- (Loi n° 62-24 du 20 juillet 1962). S’il a encouru une peine correctionnelle\nou de simple police, il ne sera condamné qu’à la moitié de la peine à laquelle\nil aurait pu être condamné s’il avait eu 18 ans.\nSection III : De la complicité","[CPN] Art. 48 : Les complices d’un crime ou d’un délit seront punis de la même\npeine que les auteurs mêmes de ce crime ou de ce délit, sauf le cas où la loi\nen aurait disposé autrement.","[CPN] Art. 49 : Seront punis comme complices d’une action qualifiée crime ou\ndélit ceux qui, par dons, promesses, menaces, abus d’autorité ou de pouvoir,\nmachination ou artifices coupables auront provoqué à cette action ou donné\ndes instructions pour la commettre,\n- ceux qui auront, avec connaissance, aidé ou assisté l’auteur ou les auteurs\nde l’action, dans les faits qui l’auront préparée ou facilitée, ou dans ceux\nqui l’auront consommée,\n- ceux qui auront procuré des armes, des instruments ou tout autre moyen\nqui aura servi à l’action, sachant qu’ils devaient y servir.\nCHAPITRE II : DE LA MESURE DE LA PEINE\nSection 1 : Des excuses.","[CPN] Art. 50 : Nulle infraction ne peut être excusée, ni la peine mitigée, que\ndans les cas et dans les circonstances où la loi déclare le fait excusable et\npermet de lui appliquer une peine moins rigoureuse.","[CPN] Art. 51 : Lorsque le fait d’excuse sera prouvé :\n- s’il s’agit d’un crime comportant la peine de mort ou celle de\nl’emprisonnement à vie, la peine sera réduite à un emprisonnement de\ndeux à moins de dix ans ;\n- s’il s’agit d’un crime comportant une peine d’emprisonnement à temps,\nelle sera réduite à un emprisonnement de six mois à deux ans;\n\n- s’il s’agit d’un délit, la peine sera réduite à un emprisonnement de six\njours à six mois;\n- s’il s’agit d’une contravention, l’auteur de l’infraction bénéficiera de\nl’absolution.","[CPN] Art. 52 : Lorsqu’en application de l’article 51, une peine correctionnelle\nest substituée à une peine criminelle, l’infraction devient un délit.\nLorsqu’une peine de simple police est substituée à une peine correctionnelle,\nl’infraction devient une contravention.\nSection II : Des circonstances atténuantes","[CPN] Art. 53 : Les peines prévues par la loi contre l’accusé reconnu coupable,\nen faveur de qui les circonstances atténuantes auront été déclarées, pourront\nêtre réduites, d’après l’échelle des peines fixées aux articles 5 et 6, jusqu’à\ndix ans d’emprisonnement si le crime est passible de la peine de mort,\njusqu’à cinq ans d’emprisonnement si le crime est passible d’une peine\nperpétuelle, jusqu’à deux ans d’emprisonnement dans les autres cas.\nS’il est fait application d’une peine d’emprisonnement correctionnel, une\namende pourra être prononcée, n’excédant pas 5.000.000 de francs; les\ncoupables pourront de plus être frappés de la dégradation civique pour cinq\nans au moins et dix ans au plus à compter du jour où ils auront subi leur\npeine; ils pourront en outre être frappés de l’interdiction de séjour pendant\nvingt ans au plus.","[CPN] Art. 54 : Sauf disposition expresse, lorsque le délit est puni des peines de\nl’emprisonnement et de l’amende, ou de l’une de ces deux peins seulement,\nsi les circonstances paraissent atténuantes, les tribunaux correctionnels\nsont autorisés à réduire l’emprisonnement et l’amende même à trente jours\net à 100.000 francs ou à une peine moindre.\nIls pourront aussi prononcer séparément l’une ou l’autre de ces peines, et\nmême substituer l’amende à l’emprisonnement, sans qu’en aucun cas elle\npuisse être en dessous des peines de simple police.\nDans le cas où l’amende est substituée à l’emprisonnement, si la peine de\nl’emprisonnement est seule prévue par l’article dont il est fait application,\nle maximum de cette amende sera de 500.000 francs.\n\nSection III : Du cumul d’infractions.","[CPN] Art. 55 : En cas de conviction de plusieurs crimes ou délits, la peine la plus\nforte sera seule prononcée.\nSection IV : De la récidive","[CPN] Art. 56 : Quiconque, ayant été condamné à une peine afflictive et\ninfamante, aura commis un second crime puni d’une peine\nd’emprisonnement de dix à trente ans, sera condamné à la peine de\nl’emprisonnement à vie.\nSi le second crime emporte la peine d’emprisonnement à vie, il sera\ncondamné à la peine de mort.\nToutefois, l’individu condamné par un tribunal militaire ne sera, en cas de\ncrime ou délit postérieur, passible des peines de la récidive qu’autant que la\npremière condamnation aura été prononcée pour des crimes ou délits\npunissables d’après les lois pénales ordinaires.","[CPN] Art. 57 : Quiconque, ayant été condamné à une peine d’emprisonnement\ncorrectionnel pour crime, aura, dans un délai de cinq ans, à compter du jour\noù la condamnation est devenue irrévocable, commis un délit ou un crime\npuni d’une peine d’emprisonnement à temps, sera condamné au maximum\nde la peine prévue par la loi et cette peine pourra être élevée au double.","[CPN] Art. 58 : Quiconque, ayant été condamné à une peine afflictive et infamante\naura, dans un délai de cinq ans, à compter du jour où la condamnation est\ndevenue irrévocable, commis un délit, sera condamné au maximum de la\npeine prévue par la loi et cette peine pourra être élevée au double.","[CPN] Art. 59 : (Loi n° 63-38 du 10 juillet 1963). Quiconque, ayant été\ncondamné à une ou plusieurs peines d’emprisonnement correctionnel, aura,\ndans un délai de cinq ans à compter du jour où la condamnation est devenue\nirrévocable, commis un même délit ou un délit du même genre, sera\ncondamné à une peine qui ne pourra être inférieure au double de la peine\nou de la plus forte des peines précédemment prononcées, sans toutefois\nqu’elle puisse être inférieure au minimum de la peine encourue ni supérieure\nau double du maximum de cette peine.\nLa durée de toute peine subie n’est pas comprise dans le délai de cinq\nprévus à l’alinéa précédent, ainsi qu’aux articles 57 et 58.\n\nCode pénal","[CPN] Art. 60 : Sont considérés comme délits du même genre, les délits compris\ndans chacun des groupes ci -après :\n1) délits contre la sûreté de l’Etat;\n2) délits relatifs à l’exercice des droits civiques;\n3) attentats à la liberté et abus d’autorité;\n4) soustractions et détournements de fonds, détournements et suppressions\nd’actes par les dépositaires, concussions, corruptions et trafics d’influence,\nvols, escroqueries, abus de confiance, extorsions de fonds, filouteries,\némissions de chèques sans provision, recels, banqueroutes frauduleuses,\nfraudes et falsifications;\n5) coloration et imitation des monnaies, contrefaçons, usage frauduleux\ndes sceaux, timbres et marques, faux et usage de faux;\n6) rébellion, menaces, administration de substances nuisibles, violences et\ncoups et blessures volontaires, résistance à l’exécution d’une décision de justice,\nmise en danger de la vie d’autrui (Loi n° 2003-25 du 13 juin 2003) ;\n7) vagabondage et mendicité ;\n8) toutes les infractions à la police des étrangers ;\n9) homicide et blessures involontaires;\n10) outrages aux bonnes mœurs, publications interdites ou dangereuses\npour la jeunesse, outrages publics à la pudeur, actes impudiques sur mineurs\nde même sexe, proxénétisme, excitation de mineurs à la débauche, racolage;\n11) abandon d’un enfant ou d’un incapable, abandon de famille;\n12) faux témoignage, subornation de témoins, faux serment, dénonciation\ncalomnieuse;\n13) diffamation, injures ou outrages;\n14) incendies, destructions et dégradatio","[CPN] Art. 61 : Dans les cas prévus aux articles 56, 57, 58 et 59, il ne pourra être\nfait application des dispositions relatives aux circonstances atténuantes.\nToutefois, lorsque la peine de mort sera encourue, l’emprisonnement à vie\npourra lui être substitué.\n\nLIVRE II\nDES CRIMES, DES DELITS ET DE LEUR\nPUNITION\n\nTITRE I : DE LA SURETE DE L’ETAT ET DES\nATTROUPEMENTS\nCHAPITRE PREMIER : DES CRIMES ET DELITS CONTRE\nLA SURETE DE L’ETAT.\nSection I : Des crimes de trahison et d’espionnage.","[CPN] Art. 62 : Sera coupable de trahison et puni de mort tout nigérien, tout\nmilitaire au service du Niger qui :\n1) portera les armes contre le Niger ;\n2) entretiendra des intelligences avec une puissance étrangère, en vue\nde l’engager à entreprendre des hostilités contre le Niger, ou lui en fournira\nles moyens, soit en facilitant la pénétration des forces étrangères sur le\nterritoire nigérien, soit en ébranlant la fidélité des armées, soit de toute\nautre manière ;\n3) livrera à une puissance étrangère ou à ses agents soit des troupes\nnigériennes, soit des territoires, villes, forteresses, ouvrages, postes,\nmagasins, arsenaux, matériels, munitions, vaisseaux, bâtiments ou appareils\nde navigation aérienne, appartenant au Niger ou affectés à sa défense;\n4) en vue de nuire à la défense nationale, détruira ou détériorera un\nnavire, un appareil de navigation aérienne, un matériel, une fourniture, une\nconstruction ou une installation quelconque, ou qui, dans le même but y\napportera, soit avant, soit après leur achèvement, des malfaçons de nature\nà les endommager ou à provoquer un accident.","[CPN] Art. 63 : Sera coupable de trahison et puni de mort tout nigérien, tout\nmilitaire au service du Niger qui, en temps de guerre :\n1) provoquera des militaires à passer au service d’une puissance étrangère,\nleur en facilitera les moyens ou fera des enrôlements pour une puissance\nen guerre avec le Niger;\n2) entretiendra des intelligences avec une puissance étrangère ou avec\nses agents en vue de favoriser les entreprises de cette puissance contre le\nNiger;\n\n3) aura entravé la circulation de matériel militaire;\n4) aura participé sciemment à une entreprise de démoralisation de l’armée\nou de la nation ayant pour objet de nuire à la défense nationale.","[CPN] Art. 64 : Sera coupable de trahison et puni de mort tout nigérien qui :\n1) livrera à une puissance étrangère ou à ses agents, sous quelque forme\net par quelque moyen que ce soit, un renseignement, objet, document ou\nprocédé qui doit être tenu secret dans l’intérêt de la défense nationale;\n2) s’assurera, par quelque moyen que ce soit, la possession d’un tel\nrenseignement, objet, document ou procédé en vue de les livrer à une\npuissance étrangère ou à ses agents;\n3) détruira ou laissera détruire un tel renseignement, objet, document\nou procédé en vue de favoriser une puissance étrangère.","[CPN] Art. 65 : Sera coupable d’espionnage et puni de mort tout étranger qui\ncommettra l’un des actes visés à l’article 62, 2e, à l’article 62, 4e, à l’article\n63 et à l’article 64.\nLa provocation à commettre ou l’offre de commettre un des crimes visés aux\narticles 62, 63 et 64 et au présent article sera punie comme le crime même.\nSection II : Des autres atteintes à la défense nationale.","[CPN] Art. 66 : Sera puni de l’emprisonnement à vie tout nigérien ou tout étranger\nqui, dans l’intention de les livrer à une puissance étrangère, rassemblera\ndes renseignements, objets, documents ou procédés dont la réunion et\nl’exploitation sont de nature à nuire à la défense nationale.","[CPN] Art. 67 : Sera puni d’un emprisonnement de dix à vingt ans tout gardien,\ntout dépositaire par fonction ou par qualité d’un renseignement, objet,\ndocument ou procédé qui doit être tenu secret dans l’intérêt de la défense\nnationale ou dont la connaissance pourrait conduire à la découverte d’un\nsecret de la défense nationale qui, sans intention de trahison ou d’espionnage\nl’aura :\n1) détruit, soustrait, laissé détruire ou soustraire, reproduit ou laissé\nreproduire;\n\n2) porté ou laissé porter à la connaissance d’une personne non qualifiée\nou du public.\nLa peine sera celle d’un emprisonnement de cinq à moins de dix ans si le\ngardien ou le dépositaire a agi par maladresse, imprudence, inattention,\nnégligence ou inobservation des règlements.","[CPN] Art. 68 : Sera puni d’un emprisonnement de cinq à moins de dix ans tout\nnigérien ou étranger autre que ceux visés à l’article 67 qui, sans intention\nde trahison ou d’espionnage :\n1) s’assurera, étant sans qualité, la possession d’un renseignement, objet,\ndocument ou procédé, qui doit être tenu secret dans l’intérêt de la défense\nnationale ou dont la connaissance pourrait conduire à la découverte d’un\nsecret de la défense nationale;\n2) détruira, soustraira, laissera détruire ou soustraire, reproduira ou laissera\nreproduire un tel renseignement, objet, document ou procédé;\n3) portera ou laissera porter à la connaissance d’une personne non\nqualifiée ou du public un tel renseignement, objet, document ou procédé, ou\nen aura étendu la divulgation.","[CPN] Art. 69 : Sera puni d’un emprisonnement de dix à vingt ans tout nigérien\nou étranger qui, sans autorisation préalable de l’autorité compétente, livrera\nou communiquera à une personne agissant pour le compte d’une puissance\nétrangère ou d’une entreprise étrangère soit une invention intéressant la\ndéfense nationale, soit des renseignements, études, ou procédés de\nfabrication se rapportant à une invention de ce genre ou à une application\nindustrielle intéressant la défense nationale.","[CPN] Art. 70 : Sera puni d’un emprisonnement de un à cinq ans tout nigérien ou\nétranger qui, sans intention de trahison ou d’espionnage, aura porté à la\nconnaissance d’une personne non qualifiée ou du public une information\nmilitaire non rendue publique par l’autorité compétente et dont la divulgation\nest manifestement de nature à nuire à la défense nationale.","[CPN] Art. 71 : Sera puni d’un emprisonnement de dix à vingt ans tout nigérien\nou étranger qui :\n\n1) s’introduira sous un déguisement ou un faux nom, en dissimulant sa\nqualité ou sa nationalité, dans une forteresse, un ouvrage, poste ou arsenal,\ndans les travaux, camps, bivouacs ou cantonnements d’une armée, dans\nun bâtiment de commerce employé pour la défense nationale, dans un\nappareil de navigation aérienne ou dans un véhicule militaire armé, dans un\nétablissement militaire de toute nature, ou dans un établissement ou chantier\nintéressant la défense nationale;\n2) même sans se déguiser ou sans dissimuler son nom, sa qualité ou sa\nnationalité, aura organisé d’une manière occulte un moyen quelconque de\ncorrespondance ou de transmission à distance de nature à nuire à la défense\nnationale ;\n3) survolera le territoire nigérien au moyen d’un aéronef étranger sans\nêtre autorisé par une convention diplomatique ou une permission de l’autorité\nnigérienne;\n4) dans une zone d’interdiction fixée par l’autorité militaire, exécutera,\nsans l’autorisation de celle-ci, des dessins, photographies, levés ou opérations\nphotographiques à l’intérieur ou autour des places, ouvrages, postes, ou\nétablissements militaires ou intéressant la défense nationale;\n5) séjournera, au mépris d’une interdiction édictée par décret, dans un\nrayon déterminé autour des ouvrages fortifiés ou des établissements\nmilitaires;\n6) communiquera à une personne non qualifiée ou rendra publics des\nrenseignements relatifs soit aux ","[CPN] Art. 72 : Sera puni d’un emprisonnement de dix à vingt ans quiconque :\n1) aura, par des actes hostiles non approuvés par le Gouvernement,\nexposé le Niger à une déclaration de guerre ;\n\n2) aura, par des actes hostiles non approuvés par le Gouvernement,\nexposé des nigériens à subir des représailles ;\n3) entretiendra, avec des agents d’une puissance étrangère, des\nintelligences de nature à nuire à la situation militaire ou diplomatique du\nNiger ou à ses intérêts économiques essentiels.","[CPN] Art. 73 : Sera puni d’un emprisonnement de dix à vingt ans quiconque, en\ntemps de guerre :\n1) entretiendra, sans autorisation du Gouvernement, une correspondance\nou des relations avec les sujets ou les agents d’une puissance ennemie;\n2) fera, directement ou par intermédiaire, des actes de commerce avec\nles sujets ou les agents d’une puissance ennemie, au mépris des prohibitions\nédictées.","[CPN] Art. 74 : Sera puni d’un emprisonnement de un à cinq ans et d’une amende\nde 50.000 à 1.000.000 de francs quiconque, en temps de guerre, accomplira\nsciemment un acte de nature à nuire à la défense nationale, non prévu et\nréprimé par un autre texte.","[CPN] Art. 75 : Sera puni d’un emprisonnement de cinq à moins de dix ans\nquiconque, en temps de paix, en vue de nuire à la défense nationale, aura\nentravé la circulation de matériel militaire ou aura, par quelque moyen que\nce soit, provoqué, facilité ou organisé une action violente ou concertée\nayant ces entraves pour but ou pour résultat.","[CPN] Art. 76 : Sera puni d’un emprisonnement de cinq à moins de dix ans\nquiconque, en temps de paix, aura participé en connaissance de cause à\nune entreprise de démoralisation de l’armée ayant pour objet de nuire à la\ndéfense nationale.","[CPN] Art. 77 : Sera puni d’un emprisonnement de un à cinq ans et d’une amende\nde 50.000 à 1.000.000 de francs quiconque, sans autorisation du\nGouvernement, en temps de paix, enrôlera des soldats pour le compte d’une\npuissance étrangère.\n\nSection III : Des attentats, complots et autres infractions contre\nl’autorité de l’Etat et l’intégrité du territoire national.","[CPN] Art. 78 : L’attentat dont le but aura été soit de détruire ou de changer le\nrégime constitutionnel, soit d’exciter les citoyens ou habitants à s’armer\ncontre l’autorité de l’Etat ou à s’armer les uns contre les autres, soit à\nporter atteinte à l’intégrité du territoire national sera puni de\nl’emprisonnement à vie.\nL’exécution ou la tentative constitueront seules l’attentat.","[CPN] Art. 79 : Le complot ayant pour but les crimes mentionnés à l’article 78,\ns’il a été suivi d’un acte commis ou commencé pour en préparer l’exécution,\nsera puni d’un emprisonnement de dix à vingt ans.\nSi le complot n’a pas été suivi d’un acte commis ou commencé pour en\npréparer l’exécution, la peine sera celle d’un emprisonnement de cinq à\nmoins de dix ans.\nIl y a complot dès que la résolution d’agir est concertée et arrêtée entre\ndeux ou plusieurs personnes.\nS’il y a proposition faite et non agréée de former un complot pour arriver\naux crimes mentionnés à l’article 78, celui qui aura fait une telle proposition\nsera puni d’un emprisonnement de un à moins de dix ans et d’une amende\nde 50.000 à 2.000.000 de francs. Le coupable pourra de plus être interdit,\nen tout ou partie, des droits visés à l’article 21.","[CPN] Art. 80 : Quiconque, hors les cas prévus aux articles 78 et 79, aura entrepris\npar quelque moyen que ce soit de porter atteinte à l’intégrité du territoire\nnational, sera puni d’un emprisonnement de un à moins de dix ans et d’une\namende de 50. 000 à 2. 000. 000 de francs. Il pourra en outre être privé de\ntout ou partie des droits visés à l’article 21.","[CPN] Art. 81 : Ceux qui auront levé ou fait lever des troupes armées, engagé ou\nenrôler des soldats ou leur auront fourni des armes ou munitions, sans ordre\nou autorisation du pouvoir légitime, seront punis de l’emprisonnement à vie.","[CPN] Art. 82 : Ceux qui, sans droit ou motif légitime, auront pris un\ncommandement militaire quelconque,\nCeux qui, contre l’ordre du Gouvernement, auront retenu un tel\ncommandement,\n\nLes commandants qui auront tenu leur armée ou troupe rassemblée, après\nque le licenciement ou la séparation en auront été ordonnés, seront punis\nde l’emprisonnement à vie.","[CPN] Art. 83 : Lorsqu’une des infractions prévues aux articles 78, 80, 81 et 82\naura été exécutées ou simplement tentées avec usage d’armes, la peine\nsera la mort.","[CPN] Art. 84 : Toute personne qui, pouvant disposer de la force publique en\naura requis ou ordonné, fait requérir ou ordonner l’action ou l’emploi pour\nempêcher l’exécution des lois sur le recrutement militaire ou sur la\nmobilisation, sera puni d’un emprisonnement de dix à vingt ans.\nSi cette réquisition ou cet ordre ont été suivis de leur effet, le coupable sera\npuni de l’emprisonnement à vie.\nSection IV : Des crimes tendant à troubler l’Etat par le massacre ou\nla dévastation","[CPN] Art. 85 : Ceux qui auront commis un attentat dont le but aura été de porter\nle massacre ou la dévastation dans une ou plusieurs localités seront punis\nde mort.\nL’exécution ou la tentative constitueront seules l’attentat.","[CPN] Art. 86 : Le complot ayant pour but le crime prévu à l’article 85, s’il a été\nsuivi d’un acte commis ou commencé pour en préparer l’exécution, sera\npuni de l’emprisonnement à vie.\nSi le complot n’a pas été suivi d’un acte commis ou commencé pour en\npréparer l’exécution, la peine sera celle d’un emprisonnement de dix à\nvingt ans.\nIl y a complot dès que la résolution d’agir est concertée et arrêtée entre\ndeux ou plusieurs personnes.\nS’il y a eu proposition faite et non agréée de former un complot pour arriver\naux crimes mentionnés à l’article 85, celui qui aura fait une telle proposition\nsera puni d’un emprisonnement de cinq à moins de dix ans.","[CPN] Art. 87 : Sera puni de mort quiconque, en vue de troubler l’Etat par l’un\ndes crimes prévus aux articles 78 et 85 ou par l’envahissement, le pillage\n\nou le partage des propriétés publiques ou privées ou encore en faisant\nattaque ou résistance envers la force publique agissant contre les auteurs\nde ces crimes, se sera mis à la tête des bandes armées ou y aura exercé\nune fonction ou un commandement quelconque.\nLa même peine sera appliquée à ceux qui auront dirigé l’association, levé\nou fait lever, organisé ou fait organiser des bandes ou leurs auront,\nsciemment et volontairement, fourni ou procuré des subsides, des armes,\nmunitions et instruments de crime ou envoyé des subsistances ou qui auront,\nde toute autre manière, pratiqué des intelligences avec les directeurs ou\ncommandants des bandes.","[CPN] Art. 88 : Les individus faisant partie de bandes, sans y exercer aucun\ncommandement ni emploi, seront punis d’un emprisonnement de dix à vingt ans.\nSection V : Des crimes commis par la participation à un mouvement\ninsurrectionnel","[CPN] Art. 89 : Seront punis d’un emprisonnement de dix à vingt ans les individus\nqui, dans un mouvement insurrectionnel :\n1) auront fait ou aidé à faire des barricades, des retranchements ou tous\nautres travaux ayant pour objet d’entraver ou d’arrêter l’exercice de la\nforce publique;\n2) auront empêché, à l’aide de violences ou de menaces, la convocation\nou la réunion de la force publique, ou qui auront provoqué ou facilité le\nrassemblement des insurgés, soit par la distribution d’ordres ou de\nproclamations, soit par le port de drapeaux ou autres signes de ralliement,\nsoit par tout autre moyen d’appel;\n3) auront, pour faire attaque ou résistance envers la force publique, envahi\nou occupé des édifices, postes et autres établissements publics, des maisons\nhabitées ou non habitées. La peine sera la même à l’égard du propriétaire\nou du locataire qui, connaissant le but des insurgés, leur aura procuré sans\ncontrainte l’entrée desdites maisons.","[CPN] Art. 90 : Seront punis d’un emprisonnement de dix à vingt ans, les individus\nqui, dans un mouvement insurrectionnel :\n\n1) se seront emparés d’armes, munitions ou matériels de toutes espèces,\nsoit à l’aide de violences ou de menaces, soit par le pillage de boutiques ou\nde postes, magasins, arsenaux ou autres établissements publics, soit par le\ndésarmement des agents de la force publique;\n2) auront porté soit des armes apparentes ou cachées ou de munitions,\nsoit un uniforme ou costume ou autres insignes civils ou militaires.\nSi les individus, porteurs d’armes apparentes ou cachées ou de munitions,\nétaient revêtus d’un uniforme, d’un costume ou d’autres insignes civils ou\nmilitaires, ils seront punis de l’emprisonnement à vie.\nLes individus qui auront fait usage de leurs armes seront punis de mort.","[CPN] Art. 91 : Seront punis de mort ceux qui auront dirigé ou organisé un\nmouvement insurrectionnel ou qui lui auront sciemment et volontairement\nfourni ou procuré des armes, munitions et instruments de crime, ou envoyé\ndes subsistances ou qui auront, de toute manière, pratiqué des intelligences\navec les directeurs ou commandants de ce mouvement.\nSection VI : Dispositions diverses","[CPN] Art. 92 : Sous réserve des obligations résultant du secret professionnel,\nsera punie, en temps de guerre, d’un emprisonnement de dix à vingt ans au\nplus et, en temps de paix d’un emprisonnement de un à cinq ans et d’une\namende de 50.000 à 1.500.000 francs, toute personne qui, ayant\nconnaissance de projets ou d’actes de trahison, d’espionnage ou d’autres\nactivités de nature à nuire à la défense nationale, n’en fera pas la déclaration\naux autorités militaires, administratives ou judiciaires, dès le moment où\nelle les aura connus.\nOutre les personnes désignées à l’article 49, sera puni comme complice\nquiconque, autre que l’auteur ou le complice :\n1) fournira sans contrainte et en connaissance de leurs intentions, subsides,\nmoyens d’existence, logement, lieu de retraite ou de réunion aux auteurs\nde crimes et délits contre la sûreté de l’Etat;\n2) portera sciemment la correspondance des auteurs de tels crimes ou tels\ndélits, ou leur félicitera sciemment, de quelque manière que ce soit, la recherche,\nle recel, le transport, ou la transmission de l’objet du crime ou du délit.\n\nOutre le cas prévu à l’article 354, sera puni comme receleur quiconque,\nautre que l’auteur ou le complice :\n1) recèlera sciemment les objets ou instruments ayant servi ou devant\nservir à commettre le crime ou le délit ou les objets, matériels ou documents,\nobtenus par le crime ou le délit;\n2) détruira, soustraira, recèlera, dissimulera ou altérera sciemment un\ndocument public ou privé de nature à faciliter la r","[CPN] Art. 93 : Sera exempt de la peine encourue celui qui, avant toute exécution\nou tentative d’un crime ou d’un délit contre la sûreté de l’Etat, en donnera\nle premier connaissance aux autorités administratives ou judiciaires.\nSi la dénonciation intervient après la consommation ou la tentative du crime\nou délit mais avant l’ouverture des poursuites :\n- la peine de l’emprisonnement criminel à temps sera substituée à la peine\nde mort;\n- la peine de l’emprisonnement correctionnel sera substituée à celle de\nl’emprisonnement criminel;\n- la peine de l’emprisonnement de simple police sera substituée à celle de\nl’emprisonnement correctionnel.\nSauf pour les crimes particuliers qu’ils auraient personnellement commis, il\nne sera prononcé aucune peine contre ceux qui, ayant fait partie d’une\nbande armée sans y exercer aucun commandement et sans y remplir aucun\nemploi ni fonctions, se seront retirés au premier avertissement des autorités\nciviles ou militaires ou se seront rendus à ces autorités.\nCeux qui seront exempts de peine par application du présent article pourront\nnéanmoins être interdits de séjour comme en matière correctionnelle et\nprivés de tout ou partie des droits énumérés à l’article 21.\n\nCode pénal","[CPN] Art. 94 : La rétribution reçue par le coupable, ou le montant de sa valeur,\nlorsque la rétribution n’a pu être saisie, sera déclarée acquise au trésor par\nle jugement.\nLa confiscation de l’objet du crime ou du délit et des objets et instruments\nayant servi à le commettre sera prononcée.\nSont compris dans le mot armes, toutes machines, tous instruments ou\nustensiles tranchants, perçants ou contondants.\nLes couteaux et ciseaux de poche, les cannes simples et tous autres objets\nquelconques ne seront réputés armes qu’autant qu’il en aura été fait usage\npour tuer, blesser ou frapper.","[CPN] Art. 95 : La tentative d’un délit contre la sûreté de l’Etat sera punie comme\nle délit lui-même.\nEn matière correctionnelle, l’interdiction de séjour pourra être prononcée\ndans tous les cas prévus au présent chapitre.","[CPN] Art. 96 : Le Président de la République pourra, par décret pris en Conseil\ndes ministres, étendre soit pour le temps de guerre, soit pour le temps de\npaix, tout ou partie des dispositions relatives aux crimes ou délits commis\ncontre la sûreté de l’Etat aux actes concernant celles-ci qui seraient commis\ncontre les puissances alliées ou amies du Niger.\nCHAPITRE II : DES ATTROUPEMENTS","[CPN] Art. 97 : Est interdit sur la voie publique ou dans un lieu public :\n1) Tout attroupement armé;\n2) Tout attroupement non armé qui pourrait troubler la tranquillité publique.\nL’attroupement est armé si l’un des individus qui le composent est porteur\nd’une arme apparente, ou si plusieurs d’entre eux sont porteurs d’armes\ncachées ou d’objets quelconques, apparents ou cachés, ayant servi d’armes\nou apportés en vue de servir d’armes.\nLes représentants de la force publique appelés en vue de dissiper un\nattroupement ou pour assurer l’exécution de la loi, d’un jugement ou mandat\nde justice, peuvent faire usage de la force si des violences ou voies de fait\n\nsont exercées contre eux, ou s’ils ne peuvent défendre autrement le terrain\nqu’ils occupent ou les postes dont la garde leur est confiée.\nDans les autres cas, l’attroupement est dissipé par la force après que le\nchef de la circonscription administrative, le maire ou l’un de ses adjoints,\nun commissaire de police ou tout autre officier de police judiciaire porteur\ndes insignes de sa fonction :\n1) aura annoncé sa présence par un signal sonore ou lumineux de nature\nà avertir efficacement les individus constituant l’attroupement;\n2) aura sommé les personnes participants à l’attroupement de se disperser,\nà l’aide d’un haut-parleur ou en utilisant un signal sonore ou lumineux de\nnature également à avertir efficacement les individus constituant\nl’attroupement;\n3) aura procédé de la même manière à une seconde sommation si la\npremière est r","[CPN] Art. 98 : Sera puni d’un emprisonnement de deux mois à un an toute\npersonne non armée qui, faisant partie d’un attroupement armé ou non\narmé, ne l’aura pas abandonné après la première sommation.\nL’emprisonnement sera de six mois à trois ans si la personne non armée a\ncontinué à faire volontairement partie d’un attroupement armé ne s’étant\ndispersé que devant l’usage de la force.\nLes personnes condamnées par application du présent article peuvent être\nprivées de tout ou partie des droits mentionnés à l’article 21.","[CPN] Art. 99 : Sans préjudice, le cas échéant, de peines plus fortes, sera puni\nd’un emprisonnement de six mois à trois ans quiconque, dans un\nattroupement, au cours d’une manifestation ou à l’occasion d’une réunion,\naura été trouvé porteur d’une arme apparente ou cachée ou d’objets\nquelconques apparents ou cachés ayant servi d’armes ou apportés en vue\nde servir d’armes.\nVoir décret n° 66-70/PRN du 20 avril 1966, déterminant les modalités d’application de\nl’article 97 du Code pénal (JO n° 9 du 1er mai 1966)\n\nL’emprisonnement sera de un à cinq ans dans le cas d’attroupement dissipé\npar la force.\nLes personnes condamnées en application du présent article peuvent être\ninterdites de séjour et privées, en tout ou partie, des droits mentionnés à\nl’article 21.\nL’interdiction du territoire national pourra être prononcée contre tout\nétranger s’étant rendu coupable de l’un des délits prévus au présent article.","[CPN] Art. 100 : Toute provocation directe à un attroupement non armé soit par\ndiscours proférés publiquement, soit par écrits ou imprimés affichés ou\ndistribués sera puni d’un emprisonnement de trois mois à un an, si elle a été\nsuivie d’effet et, dans le cas contraire, d’un emprisonnement de deux à six\nmois et d’une amende de 50.000 à 300.000 francs, ou de l’une de ces deux\npeines seulement.\nToute provocation directe par les mêmes moyens à un attroupement armé\nest punie d’un emprisonnement de un à cinq ans, si elle a été suivie d’effet\net, dans le cas contraire, d’un emprisonnement de trois mois à un an et\nd’une amende de 50.000 à 300.000 francs, ou de l’une de ces deux peines\nseulement.","[CPN] Art. 101 : L’exercice de poursuites pour délits d’attroupement ne fait pas\nobstacle à la poursuite pour crime ou délits particuliers qui auraient été\ncommis au milieu des attroupements.\nLa procédure de flagrant délit est applicable aux délits prévus et punis par\nle présent chapitre commis sur les lieux mêmes de l’attroupement.\nToute personne qui aura continué à faire partie d’un attroupement après la\ndeuxième sommation faite par un représentant de l’autorité publique pourra\nêtre condamnée à la réparation pécuniaire des dommages causés par cet\nattroupement.\n\nTITRE II : CRIMES ET DELITS CONTRE LA\nCONSTITUTION ET LA PAIX PUBLIQUE\nCHAPITRE I : DES CRIMES ET DELITS DE CARACTERE\nRACIAL, REGIONALISTE OU RELIGIEUX.","[CPN] Art. 102 : Tout acte de discrimination raciale ou ethnique, de même que\ntoute propagande régionaliste, toute manifestation contraire à la liberté de\nconscience et à la liberté de culte, susceptible de dresser les uns contre les\nautres, les citoyens, sera punie de un à cinq ans d’emprisonnement et de\nl’interdiction de séjour.\nLorsque l’acte de discrimination raciale ou ethnique, la propagande\nrégionaliste ou la manifestation contraire à la liberté de conscience ou de\nculte aura eu pour but ou pour effet l’un des crimes ou délits attentatoires\nà la sécurité de l’Etat ou à l’intégrité du territoire de la République, son\nauteur ou son instigateur sera poursuivi comme coauteur ou comme complice\nsuivant le cas.\nCHAPITRE II : DES CRIMES ET DELITS RELATIFS A\nL’EXERCICE DES DROITS CIVIQUES.","[CPN] Art. 103 : Lorsque par attroupement, voies de fait ou menaces, un ou plusieurs\ncitoyens auront été empêchés d’exercer leurs droits civiques, chacun des\ncoupables sera puni d’un emprisonnement de six mois à deux ans et privé de\nses droits civiques pendant cinq ans au moins et dix ans au plus.","[CPN] Art. 104 : Si ce délit a été commis par suite d’un plan concerté pour être\nexécuté soit dans toute la République, soit dans une ou plusieurs\ncirconscriptions ou localités, la peine sera de cinq à moins de dix ans\nd’emprisonnement.\nL’interdiction de séjour sera prononcée.","[CPN] Art. 105 : Tout citoyen membre d’un bureau de vote, tout scrutateur qui,\nau cours des opérations, aura falsifié ou tenté de falsifier, soustrait ou tenté\nde soustraire, ajouté ou tenté d’ajouter des bulletins, inscrit ou tenté d’inscrire\nsur les bulletins des votants illettrés des noms autres que ceux qui leur\nauraient été déclarés, induit ou tenté d’induire en erreur sur la signification\ndes couleurs des bulletins, sera puni de un à deux ans d’emprisonnement et\n\nde l’interdiction du droit de voter et d’être éligible pendant cinq ans au\nmoins et dix ans au plus.","[CPN] Art. 106 : Toutes autres personnes coupables des faits énoncés dans\nl’article précédent seront punies d’un emprisonnement de deux à six mois\net de l’interdiction du droit de voter et d’être éligibles pendant cinq ans au\nmoins et dix ans au plus.","[CPN] Art. 107 : Tout citoyen qui aura, pendant les élections, acheté ou vendu un\nsuffrage de quelque façon que ce soit et quel que soit le prix, sera puni de trois\nmois à un an d’emprisonnement, et privé de ses droits civiques et de toutes\nfonctions ou emplois publics pendant cinq ans au moins et dix ans au plus.\nLe vendeur et l’acheteur du suffrage seront en outre condamnés chacun à\nune amende double de la valeur des choses reçues ou promises.\nCHAPITRE III : CRIMES ET DELITS COMMIS PAR LES\nFONCTIONNAIRES.\nSection 1 : Attentats à la liberté","[CPN] Art. 108 : Tout fonctionnaire public, agent ou préposé de l’administration\nqui aura ordonné ou fait quelque acte arbitraire ou attentatoire soit à la\nliberté individuelle, soit aux droits civiques d’un ou plusieurs citoyens, soit à\nla Constitution, sera puni d’un emprisonnement de un à cinq ans et pourra\nen outre, conformément aux dispositions de l’article 25, être privé de tout\nou partie des droits énoncés à l’article 21.\nSi néanmoins, il justifie avoir agi par ordre de ses supérieurs pour des objets\ndu ressort de ceux-ci, sur lesquels il leur était dû obéissance hiérarchique,\nil sera exempt de la peine, laquelle dans ce cas sera appliquée seulement\naux supérieurs qui auront donné l’ordre.\nDans tous les cas, lorsque l’ordre est manifestement illégal les dispositions\nde l’article 42 alinéa 2 s’appliquent (Loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 109 : Les dommages intérêts, qui pourraient être prononcés à raison\ndes attentats exprimés dans l’article 108 ci-dessus, seront demandés soit\nsur la poursuite pénale, soit par voie civile, et seront réglés, eu égard aux\npersonnes, aux circonstances et au préjudice souffert.\n\nCode pénal","[CPN] Art. 110 : Les régisseurs de prison qui auront reçu un prisonnier sans\nmandat ou jugement ou, quand il s’agira d’une expulsion ou d’une extradition\nsans ordre provisoire du Gouvernement, ceux qui l’auront retenu ou refusé\nde le représenter à l’officier de police ou au porteur de ses ordres, sans\njustifier de la défense du procureur de la République ou du juge, ceux qui\nauront refusé d’exhiber leurs registres à l’officier de police seront, comme\ncoupables de détention arbitraire, punis de six mois à deux ans\nd’emprisonnement et d’une amende de 10.000 à 150.000 francs ou de\nl’une de ces deux peines seulement.","[CPN] Art. 111 : Seront punis d’un emprisonnement de cinq à moins de dix ans\ntous procureurs généraux ou de la République, tous substituts, tous juges,\ntous officiers de police judiciaire qui auront provoqué, donné ou signé un\njugement, une ordonnance ou un mandat tendant à la poursuite personnelle\nou accusation soit d’un ministre, soit d’un membre de l’Assemblée nationale,\nsans les formalités ou les autorisations prescrites par la loi; ou qui, s’agissant\nde ces derniers, n’auront pas suspendu la détention ou la poursuite à la\nrequête de l’Assemblée nationale ou qui, en dehors des cas de flagrants\ndélits auront, sans les mêmes formalités et autorisations, donné ou signé\nl’ordre ou le mandat de saisir ou arrêter un ou plusieurs membres de\nl’Assemblée.\nLes coupables pourront, en outre, conformément aux dispositions de l’article\n25, être privés de tout ou partie des droits mentionnés à l’article 21.","[CPN] Art. 112 : Seront punis d’un emprisonnement de un à cinq ans les procureurs\ngénéraux ou de la République, les substituts, les juges ou les officiers de\npolice judiciaire qui auront retenu ou fait retenir sans titre régulier de détention\nun individu hors des lieux déterminés par le Gouvernement ou\nl’administration publique (Loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 113 : Les fonctionnaires publics chargés de la police administrative\nou judiciaire, qui auront refusé ou négligé de déférer à une réclamation\nlégale tendant à constater les détentions illégales et arbitraires, soit dans\nles lieux destinés à la garde des détenus, soit partout ailleurs, et qui ne\njustifieront pas les avoir dénoncés à l’autorité supérieure, seront punis d’un\nemprisonnement de six mois à deux ans.\n\nSection II : Des abus d’autorité contre les particuliers","[CPN] Art. 114 : Tout fonctionnaire de l’ordre administratif ou judiciaire, tout\nagent de la force publique qui, agissant en sa dite qualité, se sera introduit\ndans le domicile d’un citoyen, contre le gré de celui-ci, hors les cas prévus\npar la loi et sans les formalités qu’elle a prescrites, sera puni d’un\nemprisonnement de trois mois à deux ans, et d’une amende de 10. 000 à\n100. 000 francs, ou de l’une de ces deux peines seulement.","[CPN] Art. 115 : Tout juge ou tribunal, tout administrateur ou autorité administrative\nqui, sous quelque prétexte que ce soit, même du silence ou de l’obscurité\nde la loi, aura dénié de rendre la justice qu’il doit aux parties, après avoir\nété requis et qui aura persévéré dans son déni, après avertissement ou\ninjonction de ses supérieurs, pourra être poursuivi, et sera puni d’une amende\nde 10. 000 à 100. 000 francs et de l’interdiction de l’exercice des fonctions\npubliques depuis cinq ans jusqu’à vingt ans.","[CPN] Art. 116 : Toute suppression, tout retard volontaire dans la transmission\nou la distribution, toute ouverture de lettre confiée à l’administration des\npostes et télécommunications, commis ou facilités par un fonctionnaire ou\npréposé du Gouvernement ou de l’administration des postes et\ntélécommunications, seront punis d’un emprisonnement de trois mois à cinq\nans et d’une amende de 10. 000 à 100. 000 francs.\nLe coupable pourra en outre, conformément aux dispositions de l’article\n25, être privé de tout ou partie des droits mentionnés à l’article 21.\nEn dehors des cas prévus au paragraphe 1erdu présent article, toute\nsuppression, toute ouverture de correspondance adressée à des tiers, faite\nde mauvaise foi, sera punie d’un emprisonnement de six jours à un an et\nd’une amende de 5. 000 à 100. 000 francs, ou de l’une de ces deux peines\nseulement, sans préjudice des peines du vol si les éléments constitutifs de\nce délit sont relevés.\nSection III : Coalition de fonctionnaires","[CPN] Art. 117 : Tous dépositaires de quelque partie de l’autorité publique qui,\nsoit par réunion d’individus ou de corps, soit par délégation ou\ncorrespondance entre eux, auront concerté des mesures contraires à la\nConstitution et aux lois, seront punis d’un emprisonnement de six mois à\n\ntrois ans et d’une amende de 50. 000 à 200. 000 francs ou de l’une de ces\ndeux peines seulement.\nIls pourront, en outre, en application de l’article 25, être privés de tout ou\npartie des droits mentionnés à l’article 21.","[CPN] Art. 118 : Si, par l’un des moyens exprimés ci-dessus, il a été concerté\ndes mesures contre l’exécution des lois ou des ordres du Gouvernement, la\npeine sera de deux à cinq ans d’emprisonnement.\nSi ce concert a eu lieu entre les autorités civiles et les corps militaires ou de\nsécurité ou leurs chefs, ceux qui en seront les auteurs ou provocateurs\nseront punis d’un emprisonnement de dix à trente ans.\nLes autres coupables seront punis de cinq à moins de dix ans\nd’emprisonnement et de l’interdiction de séjour.\nDans les cas visés par les alinéas 1 et 3 du présent article, l’interdiction des\ndroits civiques et de tout emploi public pendant dix ans au plus sera en\noutre prononcée.","[CPN] Art. 119 : (Loi n° 63-3 du 1er février 1963).Les fonctionnaires publics\nqui, dans le dessein de s’opposer aux lois ou à l’action Gouvernementale,\nauront par délibération, arrêté de donner des démissions individuellement\nou collectivement, dont l’objet ou l’effet serait d’empêcher ou de suspendre\nsoit l’administration de la justice, soit l’accomplissement d’un service public\nquelconque, seront punis d’un emprisonnement de deux à cinq ans et d’une\namende de 50.000 à 200. 000 francs.\nL’abandon de poste par tout fonctionnaire public, dont le but ou l’effet aura\nété d’empêcher ou de suspendre l’accomplissement de son service, sera\npuni d’un emprisonnement de un à trois ans et d’une amende de 20.000 à\n100.000 francs.\nLes peines prévues à l’alinéa 1 seront appliquées si après abandon de\nposte, le fonctionnaire public quitte ou tente de quitter le territoire national.\nLes coupables, en outre pourront être privés de tout ou partie des droits\nmentionnés à l’article 21.\n\nCode pénal","[CPN] Art. 120 : Les dispositions qui précèdent n’ont rien de commun avec le\nfait, pour les fonctionnaires, d’user du droit de grève et de la liberté de se\ngrouper au sein d’organisations de coopération ou d’organisations syndicales\nde leur choix pour la défense de leurs intérêts professionnels.\nSection IV : Soustractions commises par les dépositaires publics.\nArt. 121(nouveau) : (Loi n° 2016-22 du 16 juin 2016) Le détournement\nde biens publics est la soustraction, la dissipation ou tout autre usage illicite,\npar un agent public, à son profit ou au profit d’une autre personne ou d’une\nentité, de tous biens, de tous fonds ou valeurs publiques ou privés ou de\ntoute autre chose de valeur qui lui ont été remis en raison de ses fonctions.\nEst considéré détournement de biens publics, la soustraction, la dissipation\nou tout autre usage illicite par toute personne, à son profit ou au profit\nd’une autre personne ou entité, de tous biens, de tous fonds ou valeurs\npubliques ou privés ou de toute autre chose de valeur qui lui ont été remis.\nSont considérés comme biens publics, les biens appartenant :\n- à l’Etat et aux autres collectivités territoriales ;\n- aux établissements publics à caractère administratif ;\n- aux entreprises publiques à caractère industriel et commercial ;\n- aux établissements publics à caractère social ;\n- aux établissements publics à caractère scientifique, culturel et technique ;\n- aux sociétés et entreprises dans lesquelles l’Etat ou d’autres collectivités\npubliques dét","[CPN] Art. 122 : Sera puni des mêmes peines tout fonctionnaire ou officier public,\ntout commis à une perception, dépositaire ou comptable public, qui aura\ndétruit, supprimé ou détourné les actes ou titres juridiques dont il était\ndépositaire en cette qualité, ou qui lui auront été remis ou communiqués en\nraison de ses fonctions.\nArt. 123(nouveau) : (Loi n° 2016-22 du 16 juin 2016) Le bénéfice des\ndispositions relatives aux circonstances atténuantes pourra être accordé si,\navant jugement et après expertise, le prévenu restitue ou rembourse la\nmoitié au moins de la valeur estimative en argent des biens détournés,\ndissipés ou soustraits.\nLe bénéfice de la loi sur le sursis pourra être accordé si, avant jugement, le\nprévenu restitue la totalité de la valeur estimative en argent des biens\ndétournés, dissipés ou soustraits.\nSous réserve des dispositions de l’article 121 (nouveau) ci-dessus, les peines\nprévues contre l’accusé reconnu coupable, en faveur de qui les circonstances\natténuantes auront été déclarées, peuvent être réduites jusqu’à cinq (5) ans\nd’emprisonnement si le crime est passible d’une peine d’emprisonnement à\nvie et jusqu’à deux (2) ans d’emprisonnement dans les autres cas.\n\nSection V : Concussion","[CPN] Art. 124 : Tous fonctionnaires ou officiers publics, tous percepteurs de\ndroits, contributions ou deniers publics, leurs commis ou préposés, qui auront\nreçu, exigé ou ordonné de percevoir pour droits, taxes contributions ou\ndeniers, ou pour salaires et traitements, ce qu’ils savaient n’être pas dû ou\nexcéder ce qui était dû, seront punis, savoir :\n- les fonctionnaires ou officier publics, les percepteurs de droits, contributions\nou deniers publics, d’un emprisonnement de six mois à moins de dix ans et\nd’une amende de 50.000 à 1.000.000 de francs;\n- leurs commis ou préposés, d’un emprisonnement de trois mois à cinq ans\net d’une amende de 10.000 à 500.000 francs.\nToutefois, les fonctionnaires ou officiers publics, les percepteurs de droits,\ncontributions ou deniers publics, leurs commis ou préposés qui se seront\nrendus coupables du délit de concussion, mais n’auront pas poursuivi un\nintérêt pécuniaire, n’encourront que la peine d’amende prévue aux\nprécédents alinéas.","[CPN] Art. 125 : Les dispositions qui précèdent sont applicables aux greffiers et\nofficiers ministériels lorsque le fait a été commis à l’occasion des recettes\ndont ils sont chargés par la loi.","[CPN] Art. 126 : Seront punis d’un emprisonnement de trois mois à moins de\ncinq ans et d’une amende de 50. 000 à 1000.000 de francs les détenteurs\nde l’autorité publique qui, sous une forme quelconque et pour quelque motif\nque ce soit, auront sans autorisation de la loi accordé des exonérations ou\nfranchises de droits, impôts et taxes, ou auront effectué gratuitement la\ndélivrance de produits des établissements de l’Etat.","[CPN] Art. 127 : Ceux qui auront bénéficié sciemment d’un délit de concussion\nseront punis comme complices.","[CPN] Art. 128 : Dans tous les cas prévus à la présente section :\n- la tentative de délit sera punie comme le délit lui-même;\n- il ne pourra être fait application des dispositions relatives aux circonstances\natténuantes et au sursis;\n- les coupables pourront, en outre être privés de tout ou partie des droits\nmentionnés à l’article 21.\n\nSection VI : Ingérence des fonctionnaires","[CPN] Art. 129 : Tout fonctionnaire, tout officier public, tout agent d’une administration\npublique qui, soit ouvertement, soit par des actes simulés, soit par interposition\nde personnes, aura pris ou reçu quelque intérêt que ce soit dans les actes,\nadjudications, entreprises ou régies, dont il a ou avait, au temps de l’acte, en\ntout ou partie, l’administration ou la surveillance, sera puni d’un emprisonnement\nde six mois au moins et de deux ans au plus et d’une amende de 100.000 à\n1.000.000 de francs ou de l’une de ces deux peines seulement.\nLa présente disposition est applicable à tout fonctionnaire ou agent ou préposé\nd’une administration publique qui aura pris un intérêt quelconque dans une\naffaire dont il était chargé d’ordonner le paiement ou de faire la liquidation.\nTout fonctionnaire public, tout agent ou préposé de l’administration publique,\nchargé à raison même de sa fonction :\n1) de la surveillance ou du contrôle d’une entreprise privée;\n2) de la passation, au nom de l’Etat, de marchés ou contrats de toute nature\navec une entreprise privée;\n3) de l’expression d’avis sur les marchés ou contrats de toute nature passés\navec une entreprise privée, et qui, pendant un délai de cinq ans à compter\nde la cessation de la fonction, prendra ou recevra une participation par\ntravail, conseils ou capitaux (sauf par dévolution héréditaire en ce qui\nconcerne les capitaux) :\n- soit dans une quelconque des entreprises visées ci -dessus ;\n- soit dans toute entreprise possédant avec l’une de","[CPN] Art. 130.1 : Corruption d’agents étrangers et de fonctionnaires\nd’organisations internationales publiques.\n(Loi n° 2017-10 du 31 mars 2017)\nEst puni d’une peine d’emprisonnement de deux (2) à moins de dix (10) ans et\nd’une amende de cinquante mille(50 000)à un million (1 000 000) de francs :\n- quiconque intentionnellement promet, offre ou accorde à un agent public\nétranger ou à un fonctionnaire d’une organisation internationale publique,\ndirectement ou indirectement, un avantage indu, pour lui-même ou pour\nune autre personne ou entité, afin qu’il accomplisse ou s’abstienne\nd’accomplir ou parce qu’il a accompli ou s’est abstenu d’accomplir un\nacte dans l’exercice de ses fonctions officielles, en vue d’obtenir ou de\nconserver un marché ou un autre avantage indu en liaison avec des activités\nde commerce international ;\n- tout agent public étranger ou fonctionnaire d’une organisation internationale\npublique, qui sollicite ou accepte directement ou indirectement, un avantage\nindu, pour lui-même ou pour une autre personne ou entité, afín d’accomplir\n\nou de s’abstenir d’accomplir ou parce qu’il a accompli ou s’est abstenu\nd’accomplir un acte dans l’exercice de ses fonctions officielles.","[CPN] Art. 130.2 : Corruption dans le secteur privé\n(Loin° 2017-10 du 31 mars 2017)\nEst puni d’une peine d’emprisonnement de deux (2)à moins de dix (10) ans\net d’une amende de cent mille (100 000) à un million (1 000 000) de francs :\n- quiconque promet, offre ou accorde, directement ou indirectement, un\navantage indu à toute personne qui dirige une entité du secteur privé ou\ntravaille pour une telle entité, en quelque qualité que ce soit, pour lui-même\nou pour une autre personne, afin que, en violation de ses devoirs, elle\naccomplisse ou s’abstienne d’accomplir un acte ;\n- tout dirigeant ou travailleur d’une entité du secteur privé qui sollicite,\naccepte, directement ou indirectement, un avantage indu, pour lui-même\nou pour une autre personne, afin d’accomplir ou s’abstenir d’accomplir un\nacteen violation de ses devoirs.","[CPN] Art. 130.3 : Soustraction de biens dans le secteur privé\n(Loi n° 2017-10 du 31 mars 2017)\nEst puni d’un emprisonnement de un (1) à trois (3) ans et d’une amende de\ncent mille (100 000) à un million (1 000 000) de francs, tout dirigeant ou\ntravailleur d’une entité du secteur privé en quelque qualité que ce soit qui\ndétourne, soustrait ou dissipe, tente de détourner, de soustraire ou de dissiper,\ndes biens, fonds ou valeurs privés ou toute autre chose de valeur qui lui ont\nété remis en raison de ses fonctions.\nCette peine est portée de dix (10) à vingt (20) ans et l’amende de cinq cent\nmille (500 000) à cinq millions (5 000 000) de francs si la somme détournée\nou la valeur estimative des effets ou biens dissipés est égale ou supérieure\nà cinquante millions (50 000.000) de francs.","[CPN] Art. 130.4 : Enrichissement illicite\n(Loi n° 2017-10 du 31 mars 2017)\nLe délit d’enrichissement illicite est constitué dès lors qu’une personne\npossède un patrimoine et/ou mène un train de vie qu’elle ne peut\nraisonnablement justifier par rapport à ses revenus légitimes.\n\nLa personne reconnue coupable du délit d’enrichissement illicite est punie\nd’une peine d’emprisonnement de trois (3) à moins de dix (10) ans et une\namende d’un montant au moins égal à celui dont le coupable s’est illicitement\nenrichi et, au plus, égal au double de cette somme.","[CPN] Art. 130.5 : Blanchiment du produit du crime (Loi n° 2017-10 du 31\nmars 2017)\nEst puni d’une peine d’emprisonnementde trois (3) à sept (7) ans et d’une\namende égale au triple de la valeur des biens ou des fonds sur lesquels ont\nporté les opérations de blanchiment quiconque, intentionnellement procède :\n- à la conversion ou au transfert des biens dont il sait qu’ils sont le produit\nde l’infraction dans le but de dissimuler ou de déguiser l’origine illicite desdits\nbiens ou d’aider toute personne qui est impliquée dans la commission de\nl’infraction principale à échapper aux conséquences juridiques de ses actes ;\n- à la dissimulation ou au déguisement de la nature véritable de l’origine, de\nl’emplacement, de la disposition, du mouvement ou de la propriété de biens\nou de droits y relatifs dont il sait qu’ils sont le produit de l’infraction ;\n- à l’acquisition, à la détention ou à l’utilisation des biens dont il sait au\nmoment où il les acquiert, les détient ou les utilise, qu’ils sont le produit de\nl’infraction.\nEst puni de la même peine quiconque participe à l’une des infractions prévues\nà l’alinéa précédent ou à toute association, entente, tentative ou complicité\npar fourniture d’une assistance, d’une aide ou de conseils en vue de sa\ncommission.","[CPN] Art. 130.6 : Recel des biens et produits provenant de la corruption et\ndes infractions assimilées (Loi n° 2017-10 du 31 mars 2017)\nEst puni d’une peine d’emprisonnement de deux (2) à moins de dix (10)\nans, et d’une amende de cent mille (100 000) à un million (1 000 000) de\nfrancs quiconque dissimule ou retient de façon continue des biens en sachant\nque lesdits biens proviennent de l’une quelconque des infractions établies\nconformément à la présente loi.\n\nCode pénal","[CPN] Art. 130.7 : Abus de fonctions (Loi n° 2017-10 du 31 mars 2017)\nEst puni d’un emprisonnement de deux (2) à moins de dix (10) ans et d’une\namende de cent mille (100.000) à un million (1.000.000) de francs, tout\nagent public qui aura intentionnellement abusé de ses fonctions ou de son\nposte, en accomplissant ou en s’abstenant d’accomplir, dans l’exercice de\nses fonctions, un acte en violation des lois afin d’obtenir un avantage indu\npour lui-même ou pour une autre personne ou entité.","[CPN] Art. 130.8 : Entrave au bon fonctionnement de la justice\n(Loi n° 2017-10 du 31 mars 2017)\nEst puni d’une peine d’emprisonnement de deux (2) à cinq (5) ans et d’une\namende de cinquante mille (50 000) à cinq cent mille (500 000) francs,\nquiconque :\n- fait recours à la force physique, à des menaces ou intimidations, ou promet\nd’offrir ou d’accorder un avantage indu pour obtenir un faux témoignage\nou empêcher un témoignage ou la présentation d’éléments de preuve dans\nune procédure en rapport avec la commission d’infractions établies\nconformément à la présente loi ;\n- fait recours à la force physique, à des menaces ou intimidations pour\nempêcher un agent de la justice ou un agent de service de détection et de\nrépression d’exercer les devoirs de sa charge en rapport avec la commission\nd’infractions établies conformément à la présente loi.","[CPN] Art. 130.9 : Responsabilité des personnes morales\n(Loi n° 2017-10 du 31 mars 2017)\nLes personnes morales, autres que l’Etat sont punies d’amende de cinq\ncent mille (500 000) à cinq cent millions (500 000 000) de francs sans\npréjudice des réparations civiles, lorsqu’une infraction prévue par la présente\nloi a été commise par une personne responsable de leur direction ou de leur\ncontrôle agissant en cette qualité.\nLes personnes morales peuvent en outre être condamnées :\n- à l’interdiction à titre définitif ou pour une durée de cinq (5) ans au plus,\nd’exercer directement ou indirectement certaines activités professionnelles ;\n\n- à la fermeture définitive ou pour une durée de cinq (5) ans au plus, de\nleurs établissements ayant servi à commettre l’infraction ;\n- à la dissolution, lorsqu’elles ont été créées pour commettre les faits\nincriminés ;\n- à l’exclusion des marchés publics à titre définitif ou pour une durée de\ncinq (5) ans au plus ;\n- à la confiscation de tous les biens qui sont l’objet ou le produit direct ou\nindirect de l’infraction ;\n- au placement pour une durée de cinq (5) ans au plus, sous surveillance\njudiciaire ;\n- à la publication et diffusion de la décision par tout moyen approprié aux\nfrais des condamnés.\nLa responsabilité des personnes morales n’exclut pas celle des personnes\nphysiques auteures ou complices des mêmes faits.","[CPN] Art. 131 : Sera puni d’un emprisonnement d’un à cinq ans et d’une amende\nde 50.000 à 1.000.000 de francs, toute personne qui aurait sollicité ou agréé\ndes offres ou promesses, sollicité ou reçu des dons ou présents, pour faire\nobtenir ou tenter de faire obtenir des décorations, médailles, distinctions ou\nrécompenses, des places, fonctions ou emplois ou des faveurs quelconques\naccordées par l’autorité publique, des marchés, entreprises ou autres\nbénéfices résultant de traités conclus avec l’autorité publique ou, de façon\ngénérale, une décision favorable d’une telle autorité ou administration, et\naura ainsi abusé d’une influence réelle ou supposée.\nToutefois, lorsque le coupable est une des personnes visées au paragraphe\n1er du premier alinéa de l’article 130 et qu’il a abusé de l’influence réelle ou\nsupposée que lui donne son mandat ou sa qualité, la peine de\nl’emprisonnement sera de deux à moins de dix ans.\nArt. 132 (nouveau) : Trafic d’influence\n(Loi n° 2017-10 du 31 mars 2017)\nConstituent des faits de trafic d’influence assimilés à la corruption et punis\nd’un emprisonnement de deux (2) à moins de dix (10) ans et d’une amende\nde cinquante mille (50.000) à un million (1.000.000) de francs :\n\n- le fait de promettre, d’offrir ou d’accorder à un agent public ou à toute\nautre personne, directement ou indirectement, un avantage indu afin que\nledit agent ou ladite personne abuse de son influence réelle ou supposée en\nvue d’obtenir d’une administration ou d’une autorité publique, un","[CPN] Art. 133 : Dans tous les cas prévus à la présente section, lorsque le coupable\nsera une des personnes prévues aux alinéas 1°, 2° et 3° de l’article 130,\nelle sera privée de tout ou partie des droits énoncés à l’article 21.\nSection VIII : Exercice illégal de l’autorité publique","[CPN] Art. 134 : Tout fonctionnaire ou officier public, agent ou préposé d’une\nadministration publique, révoqué, destitué, suspendu, ou interdit légalement\nqui, après en avoir eu la connaissance officielle, aura continué l’exercice\nde ses fonctions ou qui, investi de fonctions électives ou temporaires, les\naura exercées après avoir été remplacé ou lorsque ses fonctions auront\npris fin, sera puni d’un emprisonnement de six mois à deux ans et d’une\namende de 10.000 à 100. 000 francs ou d’une de ces deux peines seulement.\nIl pourra, en outre, conformément à l’article 25, être privé de l’exercice de\ntout ou partie des droits visés à l’article 21.\nSection VIII bis : Atteintes à la liberté d’accès et à l’égalité des\ncandidats devant les marchés publics et les délégations de service\npublic (Loi n° 2003-25 du 13 juin 2003).\nArt. 134-1 : Est puni d’un emprisonnement de deux à moins de 10 ans et\nd’une amende de 100.000 à 10.000.000 de francs, le fait par une personne\ndépositaire de l’autorité publique ou chargée d’une mission de service public,\nou investie d’un mandat électif public, ou exerçant les fonctions de\nreprésentant, administrateur ou agent de l’Etat, des collectivités territoriales,\ndes établissement publics, des sociétés d’économie mixte ou par toute\npersonne agissant pour le compte de l’une de celles susmentionnées, de\n\nprocurer ou de tenter de procurer à autrui un avantage injustifié par un\nacte contraire aux dispositions législatives ou règlementaires.\nCeux qui auront bénéficié","[CPN] Art. 134.2 : Non dénonciation des infractions\n(Loi n° 2017-10 du 31 mars 2017)\nEst punie d’une peine d’emprisonnement de deux (2) à cinq (5) ans et\nd’une amende de cinquante mille (50 000) à cinq cent mille (500 000)\nfrancs, toute personne qui, de par sa fonction ou profession, permanente\nou provisoire, a connaissance d’une ou de plusieurs infractions prévues par\nla présente section et n’en informe pas les autorités publiques compétentes.","[CPN] Art. 134.3 : Circonstances aggravantes\n(Loi n° 2017-10 du 31 mars 2017)\nSi l’auteur d’une ou de plusieurs infractions prévues par la présente section\nest un magistrat ou un arbitre, un agent des douanes, du fisc ou du trésor,\nun fonctionnaire exerçant une fonction supérieure de l’Etat, un membre de\nl’autorité nationale en charge de la lutte contre la corruption et les infractions\nassimilées, des inspecteurs d’Etat, des finances, des inspecteurs des\nservices, un officier ou un agent de police judiciaire, un officier public ou\nun greffier, la peine est de cinq (5) à dix (10) ans d’emprisonnement et une\namende égale au double de celle prévue pour l’infraction commise.","[CPN] Art. 134.4 : Exemption et atténuation des peines\n(Loi n° 2017-10 du 31 mars 2017)\nBénéficie d’une exemption de poursuite, toute personne auteure ou complice\nd’une ou de plusieurs infractions prévues par la présente section, qui, avant\ntoute poursuite, révèle une information aux autorités administratives\ncompétentes ou judiciaires et permet ainsi d’identifier les personnes mises\nen cause.\n\nBénéficie de la moitié de la peine prévue voire du sursis, toute personne\nauteure ou complice d’une ou de plusieurs infractions prévues par la présente\nsection, qui, après toute poursuite, facilite l’arrestation d’une ou de plusieurs\npersonnes mises en cause.","[CPN] Art. 134.5 : Peines complémentaires (Loi n° 2017-10 du 31 mars 2017)\nEn cas de condamnation pour une ou plusieurs infractions prévues par la\nprésente section, la juridiction peut prononcer une ou plusieurs des peines\nsuivantes :\n- l’interdiction d’exercer des droits civiques pour une durée de dix (10) ans ;\n- l’interdiction d’exercer toute fonction publique pour une durée de dix (10)\nans ;\n- l’interdiction d’obtenir toute distinction ou décoration décernée par l’Etat\nou ses démembrements.","[CPN] Art. 134.6 : Tentative et complicité (Loi n° 2017-10 du 31 mars 2017)\nLes dispositions du code pénal relatives à la tentative et à la complicité\nsont applicables aux infractions prévues à la présente section.\nCHAPITRE IV : DU FAUX\nSection I : Fausse monnaie","[CPN] Art. 135 : Quiconque aura contrefait ou altéré soit des monnaies métalliques\nayant cours légal au Niger, soit des effets émis par le Trésor public avec\nson timbre ou sa marque, soit des billets de banque autorisés par la loi ou\ndes billets de même nature émis par le Trésor, ou participé à l’émission,\nl’exposition ou l’introduction sur le territoire nigérien de ces monnaies, effets\net billets contrefaits ou altérés, sera puni d’un emprisonnement de cinq à\nmoins de dix ans et d’une amende de 100.000 à 10.000.000 de francs.","[CPN] Art. 136 : Sera puni d’un emprisonnement de six mois à trois ans et d’une\namende de 40.000 à 4.000.000 de francs quiconque aura coloré les monnaies\nmétalliques ayant cours légal au Niger, dans le but de tromper sur la nature\ndu métal ou les aura émises ou introduites sur le territoire nigérien ou aura\nparticipé à leur émission ou à leur introduction.\n\nCode pénal","[CPN] Art. 137 : Les opérations prévues aux articles précédents, même perpétrées\nà l’étranger, seront punies suivant les mêmes distinctions s’il s’agit de\nmonnaies, billets ou effets étrangers.\nToutefois, ceux qui, à l’étranger, se sont rendus coupables comme auteurs\nou complices de tels délits, ne pourront être poursuivis au Niger que dans\nles conditions prévues au code de procédure pénale.","[CPN] Art. 138 : La participation énoncée aux précédents articles ne s’applique\npoint à ceux qui, ayant reçu pour bonnes des pièces de monnaies contrefaites,\naltérées ou colorées, les ont remises en circulation.\nToutefois, celui qui aura fait usage desdites pièces, après en avoir vérifié\nou fait vérifier les vices, sera puni d’une amende triple au moins et sextuple\nau plus de la somme représentée par les pièces qu’il aura rendues à la\ncirculation, sans que cette amende puisse, en aucun cas, être inférieure à\n50.000 francs.","[CPN] Art. 139 : La soustraction, l’émission ou la mise en circulation de moyens\nde paiement ayant pour objet de suppléer ou de remplacer les signes\nmonétaires ayant cours légal, sera punie d’un emprisonnement de un à\ncinq ans et d’une amende de 200.000 francs à 20.000.000 de francs ou de\nl’une de ces deux peines seulement.\nLes moyens de paiement souscrits, émis ou mis en circulation contrairement\naux prohibitions du présent article, seront saisis par les agents habilités à\nconstater les infractions. Leur confiscation devra être prononcée par le\ntribunal.","[CPN] Art. 140 : Seront punis d’une amende de 50.000 à 500.000 francs ceux\nqui, sans y avoir été préalablement autorisés par l’autorité publique,\nemploient ou détiennent des appareils ou instruments susceptibles d’être\nutilisés pour la fabrication des monnaies métalliques, d’effets émis par le\nTrésor ou de billets de banque, ainsi que ceux qui en ont livré à des personnes\nnon pourvues d’une autorisation.\nSection II : Contrefaçon des sceaux de l’Etat, timbres et marques","[CPN] Art. 141 : Ceux qui auront contrefait le sceau de l’Etat ou fait usage du\nsceau contrefait, seront punis d’un emprisonnement de cinq à moins de dix\nans et d’une amende de 100.000 à 10.000.000 de francs.\n\nCode pénal","[CPN] Art. 142 : Ceux qui auront contrefait, ou falsifié, soit un ou plusieurs timbres\nnationaux, soit les marteaux de l’Etat servant aux marques forestières, soit\nle poinçon ou des poinçons servant à marquer les matières d’or ou d’argent,\nou qui auront fait usage des papiers, effets, timbres, marteaux ou poinçons\nfalsifiés ou contrefaits, seront punis d’un emprisonnement de deux à six\nans et d’une amende de 80.000 à 8.000.000 de francs.","[CPN] Art. 143 : Sera puni d’un emprisonnement de un à cinq ans et d’une\namende de 50.000 à 5.000.000 de francs quiconque s’étant indûment procuré\nles vrais timbres, marteaux ou poinçons ayant l’une des destinations\nexprimées en l’article 142, en aura fait une application ou usage préjudiciable\naux droits ou intérêts de l’Etat.","[CPN] Art. 144 : Seront punis d’un emprisonnement de six mois à trois ans et\nd’une amende de 40.000 à 4.000.000 de francs :\n1) Ceux qui auront contrefait les marques destinés à être apposées au\nnom du Gouvernement sur les diverses espèces de denrées ou de\nmarchandises ou qui auront fait usage de ces fausses marques ;\n2) Ceux qui auront contrefait le sceau, le timbre ou marque d’une autorité\nquelconque, ou qui auront fait usage de sceaux, timbres ou marques\ncontrefaits;\n3) Ceux qui auront contrefait les papiers à l’entête ou imprimés officiels\nen usage dans les assemblées instituées par la Constitution, les\nadministrations publiques ou les différentes juridictions, qui les auront vendus,\ncolportés ou distribués, ou qui auront fait usage des papiers ou imprimés\nainsi contrefaits ;\n4) Ceux qui auront contrefait ou falsifié les timbres-poste, empreintes\nd’affranchissement ou coupons-réponsesémis par l’administrationnigérienne\ndes postes et les timbres mobiles, qui auront vendu, colporté, distribué ou\nutilisé sciemment lesdits timbres, empreintes ou coupons-réponses\ncontrefaits ou falsifiés.","[CPN] Art. 145 : Quiconque s’étant indûment procuré de vrais sceaux, marques,\ntimbres ou imprimés prévus à l’article précédent, en aura fait ou tenté d’en\nfaire une application ou un usage frauduleux, sera puni d’un emprisonnement\nde trois mois à deux ans et d’une amende de 30.000 à 3.000.000 de francs.\n\nCode pénal","[CPN] Art. 146 : Seront punis d’un emprisonnement de dix jours à six mois et\nd’une amende de 10.000 à 300.000 francs :\n1) Ceux qui auront fabriqué, vendu, ou distribué, tous objets, imprimés ou\nformules, obtenus par un procédé quelconque qui, par leur forme extérieure,\nprésenteraient avec les pièces de monnaie ou de billets de banque ayant\ncours légal au Niger ou à l’étranger, avec les titres de rente, vignettes et\ntimbres de service des postes et télécommunications ou des régies de l’Etat,\nactions, obligations, parts d’intérêt, coupons de dividende y afférents et\ngénéralement avec les valeurs fiduciaires émises par l’Etat, les\nétablissements publics, ainsi que par des sociétés, compagnies ou entreprises\nprivées, une ressemblance de nature à faciliter l’acceptation desdits objets,\nimprimés ou formules aux lieu et place des valeurs imitées ;\n2) Ceux qui auront fabriqué, vendu, colporté, distribué ou utilisé des\nimprimés qui, par leur format, leur couleur, leur texte, leur disposition\ntypographique ou tout autre caractère, présenteraient, avec les papiers à\nentête ou imprimés officiels en usage dans les assemblées instituées par la\nConstitution, les administrations publiques et les différentes juridictions, une\nressemblance de nature à causer une méprise dans l’esprit du public;\n3) Ceux qui auront sciemment fait usage de timbres-poste ou de timbres\nmobiles ayant déjà été utilisés, ainsi que ceux qui auront, par tous les moyens,\naltéré des timbres dans le but de les soustraire à l’obl","[CPN] Art. 147 : Les personnes coupables des délits prévus aux deux précédentes\nsections, hormis ceux énoncés à l’article 146, seront exemptes de peine si,\navant la consommation de ces délits et avant toutes poursuites, elles ont\ndonné connaissance et révélé les auteurs aux autorités constituées ou si,\nmême après les poursuites commencées, elles ont procuré l’arrestation\ndes autres coupables.","[CPN] Art. 148 : Hors les cas prévus à l’article 146, les coupables pourront être,\nconformément à l’article 25, privés de tout ou partie des droits énumérés à\nl’article 21.\nIls pourront, en outre, être interdits de séjour.","[CPN] Art. 149 : Dans tous les cas de contrefaçon, d’altération ou de coloration,\nle corps du délit sera confisqué et détruit.","[CPN] Art. 150 : La tentative sera toujours punie comme le délit lui-même.","[CPN] Art. 151 : Il ne pourra être fait application des dispositions relatives au\nsursis et aux circonstances atténuantes dans les cas prévus aux articles\n135, 136, 137, 141 et 142.\nSection IV : Faux en écriture","[CPN] Art. 152 : Le faux en écriture est l’altération frauduleuse de la vérité de\nnature à causer un préjudice et commise dans un écrit destiné ou apte à la\npreuve d’un droit ou d’un fait ayant des effets de droit.","[CPN] Art. 153 : Sera puni d’un emprisonnement de cinq à moins de dix ans et\nd’une amende de 20.000 à 1.000.000 de francs tout fonctionnaire ou officier\npublic, tout agent ou préposé d’une administration publique qui, dans\nl’exercice de ses fonctions, aura commis un faux :\n\n- soit par falsification matérielle résultant de fausses signatures, contrefaçon\nou altération d’écriture ou de signature, fabrication d’acte ou convention\nformant titre, addition, suppression ou modification apportées après la\nconfection des actes ou écrits dans les déclarations ou faits contenus auxdits\nactes ou écrits, et qu’ils avaient pour objet de recevoir ou de constater;\n- par fabrication ou dénaturation de la substance ou des circonstances\ndes actes ou écrits, effectuée au moment de leur rédaction, et réalisée en\ny portant des déclarations ou conventions autres que celles faites ou dictées\npar les parties, ou en y altérant par des mentions fausses ou des omissions\nvolontaires les faits que l’acte ou l’écrit avait pour objet de constater ou en\ny constatant comme vrais des faits faux, ou comme avoués des faits qui ne\nl’étaient pas.","[CPN] Art. 154 : Seront punies d’un emprisonnement de un an à huit ans et\nd’une amende de 10.000 à 500.000 francs, toutes autres personnes qui\nauront commis un faux en écriture publique ou authentique.","[CPN] Art. 155 : Sera punie d’un emprisonnement de six mois à trois ans et d’une\namende de 10.000 à 100.000 francs toute personne qui, par des déclarations\nmensongères faites devant un fonctionnaire ou officier public ou un agent ou\npréposé d’une administration publique, aura provoqué l’insertion, dans un\nacte public ou authentique, d’énonciations contraires à la vérité.","[CPN] Art. 156 : Sera puni d’un emprisonnement de six mois à cinq ans quiconque\naura, de l’une des manières exprimées à l’article 153, commis un faux en\nécriture de commerce ou de banque ou en écriture privée.","[CPN] Art. 157 : Celui qui a fait sciemment usage d’une pièce fausse sera puni\nde la même peine que s’il avait commis le faux.","[CPN] Art. 158 : Sera puni d’un emprisonnement de six mois à trois ans et d’une\namende de 50.000 à 500.000 francs quiconque aura fait frauduleusement\nusage d’une pièce dont tout ou partie des mentions sont devenus incomplètes\nou inexactes.","[CPN] Art. 159 : Les fonctionnaires, officiers publics, agents ou préposés d’une\nadministration, reconnus coupables de faux et d’usage de faux dans\nl’exercice de leurs fonctions ne pourront bénéficier des dispositions relatives\naux circonstances atténuantes et aux sursis.\n\nCode pénal","[CPN] Art. 160 : La tentative du délit de faux sera punie comme le délit consommé.","[CPN] Art. 161 : Dans tous les cas prévus à la présente section, le tribunal pourra\npriver les coupables de tout ou partie des droits énumérés à l’article 21.\nCHAPITRE V : CRIMES ET DELITS CONTRE LES\nCITOYENS CHARGES D’UN SERVICE PUBLIC\nSection I : Rébellion","[CPN] Art. 162 : Toute attaque, toute résistance avec violence ou voies de fait\nenvers les fonctionnaires ou agents chargés de l’exécution des ordres de\nl’autorité publique, agissant dans l’exercice ou à l’occasion de l’exercice\nde leurs fonctions, est qualifiée de rébellion.","[CPN] Art. 163 : Si la rébellion a été commise par une ou deux personnes sans\narmes ostensibles, elle sera punie d’un emprisonnement de trois mois à deux\nans et d’une amende de 10. 000 à 100. 000 francs; si elle a été commise\navec armes ostensibles, l’emprisonnement sera de six mois à trois ans.","[CPN] Art. 164 : Si la rébellion a été commise par plus de deux personnes sans\narmes ostensibles, elle sera punie d’un emprisonnement de un à cinq ans et\nd’une amende de 10.000 à 100.000 francs; si elle a été commise avec\narmes ostensibles, l’emprisonnement sera de deux à moins de dix ans.","[CPN] Art. 165 : En cas de rébellion en bande ou attroupement, il ne sera prononcé\naucune peine contre les rebelles sans fonction ni emploi dans la bande qui se\nseront retirés au premier avertissement de l’autorité publique ou même qui, depuis,\nont été saisis hors du lieu de la rébellion sans nouvelle résistance et sans armes.\nToutefois, et sous réserve des autres crimes ou délits qu’ils auront pu\ncommettre au cours de la réunion, ils pourront être interdits de séjour.","[CPN] Art. 166 : Ceux qui, faisant partie d’une réunion non réputée armée, se\ntrouveraient munis d’armes cachées, seront individuellement punis comme\ns’ils avaient fait partie d’une troupe ou réunion armée.\nEst réputée armée toute rébellion commise en réunion dont deux au moins\ndes participants sont porteurs d’armes ostensibles. Sont considérées comme\narmes, outre les armes à feu, tous objets tranchants, perçants ou\ncontondants.\n\nCode pénal","[CPN] Art. 167 : La peine appliquée pour rébellion à des prisonniers, prévenus,\naccusés ou condamnés, sera subie dans les conditions suivantes :\n- ceux qui sont condamnés à une peine non capitale ni perpétuelle,\nimmédiatement après l’expiration de leur peine;\n- pour les autres, immédiatement après l’arrêt ou le jugement définitif ou\nl’acte qui met fin à leur détention.","[CPN] Art. 168 : L’interdiction de séjour pourra être prononcée contre toute\npersonne condamnée pour rébellion.\nSection II : Les outrages","[CPN] Art. 169 : L’outrage par paroles, gestes, menaces, écrits ou dessins non\nrendus publics ou encore par envoi d’objets quelconques visant un\nfonctionnaire ou officier public ou citoyen chargé d’un ministère de service\npublic, dans l’exercice ou à l’occasion de l’exercice de ses fonctions, et\ntendant, dans ces divers cas à inculper son honneur ou sa délicatesse, sera\npuni d’un emprisonnement de trois à six mois et d’une amende de 10.000 à\n100.000 francs ou de l’une de ces deux peines seulement.","[CPN] Art. 170 : L’outrage commis dans la même intention par un des moyens\nénumérés à l’article précédent contre un magistrat de l’ordre administratif\nou judiciaire ou un juré, dans l’exercice ou à l’occasion de l’exercice de\nses fonctions, sera puni d’un emprisonnement de trois mois à deux ans et\nd’une amende de 10.000 à 100.000 francs ou de l’une de ces deux peines\nseulement. Si l’outrage a eu lieu à l’audience d’une cour ou d’un tribunal,\nla peine sera d’un emprisonnement de deux à cinq et d’une amende de\n10.000 à 1.000.000 francs.","[CPN] Art. 171 : Quiconque aura publiquement, par des paroles ou écrits, cherché\nà jeter le discrédit sur un acte ou une décision juridictionnelle, dans des\nconditions de nature à porter atteinte à l’autorité de la justice ou à son\nindépendance, sera puni de un à six mois d’emprisonnement et d’une amende\nde 50. 000 à 500.000 francs ou de l’une de ces deux peines seulement.\nSera puni des mêmes peinesquiconque aura publié, avant l’intervention de\nla décision juridictionnelle définitive, des commentaires tendant à exercer\ndes pressions sur les déclarations des témoins ou sur la décision des\njuridictions d’instruction ou de jugement.\n\nLe tribunal pourra, en outre, ordonner que sa décision soit affichée ou\npubliée dans les conditions prévues aux articles 25, alinéa 2 et 22, alinéa 2.\nLes dispositions qui précèdent ne peuvent en aucun cas être appliquées\naux commentaires purement techniques ni à des paroles ou écrits tendant\nà la révision d’une condamnation.","[CPN] Art. 172 : Lorsque l’infraction spécifiée à l’article précédent aura été\ncommise par la voie de la presse, les gérants ou éditeurs seront, par le fait\nseul de la publication, passibles comme auteurs principaux des peines portées\naudit article.\nA leur défaut, l’auteur, et à défaut de l’auteur, les imprimeurs, distributeurs\net afficheurs, seront poursuivis comme auteurs principaux.\nLorsque l’auteur n’est pas poursuivi comme auteur principal, il sera poursuivi\ncomme complice.\nPourront être poursuivies comme complices et dans tous les cas, toutes\npersonnes auxquelles l’article 49 pourrait s’appliquer.\nSection III : Les violences","[CPN] Art. 173 : Les violences ou voies de fait exercées contre les fonctionnaires\nou officiers publics ou les citoyens chargés d’un ministère de service public,\ncommises dans l’exercice ou à l’occasion de l’exercice de leurs fonctions,\nseront punis d’un emprisonnement de six mois à trois ans et d’une amende\nde 10.000 à 500.000 francs.\nS’il en est résulté pour la victime effusion de sang, blessures ou maladies\nou s’il y a eu préméditation ou guet-apens, les peines seront d’un\nemprisonnement de un à moins de dix ans et d’une amende de 20.000 à\n200.000 francs.\nSi les violences ont occasionné la mort de la victime, le coupable sera puni\nd’un emprisonnement de dix à vingt-cinq ans.","[CPN] Art. 174 : Les violences ou voies de fait exercées contre les magistrats de\nl’ordre administratif ou judiciaire dans l’exercice ou à l’occasion de\nl’exercice de leurs fonctions, seront punies d’un emprisonnement de un à\ncinq ans et d’une amende de 10.000 à 500.000 francs.\n\nSi elles ont eu lieu à l’audience d’un tribunal ou d’une cour, ou si elles ont été\nla cause d’effusion de sang, blessures ou maladies, ou s’il y a eu préméditation\nou guet-apens, l’emprisonnement sera de deux ans à moins de dix ans.\nS’il en est résulté la mort de la victime, le coupable sera puni d’un\nemprisonnement de quinze à trente ans.","[CPN] Art. 175 : Le meurtre d’un magistrat, d’un fonctionnaire, d’un officier public\nou d’un citoyen chargé d’un ministère de service public, dans l’exercice ou à\nl’occasion de l’exercice de ses fonctions, sera puni de la peine de mort.","[CPN] Art. 176 : Dans les cas prévus aux articles 173 alinéas 2 et 3, 174 alinéas\n2 et 3, et 175, il ne pourra être fait application des dispositions relatives aux\ncirconstances atténuantes et au sursis.\nToutefois, lorsque la peine de mort sera encourue, l’emprisonnement à vie\npourra lui être substitué.\nL’interdiction de séjour pourra être prononcée en matière correctionnelle.\nCHAPITRE VI : VAGABONDAGE - MENDICITE\nSection 1 : Vagabondage","[CPN] Art. 177 : Les vagabonds sont ceux qui n’ont ni domicile certain, ni moyen\nde subsistance et qui n’exercent habituellement ni métier, ni profession.","[CPN] Art. 178 : Les vagabonds seront punis d’un emprisonnement de trois à six\nmois. L’interdiction de séjour sera en outre prononcée.\nSection II : Mendicité","[CPN] Art. 179 : Toute personne qui aura été trouvée mendiant dans un lieu\npublic ou privé sera punie d’un emprisonnement de trois à six mois.","[CPN] Art. 180 : Aucune peine ne pourra toutefois être prononcée contre les\nvieillards de plus de soixante ans et les infirmes.","[CPN] Art. 181 : (Loi n° 63-3 du 1er février 1963). Les parents de mineurs de\nmoins de dix-huit ans se livrant habituellement à la mendicité, tous ceux qui\nles auront invités à mendier ou qui en tirent sciemment profit, seront punis\nd’un emprisonnement de six mois à un an.\n\nCode pénal","[CPN] Art. 182 : Toute personne membre d’une organisation de mendiants sera\npunie d’un emprisonnement de un à deux ans.\nL’interdiction de séjour sera en outre prononcée.\nCHAPITRE VII : DES INFRACTIONS CONTRE L’AUTORITE\nPUBLIQUE\nSection I : Refus d’un service légalement dû.","[CPN] Art. 183 : Tout commandant d’armes, tout officier ou sous-officier ou chef\nde détachement de la force publique qui, après en avoir été légalement requis\npar l’autorité civile, aura refusé de faire agir la force placée sous ces ordres,\nsera puni d’un emprisonnement de six mois à deux ans et d’une amende de\n10.000 à 100.000 francs, ou de l’une de ces deux peines seulement.","[CPN] Art. 184 : Les témoins et jurés défaillants qui auront allégué une excuse\nreconnue fausse, le médecin qui ne défère pas aux réquisitions de la justice,\nles particuliers qui ne se conforment pas aux réquisitions légales des\nreprésentants des autorités publiques, seront condamnés à un\nemprisonnement de quinze jours à deux mois et à une amende de 10.000 à\n100.000 ou à l’une de ces deux peines seulement.\nSont assimilées aux réquisitions légales, mentionnées à l’alinéa précédent,\nles convocations émanant des chefs de circonscriptions administratives, des\nmagistrats et des officiers de police judiciaire, et remises à leurs destinataires.","[CPN] Art. 185 : Ceux qui par violences, voies de fait, menaces ou manœuvres\nconcertées, auront organisé ou tenté d’organiser le refus collectif de payer\nl’impôt seront punis d’une peine de trois mois à deux ans d’emprisonnement\net d’une amende de 20.000 à 200.000 francs.\nCeux qui auront refusé collectivement le paiement de l’impôt seront punis\nd’une peine de six mois à un an d’emprisonnement et d’une amende de\n10.000 à 100.000 francs ou de l’une de ces deux peines seulement.\nLe refus individuel du paiement de l’impôt, s’il n’est pas justifié par un titre\nde dégrèvement ou de décharge, sera puni d’une peine de 15 jours à six\nmois d’emprisonnement et d’une amende de 5.000 à 100.000 francs ou de\nl’une de ces deux peines seulement.\n\nDans les cas prévus aux alinéas 2 et 3, les poursuites ne pourront être\nengagées que sur la plainte des agents chargés du recouvrement de l’impôt;\ntoutefois, aucune poursuite n’aura lieu avant l’expiration d’une période de\ntrois mois après la date de mise en recouvrement du rôle.","[CPN] Art. 186 : Sera puni d’un emprisonnement de un à six mois et d’une amende\nde 10.000 à 100.000 francs ou de l’une de ces deux peines seulement celui\nqui, ayant eu connaissance d’un crime déjà tenté ou consommé, n’aura pas\naverti aussitôt les autorités administratives ou judiciaires.\nLa peine d’emprisonnement sera de six mois au moins et de trois ans au\nplus si la dénonciation aurait pu avoir pour effet de prévenir ou de limiter\nles effets du crime, ou si le coupable était susceptible de commettre de\nnouveaux crimes que la dénonciation aurait pu prévenir.\nSont exempts des dispositions du présent article l’époux, l’épouse, les\nparents ou alliés, jusqu’au quatrième degré inclusivement, des auteurs ou\ncomplices du crime.","[CPN] Art. 187 : Quiconque, après avoir publiquement dénoncé un crime ou un\ndélit et déclaré qu’il en connaissait le ou les auteurs, refuse de répondre\naux questions qui lui sont posées, sur ce point, par le juge d’instruction,\nsera puni d’un emprisonnement de un mois à un an et d’une amende de\n10.000 à 100.000 francs ou de l’une de ces deux peines seulement.","[CPN] Art. 188 : Sera puni d’un emprisonnement de six mois à trois ans et d’une\namende de 10.000 à 100.000 francs ou de l’une de ces deux peines seulement\nquiconque, pouvant empêcher par son action immédiate, sans risque pour\nlui ou pour les tiers, soit un fait qualifié crime, soit un délit contre l’intégrité\ncorporelle, s’abstient volontairement de le faire.\nSera puni des mêmes peines quiconque s’abstient volontairement de porter à\nune personne en péril l’assistance que, sans risque pour lui ni pour les tiers, il\npouvait lui prêter soit par son action personnelle, soit en provoquant un secours.\nSera puni des mêmes peines celui qui, connaissant la preuve de l’innocence\nd’une personne incarcérée préventivement ou jugée pour crime ou délit,\ns’abstient volontairement d’en apporter aussitôt le témoignage aux autorités\nde justice ou de police. Toutefois, aucune peine ne sera prononcée contre\ncelui qui apportera son témoignage tardivement mais spontanément.\n\nSont exceptés de la disposition de l’alinéa précédent le coupable du fait qui\nmotivait la poursuite, les coauteurs, les complices, le conjoint, les parents\nou alliés jusqu’au quatrième degré inclusivement.\nSection II. Usurpation de titre ou de fonction","[CPN] Art. 189 : Quiconque, sans titre, se sera immiscé dans les fonctions\npubliques, civiles ou militaires, ou aura fait les actes d’une de ces fonction,\nou sans faire un acte de la fonction, aura cherché par des manœuvres, à\npersuader qu’il en était investi, sera puni d’un emprisonnement de un à\ncinq ans et d’une amende de 10.000 à 100.000 francs ou de l’une de ces\ndeux peines seulement.","[CPN] Art. 190 : Toute personne qui aura publiquement porté un costume, un\nuniforme ou une décoration ayant un caractère officiel et qui ne lui a point\nété régulièrement attribué, conféré ou reconnu par la puissance publique,\nsera puni d’un emprisonnement de six mois à trois ans et d’une amende de\n10.000 à 100.000 francs ou de l’une de ces deux peines seulement.\nSera puni des mêmes peines quiconque, sans remplir les conditions exigées,\naura fait usage ou se sera réclamé d’un titre attaché à une profession\nlégalement réglementée, d’un diplôme ou d’une qualité, dont les conditions\nd’attribution sont fixées par l’autorité publique.\nIl pourra être fait application des dispositions de l’article 25, alinéa 2.\nSection III : Bris de scellés","[CPN] Art. 191 : Lorsque les scellés apposés soit par ordre de l’autorité publique\nsoit par suite d’une ordonnance de justice rendue en quelque matière que\nce soit, auront été brisés, les gardiens seront punis, pour simple négligence,\nd’un emprisonnement de deux à six mois et d’une amende de 10.000 à\n100.000 francs ou de l’une de ces deux peines seulement.","[CPN] Art. 192 : Quiconque aura, à dessein, brisé ou tenté de briser des scellés,\nou participé au bris de scellés ou à la tentative de bris de scellés, sera puni\nd’un emprisonnement de un à trois ans, et d’une amende de 10.000 à 100.000\nfrancs ou de l’une de ces deux peines seulement.\nSi c’est le gardien lui-même qui a brisé les scellés ou participé au bris de\nscellés, il sera puni d’un emprisonnement de deux à cinq ans.\n\nCode pénal","[CPN] Art. 193 : Tout vol commis à l’aide de bris de scellés sera puni comme vol\ncommis à l’aide d’effraction.\nSection IV. Enlèvement de pièces dans les dépôts publics.","[CPN] Art. 194 : Quiconque se sera rendu coupable de soustraction frauduleuse\nou de destruction volontaire de pièces ou de procédures criminelles, ou\nd’autres papiers, registres, actes et effets contenus dans les archives, greffes\net dépôts publics, ou remis à un dépositaire public en cette qualité, sera\npuni d’un emprisonnement de un à cinq ans.\nSi les soustractions ou destructions ont été commises avec violences envers\nles personnes, ou par effraction, la peine d’emprisonnement sera de deux à\nmoins de dix ans.\nSi les soustractions ou destructions sontle fait du dépositaire lui-même, il\nsera puni de la peine d’emprisonnement prévu à l’alinéa précédent.\nDans les cas prévus aux alinéas 2 et 3, il ne pourra être fait application des\ndispositions relatives aux circonstances atténuantes et au sursis.\nDans tous les cas, la tentative sera punie comme le délit consommé.","[CPN] Art. 195 : Lorsque les soustractions ou destructions de pièces visées à\nl’article précédent auront été commises, les greffiers, archivistes, notaires\nou autres dépositaires négligents, seront punis d’un emprisonnement de\nquinze jours à six mois et d’une amende de 20.000 à 200.000 ou de l’une de\nces deux peines seulement.\nSection V : Opposition à l’exécution des travaux publics","[CPN] Art. 196 : Quiconque, par violences ou voies de fait, se sera opposé à la\nconfection des travaux autorisés par l’autorité publique, sera puni d’un\nemprisonnement de trois mois à deux ans et d’une amende de 10.000 à\n100.000 ou de l’une de ces deux peines seulement.\nSection V bis : Résistance à l’exécution d’une décision de justice\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 196. 1 : Quiconque aura résisté ou tenté de résister à l’exécution\nd’une décision de justice devenue définitive ou exécutoire sera puni d’un\nemprisonnement de trois mois à deux ans et d’une amende de 10.000 à\n100.000 francs.\n\n- Si la résistance a été commise avec port d’arme l’emprisonnement sera\nde 6 mois à 3 ans et l’amende de 10.000 à 200.000 francs.\n- Si la résistance a été commise avec violence, l’emprisonnement sera de\n1 à 5 ans et l’amende de 20.000 à 200.000 francs.","[CPN] Art. 196. 2 : Si la résistance a été commise en réunion de deux ou plusieurs\npersonnes, l’emprisonnement sera de 2 à 5 ans et l’amende de 20 000 à\n200.000 francs.\nSi la résistance a été commise en réunion de plusieurs personnes avec\narme, l’emprisonnement sera de 2 à 7 ans et l’amende de 20.000 à 200.000\nfrancs.\nSi les faits prévus à l’alinéa précédent ont été commis avec violence,\nl’emprisonnement sera de 2 à moins de 10 ans et l’amende de 50 000 à\n500.000 francs.","[CPN] Art. 196. 3 : Tout dépositaire de l’autorité publique qui aura refusé de prêter\nmain forte lorsqu’il en sera régulièrement requis pour l’exécution d’une décision\nde justice devenue définitive ou exécutoire sera puni d’un emprisonnement de\n6 mois à 2 ans et d’une amende de 10. 000 à 20. 000 francs.\nCHAPITRE VIII : EVASION ET ASSISTANCE AUX\nMALFAITEURS\nSection I : Evasion de détenus","[CPN] Art. 197 : Toute personne détenue légalement en quelque lieu que ce soit\nqui se sera évadée ou aura tenté de s’évader sera, pour ce seul fait, punie\nd’un emprisonnement de trois mois à un an.\nSi l’évasion a eu lieu par bris de prison ou violences, l’emprisonnement\nsera de six mois à deux ans.\nLa peine prononcée sera subie immédiatement après l’expiration de celle\nque le détenu aura encourue pour l’infraction motivant la détention ou\nimmédiatement après l’arrêt ou le jugement qui l’aura acquitté ou renvoyé\nabsous de ladite infraction.\n\nCode pénal","[CPN] Art. 198 : Tout gardien ou préposé à la conduite, au transport ou à la\ngarde des détenus qui, par sa négligence, aura permis l’évasion de détenus,\nsera puni d’un emprisonnement de trois mois à un an et d’une amende de\n5.000 à 100.000 francs ou de l’une de ces deux peines seulement.","[CPN] Art. 199 : Tout gardien ou préposé à la conduite, au transport ou à la\ngarde de détenus, qui aura tenté de procurer ou de faciliter une évasion,\nmême si celle-ci n’a été consommée ni tentée, et quand bien même que les\npréparatifs auraient été menés à l’insu du détenu, sera puni d’un\nemprisonnement de six mois à trois et d’une amende de 10.000 à 100.000\nfrancs.","[CPN] Art. 200 : Ceux qui, n’étant pas chargés de la garde ou de la conduite du\ndétenu, auront procuré, facilité ou tenté de procurer ou de faciliter son\névasion ou sa fuite une fois l’évasion réalisée, seront punis d’un\nemprisonnement de trois mois à deux ans.\nSi l’évasion a eu lieu ou a été tentée avec violence ou bris de prisons,\nl’emprisonnement sera de deux à huit ans contre ceux qui l’auront favorisée\nen fournissant des instruments ou des armes propres à l’opérer.","[CPN] Art. 201 : Dans les cas prévus aux alinéas 2 des articles 197 et 199, le\ntribunal ne pourra faire application des dispositions relatives aux\ncirconstances atténuantes et au sursis.","[CPN] Art. 202 : La peine d’interdiction de séjour pourra être prononcée contre\ntoute personne condamnée pour avoir favorisé une évasion ou une tentative\nd’évasion.","[CPN] Art. 203 : Les peines d’emprisonnement ci-dessus établies contre les\ngardiens ou préposés à la conduite, au transport ou à la garde des détenus,\nen cas de négligence seulement, cesseront lorsque les évadés seront repris\nou représentés, pourvu que ce soit dans les deux mois de l’évasion, et\nqu’ils ne soient pas arrêtés pour crimes ou délits commis postérieurement.","[CPN] Art. 204 : Aucune poursuite n’aura lieu contre ceux qui auront tenté de\nprocurer ou de faciliter une évasion si, avant que celle-ci ait été réalisée, ils\nont donné connaissance du projet aux autorités administratives ou judiciaires\net leur en ont révélé les auteurs.\n\nSection II : Recel de malfaiteurs","[CPN] Art. 205 : Ceux qui, connaissant les agissements des malfaiteurs exerçant\ndes brigandages ou des violences contre la sûreté de l’Etat, la paix publique,\nles personnes ou les propriétés, leur fournissent habituellement logement,\nlieu de retraite ou de réunion, seront punis comme les auteurs.","[CPN] Art. 206 : Ceux qui auront sciemment recelé une personne qu’ils savaient\nrecherchée par la justice, ou qui l’auront soustraite ou tenté de la soustraire\nà l’arrestation ou aux recherches, ou l’auront aidé à se cacher ou à prendre\nla fuite, seront punis d’un emprisonnement de six mois à cinq ans et d’une\namende de 10.000 à 100.000 francs, ou de l’une de ces deux peines seulement.\nSont exceptés des dispositions qui précèdent, le conjoint, les parents ou\nalliés de la personne recherchée, jusqu’au quatrième degré inclusivement.\nSection III : Remise d’objets aux détenus","[CPN] Art. 207 : Sera puni d’un emprisonnement de trois mois à un an et d’une\namende de 10. 000 à 100. 000 francs ou de l’une de ces deux peines\nseulement quiconque aura, dans des conditions irrégulières, remis ou fait\nparvenir ou tenté de remettre ou de faire parvenir à un détenu, en quelque\nlieu que ce soit, des sommes d’argent, correspondances ou objets\nquelconques.\nLa sortie ou la tentative de sortie irrégulière de sommes d’argent,\ncorrespondances ou objets quelconques, sera punie des mêmes peines.\nSection IV : Association de malfaiteurs","[CPN] Art. 208 : Quiconque se sera affilié ou aura participé à une association\ndont le but est de commettre des crimes ou délits contre des personnes ou\ndes propriétés sera puni d’un emprisonnement de deux à moins de dix ans.\nIl ne pourra être fait application des dispositions relatives aux circonstances\natténuantes et au sursis.\nL’interdiction de séjour sera en outre prononcée.\nLes coupables du délit mentionné au 1eralinéa du présent article seront\nexemptés de peine si, avant toute poursuite, ils ont révélé aux autorités\nconstituées l’entente établie ou fait connaître l’existence de l’association.\n\nTITRE III : ATTENTATS CONTRE LES PERSONNES\nCHAPITRE PRELIMINAIRE : DES CRIMES CONTRE\nL’HUMANITE ET DES CRIMES DE GUERRE\n(Loi n° 2003-25 du 13 juin 2003).\nSection 1 : Du génocide\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 208. 1 : (Loi n° 2003-25 du 13 juin 2003)Constitue un génocide le\nfait, en exécution d’un plan concerté tendant à la destruction totale ou\npartielle d’un groupe national, ethnique, racial ou religieux ou d’un groupe\ndéterminé à partir de tout autre critère arbitraire, de commettre ou de faire\ncommettre à l’endroit de ce groupe l’un des actes suivants :\n• Atteinte volontaire à la vie ;\n• Atteinte à l’intégrité physique ou psychique;\n• Soumission à des conditions d’existence de nature à entraîner la destruction\ntotale ou partielle du groupe ;\n• Mesures visant à entraver les naissances;\n• Transfert forcé d’enfants.\nLe génocide est puni de la peine de mort.\nSection 2 : Des crimes contre l’humanité\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 208. 2 : (Loi n° 2003-25 du 13 juin 2003) Constituent des crimes\ncontre l’humanité, la déportation, la réduction en esclavage ou la pratique\nmassive et systématique d’exécutions sommaires, d’enlèvements de\npersonnes suivis de leur disparition, de la torture ou d’actes inhumains,\ninspirés par des motifs politiques, philosophiques, raciaux ou religieux et\norganisés en exécution d’un plan concerté à l’encontre d’un groupe de\npopulation civile.\nLes crimes contre l’humanité sont punis de la peine de mort.\n\nSection 3 : Des crimes de guerre\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 208. 3 : (Loi n° 2003-25 du 13 juin 2003)Constituent des crimes\nde guerre et réprimés conformément aux dispositions du présent chapitre,\nles infractions graves énumérées ci-après, portant atteinte, par action ou\nomission, aux personnes et aux biens protégés par les conventions signées\nà Genève le 12 août 1949, par les protocoles I et II additionnels à ces\nconventions, adoptés à Genève le 8 juin 1977 :\n1) l’homicide intentionnel;\n2) la torture ou les autres traitements inhumains, y compris les expériences\nbiologiques;\n3) le fait de causer intentionnellement de grandes souffrances ou de\nporter des atteintes graves à l’intégrité physique, à la santé;\n4) le fait de contraindre à servir dans les Forces armées de la puissance\nennemie ou de la partie adverse un prisonnier de guerre, une personne\ncivile protégée par la convention relative à la protection des personnes\nciviles en temps de guerre ou une personne protégée à ce même égard par\nles protocoles I et II additionnels aux conventions internationales de Genève\ndu 12 août 1949 ;\n5) le fait de priver un prisonnier de guerre, une personne civile protégée\npar la convention sur la protection des personnes civiles en temps de guerre\nou une personne protégée à ce même égard, par les protocoles I et II\nadditionnels aux conventions internationales de Genève du 12 août 1949,\nde son droit d’être jugé régulièrement et impartialement selon les\nprescriptions de ces dispositions ;\n6) la déportation, le transfert ou le déplacement illicite","[CPN] Art. 208. 4 : (Loi n° 2003-25 du 13 juin 2003) Les infractions énumérées\naux paragraphes 1°, 2° et 11° à 15° de l’article 208.3 sont punies de la\npeine de mort.\n\nLes infractions énumérées au 3° et au 10° de l’article 208.3 sont punies de\nl’emprisonnement à perpétuité. Elles sont punies de la peine de mort si\nelles ont eu pour conséquence la mort d’une ou plusieurs personnes.\nL’infraction visée au 8° de l’article 208.3 est punie de la peine\nd’emprisonnement de quinze à vingt ans. La même infraction ainsi que\ncelle visée au 16° du même articlesont punis de la peine d’emprisonnement\nde quinze à vingt ans si elles ont eu pour conséquence soit une maladie\nparaissant incurable, soit une incapacité permanente de travail, soit la perte\nde l’usage absolu d’un organe, soit une mutilation grave. Elles sont punies\nde l’emprisonnement à perpétuité si elles ont eu pour conséquence la mort\nd’une ou plusieurs personnes.\nLes infractions énumérées aux 4° à 7° et au 17° de l’article 208.3 sont\npunies de la peine d’emprisonnement de quinze à vingt ans. Dans les cas\nde circonstances aggravantes prévues à l’alinéa précédent, elles sont punies,\nselon les cas des peines prévues à cet alinéa.\nLes infractions énumérées aux 18° à 20° de l’article 208.3 sont punies de\nla peine d’emprisonnement de quinze à vingt ans, sous réserve de l’application\ndes dispositions pénales plus sévères réprimant les atteintes graves à la\ndignité de la personne.\nL’infraction prévue au paragraphe 9° de l’article 208.3 est pu","[CPN] Art. 208.5 : (Loi n° 2003-25 du 13 juin 2003)La participation à un\nattroupement formé ou à une entente établie en vue de la préparation\ncaractérisée par un ou plusieurs faits matériels de l’un des crimes définis\npar les articles 208.1 et 208.2 est punie de la peine de mort.\nLa tentative est punie des peines prévues pour l’infraction consommée.","[CPN] Art. 208. 6 : (Loi n° 2003-25 du 13 juin 2003)L’auteur ou le co-auteur\nd’un crime visé par le présent chapitre ne peut être exonéré de sa\nresponsabilité du seul fait qu’il a accompli un acte prescrit ou autorisé par\ndes dispositions législatives ou un acte commandé par l’autorité légitime.\n\nToutefois, la juridiction tient compte de cette circonstance lorsqu’elle\ndétermine la peine et en fixe le montant, sans qu’elle puisse descendre en\ndessous de 20 ans.\nAucun intérêt, aucune nécessité d’ordre politique, militaire ou national, ne\npeut justifier, même à titre de représailles, les infractions prévues par les\narticles 208.1, 208.2 et 208.3, sans préjudice des exceptions mentionnées\naux 9° et 13° de l’article 208.3.","[CPN] Art. 208.7 : (Loi n° 2003-25 du 13 juin 2003)L’immunité attachée à la\nqualité officielle d’une personne n’empêche pas l’application des dispositions\ndu présent chapitre.","[CPN] Art. 208. 8 : (Loi n° 2003-25 du 13 juin 2003)L’action publique relative\naux crimes prévus au présent chapitre ainsi que les peines prononcées sont\nimprescriptibles.\nLes juridictions nigériennes sont compétentes pour connaître des infractions\nprévues au présent chapitre, indépendamment du lieu où celles-ci auront\nété commises.\nPour les infractions commises à l’étranger par un nigérien contre un étranger,\nla plainte de l’étranger ou de sa famille ou l’avis officiel de l’autorité du\npays où l’infraction a été commise n’est pas requis.\nCHAPITRE PREMIER : ALTERATION DE LA VERITE ET\nDIVULGATION\nSection I : Faux témoignage","[CPN] Art. 209 : Le faux témoignage est le fait d’altérer sciemment la vérité\ndans une déposition faite sous serment devant une juridiction de jugement\nou devant une juridiction d’instruction.","[CPN] Art. 210 : Quiconque sera coupable de faux témoignage, en matière de\nsimple police, soit contre le prévenu, soit en sa faveur, sera puni d’un\nemprisonnement de un à trois ans et d’une amende de 10. 000 à 100. 000\nfrancs ou de l’une de ces deux peines seulement.","[CPN] Art. 211 : Le coupable de faux témoignage, en matière correctionnelle,\nsoit contre l’inculpé ou le prévenu, soit en sa faveur, sera puni d’un\n\nemprisonnement de deux à cinq ans et d’une amende de 20.000 à 200.000\nfrancs ou de l’une de ces deux peines seulement.\nSi néanmoins le prévenu a été condamné à plus de cinq années\nd’emprisonnement, le faux témoin qui a déposé contre lui encourra la même\npeine.","[CPN] Art. 212 : Le coupable de faux témoignage, en matière criminelle, soit\ncontre l’inculpé ou l’accusé, soit en sa faveur, sera puni d’un emprisonnement\nde deux à cinq ans et d’une amende de 50. 000 à 300. 000 francs.\nSi néanmoins l’accusé a été condamné à une peine égale ou supérieure à\ndix ans d’emprisonnement, le faux témoin qui a déposé contre lui encourra\nla même peine.","[CPN] Art. 213 : Le coupable de faux témoignage, en matière civile ou\nadministrative, sera puni d’un emprisonnement de deux à cinq ans et d’une\namende de 20. 000 à 200. 000 francs ou de l’une de ces deux peines\nseulement.","[CPN] Art. 214 : Le faux témoin, qui aura reçu de l’argent, une récompense\nquelconque ou des promesses, sera puni :\n1) en matière de simple police : d’un emprisonnement de deux à cinq ans\net d’une amende de 20. 000 à 200. 000 francs;\n2) en matière correctionnelle, civile ou administrative : d’un\nemprisonnement de cinq à moins de dix ans et d’une amende de 50. 000 à\n300. 000 francs;\n3) en matière criminelle : d’un emprisonnement de dix à vingt ans. Dans\ntous les cas, ce que le faux témoin aura reçu sera confisqué.","[CPN] Art. 215 : L’interprète qui, en matière civile, administrative, criminelle,\ncorrectionnelle ou de simple police, aura de mauvaise foi dénaturé la\nsubstance de paroles ou de documents oralement traduits, sera puni des\npeines du faux témoignage selon les dispositions contenues dans les articles\n210, 211, 212, 213 et 214.","[CPN] Art. 216 : Dans les cas prévus aux articles 210, 211, 213 et 214 alinéas\n1eret 2e, les coupables pourront, conformément aux dispositions de l’article\n25 être privés en tout ou partie des droits mentionnés à l’article 21.\n\nSection II : Subornation de témoins","[CPN] Art. 217 : Quiconque, en toute matière, soit au cours d’une procédure et\nen tout état de cause, soit en vue d’une demande ou d’une défense en\njustice, aura usé de promesses, offres ou présents, de pressions, menaces,\nvoies de fait, manœuvres ou artifices pour déterminer autrui à faire ou\ndélivrer ou à ne pas faire ou à ne pas délivrer une déposition, une déclaration\nou une attestation mensongère sera, que cette subornation ait ou non produit\nson effet, puni d’un emprisonnement de deux mois à trois ans et d’une\namende de 50.000 à 500.000 ou de l’une de ces deux peines seulement,\nsans préjudice des peines plus fortes prévues à la section précédente, s’il\nest complice d’un faux témoignage qualifié crime ou délit.","[CPN] Art. 218 : La subornation d’interprète sera punie comme subornation de\ntémoin selon les dispositions de l’article précédent.\nSection III : Faux serment","[CPN] Art. 219 : Celui à qui le serment aura été déféré ou référé en matière\ncivile, et qui aura fait un faux serment, sera puni d’un emprisonnement de\nun à cinq ans et d’une amende de 20.000 à 200.000 francs.\nIl pourra en outre, conformément aux dispositions de l’article 25, être privé,\nen tout ou en partie, des droits mentionnés à l’article 21.\nSection IV : Dénonciation calomnieuse","[CPN] Art. 220 : Quiconque aura, par quelque moyen que ce soit, fait une\ndénonciation calomnieuse contre un ou plusieurs individus aux officiers de\npolice administrative ou judiciaire, ou à toute autre autorité compétente, ou\nencore aux supérieurs hiérarchiques ou aux employeurs du dénoncé, sera\npuni d’un emprisonnement de six mois à cinq ans et d’une amende de\n50.000 à 500.000 francs.\nLe tribunal pourra, en outre, ordonner l’insertion du jugement intégralement\nou par extrait, dans un ou plusieurs journaux, et aux frais du condamné.\nSi le fait dénoncé est susceptible de sanctions pénales ou disciplinaires, les\npoursuites pourront être engagées en vertu du présent article, soit après\njugement ou arrêt d’acquittement ou de relaxe, soit après ordonnance ou\narrêt de non-lieu, soit après classement de la dénonciation par le magistrat,\n\nfonctionnaire, autorité supérieure ou employeur compétent pour lui donner\nla suite qu’elle était susceptible de comporter.\nLa juridiction saisie en vertu du présent article sera tenue de surseoir à\nstatuer si les poursuites concernant le fait dénoncé sont pendantes.\nSection V : Révélation de secret.","[CPN] Art. 221 : Les médecins, chirurgiens, pharmaciens, sages-femmes,\ninfirmiers et toutes autres personnes dépositaires, par état ou profession ou\npar fonctions temporaires ou permanentes, des secrets qu’on leur confie,\nqui, hors le cas où la loi les oblige ou les autorise à se porter dénonciateurs,\nauront révélé des secrets, seront punis d’un emprisonnement de deux mois\nà un an et d’une amende de 10.000 à 200.000 ou de l’une de ces deux\npeines seulement.\nToutefois, les personnes ci-dessus énumérées, sans être tenues de dénoncer\nles avortements jugés par elles criminels dont elles ont eu connaissance à\nl’occasion de l’exercice de leur fonction, n’encourent pas, si elles les\ndénoncent, les peines prévues à l’alinéa précédent; citées en justice, pour\nune affaire d’avortement, elles demeurent libres de fournir leur témoignage\nà la justice sans s’exposer à aucune peine.\nCHAPITRE II : COUPS ET BLESSURES VOLONTAIRES ET\nAUTRES CRIMES ET DELITS VOLONTAIRES.\nSection I : Coups et blessures volontaires","[CPN] Art. 222 : Tout individu qui, volontairement, aura fait des blessures ou\nporté des coups, ou commis toutes autres violences ou voies de fait, sera\npuni d’un emprisonnement de trois mois à deux ans et d’une amende de\n10.000 à 100.000 francs ou de l’une de ces deux peines seulement.\nSi les coups, les blessures ou les violences ou les voies de fait, ont eu lieu\navec préméditation, guet-apens, ou usage d’une arme, le coupable sera\npuni d’un emprisonnement de six mois à trois ans et d’une amende de\n20.000 à 200.000 francs ou de l’une de ces deux peines seulement.\n\nSi les faits précisés à l’alinéa précédent ont eu lieu avec préméditation, de\nmutilation, amputation, ou privation de l’usage d’un membre, cécité, perte\nd’un œil ou d’autres infirmités permanentes, un emprisonnement de un à\nhuit ans sera prononcé.\nSi les faits précisés à l’alinéa précédent ont eu lieu avec préméditation,\nguet-apens ou usage d’une arme, l’emprisonnement sera de deux à moins\nde dix ans.\nSi les coups portés ou les blessures faites volontairement sans intention de\ndonner la mort, l’ont pourtant occasionnée, le coupable sera puni d’un\nemprisonnement de dix à vingt ans.\nSi les faits précisés à l’alinéa précédent ont eu lieu avec préméditation, guetapens ou usage d’une arme, l’emprisonnement sera de quinze à trente ans.","[CPN] Art. 223 : Outre les armes à feux, sont considérées comme armes, au\nsens de la présente section, tous objets et instruments perçants, tranchants\nou contondants.","[CPN] Art. 224 : La préméditation consiste dans le dessein formé avant l’action,\nd’attenter à la personne d’un individu déterminé ou même de celui qui sera\ntrouvé ou rencontré, quand même ce dessein serait dépendant de quelque\ncirconstance ou condition.","[CPN] Art. 225 : Le guet-apens consiste à attendre plus ou moins de temps, dans\nun ou divers lieux, un individu, soit pour exercer sur lui des actes de violence,\nsoit pour lui donner la mort.","[CPN] Art. 226 : Lorsque les coups, blessures ou violences ou voies de fait spécifiés\nà l’article 222 auront été commis, soit sur la personne des père et mère\nlégitimes, naturels ou adoptifs de l’auteur, ou autres ascendants légitimes,\nsoit sur la personne d’un enfant au-dessous de l’âge de treize ans accomplis,\nles peines mentionnées à l’article 222 seront aggravées ainsi qu’il suit :\n1) dans les cas prévus aux alinéas 1 et 2, les peines seront portées au\ndouble ;\n2) dans le cas prévu à l’alinéa 3, l’emprisonnement sera de deux à moins\nde dix ans;\n\n3) dans le cas prévu à l’alinéa 4, l’emprisonnement sera de trois à moins\nde dix ans;\n4) dans le cas prévu à l’alinéa 5, l’emprisonnement sera de trente ans;\n5) dans le cas prévu à l’alinéa 6, l’emprisonnement sera à vie.","[CPN] Art. 227 : La privation d’aliments ou de soins, susceptibles de compromettre\nla santé d’un enfant au-dessous de l’âge de treize ans accomplis, est\nassimilée aux violences ci-dessus précitées.","[CPN] Art. 228 : Dans les cas prévus aux alinéas 3 et 4 de l’article 222 ainsi\nqu’aux 2° et 3° de l’article 226, il ne pourra être fait application des\ndispositions relatives aux circonstances atténuantes et au sursis.","[CPN] Art. 229 : Le coupable puni d’une peine correctionnelle en vertu des\ndispositions de la présente section pourra être privé, en tout ou en partie\ndes droits mentionnés à l’article 21.\nL’interdiction de séjour pourra, en outre, être prononcée dans tous les cas.\nSection II : Administration de substances nuisibles et mise en\ndanger de la vie d’autrui\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 230 : Celui qui aura occasionné à autrui une maladie ou une incapacité\nde travail personnel en lui administrant volontairement, de quelque manière\nque ce soit, des substances qui, sans être de nature à donner la mort, sont\nnuisibles à la santé, sera puni d’un emprisonnement de six mois à cinq ans\net d’une amende de 10.000 à 100.000 francs.\nSi la maladie ou l’incapacité de travail a duré plus de vingt jours ou si le\ndélit ci-dessus spécifié a été commis envers un des ascendants, descendants\nou le conjoint, la peine d’emprisonnement sera de deux à cinq ans.\nLe coupable pourra être interdit de séjour et privé, conformément aux\ndispositions de l’article 25, en tout ou en partie, des droits mentionnés à\nl’article 21. Le tribunal ne pourra faire application des dispositions relatives\naux circonstances atténuantes et au sursis.\n\nCode pénal","[CPN] Art. 230.1 : (Loi n° 2003-25 du 13 juin 2003). Le fait d’exposer\ndirectement autrui à un risque immédiat de mort ou des blessures de nature\nà entraîner une mutilation ou une infirmité permanente, par violation\nmanifestement délibérée d’une obligation particulière de sécurité ou de\nprudence imposée par la loi ou le règlement, est puni d’un an à deux ans\nd’emprisonnement et d’une amende de 20.000 à 200.000 francs.\nLe fait d’exposer sciemment autrui à un risque de maladie du Syndrome\nimmunodéficience acquis (SIDA) est puni de cinq ans à moins de 10 ans\nd’emprisonnement et une amende de 50.000 à 500.000 francs.\nLes peines prévues à l’alinéa précédent sont portées au maximum lorsque\nl’auteur appartient au corps médical ou paramédical.\nSection III : Castration","[CPN] Art. 231 : La castration est l’ablation ou l’amputation volontaire d’un organe\nnécessaire à la génération.","[CPN] Art. 232 : Toute personne coupable du crime de castration subira la peine\nde l’emprisonnement à vie.\nSi la mort en est résultée, la peine de mort sera prononcée.\nSection III bis : Mutilations génitales féminines\n(Loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 232.1 : (Loi n° 2003-25 du 13 juin 2003)Est qualifiée de mutilation\ngénitale féminine, toute atteinte à l’organe génital de la femme par ablation\ntotale ou partielle d’un ou plusieurs de ses éléments, par excision, infibulation,\npar insensibilisation ou par tout autre moyen.","[CPN] Art. 232.2 : (Loi n° 2003-25 du 13 juin 2003)Quiconque aura commis ou\ntenté de commettre une mutilation génitale féminine sera puni d’un emprisonnement\nde six mois à trois ans et d’une amende de 20.000 à 200.000 francs.\nSi la mutilation génitale féminine faite volontairement sans intention de\ndonner la mort l’a pourtant occasionnée, le coupable sera puni d’un\nemprisonnement de dix à vingt ans.\nLe complice est puni de la même peine que l’auteur principal.\n\nCode pénal","[CPN] Art. 232.3 : (Loi n° 2003-25 du 13 juin 2003)Les peines prévues à\nl’article précédent sont portées au maximum lorsque l’auteur appartient au\ncorps médical ou paramédical ; une interdiction d’exercer sa profession\npeut être prononcée pendant une durée n’excédant pas cinq ans.\nSection IV : Menaces","[CPN] Art. 233 : Quiconque aura menacé par écrit anonyme ou signé, image,\nsymbole ou emblème, d’assassinat, d’emprisonnement ou de tout autre\nattentat contre les personnes qui serait punissable d’une peine criminelle,\nsera, dans le cas où la menace aurait été faite avec ordre de déposer une\nsomme d’argent dans un lieu déterminé, ou de remplir toute autre condition,\npuni d’un emprisonnement de deux à cinq ans et d’une amende de 20.000\nà 200.000 francs.\nLe coupable pourra, en outre, conformément aux dispositions de l’article\n25, être privé, en tout ou en partie, des droits mentionnés à l’article 21.\nLa peine d’interdiction de séjour pourra en outre être prononcée.","[CPN] Art. 234 : Si cette menace n’a été accompagnée d’aucun ordre ou condition,\nla peine d’emprisonnement sera de un à trois ans et l’amende de 10.000 à\n100.000 francs.\nLa peine d’interdiction de séjour pourra en outre être prononcée.","[CPN] Art. 235 : Si la menace faite avec ordre ou sous condition a été verbale, le\ncoupable sera puni d’un emprisonnement de six mois à deux ans et d’une\namende de 10.000 à 100.000 francs ou de l’une de ces deux peines\nseulement.","[CPN] Art. 236 : Quiconque aura, par l’un des moyens prévus aux articles\nprécédents, menacé de voies de fait ou violences non prévues à l’article\n233, si la menace a été faite avec ordre ou sous condition, sera puni d’un\nemprisonnement de trois à six mois et d’une amende de 10.000 à 100.000\nfrancs ou de l’une de ces deux peines seulement.\n\nCHAPITRE III : MEURTRES ET AUTRES CRIMES\nCAPITAUX","[CPN] Art. 237 : L’homicide commis volontairement est un meurtre.","[CPN] Art. 238 : Le meurtre commis avec préméditation ou guet-apens est un\nassassinat.","[CPN] Art. 239 : Le meurtre des père et mère légitimes, naturels ou adoptifs, ou\nde tout autre ascendant légitime, est un parricide.","[CPN] Art. 240 : Le meurtre ou l’assassinat d’un nouveau-né est un infanticide.","[CPN] Art. 241 : Tout attentat à la vie d’une personne par l’effet de substances\nqui peuvent donner la mort plus ou moins promptement, de quelque manière\nque ces substances aient été employées ou administrées, et quelles qu’en\naient été les suites, est qualifié d’empoisonnement.","[CPN] Art. 242 : Tout coupable de meurtre sera puni à l’emprisonnement à vie.\nToutefois, le meurtre emportera la peine de mort :\n1) s’il a été précédé, accompagné ou suivi d’un autre crime;\n2) s’il a eu pour objet, soit de préparer, faciliter ou exécuter un délit, soit de\nfavoriser la fuite ou d’assurer l’impunité des auteurs ou complices de ce\ndélit.","[CPN] Art. 243 : Tout coupable d’assassinat, de parricide ou d’empoisonnement,\nsera puni de mort.\nToutefois, la mère, auteur principal ou complice de l’assassinat de son enfant\nnouveau-né, sera punie d’une peine d’emprisonnement de dix à vingt ans,\nmais sans que cette disposition puisse s’appliquer à ses co-auteurs ou\ncomplices.","[CPN] Art. 244 : Sera punie comme coupable d’assassinat, toute personne qui,\npour l’exécution d’un crime, emploiera des tortures ou commettra des actes\nde barbarie.\n\nCHAPITRE IV : CRIMES ET DELITS EXCUSABLES","[CPN] Art. 245 : Le meurtre ainsi que les blessures et les coups sont excusables :\n1) s’ils ont été provoqués par des coups et violences graves envers les\npersonnes;\n2) s’ils ont été commis en repoussant, pendant le jour, l’escalade ou\nl’effraction des clôtures, murs ou entrée d’une maison ou d’un appartement\nhabité, ou de leurs dépendances.\nToutefois le parricide, le génocide et les crimes contre l’humanité ne sont\njamais excusables, (Loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 246 : Le meurtre commis par un époux sur l’autre, ainsi que sur le\ncomplice, à l’instant où il les surprend en flagrant délit d’adultère dans la\nmaison conjugale, est excusable.","[CPN] Art. 247 : Le crime de castration, s’il a été immédiatement provoqué par\nun outrage violent à la pudeur, est excusable.\nCHAPITRE V : CRIMES ET DELITS CONTRE L’ENFANT ET\nLA FAMILLE\nSection I : Enlèvement, recel, suppression, supposition et\nsubstitution d’enfant, non représentation d’un enfant par la\npersonne chargée de sa garde","[CPN] Art. 248 : Les coupables d’enlèvement, de recel ou de suppression d’enfant,\nde substitution d’un enfant à un autre ou de supposition d’enfant à une\nfemme qui ne sera pas accouchée, seront punis d’un emprisonnement de\ndeux à huit ans.\nLa tentative sera punie comme le délit lui-même.\nS’il n’est pas établi que l’enfant ait vécu, la peine d’emprisonnement sera\nde deux mois à deux ans.\nS’il est établi que l’enfant n’a pas vécu, la peine d’emprisonnement sera de\nquinze jours à deux mois.\n\nCode pénal","[CPN] Art. 249 : Seront punis de la peine prévue à l’alinéa 1 de l’article précédent\nceux qui, étant chargés d’un enfant, ne le représenteront point aux personnes\nqui ont le droit de le réclamer.","[CPN] Art. 250 : Dans les cas prévus aux articles 248, alinéa 1 et 249, le coupable\npourra, conformément aux dispositions de l’article 25, être privé, en tout ou\nen partie des droits mentionnés à l’article 21.\nSection II : Défaut de déclaration de naissance ou de remise d’un\nnouveau-né.","[CPN] Art. 251 : Toute personne ayant assisté à un accouchement et tenue par\nla loi de le déclarer, qui n’en aura pas fait la déclaration à l’autorité\ncompétente dans les délais légaux, sera punie d’un emprisonnement de\ndeux à six mois et d’une amende de 10.000 à 100.000 francs ou de l’une de\nces deux peines seulement.","[CPN] Art. 252 : Toute personne qui, ayant trouvé un enfant nouveau-né, ne\nl’aura pas déclaré à l’autorité compétente, sera punie des peines prévues\nau précédent article.\nSection III : Abandon d’un enfant ou d’un incapable","[CPN] Art. 253 : Ceux qui auront exposé ou fait exposer, délaissé ou fait délaisser,\nen un lieu quelconque, un enfant ou un incapable hors d’état de se protéger\nlui-même en raison de son état physique ou mental seront, de ce seul fait,\ncondamnés à un emprisonnement de trois mois à trois ans et à une amende\nde 20.000 à 200.000 francs.\nS’il résulte de l’exposition ou du délaissement une maladie ou une incapacité\nnon permanente, la peine d’emprisonnement sera de six mois à cinq ans.\nSi l’enfant ou l’incapable est demeuré mutilé ou estropié, ou s’il est resté\natteint d’une incapacité permanente, la peine d’emprisonnement sera de deux\nà moins de dix ans. Lorsque l’exposition ou le délaissement aura occasionné\nla mort, la peine sera celle de l’emprisonnement de dix à trente ans.","[CPN] Art. 254 : Dans le cas prévu à l’alinéa 3 du précédent article, il ne pourra\nêtre fait application des dispositions relatives aux circonstances atténuantes\net au sursis.\n\nDans les cas prévus aux alinéas 1,2 et 3, le coupable pourra, conformément\naux dispositions de l’article 25, être privé, en tout ou en partie, des droits\nmentionnés à l’article 21.\nSection IV : Détournement de mineur","[CPN] Art. 255. § 1 : (Loi n° 63-3 du 1erfévrier 1963). Quiconque aura, par\nfraude ou violence, enlevé ou fait enlever des mineurs de moins de 18 ans,\nou les aura entraînés, détournés ou déplacés, ou les aura fait entraîner,\ndétourner ou déplacer des lieux où ils étaient mis par ceux à l’autorité ou à\nla direction desquelles ils étaient soumis ou confiés, sera puni d’un\nemprisonnement de deux à moins de dix ans.\nLa tentative sera punie comme le délit lui-même.","[CPN] Art. 256 : Si le coupable s’est fait payer ou a eu pour but de se faire payer\nune rançon par les personnes sous l’autorité ou la surveillance desquelles\nle mineur était placé, la peine sera celle de l’emprisonnement à vie.\nToutefois, dans le cas prévu ci-dessus, la peine sera celle d’un\nemprisonnement de dix à trente ans si le mineur est retrouvé vivant avant\nqu’ait été rendu l’arrêt de condamnation.","[CPN] Art. 257 : L’enlèvement emportera la peine de mort s’il a été suivi de la\nmort du mineur.","[CPN] Art. 258. § 1 : (Loi n° 63-3 du 1er février 1963). Celui qui, sans fraude\nni violence aura enlevé ou détourné, ou tenté d’enlever ou de détourner un\nmineur de moins de 18 ans, sera puni d’un emprisonnement de un à cinq\nans et d’une amende de 10.000 à 100.000 francs ou de l’une de ces deux\npeines seulement.\nLorsqu’une mineure ainsi enlevée ou détournée aura épousé son ravisseur,\ncelui-ci ne pourra être poursuivi que sur la plainte des personnes qui ont\nqualité pour demander l’annulation du mariage et ne pourra être condamné\nqu’après que cette annulation aura été prononcée.\n\nSection V : Non représentation d’un enfant sur la garde duquel il a\nété statué par décision de justice.","[CPN] Art. 259 : Quand il aura été statué sur la garde d’un mineur par décision\nde justice, provisoire ou définitive, le père, la mère ou toute autre personne\nqui ne représentera pas ce mineur à ceux qui ont le droit de le réclamer ou\nqui, même sans fraude ou violence, l’enlèvera ou le détournera ou le fera\nenlever ou détourner des mains de ceux auxquels sa garde aura été confiée,\nou des lieux où ces dernières l’auront placé, sera puni d’un emprisonnement\nde deux mois à deux ans et d’une amende de 20.000 à 200.000 francs ou\nde l’une de ces deux peines seulement.\nSection VI : Abandon de famille ou de foyer","[CPN] Art. 260 : (Loi n° 65-42 du 9 septembre 1965). Sera puni d’une peine\nd’emprisonnement de un mois à un an et d’une peine d’amende de 20.000\nà 200.000 francs ou de l’une de ces deux peines seulement:\n1) le père ou la mère de famille qui abandonne, sans motif grave, pendant\nplus de deux mois, la résidence familiale et se soustrait à tout ou partie des\nobligations d’ordre moral ou d’ordre matériel résultant de la puissance\npaternelle ou de la tutelle légale ; le délai de deux mois ne pourra être\ninterrompu que par un retour au foyer impliquant la volonté de reprendre\ndéfinitivement la vie familiale;\n2) le mari qui, sans motif grave abandonne volontairement, pendant\nplus de six mois, sa femme, la sachant enceinte;\n3) le mari qui, sans motif grave abandonne volontairement sa femme\npendant plus d’un an;\n4) la femme qui, sans motif grave ou hors des cas prévus par la coutume,\nabandonne volontairement le domicile conjugal, pendant plus de trois mois ;\n5) les père et mère, que la déchéance de la puissance paternelle soit ou\nnon prononcée à leur égard, qui compromettent gravement par de mauvais\ntraitements, par des exemples pernicieux d’ivrognerie habituelle ou\nd’inconduite notoire, par un défaut de soins ou par un manque de direction\nnécessaire, soit la santé, soit la sécurité, soit la moralité de leurs enfants ou\nd’un ou de plusieurs de ces derniers.\n\nEn ce qui concerne les infractions prévues aux 1°,2°,3° et 4° alinéas du\nprésent article, la poursuite comportera initialement une inte","[CPN] Art. 261 : Sera punie d’un emprisonnement de trois mois à un an et d’une\namende de 20.000 à 200.000 francs, ou de l’une de ces deux peines\nseulement, toute personne qui, en méconnaissance d’une ordonnance ou\nd’un jugement l’ayant condamnée à verser une pension alimentaire à son\nconjoint, à ses ascendants ou à ses descendants, sera volontairement\ndemeurée plus de deux mois sans fournir la totalité des subsides déterminés\npar le juge, ni acquitter le montant intégral de la pension.\nLe défaut de paiement sera présumé volontaire sauf preuve contraire;\nl’insolvabilité qui résulte de l’inconduite habituelle, de la paresse ou de\nl’ivrognerie ne sera en aucun cas un motif d’excuse valable pour le débiteur.\nToute personne, condamnée pour l’un des délits prévus au présent article et à\nl’article précédent, pourra, en outre, conformément aux dispositions de l’article\n25, être privée, en tout ou en partie, des droits mentionnés à l’article 21.\nLe tribunal compétent pour connaître des délits visés au présent article\nsera celui du domicile ou de la résidence de la personne qui doit recevoir la\npension ou bénéficier des subsides.\nSection VII : Infractions aux lois sur les inhumations","[CPN] Art. 262 : Ceux qui auront contrevenu, d’une manière quelconque, aux\nlois et règlements relatifs aux inhumations, seront punis d’un\nemprisonnement de quinze jours à deux mois et d’une amende de 10. 000\nà 100. 000 francs, ou de l’une de ces deux peines seulement.\n\nCode pénal","[CPN] Art. 263 : Quiconque aura recelé ou caché le cadavre d’une personne\nhomicidée ou morte des suites de coups et blessures volontaires, sera puni\nd’un emprisonnement de trois mois à deux ans et d’une amende de 10.000\nà 100.000 francs.","[CPN] Art. 264 : Sera puni d’un emprisonnement de trois mois à deux ans et\nd’une amende de 10.000 à 100.000 francs quiconque se sera rendu coupable\nde violation de tombeaux ou de sépulture.\nLes mêmes peines seront applicables à quiconque aura profané ou mutilé\nun cadavre, même non inhumé.\nDans les cas prévus aux alinéas précédents, il ne pourra être fait application\ndes dispositions relatives aux circonstances atténuantes et au sursis.\nCHAPITRE VI : ATTENTATS A LA LIBERTE INDIVIDUELLE\nSection 1 : Arrestations et séquestrations arbitraires","[CPN] Art. 265 : Seront punis d’un emprisonnement de un à moins de dix ans,\nsans ordre des autorités constituées, et hors les cas où la loi ordonne de\nsaisir des prévenus, auront arrêté, détenu ou séquestré des personnes\nquelconques.\nQuiconque aura prêté un lieu pour exécuter la détention ou séquestration\nsubira la même peine.\nIl ne pourra être fait application pour le présent article des dispositions\nrelatives aux circonstances atténuantes et au sursis.","[CPN] Art. 266 : La peine sera d’un emprisonnement de dix à vingt ans dans\nchacun des cas suivants :\n- si l’arrestation a eu lieu en vertu d’un faux ordre de l’autorité publique;\n- si elle a été exécutée avec un faux costume;\n- si la victime a été arrêtée ou détenue avec menace de mort.","[CPN] Art. 267 : Dans les cas prévus aux articles précédents, si les personnes\narrêtées, détenues ou séquestrées ont été soumises à des tortures\ncorporelles, la peine sera celle de la mort.\n\nCode pénal","[CPN] Art. 268 : la peine sera réduite à celle d’un emprisonnement de six à cinq\nans si les coupables des délits mentionnés à l’article 265, non encore\npoursuivis de fait, ont rendu la liberté à la personne arrêtée, séquestrée ou\ndétenue, avant le dixième jour accompli depuis celui de l’arrestation,\ndétention ou séquestration.\nSection II : Aliénation de la liberté d’autrui","[CPN] Art. 269 : Quiconque aura mis ou reçu une personne en gage, quelqu’en\nsoit le motif, sera puni d’un emprisonnement de deux mois à deux ans et\nd’une amende de 10.000 à 100. 000 francs ou de l’une de ces deux peines\nseulement.\nLa peine d’emprisonnement pourra être portée à cinq ans, si la personne\nmise ou reçue en gage est âgée de moins de treize ans.\nLes coupables pourront en outre, dans tous les cas être privés,\nconformément aux dispositions de l’article 25, des droits mentionnés à\nl’article 21.","[CPN] Art. 270 : Toute personne qui aura aliéné, soit à titre gratuit, soit à titre\nonéreux, la liberté de toute autre personne, sera punie de l’emprisonnement\nde dix à trente ans.\nSi la personne est âgée de moins de treize ans, la peine de l’emprisonnement\nà vie sera encourue.\nSi le coupable a aliéné la liberté de plusieurs personnes, il sera puni de la\npeine de mort.\nSection II bis : De l’esclavage\n(Loi n° 2003-25 du 13 juin 2003).\nParagraphe 1. - Du crime de l’esclavage\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 270. 1 : (Loi n° 2003-25 du 13 juin 2003)L’ « esclavage » est\nl’état ou la condition d’un individu sur lequel s’exercent les attributs du\ndroit de propriété ou certains d’entre eux;\n«L’esclave» est cet individu qui a ce statut ou cette condition.\n\nLa « personne de condition servile» est celle qui est placée dans le statut\nou la condition qui résulte d’une des institutions ou pratiques d’esclavage\nnotamment :\n1) la servitude ou toute autre forme de soumission ou de dépendance\nabsolue à un maître;\n2) toute institution ou pratique en vertu de laquelle :\na) une femme est, sans qu’elle ait le droit de refuser, promise ou donnée\nen mariage moyennant une contrepartie en espèces ou en nature versée\nau maître;\nb) le maître d’une femme considérée comme esclave a le droit de la\ncéder à un tiers, à titre onéreux ou autrement;\nc) le maître a le droit d’entretenir des rapports sexuels avec la femme\nesclave;\n3) toute institution ou pratique en vertu de laquelle un mineur de moins de\ndix-huit ans est remis, soit par ses parents, soit par son tuteur, soit par son\nmaître ou le maître d’un ou de ses deux parents, à un tiers, contre paiement\nou non, en vue de l’exploitation de la personne ou du travail dudit mineur.","[CPN] Art. 270. 2 : (Loi n° 2003-25 du 13 juin 2003)Le fait de réduire autrui\nen esclavage ou d’inciter autrui à aliéner sa liberté ou sa dignité ou celle\nd’une personne à sa charge, pour être réduit en esclavage, est puni d’une\npeine d’emprisonnement de 10 à 30 ans et d’une amende de 1.000.000 à\n5.000.000 de francs.\nEst puni de la même peine prévue à l’alinéa précédent, le fait pour un\nmaître ou son complice :\n1) d’entretenir des rapports sexuels avec une femme considérée esclave\nou l’épouse d’un homme considéré comme esclave;\n2) de mettre à la disposition d’une autre personne une femme considérée\ncomme esclave en vue d’entretenir des rapports sexuels.\nLa complicité et la tentative des infractions prévues aux articles précédents\nsont passibles de la peine prévue au présent article.\n\nParagraphe 2. - Du délit d’esclavage\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 270. 3 : (Loi n° 2003-25 du 13 juin 2003)Constitue le délit\nd’esclavage :\n1) toute atteinte à l’intégrité physique ou morale d’une personne en raison\nde sa condition servile, tout traitement dégradant, inhumain ou humiliant\nexercé contre cette personne;\n2) le fait pour un maître de percevoir les fruits et les revenus résultant de\nla prostitution de la femme de condition servile ou du travail de toute\npersonne de « condition servile»;\n3) l’extorsion de fonds, le chantage exercé à l’encontre d’une personne\nde « condition servile»;\n4) le fait pour un maître de percevoir un tribut d’une personne en raison\ndu droit de propriété qu’il exerce sur cette personne;\n5) l’enlèvement des enfants prétendus esclaves pour les mettre en\nservitude.","[CPN] Art. 270. 4 : (Loi n° 2003-25 du 13 juin 2003)Toute personne reconnue\ncoupable du délit d’esclavage sera punie d’un emprisonnement de cinq à\nmoins de dix ans et d’une amende de 500. 000 à 1.000. 000 de francs.\nLa tentative est punissable de la peine prévue à l’alinéa précédent.\nParagraphe 3. - Du régime commun\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 270. 5 : (Loi n° 2003-25 du 13 juin 2003)Toute association\nrégulièrement déclarée depuis au moins un an à la date des faits et ayant\nen vertu des statuts, comme objectif de combattre l’esclavage ou les\npratiques analogues est habilitée à exercer l’action civile en réparation des\ndommages causés par les infractions à la loi pénale sur l’esclavage.\n\nSection III : Violation de domicile","[CPN] Art. 271 : Tout individu qui se sera introduit, à l’aide de menaces ou de\nviolences, dans le domicile d’une personne, sera puni d’un emprisonnement\nde trois mois à deux ans et d’une amende de 10.000 à 100.000 francs ou de\nl’une de ces deux peines seulement.\nCHAPITRE VII : HOMICIDE ET BLESSURES\nINVOLONTAIRES, DELIT DE FUITE\nSection 1 : Homicide et blessures involontaires","[CPN] Art. 272 : Quiconque, par maladresse, imprudence, inattention, négligence\nou inobservation des règlements, aura involontairement porté des coups ou\noccasionné des blessures ou maladies entraînant une incapacité de travail\npersonnel supérieure à dix jours, sera puni d’un emprisonnement de deux\nmois à un an et d’une amende de 20.000 à 200.000 francs ou de l’une de\nces deux peines seulement.\nSi la mort s’en est suivie, l’emprisonnement sera de trois mois à trois ans et\nl’amende de 20.000 à 200.000 francs.","[CPN] Art. 273 : Si un incendie involontairement provoqué entraîne la mort ou\noccasionne des blessures à une ou plusieurs personnes, il sera fait application\ndes peines prévues à l’article précédent suivant les distinctions qui y sont\nétablies.\nSection II : Délit de fuite","[CPN] Art. 274 : Tout conducteur d’un véhicule qui, sachant que ce véhicule\nvient de causer ou d’occasionner un accident, ne s’est pas arrêté et a ainsi\ntenté d’échapper à la responsabilité civile ou pénale qu’il peut avoir encourue,\nsera, lorsque ledit accident aura entraîné un homicide ou des blessures sur\nla personne d’un ou de plusieurs individus, puni d’un emprisonnement de\nun à moins de dix ans et d’une amende de 50.000 à 500.000 francs.\n\nCHAPITRE VIII : ATTENTATS AUX MŒURS\nSection 1 : Outrage public à la pudeur","[CPN] Art. 275 : Constitue un outrage public à la pudeur tout acte matériel contraire\naux bonnes mœurs commis dans des conditions telles qu’il ait été aperçu\nou pu l’être par des tiers dont il était susceptible de blesser la pudeur.","[CPN] Art. 276 : Toute personne qui aura commis un outrage public à la pudeur\nsera punie d’un emprisonnement de trois mois à trois ans et d’une amende\nde 10.000 à 100.000 francs.\nSection II : Attentats à la pudeur","[CPN] Art. 277 : Constitue un attentat à la pudeur tout acte impudique exercé\ndirectement sur une personne de l’un ou de l’autre sexe.","[CPN] Art. 278 : Tout attentat à la pudeur, consommé ou tenté sans violence sur\nla personne d’un enfant de l’un ou l’autre sexe âgé de moins de treize ans,\nsera puni d’un emprisonnement de deux à moins de dix ans et d’une amende\nde 20.000 à 200.000 francs.","[CPN] Art. 279 : Sera puni des peines mentionnées à l’article précédent l’attentat\nà la pudeur commis par tout ascendant sur la personne d’un mineur âgé de\ntreize à vingt-et-un ans, non émancipé par le mariage.","[CPN] Art. 280 : Quiconque aura commis un attentat, consommé ou tenté avec\nviolence, contre des individus de l’un ou l’autre sexe, sera puni d’un\nemprisonnement de deux à moins de dix ans et d’une amende de 20.000 à\n200.000 francs.\nSi l’attentat a été commis sur un enfant au-dessous de l’âge de treize ans,\nl’emprisonnement sera de dix à vingt ans.","[CPN] Art. 281 : Dans tous les cas prévus à la présente section, les coupables\npourront être, conformément aux dispositions de l’article 25, privés de tout\nou partie des droits mentionnés à l’article 21.\nL’interdiction de séjour pourra, en outre, être prononcée contre les\ncoupables.\n\nSection II bis : Harcèlement sexuel\n(Loi n° 2003-25 du 13 juin 2003)","[CPN] Art. 281.1 : (Loi n° 2003-25 du 13 juin 2003)Le fait de harceler autrui\nen usant d’ordres, de menaces ou de contrainte dans le but d’obtenir des\nfaveurs de nature sexuelle est puni d’un emprisonnement de trois à six\nmois et d’une amende de 10.000 à 100.000 francs.\nSi le harcèlement est le fait d’une personne abusant de l’autorité que lui\nconfèrent ses fonctions, l’emprisonnement sera de trois mois à un an et\nl’amende de 20.000 à 20.000 francs.\nSection III : Actes impudiques sur mineurs de même sexe","[CPN] Art. 282 : Quiconque aura commis un acte impudique ou contre nature avec\nun individu de son sexe, mineur de vingt-et-un an, sera puni d’un emprisonnement\nde six mois à trois ans et d’une amende de 10.000 à 100.000 francs.\nSection IV : Viol","[CPN] Art. 283 : (Loi n° 2003-25 du 13 juin 2003) Tout acte de pénétration\nsexuelle, de quelque nature qu’il soit, commis sur la personne d’autrui par\nviolence, contrainte, menace ou surprise est un viol.","[CPN] Art. 284 : Quiconque aura commis le crime de viol sera puni d’un\nemprisonnement de dix à vingt ans.\nSi le crime a été commis sur la personne d’un enfant au-dessous de l’âge\nde treize ans, le coupable sera puni d’un emprisonnement de quinze à\ntrente ans.\nSection V : Attentat à la pudeur et viol aggravés","[CPN] Art. 285 : Si les coupables d’attentat à la pudeur ou de viol sont ascendants\nde la personne sur laquelle a été commis le délit ou le crime, s’ils sont de\nceux qui ont autorité sur elle, s’ils sont instituteurs, s’ils sont ses serviteurs,\nou serviteurs des personnes ci-dessus désignées, s’ils sont fonctionnaires\nou ministres d’un culte, ou si le coupable, quel qu’il soit, a été aidé par une\nou plusieurs personnes, la peine sera celle d’un emprisonnement de dix à\nvingt ans dans le cas prévu à l’article 278, et d’un emprisonnement à vie\ndans les cas prévus aux articles 280 et 284.\n\nSection VI : Adultère","[CPN] Art. 286 : L’adultère de la femme mariée est le fait par celle-ci d’avoir\ndes relations sexuelles avec un autre homme que son mari.","[CPN] Art. 287 : L’adultère de l’homme est le fait par celui-ci d’avoir des relations\nsexuelles avec une autre femme que sa ou ses épouses légitimes.","[CPN] Art. 288 : L’adultère de la femme ne pourra être dénoncé que par le mari.\nL’adultère du mari ne pourra être dénoncé que par la ou les épouses légitimes.","[CPN] Art. 289 : Le coupable d’adultère sera puni d’un emprisonnement de quinze\njours à trois mois et d’une amende de 10.000 à 100.000 francs ou de l’une\nde ces deux peines seulement.\nLe désistement de l’époux offensé met fin à la poursuite. Son pardon arrête\nl’effet de la condamnation.\nSection VII : Mariage contracté hors les cas prévus par la loi ou la\ncoutume","[CPN] Art. 290 : Quiconque, étant engagé dans les liens de mariage, en aura\ncontracté un autre hors les cas prévus par la loi ou sa coutume, sera puni\nd’un emprisonnement de deux mois à un an et d’une amende de 50.000 à\n500.000 francs, ou de l’une de ces deux peines seulement.\nL’officier public ou l’officiant qui auront sciemment prêté leur ministère à\nce mariage seront punis de la même peine.\nSection VIII : Proxénétisme et excitation à la débauche","[CPN] Art. 291 : Sera considéré comme proxénète et puni d’un emprisonnement\nde six mois à trois ans et d’une amende de 50.000 à 5.000.000 francs, celui\nou celle :\n1) qui, d’une manière quelconque, aide, assiste ou protège sciemment la\nprostitution d’autrui ou le racolage en vue de la prostitution;\n2) qui, sous une forme quelconque, partage les produits de la prostitution\nd’autrui ou reçoit des subsides d’une personne se livrant habituellement à\nla prostitution;\n\n3) qui, sciemment, vit avec une personne se livrant habituellement à la\nprostitution;\n4) qui, étant en relations habituelles avec une ou plusieurs personnes se\nlivrant à la prostitution, ne peut justifier de ressources correspondant à son\ntrain de vie;\n5) qui embauche, entraîne ou entretient, même avec son consentement,\nune personne même majeure, en vue de la prostitution, ou la livre à la\nprostitution ou à la débauche;\n6) qui fait office d’intermédiaire, à un titre quelconque, entre les personnes,\nse livrant à la prostitution ou à la débauche et les individus qui exploitent ou\nrémunèrent la prostitution ou la débauche d’autrui;\n7) qui, par menace, pression, manœuvre ou par tout autre moyen, entrave\nl’action de la prévention de contrôle, d’assistance ou de rééducation,\nentreprise par des organismes qualifiés en faveur de personnes se livrant à\nla prostitution ou en danger de prostitution.","[CPN] Art. 292 : La peine sera d’un emprisonnement de deux à cinq ans et\nd’une amende de 50.000 à 5.000.000 de francs dans le cas où :\n1) le délit a été commis à l’égard d’un mineur ;\n2) le délit a été accompagné de menace, de contrainte, de voies de fait,\nd’abus d’autorité ou de dol;\n3) l’auteur du délit était porteur d’une arme apparente ou cachée;\n4) l’auteur de délit est époux, père, mère ou tuteur de la victime ou\nappartient à l’une des catégories énumérées à l’article 285 ;\n5) l’auteur du délit est appelé à participer, de par ses fonctions, à la\nlutte contre la prostitution, à la protection de la santé, ou au maintien de\nl’ordre public;\n6) le délit a été commis à l’égard de plusieurs personnes;\n7) les victimes du délit ont été livrées ou incitées à se livrer à la prostitution\nhors du territoire de la République;\n\n8) les victimes du délit ont été livrées ou incitées à se livrer à leur arrivée\nou dans un délai rapproché de leur arrivée sur le territoire de la République.\n9) Le délit a été commis par plusieurs auteurs, co-auteurs ou complices.","[CPN] Art. 293 : Sera puni des peines prévues à l’article précédent quiconque\naura attenté aux mœurs en excitant, favorisant ou facilitant habituellement\nla débauche ou la corruption de la jeunesse de l’un ou l’autre sexe, au\ndessous de l’âge de vingt-et-un an ou, même occasionnellement, des mineurs\nde treize ans.\nLes peines prévues aux articles 291 et 292 ainsi qu’au présent article seront\nprononcées, alors que les divers actes qui sont les éléments constitutifs des\ninfractions auront été accomplis dans des pays différents.","[CPN] Art. 294 : Sera puni des peines prévues à l’article 292 tout individu qui\ndétient, directement ou par personne interposée, qui gère, dirige ou fait\nfonctionner un établissement de prostitution ou qui tolère habituellement la\nprésence d’une ou plusieurs personnes se livrant à la prostitution à l’intérieur\nd’un hôtel, maison meublée, pension, débit de boisson, club, circonscription,\ndancing ou lieu de spectacle ou de leurs annexes ou lieu quelconque ouvert\nau public ou utilisé par le public et dont il est le détenteur, le gérant ou le\npréposé. Les mêmes peines sont applicables à toute personne qui assiste\nlesdits détenteurs, gérants ou préposés. En cas de nouvelle infraction dans\nun délai de dix ans, les peines encourues seront portées au double.\nDans tous les cas où les faits incriminés se seront produits dans un\nétablissement visé à l’alinéa précédent, et dont le détenteur, le gérant ou le\npréposé est condamné par application des deux articles précédents ou du\nprésent article, le jugement portera retrait de la licence dont le condamné\nserait bénéficiaire et pourra, en outre, prononcer la fermeture définitive de\nl’établissement.\nLes coupables d’un des délits ou de la tentative d’un des délits mentionnés\naux articles 291, 292, 293 et au présent article pourront être, conformément\naux dispositions de l’article 25, privés de tout ou partie des droits énumérés\nà l’article 21.\nDans tous les cas, les coupables pourront être mis en état d’interdiction de\nséjour.\n\nLes biens mobiliers ","[CPN] Art. 295 : Quiconque, par aliments, breuvages, médicaments, manœuvres,\nviolences ou par tout autre moyen, aura procuré ou tenté de procurer\nl’avortement d’une femme enceinte ou supposée enceinte, qu’elle ait\nconsenti ou non, sera puni d’un emprisonnement de un à cinq ans et d’une\namende de 50.000 à 500.000 francs.\nL’emprisonnement sera de 5 à moins de 10 ans s’il est établi que le coupable\ns’est livré habituellement aux actes visés à l’alinéa précédent, ou si la victime\nest mineure de moins de 16 ans.\nSera punie d’un emprisonnement de six mois à deux ans et d’une amende\nde 20.000 à 200.000 francs la femme qui se sera procuré l’avortement à\nelle-même ou aura tenté de se le procurer ou qui aura consenti à faire\nusage des moyens à elle indiqués ou administrés à cet effet.","[CPN] Art. 296 : Les médecins, sages-femmes, chirurgiens, dentistes,\npharmaciens, ainsi que les étudiants en médecine, les étudiants ou employés\nen pharmacie, herboristes, bandagistes, marchands d’instruments de\nchirurgie, infirmiers, masseurs, qui auront indiqué, favorisé ou pratiqué les\nmoyens de procurer l’avortement, seront condamnés aux peines prévues\naux alinéas 1 et 2 de l’article précédent. La suspension pendant cinq ans\nde l’exercice de leur profession sera, en outre, prononcée contre les\ncoupables.\nQuiconque contrevient à l’interdiction d’exercer sa profession prononcée\nen vertu de l’alinéa précédent sera puni d’un emprisonnement de six mois\nà deux ans et d’une amende de 50.000 à 500.000 francs ou de l’une de ces\ndeux peines seulement.","[CPN] Art. 297 : Dans les cas prévus aux alinéas 1 et 2 de l’article 295 et 296, le\ncoupable pourra en outre être interdit de séjour.\n\nCHAPITRE X : REGLEMENTATION DU COMMERCE ET DU\nPORT DES ARMES\nArt. 298 (nouveau) : (Loi n° 2008-52 du 24 novembre 2008)Hors les\ncas prévus ou autorisés par les règlements ou ceux qui résultent d’un usage\ncoutumier, le port de poignards, stylets, baïonnettes, cannes à épée, cannes\nplombées, casse-têtes et de toutes armes offensives sécrètes ou cachées\nautres que les armes à feu, est interdit sur le territoire de la République.\nTout individu qui sera trouvé porteur desdites armes sera puni d’un\nemprisonnement de trois (3) mois à cinq (5) ans et d’une amende de vingt\nmille (20.000) à deux cent mille (200.000) francs.\nEn outre la confiscation des armes objet de l’infraction sera ordonnée.\nIl pourra toutefois être fait application des dispositions relatives aux\ncirconstances atténuantes et au sursis.\nArt. 299 (nouveau) : (Loi n° 2008-52 du 24 novembre\n2008)L’importation, la vente, le transport, la possession et le port des armes\nà feu ou à air comprimé, des balles, des cartouches et des poudres\nquelconques, ainsi que de tout explosif, sont interdits sur l’étendue du\nterritoire de la République.\nTout individu qui aura importé, vendu, cédé, transporté, détenu ou qui sera\ntrouvé en possession, sur le territoire de la République, des armes, explosifs,\nou munitions ci-dessus énumérés, sera puni d’un emprisonnement de six\n(6) mois à moins de dix (10) ans et d’u","[CPN] Art. 300 : Sauf autorisation de l’autorité publique, la fabrication des\nexplosifs, des armes à feu perfectionnées et des armes à feu dites armes\nde traite, ainsi que celles des pièces détachées desdites armes et des\n\nmunitions, est interdite sur l’étendue du territoire de la République. Les\ncoupables seront punis des peines prévues à l’article précédent et la\nconfiscation des explosifs, des armes, pièces et munitions, objet de\nl’infraction ordonnée.\nCHAPITRE XI : IVRESSE PUBLIQUE ET POLICE DES\nDEBITS DE BOISSONS\nSection 1 : Ivresse publique","[CPN] Art. 301 : Toute personne qui sera trouvée en état d’ivresse manifeste\ndans les rues, chemins, places, cafés, cabarets, ou autres lieux publics,\nsera immédiatement arrêtée et déférée devant le procureur de la République\npour être traduite devant le tribunal correctionnel suivant la procédure de\nflagrant délit.\nElle sera punie d’un emprisonnement de dix jours à deux mois et d’une\namende de 5.000 à 100.000 francs ou de l’une de ces deux peines seulement.\nEn cas de récidive, le coupable pourra, conformément aux dispositions de\nl’article 25, être privé de tout ou partie des droits mentionnés à l’article 21.\nSection II : Police des débits de boissons\nArt. 302 §§ 1 et 2 : (Loi n° 63-3 du 1erfévrier 1963). Seront punis d’un\nemprisonnement de dix jours à six mois et d’une amende de 20.000 à 200.000\nfrancs, ou de l’une de ces deux peines seulement, les cafetiers, cabaretiers,\net autres débitants qui auront donné à boire à des personnes manifestement\nivres ou qui les auront reçues dans leur établissement, ou auront servi des\nspiritueux et des boissons alcoolisées à des mineurs âgés de moins de 18 ans.\nToutefois, dans le cas où le débitant sera prévenu d’avoir servi des spiritueux\nou des boissons alcooliques à un mineur de moins de 18 ans, il pourra\nprouver qu’il a été induit en erreur sur l’âge du mineur. S’il fait cette preuve,\naucune peine ne lui sera applicable de ce chef.","[CPN] Art. 303 : Quiconque vendra au détail à crédit, soit au verre, soit en\nbouteille, des spiritueux et boissons alcooliques à consommer sur place ou\nà emporter, sera puni d’un emprisonnement de dix jours à deux mois et\n\nd’une amende de 20.000 à 200.000 francs ou de l’une de ces deux peines\nseulement.","[CPN] Art. 304 : (Loi n° 2003-25 du 13 juin 2003). Sera punie des peines\nprévues à l’article précédent toute personne qui emploiera dans les débits\nde boissons à consommer sur place des mineurs de moins de 18 ans.","[CPN] Art. 305 : Dans les cas prévus aux articles 302 et 304, la fermeture de\nl’établissement pourra être ordonnée par le tribunal pendant cinq jours au\nmoins et trente jours au plus.\n\nTITRE IV : CRIMES ET DELITS CONTRE LA PROPRIETE\nCHAPITRE PREMIER : VOL\nSection I. Vol simple","[CPN] Art. 306 : Quiconque a soustrait frauduleusement une chose qui ne lui\nappartient pas est coupable de vol.","[CPN] Art. 307 : Le vol simple sera puni d’un emprisonnement de un à trois ans\net d’une amende de 5.000 à 100.000 francs.\nSection II. Vol qualifié","[CPN] Art. 308 : Sera puni d’un emprisonnement de deux à sept ans et d’une\namende de 10.000 à 150.000 francs le vol commis :\n- par le salarié chez son employeur ;\n- ou par des aubergistes, hôteliers, transporteurs, bateliers, ou leurs\npréposés, au préjudice de leurs clients.","[CPN] Art. 309 : Sera puni d’un emprisonnement de deux à sept ans et d’une\namende de 10.000 à 150.000 francs le vol commis avec une des\ncirconstances suivantes :\n1) la nuit ;\n2) en réunion de deux ou plusieurs personnes ;\n3) avec port d’armes;\n4) dans une habitation ou ses dépendances, ou dans des parcs ou enclos,\ndans des véhicules de transports publics;\n5) par effraction, escalade ou usage de fausses clés, dans une habitation\nou ses dépendances, ou prise de faux titres publics, ou usage de faux\ncostumes ou allégation de faux ordres de l’autorité;\n6) avec utilisation d’un véhicule motorisé, d’un chameau ou d’un cheval.\nSi le vol ci-dessus précisé a été commis avec violences et si les violences\nont laissé des traces de blessures ou de contusions, la peine\nd’emprisonnement sera de deux à moins de dix ans.\n\nCode pénal","[CPN] Art. 310 : Lorsque le vol aura été commis avec deux des circonstances\nmentionnées à l’article 309, l’emprisonnement sera de deux à moins de dix ans.\nSi des violences ayant laissé des traces de blessures ou de contusions ont\nété exercées, l’emprisonnement sera de dix à vingt ans.\nLorsque le vol aura été précédé ou suivi de viol la peine de mort sera\nencourue (Loi n° 2003-25 du 13 juin 2003).\nDans le cas prévu à l’alinéa précédent, les dispositions relatives aux\ncirconstances atténuantes ne seront pas applicables (Loi n° 2003-25 du\n13 juin 2003).","[CPN] Art. 311 : Lorsque le vol aura été commis avec trois des circonstances\nmentionnées à l’article 309, l’emprisonnement sera de dix à vingt ans.\nSi des violences ayant laissé des traces de blessures ou de contusions ont\nété exercées, l’emprisonnement sera de quinze à trente ans.","[CPN] Art. 312 : Lorsque le vol aura été commis avec quatre ou plus de\ncirconstances mentionnées à l’article 309, l’emprisonnement à vie sera\nprononcé.\nSi des violences ayant laissé des traces de blessures ou de contusions ont\nété exercées, la peine de mort sera encourue.","[CPN] Art. 313 : La tentative de vol sera punie comme le vol lui-même.","[CPN] Art. 314 : Sont réputés habitation et dépendances, tout bâtiment, logement,\nloge, cabane, même mobile, case, paillote, tente, qui, sans être actuellement\nhabitée, est destinée à l’habitation, et tout ce qui en dépend comme cours,\nbasses-cours, granges, écuries, édifices qui y sont enfermés, quel qu’en\nsoit l’usage et quand même ils auraient une clôture particulière dans la\nclôture ou enceinte générale.","[CPN] Art. 315 : Est réputé parc ou enclos, tout terrain environné de fossés, de\npieux, de claies, de planches, de haies vives ou sèches, ou de murs de\nquelque espèce de matériaux que ce soit, quelles que soient la hauteur, la\nprofondeur, la vétusté, la dégradation de ces diverses clôtures, quand bien\nmême il n’y aurait pas de porte fermée à clé ou autrement ou quand la\nporte serait à claire voie et ouverte habituellement.\n\nCode pénal","[CPN] Art. 316 : Les parcs mobiles destinés à contenir du bétail dans la campagne\nde quelque manière qu’ils soient faits, sont aussi réputés enclos; même\nlorsqu’ils tiennent aux cabanes mobiles ou autres abris destinés aux gardiens,\nils sont réputés dépendants d’une habitation.","[CPN] Art. 317 : Est qualifié d’effraction, tout forcement, rupture, dégradation,\ndémolition, enlèvement de murs, toits, planchers, portes, fenêtres, serrures,\ncadenas ou autres ustensiles ou instruments servant à fermer ou à empêcher\nde passage, et de toute espèce de clôture qu’elle soit.\nLes effractions sont extérieures ou intérieures.\nLes effractions extérieures sont celles à l’aide desquelles on peut\ns’introduire dans les maisons, cours, basses-cours, enclos ou dépendances,\nou dans les appartements ou logements particuliers.\nLes effractions intérieures sont celles qui, après l’introduction dans les\nlieux mentionnés à l’alinéa ci-dessus, sont faites aux portes ou clôtures du\ndedans ainsi qu’aux armoires ou autres meubles fermés.\nEst compris dans la classe des effractions intérieures le simple enlèvement\ndes caisses, boites, ballots sous toile et corde, et autres meubles fermés qui\ncontiennent des effets quelconques, bien que l’effraction n’ait pas été faite\nsur le lieu.","[CPN] Art. 318 : Est qualifié escalade, toute entrée dans les maisons, bâtiments,\ncours, basses-cours, édifices quelconques, jardins, parcs ou enclos, exécutée\npar dessus les murs, portes, toitures, ou toute autre clôture.\nL’entrée par une couverture souterraine autre que celle qui a été établie\npour servir d’entrée est une circonstance de même gravité que l’escalade.","[CPN] Art. 319 : Sont qualifiés fausses clés, tous crochets, rossignols, passepartout, clés imitées, contrefaites, altérées ou qui n’ont pas été destinées\npar les propriétaires, locataires, aubergistes ou logeurs aux serrures, cadenas\nou aux fermetures quelconques auxquelles le coupable les aurait employées.\nQuiconque aura contrefait ou altéré des clés sera condamné à un emprisonnement\nde trois mois à deux ans et à une amende de 10.000 à 100.000 francs. Si le\ncoupable est serrurier de profession, il sera puni d’un emprisonnement de deux à\ncinq ans et d’une amende de 20.000 à 200.000 francs.\n\nCode pénal","[CPN] Art. 320 : Sont considérées comme armes, au sens de l’article 309, celles\ndéfinies à l’article 223.\nSection III : Vol de bétail","[CPN] Art. 321 : Quiconque aura volé ou tenté de voler du bétail, sera puni d’un\nemprisonnement de un à cinq ans et d’une amende de 10.000 à 100.000\nfrancs (Loi n° 2003-25 du 13 juin 2003).\nArt. 322 et 323 : (Abrogés par la loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 324 : (Loi n° 2003-25 du 13 juin 2003) Lorsqu’un vol aura été\ncommis par plusieurs personnes, les causes d’aggravation retenues à l’égard\nd’un des auteurs seront communes à tous les coauteurs et complices.\nLorsque le vol aura été précédé ou suivi de viol, d’enlèvement de femmes,\nd’enfants ou de toute autre personne ou d’usage d’arme à feu la peine de\nmort sera encourue.","[CPN] Art. 325 : Les dispositions relatives aux circonstances atténuantes et au\nsursis sont applicables au prévenu ou à l’accusé lorsqu’il aura restitué\nl’animal volé ou indemnisé effectivement la victime (Loi n° 2003-25 du\n13 juin 2003).\nArt. 326 à 331 : (Abrogés par la loi n° 2003-25 du 13 juin 2003).\nSection IV : Dispositions communes au présent chapitre","[CPN] Art. 332 : Dans tous les cas prévus au présent chapitre, les coupables\npourront être, conformément aux dispositions de l’article 25, privés en tout\nou en partie des droits mentionnés à l’article 21.\nLe tribunal pourra en toutes circonstances, prononcer l’interdiction de séjour.\nCHAPITRE II : ESCROQUERIE","[CPN] Art. 333 : Quiconque, par des manœuvres frauduleuses quelconques, se\nsera fait remettre ou délivrer, ou aura tenté de se faire remettre ou délivrer,\ndes fonds, des meubles ou des obligations, dispositions, billets, promesses,\nquittances ou décharges, et aura ainsi escroqué ou tenté d’escroquer tout\nou partie de la fortune d’autrui, sera puni d’un emprisonnement de un à\ncinq ans et d’une amende de 20.000 à 200.000 francs.\n\nSont considérés comme manœuvres frauduleuses :\n1) le simple usage d’un faux nom ou d’une fausse qualité;\n2) les marchandises, artifices, mises en scène, l’intervention d’un tiers;\n3) les mensonges, même verbaux, lorsqu’ils constituent des tromperies\ndifficiles à vérifier et de nature à abuser une personne normalement prudente\nou même lorsqu’ils émanent de personnes qui, en raison de leurs fonctions\nou de leur position sociale, inspirent le respect, la confiance ou la crainte.","[CPN] Art. 334 : Les peines prévues au précédent article seront applicables à\nquiconque aura, dans le cas de mariage devant être célébré selon la coutume,\ndonné ou promis en mariage une fille dont, selon la coutume, il ne pouvait\npas ou plus disposer et perçu ou tenté de percevoir tout ou partie de la dot\nfixée par la coutume.","[CPN] Art. 335 : Lorsque l’escroquerie aura été commise par une personne ayant\nfait appel au public, en vue de l’émission d’actions, obligations, bons, parts\nou titres quelconques, soit d’une société, soit d’une entreprise commerciale\nou industrielle, l’emprisonnement sera de deux à moins de dix ans et l’amende\nde 100.000 à 5.000.000 francs.","[CPN] Art. 336 : Si l’escroquerie a été commise soit en prenant le titre de\nfonctionnaire ou agent de l’autorité publique, soit en portant indûment un\nuniforme, costume ou insigne, soit en alléguant un faux ordre de l’autorité\npublique, la peine d’emprisonnement sera de deux à moins de dix ans et\nl’amende de 20.000 à 200.000 francs.","[CPN] Art. 337 : Dans tous les cas prévus au présent chapitre, les coupables\npourront, conformément aux dispositions de l’article 25, être privés en tout\nou en partie des droits mentionnés à l’article 21.\nLe tribunal pourra, en outre, prononcer l’interdiction de séjour.\n\nCHAPITRE III (NOUVEAU) : ABUS DE CONFIANCE ET\nDELIT D’INITIE\n(Loi n° 2016-22 du 16 juin 2016)\nSection 1 : Abus de confiance","[CPN] Art. 338 : Quiconque aura frauduleusement détourné ou dissipé un meuble\ncorporel ou une valeur incorporelle, qui lui aura été volontairement remis à\nun titre quelconque, à charge de le restituer ou d’en faire un usage déterminé,\nsera puni d’une peine d’emprisonnement de deux mois à deux ans et d’une\namende de 10.000 à 100.000 francs.\nSi l’abus de confiance a été commis par une personne faisant appel au\npublic, afin d’obtenir soit pour son propre compte, soit comme directeur,\nadministrateur ou agent d’une société ou d’une entreprise commerciale ou\nindustrielle, la remise de fonds ou de valeurs, à titre de dépôt, de mandat ou\nde nantissement, la peine d’emprisonnement sera de deux mois à deux ans\net l’amende de 50.000 à 5.000.000 de francs.\nSi l’abus de confiance prévu et puni par l’alinéa 1 er a été commis par un\nofficier public ou ministériel, ou par un salarié, les peines seront d’un\nemprisonnement de deux à moins de dix ans et d’une amende de 10.000 à\n500.000 francs.","[CPN] Art. 338.1 : (Loi n° 2003-25 du 13 juin 2003). Seront punis d’un\nemprisonnement de deux à moins de dix ans et d’une amende de 100.000\nfrancs à 100.000.000 de francs ou de l’une de ces deux peines seulement,\nle gérant de la société à responsabilité limitée, les administrateurs, le\nprésident-directeur général, le directeur général, l’administrateur général\nou l’administrateur général-adjoint des sociétés anonymes, sociétés d’Etat\net sociétés d’économie mixte qui, de mauvaise foi, font des biens ou du\ncrédit de la société, un usage qu’ils savaient contraire à l’intérêt de celleci, à des fins personnelles, matérielles ou morales, ou pour favoriser une\nautre personne morale dans laquelle ils étaient intéressés, directement ou\nindirectement.","[CPN] Art. 338.2 : (Loi n° 2016-22 du 16 juin 2016) Le délit d’initié est le fait,\npour le président d’une société, les directeurs généraux, les membres du\ndirectoire d’une société, les personnes physiques ou morales exerçant dans\n\ncette société les fonctions d’administrateur ou de membre du conseil de\nsurveillance ainsi que les représentants permanents des personnes morales\nqui exercent ces fonctions, et pour les personnes disposant, à l’occasion de\nl’exercice de leur profession ou de leurs fonctions, d’informations\nprivilégiées sur les perspectives ou la situation d’un émetteur dont les titres\nsont négociés sur un marché réglementé ou sur les perspectives d’évolution\nd’un instrument financier admis sur un marché réglementé, de réaliser ou\nde permettre de réaliser, soit directement, soit par personne interposée,\nune ou plusieurs opérations avant que le public ait connaissance de ces\ninformations.","[CPN] Art. 338.3 : (Loi n° 2016-22 du 16 juin 2016) Le délit d’initié est puni\nde la peine de un (1) an à trois (3) ans d’emprisonnement et d’une amende\nde 25.000.000 de francs à 250.000.000 de francs. Le montant de l’amende\npeut être porté au-delà de ce chiffre, jusqu’au double du montant du profit\néventuellement réalisé, sans que l’amende puisse être inférieure à ce même\nprofit.","[CPN] Art. 338.4 : (Loi n° 2016-22 du 16 juin 2016) Est puni de la peine de\nsix (6) mois à un (1) an d’emprisonnement et d’une amende de 25.000.000\nde francs à 100.000.000 de francs, le fait pour toute personne disposant\ndans l’exercice de sa profession ou de ses fonctions, d’une information\nprivilégiée sur les perspectives ou la situation d’un émetteur dont les titres\nsont négociés sur un marché réglementé ou sur les perspectives d’évolution\nd’un instrument financier admis sur un marché réglementé, de la\ncommuniquer à un tiers en dehors du cadre normal de sa profession ou de\nses fonctions.","[CPN] Art. 338.5 : (Loi n° 2016-22 du 16 juin 2016) Est puni de la peine de\nsix (6) mois à un (1) an d’emprisonnement et d’une amende de 25.000.000\nde francs à 100.000.000 de francs le fait pour toute personne autre que\ncelles visées aux articles 338.2 et 338.4 ci-dessus, possédant en\nconnaissance de cause des informations privilégiées sur la situation ou les\nperspectives d’un émetteur dont les titres sont négociés sur un marché\nréglementé ou sur les perspectives d’évolution d’un instrument financier\nadmis sur un marché réglementé, de réaliser ou de permettre de réaliser,\ndirectement ou indirectement, une opération ou de communiquer à un tiers\nces informations, avant que le public en ait connaissance.\n\nLe montant de l’amende peut être porté au-delà de ce chiffre, jusqu’au\ndouble du montant du profit réalisé, sans que l’amende puisse être inférieure\nà ce même profit.","[CPN] Art. 338.6 : (Loi n° 2016-22 du 16 juin 2016) Les dispositions relatives\nau sursis et aux circonstances atténuantes ne sont pas applicables dans\ntous les cas prévus à la présente section.\nSection II : Abus des besoins d’un mineur","[CPN] Art. 339 : Quiconque aura abusé des besoins d’un mineur, des faiblesses\nou des passions d’un mineur pour lui faire souscrire, à son préjudice, des\nobligations, quittances ou décharges, pour prêt d’argent ou de choses\nmobilières, ou d’effets de commerce, ou de tous autres effets obligatoires,\nsous quelque forme que cette négociation ait été faite ou déguisée, sera\npuni d’un emprisonnement de six mois à trois ans et d’une amende de\n50.000 à 500.000 francs.\nSection III : Abus de blanc-seing","[CPN] Art. 340 : Quiconque, abusant d’un blanc-seing qui lui aura été confié,\naura frauduleusement écrit au-dessus une obligation ou décharge, ou tout\nautre acte pouvant compromettre la personne ou la fortune du signataire,\nsera puni d’un emprisonnement de un à cinq ans et d’une amende de 20.000\nà 200.000 francs.\nSection IV. Dispositions communes","[CPN] Art. 341 : Dans tous les cas prévus au présent chapitre, le coupable,\nconformément aux dispositions de l’article 25, pourra être privé en tout ou\nen partie des droits mentionnés à l’article 21 ; il pourra, en outre être frappé\nde l’interdiction de séjour.\nCHAPITRE IV : IMMUNITE LEGALE","[CPN] Art. 342 : Ne pourront donner lieu qu’à des réparations civiles, les délits\nportant directement atteinte à la propriété commis :\n1) par des maris au préjudice de leurs femmes, par des femmes au\npréjudice de leur mari, par un veuf ou une veuve quant aux choses qui\navaient appartenu à l’époux décédé;\n\n2) par des enfants ou autres descendants au préjudice de leurs pères\nou mères ou autres ascendants, par des pères, mères ou autres ascendants\nau préjudice de leurs enfants ou autres descendants.\nA l’égard de tous autres individus qui auraient recelé ou appliqué à leur\nprofit tout ou partie des objets provenant du délit, ils seront punis comme\ncoupables de recel, conformément à l’article 354.\nCHAPITRE V : EXTORSION DE FONDS ET FILOUTERIES\nSection 1 : Extorsion de titres ou de signature par violence","[CPN] Art. 343 : Quiconque aura extorqué ou tenté d’extorquer par force, violence\nou contrainte, la signature ou la remise d’un écrit, d’un acte, d’un titre,\nd’une pièce quelconque contenant ou opérant obligation, disposition ou\ndécharge, sera puni d’un emprisonnement de deux à moins de dix ans et\nd’une amende de 20.000 à 200.000 francs.\nIl ne pourra en aucun cas être fait application des dispositions relatives aux\ncirconstances atténuantes et au sursis.\nSection II : Chantage","[CPN] Art. 344 : Quiconque, à l’aide de la menace, écrite ou verbale, de révélations\nou d’imputations diffamatoires, aura extorqué ou tenté d’extorquer, soit la remise\nde fonds ou valeurs, soit la signature ou la remise des écrits énumérés à l’article\nprécédent, et se sera rendu ainsi coupable de chantage, sera puni d’un\nemprisonnement de un à cinq ans et d’une amende de 20.000 à 200.000 francs.\nSection III : Détournement et destruction d’objets saisis ou donnés\nen gage","[CPN] Art. 345 : Le saisi qui aura détruit, détourné ou tenté de détruire ou tenté\nde détourner des objets saisis sur lui et confiés à sa garde, sera puni d’un\nemprisonnement de deux mois à deux ans et d’une amende de 20.000 à\n500.000 francs.\nL’emprisonnement sera de un à cinq ans si la garde des objets saisis, et\nqu’il aura détruits ou détournés, ou tenté de détruire ou de détourner, avait\nété confiée à un tiers.\n\nCode pénal","[CPN] Art. 346 : Les peines d’emprisonnement de deux mois à cinq ans et\nd’amende de 10.000 à 500.000 francs seront applicables à tout débiteur,\nemprunteur ou tiers donneur de gage qui aura détruit, détourné ou tenté de\ndétruire ou de détourner des objets par lui donnés à titre de gage.","[CPN] Art. 347 : Celui qui aura recelé sciemment les objets détournés, le conjoint,\nles ascendants et descendants du saisi, du débiteur, de l’emprunteur ou\ntiers donneur de gage qui l’auront aidé dans la destruction, le détournement,\nou dans la tentative de destruction ou de détournement de ces objets, seront\npunis d’une peine égale à celle qu’il aura encourue.\nSection IV : Larcins et filouteries","[CPN] Art. 348 : Quiconque, sachant qu’il est dans l’impossibilité absolue de\npayer, aura consommé des boissons ou aliments ou aura occupé une ou\nplusieurs chambres, dans les établissements à ce destinés, sera puni d’un\nemprisonnement de six jours à six mois et d’une amende de 5.000 à 100.000\nfrancs ou de l’une de ces deux peines seulement.\nSera puni des mêmes peines celui qui, sachant qu’il est dans l’impossibilité\nabsolue de payer, aura utilisé un moyen de transport public.\nSection V : Émission de chèques sans provision","[CPN] Art. 349 : Sera puni d’un emprisonnement de six mois à cinq ans et d’une\namende de 10.000 à 200.000 francs :\n1) celui qui, de mauvaise foi, aura, soit émis un chèque sans provision\npréalable disponible ou avec une provision inférieure au montant du chèque,\nsoit retiré, après l’émission, tout ou partie de la provision, soit fait défense\nau tiré de payer;\n2) celui qui, en connaissance de cause, a accepté de recevoir un chèque\némis dans les conditions visées à l’alinéa précédent.","[CPN] Art. 350 : Sera puni des peines prévues à l’article 355 :\n1) celui qui a contrefait ou falsifié un chèque;\n2) celui qui, en connaissance de cause, a accepté de recevoir un chèque\ncontrefait ou falsifié.\n\nCode pénal","[CPN] Art. 351 : Dans les cas prévus aux articles 349 et 350, lorsqu’il y aura\nrécidive, le coupable sera obligatoirement frappé de l’interdiction de tirer\ndes chèques pendant une durée de trois à cinq ans, qui sera déterminée par\nle tribunal, sur tout établissement bancaire ou assimilé et sur l’administration\ndes postes et télécommunications.\nLes infractions prévues à la présente section seront considérées comme\nétant, au point de vue de la récidive, un même délit.","[CPN] Art. 352 : A l’occasion des poursuites pénales exercées contre le tireur, le\nbénéficiaire qui s’est constitué partie civile est recevable à demander, devant\nles tribunaux répressifs, une somme égale au montant du chèque, sans préjudice\nle cas échéant de tous dommage-intérêts. Il pourra néanmoins, s’il le préfère,\nagir en paiement de sa créance devant la juridiction ordinaire.\nSection VI : Dispositions communes","[CPN] Art. 353 : Dans tous les cas prévus au présent chapitre, le coupable pourra\nêtre privé, conformément aux dispositions de l’article 25, de tout ou partie\ndes droits mentionnés à l’article 21 ; l’interdiction de séjour pourra, en\noutre, être prononcée.\nCHAPITRE VI : RECEL","[CPN] Art. 354 : Le recel est le fait de détenir sciemment, à un titre quelconque,\ndes choses obtenues à l’aide d’un crime ou d’un délit.\nLe receleur sera puni d’un emprisonnement de un à moins de dix ans et\nd’une amende de 20.000 à 200.000 francs.\nLes dispositions relatives aux circonstances atténuantes et au sursis ne\nseront applicables aux receleurs d’un animal volé que dans les conditions\nprévues à l’article 325 ci-dessus(Loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 355 : Dans le cas où une peine afflictive et infamante est applicable\nau fait qui a procuré les choses recelées, le receleur sera puni de la peine\nattachée par la loi au crime et aux circonstances du crime dont il aura eu\nconnaissance au temps du recel.\nNéanmoins, la peine de mort sera remplacée à l’égard des receleurs par\ncelle de l’emprisonnement à vie.\n\nCHAPITRE VII : MAISONS DE JEUX, JEUX DE HASARD,\nLOTERIES, MAISONS DE PRETS SUR GAGES ET DELIT\nD’USURE\nSection 1 : Maisons de jeux","[CPN] Art. 356 : Ceux qui, sans autorisation de l’autorité publique, auront tenu\nune maison de jeux de hasard, et y auront admis le public, soit librement,\nsoit sur présentation des intéressés ou affiliés, les préposés et agents de\ncette maison, seront punis d’un emprisonnement de un à cinq ans et d’une\namende de 50.000 à 5.000.000 de francs.\nLes joueurs seront punis d’un emprisonnement de trois mois à deux ans et\nd’une amende de 5.000 à 100.000 francs.","[CPN] Art. 357 : Des visites, perquisitions et saisies, pourront être opérés à toute\nheure du jour ou de la nuit en vue d’y constater les infractions prévues à\nl’article précédent, à l’intérieur de tout hôtel, maison meublée, pension,\ndébit de boisson, club, cercle et leurs annexes et tout autre lieu ouvert au\npublic ou utilisé par le public, lorsqu’il sera constaté que des personnes\ns’adonnant aux jeux de hasard y sont reçues habituellement.\nSection II : Jeux de hasard sur la voie publique ou dans un lieu\npublic","[CPN] Art. 358 : (Loi n° 2003-25 du 13 juin 2003). Ceux qui, sur la voie\npublique ou dans un lieu public, auront établi ou tenu des jeux de hasard\ncomportant des gains ou des pertes de fonds ou d’effets, seront punis d’un\nemprisonnement de dix jours à deux mois et d’une amende de 20.000 à\n200.000 francs ou de l’une de ces deux peines seulement.\nLes joueurs seront punis des mêmes peines.","[CPN] Art. 359 : Les personnes qui auront contrevenu aux dispositions de l’article\nprécédent seront immédiatement arrêtées et déférées devant le procureur\nde la République pour être traduites devant le tribunal correctionnel suivant\nla procédure de flagrant délit.\n\nSection III : Loteries","[CPN] Art. 360 : Ceux qui, sans autorisation de l’autorité publique2, auront établis\nou tenus des loteries ou tombolas, seront punis d’un emprisonnement de six\nmois à deux ans et d’une amende de 20.000 à 200.000 francs ou de l’une\nde ces deux peines seulement.\nSection IV : Maisons de prêts sur gages","[CPN] Art. 361 : Seront punis d’un emprisonnement de un à cinq ans et d’une\namende de 20.000 à 200.000 francs ceux qui auront établi ou tenu une\nmaison de prêts sur gages ou nantissement, sans autorisation légale, ou qui,\nayant une autorisation, n’auront pas tenu un registre conforme aux\nrèglements contenant de suite, sans aucun blanc ni interligne, les sommes\nou les objets prêtés, les noms, domicile et profession des emprunteurs, la\nnature, la qualité et la valeur des objets mis en nantissement.\nSection V : Dispositions communes","[CPN] Art. 362 : Dans tous les cas prévus aux sections I, II, III et IV du présent\nchapitre, les coupables pourront, conformément aux dispositions de l’article\n25, être privés de tout ou partie des droits mentionnés à l’article 21 ; ils\npourront en outre être frappés de l’interdiction de séjour.","[CPN] Art. 363 : Dans les cas prévus aux sections I, II et III du présent chapitre,\nseront confisqués tous les fonds ou effets qui auront été trouvés exposés\nau jeu ou mis en loterie, les meubles, instruments, ustensiles, appareils\nemployés ou destinés au service des jeux ou des loteries, les meubles et les\neffets mobiliers dont les lieux seront garnis ou décorés.\nSection VI : Délit d’usure\n(Loi n° 2003-25 du 13 juin 2003).","[CPN] Art. 364.1 : (Loi n° 2003-25 du 13 juin 2003). Constitue un prêt usuraire,\ntout prêt ou toute convention dissimulant un prêt d’argent consenti, en toute\nmatière, à un taux effectif global excédant à la date de sa stipulation, le\ntaux de l’usure.\nVoir également le décret n° 64-79/MI du 1er avril 1964, règlementant les conditions\nd’application des dérogations prévues à l’article 360 du Code pénal portant prohibition\ndes loteries (JO n° 7 du 1er avril 1964).\n\nLe taux de l’usure est déterminé par le Conseil des ministres de l’Union\nEconomique et Monétaire Ouest Africaine (UEMOA). Il est publié au\nJournal Officiel ou dans un journal d’annonces légales à l’initiative du\nministre chargé des finances.","[CPN] Art. 364.2 : (Loi n° 2003-25 du 13 juin 2003) Sera puni d’un\nemprisonnement de deux mois à deux ans et d’une amende de 100.000 à\n5.000.000 de francs CFA ou de l’une de ces deux peines seulement,\nquiconque aura consenti à autrui un prêt usuraire ou apporté sciemment, à\nquelque titre et de quelque manière que ce soit, directement ou indirectement\nson concours à l’obtention ou à l’octroi d’un prêt usuraire.\nEn cas de récidive, le maximum de la peine sera porté à cinq ans\nd’emprisonnement et 15.000.000 de francs CFA d’amende.","[CPN] Art. 364.3 : (Loi n° 2003-25 du 13 juin 2003) Outre les peines fixées\npar le précédent article, le tribunal peut ordonner :\n1) la publication de sa décision aux frais du condamné dans les journaux\nqu’il désigne ainsi que toute forme qu’il appréciera ;\n2) la fermeture provisoire ou définitive de l’entreprise qui s’est livrée ou\ndont les dirigeants se sont livrés à des opérations usuraires, assortie de la\nnomination d’un administrateur ou d’un liquidateur.\nEn cas de fermeture provisoire, le délinquant ou l’entreprise doit continuer\nà payer à son personnel, les salaires et indemnités de toutes natures auxquels\ncelui-ci a droit. Cette durée ne peut excéder trois mois.\nEn cas de récidive, la fermeture définitive sera ordonnée.","[CPN] Art. 364.4 : (Loi n° 2003-25 du 13 juin 2003) Sont passibles des peines\nprévues à l’article 364.3 et éventuellement des mesures fixées à l’article\n364.3, ceux qui, chargés à un titre quelconque de la direction ou de\nl’administration d’une entreprise, société, association, coopérative, ou autre\npersonne morale laissent sciemment toute personne soumise à leur autorité\nou leur contrôle contrevenir aux dispositions de la présente section.","[CPN] Art. 364.5 : (Loi n° 2003-25 du 13 juin 2003) La prescription du délit\nd’usure court à compter du jour de la dernière perception soit de l’intérêt,\nsoit du capital, ou de la dernière remise de choses se rattachant à l’opération\nusuraire.\n\nCHAPITRE VIII : BANQUEROUTE","[CPN] Art. 365 : Ceux qui sont déclarés coupables de banqueroute seront punis :\n- les banqueroutiers simples, d’un emprisonnement de un mois à deux ans;\n- les banqueroutiers frauduleux, d’un emprisonnement de un à cinq ans.\nEn outre, les banqueroutiers frauduleux pourront être privés, conformément\naux dispositions de l’article 25, en tout ou en partie, des droits mentionnés\nà l’article 21.","[CPN] Art. 366 : Les complices de banqueroute, simple ou frauduleuse, encourent\nles peines prévues à l’article précédent, même s’ils n’ont pas la qualité de\ncommerçant.\nCHAPITRE IX : VIOLATION DES REGLEMENTS RELATIFS\nAU COMMERCE\nSection 1 : Entraves à la liberté des enchères.","[CPN] Art. 367 : Ceux qui, dans les adjudications publiques, auront entravé ou\ntroublé, tenté d’entraver ou troubler la liberté des enchères ou des\nsoumissions, par voies de fait, violences ou menaces, soit avant soit pendant\nles enchères ou soumissions, seront punis d’un emprisonnement de quinze\njours à trois mois et d’une amende de 50.000 à 500.000 francs, ou de l’une\nde ces deux peines seulement.\nLes mêmes peines seront encourues par ceux qui, par dons, promesses ou\nententes frauduleuses, auront écarté ou tenté d’écarter les enchérisseurs,\nlimité ou tenté de limiter les enchères ou soumissions, ainsi que par ceux\nqui auront reçu ces dons ou accepté ces promesses.\nSeront punis des mêmes peines tous ceux qui, après une adjudication\npublique, procéderont ou participeront à une remise aux enchères sans le\nconcours d’un officier ministériel compétent.\nSection II : Entraves à la liberté du travail","[CPN] Art. 368 : Sera puni d’un emprisonnement de quinze jours à trois ans et\nd’une amende de 10.000 à 100.000 francs ou de l’une de ces deux peines\nseulement, quiconque, à l’aide de violences, voies de fait, menaces ou\n\nmanœuvres frauduleuses, aura amené ou maintenu, tenté d’amener ou de\nmaintenir une cessation concertée du travail.\nL’interdiction de séjour pourra, en outre, être prononcée contre le ou les\ncoupables.\nSection III : Révélation de secrets de fabrique","[CPN] Art. 369 : Tout directeur, agent salarié d’une fabrique, qui aura communiqué ou\ntenté de communiquer à des étrangers ou à des nigériens résidant en pays étranger,\ndes secrets de la fabrique où il est employé, sera puni d’un emprisonnement de\ndeux à cinq ans et d’une amende de 50.000 à 500.000 francs.\nLe coupable en outre, pourra être privé, conformément aux dispositions de\nl’article 25, en tout ou en partie des droits mentionnés à l’article 21.\nSi ces secrets ont été communiqués à des Nigériens résidant au Niger, la\npeine sera d’un emprisonnement de trois mois à deux ans et d’une amende\nde 20.000 à 200.000 francs.\nSection IV : Actions illicites sur le marché","[CPN] Art. 370 : Tous ceux :\n1) qui, par des faits faux ou calomnieux semés sciemment dans le public,\npar des offres jetées sur le marché à dessein de troubler les cours, par des\nsuroffres faites au prix que demandaient les vendeurs eux-mêmes, par des\nvoies ou moyens frauduleux quelconques.\n2) ou qui, en exerçant ou tentant d’exercer, soit individuellement, soit par\nréunion ou coalition, une action sur le marché, dans le but de se procurer un\ngain qui ne serait pas le résultat du jeu naturel de l’offre et de la demande.\nAuront, directement ou par personne interposée, opéré ou tenté d’opérer\nla hausse ou la baisse artificielle du prix des denrées ou marchandises, ou\ndes effets publics ou privés, seront punis d’un emprisonnement de deux\nmois à deux ans et d’une amende de 100.000 à 1.000.000 de francs ou de\nl’une de ces deux peines seulement.\nLe tribunal pourra, en outre, prononcer contre les coupables la peine de\nl’interdiction de séjour.\n\nCode pénal","[CPN] Art. 371 : Dans le cas prévu à l’article précédent, le tribunal ordonnera\nque le jugement de condamnation soit publié intégralement ou par extraits\ndans les journaux qu’il désignera et affiché dans les lieux qu’il indiquera.\nLe tribunal fixera le temps pendant lequel cet affichage devra être maintenu\nsans que la durée en puisse excéder quinze jours.\nSection V : Contrefaçon de brevets et d’œuvres","[CPN] Art. 372 : Constitue le délit de contrefaçon, toute édition d’écrits, de\ncompositions musicales, de dessins, de peintures ou de toute autre production,\nimprimée ou gravée en entier ou en partie, au mépris des lois et règlements\nrelatifs à la propriété des auteurs.\nLa contrefaçon, sur le territoire nigérien, d’ouvrages publiés au Niger ou à\nl’étranger, est punie d’un emprisonnement de quinze jours à six mois et d’une\namende de 50.000 à 500.000 francs ou de l’une de ces deux peines seulement.\nSeront punis des mêmes peines le délit, l’exportation et l’importation des\nouvrages contrefaits.","[CPN] Art. 373 : Est également un délit de contrefaçon toute reproduction,\nreprésentation ou diffusion, par quelque moyen que ce soit, d’une œuvre\nde l’esprit, en violation des droits de l’auteur, tels qu’ils sont définis et\nréglementés par la loi.","[CPN] Art. 374 : Toute atteinte au droit du bénéficiaire d’un brevet d’invention,\nsoit par la fabrication de produits, soit par l’emploi de moyens faisant l’objet\nde son brevet, constitue le délit de contrefaçon et sera punie des peines\nprévues à l’article 372.","[CPN] Art. 375 : La peine d’emprisonnement sera de trois mois à deux ans, s’il\nest établi que le coupable s’est livré, habituellement, aux actes visés aux\ntrois articles précédents.\nEn cas de récidive, après condamnation prononcée en vertu de l’alinéa\nprécédent, la fermeture temporaire ou définitive des établissements exploités\npar le contrefacteur d’habitude, ou ses complices, pourra être prononcée.\nLorsque cette mesure de fermeture aura été prononcée, le personnel devra\nrecevoir une indemnité égale à son salaire, augmentée de tous les avantages\nen nature, pendant la durée de la fermeture et au plus pendant six mois.\n\nSi les conventions collectives ou particulières prévoient, après licenciement,\nune indemnité supérieure, c’est celle-ci qui sera due.\nToute infraction aux dispositions des deux alinéas précédents sera punie d’un\nemprisonnement de un à six mois et d’une amende de 10.000 à 100.000 francs.","[CPN] Art. 376 : Dans tous les cas prévus par les articles 372, 373, 374 et 375,\nles coupables seront, en outre, condamnés à la confiscation de sommes\négales au montant des parts de recettes produites par la reproduction, la\nreprésentation et la diffusion illicite ainsi qu’à la confiscation de tout matériel\nspécialement installé en vue de la reproduction illicite et de tous les\nexemplaires et objets contrefaits.\nLe tribunal pourra ordonner, à la requête de la partie civile, la publication\ndes jugements de condamnation, intégralement ou par extraits, dans les\njournaux qu’il désignera et l’affichage desdits jugements dans les lieux\nqu’il indiquera.\nLe matériel ou les exemplaires contrefaits, ainsi que les recettes ou parts\nde recettes ayant donné lieu à confiscation seront remis à la partie lésée ou\nà ses ayants-droit pour les indemniser d’autant du préjudice qu’ils auront\nsouffert; le surplus de leur indemnité ou l’entière indemnité s’il n’y a eu\naucune confiscation de matériel, d’objets contrefaits ou de recettes, sera\nréglé par les voies ordinaires.","[CPN] Art. 377 : Dans tous les cas prévus au présent chapitre, le ministère public\nne pourra agir que sur la plainte de la partie lésée.\nTITRE IV (BIS) : DES INFRACTIONS RELATIVES AU DROIT\nOHADA (Loi n° 2017-10 du 31 mars 2017)","[CPN] Art. 377.1 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’une peine\nd’emprisonnement de deux (2)à moins de dix (10) ans et d’une amende de\ncent mille (100 000) à un million (1 000 000) de francs :\n- quiconque promet, offre ou accorde, directement ou indirectement, un\navantage indu à toute personne qui dirige une entité du secteur privé ou\ntravaille pour une telle entité, en quelque qualité que ce soit, pour lui-même\nou pour une autre personne, afin que, en violation de ses devoirs, elle\naccomplisse ou s’abstienne d’accomplir un acte ;\n\n- tout dirigeant ou travailleur d’une entité du secteur privé qui sollicite, accepte,\ndirectement ou indirectement, un avantage indu, pour lui-même ou pour une\nautre personne, afin d’accomplir ou s’abstenir d’accomplir un acte en\nviolationde ses devoirs.","[CPN] Art. 377.2 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’un\nemprisonnement de deux (2 ) à moins de dix (10) ans et d’uneamende de\ncent mille (100 000) à cent millions (100 000 000) de francs, ou de l’une de\nces deux peines seulement, le gérant de la société à responsabilité limitée,\nles administrateurs, le président directeur général, le directeur général,\nl’administrateur général ou l’administrateur général adjoint qui, de mauvaise\nfoi, font des biens ou du crédit de la société, un usage qu’ils savaient contraire\nà l’intérêt de celle-ci, à des fins personnelles, matérielles ou morales, ou\npour favoriser une autre personne morale dans laquelle ils étaient intéressés\ndirectement ou indirectement.","[CPN] Art. 377.3 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’un\nemprisonnement de trois (3) à moins de dix (10) ans et d’une amende de\ndeux millions (2 000 000) de francs à dix millions (10 000 000) de francs, le\nfait pour les fondateurs, le président-directeur général, le directeur général,\nl’administrateur général ou l’administrateur général adjoint d’une société\nanonyme d’émettre des actions avant l’immatriculation ou à n’importe quelle\népoque lorsque l’immatriculation est obtenue par fraude ou que la société\nest irrégulièrement constituée.","[CPN] Art. 377.4 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement de trois (3) à moins de dix (10) ans et d’une amende de\ndeux millions (2 000 000) de francs à dix millions (10 000 000) de francs :\n- ceux qui, sciemment par l’établissement de la déclaration notariée de\nsouscription et de versement ou du certificat du dépositaire, auront affirmé\nsincères et véritables des souscriptions qu’ils savaient fictives ou auront\ndéclaré que les fonds qui n’ont pas été mis définitivement à la disposition de\nla société ont été effectivement versés ;\n- ceux qui auront remis au notaire ou au dépositaire, une liste des actionnaires\nou des bulletins de souscription et de versement mentionnant des souscriptions\nfictives ou des versements de fonds qui n’ont pas été mis définitivement à\nla disposition de la société ;\n\n- ceux qui, sciemment par simulation de souscription ou de versement ou\npar publication de souscription ou de versement qui n’existent pas ou de\ntous autres faits faux, auront obtenu ou tenté d’obtenir des souscriptions ou\ndes versements ;\n- ceux qui, sciemment pour provoquer des souscriptions ou des versements\nauront publié les noms de personnes désignées contrairement à la vérité\ncomme étant ou devant être attachées à la société à un titre quelconque ;\n- ceux qui, frauduleusement auront fait attribuer à un apport en nature, une\névaluation supérieure à sa valeur réelle.","[CPN] Art. 377.5 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende de un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs, ceux qui auront\nsciemment négocié :\n- des actions nominatives qui ne sont pas demeurées sous la forme nominative\njusqu’à leur entière libération ;\n- des actions d’apport avant l’expiration du délai pendant lequel elles ne\nsont pas négociables ;\n- des actions de numéraire pour lesquelles le versement du quart du nominal\nn’a pas été effectué.","[CPN] Art. 377.6 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement de trois (3) à moins de dix (10) ans et une amende de un\nmillion (1 000 000) de francs à cinq millions (5 000 000) de francs, les\ndirigeants sociaux qui, en l’absence d’inventaire ou au moyen d’inventaire\nfrauduleux, auront sciemment opéré entre les actionnaires ou les associés\nla répartition de dividendes fictifs.","[CPN] Art. 377.7 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement de trois (3) ans à moins de dix (10) ans et d’une amende\nde cinq millions (5 000 000) de francs à vingt millions (20 000 000) de\nfrancs, les dirigeants sociaux qui auront sciemment, même en l’absence de\ntoute distribution de dividendes, publié ou présenté aux actionnaires ou\nassociés, en vue de dissimuler la véritable situation de l’entreprise, des états\nfinanciers de synthèse ne donnant pas, pour chaque exercice, une image\n\nfidèle des opérations de l’exercice, de la situation financière et de celle du\npatrimoine de la société à l’expiration de cette période.","[CPN] Art. 377.8 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement de deux (2) mois à un (1) an et d’une amende de cinq cent\nmille (500 000) francs à cinq millions (5 000 000) de francs ou de l’une de\nces deux peines seulement, ceux qui, sciemment auront empêchéun\nactionnaire ou un associé de participer à une assemblée générale.","[CPN] Art. 377.9 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement d’ un (1) à moins de dix (10) ans et d’une amende de cinq\ncent mille (500 000) francs à cinq millions (5 000 000) de francs, les\nadministrateurs, le président du conseil d’administration, le président directeur\ngénéral, le directeur général, l’administrateur général ou l’administrateur\ngénéral adjoint d’une société anonyme qui, lors d’une augmentation de\ncapital, auront émis des actions ou des coupures d’actions :\n- avant que le certificat du dépositaire ait été établi ;\n- sans que les formalités préalables à l’augmentation de capital aient été\nrégulièrement accomplies ;\n- sans que le capital antérieurement souscrit de la société ait été intégralement\nlibéré ;\n- sans que les nouvelles actions d’apport aient été intégralement libérées avant\nl’inscription modificative au registre du commerce et du crédit mobilier ;\n- sans que les nouvelles actions aient été libérées d’un quart au moins de\nleur valeur nominale au moment de la souscription ;\n- le cas échéant, sans que l’intégralité de la prime d’émission ait été libérée\nau moment de la souscription.\nLes mêmes peines sont également applicables aux personnes visées au\nprésent article qui n’auront pas maintenu les actions de numéraire sous\nforme nominative jusqu’à leur entière libération.","[CPN] Art. 377.10 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs, les dirigeants\nsociaux qui, lors d’une augmentation de capital :\n\n- n’auront pas fait bénéficier les actionnaires, proportionnellement au montant\nde leurs actions, d’un droit préférentiel de souscription des actions de\nnuméraire, lorsque ce droit n’a pas été supprimé par l’assemblée générale\net que les actionnaires n’y ont pas renoncé ;\n- n’auront pas fait réserver aux actionnaires un délai de vingt (20) jours au\nmoins, à dater de l’ouverture de la souscription, sauf lorsque ce délai a été\nclos par anticipation ;\n- n’auront pas attribué les actions rendues disponibles, faute d’un nombre\nsuffisant de souscription à titre irréductible, aux actionnaires qui ont souscrit à\ntitre réductible un nombre d’actions supérieur à celui qu’ils pouvaient souscrire\nà titre irréductible, proportionnellement aux droits dont ils disposent ;\n- n’auront pas réservé les droits des titulaires de bons de souscription.\nSont punis d’un emprisonnement d’un (1) à cinq (5) ans et d’une amende\nde un million (1 000 000) de francs à dix millions (10 000 000) de francs, les\ndirigeants sociaux qui, sciemment, auront donné ou confirmé des indications\ninexactes dans les rapports présentés à l’assemblée générale appelée à\ndécider de la suppression du droit préférentiel de souscription.","[CPN] Art. 377.11 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs, les\nadministrateurs, le président-directeur général, le directeur général,\nl’administrateur général ou l’administrateur général adjoint qui, sciemment,\nauront procédé à une réduction de capital :\n- sans respecter l’égalité des actionnaires ;\n- sans avoir communiqué le projet de réduction de capital aux commissaires\naux comptes, quarante-cinq (45) jours avant la tenue de l’assemblée générale\nappelée à statuer sur la réduction de capital.","[CPN] Art. 377.12 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement d’un (1) à trois (3) ans et d’une amende d’un million (1 000 000)\nde francs à dix millions (10 000 000) de francs, les dirigeants sociaux qui\nn’auront pas provoqué la désignation des commissaires aux comptes de la\nsociété ou ne les auront pas convoqué aux assemblées générales.\n\nCode pénal","[CPN] Art. 377.13 : (Loi n° 2017-10 du 31 mars 2017) Est punie d’un\nemprisonnement de deux (2) à cinq (5) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs, toute personne\nqui, soit en son nom personnel, soit à titre d’associé d’une société de\ncommissaires aux comptes,aura sciemment accepté, exercé ou conservé des\nfonctions de commissaires aux comptes nonobstant les incompatibilités légales.","[CPN] Art. 377.14 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’un\nemprisonnement de deux (2) à cinq (5) ans et d’une amende d’un million\n(1 000 000) de francs à dix millions (10 000 000) de francs, tout commissaire\naux comptes qui, soit en son nom personnel, soit à titre d’associé d’une\nsociété de commissaires aux comptes, aura sciemmentdonné ou confirmé\ndes informations mensongères sur la situation de la société ou qui n’aura\npas révélé au ministère public les faits délictueux dont il aura eu connaissance.","[CPN] Art. 377.15 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs, les dirigeants\nsociaux ou toute personne au service de la société qui, sciemmentauront\nfait obstacle aux vérifications ou au contrôle des commissaires aux comptes\nou quiauront refusé la communication, sur place, de toutes les pièces utiles\nà l’exercice de leur mission et notamment de tous contrats, livres, documents\ncomptables et registres de procès-verbaux.","[CPN] Art. 377.16 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement de six (6) moisà deux (2) ans et d’une amende de cinq\ncent mille (500 000) francs à cinq millions (5 000 000) de francs ou l’une de\nces deux peines seulement, les dirigeants sociaux qui, sciemment, lorsque\nles capitaux propres de la société deviennent inférieurs à la moitié du capital\nsocial du fait des pertes constatées dans les états financiers de synthèse :\n- n’auront pas fait convoquer dans les quatre (4) mois qui suivent l’approbation\ndes états financiers de synthèse ayant fait apparaître ces pertes, l’assemblée\ngénérale extraordinaire à l’effet de décider, s’il y a lieu de la\ndissolutionanticipée de la société ;\n- n’auront pas déposé au greffe du tribunal chargé des affaires\ncommerciales, inscritauregistre du commerce et du crédit mobilier et publié\ndans un journal habilité à recevoir les annonces légales, la dissolution\nanticipée de la société.\n\nCode pénal","[CPN] Art. 377.17 : (Loi n° 2017-10 du 31 mars 2017)Est puni d’un\nemprisonnement de deux (2) à cinq (5) ans et d’une amende de deux millions\n(2 000 000) de francs à cinq millions (5 000 000) de francs ou de l’une de\nces deux peines seulement, le liquidateur d’une société qui, sciemment :\n- n’aura pas, dans le délai d’un (1) mois à compter de sa nomination, publié\ndans un journal habilité à recevoir les annonces légales du lieu du siège\nsocial, l’acte le nommant liquidateur et déposé au registre du commerce et\ndu crédit mobilier, les décisions prononçant la dissolution ;\n- n’aura pas convoqué les associés, en fin de liquidation, pour statuer sur le\ncompte définitif de la liquidation, sur le quitus de sa gestion et la décharge\nde son mandat et pour constater la clôture de la liquidation ;\n- n’aura pas déposé ses comptes définitifs au greffe du tribunal chargé des\naffaires commerciales du lieu du siège social, ni demandé en justice\nl’approbationde ceux-ci.","[CPN] Art. 377.18 : (Loi n° 2017-10 du 31 mars 2017)Est puni d’un\nemprisonnement de deux (2) à cinq (5) ans et d’une amende de deux millions\n(2 000 000) de francs à cinq millions (5 000 000) de francs ou de l’une de\nces deux (02) peines seulement, lorsque la liquidation intervient sur décision\njudiciaire, le liquidateur qui sciemment :\n- n’aura pas, dans les six (6) mois de sa nomination, présenté un rapport sur\nla situation active et passive de la société en liquidation et sur la poursuite\ndes opérations de liquidation, ni sollicité les autorisations nécessaires pour\nles terminer ;\n- n’aura pas, dans les trois (3) mois de la clôture de chaque exercice, établi\nles états financiers de synthèse au vu de l’inventaire et un rapport écrit\ndans lequel il rend compte des opérations de la liquidation au cours de\nl’exercice écoulé ;\n- n’aura pas permis aux associés d’exercer, en période de liquidation, leur\ndroit de communication des documents sociaux dans les mêmes conditions\nqu’antérieurement ;\n- n’aura pas convoqué les associés, au moins une (1) fois par an, pour leur\nrendre compte des états financiers de synthèse en cas de continuation de\nl’exploitation sociale ;\n\n- n’aura pas déposé à un compte ouvert dans une banque au nom de la\nsociété en liquidation, dans le délai de quinze (15) jours à compter de la\ndécision de répartition, les sommes affectées aux répartitions entre les\nassociés et les créanciers ;\n- n’aura pas déposé, sur un compte de consignation ouvert dans les écritures\nde la ","[CPN] Art. 377.19 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’un\nemprisonnement de cinq (5) à moins de (10) ans et d’une amende de deux\nmillions (2 000 000) de francs à vingt millions (20 000 000) de francs, le\nliquidateur qui, de mauvaise foi :\n- aura fait des biens ou du crédit de la société en liquidation, un usage qu’il\nsavait contraire à l’intérêt de celle-ci, à des fins personnelles ou pour favoriser\nune autre personne morale dans laquelle il était intéressé, directement ou\nindirectement ;\n- aura cédé tout ou partie de l’actif de la société en liquidation à une personne\nayant eu dans la société la qualité d’associé en nom collectif, de commandité,\nde gérant, de membre du conseil d’administration, d’administrateur général\nou de commissaire aux comptes, sans avoir obtenu le consentement unanime\ndes associés ou, à défaut, l’autorisation de la juridiction compétente.","[CPN] Art. 377.20 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’une peine\nd’emprisonnement de cinq (5) à moins de dix (10) ans et d’une amende\nd’un million (1 000 000) de francs à six millions (6 000 000) de francs, tout\nsyndic d’une procédure collective qui :\n- exerce une activité personnelle sous le couvert de l’entreprise du débiteur\nmasquant ses agissements ;\n- dispose du crédit ou des biens du débiteur comme des siens propres ;\n- dissipe les biens du débiteur ;\n- poursuit abusivement et de mauvaise foi, dans son intérêt personnel, soit\ndirectement, soit indirectement, une exploitation déficitaire de l’entreprise\ndu débiteur ;\n\n- participe, à quelque titre que ce soit, à l’administration de toute procédure\ncollective ;\n- se rend acquéreur pour son compte directementou indirectement,des biens\nen violation des interdictions légales.","[CPN] Art. 377.21 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’un\nemprisonnement de cinq (5) à moins de dix (10) ans et d’une amende de\ncinq cent mille (500 000) francs à un million cinq cent mille (1 500 000)\nfrancs au plus, tout créancier qui a :\n- stipulé avec le débiteur ou avec toutes personnes, des avantages particuliers\nen raison de son vote dans les délibérations de la masse ;\n- fait un traité particulier duquel il résulterait en sa faveur un avantage à la\ncharge de l’actif du débiteur à partir du jour de la décision d’ouverture de la\nprocédure collective.","[CPN] Art. 377.22 : (Loi n° 2017-10 du 31 mars 2017) Sont punis d’un\nemprisonnement de deux (2) mois à deux (2) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs ou l’une de ces deux\npeines seulement, les présidents, les administrateurs ou les directeurs généraux\nde société qui auront émis des valeurs mobilières offertes au public :\n- sans qu’une notice soit insérée dans le journal habilité à recevoir les\nannonces légales, préalablement àtoute mesure de publicité ;\n- sans que les prospectus et les circulaires reproduisent les énonciations de\nla notice prévue au tiret ci-dessus etcontiennent la mention de l’insertion de\ncette notice au journal habilité à recevoir les annonces légales avec référence\nau numéro dans lequel elle a été publiée ;\n- sans que les affiches et les annonces dans les journaux reproduisent les\nmêmes énonciations ou, tout au moins, un extrait de ces énonciations avec\nréférence à ladite notice et indications du numéro du journal habilité à recevoir\nles annonces légales dans lequel elle a été publiée ;\n- sans que les affiches, les prospectus et les circulaires mentionnent la\nsignature de la personne ou du représentant de la société de laquelle l’offre\némane et précisent si les valeurs offertes sont cotées ou non et, dans\nl’affirmative, à quelle bourse.\n\nLa même sanction pénale sera applicable aux personnes qui ont servi\nd’intermédiaires à l’occasion de la cession de valeurs mobilières sans qu’aient\nété respectées les presc","[CPN] Art. 377.23 : (Loi n° 2017-10 du 31 mars 2017) Est coupable de\nbanqueroute simple, toute personne physique en état de cessation de\npaiements qui se trouve dans l’un des cas suivants :\n- si, elle a contracté sans recevoir des valeurs en échange, des engagements\njugés trop importants eu égard à sa situation lorsqu’elle les a contractés ;\n- si, dans l’intention de retarder la constatation de la cessation de paiements,\nelle a fait des achats en vue d’une revente au-dessous du cours ou si, dans\nla même intention, elle a employé des moyens ruineux pour se procurer des\nfonds ;\n- si, sans excuse légitime, elle ne fait pas au greffe de la juridiction compétente\nla déclaration de son état de cessation de paiements dans le délai de trente\n(30) jours ;\n- si, sa comptabilité est incomplète ou irrégulièrement tenue ou si elle n’a\ntenu aucune comptabilité conforme aux règles comptables et aux usages\nreconnus de la profession eu égard à l’importance de l’entreprise ;\n- si, ayant été déclarée deux fois en état de cessation de paiements dans un\ndélai de cinq (5) ans, ces procédures ont été clôturées pour insuffisance\nd’actif.","[CPN] Art. 377.24 : (Loi n° 2017-10 du 31 mars 2017) Est coupable de\nbanqueroute frauduleuse, toute personne physique commerçante ou associée\ndes sociétés commerciales qui a la qualité de commerçant, en cas de\ncessation de paiements qui :\n- a soustrait sa comptabilité ;\n- a détourné ou dissipé tout ou partie de son actif ;\n- s’est frauduleusement reconnue débitrice des sommes qu’elle ne devait\npas,soit dans ses écritures, soit par des actes publics ou des engagements\nsous seing privé, soit dans son bilan ;\n\n- a exercé la profession commerciale contrairement à une interdiction prévue\npar les lois et règlements ;\n- a payé un créancier au préjudice de la masse après la cessation de\npaiements ;\n- a stipulé avec un créancier des avantages particuliers en raison de son\nvote dans la délibération de la masse ou qui a fait avec un créancier un\ntraité particulier duquel il résulterait, pour ce dernier, un avantage à la charge\nde l’actif du débiteur à partir du jour de la décision d’ouverture.","[CPN] Art. 377.25 : (Loi n° 2017-10 du 31 mars 2017) Est également coupable\nde banqueroute frauduleuse, tout commerçant, toute personne physique ou\ntoute personne associée des sociétés commerciales qui a la qualité de\ncommerçant, qui à l’occasion d’une procédure de règlement judiciaire a :\n- de mauvaise foi, présenté ou fait présenter un compte de résultats ou un\nbilan ou un état des créances et des dettes ou un état actif et passif des\nprivilèges et sûretés, inexact ou incomplet ;\n- sans autorisation du président de la juridiction compétente, accompli un\ndes actes interdits ci-dessous ;\n- payé, en tout ou en partie, les créances nées antérieurement à la décision\nde suspension des poursuites individuelles de la décision de règlement\npréventif ;\n- fait un acte de dispositionétranger à l’exploitationnormale de l’entreprise\nou a consenti une sûreté ;\n- désintéressé les cautions qui ont acquitté les créances nées antérieurement\nàla décision de suspension de la poursuite individuelle.","[CPN] Art. 377.26 : (Loi n° 2017-10 du 31 mars 2017) Peuvent être coupables\nd’infractions assimilées aux banqueroutes :\n- les personnes physiques dirigeantes de personnes morales assujetties aux\nprocédures collectives ;\n- les personnes physiques représentantes permanentes de personnes morales\ndirigeantes, des personnes morales assujetties aux procédures collectives.\n\nLes dirigeants visés au présent article s’entendent de tous les dirigeants de\ndroit ou de fait et, d’une manière générale, de toute personne ayant directement\nou par personne interposée, administré, géré ou liquidé la personne morale\nsous le couvert ou en lieu et place de ses représentants légaux.","[CPN] Art. 377.27 : (Loi n° 2017-10 du 31 mars 2017) Sont punis des peines\nde banqueroute simple, les dirigeants visés à l’article 377.26 ci-dessus qui\nont, en cette qualité et de mauvaise foi :\n- consommé des sommes appartenant à la personne morale en faisant des\nopérations de pur hasard ou des opérations fictives ;\n- fait des achats en vue d’une revente en dessous du cours ou, dans la\nmême intention, employé des moyens ruineux pour se procurer des fonds\ndans l’intention de retarder la constatation de la cessation de paiements de\nla personne morale ;\n- payé ou fait payer un créancier au préjudice de la masse après cessation\nde paiements de la personne morale ;\n- fait contracter par la personne morale, pour le compte d’autrui, sans qu’elle\nreçoive de valeurs en échange, des engagements jugés trop importants eu\négard à sa situation lorsque ceux-ci ont été contractés ;\n- tenu ou fait tenir ou laissé tenir irrégulièrement ou incomplètement la\ncomptabilité de la personne morale dans les conditions prévues à l’article\n377.23, 4ème tiret ;\n- omis de faire au greffe de la juridiction compétente, dans le délai de trente (30)\njours, la déclaration de l’état de cessation de paiements de la personne morale ;\n- détourné ou dissimulé, tenté de détourner ou de dissimuler une partie de\nleurs biens ou qui se sont frauduleusement reconnus débiteurs de sommes\nqu’ils ne devaient pas, en vue de soustraire tout ou partie de leur patrimoine\naux poursuites de la personne morale en état de cessation de pa","[CPN] Art. 377.28 : (Loi n° 2017-10 du 31 mars 2017) Pour les personnes\nmorales comportant des associés indéfiniment et solidairement responsables\ndes dettes de celles-ci, les représentants légaux ou de fait sont coupables\nde banqueroute simple si, sans excuse légitime, ils ne font pas au greffe de\n\nla juridiction compétente, dans le délai de trente (30) jours, la déclaration de\nleur état de cessation de paiements ou si cette déclaration ne comporte pas\nla liste des associés solidaires avec l’indication de leurs noms et domiciles.","[CPN] Art. 377.29 : (Loi n° 2017-10 du 31 mars 2017) Sont punis des peines\nde banqueroute frauduleuse, les dirigeants visés aux articles 377.24 et 377.25\nci-dessus qui ont frauduleusement :\n- soustrait les livres de la personne morale ;\n- détourné ou dissimulé une partie de son actif ;\n- reconnu la personne morale débitrice de sommes qu’elle ne devait pas,\nsoit dans les écritures, soit par des actes publics ou des engagements sous\nsignature privée, soit dans le bilan ;\n- exercé la profession de dirigeant contrairement à une interdiction prévue\npar les Actes uniformes de l’OHADA ou par la loi et les règlements ;\n- stipulé avec un créancier, au nom de la personne morale, des avantages\nparticuliers à raison de son vote dans les délibérations de la masse ou qui\nont fait avec un créancier un traité particulier duquel il résulterait pour ce\ndernier un avantage à la charge de l’actif de la personne morale, à partir du\njour de la décision déclarant la cessation de paiement.\nSont également punis des peines de banqueroute frauduleuse, les dirigeants\nvisés à l’article 377.27 ci-dessus qui, à l’occasion d’une procédure de\nrèglement préventif, ont :\n- de mauvaise foi, présenté ou fait présenter un compte de résultats ou un\nbilan ou un état des créances et des dettes ou un état actif et passif des\nprivilèges et sûretés, inexact ou incomplet ;\n- sans autorisation du président de la juridiction compétente, ont violé\nl’interdiction de la décision de règlement préventif ;\n- en payant en tout ou en p","[CPN] Art. 377.30 : (Loi n° 2017-10 du 31 mars 2017) Sont punies des peines\nde banqueroute frauduleuse :\n- les personnes convaincues d’avoir, dans l’intérêt du débiteur, soustrait,\nrecelé ou dissimulé tout ou partie de ses biens meubles ou immeubles, le\ntout sans préjudice des dispositions pénales relatives à la complicité ;\n- les personnes convaincues d’avoir frauduleusement produit dans la\nprocédure collective, soit en leur nom, soit par interposition ou supposition\nde personne, des créances supposées ;\n- les personnes qui, faisant le commerce sous le nom d’autrui ou sous un\nnom supposé, ont de mauvaise foi, détourné ou dissimulé, tenté de détourner\nou de dissimuler une partie de leurs biens.","[CPN] Art. 377.31 : (Loi n° 2017-10 du 31 mars 2017) Les coupables de\nbanqueroute sont punis comme suit :\n- les banqueroutiers simples, d’un emprisonnement de deux (2) à cinq (5) ans\net d’une amende decinq cent mille (500 000) à deux millions (2 000 000) de\nfrancs ;\n- les banqueroutiers frauduleux, d’un emprisonnement de cinq (5) à moins\nde dix (10) ans et d’une amende de deux millions (2 000 000) de francs à\ncinq millions (5 000 000) de francs.\nEn outre, l’interdiction des droits mentionnés à l’article 21 du code pénal\npourra être prononcée à l’encontre des banqueroutiers frauduleux.","[CPN] Art. 377.32 : (Loi n° 2017-10 du 31 mars 2017) Le conjoint, les\ndescendants, les ascendants ou les collatérauxdu débiteur ou ses alliés qui,\nà l’insu du débiteur auraient détourné, diverti ou recelé des effets dépendants\nde l’actif du débiteur en état de cessation de paiements encourent les peines\nprévues à l’article précédent.","[CPN] Art. 377.33 : (Loi n° 2017-10 du 31 mars 2017) Les complices de\nbanqueroute, simple ou frauduleuse, encourent les peines prévues à l’article\n377.31 ci-dessus suivant le cas, même s’ils n’ont pas la qualité de commerçant.","[CPN] Art. 377.34 : (Loi n° 2017-10 du 31 mars 2017) Les agents de change\nreconnus coupables de banqueroute simple sont punis des peines de\nbanqueroute frauduleuse.\n\nLorsqu’ils sont reconnus coupables de banqueroute frauduleuse, ils sont\npunis d’un emprisonnement de dix (10)à vingt (20) ans.\nEn outre, l’interdiction des droits mentionnés à l’article 21 du code pénal\npourra être prononcée à leur encontre.","[CPN] Art. 377.35 : (Loi n° 2017-10 du 31 mars 2017) Est punie d’un\nemprisonnement de six (6) mois à trois (3) ans et d’une amende de cinq\ncent mille (500 000) francs à un million (1 000 000) de francs, toute personne\nqui a commencé à organiser son insolvabilité avant qu’une action judiciaire\nne soit déclenchée contre elle ou qui a continué à organiser ladite insolvabilité\nau cours du procès en vue de se soustraire à l’exécution de la condamnation\npécuniaire ou de nature patrimoniale qui pourrait être rendue à son encontre.\nElle encourt les mêmes peines lorsque l’insolvabilité organisée intervient\ndans un délai d’un (1) an à compter du prononcé de la décision judiciaire.\nLe tribunal peut décider que la personne condamnée comme complice de\nl’infraction définie ci-dessus sera tenue solidairement, dans la limite des\nfonds ou de la valeur vénale des biens reçus à titre gratuit ou onéreux, aux\nobligations pécuniaires résultant de la condamnation à l’exécution de laquelle\nl’auteur de l’infraction a voulu se soustraire.\nLorsque ces obligations résultent d’une condamnation pénale, le tribunal\npourra décider que la peine qu’il prononce ne se confondra pas avec celle\nprécédemment prononcée.\nLa prescription de l’action publique ne court qu’à compter de la condamnation\nà l’exécution de laquelle le débiteur a voulu se soustraire ou, s’ils lui sont\npostérieurs, des derniers agissements ayant pour objet d’organiser ou\nd’aggraver l’insolvabilité du débiteur.","[CPN] Art. 377.36 : (Loi n° 2017-10 du 31 mars 2017) Est punie d’une peine\nd’amende de cinq cent mille (500 000) francs à un million (1 000 000) de\nfrancs, toute personne qui :\n- s’est abstenue dans le premier mois d’exploitation de son commerce, de\nrequérir du greffe de la juridiction compétente son immatriculation au registre\nde commerce ;\n\n- s’est abstenue dans le délai de trente (30) jours de requérir les inscriptions\nmodificatives complémentaires dans le cadre de son commerce notamment,\nsur son état civil, son régime matrimonial, sa capacité ou sur le statut de la\npersonnemorale intervenue dans lecadre de son commerce ;\n- s’est abstenue dans le délai d’un (1) mois à compter de la cessation de son\nactivité commerciale de demander sa radiation du registre de commerce et\nde crédit mobilier ou en cas de décès, lorsque ses ayants-droit se sont\nabstenus dans le délai de trois (3) mois à compter dudit décès, de demander\nla radiation de l’inscription au registre ou sa modification s’ils doivent euxmêmes continuer l’exploitation.","[CPN] Art. 377.37 : (Loi n° 2017-10 du 31 mars 2017) Est punie d’un\nemprisonnement de six (6) mois à trois (3) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs,toute personne\nqui effectue une inscription de sûreté mobilière par fraude ou portant des\nindications inexactes données de mauvaise foi.\nLe tribunal peut ordonner, en prononçant la condamnation, la rectification\nde la mention inexacte dans les termes qu’il détermine.\nEst puni de la même peine le locataire-gérant qui n’a pas indiqué en tête de\nses bons de commande, factures et autres documents à caractère financier\nou commercial, avec son numéro d’immatriculation au registre de commerce\net de crédit mobilier, sa qualité de locataire-gérant d’un fondsde commerce.","[CPN] Art. 377.38 : (Loi n° 2017-10 du 31 mars 2017) Est punie d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende d’un million\n(1 000 000) de francs à cinq millions (5 000 000) de francs, toute personne\nqui a, par des manœuvres frauduleuses, privé le créancier nanti, de ses\ndroits ou les a diminués.","[CPN] Art. 377.39 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende d’un million (1\n000 000) de francs à cinq millions (5 000 000) de francs,le débiteur ou toute\npersonne qui aura, par des manœuvres frauduleuses, totalement ou\npartiellement, privé le bailleur de son privilège sur les meubles garnissant\nles lieux loués.\n\nCode pénal","[CPN] Art. 377.40 : (Loi n° 2017-10 du 31 mars 2017)Sont punis d’un\nemprisonnement de six (6) mois à deux (2) ans et d’une amende de cinq\ncent mille (500 000) francs à deux millions (2 000 000) de francs, les\nentrepreneurs individuels et les dirigeants sociaux qui :\n- n’ont pas, pour chaque exercice social, dressé l’inventaire et établi les\nétats financiers annuels ainsi que, le cas échéant, le rapport de gestion et le\nbilan social ;\n- ont sciemment, établi et communiqué des états financiers ne délivrant pas\nune image fidèle du patrimoine, de la situation financière et du résultat de\nl’exercice.","[CPN] Art. 377.41 : (Loi n° 2017-10 du 31 mars 2017) Est puni d’une amende\nde cinq cent mille (500 000) francs à cinq millions (5 000 000) de francs,\ntout agent public en fonction, qui a sciemment omis de déclarer toutes\nactivités extérieures, tout emploi, tous placements, tous avoirs et tous dons\nou avantages substantiels susceptibles d’entraîner un conflit d’intérêt avec\nses fonctions sans préjudice des sanctions disciplinaires.","[CPN] Art. 377.42 : (Loi n° 2017-10 du 31 mars 2017)Est puni d’un\nemprisonnement d’un (1) à cinq (5) ans et d’une amende de cinq millions\n(5 000 000) de francs à cinquante millions (50 000 000) de francs, tout\nagent publicqui prend ou reçoit, directement ou indirectement, un intérêt\nquelconque dans une entreprise ou dans une opération dont il a, au moment\nde l’acte, la charge d’assurer la surveillance, l’administration, la liquidation\nou le paiement.","[CPN] Art. 377.43 : (Loi n° 2017-10 du 31 mars 2017) Est punie d’une amende\nde cinq millions (5 000 000) de francs à dix millions (10.000.000) de francs\ntoute personne qui, ayant été chargée en tant qu’agent public d’assurer la\nsurveillance ou le contrôle d’une entreprise privée, ou de conclure des\ncontrats avec une telle entreprise, y prend ou reçoit un intérêt avant\nl’expiration d’un délai de cinq (5) ans suivant la cessation de ses fonctions.\nCet intérêt consiste en une participation par travail, conseil ou capitaux\ndans l’entreprise ou dans une entreprise qui possède au moins trente pour\ncent (30%) du capital commun avec cette entreprise.\n\nTITRE V : DESTRUCTIONS ET DEGRADATIONS\nCHAPITRE PREMIER : INCENDIE ET DESTRUCTION\nVOLONTAIRES","[CPN] Art. 378 : Quiconque aura volontairement mis le feu à des édifices,\nmagasins, chantiers, véhicules de transports publics, terrestres, fluviaux et\naériens, et généralement aux lieux habités ou servant d’habitation, qu’ils\nappartiennent ou non à l’auteur du crime, sera puni d’un emprisonnement\nde dix à vingt ans.","[CPN] Art. 379 : Quiconque aura volontairement mis le feu ou tenté de mettre le\nfeu aux édifices, magasins, chantiers, lorsqu’ils ne sont ni habités, ni servant\nà l’habitation, ou à des forêts, bois, taillis ou récoltes sur pied, lorsqu’ils ne\nlui appartiennent pas, sera puni d’un emprisonnement de deux à moins de\ndix ans et d’une amende de 10.000 à 200.000 francs.","[CPN] Art. 380 : Celui qui, en mettant ou en faisant mettre le feu, ou en tentant\nde le mettre à l’un des objets énumérés à l’article précédent, et à lui-même\nappartenant, aura volontairement causé un préjudice quelconque à autrui,\nsera puni d’en emprisonnement de un à cinq ans et d’une amende de 10.000\nà 100.000 francs.\nSera puni des mêmes peines celui qui aura mis le feu sur l’ordre du\npropriétaire.","[CPN] Art. 381 : Quiconque aura volontairement mis le feu, ou tenté de le mettre,\nsoit à des pailles ou récoltes en tas ou en meules, soit à des bois disposés\nen tas ou en stères, soit à des véhicules, qui ne lui appartiennent pas, sera\npuni d’un emprisonnement de un à cinq ans et d’une amende de 10.000 à\n100.000 francs.","[CPN] Art. 382 : Celui qui, en mettant ou en faisant mettre le feu, ou en tentant\nde le mettre à l’un des objets énumérés à l’article précédent et à lui-même\nappartenant, aura volontairement causé un préjudice quelconque à autrui,\nsera puni d’un emprisonnement de six mois à trois ans et d’une amende de\n10.000 à 100.000 francs.\nSera puni des mêmes peines celui qui aura mis le feu sur l’ordre du\npropriétaire.\n\nCode pénal","[CPN] Art. 383 : Celui qui aura communiqué l’incendie à l’un des objets énumérés\naux articles précédents, en mettant ou en tentant de mettre volontairement\nle feu à des objets quelconques appartenant soit à lui, soit à autrui et placés\nde manière à communiquer ledit incendie, sera puni de la même peine que\ns’il avait mis le feu directement à l’un desdits objets.","[CPN] Art. 384 : Dans tous les cas où l’incendie volontairement provoqué aura\nentraîné la mort d’une ou de plusieurs personnes, la peine sera celle d’un\nemprisonnement à vie.\nS’il en est résulté une amputation, mutilation, privation de l’usage d’un\nmembre, cécité ou perte d’un œil, ou autres infirmités permanentes, la\npeine sera celle d’un emprisonnement de dix à trente ans.","[CPN] Art. 385. : (Loi n° 63-3 du 1er février 1963) Les peines seront les\nmêmes, suivant les distinctions faites aux articles précédents, contre ceux\nqui, volontairement, auront détruit en tout ou en partie ou tenté de détruire\npar l’effet de toutes substances explosibles, les édifices, habitations,\nmagasins ou chantiers ou leurs dépendances, digues, ponts, voies privées\nou publiques, véhicules de toute nature et généralement tous objets mobiliers\nou immobiliers de quelque nature qu’ils soient.\nLe dépôt dans une intention criminelle, sur la voie publique ou privée, d’un\nengin explosif, est puni d’un emprisonnement de dix à vingt ans.","[CPN] Art. 386 : La menace d’incendier ou de détruire par l’effet de toutes\nsubstances explosibles les objets compris dans l’énumération de l’article\nprécédent, sera punie des peines édictées pour les menaces contre les\npersonnes et d’après les distinctions établies par les articles 233, 234, 235\net 236.","[CPN] Art. 387 : Dans tous les cas prévus au présent chapitre, l’interdiction de\nséjour sera prononcée, et le coupable pourra être privé en tout ou en partie\ndes droits mentionnés à l’article 21.\n\nCHAPITRE II : INCENDIE INVOLONTAIRE DE MAISON\nHABITEE OU SERVANT A L’HABITATION.","[CPN] Art. 388 : Quiconque aura, par maladresse, imprudence, négligence ou\ninobservation des règlements, involontairement causé l’incendie d’une maison\nhabitée ou servant à l’habitation ou de ses dépendances, appartenant à autrui,\nsera puni d’un emprisonnement de quinze jours à deux mois et d’une amende\nde 5.000 à 100.000 francs ou de l’une de ces deux peines seulement.\nCHAPITRE III : DESTRUCTION D’EDIFICES ET\nDEGRADATIONS DE MONUMENTS PUBLICS","[CPN] Art. 389 : Quiconque aura volontairement détruit ou renversé, ou tenté de\ndétruire ou de renverser, par quelque moyen que ce soit en tout ou en\npartie, des édifices, ponts, digues, voies publiques ou privées ou autres\nconstructions qu’il savait appartenir à autrui, sera puni d’un emprisonnement\nde deux à moins de dix ans et d’une amende de 10.000 à 100.000 francs;\nl’interdiction de séjour sera en outre prononcée.\nLe coupable pourra être privé, conformément aux dispositions de l’article\n25, en tout ou en partie, des droits mentionnés à l’article 21.\nSi la destruction ou le renversement ont entraîné mort d’homme, le coupable\nsera puni de la peine d’emprisonnement à vie; s’il en est résulté une\namputation, mutilation, privation de l’usage d’un membre, cécité ou perte\nd’un œil ou autres infirmités permanentes, la peine sera celle d’un\nemprisonnement de dix à trente ans.\nCHAPITRE IV : BRIS DE CLÔTURE ET ENLEVEMENT DE\nBORNES","[CPN] Art. 390 : Quiconque aura volontairement, en tout ou en partie, comblé\ndes fossés, coupé ou arraché des haies vives ou sèches;\nQuiconque aura déplacé ou supprimé des bornes ou pieds corniers ou autres\narbres plantés ou reconnus pour établir les limites entre différentes\npropriétés;\nSera puni d’un emprisonnement de six mois à deux et d’une amende 10.000\nà 100.000 francs ou de l’une de ces deux peines seulement.\n\nCHAPITRE V : DEGRADATION DE VEHICULES","[CPN] Art. 391 : Quiconque, volontairement, aura dégradé, par un moyen\nquelconque, en tout ou en partie, un véhicule quel qu’il soit, appartenant à\nautrui, sera puni d’un emprisonnement de un à cinq ans et d’une amende\nde 10.000 à 100.000 francs, sans préjudice des dispositions relatives aux\narticles 378, 381 et 385, s’il échet.\nLa tentative du délit prévu au présent article sera punie comme le délit luimême.\nCHAPITRE VI : DESTRUCTION DE TITRES","[CPN] Art. 392 : Quiconque aura volontairement brûlé ou détruit, d’une manière\nquelconque, des registres, minutes ou actes originaux de l’autorité publique,\ndes titres, billets, lettres de change, effets de commerce ou de banque,\ncontenant ou opérant obligation, disposition ou décharge ;\nQuiconque aura sciemment détruit, soustrait, recelé, dissimulé ou altéré un\ndocument public ou privé de nature à faciliter la recherche de crimes ou\ndélits, la découverte des preuves, ou le châtiment de leur auteur, sera, sans\npréjudice des peines plus graves prévues par la loi, puni ainsi qu’il suit :\n- si les pièces détruites sont des actes de l’autorité publique ou des effets\nde commerce ou de banque, la peine sera celle d’un emprisonnement de\ndeux à moins de dix ans, et d’une amende de 20.000 à 200.000 francs;\n- s’il s’agit de toute autre pièce, le coupable sera puni d’un emprisonnement\nde un à cinq ans et d’une amende de 10.000 à 100.000 francs.\nDans le cas prévu à l’alinéa 3 du présent article, le coupable pourra être\nprivé, conformément aux dispositions de l’article 25, en tout et en partie\ndes droits mentionnés à l’article 21. L’interdiction de séjour pourra être\nprononcée.\n\nCHAPITRE VII : DESTRUCTION D’OBJETS MOBILIERS ET\nDE RECOLTES","[CPN] Art. 393 : Tout pillage, tout dégât d’objets mobiliers, effets, denrées ou\nmarchandises, grain, farine et toutes autres substances alimentaires, vins\nou autres boissons, sera puni d’un emprisonnement de six mois à deux ans,\net d’une amende de 5.000 à 100.000 francs.\nSi le pillage ou le dégât a été commis en réunion ou en bande et à force\nouverte, la peine d’emprisonnement sera de deux à moins de dix ans.\nNéanmoins ceux qui prouveront avoir été entraînés par des provocations\nou sollicitations à prendre part à des violences, pourront n’être punis que\nde l’emprisonnement de un à cinq ans, et d’une amende de 5.000 à 100.000\nfrancs.","[CPN] Art. 394 : Quiconque, à l’aide d’une liqueur ou substance corrosive, ou\npar tout autre moyen, aura volontairement détérioré des marchandises,\nmatières ou instruments quelconques servant à la fabrication ou résultant\nde la fabrication, sera puni d’un emprisonnement de trois mois à deux ans\net d’une amende de 50.000 à 500.000 francs.\nSi le délit a été commis par un ouvrier de fabrique ou par un employé de la\nmaison de commerce, l’emprisonnement sera de deux à cinq ans.","[CPN] Art. 395 : Quiconque aura dévasté des récoltes sur pied ou des plants\nvenus naturellement ou faits de main d’homme, sera puni d’un\nemprisonnement de un à cinq ans et d’une amende de 10.000 à 100.000\nfrancs.\nQuiconque aura coupé des grains ou fourrages qu’il savait appartenir à\nautrui, sera puni d’un emprisonnement de trois à six mois et d’une amende\nde 10.000 à 100.000 francs.\nL’emprisonnement sera de six mois à un an s’il a coupé du grain en vert ou\nsi le fait a été commis la nuit.","[CPN] Art. 396 : Toute rupture, toute destruction d’instrument agricole, de parc\nà bestiaux, de cabane de gardien, sera puni d’un emprisonnement de deux\nmois à deux ans et d’une amende de 10.000 à 100.000 francs.\n\nCHAPITRE VIII : ABATTAGE ET MUTILATION D’ARBRES","[CPN] Art. 397 : Quiconque aura abattu, brûlé, mutilé, coupé ou écorcé de manière\nà les faire périr un ou plusieurs arbres qu’il savait appartenir à autrui, sera\npuni d’un emprisonnement de trois mois à un an et d’une amende de 10.000\nà 100.000 francs ou de l’une de ces deux peines seulement.\nSi le ou les arbres étaient plantés sur les places, routes, chemins, rues ou\nvoies publiques, la peine d’emprisonnement sera de six mois à deux ans.\nCHAPITRE IX : DOMMAGES AUX ANIMAUX","[CPN] Art. 398 : Quiconque aura volontairement empoisonné des chevaux ou\nautres bêtes de voiture, de monture ou de charge, des bestiaux à cornes,\ndes moutons, chèvres ou porcs ou des poissons dans les étangs, viviers ou\nréservoirs, sera puni d’un emprisonnement de un à cinq ans et d’une amende\nde 5.000 à 100.000 francs, ou de l’une de ces deux peines seulement.","[CPN] Art. 399 : Ceux qui auront, sans nécessité, en quelque lieu que ce soit, tué\ndes chevaux ou autres bêtes de voiture, de monture ou de charge, des\nbestiaux à cornes, des moutons, chèvres ou porcs ou des poissons dans les\nétangs, viviers ou réservoirs, appartenant à autrui.\n(Loi n° 2003-25 du 13 juin 2003). Ceux qui auront, sans nécessité, tué\nun animal domestique dans un lieu dont celui à qui cet animal appartient est\npropriétaire, locataire, ou fermier, seront punis d’un emprisonnement de\nquinze jours à six mois et d’une amende de 5.000 à 100.000 francs ou de\nl’une de ces deux peines seulement.\n\nTITRE VI (NOUVEAU) : DU TERRORISME ET DU\nFINANCEMENT DU TERRORISME\n(Ord. n° 2011-12 du 27 janvier 2011)\nCHAPITRE PREMIER : DU DETOURNEMENT\nD’AERONEFS, DE NAVIRES, DE PLATES-FORMES FIXES ET\nDE VEHICULES TERRESTRES ET FLUVIAUX\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1 : (Loi n° 2003-25 du 13 juin 2003) Toute personne qui, par\nviolence ou menace de violence, s’empare d’un aéronef ou en exerce le\ncontrôle sera punie d’un emprisonnement de dix à vingt ans.\n- S’il est résulté de ces actes des blessures ou maladies, la peine sera celle\nde vingt à trente ans.\n- S’il en est résulté la mort de l’une ou de plusieurs personnes, la peine de\nmort sera prononcée.\nDans le cas prévu à l’alinéa premier la peine sera réduite à l’emprisonnement\nde cinq à moins de dix ans, si le coupable restitue spontanément le contrôle\nde l’aéronef à son commandant ou aux autorités légitimes.\nCHAPITRE II : DES INFRACTIONS CONTRE LA SECURITE\nDE L’AVIATION CIVILE, DES TRANSPORTS TERRESTRES\nET FLUVIAUX\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.1 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie d’un\nemprisonnement de deux (2) à sept (7) ans et d’une amende de cinq cent\nmille (500 000) à cinq millions (5 000 000) francs CFA, toute personne qui,\nillicitement et intentionnellement :\na) se livre à un acte de violence à l’encontre d’une personne se trouvant à\nbord d’un aéronef en vol ou au sol, des services d’un aéroport si cet acte\nest de nature à compromettre la sécurité de cet aéronef ;\nb) se livre à un acte de violence à l’encontre d’une personne se trouvant à\nbord d’un véhicule terrestre ou fluvial ;\n\nc) communique une information qu’elle sait être fausse, et de ce fait,\ncompromet la sécurité d’un aéronef en vol.","[CPN] Art. 399.1.2 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie d’un\nemprisonnement de cinq (5) à moins de dix (10) ans et d’une amende de un\nmillion cinq cent mille (1 500 000) à cinq millions (5 000 000) francs CFA,\ntoute personne qui, illicitement et intentionnellement :\na) détruit ou cause des dommages à un aéronef, que celui-ci soit en service\nou non, qui le rendent inapte au vol ou qui sont de nature à compromettre\nsa sécurité en vol ;\nb) place ou fait placer sur un aéronef en service, par quelque moyen que\nce soit, un dispositif ou des substances propres à détruire ledit aéronef ou à\nlui causer des dommages qui le rendent inapte au vol ou qui sont de nature\nà compromettre sa sécurité en vol ;\nc) détruit ou endommage des installations ou services de navigation aérienne\nou en perturbe le fonctionnement, si l’un de ces actes est de nature à\ncompromettre la sécurité d’un aéronef en vol ;\nd) détruit ou cause des dommages à un véhicule terrestre ou fluvial, que\ncelui-ci soit en service ou non, qui le rendent inapte à l’usage auquel il est\ndestiné ou qui sont de nature à compromettre sa sécurité;\ne) place ou fait placer sur un véhicule, par quelque moyen que ce soit, un\ndispositif ou des substances propres à détruire ledit véhicule ou à lui causer\ndes dommages qui le rendent inapte à l’usage auquel il est destiné ou qui\nsont de nature à compromettre la sécurité des personnes ou des biens ;\nf) détruit ou endommage des installations ou équipements publics ou privés\nou en perturb","[CPN] Art. 399.1.3 : (Ord. n° 2011-12 du 27 janvier 2011) Toute personne\nqui, illicitement et intentionnellement, à l’aide d’un dispositif, d’une substance\nou d’une arme se livre à l’encontre d’une autre personne, dans un aéroport\nservant à l’aviation civile internationale ou toute autre installation publique\nou privée, à un acte de violence qui cause ou est de nature à causer des\nblessures graves ou la mort, sera punie de la peine de mort si cet acte est\nde nature à compromettre la sécurité dans cet aéroport ou dans cette\ninstallation.","[CPN] Art. 399.1.4 : (Ord. n° 2011-12 du 27 janvier 2011) Toute personne\nqui, illicitement et intentionnellement,à l’aide d’un dispositif, d’une substance\nou d’une arme détruit ou endommage gravement les installations d’un\naéroport servant à l’aviation civile internationale ou en interrompt les services\nsera punie de quinze (15) à trente (30) ans d’emprisonnement si cet acte\nest de nature à compromettre la sécurité dans cet aéroport.","[CPN] Art. 399.1.5 : Toute personne qui, illicitement et intentionnellement, à\nl’aide d’un dispositif, d’une substance ou d’une arme détruit ou endommage\ngravement les installations ou équipements publics ou privés ou en interrompt\nleurs services sera punie de quinze (15) à trente (30) ans d’emprisonnement.\nCHAPITRE III : DES INFRACTIONS CONTRE LA SECURITE\nDES NAVIRES ET PLATES FORMES FIXES\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.6 :(Ord. n° 2011-12 du 27 janvier 2011) Sera punie d’un\nemprisonnement de deux (2) à sept (7) ans et d’une amende de un million\n(1 000 000) à deux millions (2 000 000) francs CFA toute personne qui\nillicitement et intentionnellement :\na) se livre à un acte de violence à l’encontre d’une personne se trouvant à\nbord d’un navire ou d’une plate-forme fixe, si cet acte est de nature à\ncompromettre la sécurité de la navigation du navire ou de la plate-forme ;\nb) détruit ou cause à un navire, à sa cargaison ou à une plateforme fixe des\ndommages qui sont de nature à compromettre la sécurité de la navigation\ndu navire ou de la plate-forme fixe ;\n\nc) place ou fait placer sur un navire ou une plate-forme fixe, par quelque\nmoyen que ce soit, un dispositif ou une substancepropre à détruire le navire\nou la plate-forme fixe, ou de nature à compromettre la sécurité de la plateforme fixe, ou à causer au navire ou à sa cargaison des dommages qui\ncompromettent ou sont de nature à compromettre la sécurité de la navigation\ndu navire ;\nd) détruit ou endommage gravement des installations ou services de\nnavigation maritime ou en perturbe gravement le fonctionnement, si l’un de\nces actes est de nature à compromettre la sécurité de la navigation d’un\nnavire ;\ne) communique une information qu’elle sait être fausse, et de ce fait,\ncompromet la navigation d’un navire.\nS’il est résulté de ces actes des blessures, maladies ou infirmités\npermanentes, la peine sera celle de deux (2) à moins de dix","[CPN] Art. 399.1.7 : (Ord. n° 2011-12 du 27 janvier 2011) Toute personne\nqui menace de commettre l’une quelconque des infractions prévues aux\nparagraphes a), b) et d) de l’article 399.1.6 sera punie d’un emprisonnement\nde deux (2) à sept (7) ans et d’une amende de cinq cent mille (500.000) à\ndeux millions (2.000.000) francs CFA si cette menace est de nature à\ncompromettre la sécurité de la navigation du navire ou de la plateforme\nfixe.","[CPN] Art. 399.1.8 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie d’un\nemprisonnement de quinze (15) à trente (30) ans, toute personne qui\nillicitement et intentionnellement, lorsque cet acte, par sa nature ou son\ncontexte, vise à intimider une population ou à contraindre un Gouvernement\nou une organisation internationale à accomplir ou à s’abstenir d’accomplir\nun acte quelconque :\n\na) utilise, contre ou à bord d’un navire ou d’une plate-forme fixe, ou déverse\nà partir d’un navire ou d’une plate-forme fixe, des explosifs, des matières\nradioactives ou des armes biologiques, chimiques ou nucléaires (BCN),\nd’une manière qui provoque ou risque de provoquer la mort ou des\ndommages corporels ou matériels graves ;\nb) déverse, à partir d’un navire ou d’une plate-forme fixe, des hydrocarbures,\ndu gaz naturel liquéfié, ou d’autres substances nocives ou potentiellement\ndangereuses, qui ne sont pas visées au point a)ci-dessus), en quantités ou\nconcentrations qui provoquent ou risquent de provoquer des dommages\ncorporels ou matériels graves ;\nc) utilise un navire de manière à provoquer la mort ou des dommages\ncorporels ou matériels graves ;\nd) menace de commettre l’une des infractions visées au présent article.\nS’il est résulté de ces actes, des blessures, maladies ou infirmités\npermanentes, la peine sera celle de l’emprisonnement à vie.\nS’il en est résulté la mort d’une ou de plusieurs personnes, la peine de mort\nsera prononcée.","[CPN] Art. 399.1.9 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie d’un\nemprisonnement de quinze (15) à trente (30) ans, toute personne qui, illicitement\net intentionnellement, transporte à bord d’un navire ou d’un véhicule :\na) des explosifs ou des matières radioactives, en sachant que ceux-ci sont\ndestinés à provoquer ou à menacer de provoquer la mort, des dommages\ncorporels ou matériels graves ;\nb) toute arme biologique, chimique ou nucléaire (BCN), en sachant qu’il\ns’agit d’une arme BCN ;\nc) des matières brutes ou produits fissiles spéciaux, équipements ou matières\nspécialement conçus ou préparés pour le traitement, l’utilisation ou la\nproduction de produits fissiles spéciaux, en sachant que ces matières,\nproduits ou équipements sont destinés à une activité explosive nucléaire ou\nà toute autre activité nucléaire non soumise à des garanties en vertu d’un\naccord de garanties généralisées de l’Agence internationale de l’énergie\natomique (AIEA);\n\nd) des équipements, matières ou logiciels ou des technologies connexes qui\ncontribuent de manière significative à la conception, la fabrication ou au\nlancement d’une arme biologique, chimique ou nucléaire, en ayant l’intention\nde les utiliser à cette fin.\nS’il est résulté de ces actes des blessures ou maladies ou infirmités\npermanentes, la peine sera celle de l’emprisonnement à vie.\nS’il en est résulté la mort d’une ou de plusieurs personnes, la peine de mort\nsera prononcée.","[CPN] Art. 399.1.10 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie de la\nmême peine que celle prévue à l’article précédent, toute personne qui\ntransporte à bord d’un navire ou d’un véhicule une autre personne, en\nsachant qu’elle a commis un acte qui constitue une infraction visée dans le\nprésent titre, en ayant l’intention d’aider cette personne à échapper à des\npoursuites pénales.\nLes exceptions prévues par l’alinéa 2 de l’article 206 du Code pénal sont\napplicables dans ce cas.\nCHAPITRE IV : DE LA PRISE D’OTAGES\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.11 : (Ord. n° 2011-12 du 27 janvier 2011) Les faits prévus\nà l’alinéa 1 de l’article 265 du Code pénal seront punis d’un emprisonnement\nde dix (10) à trente (30) ans lorsqu’ils ont été commis afin de contraindre\nune tierce partie, à savoir un Etat, une organisation internationale,\nintergouvernementale, une personne physique ou morale ou un groupe de\npersonnes, à accomplir un acte quelconque ou à s’en abstenir en tant que\ncondition explicite ou implicite de la libération de l’otage.\nSi les personnes arrêtées, détenues ou séquestrées ont subi des tortures\ncorporelles, l’emprisonnement à vie sera prononcé.\n\nCHAPITRE V : DES INFRACTIONS CONTRE LES\nPERSONNES JOUISSANT D’UNE PROTECTION\nINTERNATIONALE\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.12 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie de la\npeine de mort toute personne qui, intentionnellement, commet le meurtre\nd’une personne jouissant d’une protection internationale.","[CPN] Art. 399.1.13 : Sera punie de l’emprisonnement à vie, toute personne qui,\nintentionnellement :\na) commet un enlèvement ou un acte attentatoire à l’intégrité physique ou\nà la liberté d’une personne jouissant d’une protection internationale\nb) commet, en recourant à la violence, contre les locaux officiels, le logement\nprivé ou les moyens de transport d’une personne jouissant d’une protection\ninternationale, une attaque de nature à mettre sa personne ou sa liberté en\ndanger;\nc) menace de commettre une telle attaque.\nCHAPITRE VI : DES ATTENTATS TERRORISTES A\nL’EXPLOSIF\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.14 : (Ord. n° 2011-12 du 27 janvier 2011) Seront punis\nd’un emprisonnement de quinze (15) à trente (30) ans ceux qui auront\nlivré, posé, fait exploser ou détonner dans un lieu public ou contre une\ninstallation Gouvernementale ou une autre installation publique ou privée,\nun système de transport public ou privé ou une infrastructure :\na) une arme ou un engin explosif ou incendiaire conçu pour ou ayant la\ncapacité de provoquer la mort, des dommages corporels graves ou\nd’importants dégâts matériels ;\nb) une arme ou un engin conçu pour ou ayant la capacité de provoquer la\nmort, des dommages corporels graves ou d’importants dégâts matériels,\npar l’émission, la dissémination ou l’impact de produits chimiques toxiques,\n\nd’agents biologiques, toxines ou substances analogues ou de rayonnements\nou de matières radioactives ;\nc) toute autre arme ou engin meurtrier, dans l’intention de provoquer la\nmort ou des dommages corporels graves, ou dans l’intention de causer des\ndestructions massives de ce lieu, de cette installation, de ce système ou de\ncette infrastructure, lorsque ces destructions entraînent ou risquent\nd’entraîner des pertes économiques considérables.\nSi les actes ainsi posés ont entraîné des blessures ou maladies ou infirmités\npermanentes, la peine sera celle de l’emprisonnement à vie.\nSi les actes ainsi posés ont entraîné mort d’homme ou des pertes\néconomiques considérables, la peine de mort sera prononcée.\nCHAPITRE VII : DU TERRORISME NUCLEAIRE\n(Ord. n° 2011-12 d","[CPN] Art. 399.1.15 : (Ord. n° 2011-12 du 27 janvier 2011) Sera punie d’un\nemprisonnement de quinze (15) à trente (30) ans toute personne qui,\nillicitement et intentionnellement :\n(a) détient des matières radioactives, fabrique ou détient un engin dans\nl’intention d’entraîner la mort d’une personne ou de lui causer des dommages\ncorporels graves, ou dans l’intention de causer des dégâts substantiels à\ndes biens ou à l’environnement ;\n(b) emploie de quelque manière que ce soit, des matières ou engins\nradioactifs, ou utilise ou endommage une installation nucléaire de façon à\nlibérer ou risquer de libérer des matières radioactives dans l’intention\nd’entraîner la mort d’une personne ou de lui causer des dommages corporels\ngraves, de causer des dégâts substantiels à des biens ou à l’environnement\nou de contraindre une personne physique ou morale, une organisation\ninternationale ou un Gouvernement à accomplir un acte ou à s’en abstenir.\nSi les actes ainsi posés ont entraîné mort d’homme ou des pertes\néconomiques considérables, la peine de mort sera prononcée.\nLa même peine est applicable à toute personne qui :\n\n(a) menace, dans des circonstances qui rendent la menace crédible, de\ncommettre une infraction visée au point (b) ci-dessus) ;\n(b) exige illicitement et intentionnellement la remise de matières ou engins\nradioactifs ou d’installations nucléaires en recourant à la menace, dans des\ncirconstances qui la rendent crédible, ou à l’emploi de la force.\nCHAPITRE VIII : DES INFRACTIONS RELAT","[CPN] Art. 399.1.16 : (Ord. n° 2011-12 du 27 janvier 2011) Est puni d’une\npeine d’emprisonnement de dix (10) à trente (30) ans et d’une amende de\n50 millions (50 000 000) à cinq cent millions (500.000.000) francs CFA, le\nfait de commettre intentionnellement l’un des actes suivants :\na) le recel, la détention, l’utilisation, le transfert, l’altération, la cession, ou\nla dispersion de matières nucléaires ou dangereuses, sans l’autorisation\nrequise, et entraînant ou pouvant entraîner la mort ou des blessures graves\npour autrui ou des dommages substantiels aux biens ou à l’environnement ;\nb) le vol simple ou le vol qualifié de matières nucléaires ou dangereuses ;\nc) le détournement ou toute autre appropriation indue des matières nucléaires\nou dangereuses ;\nd) le transport, l’envoi, le déplacement des matières nucléaires ou\ndangereuses ou vers ou depuis un Etat sans l’autorisation requise ;\ne) l’acte dirigé contre une installation nucléaire, ou perturbant le\nfonctionnement d’une installation nucléaire, par lequel l’auteur provoque\nintentionnellement ou sait qu’il peut provoquer la mort ou des blessures\ngraves pour autrui ou des dommages substantiels aux biens ou à\nl’environnement par suite de l’exposition à des rayonnements ou du\nrelâchement des substances radioactives, à moins que cet acte ne soit\nentrepris en conformité avec le droit national de l’Etat sur le territoire duquel\nl’installation nucléaire est située ;\nf) le fait d’exiger des matières nucléaires ou dangereuses par la menac","[CPN] Art. 399.1.17 (nouveau) : (Loi n° 2016-22 du 16 juin 2016) Toute\npersonne qui participe à l’organisation, la préparation ou la commission de\nl’une ou de plusieurs des infractions prévues par la présente loi ou qui apporte\nquelque forme d’appui que ce soit, actif ou passif, dans l’intention ou en\nsachant que le but d’une telle participation ou d’un tel appui est la commission\nde l’une ou de plusieurs des infractions prévues par la présente loi, est punie\nd’une peine d’emprisonnement de dix (10) à trente (30) ans et d’une amende\nde cinq cent mille (500 000) à dix millions (10 000 000) de francs.\n\nToute personne qui fournit des armes, dans l’intention ou en sachant que\nces armes peuvent être utilisées pour la commission de l’une des infractions\nprévues par la présente loi, est punie de la même peine que celle fixée à\nl’alinéa précédent.\nCHAPITRE IX (BIS) : DE L’APOLOGIE ET DE\nL’INCITATION AU TERRORISME\n(Loi n° 2016-22 du 16 juin 2016)","[CPN] Art. 399.1.17 (bis) : (Loi n° 2016-22 du 16 juin 2016) Toute personne,\nqui par n’importe quel moyen, appelle ou incite à commettre des infractions\nterroristes, incite au fanatisme ethnique, racial ou religieux ou utilise un\nnom, un terme, un symbole, des expressions publiques de soutien à des\nactes de terrorisme et/ou des groupes terroristes, diffuse des discours de\nhaine ou fait la promotion d’idéologies favorables au terrorisme, renforce\ndes tensions ethniques et religieuses susceptibles de fournir une base au\nterrorisme, ou utilise tout autre signe dans le but de faire l’apologie d’une\norganisation qualifiée terroriste, est punie d’une peine d’emprisonnement\nde cinq (5) ans à moins de dix (10) ans et d’une amende de cinq cent mille\n(500 000) à dix millions (10 .000.000) de francs.\nCHAPITRE X : DE L’ORGANISATION D’ACTES DE\nTERRORISME : DE LA CONTRIBUTION A LA\nCOMMISSION D’ACTES DE TERRORISME\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.18 : (Ord. n° 2011-12 du 27 janvier 2011) Toute personne qui\norganise la commission d’une infraction prévue par la présente ordonnance\nou donne l’ordre à d’autres personnes de la commettre, sera punie d’une\npeine d’emprisonnement de dix (10) à trente (30) ans et d’une amende de\ncinq cent mille (500 000) à dix millions (10 000 000) francs CFA.\nToute personne qui contribue à la commission de l’une ou plusieurs des\ninfractions prévues par la présente ordonnance par un groupe de personnes\nagissant de concert, si elle le fait délibérément, soit pour faciliter l’activité\ncriminelle générale du groupe ou servir les buts de celui-ci, soit en\n\nconnaissant l’intention du groupe de commettre une telle infraction, sera\npunie de la même peine que celle fixée à l’alinéa précédent.\nToute infraction entrant dans le champ d’application de la présente\nordonnance, commise ou tentée par un membre des forces de défense et\nde sécurité sera punie de la peine d’emprisonnement à vie.\nCHAPITRE XI (NOUVEAU) : DE L’ASSOCIATION DE\nMALFAITEURS EN VUE DE PERPETRER DES ACTES\nTERRORISTES.\n(Loi n° 2016-22 du 16 juin 2016)","[CPN] Art. 399.1.19 (nouveau) : (Loi n° 2016-22 du 16 juin 2016) Le fait de\nparticiper à un groupement formé ou à une entente établie en vue de la\npréparation d’un des actes terroristes caractérisés par un ou plusieurs faits\nmatériels est puni d’un emprisonnement de cinq (5) ans à moins de dix (10)\nans.\nLe fait de diriger ou d’organiser le groupement ou l’entente est puni d’un\nemprisonnement de dix (10) ans à trente (30) ans.\nCHAPITRE XI (BIS) : RECEL DE TERRORISTES\n(Loi n° 2016-22 du 16 juin 2016)","[CPN] Art. 399.1.19 nouveau (bis) : (Loi n° 2016-22 du 16 juin 2016) Ceux\nqui, connaissant les agissements des individus exerçant des actes terroristes\nou tout autre acte prévu par la présente loi, leur fournissent habituellement\nlogement, lieu de retraite ou de réunion, sont punis d’une peine\nd’emprisonnement de cinq (5) ans à moins de dix (10) ans.","[CPN] Art. 399.1.19 nouveau (ter) : (Loi n° 2016-22 du 16 juin 2016) Ceux\nqui auront sciemment recelé une personne qu’ils savaient recherchée par\nla justice, ou qui l’auront soustraite ou tenté de la soustraire à l’arrestation\nou aux recherches, ou l’auront aidé à se cacher ou à prendre la fuite,\nquand bien même il s’agit des membres de leurs familles, seront punis d’un\nemprisonnement de cinq (5) ans à moins de dix (10) ans.\n\nCHAPITRE XII : DU REPENTI\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.20 : (Ord. n° 2011-12 du 27 janvier 2011) Tout membre\nd’un groupement ou entente planifiant un acte terroriste est exempté de\ntoute poursuite si, ayant averti l’autorité administrative ou judiciaire, il a\npermis d’éviter la réalisation de l’infraction.\nTout membre d’un groupement ou entente ayant participé à la réalisation\nd’un acte terroriste et donnant à l’autorité administrative ou judiciaire toutes\ninformations permettant d’identifier les auteurs de l’infraction peut bénéficier\ndes circonstances atténuantes prévues par les articles 53 et 54 du Code\npénal.\nCHAPITRE XIII : DU FINANCEMENT DU TERRORISME\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.21 (nouveau) : (Loi n° 2016-22 du 16 juin 2016) Est punie\nd’un emprisonnement de cinq (5) ans à moins de dix (10) ans toute personne\nqui, par quelque moyen que ce soit, directement ou indirectement, illicitement\net délibérément, fournit, réunit, gère des fonds, des valeurs ou des biens\nquelconques dans l’intention de les voir utilisés ou en sachant qu’ils seront\nutilisés, en tout ou partie, en vue de commettre :\na) un acte constituant une infraction prévue par le présent titre ;\nb) tout autre acte destiné à tuer ou blesser grièvement un civil, ou toute\nautre personne qui ne participe pas directement aux hostilités dans une\nsituation de conflit armé, lorsque, par sa nature ou son contexte, cet acte\nvise à intimider une population ou à contraindre un Gouvernement ou une\norganisation internationale à accomplir ou à s’abstenir d’accomplir un acte\nquelconque.\nLa confiscation des fonds ainsi réunis est prononcée au bénéfice du trésor\npublic.\nc) tout acte de fourniture ou réunion de fonds sachant qu’ils seront utilisés,\nen tout ou en partie, par une organisation terroriste, par un terroriste\nindividuel ou un groupe de terroristes pour toutes fins.\n\nL’infraction est constituée même si les fonds collectés n’ont pas été\neffectivement utilisés dans la commission de l’infraction.\nL’expression «fonds» s’entend des biens de toute nature, corporels ou\nincorporels, mobiliers ou immobiliers, acquis par quelque moyen que ce\nsoit, et des documents ou instruments juridiques sous quelq","[CPN] Art. 399.1.22 : (Ord. n° 2011-12 du 27 janvier 2011) Quiconque aura\nrecruté une personne pour commettre ou participer à la commission de\nl’une ou plusieurs des infractions prévues par le présent titre, dans l’intention\nou en sachant que le but de ce recrutement ou de cette demande est de\nparticiper à la commission de l’une ou de plusieurs infractions prévues par\nle présent titre, sera puni d’un emprisonnement de cinq (5) à moins de dix\n(10) ans et d’une amende de deux (2) millions à vingt (20) millions de\nfrancs CFA.","[CPN] Art. 399.1.23 : (Ord. n° 2011-12 du 27 janvier 2011)Constitue\négalement une infraction terroriste, punie des mêmes peines que celles\nfixées à l’article 399.1.22 ci-dessus :\na) le fait de recevoir un entraînement, sur le territoire national ou à l’étranger,\nen vue de commettre une infraction terroriste à l’intérieur ou à l’extérieur\ndu pays ;\nb) le fait d’entraîner une personne ou un groupe de personnes, sur le territoire\nnational ou à l’étranger, en vue de commettre un acte terroriste à l’intérieur\nou à l’extérieur du pays.\n\nCHAPITRE XIV (TER)* : DE LA MINORITE\n(Loi n° 2016-22 du 16 juin 2016)","[CPN] Art. 399.1.23 (Ter)** : (Loi n° 2016-22 du 16 juin 2016) Sont punis de\nla moitié de la peine prévue pour les majeurs, les mineurs qui commettent\nl’une des infractions terroristes prévues par la présente loi, sans que le\nmaximum de la peine d’emprisonnement n’excède douze (12) ans.\nCHAPITRE XV : DE LA RESPONSABILITE DES PERSONNES\nMORALES\n(Ord. n° 2011-12 du 27 janvier 2011)","[CPN] Art. 399.1.24 (nouveau) : (Loi n° 2016-22 du 16 juin 2016) Lorsque\nla personne responsable de la direction ou du contrôle d’une personne morale\nconstituée sur le territoire de la République du Niger ou régie par sa\nlégislation a, en cette qualité, commis une infraction relative à la présente\nloi, cette personne morale est punie d’une amende de cinq cent millions\n(500 000 000) de francs, sans préjudice de la condamnation de la ou des\npersonnes assurant la direction de la personne morale comme auteur ou\ncomplice des mêmes faits.\nLes dispositions de l’alinéa précédent s’appliquent sans préjudice des\ndispositions de la législation relative à la lutte contre le blanchiment des\ncapitaux et le financement du terrorisme.\nTITRE VII : DES INFRACTIONS EN MATIERE\nD’INFORMATIQUE\n(Loi n° 2003- 25 du 13 juin 2003).","[CPN] Art. 399.2 : (Loi n° 2003- 25 du 13 juin 2003) Est puni d’un\nemprisonnement de deux mois à un an et d’une amende de 50.000 à 300.000\nfrancs ou de l’une de ces deux peines seulement, quiconque,\nfrauduleusement, accède ou se maintient dans tout ou partie d’un système\nde traitement automatisé de données. Lorsqu’il en résulte soit la suppression\nErreur de numérotation contenue dans la Loi n°2016-22 du 16 juin 2016, puisque dans la\nnumérotation antérieure à 2016 il n’y avait pas de Chapitre XIV (Bis)..\n*\n\nIdem. Dans la Loi n° 2016-22 du 16 juin 2016, il était fait cas d’insérez après l’Article\n399.1.23 (bis) un Article 399.1.23 (ter), or l’Article 399.1.23 (bis) n’a jamais existé.\n\n**\n\nou la modification de données contenues dans le système, soit à une altération\ndu fonctionnement de ce système, l’emprisonnement est de deux mois à\ndeux ans et l’amende de 100.000 à 600.000 francs.","[CPN] Art. 399.3 : (Loi n° 2003- 25 du 13 juin 2003) Est puni d’un\nemprisonnement de trois mois à trois ans et d’une amende de 100.000 à\n1.000.000 de francs ou de l’une de ces peines seulement, quiconque\nintentionnellement et au mépris des droits d’autrui, entrave ou force le\nfonctionnement d’un système de traitement automatisé de données.","[CPN] Art. 399.4 : (Loi n° 2003- 25 du 13 juin 2003) Est puni d’un\nemprisonnement de trois mois à trois ans et d’une amende de 100.000 à\n1.000.000 de francs ou de l’une de ces peines seulement, quiconque\nintentionnellement et au mépris des droits d’autrui, directement ou\nindirectement, introduit des données dans un système de traitement\nautomatisé, supprimé ou modifié les données qu’il contient ou leur mode de\ntraitement ou de transmission.","[CPN] Art. 399.5 : (Loi n° 2003- 25 du 13 juin 2003) Est puni d’un\nemprisonnement de un an à trois ans et d’une amende de 300.000 à\n1.500.000 de francs ou de l’une de ces peines seulement, quiconque procède\nà la falsification de documents informatisés, quelle que soit leur forme, de\nnature à causer un préjudice à autrui.","[CPN] Art. 399.6 : (Loi n° 2003- 25 du 13 juin 2003) Est puni d’un\nemprisonnement de un à trois ans et d’une amende de 300.000 à 1.500.000\nde francs ou de l’une de ces peines seulement, quiconque sciemment fait\nusage de documents informatisés visés à l’article précédent.","[CPN] Art. 399.7 : (Loi n° 2003- 25 du 13 juin 2003) La tentative des délits\nprévus aux articles 399.2 à 399.6 est punie des mêmes peines.","[CPN] Art. 399.8 : (Loi n° 2003- 25 du 13 juin 2003) Est puni des peines\nprévues pour l’infraction elle-même ou pour l’infraction la plus sévèrement\nréprimée, quiconque participe à une association formée ou une entente\nétablie en vue de la préparation concrétisée par un ou plusieurs faits\nmatériels, d’une ou plusieurs infractions prévues par les articles ci-dessus.","[CPN] Art. 399.9 : (Loi n° 2003- 25 du 13 juin 2003)La juridiction saisie peut\nprononcer la confiscation des matériels appartenant au condamné et ayant\nservi à commettre les infractions prévues au présent titre.\n\nLIVRE III\nDES PEINES EN MATIERE DE SIMPLE POLICE\nET DE LEURS EFFETS\n\nCode pénal","[CPN] Art. 400 : Les peines de simple police sont :\n- l’emprisonnement d’une durée de un à trente jours;\n- l’amende de 500 francs à moins de 100.000 francs.","[CPN] Art. 401 : Les dispositions des articles 34, 35, 36 et 37 sont applicables en\nmatière de simple police.","[CPN] Art. 402 : Les tribunaux de simple police pourront, dans les cas prévus\npar les règlements, prononcer la confiscation, soit des choses saisies en\ncontravention, soit des choses produites par la contravention, soit des\nmatières ou des instruments qui ont servi ou étaient destinés à la commettre.","[CPN] Art. 403 : Dans les cas spécialement prévus, les tribunaux de simple police\npourront ordonner que leur décision sera affichée en caractères très\napparents dans les lieux qu’ils indiquent aux frais du condamné.\nCet affichage sera prononcé pour une durée qui ne pourra excéder quinze\njours.\nLa suppression, la dissimulation, et la lacération totale ou partielle des\naffiches apposées conformément au présent article, opérées volontairement,\nseront punies d’une amende de 10.000 à 100.000 francs et d’un\nemprisonnement de un à six mois ou de l’une de ces deux peines seulement;\nil sera procédé de nouveau à l’exécution intégrale de l’affichage au frais\ndu condamné.","[CPN] Art. 404 : Si les circonstances paraissent atténuantes, les tribunaux de\nsimple police sont autorisés, même en cas de récidive, à réduire\nl’emprisonnement et l’amende sans pouvoir cependant prononcer des peines\ninférieures à 500 francs d’amende et un jour d’emprisonnement.\nIls pourront aussi prononcer séparément l’une ou l’autre de ces peines et\nmême substituer l’amende à l’emprisonnement sans qu’en aucun cas\nl’amende puisse être inférieure à 500 francs.","[CPN] Art. 405 : En cas de condamnation à une peine de simple police supérieure\nà dix jours d’emprisonnement ou à 50.000 francs d’amende, le sursis peut\nêtre ordonné.\n\nCode pénal","[CPN] Art. 406 : Il y a récidive en matière de contravention de simple police\nlorsqu’il a été rendu contre le contrevenant, dans les douze mois précédents,\nun premier jugement devenu définitif pour contravention commise dans le\nressort du même tribunal.\nToutefois, la récidive des contraventions passibles d’un emprisonnement\nsupérieur à dix jours ou d’une amende supérieure à 50.000 francs est\nindépendante du lieu où la première contravention a été commise.","[CPN] Art. 407 : Sont abrogées toutes dispositions antérieures et contraires au\nprésent Code.","[CPN] Art. 408 : La présente loi sera publiée au Journal Officiel de la République\ndu Niger et exécutée comme loi de l’Etat.\n\nCode de procédure pénale","[CPPN] Art. 2 : L’action civile en réparation du dommage causé par un crime, un\ndélit ou une contravention, appartient à tous ceux qui ont personnellement\nsouffert du dommage directement causé par l’infraction.\nLa renonciation à l’action civile ne peut arrêter ni suspendre l’exercice de\nl’action publique, sous réserve des cas visés à l’alinéa 3 de l’article 6.","[CPPN] Art. 3 : L’action civile peut être exercée en même temps que l’action\npublique et devant la même juridiction.\nElle est recevable pour tous chefs de dommages, aussi bien matériels que\ncorporels ou moraux, qui découleront des faits objets de la poursuite.\nLa partie lésée est recevable à réclamer devant la juridiction répressive,\noutre la réparation du préjudice corporel ou moral, celle du préjudice matériel\ncausé par le même fait, même si aucune contravention connexe, génératrice\ndes dégâts matériels, n’a été retenue par le titre de la poursuite.\n(Ord. n° 82-23 du 16 septembre 1982). S’il apparaît au cours de la poursuite,\nque la responsabilité civile du prévenu ou du civilement responsable est\ncouverte, en totalité ou en partie, par un contrat d’assurance, l’assureur est\ncité devant la juridiction répressive en même temps que l’assuré.\nL’assureur peut aussi intervenir volontairement, et même pour la première\nfois, en cause d’appel.","[CPPN] Art. 4 : L’action civile peut être aussi exercée séparément de l’action\npublique.\nToutefois, il est sursis au jugement de cette action exercée devant la\njuridiction civile tant qu’il n’a pas été prononcé définitivement sur l’action\npublique lorsque celle-ci a été mise en mouvement.\n\nCode de procédure pénale","[CPPN] Art. 5 : La partie qui a exercé son action devant la juridiction civile\ncompétente ne peut la porter devant la juridiction répressive.\nIl n’en est autrement que si celle-ci a été saisie par le ministère public\navant qu’un jugement sur le fond ait été rendu par la juridiction civile.","[CPPN] Art. 6 : L’action publique pour l’application de la peine s’éteint par la mort\ndu prévenu, la prescription, l’amnistie, l’abrogation de la loi pénale et la\nchose jugée.\nToutefois, si des poursuites ayant entraîné condamnation ont révélé la\nfausseté du jugement ou de l’arrêt qui a déclaré l’action publique éteinte,\nl’action publique pourra être reprise; la prescription doit alors être considérée\ncomme suspendue depuis le jour où le jugement ou arrêt était devenu définitif\njusqu’à celui de la condamnation du coupable de faux ou usage de faux.\nElle peut, en outre, s’éteindre par transaction lorsque la loi en dispose\nexpressément; il en est de même, en cas de retrait de plainte, lorsque celleci est une condition nécessaire de la poursuite.","[CPPN] Art. 7 : En matière de crime, l’action publique se prescrit par dix années\nrévolues à compter du jour où le crime a été commis si, dans cet intervalle,\nil n’a été fait aucun acte d’instruction ou de poursuite.\nS’il en a été effectué dans cet intervalle, elle ne se prescrit qu’après dix\nannées révolues à compter du dernier acte. Il en est ainsi même à l’égard\ndes personnes qui ne seraient pas impliquées dans cet acte d’instruction ou\nde poursuite.","[CPPN] Art. 8 : En matière de délit, la prescription de l’action publique est de trois\nannées révolues; elle s’accomplit selon les distinctions spécifiées à l’article\nprécédent.","[CPPN] Art. 9 : En matière de contravention, la prescription de l’action publique est d’une\nannée révolue; elle s’accomplit selon les distinctions spécifiées à l’article 7.","[CPPN] Art. 10 :\n(Loi n° 2003-26 du 13 juin 2003). L’action civile est\nindépendante de l’action publique et se prescrit selon les règles du Code\ncivil.\n(Loi n° 2003-26 du 13 juin 2003). Lorsqu’il a été statué sur l’action\npublique, les mesures d’instruction ordonnées par le juge pénal sur l’action\ncivile obéissent aux règles de la procédure civile.\n\nLIVRE PREMIER :\nDE L’EXERCICE DE L’ACTION PUBLIQUE ET\nDE L’INSTRUCTION\n\nTITRE PREMIER : DES AUTORITES CHARGES DE\nL’ACTION PUBLIQUE ET DE L’INSTRUCTION","[CPPN] Art. 11 : Sauf dans les cas où la loi en dispose autrement et sans préjudice\ndes droits de la défense, la procédure au cours de l’enquête et de l’instruction\nest secrète.\nToute personne qui concourt à cette procédure est tenue au secret professionnel\ndans les conditions et sous les peines de l’article 221 du code pénal.\nCHAPITRE PREMIER : DE POLICE JUDICIAIRE\nSection 1- Dispositions générales","[CPPN] Art. 12 : La police judiciaire est exercée, sous la direction du procureur de la\nRépublique, par les officiers, fonctionnaires et agents désignés au présent titre.","[CPPN] Art. 13 : (Loi n° 2003-26 du 13 juin 2003). Elle est placée, dans chaque\nressort de Cour d’Appel, sous la surveillance du procureur général et sous le\ncontrôle de la Chambre d’accusation conformément aux articles 216 et suivants.","[CPPN] Art. 14 : Elle est chargée, suivant les distinctions établies au présent titre,\nde constater les infractions à la loi pénale, d’en rassembler les preuves et\nd’en rechercher les auteurs tant qu’une information n’est pas ouverte.\nLorsqu’une information est ouverte, elle exécute les délégations des\njuridictions d’instruction et défère à leurs réquisitions.","[CPPN] Art. 15 : La police judiciaire comprend :\n1) les officiers de police judiciaire;\n2) les agents de police judiciaire;\n3) les fonctionnaires et agents auxquels sont attribuées par la loi certaines\nfonctions de police judiciaire.\nSection II – Des officiers de police judiciaire\nArt. 16 (nouveau) : (Ord. n° 2011-13 du 27 janvier 2011)Ont qualité\nd’officiers de police judiciaire :\n- les procureurs de la République et leurs substituts ;\n- les juges d’instruction ;\n\n- les juges d’instance ;\n- les gouverneurs ;\n- les préfets ;\n- le directeur général de la Police nationale et son adjoint ;\n- les officiers et gradés de la Gendarmerie ;\n- les commissaires et inspecteurs principaux de Police, les officiers de paix\net officiers de Police ;\n- les officiers de la Garde nationale du Niger ;\n- les sous-officiers de la Garde nationale du Niger ayant au moins trois (3)\nans de service dans leurs corps et ayant suivi une formation de préparation\nà la qualité d’Officier de police judiciaire (OPJ) ;\n- les inspecteurs de police nommés commissaires de police et les chefs de\nbrigade mobile de la Police nationale ;\n- les maréchaux des logis et gendarmes, chefs de brigade, de poste ou de\npeloton ;\n- les inspecteurs de police ayant au moins trois (3) ans de service dans la\nPolice et désignés par arrêté du ministre chargé de la justice sur proposition\ndu ministre chargé de l’intérieur ;\n- les maréchaux des logis et gendarmes comptant au moins trois (3) ans de\nservice dans la Gendarmerie, désignés par arrêt","[CPPN] Art. 17 : Les officiers de police judiciaire exercent les pouvoirs définis à\nl’article 14 ; ils reçoivent les plaintes et dénonciations; ils procèdent à des\nenquêtes préliminaires dans les conditions prévues par les articles 69 à 71.\nEn cas de crimes et délits flagrants, ils exercent les pouvoirs qui leur sont\nconférés par les articles 48 à 62.\nIls ont le droit de requérir directement le concours de la force publique\npour l’exécution de leur mission.\n\nCode de procédure pénale","[CPPN] Art. 18 : Les officiers de police judiciaire peuvent opérer dans toute\nl’étendue du ressort du tribunal de première instance auquel ils sont\nrattachés.\nIls peuvent, sur commission rogatoire, expresse, ainsi qu’au cas de crime\nou délit flagrant, opérer sur tout le territoire de la République du Niger.","[CPPN] Art. 19 : Les officiers de police judiciaire sont tenus d’informer sans délai\nle procureur de la République des crimes, délits et contraventions dont ils\nont connaissance. Dès la clôture de leurs opérations, ils doivent lui faire\nparvenir directement l’orignal ainsi qu’une copie certifiée conforme des\nprocès-verbaux qu’ils ont dressés; tous actes et documents y relatifs lui\nsont en même temps adressés; les objets saisis sont mis à sa disposition.\nLes procès-verbaux doivent énoncer la qualité d’officier de police judiciaire\nde leur rédacteur.\nSection III – Des agents de police judiciaire","[CPPN] Art. 20 : Sont agents de police judiciaire les fonctionnaires des services\nactifs de police, les gendarmes et les gradés du corps des FNIS qui n’ont\npas la qualité d’officier de police judiciaire, à l’exception de ceux exerçant\ndes fonctions de direction ou de contrôle.","[CPPN] Art. 21 : Les agents de police judiciaire ont pour mission :\n1) de seconder, dans l’exercice de leurs fonctions, les officiers de police\njudiciaire;\n2) de rendre compte à leurs chefs hiérarchiques de tous crimes, délits ou\ncontraventions dont ils ont connaissance;\n3) de constater, en se conformant aux ordres de leurs chefs, les infractions\nà la loi pénale et de recueillir tous les renseignements en vue de découvrir\nles auteurs de ces infractions, le tout dans le cadre et dans les formes\nprévus par les lois qui leur sont propres.\nParagraphe 1- DES INSPECTEURS ET AGENTS ASSERMENTES\nDES EAUX ET FORETS","[CPPN] Art. 22 : Les inspecteurs et agents assermentés des Eaux et Forêts\nrecherchent et constatent par procès-verbaux les infractions à la\nrèglementation des Eaux et Forêts et de la chasse.\n\nCode de procédure pénale","[CPPN] Art. 23 : Les inspecteurs et agents assermentés des Eaux et Forêts suivent\nles choses enlevées dans les lieux où elles ont été transportées et les mettent\nsous séquestre.\nIls ne peuvent cependant pénétrer dans les maisons, ateliers, bâtiments,\ncours adjacentes et enclos, qu’en présence d’un officier de police judiciaire\nqui ne peut se refuser à les accompagner et qui signe le procès-verbal de\nl’opération à laquelle il a assisté.","[CPPN] Art. 24 : Les inspecteurs et agents assermentés des Eaux et Forêts\nconduisent devant un officier de police judiciaire tout individu qu’ils\nsurprennent en flagrant délit.\nIls peuvent, dans l’exercice des fonctions visées à l’article 22, requérir\ndirectement la force publique.","[CPPN] Art. 25.Ils peuvent être requis par le procureur de la République, le juge\nd’instruction et les officiers de police judiciaire, afin de leur prêter assistance.","[CPPN] Art. 26 : Ils remettent à leurs chefs hiérarchiques les procès-verbaux\nconstatant les infractions visées à l’article 22.","[CPPN] Art. 27 : Ces procès-verbaux sont ensuite, sauf transaction préalable,\ntransmis au procureur de la République.\nParagraphe II : DES FONCTIONNAIRES ET AGENTS DES\nADMINISTRATIONS ET SERVICES PUBLICS","[CPPN] Art. 28 : Les fonctionnaires et agents des administrations et services\nauxquels des textes spéciaux attribuent certains pouvoirs de police judiciaire\nexercent ces pouvoirs dans les conditions et limites fixées par ces textes.\nParagraphe III : DES CADRES PARTICULIERS ASSERMENTES","[CPPN] Art. 29 : Les gardes particuliers assermentés constatent par procèsverbaux tous délits et contraventions portant atteinte aux propriétés dont ils\nont la garde.\nLes procès-verbaux sont remis ou envoyés par lettre recommandée\ndirectement au procureur de la République. Cet envoi doit avoir lieu, à\npeine de nullité, dans les trois jours au plus tard, y compris celui où ils ont\nconstaté le fait, objet de leur procès-verbal.\n\nCHAPITRE II : DU MINISTERE PUBLIC\nSection 1 : Dispositions générales","[CPPN] Art. 30 : Le ministère public exerce l’action publique, requiert l’application\nde la loi et assure l’exécution des décisions de justice.\n(Ord. n° 92-02 du 21 février 1992). Lorsque l’exercice de l’action\npublique porte sur le détournement ou la dissipation de deniers publics,\nd’effets ou objets ayant une valeur estimative en argent, le ministère public\npeut ordonner que les biens appartenant aux personnes en cause, soient\ninventoriés et placés sous séquestre au greffe de la juridiction compétente\njusqu’à décision définitive.","[CPPN] Art. 31 : Le ministère public est représenté auprès de chaque juridiction\nrépressive.\nIl assiste aux débats des juridictions de jugements; toutes les décisions sont\nprononcées en sa présence.","[CPPN] Art. 32 : Il est tenu de prendre des réquisitions écrites conformes aux\ninstructions qui lui sont données dans les conditions prévues aux articles\n35, 36 et 43. Il développe librement les observations orales qu’il croît\nconvenables au bien de la justice.\nSection II : Des attributions du procureur général près la Cour\nd’Appel","[CPPN] Art. 33 : Le procureur général représente en personne ou par ses substituts\nle ministère public auprès de la Cour d’Appel et auprès de la Cour d’assises\ninstituée au siège de la Cour d’Appel.\nIl peut, dans les mêmes conditions, représenter le ministère public auprès\ndes autres cours d’assises sur le territoire de la République du Niger.","[CPPN] Art. 34 : Le procureur général est chargé de veiller à l’application de la loi\npénale sur le territoire de la République du Niger.\nA cette fin, il lui est adressé tous les mois par chaque procureur de la\nRépublique un état des affaires de son ressort.\nLe procureur général a, dans l’exercice de ses fonctions, le droit de requérir\ndirectement la force publique.\n\nCode de procédure pénale","[CPPN] Art. 35 : Le ministre de la justice peut dénoncer au procureur général les\ninfractions à la loi pénale dont il a connaissance, lui enjoindre d’engager ou\nde faire engager des poursuites ou de saisir la juridiction compétente de\ntelles réquisitions écrites que le ministre juge opportunes.","[CPPN] Art. 36 : Le procureur général a autorité sur tous les officiers du ministère\npublic du ressort de la Cour d’Appel.\nA l’égard de ces magistrats, il a les mêmes prérogatives que celles reconnues\nau ministre de la justice à l’article précédent.","[CPPN] Art. 37 : (Loi n° 2003-26 du 13 juin 2003). Les officiers de police\njudiciaire visés à l’article 16, autres que les magistrats, les gouverneurs des\nrégions, les préfets, les sous-préfets et leurs adjoints, les maires et leurs\nadjoints, ne peuvent exercer effectivement les attributions attachées à leur\nqualité d’officier de police judiciaire que s’ils sont affectés à un emploi\ncomportant cet exercice et en vertu d’une décision du procureur général\nprès la Cour d’appelles y habilitant personnellement.\n(Loi n° 2003-26 du 13 juin 2003). Les conditions d’octroi, de retrait ou\nde suspension pour une durée déterminée de l’habilitation prévue par le\nprécédent alinéa sont fixées par décret pris en Conseil des ministres sur\nrapport du ministre de la justice et sur avis des ministres concernés.\nLes officiers et agents de la police judiciaire sont placés sous la surveillance\ndu procureur général.\nSection III : Des attributions du procureur de la République et des\njuges d’instance","[CPPN] Art. 38 : Le procureur de la République représente en personne ou par\nses substituts le ministère public près le tribunal de grande instance.\nIl représente également en personne ou par ses substituts le ministère public\nauprès de la Cour d’assises instituée au siège du tribunal.\nIl exercice l’action publique auprès du tribunal de grande instance ainsi que\nprès des tribunaux d’instance qui y sont rattachés.\nDans les tribunaux d’instance, les présidents de tribunaux d’instance sont,\nsous le contrôle du procureur de la République, investis des pouvoirs de ce\ndernier.\n\nCode de procédure pénale","[CPPN] Art. 39 : (Loi n° 2003-26 du 13 juin 2003). Le procureur de la République\nreçoit les plaintes et les dénonciations et apprécie la suite à leur donner. En\ncas de classement sans suite, il avise le plaignant.\nToute autorité constituée, tout officier public ou fonctionnaire qui, dans\nl’exercice de ses fonctions, acquiert la connaissance d’un crime ou d’un\ndélit, est tenu d’en donner avis sans délai au procureur de la République et\nde transmettre à ce magistrat tous les renseignements, procès-verbaux et\nactes qui y sont relatifs.\nToute personne déférée devant le procureur de la République peut se faire\nassister d’un avocat.\nLorsque la personne déférée a fait le choix d’un avocat, elle ne peut être\nentendue qu’en présence de celui-ci. Toutefois, l’avocat informé dans un\ndélai raisonnable est tenu d’être présent.","[CPPN] Art. 40 : Le procureur de la République procède ou fait procéder à tous\nles actes nécessaires à la recherche et à la poursuite des infractions à la loi\npénale.\nA cette fin, il dirige l’activité des officiers et agents de la police judiciaire\ndans le ressort de son tribunal.\nEn cas d’infractions flagrantes, il exerce les pouvoirs qui lui sont attribués\npar l’article 62.","[CPPN] Art. 41 : Le procureur de la République a, dans l’exercice de ses fonctions,\nle droit de requérir directement la force publique.","[CPPN] Art. 42 : Sont compétents le procureur de la République du lieu de\nl’infraction, celui de la résidence de l’une des personnes soupçonnées d’avoir\nparticipé à l’infraction, celui du lieu d’arrestation d’une de ces personnes,\nmême lorsque cette arrestation a été opérée pour une autre cause","[CPPN] Art. 43 : Le procureur de la République représente en personne ou par\nses substituts le ministère public près le tribunal de simple police de son\nressort. Il peut lui déférer les contraventions dont il est informé.\n\nCHAPITRE III : DU JUGE D’INSTRUCTION","[CPPN] Art. 44 : Le juge d’instruction est chargé de procéder aux informations,\nainsi qu’il est dit au chapitre premier du titre III.\nIl ne peut, à peine de nullité, participer au jugement des affaires criminelles\ndont il a connu en sa qualité de juge d’instruction.","[CPPN] Art. 45 : Il est nommé au moins un juge d’instruction dans chaque tribunal.\nDans les tribunaux d’instance, les fonctions de juge d’instruction sont\nremplies par le juge d’instance.\nDans les ressorts où il n’y a qu’un juge d’instruction, s’il est absent, malade\nou autrement empêché, il est remplacé par un juge provisoirement désigné\npar ordonnance du président du tribunal; à défaut, le président du tribunal\nest chargé des fonctions de juge d’instruction. Dans ce dernier cas, il peut\njuger les affaires qu’il a instruites.","[CPPN] Art. 46 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction ne\npeut informer qu’après avoir été saisi par un réquisitoire du procureur de la\nRépublique ou par une plainte avec constitution de partie civile, dans les\nconditions prévues aux articles 73 et 81.\nEn cas de crimes ou délits flagrants, il exerce les pouvoirs qui lui sont\nattribués par l’article 66.\nLe juge d’instruction a, dans l’exercice de ses fonctions, le droit de requérir\ndirectement la force publique.","[CPPN] Art. 47 : Sont compétents le juge d’instruction du lieu de l’infraction, celui\nde la résidence de l’une des personnes soupçonnées d’avoir participé à\nl’infraction, celui du lieu d’arrestation d’une de ces personnes, même lorsque\ncette arrestation a été opérée pour une autre cause.\nTITRE II : DES ENQUETES\nCHAPITRE PREMIER – DES CRIMES ET DELITS FLAGRANTS","[CPPN] Art. 48 : Est qualifié crime ou délit flagrant, le crime ou le délit qui se\ncommet actuellement ou qui vient de se commettre. Il y a aussi crime ou\ndélit flagrant lorsque, dans un temps très voisin de l’action, la personne\n\nsoupçonnée est poursuivie par la clameur publique ou est trouvée en\npossession d’objets, ou présente des traces ou indices, laissant penser qu’elle\na participé au crime ou au délit.\nEst assimilé au crime ou délit flagrant tout crime ou délit qui, même non\ncommis dans les circonstances prévues à l’alinéa précédent, a été commis\ndans une maison dont le chef requiert le procureur de la République ou un\nofficier de police judiciaire de le constater.\nPeut être également soumis à la procédure du flagrant délit, tout délit, même\nancien, reconnu par son ou ses auteurs devant le procureur de la République\nou pour lequel des charges précises et concordantes ont été recueillies.","[CPPN] Art. 49 : En cas de crime flagrant, l’officier de police judiciaire qui en est\navisé informe immédiatement le procureur de la République, se transporte\nsans délai sur le lieu du crime et procède à toutes constatations utiles.\nIl veille à la conservation des indices susceptibles de disparaître et de tout\nce qui peut servir à la manifestation de la vérité. Il saisit les armes et\ninstruments qui ont servi à commettre le crime ou qui étaient destinés à le\ncommettre, ainsi que tout ce qui paraît avoir été le produit de ce crime.\nIl représente les objets saisis, pour reconnaissance, aux personnes qui\nparaissent avoir participé au crime, si elles sont présentes.","[CPPN] Art. 50 : Dans les lieux où un crime a été commis, il est interdit, sous peine\nd’une amende de 5.000 à 20.000 francs, à toute personne non habilitée, de\nmodifier avant les premières opérations de l’enquête judiciaire l’état des\nlieux et d’y effectuer des prélèvements quelconques.\nToutefois, exception est faite lorsque ces modifications ou ces prélèvements\nsont commandés par les exigences de la sécurité ou de la salubrité publique,\nou par les soins à donner aux victimes.\nSi les destructions des traces ou si les prélèvements sont effectués en vue\nd’entraver le fonctionnement de la justice, la peine est un emprisonnement\nde trois mois à trois ans et une amende de 30.000 à 300.000 francs.","[CPPN] Art. 51 : Si la nature du crime est telle que la preuve en puisse être acquise\npar la saisie des papiers, documents ou autres objets en la possession des\npersonnes qui paraissent avoir participé au crime ou détenir des pièces ou\n\nobjets relatifs aux faits incriminés, l’officier de police judiciaire se transporte\nsans désemparer au domicile de ces dernières pour y procéder à une\nperquisition dont il dresse procès-verbal.\nIl a seul, avec les personnes désignées à l’article 52 et celles auxquelles il\na éventuellement recours en application de l’article 55, le droit de prendre\nconnaissance des papiers ou documents avant de procéder à leur saisie.\nToutefois, il a l’obligation de provoquer préalablement toutes mesures utiles pour\nque soit assuré le respect du secret professionnel et des droits de la défense.\nTous objets et documents saisis sont immédiatement inventoriés et placés\nsous scellés.\nCependant, si leur inventaire sur place présente des difficultés, ils font\nl’objet de scellés fermés provisoires jusqu’au moment de leur inventaire et\nde leur mise sous scellés définitifs et ce, en présence des personnes qui ont\nassisté à la perquisition suivant les modalités prévues à l’article 52.\nAvec l’accord du procureur de la République, l’officier de police judiciaire ne maintient\nque la saisie des objets et documents utiles à la manifestation de la vérité.","[CPPN] Art. 52 : Sous réserve de ce qui est dit à l’article précédent concernant le\nrespect du secret professionnel et des droits de la défense, les opérations\nprescrites par ledit articlesont faites en présence de la personne au domicile\nde laquelle la perquisition a lieu.\nEn cas d’impossibilité, l’officier de police aura l’obligation de l’inviter à\ndésigner un représentant de son choix; à défaut, l’officier de police judiciaire\nchoisira deux témoins requis à cet effet par lui, en dehors des personnes\nrelevant de son autorité administrative.\nLe procès-verbal de ces opérations, dressé ainsi qu’il est dit à l’article 60,\nest signé par les personnes visées au présent article; au cas de refus, il en\nest fait mention au procès-verbal.","[CPPN] Art. 53 : Toute communication ou toute divulgation, sans l’autorisation de\nl’inculpé ou de ses ayants droit ou du signataire ou du destinataire, d’un\ndocument provenant d’une perquisition à une personne non qualifiée par la\nloi pour en prendre connaissance, est punie d’une amende de 30.000 à\n300.000 francs et d’un emprisonnement de trois mois à trois ans.\n\nCode de procédure pénale","[CPPN] Art. 54 : Sauf réclamation faite de l’intérieur de la maison ou exception\nprévues par la loi, les perquisitions et les visites domiciliaires ne peuvent\nêtre commencées avant cinq heures et après vingt et une heures.","[CPPN] Art. 55 : S’il y a lieu de procéder à des constatations qui ne puissent être\ndifférées, l’officier de police judiciaire a recours à toutes personnes\nqualifiées.\nLes personnes ainsi appelées prêtent, par écrit, serment de donner leur\navis en leur honneur et conscience.","[CPPN] Art. 56 : L’officier de police judiciaire peut défendre à toute personne de\ns’éloigner du lieu de l’infraction jusqu’à clôture de ses opérations.\nToute personne dont il apparaît nécessaire, au cours des recherches\njudiciaires, d’établir ou de vérifier l’identité, doit, à la demande de l’officier\nde police judiciaire, se prêter aux opérations qu’exige cette mesure.\nTout contrevenant aux dispositions des alinéas précédents est passible d’une\npeine qui ne peut excéder dix jours d’emprisonnement et 50.000 francs\nd’amende.","[CPPN] Art. 57 : (Loi n° 2003-26 du 13 juin 2003). L’officier de police judiciaire\npeut appeler et entendre toutes personnes susceptibles de fournir des\nrenseignements sur les faits.\nLes personnes convoquées par lui sont tenues de comparaître et de déposer.\nSi elles ne satisfont pas à cette obligation, avis en est donné au procureur\nde la République qui peut les contraindre à comparaître par la force publique.\nIl dresse un procès-verbal de leurs déclarations. Les personnes entendues\nprocèdent elles-mêmes à sa lecture, peuvent y faire consigner leurs\nobservations et y apposent leur signature. Si elles déclarent ne savoir lire,\nlecture et traduction leur en sont faites par un interprète ou par un officier\nde police dans leurs langues. Au cas de refus de signer le procès-verbal,\nmention en est faite sur celui-ci.","[CPPN] Art. 58 : L’officier de police judiciaire peut faire appel à un interprète âgé\nde vingt et un ans au moins.\nL’interprète, s’il n’est pas assermenté, fait serment de traduire fidèlement les\ndéclarations des personnes entendues. Il signe le procès-verbal qui est dressé.\n\nCode de procédure pénale","[CPPN] Art. 59 : (Loi n° 2003-26 du 13 juin 2003). Si, pour les nécessités de\nl’enquête, l’officier de police judiciaire est amené à garder à sa disposition\nune ou plusieurs personnes visées aux articles 56 et 57, il ne peut les retenir\nplus de quarante-huit heures.\nS’il existe contre une personne des indices graves et concordants de nature\nà motiver son inculpation, l’officier de police judiciaire doit la conduire devant\nle procureur de la République sans pouvoir la garder à sa disposition plus\nde quarante-huit heures, délai de conduite non compris.\nLe délai de quarante-huit (48) heures prévu à l’alinéa précédent peut être\nprolongé d’un nouveau délai de même durée par autorisation écrite du\nprocureur de la République ou du juge d’instruction.","[CPPN] Art. 60 : Les procès-verbaux dressés par l’officier de police judiciaire\nen exécution des articles 49 à 57 sont rédigés sur le champ et signés par lui\nsur chaque feuille du procès-verbal.","[CPPN] Art. 61 : Les dispositions des articles 49 à 60 sont applicables, au cas de\ndélit flagrant, dans tous les cas où la loi prévoit une peine d’emprisonnement.","[CPPN] Art. 62 : L’arrivée du procureur de la République sur les lieux dessaisit\nl’officier de police judiciaire.\nLe procureur de la République accomplit alors tous actes de police judiciaire\nprévus au présent chapitre.\nIl peut aussi prescrire à tous officiers de police judiciaire de poursuivre les\nopérations.","[CPPN] Art. 63 : Si les nécessités de l’enquête l’exigent, le procureur de la\nRépublique ou le juge d’instruction, lorsqu’il procède comme il est dit au\nprésent chapitre, peut se transporter dans les ressorts des tribunaux\nlimitrophes de celui où il exerce ses fonctions, à l’effet d’y poursuivre ses\ninvestigations. Il doit aviser, au préalable, le procureur de la République du\nressort du tribunal dans lequel il se transporte. Il mentionne sur son procèsverbal les motifs de son transport.","[CPPN] Art. 64 : En cas de crime flagrant et si le juge d’instruction n’est pas\nencore saisi, le procureur de la République peut décerner mandat d’amener\ncontre toute personne soupçonnée d’avoir participé à l’infraction.\n\nLe procureur de la République interroge sur le champ la personne ainsi\nconduite devant lui. Si elle se présente spontanément, accompagnée d’un\ndéfenseur, elle ne peut être interrogée qu’en présence de ce dernier.","[CPPN] Art. 65 : En cas de délit flagrant, lorsque le fait est puni d’une peine\nd’emprisonnement, et si le juge d’instruction n’est pas saisi, le procureur\nde la République peut mettre l’inculpé sous mandat de dépôt, après l’avoir\ninterrogé sur son identité et sur les faits qui lui sont reprochés.\nIl saisit alors le tribunal dans les conditions définies au livre II du présent\ncode relatif à la procédure devant les juridictions de jugement.\nLes dispositions prévues au présent article sont inapplicables aux infractions\ndont la poursuite est prévue par une loi spéciale ou si les personnes\nsoupçonnées d’avoir participé au délit sont mineures de dix-huit ans.","[CPPN] Art. 66 : Lorsque le juge d’instruction est présent sur les lieux, le procureur\nde la République ainsi que les officiers de police judiciaire sont de plein\ndroit dessaisis à son profit.\nLe juge d’instruction accomplit alors tous actes de police judiciaire prévus\nau présent chapitre.\nIl peut aussi prescrire à tous officiers de police judiciaire de poursuivre\nleurs opérations.\nCes opérations terminées, le juge d’instruction transmet les pièces de\nl’enquête au procureur de la République à toutes fins utiles.\nLorsque le procureur de la République et le juge d’instruction sont\nsimultanément sur les lieux, le procureur de la République peut requérir\nl’ouverture d’une information régulière dont est saisi le juge d’instruction\nprésent par dérogation, le cas échéant, aux dispositions de l’article 76.","[CPPN] Art. 67 : Dans les cas de crime flagrant ou de délit flagrant puni d’une\npeine d’emprisonnement, toute personne a qualité pour en appréhender\nl’auteur et le conduire devant l’officier de police judiciaire le plus proche.","[CPPN] Art. 68 : En cas de découverte d’un cadavre, qu’il s’agisse ou non d’une mort\nviolente, mais si la cause en est inconnue ou suspecte, l’officier de police judiciaire\nqui en est avisé informe immédiatement le procureur de la République, se\ntransporte sans délai sur les lieux et procède aux premières constatations.\n\nLe procureur de la République se rend sur place s’il le juge nécessaire et\nse fait assister de personnes capables d’apprécier la nature des\ncirconstances du décès. Il peut, toutefois, déléguer aux mêmes fins un\nofficier de police judiciaire de son choix.Les personnes ainsi appelées\nprêtent, par écrit, serment de donner leur avis en leur honneur et conscience.\nLe procureur de la République peut aussi requérir information pour\nrecherche des causes de la mort.\nCHAPITRE II : DE L’ENQUETE PRELIMINAIRE","[CPPN] Art. 69 : Les officiers de police judiciaire, soit sur les instructions du\nprocureur de la République, soit d’office, procèdent à des enquêtes\npréliminaires.\nCes opérations relèvent de la surveillance du procureur général.","[CPPN] Art. 70 : Les perquisitions, visites domiciliaires et saisies de pièces à\nconviction ne peuvent être effectuées sans l’assentiment exprès de la\npersonne chez laquelle l’opération a lieu.\nCet assentiment doit faire l’objet d’une déclaration écrite de la main de\nl’intéressé ou, si celui-ci ne sait écrire, il en est fait mention au procèsverbal ainsi que de son assentiment.\nLes formes prévues par les articles 51 et 54 sont applicables.","[CPPN] Art. 71 : (Loi n° 2003-26 du 13 juin 2003). Si, pour les nécessités de\nl’enquête, l’officier de police judiciaire est amené à garder à sa disposition\nune ou plusieurs personnes contre lesquelles existent des indices de\nculpabilité, il ne peut les retenir plus de quarante-huit heures. Passé ce\ndélai, il doit les relâcher ou les conduire devant le procureur de la République.\nToutefois, le procureur de la République peut accorder l’autorisation de\nprolonger la garde à vue d’un nouveau délai de quarante-huit heures.\nIl est notifié au suspect son droit de prendre un avocat à partir de la 24ème\nheure de la garde à vue sous peine de nullité de la procédure.\nCe délai commence à courir à compter de l’interpellation.\nLa personne déférée doit être accompagnée d’un certificat médical attestant\nqu’elle n’a pas subi de sévices.\n\nTITRE III : DES JURICTIONS D’INSTRUCTION\nCHAPITRE PREMIER :\nDU JUGE D’INSTRUCTION/JUDICTION D’INSTRUCTION\nDU PREMIER DEGRE\nSection 1 : Dispositions générales","[CPPN] Art. 72 : L’instruction préparatoire est obligatoire en matière de crime.\nSauf dispositions spéciales, elle est facultative en matière de délit. Elle ne\npeut avoir lieu en matière de contravention.","[CPPN] Art. 73 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction ne\npeut informer qu’en vertu d’un réquisitoire du procureur de la République,\nmême s’il a procédé en cas de crime ou de délit flagrant.\nDans les tribunaux d’instance, le juge d’instance peut en outre ouvrir une\ninformation après avoir rendu une ordonnance de saisine.\nLe réquisitoire et l’ordonnance de saisine peuvent être pris contre personne\ndénommée ou non dénommée.\nLe juge d’instruction a le pouvoir d’inculper toute personne ayant pris part,\ncomme auteur ou complice, aux faits qui lui sont déférés.\nLorsque des faits, non visés au réquisitoire, sont portés à la connaissance\ndu juge d’instruction d’un tribunal de grande instance, celui-ci doit\nimmédiatement communiquer au procureur de la République les plaintes\nou les procès-verbaux qui les constatent.\nEn cas de plainte avec constitution de partie civile, il est procédé comme il\nest dit à l’article 81.","[CPPN] Art. 74 : Le juge d’instruction procède, conformément à la loi, à tous les\nactes d’information qu’il juge utiles à la manifestation de la vérité.\nToutes les pièces du dossier sont cotées et inventoriées par le greffier au\nfur et à mesure de leur rédaction ou de leur réception par le juge d’instruction.\nSi le juge d’instruction est dans l’impossibilité de procéder lui-même à tous les\nactes d’instruction, il peut donner aux officiers de police judiciaire commission\nrogatoire afin de leur faire exécuter tous les actes d’information nécessaires\ndans les conditions et sous les réserves prévues aux articles 144 et 145.\n\nLe juge d’instruction procède ou fait procéder, soit par des officiers de\npolice judiciaire, conformément à l’alinéa 3, soit par toute personne habilitée\npar le ministre de la justice, à une enquête sur la personnalité des inculpés,\nainsi que leur situation matérielle, familiale ou sociale. Toutefois, en matière\nde délit, cette enquête est facultative.\nLe juge d’instruction peut prescrire un examen médical, confier à un médecin\nle soin de procéder à un examen médico-psychologique ou ordonner toutes\nautres mesures utiles. Si ces examens sont demandés par l’inculpé ou son\nconseil, il ne peut les refuser que par ordonnance motivée.","[CPPN] Art. 75 : (Loi n° 2003-26 du 13 juin 2003). Dans son réquisitoire\nintroductif, et à toute époque de l’information par réquisitoire supplétif, le\nprocureur de la République peut requérir du magistrat instructeur tous actes\nlui paraissant utiles à la manifestation de la vérité.\nIl peut à cette fin se faire communiquer la procédure, à charge de la rendre\ndans les quarante-huit heures.\nNonobstant cette communication, le juge d’instruction peut poursuivre sont\ninformation sans désemparer.\nSi le juge d’instruction ne croit pas devoir procéder aux actes requis, il doit\nrendre dans les 5 jours de la réception des réquisitions du procureur de la\nRépublique, une ordonnance motivée.","[CPPN] Art. 76 : Lorsqu’il existe dans un tribunal plusieurs juges d’instruction, le\nprésident du tribunal ou, en cas d’empêchement, le magistrat qui le remplace,\ndésigne, pour chaque information, le juge qui en sera chargé.","[CPPN] Art. 77 : Le dessaisissement du juge d’instruction au profit d’un autre juge\nd’instruction peut être demandé au président du tribunal dans l’intérêt d’une\nbonne administration de la justice, par requête du procureur de la République,\nagissant soit spontanément, soit à la demande de l’inculpé ou de la partie civile.\nLe président du tribunal doit statuer dans les huit jours par une ordonnance\nqui ne sera pas susceptible de voies de recours.\nToutefois, en cas d’urgence et pour des actes isolés, tout juge d’instruction\npeut suppléer un autre juge d’instruction du même tribunal, à charge par lui\nd’en rendre compte immédiatement au président du tribunal.\n\nCode de procédure pénale","[CPPN] Art. 78 : (Loi n° 2003-26 du 13 juin 2003). Dans le ressort de la Cour\nd’appel, le procureur général peut charger, par voie de réquisition, tout juge\nd’instruction d’informer sur tout crime ou délit qui lui aura été dénoncé,\nmême lorsqu’il aura été commis hors du ressort de la compétence de ce\nmagistrat; il peut également requérir tout juge d’instruction de continuer\nune information commencée par un autre magistrat qu’il fait dessaisir à cet\neffet. Cette décision est prise par le président de la Cour d’appel.\nLe juge d’instruction désigné dans les conditions prévues à l’alinéa précédent\na compétence pour instrumenter sur tout le territoire de la République du\nNiger.","[CPPN] Art. 79 : Les dispositions de l’article précédent ne dérogent pas en ce qui\nconcerne les juridictions de jugement aux règles de compétence territoriale\nédictées par le présent code.\nSection II : De la constitution de partie civile et de ses effets","[CPPN] Art. 80 : Toute personne qui se prétend lésée par un crime ou un délit,\npeut en portant plainte, se constituer partie civile devant le juge d’instruction\ncompétent.","[CPPN] Art. 81 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction d’un\ntribunal de grande instance ordonne communication de la plainte au procureur\nde la République pour que ce magistrat prenne ses réquisitions.\nLe réquisitoire peut être pris contre personne dénommée ou non dénommée.\nLe procureur de la République ne peut saisir le juge d’instruction de\nréquisitions de non informer que si, pour des causes affectant l’action\npublique elle-même, les faits ne peuvent légalement comporter une poursuite\nou si, à supposer ces faits démontrés, ils ne peuvent admettre aucune\nqualification pénale. Dans le cas où le juge d’instruction passe outre, il doit\nstatuer par une ordonnance motivée.\nEn cas de plainte insuffisamment motivée ou insuffisamment justifiée par\nles pièces produites, le juge d’instruction peut aussi être saisi de réquisitions\ntendant à ce qu’il soit provisoirement informé contre toutes personnes que\nl’instruction fera connaître.\n\nDans ce cas, celui ou ceux qui se trouvent visés par la plainte peuvent être\nentendus comme témoins par le juge d’instruction, sous réserve des\ndispositions de l’article 99 dont il devra leur donner connaissance, jusqu’au\nmoment où pourront intervenir des inculpations ou, s’il y a lieu, de nouvelles\nréquisitions contre personne dénommée.\nDans les tribunaux d’instance, dès réception de la plainte, le juge d’instance\nfaisant fonctions de juge d’instruction rend une ordonnance de saisine contre\npersonne dénommée ou non dénommée ou une ordonnance d","[CPPN] Art. 82 : (Loi n° 2003-26 du 13 juin 2003). La constitution de partie\ncivile peut avoir lieu à tout moment au cours de l’instruction. Elle n’est pas\nnotifiée aux autres parties.\nElle peut être contestée, soit par le ministère public, soit par l’inculpé, soit\npar une autre partie civile.\nEn cas de contestation ou s’il déclare d’office irrecevable la constitution\nde partie civile, le juge d’instruction statue par ordonnance motivée après\ncommunication du dossier au ministère public. Cette communication est\nfacultative pour le juge d’instance, faisant fonctions de juge d’instruction.","[CPPN] Art. 83 : La partie civile qui met en mouvement l’action publique doit, si\nelle n’a pas obtenu l’assistance judiciaire et sous peine de non recevabilité\nde sa plainte, consigner au greffe la somme présumée nécessaire pour les\nfrais de la procédure. Cette somme est fixée par ordonnance du juge\nd’instruction.","[CPPN] Art. 84 : Toute partie civile qui ne demeure pas au siège du tribunal où se\nfait l’instruction est tenue d’y élire domicile par acte au greffe de cette\njuridiction.\nA défaut d’élection de domicile, la partie civile ne peut opposer le défaut de\nsignification des actes qui auraient dû lui être signifiés aux termes de la loi.","[CPPN] Art. 85 : (Loi n° 2003-26 du 13 juin 2003). Dans le cas où le magistrat\ninstructeur n’est pas compétent aux termes de l’article 47, il rend, après\nréquisitions du ministère public, une ordonnance renvoyant la partie civile,\nà se pourvoir devant telle juridiction qu’il appartiendra.\n\nLe juge d’instance faisant fonctions de juge d’instruction, peut rendre cette\nordonnance sans réquisitions du ministère public.","[CPPN] Art. 86 : (Loi n° 2003-26 du 13 juin 2003). Quand, après une information\nouverte sur constitution de partie civile, une décision de non-lieu a été rendue,\nl’inculpé et toutes personnes visées dans la plainte, et sans préjudice d’une\npoursuite pour dénonciation calomnieuse peuvent, s’ils n’usent de la voie\ncivile, demander des dommages- intérêts au plaignant dans les formes\nindiquées ci-après.\nL’action en dommages - intérêts doit être introduite dans les trois mois du\njour où l’ordonnance de non-lieu est devenue définitive. Elle est portée par\nvoie de citation devant le tribunal correctionnel où l’affaire a été instruite.\nCe tribunal est immédiatement saisi du dossier de l’information terminée\npar une ordonnance de non-lieu, en vue de sa communication aux parties.\nLes débats ont lieu en Chambre du conseil; les parties ou leurs conseils et\nsauf devant les tribunaux d’instance, le ministère public, sont entendues.\nLe jugement est rendu en audience publique.\nEn cas de condamnation, le tribunal peut ordonner la publication intégrale\nou par extrait de son jugement dans un ou plusieurs journaux qu’il désigne,\naux frais du condamné. Il fixe le coût maximum de chaque insertion.\nL’opposition, s’il échet, et l’appel sont recevables dans les délais de droit\ncommun en matière correctionnelle.\nL’appel est porté devant la Chambre des appels correctionnels statuant\ndans les mêmes formes que le tribunal.\nL’arrêt de la Cour d’appel peut être déféré à la Cour suprême comme en\nmatière pénale.\nSe","[CPPN] Art. 87 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction peut\nse transporter sur les lieux pour y effectuer toutes constatations utiles ou\nprocéder à des perquisitions. Il en donne avis au procureur de la République,\nqui a la faculté de l’accompagner. Le juge d’instance, faisant fonction de\njuge d’instruction, est dispensé de cet avis.\n\nLe juge d’instruction est toujours assisté d’un greffier. Il dresse un procèsverbal de ses opérations.","[CPPN] Art. 88 : (Loi n° 2003-26 du 13 juin 2003). Si les nécessités de\nl’information l’exigent, le juge d’instruction peut, après en avoir donné avis\nau procureur de la République de son tribunal, se transporter avec son\ngreffier dans les ressorts des tribunaux limitrophes de celui où il exerce ses\nfonctions, à l’effet d’y procéder à tous actes d’instruction, à charge par lui\nd’aviser, au préalable, le procureur de la République du ressort du tribunal\ndans lequel il se transporte. Il mentionne sur son procès-verbal les motifs\nde son transport.\nLe juge d’instance, faisant fonction de juge d’instruction, est dispensé de\nl’avis au procureur de la République de son tribunal, prévu ci-dessus.","[CPPN] Art. 89 : Les perquisitions sont effectuées dans tous les lieux où peuvent\nse trouver des objets dont la découverte serait utile à la manifestation de la\nvérité.","[CPPN] Art. 90 : Si la perquisition a lieu au domicile de l’inculpé, le juge d’instruction\ndoit se conformer aux dispositions des articles 52 et 54.","[CPPN] Art. 91 : Si la perquisition a lieu dans un domicile autre que celui de l’inculpé,\nla personne chez laquelle elle doit s’effectuer est invitée à y assister. Si\ncette personne est absente ou refuse d’y assister, la perquisition a lieu en\nprésence de deux de ses parents ou alliés présents sur les lieux ou, à défaut,\nen présence de deux témoins.\nLe juge d’instruction doit se conformer aux dispositions des articles 52,\nalinéa 2 et 54. Toutefois, il a l’obligation de provoquer préalablement toutes\nmesures utiles pour que soit assuré le respect du secret professionnel et\ndes droits de la défense.","[CPPN] Art. 92 : Lorsqu’il y a lieu, en cours d’information, de rechercher des\ndocuments et sous réserve des nécessités de l’information et du respect, le\ncas échéant, de l’obligation stipulée par l’alinéa 3 de l’article précédent, le\njuge d’instruction ou l’officier de police judiciaire par lui commis a seul le\ndroit d’en prendre connaissance avant de procéder à la saisie.\nTous objets et documents saisis sont immédiatement inventoriés et placés\nsous scellés.\n\nCes scellés ne peuvent être ouverts et les documents dépouillés qu’en\nprésence de l’inculpé assisté de son conseil, ou eux dûment appelés. Le tiers\nchez lequel la saisie a été faite est également invité à assister à cette opération.\nLe juge d’instruction ne maintient que la saisie des objets et documents\nutiles à la manifestation de la vérité ou dont la communication serait de\nnature à nuire à l’instruction. Si les nécessités de l’instruction ne s’y opposent,\nles intéressés peuvent obtenir à leurs frais, dans le plus bref délai, copie ou\nphotocopie des documents dont la saisie est maintenue.\nSi la saisie porte sur des espèces, lingots, effets ou valeurs dont la\nconservation en nature n’est pas nécessaire à la manifestation de la vérité\nou à la sauvegarde des droits des parties, il peut autoriser le greffier à en\nfaire le dépôt entre les mains de l’inspecteur de l’enregistrement ou de son\nreprésentant local.","[CPPN] Art. 92.1 : (Loi n° 2017-07 du 31 mars 2017) En matière de criminalité\ntransnationale organisée, de terrorisme et de financement du terrorisme, le\njuge d’instruction saisi, peut prendre des mesures afin d’identifier, de localiser\net de saisir les biens suivants :\n- le produit provenant de l’infraction;\n- les biens, matériels ou autres instruments utilisés ou destinés à être utilisés\npour commettre lesdites infractions;\n- le produit du crime transformé ou converti, en partie ou en totalité, en\nd’autres biens;\n- le produit du crime mêlé à des biens acquis légitimement, à concurrence\nde la valeur estimée du produit qui y a été mêlé;\n- les revenus ou autres avantages tirés du produit du crime, ceux tirés du\nproduit transformé ou converti et ceux tirés du produit mêlé.\nA ce titre, il peut, sans préjudice des droits des tiers acquis de bonne foi,\nprocéder au gel ou à la saisie des biens visés à l’alinéa précédent.\nLe juge d’instruction saisi, peut également ordonner la production ou la\nsaisie de documents bancaires, financiers ou commerciaux ayant servi ou\ndestinés à commettre lesdites infractions.\nLe secret bancaire ne peut lui être opposé.\n\nCode de procédure pénale","[CPPN] Art. 93 : Sous réserve des nécessités de l’information judiciaire, toute\ncommunication ou toute divulgation sans l’autorisation de l’inculpé ou de\nses ayants droits ou du signataire ou du destinataire d’un document provenant\nd’une perquisition à une personne non qualifiée par la loi pour en prendre\nconnaissance, est punie d’une amende de 10.000 à 100.000 francs et d’un\nemprisonnement de deux mois à deux ans.","[CPPN] Art. 94 : (Loi n° 2003-26 du 13 juin 2003). L’inculpé, la partie civile ou\ntoute autre personne qui prétend avoir droit sur un objet placé sous la main\nde la justice peut en réclamer la restitution au juge d’instruction.\nSi la demande émane de l’inculpé ou de la partie civile, elle est communiquée\nà l’autre partie ainsi qu’au ministère public. Si elle émane d’un tiers, elle\nest communiquée à l’inculpé, à la partie civile et au ministère public. La\ncommunication au ministère public est facultative si l’information est ouverte\nau siège d’un tribunal d’instance.\nLes observations que peut comporter la demande doivent être produites\ndans les trois jours de cette communication.\nLa décision du juge d’instruction peut être déférée à la Chambre\nd’accusation, sur simple requête, dans les dix jours de sa notification aux\nparties intéressées, sans toutefois que l’information puisse s’en trouver\nretardée.\nLe tiers peut, au même titre que les parties, être entendu par la Chambre\nd’accusation en ses observations, mais il ne peut prétendre à la mise à sa\ndisposition de la procédure.","[CPPN] Art. 95 : Après décision de non-lieu, le juge d’instruction demeure compétent\npour statuer sur la restitution des objets saisis. Ses décisions peuvent être déférées\nà la Chambre d’accusation, comme il est dit à l’alinéa 4 de l’article 94.\nSection IV : Des auditions de témoins","[CPPN] Art. 96 : Le juge d’instruction fait citer devant lui, par un huissier ou un\nagent de la force publique, toutes les personnes dont la déposition lui paraît\nutile. Une copie de cette citation leur est délivrée.\nLes témoins peuvent aussi être convoqués par lettre simple, par lettre\nrecommandée ou par voie administrative; ils peuvent en outre comparaître\nvolontairement.\n\nCode de procédure pénale","[CPPN] Art. 97 : Ils sont entendus séparément, et hors la présence de l’inculpé,\npar le juge d’instruction assisté de son greffier; il est dressé procès-verbal\nde leurs déclarations.\nLe juge d’instruction peut faire appel à un interprète âgé de 21 ans au\nmoins, à l’exclusion de son greffier et des témoins. L’interprète, s’il n’est\npas assermenté, prête serment de traduire fidèlement les dépositions.","[CPPN] Art. 98 : (Loi n° 2003-26 du 13 juin 2003). Les témoins prêtent serment\nde dire toute la vérité, rien que la vérité. Le juge leur demande leurs nom,\nprénoms, âge, état, profession, demeure, langue, s’ils sont parents ou alliés\ndes parties et à quel degré ou s’ils sont à leur service. Il est fait mention de\nla demande et de la réponse.","[CPPN] Art. 99 : Toute personne nommément visée par une plainte assortie d’une\nconstitution de partie civile peut refuser d’être entendue comme témoin.\nLe juge d’instruction l’en avertit, après lui avoir donné connaissance de la\nplainte. Mention en est faite au procès-verbal. En cas de refus, il ne peut\nl’entendre que comme inculpée.","[CPPN] Art. 100 : Le juge d’instruction chargé d’une information, ainsi que les\nmagistrats et officiers de police judiciaire, agissant sur commission rogatoire,\nne peuvent, à peine de nullité, entendre comme témoins des personnes\ncontre lesquelles il existe des indices graves et concordants de culpabilité,\nlorsque cette audition aurait pour effet d’éluder les garanties de la défense.","[CPPN] Art. 101 : Chaque page des procès-verbaux est signée du juge, du greffier\net du témoin. Ce dernier est alors invité à relire sa déposition telle qu’elle\nvient d’être transcrite, puis à la signer s’il déclare y persister. Si le témoin\nne sait pas lire, lecture lui en est faite par le greffier. Si le témoin ne veut ou\nne peut signer, mention en est portée sur le procès-verbal. Chaque page\nest également signée par l’interprète s’il y a lieu.","[CPPN] Art. 102 : Les procès-verbaux ne peuvent comporter aucun interligne.\nLes ratures et les renvois sont approuvés par le juge d’instruction, le greffier\net le témoin et, s’il y a lieu, par l’interprète. A défaut d’approbation, ces\nratures et ces renvois sont non avenus.\nIl en est de même du procès-verbal qui n’est pas régulièrement signé.\n\nCode de procédure pénale","[CPPN] Art. 103 : Les enfants au-dessous de l’âge de seize ans sont entendus\nsans prestation de serment.","[CPPN] Art. 104 : Toute personne citée pour être entendue comme témoin est\ntenue de comparaître, de prêter serment, et de déposer sous réserve des\ndispositions du code pénal réprimant la violation du secret professionnel.\nSi le témoin ne comparaît pas, le juge d’instruction peut, sur les réquisitions\ndu procureur de la République, l’y contraindre par la force publique et le\ncondamner à une amende de 10.000 à 100.000 francs. Toutefois, il peut\nultérieurement sur production de ses excuses et justifications, être déchargé\nde ces peines par le juge d’instruction, après réquisition du procureur de la\nRépublique.\nLa même peine peut, sur les réquisitions de ce magistrat, être prononcée\ncontre le témoin qui, bien que comparaissant, refuse de prêter serment et\nde faire sa déposition.\nLe juge d’instance, faisant fonction de juge d’instruction, peut d’office et\nsans réquisitions du ministère public, contraindre le témoin à comparaître\net prononcer à son encontre les peines prévues ci-dessus.\nLe témoin condamné en vertu des alinéas précédents peut interjeter appel\nde la condamnation dans les trois jours de ce prononcé; s’il était défaillant,\nce délai ne commence à courir que du jour de la notification de la\ncondamnation. L’appel est porté devant la Chambre d’accusation.","[CPPN] Art. 105 : La mesure de contrainte dont fait l’objet le témoin défaillant est\nprise par voie de réquisition. Le témoin est conduit directement et sans\ndélai devant le magistrat qui a prescrit la mesure.","[CPPN] Art. 106 : Si un témoin est dans l’impossibilité de comparaître, le juge\nd’instruction se transporte pour l’entendre ou délivre à cette fin commission\nrogatoire dans les formes prévues à l’article 144.","[CPPN] Art. 107 : Si le témoin entendu dans les conditions prévues à l’article\nprécédent n’était pas dans l’impossibilité de comparaître sur la citation,\nle juge d’instruction peut prononcer contre ce témoin la peine prévue à\nl’article 104.\n\nSection V : Des interrogatoires et confrontations","[CPPN] Art. 108 : (Loi n° 2003-26 du 13 juin 2003). Lors de la première\ncomparution, le juge d’instruction constate l’identité de l’inculpé, lui fait\nconnaître expressément chacun des faits qui lui sont imputés et l’avertit\nqu’il est prêt à recevoir immédiatement ses déclarations. Mention de cet\navertissement est faite au procès-verbal.\nL’inculpé peut se faire assister d’un avocat.\nSi l’inculpé ne l’a pas déjà fait, le magistrat lui donne avis de son droit de\nchoisir un conseil parmi les avocats inscrits au Niger ou dans un Etat qui a\npassé avec le Niger une convention de réciprocité.\nSi l’inculpé fait des déclarations, celles-ci sont immédiatement reçues par\nle juge d’instruction.\nLa partie civile régulièrement constituée a également le droit de se faire\nassister d’un avocat - défenseur dès sa première audition.\nLors de la première comparution, le juge avertit l’inculpé qu’il doit l’informer\nde tous ses changements d’adresse; ce dernier doit, le cas échéant, faire\nélection de domicile dans le ressort du tribunal.","[CPPN] Art. 109 : Nonobstant les dispositions prévues à l’article précédent, le\njuge d’instruction peut procéder à un interrogatoire immédiat et à des\nconfrontations si l’urgence résulte, soit de l’état d’un témoin en danger de\nmort, soit de l’existence d’indices sur le point de disparaître, ou encore\ndans le cas prévu au dernier alinéa de l’article 66.\nLe procès-verbal doit faire mention des causes d’urgence.","[CPPN] Art. 110 : L’inculpé détenu peut aussitôt après la première comparution\ncommuniquer librement avec son avocat-défenseur.\nLe juge d’instruction a le droit de prescrire l’interdiction de communiquer\npour une période de quinze jours. Il peut la renouveler mais pour une nouvelle\npériode de quinze jours seulement.\nEn aucun cas, l’interdiction de communiquer ne s’appliquera au conseil de\nl’inculpé.\n\nCode de procédure pénale","[CPPN] Art. 111 : L’inculpé et la partie civile peuvent, à tout moment de l’information,\nfaire connaître au juge d’instruction le nom du ou des avocats-défenseurs\nchoisis par eux. S’ils désignent plusieurs conseils, ils doivent faire connaître\ncelui d’entre eux auquel seront adressées les convocations et notifications.","[CPPN] Art. 112 : (Loi n° 2003-26 du 13 juin 2003). L’inculpé et la partie civile\nne peuvent être entendus ou confrontés, à moins qu’ils n’y renoncent\nexpressément, qu’en présence de leurs conseils ou eux dûment appelés.\nL’avocat-défenseur est convoqué par lettre avec accusé de réception\nadressée au plus tard l’avant-veille de l’interrogatoire.\nLa procédure doit être mise à la disposition du conseil de l’inculpé 24 heures\nau plus tard avant chaque interrogatoire. Elle doit également être mise à la\ndisposition du conseil de la partie civile 24 heures au plus tard avant les\nauditions de cette dernière.\nLes formalités prévues par le présent article ne sont exigées que si le ou\nles conseils résident au siège de l’instruction.","[CPPN] Art. 113 : Le procureur de la République peut assister aux interrogatoires\net confrontations de l’inculpé et aux auditions de la partie civile.\nChaque fois que le procureur de la République a fait connaître au juge\nd’instruction son intention d’y assister, le greffier du juge d’instruction doit,\nsous peine d’une amende civile de 1.000 francs prononcée par le président\nde la Chambre d’accusation, l’avertir par simple note, au plus tard l’avantveille de l’interrogatoire.","[CPPN] Art. 114 : Le procureur de la République et les conseils de l’inculpé et de\nla partie civile ne peuvent prendre la parole que pour poser des questions\naprès y avoir été autorisés par le juge d’instruction.\nSi cette autorisation leur est refusée, le texte des questions sera reproduit\nou joint au procès-verbal.","[CPPN] Art. 115 : Les procès-verbaux d’interrogatoire et de confrontation sont\nétablis dans les formes prévues aux articles 101 et 102.\n\nSection VI : Des mandats et de leur exécution","[CPPN] Art. 116 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction peut,\nselon le cas, décerner mandat de comparution, d’amener, de dépôt ou d’arrêt.\nLe mandat de comparution a pour objet de mettre l’inculpé en demeure de\nse présenter devant le juge à la date et à l’heure indiquées par ce mandat.\nLe mandat d’amener est l’ordre donné par le juge à la force publique de\nconduire immédiatement l’inculpé devant lui.\nLe mandat de dépôt est l’ordre donné par le juge au régisseur de\nl’établissement pénitentiaire de recevoir et de détenir l’inculpé. Ce mandat\npermet également de rechercher ou de transférer l’inculpé lorsqu’il lui a\nété précédemment notifié.\nLe mandat d’arrêt est l’ordre donné à la force publique de rechercher\nl’inculpé et de le conduire à l’établissement pénitentiaire indiqué sur le\nmandat où il sera reçu et détenu.","[CPPN] Art. 117 : (Loi n° 2003-26 du 13 juin 2003). Tout mandat précise l’identité\nde l’inculpé; il est daté et signé par le magistrat qui l’a décerné et est\nrevêtu de son sceau.\nLes mandats d’amener, de dépôt et d’arrêt mentionnent en outre la nature\nde l’inculpation et les articles de loi applicables. Cette formalité n’entraîne\npas l’obligation de délivrer un second mandat de dépôt ou d’arrêt, lorsque\nl’information révèle l’existence de faits nouveaux ou une nouvelle\nqualification des faits qui étaient à la base de la poursuite.\nLe mandat de comparution est signifié par huissier à celui qui en est l’objet\nou est notifié à celui-ci par un officier ou agent de police judiciaire, ou par\nun agent de la force publique, lequel lui en délivre copie.\nLe mandat d’amener ou d’arrêt est notifié et exécuté par un officier ou\nagent de police judiciaire, ou par un agent de la force publique, lequel en\nfait l’exhibition et lui en délivre copie.\nSi l’individu est déjà détenu pour une autre cause, la notification lui est faite\ncomme il est dit à l’alinéa précédent ou, sur instructions du procureur de la\nRépublique, par le régisseur de l’établissement pénitentiaire, qui en délivre\négalement une copie.\n\nLes mandats d’amener ou d’arrêt peuvent, en cas d’urgence, être diffusés\npar tous moyens. Dans ce cas, les mentions essentielles de l’original et\nspécialement l’identité de l’inculpé, la nature de l’inculpation, le nom et la\nqualité du magistrat mandant doivent être précisés. L’original du mandat\ndoi","[CPPN] Art. 118 : Les mandats sont exécutoires dans toute l’étendue du territoire\nde la République.","[CPPN] Art. 119 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction\ninterroge immédiatement l’inculpé qui fait l’objet d’un mandat de\ncomparution.\nIl est procédé dans les mêmes conditions à l’interrogatoire de l’inculpé\narrêté en vertu d’un mandat d’amener; toutefois si l’interrogatoire ne peut\nêtre immédiat, l’inculpé est conduit dans l’établissement pénitentiaire du\nsiège du tribunal où il ne peut être détenu plus de vingt-quatre heures.\nA l’expiration de ce délai, il est conduit d’office, par les soins du régisseur,\nsoit devant le juge d’instance, ès qualités de juge d’instruction, qui doit\nprocéder immédiatement à son interrogatoire, soit devant le procureur de\nla République qui requiert le juge d’instruction ou à son défaut le président\ndu tribunal ou un juge désigné par celui-ci, de procéder immédiatement à\nl’interrogatoire. A défaut d’être interrogé, il sera mis en liberté.","[CPPN] Art. 120 : (Loi n° 2003-26 du 13 juin 2003). Tout inculpé arrêté en\nvertu d’un mandat d’amener, qui a été maintenu pendant plus de vingtquatre heures dans l’établissement pénitentiaire du siège du tribunal sans\navoir été interrogé, est considéré comme arbitrairement détenu.","[CPPN] Art. 121 : Si l’inculpé recherché en vertu d’un mandat d’amener est trouvé\nhors du ressort du juge d’instruction qui a délivré ce mandat, il est conduit\ndevant le procureur de la République du lieu de l’arrestation.\n\nCode de procédure pénale","[CPPN] Art. 122 : (Loi n° 2003-26 du 13 juin 2003). Ce magistrat l’interroge\nsur son identité, reçoit ses déclarations, après l’avoir averti qu’il est libre\nde ne pas en faire, l’interpelle afin de savoir s’il consent à être transféré ou\ns’il préfère prolonger les effets du mandat d’amener, en attendant, au lieu\noù il se trouve, la décision du juge d’instruction saisi de l’affaire. Si l’inculpé\ndéclare s’opposer au transfèrement, il est conduit dans l’établissement\npénitentiaire et avis immédiat est donné au juge d’instruction compétent.\nLe procès-verbal de la comparution contenant un signalement complet est\ntransmis sans délai à ce magistrat, avec toutes les indications propres à\nfaciliter la reconnaissance d’identité.\nCe procès-verbal doit mentionner que l’inculpé a reçu avis qu’il est libre de\nne pas faire de déclaration.","[CPPN] Art. 123 : Le juge d’instruction saisi de l’affaire décide, aussitôt après la\nréception de ces pièces, s’il y a lieu d’ordonner le transfèrement.","[CPPN] Art. 124 : Si l’inculpé contre lequel a été décerné un mandat d’amener ne\npeut être découvert, ce mandat est présenté au maire, ou à l’un de ses\nadjoints, de la commune de sa résidence ou, à défaut, au chef de la\ncirconscription administrative dont dépend cette commune.\nLe maire, l’adjoint ou le chef de la circonscription administrative appose\nson visa sur le mandat qui est renvoyé au magistrat mandant avec un procèsverbal de recherches infructueuses.\nL’inculpé qui refuse d’obéir au mandat d’amener ou qui, après avoir déclaré\nqu’il est prêt à obéir, tente de s’évader, doit être contraint par la force.\nLe porteur du mandat d’amener emploie dans ce cas la force publique du\nlieu le plus voisin.\nCelle-ci est tenue de déférer à la réquisition contenue dans ce mandat.","[CPPN] Art. 125 : (Loi n° 2003-26 du 13 juin 2003). Si l’inculpé est en fuite ou\nrisque de s’enfuir, ou si son lieu de résidence est inconnu, ou encore s’il\nréside hors du territoire de la République, le juge d’instruction, après\nréquisition du procureur de la République, peut décerner contre lui un mandat\nd’arrêt, si le fait comporte une peine d’emprisonnement correctionnelle ou\nune peine plus grave.\n\nLe juge d’instance, faisant fonctions de juge d’instruction, peuvent décerner\nun mandat d’arrêt sans réquisitions préalables du procureur de la\nRépublique.","[CPPN] Art. 126 : (Loi n° 2003-26 du 13 juin 2003). L’inculpé saisi en vertu d’un\nmandat d’arrêt est conduit sans délai dans l’établissement pénitentiaire indiqué\nsur le mandat, sous réserve des dispositions de l’article 127, alinéa 1.\nLe régisseur délivre à l’agent chargé de l’exécution une reconnaissance\nde la remise de l’inculpé.","[CPPN] Art. 127 : Si l’inculpé est arrêté hors du ressort du juge d’instruction qui a\ndélivré le mandat, il est conduit immédiatement devant le procureur de la\nRépublique du lieu de l’arrestation, qui reçoit ses déclarations, après l’avoir\naverti qu’il est libre de ne pas en faire. Mention est faite de cet avis au\nprocès-verbal.\nLe procureur de la République informe sans délai le magistrat qui a délivré\nle mandat et requiert le transfèrement. Si celui-ci ne peut être effectué\nimmédiatement, le procureur de la République en réfère au juge mandant.","[CPPN] Art. 128 : L’agent chargé de l’exécution d’un mandat d’arrêt ne peut\ns’introduire dans le domicile d’un citoyen avant cinq heures et après vingt\net une heures.\nIl peut se faire accompagner d’une force suffisante pour que l’inculpé ne\npuisse se soustraire à la loi. Cette force est prise dans le lieu le plus proche\nde celui où le mandat d’arrêt doit s’exécuter et elle est tenue de déférer\naux réquisitions contenues dans le mandat.\nSi l’inculpé ne peut être saisi, le mandat d’arrêt est notifié à sa dernière\nhabitation et il est dressé procès-verbal de perquisition.\nCe procès-verbal est dressé en présence des deux plus proches voisins de\nl’inculpé que le porteur du mandat d’arrêt peut trouver. Ils le signent ou,\ns’ils ne savent ou ne veulent pas signer, il en est fait mention, ainsi que de\nl’interpellation qui leur a été faite.\nLe porteur du mandat d’arrêt fait ensuite viser son procès-verbal par le\nmaire ou l’un de ses adjoints ou, à défaut, par le chef de la circonscription\nadministrative du lieu et lui en laisse copie.\n\nLe mandat d’arrêt et le procès-verbal sont ensuite transmis au juge mandant\nou au greffe du tribunal.","[CPPN] Art. 129 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction ne\npeut délivrer un mandat de dépôt qu’après interrogatoire et si l’infraction\ncomporte une peine d’emprisonnement correctionnelle ou une autre peine\nplus grave.\nL’agent chargé de l’exécution du mandat de dépôt remet l’inculpé au\nrégisseur de l’établissement pénitentiaire, lequel lui délivre une\nreconnaissance de la remise de l’inculpé.","[CPPN] Art. 130 : L’inobservation des formalités prescrites pour les mandats de\ncomparution, d’amener, de dépôt et d’arrêt est sanctionnée par une amende\ncivile de 5.000 francs prononcée contre le greffier par le président de la\nChambre d’accusation; elle peut donner lieu à des sanctions disciplinaires ou\nà prise à partie contre le juge d’instruction ou le procureur de la République.\nCes dispositions sont étendues, sauf application de peines plus graves, s’il\ny a lieu, à toute violation des mesures protectrices de la liberté individuelle\nprescrites par les articles 51, 52, 54, 91,92, 132, 133 et 135.\nDans les cas visés aux deux alinéas précédents et dans tous les cas d’atteinte\nà la liberté individuelle, le conflit ne peut jamais être élevé par l’autorité\nadministrative et les tribunaux de l’ordre judiciaire sont toujours\nexclusivement compétents.\nIl en est de même dans toute instance civile fondée sur des faits constitutifs\ndes infractions relatives aux attentats à la liberté et abus d’autorité contre\nles particuliers, prévus au code pénal, qu’elle soit dirigée contre la collectivité\npublique ou contre ses agents.\nSection VII : De la détention préventive","[CPPN] Art. 131 : (Loi n° 2003-26 du 13 juin 2003). La détention provisoire est\nune mesure exceptionnelle. Elle ne peut être ordonnée ou maintenue que\ndans les conditions définies ci-après :\n1. lorsque la détention préventive de l’inculpé est l’unique moyen de\nconserver les preuves ou les indices matériels ou d’empêcher soit une\npression sur les témoins ou les victimes, soit une concertation frauduleuse\nentre les inculpés;\n\n2. lorsque cette détention est l’unique moyen pour protéger l’inculpé, de\ngarantir son maintien à la disposition de la justice, de mettre fin à l’infraction\nou prévenir son renouvèlement;\n3. lorsque l’infraction, en raison de sa gravité, des circonstances de sa\ncommission ou de l’importance du préjudice qu’elle a causé, a provoqué un\ntrouble exceptionnel et persistant à l’ordre public, auquel la détention est\nl’unique moyen de mettre fin.L’inculpé peut se faire assister par un avocat.\nLorsqu’elle est prescrite, par ordonnance motivée, les règles ci-après doivent\nêtre observées.","[CPPN] Art. 131.1 bis : (Loi n° 2003-26 du 13 juin 2003). La détention provisoire\nne peut excéder une durée raisonnable, au regard de la gravité des faits\nreprochés à l’inculpé et de la complexité des investigations nécessaires à\nla manifestation de la vérité.\nLe juge d’instruction doit ordonner la mise en liberté immédiate de la\npersonne placée en détention préventive, selon les modalités prévues par\nl’article 134, dès que les conditions prévues à l’article 131 et au présent\narticle ne sont plus remplies.","[CPPN] Art. 132 : (Loi n° 2003-26 du 13 juin 2003). En matière correctionnelle,\nlorsque le maximum de la peine prévue par la loi est inférieur ou égal à 3\nans d’emprisonnement, l’inculpé domicilié au Niger ne peut être détenu\nplus de six mois après sa première comparution devant le juge d’instruction\ns’il n’a pas été déjà condamné soit pour crime, soit pour délit à un\nemprisonnement de plus de trois ans sans sursis.\nDans les cas autres que ceux prévus à l’alinéa précédent, l’inculpé ne peut\nêtre détenu plus de six mois renouvelables une seule fois par ordonnance\nmotivée du juge d’instruction.\nArt. 132-1 : (Loi n° 2003-26 du 13 juin 2003). En matière criminelle,\nl’inculpé ne peut être maintenu en détention au-delà de 18 mois. Toutefois,\nle juge d’instruction peut, à l’expiration de ce délai décidé de prolonger la\ndétention pour une durée qui ne peut être supérieure à 12 mois par une\nordonnance non renouvelable selon la même procédure.\n\n(Loi n° 2007-04 du 22 février 2007). Toutefois, les dispositions ci-dessus\nne s’appliquent pas aux cas de meurtre, assassinat, parricide,\nempoisonnement ainsi qu’aux vols criminels et aux détournements de deniers\npublics.","[CPPN] Art. 133 : En toute matière, lorsqu’elle n’est pas de droit, la mise en\nliberté provisoire peut être ordonnée d’office par le juge d’instruction après\navis du procureur de la République, à charge pour l’inculpé de prendre\nl’engagement de se représenter à tous les actes de la procédure aussitôt\nqu’il en sera requis et de tenir informé le magistrat instructeur de tous ses\ndéplacements.\nLe procureur de la République peut également la requérir à tout moment.\nLe juge d’instruction statue dans le délai de cinq jours à compter de la date\nde ces réquisitions.\nLe juge d’instance faisant fonctions de juge d’instruction, peut ordonner la\nmise en liberté provisoire d’un inculpé sans l’avis préalable du procureur\nde la République.","[CPPN] Art. 134 : (Loi n° 2003-26 du 13 juin 2003). La mise en liberté provisoire\npeut être demandée à tout moment au juge d’instruction, par l’inculpé ou\nson conseil, sous les obligations prévues à l’article précédent.\nLe juge d’instruction doit immédiatement communiquer le dossier au\nprocureur de la République, aux fins de réquisitions, après avoir notifié la\ndemande à la partie civile qui peut présenter des observations.\nLe juge d’instruction doit statuer, par ordonnance spécialement motivée,\nau plus tard dans les dix jours de la communication au procureur de la\nRépublique.\nLorsqu’il y a une partie civile en cause, l’ordonnance du juge d’instruction\nne peut intervenir que cinq jours après l’avis donné à cette partie.\nLe juge d’instance, faisant fonctions de juge d’instruction, peut statuer sans\ncommunication préalable au procureur de la République aux fins de\nréquisitions. Il doit rendre alors son ordonnance dans les 5 jours de la\nréception de la demande.\n\nFaute par le juge d’instruction d’avoir statué dans les délais susvisés,\nl’inculpé peut saisir directement de sa demande la Chambre d’accusation\nqui, sur les réquisitions écrites et motivées du procureur général, se prononce\ndans les quinze jours de la réception de cette demande, faute de quoi l’inculpé\nest mis d’office en liberté provisoire, sauf si des vérifications concernant\nsa demande ont été ordonnées. Le droit de saisir dans les mêmes conditions\nla Chambre d’accusation appartient également au procureur de la\nRépublique.","[CPPN] Art. 135 : La mise en liberté provisoire peut aussi être demandée en tout\nétat de cause par tout inculpé, prévenu ou accusé, et en toute période de la\nprocédure.\nLorsqu’une juridiction de jugement est saisie, il lui appartient de statuer sur\nla liberté provisoire ; avant le renvoi en Cour d’assises et dans l’intervalle\ndes sessions d’assises, ce pouvoir appartient à la Chambre d’accusation.\nEn cas de pourvoi et jusqu’à l’arrêt de la Cour suprême, il est statué sur la\ndemande de mise en liberté provisoire par la juridiction qui a connu en\ndernier lieu l’affaire au fond. Si le pourvoi a été formé contre un arrêt de la\nCour d’assises, il est statué sur la détention par la Chambre d’accusation.\nEn cas de décision d’incompétence et, généralement, dans tous les cas où\naucune juridiction n’est saisie, la Chambre d’accusation connaît des\ndemandes de mise en liberté.\nDans tous les cas où un individu de nationalité étrangère inculpé, prévenu\nou accusé, est laissé ou mis en liberté provisoire, seule la juridiction\ncompétente peut lui assigner pour résidence un lieu dont il ne devra s’éloigner\nsans autorisation, avant non-lieu ou décision définitive, sous les peines\nprévues au code pénal pour infraction à arrêté d’interdiction de séjour.","[CPPN] Art. 136 : Lorsque la juridiction de jugement est appelée à statuer dans les\ncas prévus au précédent article, les parties et leurs conseils sont convoqués\npar lettre recommandée, par avis administratif avec accusé de réception\nou par notification administrative constatée par procès-verbal. La décision\nest prononcée après audition du ministère public s’il est représenté auprès\nde la juridiction et des parties ou de leurs conseils.\n\nCode de procédure pénale","[CPPN] Art. 137 : (Loi n° 2003-26 du 13 juin 2003). Préalablement à la mise\nen liberté provisoire, avec ou sans cautionnement, le demandeur doit, par\nacte reçu au greffe de l’établissement pénitentiaire, élire domicile au lieu\nde son incarcération. Avis de cette déclaration est donné par le régisseur\nde cet établissement à l’autorité compétente.\nAprès la mise en liberté provisoire, si l’inculpé invité à comparaître ne se\nprésente pas ou si des circonstances nouvelles ou graves rendent sa\ndétention nécessaire, le juge d’instruction ou la juridiction de jugement saisie\nde l’affaire peut décerner un nouveau mandat.\nLe même droit appartient en cas de décision d’incompétence à la Chambre\nd’accusation jusqu’à ce que la juridiction compétente ait été saisie.\nLorsque la liberté provisoire a été accordée par la Chambre d’accusation\nréformant l’ordonnance du juge d’instruction, ce magistrat ne peut décerner\nun nouveau mandat qu’autant que cette chambre, sur les réquisitions écrites\ndu ministère public, a retiré à l’inculpé le bénéfice de sa décision.\nArt. 138 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) La mise\nen liberté provisoire, dans tous les cas où elle n’est pas de droit, peut être\nsubordonnée à l’obligation de fournir un cautionnement.\nCe cautionnement garantit :\n1)la représentation de l’inculpé à tous les actes de la procédure et\npour l’exécution du jugement ;\n2) le payement dans l’ordre suivant ;\na) des frais avancés par la partie civile ;\nb) de ceux faits par la partie publique ;\nc","[CPPN] Art. 139 : Dans le cas où la liberté provisoire a été subordonnée à un\ncautionnement, ce cautionnement est fourni en espèces, billets de banque,\nchèques certifiés ou titres émis ou garantis par l’Etat. Il est versé entre les\nmains du greffier du tribunal ou de la Cour d’appel ou du receveur de\nl’enregistrement.\nSur le vu du récépissé, le ministère public fait exécuter, sur-le-champ, la\ndécision de mise en liberté.","[CPPN] Art. 140 : La première partie du cautionnement est restituée si l’inculpé\ns’est présenté à tous les actes de la procédure et pour l’exécution du\njugement.\nElle est acquise à l’Etat, du moment que l’inculpé, sans motif légitime\nd’excuse, a fait défaut à quelque acte de la procédure ou pour l’exécution\ndu jugement.\nNéanmoins, le juge d’instruction en cas de non-lieu, la juridiction de jugement\nen cas d’absolution ou d’acquittement, peuvent ordonner la restitution de\ncette partie du cautionnement.","[CPPN] Art. 141 : La seconde partie du cautionnement est toujours restituée en\ncas de non-lieu, d’absolution ou d’acquittement.\nEn cas de condamnation, elle est affectée aux frais, à l’amende et aux\nrestitutions et dommages accordés à la partie civile, dans l’ordre énoncé\ndans l’article 138. Le surplus est restitué.","[CPPN] Art. 142 : Le ministère public, d’office ou à la demande de la partie civile,\nest chargé de produire à l’administration de l’enregistrement, soit un\ncertificat du greffe constatant la responsabilité encourue par l’inculpé dans\nle cas de l’article 140, alinéa 2, soit l’extrait de jugement dans le cas prévu\npar l’article 141 alinéa 2.\nSi les sommes dues ne sont pas déposées, l’administration de\nl’enregistrement en poursuit le recouvrement par voie de contrainte.\nL’administration de l’enregistrement est chargée de faire sans délai aux\nayants droits la distribution des sommes déposées ou recouvrées.\nToute contestation sur ces divers points est jugée sur requête, en Chambre\ndu conseil, comme incident de l’exécution du jugement.\n\nCode de procédure pénale","[CPPN] Art. 143 : L’inculpé renvoyé devant la Cour d’assises sera mis en état\nd’arrestation en vertu de l’ordonnance de prise de corps contenue dans\nl’arrêt de la Chambre d’accusation, nonobstant la mise en liberté provisoire.\nSection VII (Bis) : De l’indemnisation à raison d’une détention\nprovisoire\nArt. 143-1 : (Loi n° 2003-26 du 13 juin 2003). Une indemnité doit être\naccordée à la personne ayant fait l’objet d’une détention provisoire au\ncours d’une procédure terminée à son égard par une décision de non-lieu,\nde relaxe ou d’acquittement devenue définitive.\nArt. 143-2 : (Loi n° 2003-26 du 13 juin 2003). L’indemnité prévue à\nl’article précédent est allouée par une décision d’une commission qui statue\nsouverainement.\nLa commission est composée de trois magistrats du siège de la Cour\nsuprême. Ces magistrats sont désignés annuellement, en même temps que\ntrois suppléants, par le bureau de la Cour suprême.\nLes fonctions du ministère public sont remplies par le parquet général près\nde la Cour suprême.\nArt. 143-3 : (Loi n° 2003-26 du 13 juin 2003). La commission, saisie\npar voie de requête dans le délai de douze (12) mois de la décision de nonlieu, de relaxe ou d’acquittement devenue définitive, statue par une décision\nmotivée qui n’est susceptible d’aucun recours.\nLes débats ont lieu contradictoirement et la décision est rendue en Chambre\nde conseil.\nLe débat est oral et le requérant qui peut se faire assister d’un avocat peut\nêtre entendu personnellement sur sa demande.\nLa procédure dev","[CPPN] Art. 144 : Le juge d’instruction peut requérir par commission rogatoire\ntout autre juge d’instruction ou tout officier de police judiciaire du ressort\nde son tribunal de procéder aux actes d’information qu’il estime nécessaires\ndans les lieux soumis à la juridiction de chacun d’eux.\nLa commission rogatoire indique la nature de l’infraction, objet des poursuites.\nElle est datée et signée par le magistrat qui la délivre et revêtue de son\nsceau.\nElle ne peut prescrire que des actes d’instruction se rattachant directement\nà la répression de l’infraction visée aux poursuites.","[CPPN] Art. 145 : (Loi n° 2003-26 du 13 juin 2003). Les magistrats ou officiers\nde police judiciaire commis pour l’exécution exercent, dans les limites de la\ncommission rogatoire, tous les pouvoirs du juge d’instruction.\nToutefois, les officiers de police judiciaire ne peuvent procéder aux\ninterrogatoires et confrontations des inculpés.\nLe juge d’instruction commis rogatoirement peut décerner tous mandats\ntels que définis à l’article 116.\nDans l’exécution des commissions rogatoires par les officiers de police\njudiciaire, aucune nullité n’est encourue de plein droit du fait de\nl’inobservation des règles prescrites par les articles 161 et 163. Toutefois,\nau cas où l’inobservation de quelque règle de procédure a été de nature à\nnuire aux droits des intéressés, le juge mandant, soit d’office, soit à la\nrequête du procureur de la République, peut refaire les actes irréguliers.","[CPPN] Art. 146 : Tout témoin cité pour être entendu au cours de l’exécution\nd’une commission rogatoire est tenu de comparaître, de prêter serment et\nde déposer.\nS’il ne satisfait pas à cette obligation, avis est donné au magistrat mandant\nqui peut le contraindre à comparaître par la force publique et prendre\ncontre lui les sanctions prévues à l’article 104 alinéas 2 et 3.","[CPPN] Art. 147 : Lorsque, pour les nécessités de l’exécution de la commission\nrogatoire, l’officier de police judiciaire est amené à retenir une personne à\n\nsa disposition, celle-ci doit être obligatoirement conduite dans les quarantehuit heures devant le juge d’instruction dans le ressort duquel se poursuit\nl’exécution. Après audition de la personne qui lui est amenée, le juge\nd’instruction peut accorder l’autorisation écrite de prolonger la garde à vue\nd’un nouveau délai de quarante-huit heures.\nA titre exceptionnel, cette autorisation peut être accordée, par décision\nmotivée, sans que la personne soit conduite devant le juge d’instruction.\nLe juge d’instruction fixe le délai dans lequel les procès-verbaux dressés\npar l’officier de police judiciaire doivent lui être transmis par celui-ci. A\ndéfaut d’une telle fixation, ces procès-verbaux doivent lui être transmis\ndans les huit jours de la fin des opérations exécutées en vertu de la\ncommission rogatoire.","[CPPN] Art. 148 : Lorsque la commission rogatoire prescrit des opérations\nsimultanées sur divers points du territoire, elle peut, sur l’ordre du juge\nd’instruction mandant, être adressée aux juges d’instruction chargés de\nson exécution sous forme de reproduction ou de copie intégrale de l’original.\nEn cas d’urgence, la commission rogatoire peut être diffusée par tous\nmoyens : la diffusion, doit toutefois préciser les mentions essentielles de\nl’orignal et spécialement la nature de l’inculpation, le nom et la qualité du\nmagistrat mandant.\nSection IX : De l’expertise","[CPPN] Art. 149 : Toute juridiction d’instruction ou de jugement, dans le cas où se\npose une question d’ordre technique, peut, soit à la demande du ministère\npublic, soit d’office ou à la demande des parties, ordonner une expertise.\nLorsque le juge d’instruction estime ne pas devoir faire droit à une demande\nd’expertise, il doit rendre une ordonnance motivée.\nLe ou les experts désignés procèdent à leur mission sous le contrôle du\njuge d’instruction ou du magistrat que doit désigner la juridiction ordonnant\nl’expertise.","[CPPN] Art. 150 : Les experts sont choisis sur une liste dressée par chaque\ntribunal au début de l’année judiciaire.\n\nDans tous les cas, les juridictions peuvent, par décision motivée, choisir un\nexpert ne figurant sur aucune liste.","[CPPN] Art. 151 : La mission des experts, qui ne peut avoir pour objet que l’examen\nde questions d’ordre technique, est précisée dans la décision qui ordonne\nl’expertise.","[CPPN] Art. 152 : Lors de leur inscription sur l’une des listes prévues à l’article\n150, les experts prêtent, devant le tribunal qui les a inscrits, serment\nd’accomplir leur mission, de faire leur rapport et de donner leur avis en leur\nhonneur et conscience. Ces experts n’ont pas à renouveler leur serment\nchaque fois qu’ils sont commis.\nLes experts ne figurant sur aucune de ces listes prêtent chaque fois qu’ils\nsont commis le serment prévu à l’alinéa précédent devant le juge d’instruction\nou le magistrat désigné par la juridiction. Le procès-verbal de prestation de\nserment est signé par le magistrat compétent, l’expert et le greffier.\nLe serment peut également être reçu par écrit. La lettre de serment est\nalors annexée au dossier de la procédure.","[CPPN] Art. 153 : Toute décision commettant un ou plusieurs experts doit leur\nimpartir un délai pour remplir leur mission.\nSi des raisons particulières l’exigent, ce délai peut être prorogé sur requête\ndes experts et par décision motivée rendue par le magistrat ou la juridiction\nqui les a désignés. Les experts qui ne déposent pas leur rapport dans le\ndélai qui leur a été imparti peuvent être immédiatement remplacés et doivent\nrendre compte des investigations auxquelles ils ont déjà procédé. Ils doivent\naussi restituer dans les quarante-huit heures les objets, pièces et documents\nqui leur auraient été confiés en vue de l’accomplissement de leur mission.\nIls peuvent être, en outre, l’objet de mesures disciplinaires allant jusqu’à la\nradiation de l’une ou l’autre des listes prévues à l’article 150 et ils encourent\nune peine d’amende de 5.000 à 10.000 francs.\nLes experts doivent remplir leur mission en liaison avec le juge d’instruction\nou le magistrat délégué; ils doivent le tenir au courant du développement de\nleurs opérations et le mettre à même de prendre à tout moment toutes\nmesures utiles.\n\nLe juge d’instruction, au cours de ses opérations, peut toujours, s’il l’estime\nutile, se faire assister des experts.","[CPPN] Art. 154 : Si les experts demandent à être éclairés sur une question\néchappant à leur spécialité, le juge peut les autoriser à s’adjoindre des\npersonnes nommément désignées, spécialement qualifiées par leur\ncompétence.\nLes personnes ainsi désignées prêtent serment dans les conditions prévues\nau deuxième alinéa de l’article 152.\nLeur rapport sera annexé intégralement au rapport mentionné à l’article 157.","[CPPN] Art. 155 : Conformément à l’article 92 alinéa 3, le juge d’instruction ou le\nmagistrat désigné par la juridiction représente à l’inculpé, avant de les faire\nparvenir aux experts, les scellés qui n’auraient pas été ouverts et inventoriés.\nIl énumère ces scellés dans le procès-verbal spécialement dressé à l’effet\nde constater cette remise. Les experts doivent faire mention dans leur rapport\nde toute ouverture ou réouverture des scellés dont ils dressent inventaire.","[CPPN] Art. 156 : Les experts peuvent recevoir, à titre de renseignement et pour\nl’accomplissement strict de leur mission, les déclarations de personnes autres\nque l’inculpé.\nS’ils estiment qu’il y a lieu d’interroger l’inculpé, et sauf délégation motivée\ndélivrée à titre exceptionnel par le magistrat, il est procédé à cet\ninterrogatoire, en leur présence, par le juge d’instruction ou le magistrat\ndésigné par la juridiction en observant dans tous les cas les formes et\nconditions prévues par les articles 112 et 113.\nToutefois, les médecins experts chargés d’examiner l’inculpé peuvent lui\nposer les questions nécessaires à l’accomplissement de leur mission hors\nla présence du juge et des conseils.","[CPPN] Art. 157 : Lorsque les opérations d’expertise sont terminées, les experts\nrédigent un rapport qui doit contenir la description desdites opérations, ainsi\nque leurs conclusions. Les experts doivent attester avoir personnellement\naccompli les opérations qui leur ont été confiées et signent leur rapport.\nEn cas de nomination de plusieurs experts, si ceux-ci sont d’avis différents,\nou s’ils ont des réserves à formuler sur des conclusions communes, chacun\nd’eux indique son opinion ou ses réserves en les motivant.\n\nLe rapport et les scellés ou leurs résidus sont déposés entre les mains du\ngreffier de la juridiction qui a ordonné l’expertise; ce dépôt est constaté\npar procès-verbal.","[CPPN] Art. 158 : Le juge d’instruction doit convoquer les parties et leur donner\nconnaissance des conclusions des experts dans les formes et délais prévus\naux articles 112 et 113.","[CPPN] Art. 159 : Les experts exposent à l’audience, s’il y a lieu, le résultat des\nopérations techniques auxquelles ils ont procédé, après avoir prêté serment\nde rendre compte de leurs recherches et constatations en leur honneur et\nconscience. Au cours de leur audition, ils peuvent consulter leur rapport et\nses annexes.\nLe président peut soit d’office, soit à la demande du ministère public, des\nparties ou de leurs conseils, leur poser toutes questions rentrant dans le\ncadre de la mission qui leur a été confiée.\nAprès leur exposé, les experts assistent aux débats, à moins que le président\nne les autorise à se retirer.","[CPPN] Art. 160 : Si, à l’audience d’une juridiction de jugement, une personne\nentendue comme témoin ou à titre de renseignement contredit les conclusions\nd’une expertise ou apporte au point de vue technique des indications\nnouvelles, le président demande aux experts, au ministère public, à la\ndéfense, et s’il y a lieu, à la partie civile, de présenter leurs observations.\nCette juridiction, par décision motivée, déclare soit qu’il sera passé outre\naux débats, soit que l’affaire sera renvoyée à une date ultérieure. Dans ce\ndernier cas, cette juridiction peut prescrire quant à l’expertise toute mesure\nqu’elle jugera utile.\nSection X : Des nullités de l’information","[CPPN] Art. 161 : Les dispositions prescrites aux articles 108 et 112 doivent être\nobservées à peine de nullité tant de l’acte lui-même que de la procédure\nultérieure.\nLa partie envers laquelle les dispositions de ces articles ont été méconnues\npeut renoncer à s’en prévaloir et régulariser ainsi la procédure. Cette\nrenonciation doit être expresse. Elle ne peut être donnée qu’en présence\ndu conseil, s’il y en a un, ou ce dernier dûment appelé.\n\nCode de procédure pénale","[CPPN] Art. 162 : S’il apparaît au juge d’instruction qu’un acte de l’information\nest frappé de nullité, il saisit la Chambre d’accusation en vue de l’annulation\nde cet acte, après avoir pris l’avis du procureur de la République et en\navoir avisé l’inculpé et la partie civile.\nSi c’est le procureur de la République qui estime qu’une nullité a été\ncommise, il requiert du juge d’instruction communication de la procédure\nen vue de sa transmission à la Chambre d’accusation et présente requête\naux fins d’annulation à cette chambre.Dans l’un ou l’autre cas, la Chambre\nd’accusation procède comme il est dit à l’article 199.","[CPPN] Art. 163 : Il y a également nullité en cas de violation des dispositions\nsubstantielles du présent titre, autres que celles visées à l’article 161, et\nnotamment en cas de violation des droits de la défense.\nLa Chambre d’accusation décide si l’annulation doit être limitée à l’acte\nvicié ou s’étendre à tout ou partie de la procédure ultérieure.\nLes parties peuvent renoncer à se prévaloir de ces nullités lorsqu’elles ne\nsont édictées que dans leur seul intérêt. Cette renonciation doit être\nexpresse.\nLa Chambre d’accusation est saisie et statue ainsi qu’il est dit à l’article\nprécédent.","[CPPN] Art. 164 : Les actes annulés sont retirés du dossier d’information et classés\nau greffe de la Cour d’appel. Il est interdit d’y puiser aucun renseignement\ncontre les parties au débat à peine de sanction disciplinaire pour les\nmagistrats et de poursuites devant leur Chambre de discipline pour les\ndéfenseurs.","[CPPN] Art. 165 : Les juridictions correctionnelles ou de simple police ont qualité\npour constater les nullités visées à l’article 161 ainsi que celles qui pourraient\nrésulter de l’inobservation des prescriptions de l’alinéa 1er de l’article 174.\nDans le cas de l’article 161, ou si, dans le cas de l’alinéa 1er de l’article\n174, l’ordonnance qui les a saisies est affectée par cette nullité, elles\nrenvoient la procédure au ministère public, pour lui permettre de saisir à\nnouveau le juge d’instruction, sous réserve, s’il s’agit de la Cour d’appel,\ndes dispositions de l’article 509.\n\nToutefois, les juridictions correctionnelles ou de simple police ne peuvent\nprononcer l’annulation des procédures d’instruction lorsque celles-ci ont\nété renvoyées devant elles par la Chambre d’accusation.\nLes parties, d’autre part, peuvent renoncer à se prévaloir des nullités visées au\nprésent article, lesquelles doivent, dans tous les cas, être présentées à la juridiction\nde jugement avant toute défense au fond, ainsi qu’en dispose l’article 366.\nSection XI : Des ordonnances de règlement","[CPPN] Art. 166 : (Loi n° 2003-26 du 13 juin 2003). Aussitôt que l’information\nlui parait terminée, le juge d’instruction communique le dossier au procureur\nde la République. Les avocats de l’inculpé et de la partie civile en sont\navisés immédiatement par lettre avec accusé de réception.\nLe procureur de la République doit lui adresser ses réquisitions dans un\ndélai de trois jours si l’inculpé est détenu et de quinze jours dans les autres\ncas. Il est tenu à l’expiration de ces délais de restituer le dossier au juge\nd’instruction.\nLe juge d’instruction qui ne reçoit pas de réquisitions dans le délai prescrit\nrend l’ordonnance de règlement.","[CPPN] Art. 167 : Le juge d’instruction examine s’il existe contre l’inculpé des\ncharges constitutives d’infraction à la loi pénale.","[CPPN] Art. 168 : Si le juge d’instruction estime que les faits ne constituent ni\ncrime, ni délit, ni contravention, ou si l’auteur est resté inconnu, ou s’il\nn’existe pas de charges suffisantes contre l’inculpé, il déclare, par\nordonnance, qu’il n’y a lieu à suivre.\nLes inculpés préventivement détenus sont mis en liberté.\nLe juge d’instruction statue en même temps sur la restitution des objets saisis.\nIl liquide les dépens et condamne aux frais la partie civile, s’il en existe en\nla cause. Toutefois, la partie civile de bonne foi peut être déchargée de la\ntotalité ou d’une partie des frais par décision spéciale et motivée.","[CPPN] Art. 169 : Si le juge estime que les faits constituent une contravention, il\nprononce le renvoi de l’affaire devant le tribunal de simple police et le\nprévenu est mis en liberté.\n\nCode de procédure pénale","[CPPN] Art. 170 : Si le juge estime que les faits constituent un délit, il prononce\nle renvoi de l’affaire devant le tribunal correctionnel.\nSi l’emprisonnement est encouru, et sous réserve des dispositions de l’article\n132, le prévenu arrêté demeure en état de détention.","[CPPN] Art. 171 : Dans le cas de renvoi, soit devant le tribunal de simple police,\nsoit devant le tribunal correctionnel, le juge d’instruction transmet le dossier\navec son ordonnance au procureur de la République. Celui-ci est tenu de\nl’envoyer sans retard au greffe du tribunal qui doit statuer.\nSi la juridiction correctionnelle est saisie, le procureur de la République doit\nfaire donner assignation au prévenu pour l’une des plus prochaines\naudiences, en observant les délais de citation prévus au présent code.","[CPPN] Art. 172 : Si le juge d’instruction estime que les faits constituent une\ninfraction qualifiée crime par la loi, il ordonne que le dossier de la procédure\net un état des pièces servant à conviction soient transmis sans délai par le\nprocureur de la République au procureur général près la Cour d’appel,\npour être procédé ainsi qu’il est dit au chapitre de la Chambre d’accusation.\nLe mandat d’arrêt ou de dépôt décerné contre l’inculpé conserve sa force\nexécutoire jusqu’à ce qu’il ait été statué par la Chambre d’accusation.\nLes pièces à conviction restent au greffe du tribunal sauf dispositions\ncontraires.","[CPPN] Art. 173 : Des ordonnances comportant non-lieu partiel peuvent intervenir\nen cours d’information.","[CPPN] Art. 174 : Il est donné avis dans les quarante-huit heures, soit par lettre\nrecommandée, soit par notification administrative, aux conseils de l’inculpé\net de la partie civile, de toutes ordonnances juridictionnelles.\n(Loi n° 69-5 du 18 février 1969). Dans les mêmes formes et délais, les\nordonnances de règlement sont portées à la connaissance de l’inculpé.\n(Loi n° 69-5 du 18 février 1969). Les ordonnances dont l’inculpé ou la\npartie civile peuvent, aux termes de l’article 178, interjeter appel, leur sont\nnotifiées, à la diligence du juge d’instruction, dans les quinze jours de leur\nsignature.\n\n(Loi n° 2004-21 du 16 mai 2004). A la diligence du juge d’instruction du\ntribunal de grande instance, il est donné avis dans les quarante-huit heures\nau procureur de la République de toutes ordonnances juridictionnelles.\n(Loi n° 2003-26 du 13 juin 2003). Avis de toute ordonnance non conforme\nà ses réquisitions est donné au procureur de la République à la diligence du\njuge d’instruction le jour même où elle est rendue sous peine de sanction\ndisciplinaire.\n(Loi n° 70-9 du 17 mars 1970). Copie de toute ordonnance de non-lieu\nmême partiel, est adressée dans les quarante-huit heures au procureur de\nla République à la diligence du juge d’instruction sous peine de sanction\ndisciplinaire.\nNotification de cette ordonnance doit être faite au procureur de la République\npar le greffier dans les quarante-huit (48) heures à partir du jour où elle a été\nrendue sous peine d’une amende civile de dix mil","[CPPN] Art. 175 : Les ordonnances rendues par le juge d’instruction en vertu de\nla présente section contiennent les nom, prénoms, date, lieu de naissance,\ndomicile et profession de l’inculpé. Elles indiquent la qualification légale du\nfait imputé à celui-ci et, de façon précise, les motifs pour lesquels il existe\nou non contre lui des charges suffisantes.","[CPPN] Art. 176 : (Loi n° 2003-26 du 13 juin 2003 et Loi n° 2004-50 du 22\njuillet 2004). Sauf en matière criminelle, les juges d’instance, agissant en\nqualité de juge d’instruction, sont dispensés de la communication au ministère\npublic du dossier de l’information, avant l’ordonnance de règlement, à moins\nqu’ils n’aient été saisis par un réquisitoire du procureur de la République ou\nque cette communication ne leur ait été requise.\nSection XII : De l’appel des ordonnances du juge d’instruction","[CPPN] Art. 177 : (Loi n° 2003-26 du 13 juin 2003). Le procureur de la\nRépublique a le droit d’interjeter appel devant la Chambre d’accusation de\ntoute ordonnance du juge d’instruction.\nCet appel, formé par déclaration au greffe du tribunal de grande instance,\ndoit être interjeté dans les trois (3) jours francs à compter du jour de la\nnotification de l’ordonnance si cette dernière a été rendue par le juge\nd’instruction du tribunal de grande instance. Si elle a été rendue par un juge\n\nd’instance, ès qualités de juge d’instruction, le délai sera le même mais il\naura pour point de départ le jour de la réception de l’ordonnance au parquet\ndu procureur de la République sans pouvoir excéder deux mois à compter\nde la date de la signature de l’ordonnance.\nLa déclaration d’appel est inscrite au greffe du tribunal et une expédition\nen est transmise sans délai au greffe du tribunal de grande instance ou du\ntribunal d’instance.\nLe droit d’appel appartient également dans tous les cas au procureur\ngénéral. Cet appel, formé par déclaration au greffe de la Cour d’appel, doit\nêtre interjeté dans les trois (3) jours francs à compter du jour de la réception\nde l’ordonnance au parquet du procureur Général, sans que ce délai puisse\ntoutefois excéder deux (2) mois à compter de la date de la signature de\nl’ordonnance. La déclaration d’appel est inscrite au greffe de la Cour d’appel\net une expédition en est transmise sans délai au greffe du tribunal de grande\ninstance ou du tribunal d’instance, suivant que","[CPPN] Art. 178 : Le droit d’appel appartient à l’inculpé contre les ordonnances\nprévues par les articles 82 et 134.\nLa partie civile peut interjeter appel des ordonnances de non informer, de\nnon-lieu et des ordonnances faisant grief à ses intérêts civils. Toutefois,\nson appel ne peut, en aucun cas, porter sur une ordonnance ou sur la\ndisposition d’une ordonnance relative à la détention de l’inculpé.\nL’inculpé et la partie civile peuvent aussi interjeter appel de l’ordonnance\npar laquelle le juge a, d’office ou sur déclinatoire, statué sur sa compétence,\nainsi que des ordonnances prévues à l’article 149 alinéa 2.\n(Loi n° 2003-26 du 13 juin 2003). L’appel de l’inculpé et de la partie\ncivile doit être formé par déclaration au greffe du tribunal, dans les cinq (5)\njours francs de la notification qui leur est faite conformément à l’article\n174 ci-dessus. Copie de l’acte d’appel doit être aussitôt remise à l’appelant.\nSi l’inculpé est détenu, sa déclaration d’appel est transmise par\nl’intermédiaire du régisseur de la prison dans les conditions prévues à l’article\n493. Récépissé de la déclaration d’appel doit être transmis à l’appelant\ndétenu après la transcription de la déclaration d’appel sur le registre.\n\nLe dossier de l’information est transmis avec l’avis motivé du procureur de\nla République au procureur général qui procède ainsi qu’il est dit aux articles\n186 et suivants.\nEn cas d’appel du ministère public, l’inculpé détenu est maintenu en prison\njusqu’à ce qu’il ait été statué sur ","[CPPN] Art. 179 : Lorsqu’il est interjeté appel d’une ordonnance autre qu’une\nordonnance de règlement, le juge d’instruction peut poursuivre son\ninformation sauf décision contraire de la Chambre d’accusation.\nSection XIII : De la reprise de l’information sur charges nouvelles","[CPPN] Art. 180 : L’inculpé à l’égard duquel le juge d’instruction a dit n’y avoir\nlieu à suivre ne peut plus être recherché à l’occasion du même fait, à moins\nqu’il ne survienne de nouvelles charges.","[CPPN] Art. 181 : Sont considérées comme charges nouvelles les déclarations\ndes témoins, pièces et procès-verbaux qui, n’ayant pu être soumis à\nl’examen du juge d’instruction, sont cependant de nature soit à fortifier les\ncharges qui auraient été trouvées trop faibles, soit à donner aux faits de\nnouveaux développements utiles à la manifestation de la vérité.","[CPPN] Art. 182 : Il appartient au ministère public seul de décider s’il y a lieu de\nrequérir la réouverture de l’information sur charges nouvelles.\nCHAPITRE II : DE LA CHAMBRE D’ACCUSATION,\nJURICTION D’INSTRUCTION DU SECOND DEGRE\nSection 1 : Dispositions générales","[CPPN] Art. 183 : La Cour d’appel comprend une Chambre d’accusation. Cette\nChambre est composée d’un président et de deux conseillers. Le président\net les conseillers composant la Chambre d’accusation sont désignés par\nordonnance du président de la Cour d’appel.\nSi pour une cause quelconque le nombre de trois magistrats ne peut être\nréuni, le président de la Cour d’appel, par ordonnance motivée, rendue sur\n\nréquisition du procureur général, pourra décider que la Chambre d’accusation\nsera composée d’un seul magistrat qu’il désignera.","[CPPN] Art. 184 : Les fonctions du ministère public auprès de la Chambre\nd’accusation sont exercées par le procureur général ou par ses substituts,\ncelles du greffe par un greffier de la Cour d’appel.","[CPPN] Art. 185 : La Chambre d’accusation se réunit au moins une fois par\nquinzaine et, sur convocation de son président ou à la demande du procureur\ngénéral, toutes les fois qu’il est nécessaire.","[CPPN] Art. 186 : (Alinéa 1. Loi n° 63-16 du 21 février 1963). Le procureur\ngénéral met l’affaire en état dans les cinq (5) jours francs de la réception\ndes pièces en matière de détention provisoire et dans les trente (30) jours\nen toute autre matière. Il la soumet avec son réquisitoire à la Chambre\nd’accusation.\n(Loi n° 2007-04 du 22 février 2007). Celle-ci doit, en matière de détention\nprovisoire, se prononcer dans les plus brefs délais et au plus tard dans les\ntrente (30) jours suivant la première audience à laquelle l’affaire est appelée,\nfaute de quoi l’inculpé est mis d’office en liberté provisoire, sauf si des\nvérifications concernant sa demande ont été ordonnées ou si des\ncirconstances imprévisibles et insurmontables mettent obstacle au jugement\nde l’affaire dans le délai prévu au présent article.\nSous peine de sanctions disciplinaires à l’endroit des différents intervenants,\nle dossier d’appel doit parvenir au parquet général de la Cour d’appel dans\nle délai maximum de quinze (15) jours, à compter de la déclaration d’appel\nlorsque la juridiction concernée et la Cour d’appel sont dans la même ville,\ndans un délai d’un (1) mois dans les autres cas.\nCette mise en liberté provisoire ne peut être révoquée que dans les conditions\nprévues par le dernier alinéa de l’article 137.","[CPPN] Art. 187 : Dans les causes dont sont saisies les juridictions correctionnelles\nou de simple police et jusqu’à l’ouverture des débats, le procureur général,\ns’il estime que les faits sont susceptibles d’une qualification plus grave que\ncelle dont ils ont été l’objet, ordonne l’apport des pièces, met l’affaire en\nétat et la soumet avec son réquisitoire à la Chambre d’accusation.\n\nCode de procédure pénale","[CPPN] Art. 188 : Le procureur général agit de même lorsqu’il reçoit,\npostérieurement à un arrêt de non-lieu prononcé par la Chambre\nd’accusation, des pièces lui paraissant contenir des charges nouvelles dans\nles termes de l’article 181. Dans ce cas et en attendant la réunion de la\nChambre d’accusation, le président de cette juridiction peut, sur les\nréquisitions du procureur général, décerner mandat de dépôt ou d’arrêt.","[CPPN] Art. 189 : Le procureur général notifie, par lettre recommandée avec\naccusé de réception ou par voie administrative, à chacune des parties et à\nson conseil, la date à laquelle l’affaire sera appelée à l’audience. La lettre\nrecommandée destinée à une partie est envoyée à son domicile élu ou, à\ndéfaut, à la dernière adresse qu’elle a donnée.\nUn délai minimum de dix jours en matière de détention préventive et de\nvingt jours en toute autre matière doit être observé entre la date de la\nnotification et celle de l’audience.\nPendant ce délai, le dossier, comprenant les réquisitions du procureur\ngénéral, est déposé au greffe de la Chambre d’accusation et tenu à la\ndisposition des conseils des inculpés et des parties civiles reçues au procès.","[CPPN] Art. 190 : Les parties et leurs conseils sont admis jusqu’au jour de\nl’audience à produire des mémoires qu’ils communiqueront au ministère\npublic et aux autres parties.\nCes mémoires sont déposés au greffe de la Chambre d’accusation et visés\npar le greffier avec l’indication du jour et de l’heure du dépôt.","[CPPN] Art. 191 : Les débats se déroulent et l’arrêt est rendu en Chambre du\nconseil.\nAprès le rapport d’un des membres de la chambre, le procureur général\nprésente des observations sommaires.\nLa Chambre d’accusation peut ordonner la comparution personnelle des\nparties ainsi que l’apport des pièces à conviction.","[CPPN] Art. 192 : Lorsque les débats sont terminés, la Chambre d’accusation\ndélibère sans qu’en aucun cas le procureur général, les parties, leurs conseils\net le greffier puissent être présents.\n\nCode de procédure pénale","[CPPN] Art. 193 : La Chambre d’accusation peut, dans tous les cas, à la demande\ndu procureur général, d’une des parties ou même d’office, ordonner tout\nacte d’information complémentaire qu’elle juge utile et notamment décerner\ntous mandats.\nElle peut également, dans tous les cas, le ministère public entendu, prononcer\nd’office la mise en liberté de l’inculpé.","[CPPN] Art. 194 : Elle peut, d’office ou sur les réquisitions du procureur général,\nordonner qu’il soit informé à l’égard des inculpés ou prévenus renvoyés\ndevant elle sur tous les chefs de crimes, de délits, de contraventions,\nprincipaux ou connexes, résultant du dossier de la procédure, qui n’auraient\npas été visés par l’ordonnance du juge d’instruction ou qui auraient été\ndistraits par une ordonnance comportant non-lieu partiel, disjonction ou renvoi\ndevant la juridiction correctionnelle ou de simple police.Elle peut statuer\nsans ordonner une nouvelle information si les chefs de poursuite visés à\nl’alinéa précédent ont été compris dans les inculpations faites par le juge\nd’instruction.","[CPPN] Art. 195 : Les infractions sont connexes soit lorsqu’elles ont été commises\nen même temps par plusieurs personnes réunies, soit lorsqu’elles ont été\ncommises par différentes personnes, même en différents temps et en divers\nlieux, mais par suite d’un concert formé à l’avance entre elles, soit lorsque\nles coupables ont commis les unes pour se procurer les moyens de commettre\nles autres, pour en faciliter, pour en consommer l’exécution, ou pour en\nassurer l’impunité, soit lorsque des choses enlevées, détournées ou obtenues\nà l’aide d’un crime ou d’un délit ont été en tout ou partie recelées.","[CPPN] Art. 196 : Les infractions sont indivisibles lorsqu’elles ont été commises\ndans le même trait de temps et dans le même lieu, si elles ont été inspirées\npar le même mobile ou s’il existe entre elles une relation de cause à effet.","[CPPN] Art. 197 : La Chambre d’accusation peut également, quant aux infractions\nrésultant du dossier de la procédure, ordonner que soient inculpées, dans\nles conditions prévues à l’article 198, des personnes qui n’ont pas été\nrenvoyées devant elle, à moins qu’elles n’aient fait l’objet d’une ordonnance\nde non-lieu devenue définitive.\nCette décision ne pourra faire l’objet d’un pourvoi en cassation.\n\nCode de procédure pénale","[CPPN] Art. 198 : Il est procédé aux suppléments d’information conformément\naux dispositions relatives à l’instruction préalable soit par un des membres\nde la Chambre d’accusation soit par un juge qu’elle délègue à cette fin.\nLe procureur général peut à tout moment requérir la communication de la\nprocédure, à charge de rendre les pièces dans les trois jours.","[CPPN] Art. 199 : La Chambre d’accusation examine la régularité des procédures\nqui lui sont soumises.\nSi elle découvre une cause de nullité, elle prononce la nullité de l’acte qui\nen est entaché et, s’il y échet, celle de tout ou partie de la procédure\nultérieure.\nAprès annulation, elle peut soit évoquer et procéder dans les conditions\nprévues aux articles 193, 194 et 197, soit renvoyer le dossier de la procédure\nau même juge d’instruction ou à tel autre, afin de poursuivre l’information.","[CPPN] Art. 200 : Lorsque la Chambre d’accusation a statué sur l’appel relevé\ncontre une ordonnance du juge d’instruction en matière de détention\npréventive, soit qu’elle ait confirmé l’ordonnance, soit que l’infirmant, elle\nait ordonné une mise en liberté ou maintenu en détention ou décerné un\nmandat de dépôt ou d’arrêt, le procureur général fait sans délai retour du\ndossier au juge d’instruction après avoir assuré l’exécution de l’arrêt.\nLorsque, en toute autre matière, la Chambre d’accusation infirme une\nordonnance du juge d’instruction, elle peut soit évoquer et procéder dans\nles conditions prévues aux articles 193, 194, 197 et 198, soit renvoyer le\ndossier au juge d’instruction ou à tel autre afin de poursuivre l’information.\nL’ordonnance du juge d’instruction frappée d’appel sort son plein et entier\neffet si elle est confirmée par la Chambre d’accusation.","[CPPN] Art. 201 : Lorsqu’elle a prescrit une information complémentaire et que\ncelle-ci est terminée, la Chambre d’accusation ordonne le dépôt au greffe\ndu dossier de la procédure.\nLe procureur général avise immédiatement de ce dépôt chacune des parties\net son conseil par lettre recommandée avec accusé de réception ou par\nnotification administrative.\n\nCode de procédure pénale","[CPPN] Art. 202 : Le dossier de la procédure reste déposé au greffe pendant dix jours\nen matière de détention préventive, pendant vingt jours en toute autre matière.\nIl est alors procédé conformément aux articles 190 et 191.","[CPPN] Art. 203 : La Chambre d’accusation statue par un seul et même arrêt sur\ntous les faits entre lesquels il existe un lien de connexité ou d’indivisibilité.","[CPPN] Art. 204 : Elle examine s’il existe contre l’inculpé des charges suffisantes.","[CPPN] Art. 205 : Si la Chambre d’accusation estime que les faits ne constituent\nni crime, ni délit, ni contravention ou si l’auteur est resté inconnu ou s’il\nn’existe pas de charges suffisantes contre l’inculpé, elle déclare qu’il n’y a\nlieu à suivre.\nLes inculpés préventivement détenus sont mis en liberté.\nLa Chambre d’accusation statue, par l’arrêt portant qu’il n’ ya lieu à suivre,\nsur la restitution des objets saisis; elle demeure compétente pour statuer\néventuellement sur cette restitution postérieurement à l’arrêt de non-lieu.","[CPPN] Art. 206 : Si la Chambre d’accusation estime que les faits constituent un\ndélit ou une contravention, elle prononce le renvoi de l’affaire dans le\npremier cas devant le tribunal correctionnel, dans le second cas devant le\ntribunal de simple police.\nEn cas de renvoi devant le tribunal correctionnel, si l’emprisonnement est\nencouru, et sous réserve des dispositions de l’article 132, le prévenu arrêté\ndemeure en état de détention.\nEn cas de renvoi devant le tribunal de simple police, le prévenu est mis en\nliberté.","[CPPN] Art. 207 : Si les faits retenus à la charge des inculpés constituent une\ninfraction qualifiée crime par la loi, la Chambre d’accusation prononce la\nmise en accusation devant la Cour d’assises.\nElle peut saisir également cette juridiction des infractions connexes.","[CPPN] Art. 208 : L’arrêt de mise en accusation contient, à peine de nullité, l’exposé\net la qualification légale des faits, objets de l’accusation.\nIl décerne en outre ordonnance de prise de corps contre l’accusé dont il\nprécise l’identité.\n\nCode de procédure pénale","[CPPN] Art. 209 : Les arrêts de la Chambre d’accusation sont signés par le\nprésident et par le greffier. Il y est fait mention du nom des juges, du dépôt\ndes pièces et mémoires, de la lecture du rapport, des réquisitions du ministère\npublic et, s’il y a lieu, de l’audition des parties ou de leurs conseils.\nLa Chambre d’accusation réserve les dépens si son arrêt n’éteint pas l’action\ndont elle a eu à connaître.\nDans le cas contraire, ainsi qu’en matière de mise en liberté, elle liquide les\ndépens et elle condamne aux frais la partie qui succombe.\nToutefois, la partie civile de bonne foi peut être déchargée de la totalité ou\nd’une partie des frais par décision spéciale et motivée.","[CPPN] Art. 210 : (Loi n° 2003-26 du 13 juin 2003). Hors le cas prévu à\nl’article 188, les dispositifs des arrêts sont, dans les trois jours, par lettre\nrecommandée ou par voie administrative, portés à la connaissance des\nconseils des inculpés et des parties civiles.\nDans les mêmes formes et délais, les dispositifs des arrêts de non-lieu sont\nportés à la connaissance des inculpés, les dispositifs des arrêts de renvoi\ndevant le tribunal correctionnel ou de simple police sont portés à la\nconnaissance des inculpés et des parties civiles.\nLes arrêts contre lesquels les inculpés ou les parties civiles peuvent former\nun pourvoi en cassation leur sont signifiés à la requête du procureur général\ndans les trois jours.","[CPPN] Art. 211 : Les dispositions des articles 161, 163 alinéas 1 et 3, 164 et 165,\nrelatives aux nullités de l’information, sont applicables au présent chapitre.\nLa régularité des arrêts de la Chambre d’accusation et celle de la procédure\nantérieure, lorsque cette Chambre a statué sur le règlement d’une procédure,\nrelève du seul contrôle de la Cour suprême, que le pourvoi soit immédiatement\nrecevable ou qu’il ne puisse être examiné qu’avec l’arrêt sur le fond.\nSection II : Des pouvoirs propres du président de la Chambre\nd’accusation","[CPPN] Art. 212 : Le président de la Chambre d’accusation exerce les pouvoirs\npropres définis aux articles suivants.\n\nCode de procédure pénale","[CPPN] Art. 213 : (Loi n° 2003-26 du 13 juin 2003). Le président de la Chambre\nd’accusation s’assure du bon fonctionnement des cabinets d’instruction du\nressort de la Cour d’appel. Il vérifie notamment les conditions d’application\ndes alinéas 3 et 4 de l’article 74 et s’emploie à ce que les procédures ne\nsubissent aucun retard injustifié.\nA cette fin, il est établi, chaque trimestre, dans chaque cabinet d’instruction,\nun état de toutes les affaires en cours portant mention, pour chacune des\naffaires, de la date du dernier acte d’instruction exécuté;\nLes affaires dans lesquelles sont impliqués des inculpés détenus\nprovisoirement figurent sur un état spécial ;\nLes états prévus dans le présent article sont adressés au président de la\nChambre d’accusation et au procureur général dans les dix premiers jours\ndu trimestre suivant sous peine de sanction disciplinaire à l’encontre du\njuge d’instruction;\nLorsqu’un délai de quatre (4) mois s’est écoulé depuis la date du dernier\nacte d’instruction nécessaire à la manifestation de la vérité, le président de\nla Chambre d’accusation peut d’office ou par requête des parties saisir\ncette juridiction. La Chambre d’accusation lorsqu’elle est saisie peut dans\nl’intérêt d’une bonne administration de la justice, soit évoquer et procéder\ndans les conditions prévues aux articles 193, 194, 197 et 198, soit renvoyer\nle dossier au juge d’instruction ou à tel autre afin de poursuivre l’information.","[CPPN] Art. 214 : Le président, chaque fois qu’il l’estime nécessaire, visite les\nétablissements pénitentiaires du ressort de la Cour d’appel et y vérifie la\nsituation des inculpés en état de détention préventive.","[CPPN] Art. 215 : Il peut saisir la Chambre d’accusation, afin qu’il soit par elle\nstatué sur le maintien en détention d’un inculpé en état de détention\npréventive.\nSection III : Du contrôle de l’activité des officiers de la police\njudiciaire","[CPPN] Art. 216 : La Chambre d’accusation exerce un contrôle sur l’activité des\nfonctionnaires civils et militaires, officiers de police judiciaire, pris en cette\nqualité, à l’exclusion des magistrats désignés à l’article 16, des maires et\nde leurs adjoints.\n\nCode de procédure pénale","[CPPN] Art. 217 : Elle est saisie soit par le procureur général soit par son président.\nElle peut se saisir d’office à l’occasion de l’examen de la procédure qui lui\nest soumise.","[CPPN] Art. 218 : La Chambre d’accusation, une fois saisie, fait procéder à une\nenquête; elle entend le procureur général et l’officier de police judiciaire\nen cause.\nCe dernier doit avoir été préalablement mis à même de prendre connaissance\nde son dossier d’officier de police judiciaire tenu au parquet général de la\ncour.\nIl peut se faire assister par un avocat défenseur.","[CPPN] Art. 219 : La Chambre d’accusation peut, sans préjudice des sanctions\ndisciplinaires qui pourraient être infligées à l’officier de police judiciaire\npar ses supérieurs hiérarchiques, lui adresser des observations ou décider\nqu’il ne pourra, soit temporairement, soit définitivement, exercer ses\nfonctions d’officier de police judiciaire et de délégué du juge d’instruction\nsur tout l’ensemble du territoire.","[CPPN] Art. 220 : Si la Chambre d’accusation estime que l’officier de police\njudiciaire a commis une infraction à la loi pénale, elle ordonne en outre la\ntransmission du dossier au procureur général à toutes fins qu’il appartiendra.","[CPPN] Art. 221 : Les décisions prises par la Chambre d’accusation contre les\nofficiers de police judiciaire sont notifiées, à la diligence du procureur général,\naux autorités dont ils dépendent.","[CPPN] Art. 222 : Les dispositions de la présente section sont applicables aux\ninspecteurs et agents assermentés des eaux et forêts.\n\nLIVRE II\nDES JURIDICTIONS DU JUGEMENT\n\nTITRE PREMIER : DE LA COUR D’ASSISES\nCHAPITRE PREMIER : DE LA COMPETENCE DE LA COUR\nD’ASSISES","[CPPN] Art. 223 : La Cour d’assises a plénitude de juridiction pour juger les individus\nrenvoyés devant elle par l’arrêt de mise en accusation.\n(Loi n° 2004-50 du 22 juillet 2004). Elle ne peut connaître d’aucune\nautre accusation.\nCHAPITRE II : DE LA TENUE DES ASSISES","[CPPN] Art. 224 : (Loi n° 2004-50 du 22 juillet 2004). Il est tenu au siège de\nchaque tribunal de première instance, des assises pour le jugement des\naffaires instruites dans le ressort de ce tribunal.","[CPPN] Art. 225 : Exceptionnellement, un arrêté du garde des sceaux, ministre de\nla justice, peut fixer le siège de la Cour d’assises dans la ville où existe une\nsection de tribunal.","[CPPN] Art. 226 : La tenue des assises a lieu tous les six mois.","[CPPN] Art. 227 : Le président de la Cour d’appel peut, après avis du procureur\ngénéral, ordonner qu’il soit tenu, au cours d’un même semestre, une ou\nplusieurs sessions supplémentaires.","[CPPN] Art. 228 : La date de l’ouverture de chaque session d’assises ordinaire ou\nsupplémentaire est fixée, après avis du procureur général, par ordonnance\ndu président de la Cour d’appel.\nCette ordonnance est portée à la connaissance du tribunal, siège de la\nCour d’assises, par les soins du procureur général.","[CPPN] Art. 229 : Le rôle de chaque session est arrêté par le président de la Cour\nd’assises, par les soins du procureur général.","[CPPN] Art. 230 : Le ministère public avise l’accusé de la date à laquelle celuici doit comparaître.\n\nCHAPITRE III : DE LA COMPOSITION DE LA COUR\nD’ASSISES","[CPPN] Art. 231 : La Cour d’assises comprend : la Cour proprement dite et le jury.","[CPPN] Art. 232 : Les fonctions du ministère public y sont exercées dans les\nconditions définies aux articles 33 et 38.\nToutefois, le procureur général peut déléguer auprès d’une Cour d’assises\nun magistrat du ministère public autre que celui qui exerce ses fonctions\nprès le tribunal siège de la Cour d’assises.","[CPPN] Art. 233 : (Loi n° 2004-50 du 22 juillet 2004). La Cour d’assises est, à\nl’audience, assistée d’un greffier.\nAu siège de la Cour d’appel, les fonctions du greffe sont exercées par le\ngreffier en chef ou un greffier de la Cour d’appel.\nDans les autres localités elles le sont par le greffier en chef ou un greffier\ndu tribunal de grande instance ou de tribunal d’instance.\nSection 1 : De la Cour","[CPPN] Art. 234 : La Cour proprement dite comprend : le président et deux\nconseillers.\nParagraphe premier : DU PRESIDENT","[CPPN] Art. 235 : La Cour d’assises est présidée par le président ou par un conseiller\nde la Cour d’appel.","[CPPN] Art. 236 : Pour la durée de chaque semestre et pour chaque Cour d’assises,\nle président est désigné par l’ordonnance du président de la Cour d’appel\nqui fixe la date d’ouverture des sessions.","[CPPN] Art. 237 : En cas d’empêchement survenu avant l’ouverture de la session,\nle président des assises est remplacé par ordonnance du président de la\nCour d’appel.\nSi l’empêchement survient au cours de la session, le président des assises\nest remplacé par le conseiller de la Cour d’assises du rang le plus élevé.\n\nParagraphe 2 : DES CONSEILLERS DE LA COUR D’ASSISES","[CPPN] Art. 238 : Les conseillers sont au nombre de deux.\nToutefois, il peut leur être adjoint un ou plusieurs conseillers supplémentaires,\nsi la durée ou l’importance de la session rendent cette mesure nécessaire.\nLes conseillers supplémentaires siègent aux audiences. Ils ne prennent\npart aux délibérations qu’en cas d’empêchement d’un conseiller titulaire,\nconstaté par ordonnance motivée du président de la Cour d’assises.","[CPPN] Art. 239 : Les conseillers sont choisis soit parmi les conseillers de la Cour\nd’appel, soit parmi les autres magistrats du siège.\n(Loi n° 2003-26 du 13 juin 2003). Lorsqu’il est tenu des assises ailleurs\nqu’au siège de la Cour d’appel, les conseillers peuvent également être\nchoisis parmi les juges d’instance.","[CPPN] Art. 240 : Les conseillers sont désignés par le président de la Cour\nd’appel pour la durée d’un semestre et pour chaque Cour d’assises, dans\nles mêmes formes que le président.","[CPPN] Art. 241 : En cas d’empêchement survenu avant l’ouverture de la session,\nles conseillers sont remplacés par ordonnance du président de la Cour\nd’appel.\nSi l’empêchement survient au cours de la session, les conseillers sont\nremplacés par ordonnance du président de la Cour d’assises.","[CPPN] Art. 242 : Lorsque la session est ouverte, le président de la Cour d’assises\npeut, s’il y a lieu, désigner un ou plusieurs conseillers supplémentaires.","[CPPN] Art. 243 : Ne peuvent faire partie de la Cour en qualité de président ou de\nconseiller les magistrats qui, dans l’affaire soumise à la Cour d’assises ont,\nsoit fait un acte de poursuite ou d’instruction, soit participé à l’arrêt de\nmise en accusation ou à une décision sur le fond relative à la culpabilité de\nl’accusé.\nSection II : Du jury","[CPPN] Art. 244 : Le jury est composé de citoyens, désignés conformément aux\ndispositions des articles suivants, et appelés jurés.\n\nParagraphe premier : DES CONDITIONS D’APTITUDE AU\nFONCTIONS DE JURE","[CPPN] Art. 245 : Peuvent seuls remplir les fonctions de juré, les citoyens de l’un\nou l’autre sexe, âgés de vingt-cinq ans, sachant lire et écrire en français,\njouissant des droits politiques, civils et de famille, et ne se trouvant dans\naucun des cas d’incapacité ou d’incompatibilité énumérés par les deux\narticles suivants.","[CPPN] Art. 246 : Sont incapables d’être jurés :\n1) les individus condamnés pour crime;\n2) ceux condamnés à une peine d’emprisonnement, quelle qu’en soit la\ndurée, pour vol, escroquerie, abus de confiance, soustraction commise par\nles dépositaires de deniers publics, ou attentats aux mœurs;\n3) ceux condamnés à plus de trois mois d’emprisonnement pour délit\nquelconque, à l’exception :\na) des condamnations pour délit d’imprudence, hors le cas de délit de fuite\nconcomitant;\nb) des condamnations prononcées pour infractions, autres que les infractions\nà la loi sur les sociétés, qui sont qualifiées délits mais dont, cependant, la\nrépression n’est pas subordonnée à la preuve de la mauvaise foi de leurs\nauteurs et qui ne sont passibles que d’une amende;\n4) ceux qui sont en état d’accusation et ceux qui sont sous mandat de\ndépôt ou d’arrêt;\n5) les fonctionnaires et agents de l’Etat et des communes, révoqués de\nleurs fonctions;\n6) les officiers ministériels destitués et les membres des ordres\nprofessionnels frappés d’une interdiction définitive d’exercer par une\ndécision juridictionnelle;\n7) les faillis non réhabilités dont la faillite a été déclarée soit par les tribunaux\nnigériens, soitpar un jugement rendu à l’étranger mais exécutoire au Niger;\n8) les aliénés, interdits ou internés, ainsi que les individus pourvus d’un\nconseil juridique;\n\n9) ceux auxquels les fonctions de juré ont été interdites par décisions de\njustice;\n10) pendant cinq ans seulement, à compter du jugement définitif, ceux","[CPPN] Art. 247 : Les fonctions de juré sont incompatibles avec celles énumérées\nci-après :\n1) membre du Gouvernement, de l’Assemblée nationale, du Conseil\nsupérieur de la magistrature, du Conseil économique et social, du Conseil\nsupérieur de la communication, de la Commission nationale des droits de\nl’Homme et des libertés fondamentales;\n2) Secrétaire général du Gouvernement ou d’un ministère, membre du\ncabinet ministériel, chef de circonscription administrative, magistrat de\nl’ordre judiciaire ou de la Cour suprême, membre de la Cour constitutionnelle\nou de la Haute Cour de justice;\n3) fonctionnaire des services de police et des forces publiques nationales,\nmilitaire des armées en activité de service, fonctionnaire ou préposé du\nservice actif des douanes, des contributions directes ou indirectes et des\neaux et forêts.\nNul ne peut être juré dans une affaire où il a accompli un acte de police\njudiciaire ou d’instruction ou dans laquelle il est témoin, interprète,\ndénonciateur, expert, plaignant ou partie civile.","[CPPN] Art. 248 : Les septuagénaires et les ministres du culte sont dispensés, s’ils\nle requièrent, des fonctions de juré.\nParagraphe 2 : DE LA FORMATION DU JURY","[CPPN] Art. 249 : Il est établi annuellement dans le ressort de chaque Cour d’assises\nune liste du jury criminel.","[CPPN] Art. 250 : (Loi n° 71-7 du 29 janvier 1971 et Loi n° 2003-26 du 13\njuin 2003). Cette liste comprend :\n1) Une liste principale de quarante noms de personnes ayant leur résidence\ndans le ressort du tribunal de grande instance, siège de la Cour d’assises.\n\n2) Une première liste supplémentaire de quinze noms de personnes ayant\nleur résidence dans la localité où siège le tribunal de grande instance;\n3) Pour chaque tribunal de grande instance établi dans le ressort de la Cour\nd’assises, une seconde liste supplémentaire comprenant dix noms de\npersonnes ayant leur résidence dans la localité où siège le tribunal de grande\ninstance.","[CPPN] Art. 251 : (Abrogé par la loi n° 71-7 du 29 janvier 1971).","[CPPN] Art. 252 : (Abrogé par la loi n° 71-7 du 29 janvier 1971).","[CPPN] Art. 253 : Les listes des jurés près les cours d’assises sont définitivement\narrêtées, avant le 1er janvier de chaque année, par le garde des sceaux,\nministre de la justice.\nElles sont publiées au Journal Officiel.","[CPPN] Art. 254 : (Loi n° 71-7 du 29 janvier 1971). Chaque liste des jurés,\narrêtée par le ministre de la justice, comprend par ordre alphabétique:\n- trente noms pris sur la liste principale;\n- dix noms pris sur la première liste supplémentaire;\n- cinq noms pour chaque section de tribunal établie dans le ressort de la\nCour d’assises, pris sur la seconde liste supplémentaire.","[CPPN] Art. 255 : Le procureur de la République notifie à chacun des jurés l’extrait\nde la liste le concernant, dans le mois de l’établissement de cette liste.\nCHAPITRE IV : DE LA PROCEDURE PREPARATOIRES AUX\nSESSIONS D’ASSISES\nSection 1 : Des actes obligatoires","[CPPN] Art. 256 : (Loi n° 63-16 du 21 février 1963). L’arrêt de renvoi est\nsignifié à l’accusé. Il lui en est laissé copie.\n(Loi n° 63-16 du 21 février 1963). Cette signification doit être faite à\npersonne si l’accusé est détenu. Dans le cas contraire, elle est faite dans\nles formes prévues au titre IV du présent livre.\n\nCode de procédure pénale","[CPPN] Art. 257 : (Loi n° 2003-26 du 13 juin 2003). Dès que l’arrêt de renvoi\nest rendu, l’accusé, s’il est détenu, est transféré dans l’établissement\npénitentiaire du lieu où se tiennent les assises.","[CPPN] Art. 258 : Si l’accusé ne peut être saisi ou ne se présente pas, on procède\ncontre lui par défaut.","[CPPN] Art. 259 : (Loi n° 2003-26 du 13 juin 2003). Si l’affaire ne doit pas être\njugée au siège de la Cour d’appel, le dossier de la procédure est renvoyé\npar le procureur général au procureur de la République près le tribunal de\ngrande instance où se tiennent les assises.\nLes pièces à conviction sont transportées au greffe de ce tribunal.","[CPPN] Art. 260 : (Loi n° 2003-26 du 13 juin 2003). Le président de la Cour\nd’assises interroge l’accusé dans le plus bref délai, après l’arrivée de ce\ndernier à l’établissement pénitentiaire et la remise du dossier au procureur\nde la République et des pièces à conviction au greffe.\nSi l’accusé est en liberté, il est procédé comme il est dit à l’article 143.\nLorsque les assises ont lieu ailleurs qu’au siège de la Cour d’appel, cette\nformalité est remplie par le président du tribunal de grande instance.\nIl doit être fait appel à un interprète si l’accusé ne parle ou ne comprend\npas la langue française.","[CPPN] Art. 261 : (Loi n° 66-18 du 29 mars 1966). Le président interroge\nl’accusé sur son identité et s’assure que celui-ci a reçu signification de\nl’arrêt de renvoi.","[CPPN] Art. 262 : L’accusé est ensuite invité à choisir un conseil pour l’assister\ndans sa défense.\nSi l’accusé ne choisit pas son conseil, le président ou son remplaçant lui en\ndésigne un d’office.\nCette désignation est non avenue si, par la suite, l’accusé choisit un conseil.","[CPPN] Art. 263 : Le conseil ne peut être choisi que parmi les avocats défenseurs\ninscrits au Niger.\n\nIl peut être désigné par le président ou son remplaçant sur une liste de\nfonctionnaires dressée annuellement par le garde des sceaux, ministre de\nla justice.\nLes avocats à un barreau étranger ne peuvent être choisis que s’il existe\nune convention de réciprocité entre la République du Niger et leur pays\nd’origine.","[CPPN] Art. 264 : L’accomplissement des formalités prescrites par les articles\n260 à 263 est constaté par un procès-verbal que signent le président ou son\nremplaçant, le greffier, l’accusé et, s’il y a lieu, l’interprète.\nSi l’accusé ne sait ou ne veut signer, le procès-verbal en fait mention.","[CPPN] Art. 265 : Les débats ne peuvent s’ouvrir moins de quinze jours après\nl’interrogatoire par le président de la Cour d’assises. L’accusé et son conseil\npeuvent renoncer à ce délai.\nL’accusé ne cesse pas de pouvoir communiquer librement avec son conseil.\nLe conseil peut prendre sur place communication de toutes les pièces du\ndossier sans que cette communication puisse provoquer un retard dans la\nmarche de la procédure.","[CPPN] Art. 266 : Il est délivré gratuitement à chacun des accusés copie des\nprocès-verbaux constatant l’infraction, des déclarations écrites des témoins\net des rapports d’expertise.","[CPPN] Art. 267 : L’accusé et la partie civile, ou leurs conseils, peuvent se faire\ndélivrer, à leurs frais, copie de toutes pièces de la procédure.","[CPPN] Art. 268 : Le ministère public notifie à l’accusé, la partie civile signifie à\nl’accusé, l’accusé signifie au ministère public, et s’il y a lieu, à la partie\ncivile, vingt-quatre heures au moins avant l’ouverture des débats, la liste\ndes personnes qu’ils désirent faire entendre en qualité de témoins.\nLes noms des experts appelés à rendre compte des travaux dont ils ont été\nchargés au cours de l’information doivent être notifiés ou signifiés dans les\nmêmes conditions.\nL’acte de notification ou l’exploit de signification doit mentionner les nom,\nprénoms, profession et résidence de ces témoins ou experts.\n\nLes citations faites à la requête des parties sont à leurs frais, ainsi que les\nindemnités des témoins cités, s’ils en requièrent; sauf au ministère public à\nfaire citer, à sa requête, les témoins qui lui sont indiqués par l’accusé, dans\nle cas où il juge que leur déclaration peut être utile pour la découverte de la\nvérité.","[CPPN] Art. 269 : La liste des jurés, telle qu’elle a été arrêtée conformément aux\nprescriptions de l’article 254, est notifiée à chaque accusé au plus tard\nl’avant-veille du tirage au sort.","[CPPN] Art. 270 : (Loi n° 2003-26 du 13 juin 2003). Les accusés qui ne\nseront arrivés dans l’établissement pénitentiaire qu’après l’ouverture de la\nsession d’assises ne pourront être jugés au cours de la session que lorsqu’ils\ny auront consenti.\nDans ce cas, ils seront considérés comme ayant renoncé à la faculté\nd’exercer aucune récusation contre les jurés antérieurement désignés par\nle sort.\nMention de leur consentement devra être insérée, à peine de nullité, au\nprocès-verbal d’interrogatoire du président.\nSection II : Des actes facultatifs ou exceptionnels","[CPPN] Art. 271 : Le président, si l’instruction lui semble incomplète ou si des\néléments nouveaux ont été révélés depuis sa clôture, peut ordonner tous\nactes d’information qu’il estime utiles.\nIl y est procédé soit par le président, soit par un de ses assesseurs ou un\njuge d’instruction qu’il délègue à cette fin. Dans ce cas, les prescriptions\ndu chapitre premier du titre III du livre premier doivent être observées, à\nl’exception de celles de l’article 158.","[CPPN] Art. 272 : Les procès-verbaux et autres pièces ou documents réunis au\ncours du supplément d’information sont déposés au greffe de la Cour\nd’assises et joints au dossier de la procédure. Ils sont mis à la disposition\ndes parties qui sont avisées de leur dépôt par les soins du greffier.\nLe procureur général peut, à tout moment, requérir communication de la\nprocédure, à charge de rendre les pièces dans les vingt-quatre heures.\n\nCode de procédure pénale","[CPPN] Art. 273 : Lorsqu’à raison d’un même crime plusieurs arrêts de renvoi ont\nété rendus contre différents accusés, le président peut, soit d’office, soit\nsur réquisition du ministère public, ordonner la jonction des procédures.\nCette jonction peut également être ordonnée quand plusieurs arrêts de renvoi\nont été rendus contre un même accusé pour des infractions différentes.","[CPPN] Art. 274 : Quand l’arrêt de renvoi vise plusieurs infractions non connexes,\nle président peut, soit d’office, soit sur réquisition du ministère public,\nordonner que les accusés ne soient immédiatement poursuivis que sur l’une\nou quelques-unes de ces infractions.","[CPPN] Art. 275 : Le président peut, soit d’office, soit sur réquisitions conformes\ndu ministère public, ordonner le renvoi à une session ultérieure des affaires\nqui ne lui paraissent pas en état d’être jugées au cours de la session au rôle\nde laquelle elles sont inscrites.\nCHAPITRE V : DE L’OUVERTURE DES SESSIONS\nSection 1 : Du tirage au sort des jurés","[CPPN] Art. 276 : Au siège de chaque Cour d’assises, quinze jours au moins avant\ncelui fixé pour l’ouverture de la session, le président de la Cour d’assises\ntire au sort, sur la liste principale, les noms de quatre jurés titulaires et de\ndeux jurés suppléants pour le service de la session.\nCette formalité peut être accomplie, en l’absence du président de la Cour\nd’assises, par le président de la juridiction de première instance.","[CPPN] Art. 277 : Le président de la Cour d’appel peut, en raison de l’importance\nou du nombre élevé des affaires inscrites au rôle de la session, ordonner\nque les quatre jurés titulaires et les deux jurés suppléants nécessaires au\nservice de la session seront remplacés par un ou plusieurs groupes de\nquatre jurés titulaires et de deux jurés suppléants dont les noms seront tirés\nau sort dans les conditions prévues au précédent article.\nLorsque le président de la Cour d’appel use de cette faculté, il doit, avant\nqu’il ne soit procédé au tirage au sort, préciser dans une ordonnance le\nnombre total des jurés titulaires et des jurés suppléants nécessaires au\nservice de la session et, en suivant l’ordre des inscriptions au rôle, le nombre\ndes affaires qui seront soumises à chacun des groupes de quatre jurés\ntitulaires et de deux jurés suppléants prévus.\n\nLe président de la Cour d’assises et les magistrats qui, aux termes de\nl’article 276, sont chargés de procéder au tirage au sort, dans\nl’accomplissement de cette formalité, doivent se conformer aux dispositions\nde l’ordonnance précitée.","[CPPN] Art. 278 : Le tirage au sort a lieu en audience publique, en présence du\nministère public, des accusés et de leurs défenseurs et des interprètes. La\nprésence des parties civiles régulièrement constituées ou de leurs conseils\nn’est pas obligatoire.\nA cet effet, le président, chargé du tirage, dispose un à un dans une urne,\naprès les avoir lus à haute et intelligible voix, les noms des jurés du ressort\nécrits sur autant de bulletins.\nLe ou les accusés peuvent renoncer à assister au tirage au sort.","[CPPN] Art. 279 : Ne sont point mis dans l’urne, les noms des jurés qui auraient\nfait le service pendant la session précédente.","[CPPN] Art. 280 : Si, parmi les jurés inscrits sur la liste principale, il en est qui ne\nremplissent pas les conditions d’aptitude exigées par les articles 245 et\n246, où se trouvent dans un cas d’incapacité, d’incompatibilité ou de dispense\nprévu par les articles 247 et 248, le président ordonne que leurs noms\nsoient rayés de la liste.\nIl en est de même en ce qui concerne les noms des jurés décédés.\nSi, à la suite de l’application des deux alinéas précédents, il reste moins de\nquinze jurés disponibles, ce nombre est complété par les jurés de la liste\nsupplémentaire, désignés par tirage au sort. Cette opération terminée, le\nmagistrat tire successivement chaque bulletin de l’urne et lit le nom qui s’y\ntrouve inscrit.","[CPPN] Art. 281 : L’accusé ou son conseil d’abord, le ministère public ensuite,\nrécusent tels jurés qu’ils jugent à propos, à mesure que leurs noms sortent\nde l’urne, sauf la limitation exprimée ci-dessous. L’accusé, son conseil ou\nle ministère public ne peuvent exposer leurs motifs de récusation.\nL’accusé ne peut récuser plus de cinq jurés, le ministère public plus de trois.\nS’il y a plusieurs accusés, ils peuvent se concerter pour exercer leurs\nrécusations; ils peuvent les exercer séparément.\n\nDans l’un et l’autre cas, ils ne peuvent excéder le nombre de récusation\ndéterminé pour un seul accusé.\nSi les accusés ou leurs conseils ne se concertent pas pour récuser, le sort\nrègle entre eux le rang dans lequel ils font les récusations. Dans ce cas, les\njurés récusés par un seul, et dans cet ordre, le sont pour tous jusqu’à ce\nque le nombre des récusations soit épuisé.\nLes accusés ou leurs conseils peuvent se concerter pour exercer une partie\ndes récusations, sauf à exercer le surplus suivant le rang fixé par le sort.","[CPPN] Art. 282 : La liste des jurés de la session est définitivement formée lorsque\nle magistrat chargé du tirage a obtenu, par le sort, le nombre de jurés\ntitulaires et suppléants nécessaires aux termes de l’article 276, sans qu’il y\nait eu de récusation ou lorsque les récusations auront été exercées\nconformément à l’article précédent.\nProcès-verbal du tout est dressé par le greffier et signé du magistrat qui a\nprésidé au tirage.","[CPPN] Art. 283 : Sept jours au moins avant l’ouverture des assises notification\nest faite, à chacun des jurés désignés par le sort, du procès-verbal constatant\nqu’il fait partie de la Cour d’assises.\nCette notification est faite par le ministère public près le tribunal du lieu où\ns’est fait le tirage au sort.\nElle contient sommation de se trouver aux jour, lieu et heure indiqués pour\nl’ouverture des assises.","[CPPN] Art. 284 : A défaut de notification à la personne, elle est faite à son domicile,\nainsi qu’au maire ou à l’adjoint, ou au chef de circonscription administrative.\nCelle de ces personnes qui a reçu la notification est tenue d’en donner\ncommunication au juré qu’elle concerne.","[CPPN] Art. 285 : En ce qui concerne les autres groupes de jurés appelés à\nremplacer le premier dans les conditions prévues à l’article 277, l’extrait\ndu procès-verbal doit contenir sommation de se trouver aux jours, lieu et\nheure où sera appelée la première affaire qui, suivant les dispositions de\nl’ordonnance, doit être soumise à leur examen.\n\nSection II : De la révision de la liste des jurés de la session","[CPPN] Art. 286 : Aux lieux, jour et heure fixés pour l’ouverture de la session, la\nCour prend séance. Le greffier procède à l’appel des jurés inscrits sur la\nliste conformément à l’article 276.\nLa Cour statue sur le cas des jurés absents.","[CPPN] Art. 287 : Tout juré qui, sans motif légitime, n’a pas déféré à la sommation\nqui lui est notifiée, est condamné par la Cour à une amende, laquelle est,\npour la première fois, de 10.000 francs, pour la seconde fois de 20.000\nfrancs et, pour la troisième fois de 50.000 francs.","[CPPN] Art. 288 : Les peines portées à l’article 287 sont applicables à tout juré qui\nmême ayant déféré à la sommation, se retire avant l’expiration de ses\nfonctions, sans une excuse jugée valable par la cour.","[CPPN] Art. 289 : (Loi n° 71-7 du 29 janvier 1971 et Loi n° 2003-26 du 13\njuin 2003). Si, à l’ouverture de la session, un ou deux jurés n’ont pas\nsatisfait à la sommation, ils sont remplacés par le ou les jurés suppléants\ndésignés par le sort conformément à l’article 276 et, si le nombre nécessaire\nn’est pas atteint, par voie de nouveau tirage au sort sur la première ou la\nseconde liste supplémentaire, selon que la Cour d’assises est réunie au\nsiège d’un tribunal de grande instance.\nLe juré supplémentaire ainsi désigné par ce nouveau tirage au sort est tenu\nde faire le service des assises lors même qu’il l’aurait fait pendant la session\nprécédente.","[CPPN] Art. 290 : Lorsqu’un procès criminel paraît de nature à entraîner de\nlongs débats, le président de la Cour d’assises peut désigner, avant\nl’ouverture de l’audience, un ou deux jurés supplémentaires, pris parmi les\njurés suppléants dans l’ordre du tirage au sort, qui assistent aux débats.\nDans le cas où l’un ou plusieurs des quatre jurés qui composent normalement\nla Cour seraient empêchés de suivre les débats jusqu’au prononcé de l’arrêt,\nils seront remplacés par les jurés supplémentaires.\nLe remplacement se fait suivant l’ordre dans lequel les jurés supplémentaires\nont été appelés par le sort.\n\nCode de procédure pénale","[CPPN] Art. 291 : (Loi n° 63-43 du 10 juillet 1963). Le président adresse aux\njurés, debout et découverts, le discours suivant :\n«Vous jurez et promettez devant Dieu et devant les hommes d’examiner\navec l’attention la plus scrupuleuse les affaires qui vous seront soumises\npendant le cours de la présente session, de n’écouter ni la haine ou la\nméchanceté, ni la crainte ou l’affection, et de ne vous décider que\nd’après les charges, les moyens de défense et les dispositions des lois,\nsuivant votre conscience et votre intime conviction, avec l’impartialité\net la fermeté qui conviennent à un homme probe et libre, et de conserver\nle secret des délibérations, même après la cessation de vos fonctions».\nChacun des jurés, appelés individuellement par le président, répond en levant\nla main : « Je le jure ».","[CPPN] Art. 292 : Le président déclare le jury définitivement constitué.\nCHAPITRE VI : DES DEBATS\nSection 1 : Dispositions générales","[CPPN] Art. 293 : Les débats sont publics, à moins que la publicité ne soit dangereuse\npour l’ordre et les mœurs. Dans ce cas, la Cour le déclare par un arrêt\nrendu en audience publique.\nToutefois, le président peut interdire l’accès de la salle d’audience aux\nmineurs ou à certains d’entre eux.\nLorsque le huis clos a été ordonné, celui-ci s’applique au prononcé des arrêts\nqui peuvent intervenir sur les incidents contentieux visés à l’article 303.\nL’arrêt sur le fond doit toujours être prononcé en audience publique.","[CPPN] Art. 294 : Les débats ne peuvent être interrompus et doivent continuer\njusqu’à ce que la cause soit terminée par l’arrêt de la Cour d’assises.\nIls peuvent être suspendus pendant le temps nécessaire au repos des juges\net de l’accusé.","[CPPN] Art. 295 : Le président a la police de l’audience et la direction des débats.\nIl rejette tout ce qui tendrait à compromettre leur dignité ou à les prolonger\nsans donner lieu d’espérer plus de certitude dans les résultats.\n\nCode de procédure pénale","[CPPN] Art. 296 : L’emploi de tout appareil d’enregistrement ou de diffusion sonore,\nde caméra de télévision ou de cinéma, d’appareils photographiques, peut\nêtre autorisé par le président.","[CPPN] Art. 297 : Le président est investi d’un pouvoir discrétionnaire en vertu\nduquel il peut, en son honneur et conscience, prendre toutes mesures qu’il\ncroît utiles pour découvrir la vérité.\nIl peut, au cours des débats, appeler, au besoin par mandat d’amener et\nentendre toutes personnes ou se faire apporter toutes nouvelles pièces qui\nlui paraissent, d’après les développements donnés à l’audience, utiles à la\nmanifestation de la vérité.\nLes témoins ainsi appelés ne prêtent pas serment et leurs déclarations ne\nsont considérées que comme renseignements.","[CPPN] Art. 298 : Les magistrats membres de la Cour et les jurés peuvent poser\ndes questions aux accusés et aux témoins en demandant la parole au\nprésident.\nIls ont le devoir de ne pas manifester leur opinion.","[CPPN] Art. 299 : Sous réserve des dispositions de l’article 295, le ministère public\npeut poser directement des questions aux accusés et aux témoins.\nL’accusé ou son conseil peut poser des questions, par l’intermédiaire du\nprésident, aux coaccusés et aux témoins. La partie civile ou son conseil\npeut, dans les mêmes conditions, poser des questions aux accusés et aux\ntémoins.","[CPPN] Art. 300 : Le ministère public prend, au nom de la loi, toutes les réquisitions\nqu’il juge utiles : la Cour est tenue de lui en donner acte et d’en délibérer.\nLes réquisitions du ministère public prises dans le cours des débats sont\nmentionnées par le greffier sur son procès-verbal. Toutes les décisions\nauxquelles elles ont donné lieu sont signées par le président et par le greffier.","[CPPN] Art. 301 : Lorsque la Cour ne fait pas droit aux réquisitions du ministère\npublic, l’instruction ni le jugement ne sont arrêtés, ni suspendus.","[CPPN] Art. 302 : L’accusé, la partie civile et leurs conseils peuvent déposer des\nconclusions sur lesquelles la Cour est tenue de statuer.\n\nCode de procédure pénale","[CPPN] Art. 303 : Tous incidents contentieux sont réglés par la cour, le ministère\npublic, les parties ou leurs conseils entendus.\nCes arrêts ne peuvent préjuger du fond.\nIls ne peuvent être attaqués par la voie du recours en cassation qu’en\nmême temps que l’arrêt sur le fond.\nSection II : De la comparution de l’accusé.","[CPPN] Art. 304 : A l’audience, la présence d’un défenseur auprès de l’accusé\nest obligatoire.\nSi le défenseur choisi ou désigné conformément à l’article 262 ne se présente\npas, le président en commet un d’office.","[CPPN] Art. 305 : L’accusé comparaît libre et seulement accompagné de gardes\npour l’empêcher de s’évader.","[CPPN] Art. 306 : Si un accusé refuse de comparaître, sommation lui est faite au\nnom de la loi, par un huissier commis à cet effet par le président, et assisté\nde la force publique. L’huissier dresse procès-verbal de la sommation et de\nla réponse de l’accusé.","[CPPN] Art. 307 : Si l’accusé n’obtempère pas à la sommation, le président peut\nordonner qu’il soit amené par la force devant la cour; il peut également,\naprès lecture faite à l’audience du procès-verbal constatant sa résistance,\nordonner que, nonobstant son absence, il soit passé outre aux débats.\nAprès chaque audience, il est, par le greffier de la Cour d’assises, donné\nlecture à l’accusé qui n’a pas comparu, du procès-verbal des débats, et il\nlui est signifié copie des réquisitions du ministère public ainsi que des arrêts\nrendus par la cour, qui sont tous réputés contradictoires.","[CPPN] Art. 308 : Lorsque, à l’audience, l’un des assistants trouble l’ordre de\nquelque manière que ce soit, le président ordonne son expulsion de la salle\nde l’audience.\nSi au cours de l’exécution de cette mesure, il résiste à cet ordre ou cause du\ntumulte, il est, sur-le-champ, placé sous mandat de dépôt, jugé et puni d’un\nemprisonnement de deux mois à deux ans, sans préjudice des peines portées\nau code pénal contre les auteurs d’outrages et de violences envers les magistrats.\n\nSur l’ordre du président, il est alors contraint par la force publique de quitter\nl’audience.","[CPPN] Art. 309 : Si l’ordre est troublé par l’accusé lui-même, il lui est fait\napplication des dispositions de l’article 308.\nL’accusé, lorsqu’il est expulsé de la salie d’audience, est gardé par la force\npublique, jusqu’à la fin des débats à la disposition de la cour; il est, après\nchaque audience, procédé ainsi qu’il est dit à l’article 307, alinéa 2.\nSection III : De la production et de la discussion des preuves","[CPPN] Art. 310 : Le président avertit le conseil de l’accusé qu’il ne peut rien\ndire contre sa conscience ou contre le respect dû aux lois et qu’il doit\ns’exprimer avec décence et modération.","[CPPN] Art. 311 : Le président ordonne au greffier de donner lecture de la liste\ndes témoins appelés par le ministère public, par l’accusé et, s’il y a lieu, par\nla partie civile, et dont les noms ont été notifiés ou signifiés conformément\naux prescriptions de l’article 268.\nL’huissier de service fait appel de ces témoins.","[CPPN] Art. 312 : Le président ordonne aux témoins de se retirer dans la Chambre\nqui leur est destinée. Ils n’en sortent que pour déposer. Le président prend,\ns’il est besoin, toutes mesures utiles pour empêcher les témoins de conférer\nentre eux avant leur déposition.","[CPPN] Art. 313 : Lorsqu’un témoin cité ne comparaît pas, la Cour peut, sur\nréquisitions du ministère public ou même d’office, ordonner que ce témoin\nsoit immédiatement amené par la force publique devant la Cour pour y être\nentendu, ou renvoyer l’affaire à la prochaine session.\nEn ce dernier cas, tous les frais de citation, d’actes de voyage de témoins et\nautres ayant pour objet de faire juger l’affaire sont, hors le cas d’excuse légitime,\nà la charge de ce témoin et il est contraint, même par corps, sur la réquisition du\nministère public, par l’arrêt qui renvoie les débats à la session suivante.\nDans tous les cas, le témoin qui ne comparaît pas ou qui refuse soit de\nprêter serment, soit de faire sa déposition peut, sur réquisition du ministère\npublic, être condamné par la Cour à la peine portée de l’article 104.\n\nLa voie de l’opposition est ouverte au condamné qui n’a pas comparu.\nL’opposition s’exerce dans les cinq jours de la signification de l’arrêt faite\nà sa personne ou son domicile. La Cour statue sur cette opposition soit\npendant la session en cours, soit au cours d’une session ultérieure.","[CPPN] Art. 314 : Le président invite l’accusé à écouter avec attention la lecture\nde l’arrêt de renvoi.\nIl ordonne du greffier de lire de cet arrêt à haute et intelligible voix.","[CPPN] Art. 315 : Le président interroge l’accusé et reçoit ses déclarations. Il a le\ndevoir de ne pas manifester son opinion sur la culpabilité.","[CPPN] Art. 316 : Les témoins appelés par les parties sont entendus dans le débat,\nmême s’ils n’ont pas déposé à l’instruction, ou s’ils n’ont pas été assignés,\nà condition que leurs noms aient été notifiés ou signifiés conformément aux\nprescriptions de l’article 268.","[CPPN] Art. 317 : Les parties peuvent s’opposer à l’audition d’un témoin dont le\nnom ne leur aurait pas été notifié ou signifié ou qui leur aurait été\nirrégulièrement notifié ou signifié.\nLa Cour statue sur cette opposition.\nSi elle est reconnue fondée, ces témoins peuvent être entendus, à titre de\nrenseignements, en vertu du pouvoir discrétionnaire du président.","[CPPN] Art. 318 : Les témoins déposent séparément l’un de l’autre, dans l’ordre\nétabli par le président.\nLes témoins doivent, sur la demande du président, faire connaître leurs\nnom, prénoms, âge, profession, leur domicile ou résidence, s’ils connaissaient\nl’accusé avant le fait mentionné dans l’arrêt de renvoi, s’ils sont parents ou\nalliés, soit de l’accusé, soit de la partie civile, et à quel degré. Le président\nleur demande encore s’ils ne sont pas attachés au service de l’un ou l’autre.\nAvant de commencer leur déposition, les témoins prêtent le serment «de\nparler sans haine et sans crainte, de dire toute la vérité, rien que la\nvérité.» Cela fait, les témoins déposent oralement.\nSous réserve des dispositions de l’article 295, les témoins ne sont pas\ninterrompus dans leur déposition.\n\nCode de procédure pénale","[CPPN] Art. 319 : Après chaque déposition, le président peut poser des questions\naux témoins.\nLe ministère public, ainsi que les conseils de l’accusé et de la partie civile,\nl’accusé et la partie civile ont la même faculté, dans les conditions\ndéterminées à l’article 299.","[CPPN] Art. 320 : Le président fait dresser d’office ou à la requête des parties,\npar le greffier, un procès-verbal des auditions, changements ou variations\nqui peuvent exister entre la déposition d’un témoin et ses précédentes\ndéclarations. Ce procès-verbal est joint au procès-verbal des débats.","[CPPN] Art. 321 : Chaque témoin, après sa déposition, demeure dans la salle\nd’audience, si le président n’en ordonne autrement, jusqu’à la clôture des\ndébats.","[CPPN] Art. 322 : Ne peuvent être reçues sous la foi du serment les dépositions :\n1) du père, de la mère ou de tout autre ascendant de l’accusé, ou de l’un\ndes accusés présent et soumis au même débat;\n2) du fils, de la fille, ou de tout autre descendant;\n3) des frères et sœurs;\n4) des alliés aux mêmes degrés;\n5) du mari ou de la femme; cette prohibition subsiste même après le divorce;\n6) de la partie civile;\n7) des enfants au-dessous de l’âge de seize ans.","[CPPN] Art. 323 : Néanmoins, l’audition sous serment des personnes désignées\npar l’article précédent n’entraîne pas nullité lorsque le ministère public ni\naucune des parties ne s’est opposé à la prestation de serment.\nEn cas d’opposition du ministère public ou d’une ou plusieurs des parties, le\ntémoin peut être entendu à titre de renseignements, en vertu du pouvoir\ndiscrétionnaire du président.","[CPPN] Art. 324 : La personne qui, agissant en vertu d’une obligation légale ou de\nsa propre initiative, a porté les faits poursuivis à la connaissance de la justice,\nest reçue en témoignage mais le président en avertit la Cour d’assises.\n\nCelui dont la dénonciation est récompensée pécuniairement par la loi peut\nêtre entendu en témoignage, à moins qu’il n’y ait opposition d’une des\nparties ou du ministère public.","[CPPN] Art. 325 : Le ministère public, ainsi que la partie civile et l’accusé, peuvent\ndemander, et le président peut toujours ordonner, qu’un témoin se retire\nmomentanément de la salle d’audience, après sa déposition, pour y être\nintroduit et entendu s’il y a lieu après d’autres dépositions, avec ou sans\nconfrontation.","[CPPN] Art. 326 : Le président peut, avant, pendant ou après l’audition d’un témoin,\nfaire retirer un ou plusieurs accusés, et les examiner séparément sur quelques\ncirconstances du procès, mais il a soin de ne reprendre la suite des débats\nqu’après avoir instruit chaque accusé de ce qui s’est fait en son absence,\net ce qui en est résulté.","[CPPN] Art. 327 : Pendant l’examen, les magistrats et les jurés peuvent prendre\nnote de ce qui leur paraît important, soit dans les dépositions des témoins, soit\ndans la défense de l’accusé, pourvu que les débats ne soient pas interrompus.","[CPPN] Art. 328 : Dans le cours ou à la suite des dépositions, le président fait, s’il\nest nécessaire, présenter à l’accusé ou aux témoins les pièces à conviction\net reçoit leurs observations.\nLe président les fait aussi présenter, s’il y a lieu, aux autres membres de la\nCour et aux jurés.","[CPPN] Art. 329 : Si, d’après les débats, la déposition d’un témoin paraît fausse, le\nprésident, soit d’office, soit à la requête du ministère public ou d’une des\nparties, peut ordonner spécialement à ce témoin d’être présent aux débats\njusqu’à leur clôture et en outre, de demeurer dans la salle d’audience\njusqu’au prononcé de l’arrêt de la Cour d’assises. En cas d’infraction à cet\nordre, le président fait mettre le témoin en état d’arrestation provisoire.\nAprès lecture de l’arrêt de la Cour d’assises, ou, dans le cas de renvoi à\nune autre session, le président ordonne que le témoin soit, par la force\npublique, conduit sans délai devant le procureur de la République qui requiert\nl’ouverture d’une information.\nLe greffier transmet à ce magistrat une expédition du procès-verbal qui a\npu être dressé par application de l’article 320.\n\nCode de procédure pénale","[CPPN] Art. 330 : En tout état de cause, la Cour peut ordonner d’office, ou à la\nrequête du ministère public ou de l’une des parties, le renvoi de l’affaire à\nla prochaine session.","[CPPN] Art. 331 : Dans le cas où l’accusé, les témoins ou l’un d’eux, ne parlent\npas suffisamment la langue française ou s’il est nécessaire de traduire un\ndocument versé aux débats, le président nomme d’office un interprète, âgé\nde vingt et un ans au moins, et lui fait prêter serment de remplir fidèlement\nsa mission.\nLe ministère public, l’accusé et la partie civile, peuvent récuser l’interprète\nen motivant leur récusation. La Cour se prononce sur cette récusation. Sa\ndécision n’est susceptible d’aucune voie de recours.\nL’interprète ne peut, même du consentement de l’accusé ou du ministère\npublic, être parmi les juges composant la cour, les jurés, le greffier qui tient\nl’audience, les parties et les témoins.","[CPPN] Art. 332 : Si l’accusé est sourd-muet et ne sait pas écrire, le président\nnomme d’office en qualité d’interprète la personne qui a le plus l’habitude\nde converser avec lui.\nIl en est de même à l’égard du témoin sourd-muet.\nLes autres dispositions du précédent article sont applicables.\nDans le cas où le sourd-muet sait écrire, le greffier écrit les questions ou\nobservations qui lui sont faites; elles sont remises à l’accusé ou au témoin,\nqui donne par écrit ses réponses ou déclarations. Il est fait lecture du tout\npar le greffier.","[CPPN] Art. 333 : Une fois l’instruction à l’audience terminée, la partie civile ou\nson conseil est entendu. Le ministère public prend ses réquisitions.\nL’accusé et son conseil présentent leur défense.\nLa réplique est permise à la partie civile et au ministère public, mais l’accusé\nou son conseil auront toujours la parole les derniers.\n\nSection IV : De la clôture des débats","[CPPN] Art. 334 : Le président déclare les débats terminés.\nIl ne peut résumer les moyens de l’accusation et de la défense.\n(Loi n° 63-16 du 21 février 1963). Le président donne lecture des\nquestions auxquelles la Cour et les jurés ont à répondre. Cette lecture n’est\npas obligatoire quand les questions sont posées dans les termes de l’arrêt\nde renvoi ou si l’accusé ou son défenseur y renonce.\nChaque question principale est posée ainsi qu’il suit : «L’accusé est-il\ncoupable d’avoir commis tel fait ?»\nUne question est posée sur chaque fait spécifié dans le dispositif de l’arrêt\nde renvoi. Chaque circonstance aggravante fait l’objet d’une question\ndistincte.\nIl en est de même, s’il y a lieu, de chaque excuse invoquée et de la question\nde discernement pour les mineurs.\nS’il résulte des débats que le fait comporte une qualification légale autre\nque celle donnée par l’arrêt de renvoi, le président doit poser une ou plusieurs\nquestions subsidiaires.\nS’il résulte des débats une ou plusieurs circonstances aggravantes, non\nmentionnées dans l’arrêt de renvoi, le président pose une ou plusieurs\nquestions spéciales.\nLe président est tenu de poser la question des circonstances atténuantes\ntoutes les fois que la culpabilité de l’accusé a été reconnue.\nSur tout incident contentieux au sujet des questions, la Cour statue dans les\nconditions prévues par l’article 303.","[CPPN] Art. 335 : Avant que la Cour d’assises ne se retire, le président donne\nlecture de l’instruction suivante, qui est, en outre, affichée en gros caractères,\ndans le lieu le plus apparent de la Chambre des délibérations :\n« La loi ne demande pas compte aux juges des moyens par lesquels ils\nse sont convaincus; elle ne leur prescrit pas de règles desquelles ils\ndoivent faire particulièrement dépendre la plénitude et la suffisance\nd’une preuve; elle leur prescrit de s’interroger eux-mêmes, dans le\n\nsilence et le recueillement, et de chercher dans la sincérité de leur\nconscience, quelle impression ont faite, sur leur raison, les preuves\nrapportées contre l’accusé, et les moyens de sa défense. La loi ne leur\nfait que cette seule question, qui renferme toute la mesure de leurs\ndevoirs : «avez-vous une intime conviction?»","[CPPN] Art. 336 : Le président fait retirer l’accusé de la salle d’audience.\nIl invite le chef du service d’ordre à faire garder les issues de la Chambre\ndes délibérations, dans laquelle nul ne pourra pénétrer, pour quelque cause\nque ce soit, sans autorisation du président.\nLe président déclare l’audience suspendue.\nCHAPITRE VII : DU JUGEMENT\nSection 1 : De la délibération de la Cour d’assises","[CPPN] Art. 337 : Les magistrats de la Cour et les jurés se retirent dans la Chambre\ndes délibérations. Ils n’en peuvent sortir qu’après avoir pris leurs décisions.","[CPPN] Art. 338 : (Loi n° 63-16 du 21 février 1963). La Cour et les jurés\ndélibèrent puis votent à la simple majorité sur les questions posées.\nEn cas de réponse affirmative sur la culpabilité, les juges et les jurés\ndélibèrent sans désemparer sur l’application de la peine.","[CPPN] Art. 339 : (Loi n° 63-16 du 21 février 1963). Lorsque la Cour d’assises\nprononce pour crime une peine correctionnelle, elle ne peut ordonner qu’il\nsera sursis à l’exécution de la peine.\nLa Cour d’assises délibère également sur les peines accessoires ou\ncomplémentaires.","[CPPN] Art. 340 : Si le fait retenu contre l’accusé ne tombe plus sous l’application\nde la loi pénale, ou si l’accusé est déclaré non coupable, la Cour d’assises\nprononce l’acquittement de celui-ci.\nSi l’accusé bénéficie d’une excuse absolutoire, la Cour d’assises prononce\nson absolution.\n\nSection II : De la décision sur l’action publique","[CPPN] Art. 341 : (Loi n° 63-16 du 21 février 1963). La Cour d’assises rentre\nensuite dans la salle d’audience. Le président fait comparaître l’accusé,\ndonne lecture des réponses faites aux questions et prononce l’arrêt portant\ncondamnation, absolution ou acquittement.\nLes décisions prises sur les questions posées doivent être signées par le\nprésident et le greffier avant la lecture du verdict à l’accusé.\nLes textes de loi dont il est fait application sont lus à l’audience par le\nprésident : il est fait mention de cette lecture dans l’arrêt.\nAu cas de condamnation ou d’absolution, l’arrêt condamne l’accusé aux\ndépens envers l’Etat et se prononce sur la contrainte par corps.\nAu cas où l’accusé est acquitté en raison de son état de démence au\nmoment des faits, la Cour peut mettre à sa charge tout ou partie des dépens\nenvers l’Etat.\nDans le cas où la condamnation n’intervient pas pour toutes les infractions\nqui ont fait l’objet de la poursuite, ou n’intervient qu’à raison d’infractions,\nqui ont fait l’objet d’une disqualification, soit au cours de l’instruction, soit\nau moment du prononcé de l’arrêt, comme aussi dans le cas de mise hors\nde cause de certains des accusés, la Cour doit, par une disposition motivée,\ndécharger le condamné de la part des frais de justice qui ne résulte pas\ndirectement de l’infraction ayant entraîné la condamnation au fond. La\nCour fixe elle-même le montant des frais dont doit être déchargé le\ncondamné, ces frais étant laissés, selon les circonstances, à la c","[CPPN] Art. 342 : Si l’accusé est absous ou acquitté, il est mis immédiatement en\nliberté s’il n’est retenu pour autre cause.","[CPPN] Art. 343 : Aucune personne acquittée légalement ne peut plus être reprise\nou accusée à raison des mêmes faits, même sous une qualification différente.","[CPPN] Art. 344 : Lorsque, dans le cours des débats, des charges sont relevées\ncontre l’accusé à raison d’autres faits, et lorsque le ministère public a fait\n\ndes réserves aux fins de poursuites, le président ordonne que l’accusé\nacquitté soit, par la force publique, conduit sans délai devant le procureur\nde la République du siège de la Cour d’assises qui doit immédiatement\nrequérir l’ouverture d’une information.","[CPPN] Art. 345 : (Loi n° 63-16 du 21 février 1963). Dans les délibérations de\nla cour, les opinions devront être recueillies par le président suivant l’âge\ndes jurés en commençant par le plus jeune.","[CPPN] Art. 346 : Après avoir prononcé l’arrêt, le président avertit, s’il y a lieu,\nl’accusé de la faculté qui lui est accordée de se pourvoir en cassation et lui\nfait connaître le délai de ce pourvoi.\nSection III : De la décision sur l’action civile","[CPPN] Art. 347 : Après que la Cour d’assises s’est prononcée sur l’action publique,\nla cour, sans l’assistance des jurés, statue sur les demandes en dommagesintérêts formées soit par la partie civile contre l’accusé, soit par l’accusé\nacquitté contre la partie civile, après que les parties et le ministère public\nont été entendus.\nLa Cour peut commettre l’un de ses membres pour entendre les parties,\nprendre connaissance des pièces et faire son rapport à l’audience, où les\nparties peuvent encore présenter leurs observations, et où le ministère public\nest ensuite entendu.","[CPPN] Art. 348 : La partie civile dans le cas d’acquittement comme celui\nd’absolution, peut demander réparation du dommage résultant de la faute\nde l’accusé, telle qu’elle résulte des faits qui sont l’objet de l’accusation.","[CPPN] Art. 349 : La Cour peut ordonner d’office la restitution des objets placés\nsous la main de la justice. Toutefois, s’il y a eu condamnation, cette restitution\nn’est effectuée que si son bénéficiaire justifie que le condamné a laissé\npasser les délais sans se pourvoir en cassation ou, s’il est pourvu, que\nl’affaire est définitivement jugée.\nLorsque la décision de la Cour d’assises est devenue définitive, la Chambre\nd’accusation est compétente pour ordonner, s’il y a lieu, la restitution des\nobjets placés sous la main de la justice. Elle statue sur requête de toute\npersonne qui prétend avoir droit sur l’objet ou à la demande du ministère\npublic.\n\nCode de procédure pénale","[CPPN] Art. 350 : L’accusé qui succombe est condamné aux dépens envers la\npartie civile.","[CPPN] Art. 351 : La partie civile qui a obtenu des dommages-intérêts n’est jamais\ntenue des dépens. Celle qui a succombé n’est condamnée aux dépens que\nsi elle a, elle-même, mis en mouvement l’action publique. Toutefois, même\nen ce cas, elle peut, eu égard aux circonstances de la cause, être déchargée\nde la totalité ou d’une partie de ces dépens par décision spéciale et motivée\nde la cour.\nSection IV : De l’arrêt et du procès-verbal","[CPPN] Art. 352 : Le greffier écrit l’arrêt; les textes des lois appliquées y sont\nindiqués.","[CPPN] Art. 353 : La minute de l’arrêt rendu après délibération de la Cour d’assises\nainsi que la minute des arrêts rendus par la Cour sont signés par le président\net le greffier.\nTous ces arrêts doivent porter mention de la présence du ministère public.","[CPPN] Art. 354 : Le greffier dresse, à l’effet de constater l’accomplissement\ndes formalités prescrites, un procès-verbal qui est signé par le président et\npar ledit greffier.\nLe procès-verbal est dressé et signé dans le délai de trois jours au plus tard\ndu prononcé de l’arrêt.","[CPPN] Art. 355 : A moins que le président n’en ordonne autrement, d’office ou\nsur la demande des parties, il n’est fait mention au procès-verbal, ni des\nréponses des accusés, ni du contenu des dépositions, sans préjudice,\ntoutefois, de l’exécution de l’article 320 concernant les additions,\nchangements ou variations dans les déclarations des témoins.","[CPPN] Art. 356 : Les minutes des arrêts rendus par la Cour d’assises sont réunies\net déposées au greffe du tribunal siège de ladite cour.\nToutefois, les minutes des arrêts rendus par la Cour d’assises tenue au\nsiège de la Cour d’appel restent déposées au greffe de ladite cour.\n\nCHAPITRE VIII : DES PROCEDURES PAR DEFAUT","[CPPN] Art. 357 : (Loi n° 66-18 du 29 mars 1966). Lorsque, après un arrêt de\nmise en accusation, l’accusé n’a pas pu être saisi ou ne se représente pas\ndans les dix jours de la signification qui en a été faite à son domicile, il est\ncité à comparaître dans les formes édictées en matière correctionnelle.\nLa Cour d’assises se prononce sur pièces sans l’assistance des jurés et ne\npeut, en cas de condamnation, accorder le bénéfice des circonstances\natténuantes.\nElle statue ensuite sur les intérêts civils.","[CPPN] Art. 358 : Si le condamné se constitue prisonnier ou s’il est arrêté avant\nque la peine soit éteinte par la prescription, l’arrêt et les procédures faites\ndepuis la citation à comparaître sont anéantis de plein droit et il est procédé\nà son égard dans la forme ordinaire.\n(Loi n° 65-20 du 15 mai 1965). Toutefois les dispositions ci-dessus ne\nsont pas applicables lorsque l’arrêt a prononcé condamnation à l’encontre\nd’un accusé renvoyé uniquement pour délit ou contravention connexes à\nun crime. Cet arrêt est en outre susceptible d’opposition dans les formes et\ndélais édictés en matière correctionnelle.","[CPPN] Art. 359 : Dans le cas prévu à l’article précédent, si, pour quelque cause\nque ce soit, des témoins ne peuvent être produits aux débats, leurs\ndépositions écrites et, s’il est nécessaire, les réponses écrites des autres\naccusés du même crime, sont lues à l’audience; il en est de même de\ntoutes les autres pièces qui sont jugées par le président utiles à la\nmanifestation de la vérité.","[CPPN] Art. 360 : L’accusé en fuite qui, après s’être représenté, obtient son\nrenvoi de l’accusation, est condamné aux frais occasionnés par la procédure\nde défaut, à moins qu’il n’en soit dispensé par la cour.","[CPPN] Art. 361 : Le recours en cassation contre les arrêts de défaut rendus par\nla Cour d’assises n’est ouvert qu’au procureur général et la partie civile en\nce qui la regarde.\n\nTITRE II : DU JUGEMENT DES DELITS\nCHAPITRE PREMIER : DU TRIBUNAL CORRECTIONNEL\nSection 1 : De la compétence et de la saisine du tribunal\ncorrectionnel\nParagraphe premier : DISPOSITIONS GENERALES","[CPPN] Art. 362 : Le tribunal correctionnel connaît des délits.","[CPPN] Art. 363 : Est compétent le tribunal correctionnel du lieu de l’infraction,\ncelui de la résidence du prévenu ou celui du lieu de l’arrestation de ce\ndernier, même lorsque cette arrestation a été opérée pour une autre cause.\nLe tribunal du lieu de la détention d’un condamné n’est compétent que\ndans les conditions prévues au titre V du livre IV, relatif aux renvois d’un\ntribunal à un autre.\nLa compétence du tribunal correctionnel s’étend aux délits et contraventions\nqui forment avec l’infraction déférée au tribunal un ensemble indivisible au\nsens de l’article 196 ; elle peut aussi s’étendre aux délits et contraventions\nconnexes, au sens de l’article 195.","[CPPN] Art. 364 : La compétence à l’égard d’un prévenu s’étend à tous coauteurs\net complices.","[CPPN] Art. 365 : Le tribunal saisi de l’action publique est compétent pour statuer\nsur toutes exceptions proposées par le prévenu pour sa défense, à moins\nque la loi n’en dispose autrement, ou que le prévenu n’excipe d’un droit\nréel immobilier.","[CPPN] Art. 366 : Les exceptions tirées de la nullité soit de la citation, soit de la\nprocédure antérieure, doivent, à peine de forclusion, être présentées avant\ntoute défense au fond.\nLa nullité de la citation ne peut être prononcée que dans les conditions\nprévues à l’article 561.","[CPPN] Art. 367 : L’exception préjudicielle est présentée avant toute défense au\nfond.\nElle n’est recevable que si elle est de nature à retirer au fait qui sert de\nbase à la poursuite le caractère d’une infraction.\n\nElle n’est admise que si elle s’appuie sur des faits ou sur des titres donnant\nun fondement à la prétention du prévenu.\nSi l’exception est admissible, le tribunal impartit un délai dans lequel le\nprévenu doit saisir la juridiction compétente. Faute par le prévenu d’avoir\nintroduit l’instance dans ce délai et de justifier de ses diligences, il est passé\noutre à l’exception.\nSi l’exception n’est pas admise, les débats sont continués.","[CPPN] Art. 368 : Lorsque le tribunal est saisi de plusieurs procédures visant des\nfaits connexes, il peut en ordonner la jonction soit d’office, soit sur réquisition\ndu ministère public, ou à la requête d’une des parties.","[CPPN] Art. 369 : Le tribunal correctionnel est saisi des infractions de sa compétence,\nsoit par le renvoi qui lui en est fait par la juridiction d’instruction, soit, par la\ncomparution volontaire des parties, dans les conditions prévues par l’article\n370, soit par la citation délivrée directement au prévenu et à aux personnes\ncivilement responsables de l’infraction, soit enfin par application de la procédure\nde flagrant délit prévue par les articles 374 à 379.","[CPPN] Art. 370 : L’avertissement délivré par le ministère public dispense de\ncitation s’il est suivi de la comparution volontaire de la personne à laquelle\nil est adressé.\nIl indique le délit poursuivi et vise le texte de la loi qui le réprime.","[CPPN] Art. 371 : La citation est délivrée dans les délais et formes prévus par les\narticles 546 et suivants.","[CPPN] Art. 372 : Toute personne ayant porté plainte est avisée par le parquet de\nla date de l’audience.","[CPPN] Art. 373 : La partie civile, qui cite directement un prévenu devant un\ntribunal répressif, fait, dans l’acte de citation, élection de domicile au siège\ndu tribunal saisi, à moins qu’elle n’y soit domiciliée.\nParagraphe 2 : DU FLAGRANT DELIT","[CPPN] Art. 374 : L’individu, arrêté en flagrant délit et déféré devant le procureur\nde la République conformément à l’article 65 du présent code, est, s’il a\nété placé sous mandat de dépôt, traduit sur-le-champ à l’audience du tribunal.\n\nCode de procédure pénale","[CPPN] Art. 375 : Si ce jour là, il n’est point tenu d’audience, le prévenu est déféré\nà l’audience du lendemain, le tribunal étant, au besoin, spécialement réuni.\nSi cette réunion est impossible, le procureur de la République doit\nimmédiatement requérir l’ouverture d’une information.\nEn tout état de la procédure, le tribunal saisi suivant la procédure de flagrant\ndélit pourra décider, soit par ordonnance du président avant tout débat, soit\npar jugement avant dire droit, de tenir l’audience en un lieu quelconque de\nson ressort.","[CPPN] Art. 376 : (Loi n° 66-18 du 29 mars 1966). Les témoins du flagrant délit\npeuvent être requis verbalement par tout officier de police judiciaire ou\nagent de la force publique. Ils sont tenus de comparaître sous les sanctions\nportées aux articles 425 à 428.","[CPPN] Art. 377 : La personne déférée en vertu de l’article 374 est avertie par le\nprésident qu’elle a le droit de réclamer un délai pour préparer sa défense;\nmention de l’avis donné par le président et de la réponse du prévenu est\nfaite dans le jugement.\nSi le prévenu use de la faculté indiquée à l’alinéa précédent, le tribunal lui\naccorde un délai de trois jours au moins.\nLes dispositions énoncées aux deux alinéas précédents ne sont pas\napplicables dans le cas prévu à l’article 375, alinéa 3.","[CPPN] Art. 378 : Si l’affaire n’est pas en état de recevoir jugement, le tribunal en\nordonne le renvoi à l’une des plus prochaines audiences pour plus ample\ninformation et, s’il y a lieu, met le prévenu en liberté provisoire, avec ou\nsans caution.","[CPPN] Art. 379 : Le tribunal est tenu de juger l’affaire dans les trente jours de la\npremière audience, même si le casier judiciaire n’a pas été produit en temps\nutile.\nDans ce dernier cas, le procureur de la République du lieu de naissance du\nprévenu, dûment avisé, requiert du président du tribunal la condamnation\ndu greffier en chef à une amende de 2.000 francs.\nToutefois, en cas d’excuse reconnue valable, le greffier pourra être déchargé\nde cette condamnation.\n\nParagraphe 3 : DE LA COMPARUTION SUR RECONNAISSANCE\nPREALABLE DE CULPABILITE\n(Loi n° 2007-04 du 22 février 2007)\nArt. 379-1 : (Loi n° 2007-04 du 22 février 2007) Pour les délits punis\nà titre principal d’une peine d’amende ou d’une peine d’emprisonnement\nd’une durée inférieure à dix (10) ans, le procureur de la République peut,\nd’office ou à la demande de l’intéressé ou de son conseil, recourir à la\nprocédure de comparution sur reconnaissance préalable de culpabilité,\nconformément aux dispositions du présent paragraphe, à l’égard de toute\npersonne convoquée à cette fin ou déférée devant lui en application des\ndispositions du Code de procédure pénale, lorsque cette personne reconnaît\nles faits qui lui sont reprochés.\nArt. 379-2 : (Loi n° 2007-04 du 22 février 2007) Le procureur de la\nRépublique peut proposer à la personne d’exécuter une ou plusieurs des\npeines encourues; la nature et le quantum de la ou des peines sont\ndéterminées conformément aux dispositions des articles 6 et 25 du Code\npénal.\nLorsqu’il est proposé une p","[CPPN] Art. 380 : Le tribunal correctionnel est présidé par le président du tribunal\nou l’un des juges. Les fonctions du ministère public sont exercées par le\nprocureur ou l’un de ses substituts; toutefois dans les tribunaux d’instance\nla présence d’un magistrat du ministère public n’est pas obligatoire; les\nfonctions du greffe sont exercées par un greffier du tribunal de grande\ninstance ou d’instance.","[CPPN] Art. 381 : Le nombre des audiences correctionnelles est déterminé à la\nfin de chaque année judiciaire pour l’année judiciaire suivante par arrêté\ndu garde des sceaux, ministre de la justice.\nIl peut être modifié dans les mêmes conditions en cours d’année, suivant\nles nécessités.\n\nSection III : Des audiences foraines","[CPPN] Art. 385 : (abrogé)\nSection IV : De la publicité et de la police de l’audience","[CPPN] Art. 386 : Les audiences sont publiques.\nNéanmoins, le tribunal peut, en constatant dans son jugement que la publicité\nest dangereuse pour l’ordre ou les mœurs, ordonner, par jugement rendu\nen audience publique, que les débats auront lieu à huis-clos.\nLorsque l’huis-clos a été ordonné, celui-ci s’applique au prononcé des\njugements séparés qui peuvent intervenir sur des incidents ou exceptions\nainsi qu’il est dit à l’article 445, alinéa 4.\nLe jugement sur le fond doit toujours être prononcé en audience publique.","[CPPN] Art. 387 : Le président a la police de l’audience et la direction des débats.","[CPPN] Art. 388 : Le président peut interdire l’accès de la salle d’audience aux\nmineurs ou à certains d’entre eux.","[CPPN] Art. 389 : L’emploi de tout appareil d’enregistrement ou de diffusion sonore,\nde caméra de télévision ou de cinéma, d’appareils photographiques, peut\nêtre autorisé par le président.","[CPPN] Art. 390 : Lorsque, à l’audience, l’un des assistants trouble l’ordre de\nquelque manière que ce soit, le président ordonne son expulsion de la salle\nd’audience.\nSi au cours de l’exécution de cette mesure, il résiste à cet ordre ou cause\ndu tumulte, il est, sur-le-champ, placé sous mandat de dépôt, jugé et puni\nd’un emprisonnement de deux mois à deux ans, sans préjudice des peines\nportées au code pénal contre les auteurs d’outrages et de violences envers\nles magistrats.\nSur l’ordre du président, il est alors contraint par la force publique de quitter\nl’audience.\n\nCode de procédure pénale","[CPPN] Art. 391 : Si l’ordre est troublé à l’audience par le prévenu lui-même, il lui\nest fait application des dispositions de l’article 390.\nLe prévenu, même libre, lorsqu’il est expulsé de la salle d’audience, est\ngardé par la force publique, jusqu’à la fin des débats, à la disposition du\ntribunal; il est alors reconduit à l’audience où le jugement est rendu en sa\nprésence.\nSection V : Des débats\nParagraphe premier : DE LA COMPARUTION DU PREVENU","[CPPN] Art. 392 : Le président constate l’identité du prévenu et donne connaissance\nde l’acte qui a saisi le tribunal. Il constate aussi, s’il y a lieu, la présence ou\nl’absence de la personne civilement responsable, de la partie civile, des\ntémoins, des experts et des interprètes.","[CPPN] Art. 393 : Dans le cas où le prévenu ne parle pas suffisamment la langue\nfrançaise ou s’il est nécessaire de traduire un document versé aux débats,\net à défaut d’un interprète assermenté, le président désigne d’office un\ninterprète, âgé de vingt et un ans au moins, et lui fait prêter serment de\nremplir fidèlement sa mission.\nLe ministère public, le prévenu et la partie civile peuvent récuser l’interprète\nen motivant leur récusation. Le tribunal se prononce sur cette récusation,\net sa décision n’est susceptible d’aucune voie de recours.\nL’interprète ne peut, même du consentement du président ou du ministère\npublic, être pris parmi les juges composant les tribunaux, les greffiers\nd’audience, les parties et les témoins.","[CPPN] Art. 394 : Si le prévenu est sourd-muet et ne sait pas écrire, le président\nnomme d’office, en qualité d’interprète, la personne qui a le plus l’habitude\nde converser avec lui.\nLes autres dispositions du précédent article sont applicables.\nDans le cas où le prévenu visé au présent article sait écrire, le greffier\nécrit les questions ou observations qui lui sont faites; elles sont remises au\nprévenu, qui donne par écrit ses réponses. Il est fait lecture du tout par le\ngreffier.\n\nCode de procédure pénale","[CPPN] Art. 395 : Au jour indiqué pour la comparution à l’audience, le prévenu en\nétat de détention y est conduit par la force publique.","[CPPN] Art. 396 : (Loi n° 63-43 du 10 juillet 1963). Le prévenu régulièrement\ncité à personne doit comparaître, à moins qu’il ne fournisse une excuse\nreconnue valable par la juridiction devant laquelle il est appelé.\nLe prévenu a la même obligation lorsqu’il est établi que bien que n’ayant\npas été cité à personne, il a eu connaissance de la citation régulière le\nconcernant dans le cas prévu par l’article 556.\nSi ces conditions sont remplies, le prévenu non comparant et non excusé\nest jugé contradictoirement.","[CPPN] Art. 397 : Toute mention inexacte dans les exploits de citation est passible\ndes peines prévues au code pénal pour faux en écriture publique.","[CPPN] Art. 398 : Le prévenu cité pour une infraction passible d’une peine\nd’amende ou d’une peine d’emprisonnement inférieure à trois années peut,\npar lettre adressée au président et qui sera jointe au dossier de la procédure,\ndemander à être jugé en son absence.\nDans ce cas, il peut être représenté par son conseil.\nToutefois, si le tribunal estime nécessaire la comparution du prévenu en\npersonne, il est procédé à la réassignation du prévenu, à la diligence du\nministère public, pour audience dont la date est fixée par le tribunal.\nLe prévenu qui ne répondrait pas à cette invitation est jugé\ncontradictoirement.\nIl est également jugé contradictoirement dans le cas prévu par le premier\nalinéa du présent article.","[CPPN] Art. 399 : Si la citation n’a pas été délivrée à la personne du prévenu et\ns’il n’est pas établi qu’il ait eu connaissance de la citation, la décision, au\ncas de non-comparution du prévenu, est rendue par défaut.","[CPPN] Art. 400 : Nul n’est recevable à déclarer qu’il fait défaut dès lors qu’il\nest présent au début de l’audience.","[CPPN] Art. 401 : Les dispositions de l’article 398 alinéas 1 et 2, sont applicables\nchaque fois que le débat sur le fond de la prévention ne doit pas être abordé,\net spécialement quand le débat ne doit porter que sur les intérêts civils.\n\nCode de procédure pénale","[CPPN] Art. 402 : La personne civilement responsable peut toujours se faire\nreprésenter par un avocat. Dans ce cas, le jugement est contradictoire à\nson égard.","[CPPN] Art. 403 : Si le prévenu ne peut, en raison de son état de santé, comparaître\ndevant le tribunal et s’il existe des raisons graves de ne point différer le\njugement de l’affaire, le tribunal ordonne, par décision spéciale et motivée,\nque le prévenu, éventuellement assisté de son conseil, sera entendu à son\ndomicile ou à l’établissement pénitentiaire dans lequel il se trouve détenu,\npar un magistrat commis à cet effet, accompagné d’un greffier. Procèsverbal est dressé de cet interrogatoire. Le débat est repris après citation\nnouvelle du prévenu, et les dispositions de l’article 398 alinéas 1 et 2, sont\napplicables, quel que soit le taux de la peine encourue. Dans tous les cas, le\nprévenu est jugé contradictoirement à la formation sanitaire où il est\nadmis.","[CPPN] Art. 404 : Le prévenu qui comparaît a la faculté de se faire assister\npar son avocat-défenseur. Le défenseur ne peut être choisi que parmi les\navocats inscrits au Niger.\nLes avocats inscrits à d’autres barreaux peuvent plaider devant les\njuridictions du Niger si l’Etat dont ils sont originaires est lié au Niger par\nune convention de réciprocité.\nL’assistance d’un conseil est obligatoire quand le prévenu est atteint d’une\ninfirmité de nature à compromettre sa défense, ou quand il est en état de\nminorité pénale. A défaut de choix par le prévenu, ce conseil est désigné par\nle président du tribunal. Ce conseil est choisi soit parmi les avocats-défenseurs,\nsoit parmi les fonctionnaires figurant sur une liste dressée au début de chaque\nannée judiciaire par le garde des sceaux, ministre de la justice.\nParagraphe 2 : DE LA CONSTITUTION DE LA PARTIE CIVILE ET\nDE SES EFFETS","[CPPN] Art. 405 : Toute personne qui, conformément à l’article 2, prétend avoir\nété lésée par un délit peut, si elle ne l’a déjà fait, se constituer partie civile\nà l’audience même.\nLe ministère d’un avocat-défenseur n’est pas obligatoire.\nLa partie civile peut, à l’appui de sa constitution, demander des dommagesintérêts correspondant au préjudice qui lui a été causé.\n\nCode de procédure pénale","[CPPN] Art. 406 : La déclaration de constitution de partie civile se fait soit avant\nl’audience au greffe, soit pendant l’audience par déclaration consignée par\nle greffier ou par dépôt de conclusions.","[CPPN] Art. 407 : Lorsqu’elle est faite avant l’audience, la déclaration de partie\ncivile doit préciser l’infraction poursuivie et contenir élection de domicile\nau siège du tribunal saisi, à moins que la partie civile n’y soit domiciliée.\nElle est immédiatement transmise par le greffier au ministère public qui\ncite la partie civile pour l’audience.","[CPPN] Art. 408 : A l’audience, la déclaration de partie civile doit, à peine\nd’irrecevabilité, être faite avant les réquisitions du ministère public sur le fond.","[CPPN] Art. 409 : La personne qui s’est constituée partie civile ne peut plus être\nentendue comme témoin.","[CPPN] Art. 410 : Le tribunal apprécie la recevabilité de la constitution de partie\ncivile et, s’il échet, déclare cette constitution irrecevable.\nL’irrecevabilité peut également être soulevée par le ministère public, le\nprévenu, le civilement responsable ou une autre partie civile.","[CPPN] Art. 411 : La partie civile peut toujours se faire représenter par un avocat.\nDans ce cas, le jugement est contradictoire à son égard.","[CPPN] Art. 412 : (Loi n° 63-16 du 21 février 1963). La partie civile\nrégulièrement citée qui ne comparaît pas ou n’est pas représentée à\nl’audience est jugée par défaut.","[CPPN] Art. 413 : Le désistement de la partie civile ne met pas obstacle à l’action\ncivile devant la juridiction compétente.\nParagraphe III : DE L’ADMINISTRATION DE LA PREUVE","[CPPN] Art. 414 : Hors les cas où la loi en dispose autrement, les infractions\npeuvent être établies par tout mode de preuve et le juge décide d’après son\nintime conviction.\nLe juge ne peut fonder sa décision que sur des preuves qui lui sont apportées\nau cours des débats et contradictoirement discutées devant lui.","[CPPN] Art. 415 : L’aveu, comme tout élément de preuve, est laissé à la libre\nappréciation des juges.\n\nCode de procédure pénale","[CPPN] Art. 416 : Tout procès-verbal ou rapport n’a de valeur probante que s’il\nest régulier en la forme, si son auteur a agi dans l’exercice de ses fonctions\net a rapporté sur une matière de sa compétence ce qu’il a vu, entendu ou\nconstaté personnellement.","[CPPN] Art. 417 : Sauf dans les cas où la loi en dispose autrement, les procèsverbaux et les rapports constatant les délits ne valent qu’à titre de simples\nrenseignements.","[CPPN] Art. 418 : Dans les cas où les officiers de police judiciaire, les agents de\npolice judiciaire ou les fonctionnaires et agents chargés de certaines\nfonctions de police judiciaire ont reçu d’une disposition spéciale de la loi le\npouvoir de constater des délits par des procès-verbaux ou des rapports, la\npreuve ne peut être rapportée que par écrit ou par témoins.","[CPPN] Art. 419 : La preuve par écrit ne peut résulter de la correspondance\néchangée entre le prévenu et son conseil.","[CPPN] Art. 420 : Les matières donnant lieu à des procès-verbaux faisant foi\njusqu’à inscription de faux sont réglées par des lois spéciales. A défaut de\ndisposition expresse, la procédure de l’inscription de faux est réglée comme\nil est dit au titre premier du livre IV.","[CPPN] Art. 421 : Si le tribunal estime qu’une expertise est nécessaire, il est procédé\nconformément aux articles 149 à 160.","[CPPN] Art. 422 : Les témoins sont cités ainsi qu’il est dit aux articles 546 et\nsuivants.","[CPPN] Art. 423 : Après avoir procédé aux constatations prévues à l’article 392,\nle président ordonne aux témoins de se retirer dans la Chambre qui leur est\ndestinée. Ils n’en sortent que pour déposer. Le président prend, s’il en est\nbesoin, toutes mesures utiles pour empêcher les témoins de conférer entre\neux avant leur déposition.","[CPPN] Art. 424 : Toute personne citée pour être entendue comme témoin est\ntenue de comparaître, de prêter serment et de déposer.","[CPPN] Art. 425 : Le témoin qui ne comparaît pas ou qui refuse, soit de prêter\nserment, soit de faire sa déposition, peut être, sur réquisitions du ministère\npublic, condamné par le tribunal à la peine portée à l’article 104.\n\nCode de procédure pénale","[CPPN] Art. 426 : Si le témoin ne comparaît pas, et s’il n’a pas fait valoir un motif\nd’excuse reconnu valable et légitime, le tribunal peut, sur réquisitions du\nministère public ou même d’office, ordonner que ce témoin soit\nimmédiatement amené devant lui par la force publique pour y être entendu,\nou renvoyer l’affaire à une prochaine audience.\nEn ce dernier cas, tous les frais de citation, d’actes, de voyage de témoins\net autres, ayant pour objet de faire juger l’affaire, sont, hors le cas d’excuse\nlégitime, à la charge de ce témoin. Sur la réquisition du ministère public, le\njugement qui ordonne le renvoi des débats le condamne, même par corps,\nau payement de ces frais.","[CPPN] Art. 427 : Le témoin qui a été condamné à une amende ou aux frais pour\nnon comparution peut, au plus tard dans les cinq jours de la signification de\ncette décision faite à sa personne ou à son domicile, former opposition.\nLa voie d’appel ne lui est ouverte que sur le jugement rendu sur cette\nopposition.","[CPPN] Art. 428 : Le témoin qui a été condamné pour refus de prêter serment ou\nde déposer peut interjeter appel.","[CPPN] Art. 429 : Avant de procéder à l’audition des témoins, le président interroge\nle prévenu et reçoit ses déclarations. Le ministère public, ainsi que la partie\ncivile et la défense, celles-ci par intermédiaire du président, peuvent lui\nposer des questions.","[CPPN] Art. 430 : Lorsqu’un témoin est sourd-muet ou ne parle pas suffisamment\nla langue française, les dispositions des articles 393 et 394 sont applicables.","[CPPN] Art. 431 : Les témoins déposent ensuite séparément.\nParmi les témoins cités, ceux qui sont produits par les parties poursuivantes\nsont entendus les premiers, sauf pour le président à régler lui-même\nsouverainement l’ordre d’audition des témoins.\nPeuvent également, avec l’autorisation du tribunal, être admises à témoigner,\nles personnes, proposées par les parties, qui sont présentes à l’ouverture\ndes débats sans avoir été régulièrement citées.","[CPPN] Art. 432 : (Loi n° 66-18 du 29 mars 1966). Les témoins doivent, sur la\ndemande du président, faire connaître leur nom, prénoms, âge, profession\n\net domicile, s’ils sont parents ou alliés du prévenu, de la personne civilement\nresponsable ou de la partie civile et s’ils sont à leur service.\nLe cas échéant, le président leur fait préciser quelles relations ils ont, ou\nont eues, avec le prévenu, la personne civilement responsable ou la partie\ncivile.","[CPPN] Art. 433 : Avant de commencer leur déposition, les témoins prêtent serment\nde dire toute la vérité, rien que la vérité.\nLes enfants au-dessous de l’âge de seize ans sont entendus sans prestation\nde serment.","[CPPN] Art. 434 : Sont reçues dans les mêmes conditions les dépositions :\n1) du père, de la mère ou de tout autre ascendant du prévenu ou de l’un\ndes prévenus présents et impliqués dans la même affaire;\n2) du fils, de la fille ou de tout autre descendant;\n3) des frères et sœurs;\n4) des alliés aux mêmes degrés;\n5) du mari, ou de la femme; cette prohibition subsiste même après le\ndivorce.","[CPPN] Art. 435 : Toutefois, les personnes visées aux articles 433, alinéa 2 et 434\npeuvent être entendues sous serment lorsque ni le ministère public ni aucune\ndes parties ne s’y sont opposés.","[CPPN] Art. 436 : Le témoin qui a prêté serment n’est pas tenu de le renouveler,\ns’il est entendu une seconde fois au cours des débats.\nLe président lui rappellera, s’il y a lieu, le serment qu’il a prêté.","[CPPN] Art. 437 : La personne qui, agissant en vertu d’une obligation légale ou de\nsa propre initiative, a porté les faits poursuivis à la connaissance de la\njustice, est reçue en témoignage, mais le président en avertit le tribunal.\nCelui dont la dénonciation est récompensée pécuniairement par la loi peut\naussi être entendu en témoignage, à moins qu’il n’y ait opposition d’une\ndes parties, ou du ministère public.\n\nCode de procédure pénale","[CPPN] Art. 438 : Les témoins déposent oralement.\nToutefois, ils peuvent, exceptionnellement, s’aider de documents avec\nl’autorisation du président.","[CPPN] Art. 439 : Le greffier tient note au plumitif d’audience du déroulement\ndes débats et principalement, sous la direction du président, des déclarations\ndes témoins ainsi que des réponses du prévenu.\nLe plumitif est signé par le greffier. Il est visé par le président, au plus tard\ndans les trois jours qui suivent chaque audience.","[CPPN] Art. 440 : Après chaque déposition, le président pose au témoin les questions\nqu’il juge nécessaires et, s’il y a lieu, celles qui lui sont proposées par les\nparties.\nLe témoin peut se retirer après sa déposition, à moins que le président n’en\ndécide autrement.\nLe ministère public, ainsi que la partie civile et le prévenu, peuvent demander,\net le président peut toujours ordonner, qu’un témoin se retire\nmomentanément de la salle d’audience après sa déposition, pour y être\nintroduit et entendu s’il y a lieu après d’autres dépositions avec ou sans\nconfrontation.","[CPPN] Art. 441 : Au cours des débats, le président fait, s’il est nécessaire,\nreprésenter au prévenu ou aux témoins les pièces à conviction et reçoit\nleurs observations.","[CPPN] Art. 442 : Le tribunal, soit d’office, soit à la demande du ministère public,\nde la partie civile ou du prévenu, peut ordonner tous transports utiles en\nvue de la manifestation de la vérité.\nLes parties et leurs conseils, sont appelés à y assister. Il est dressé procèsverbal de ces opérations.","[CPPN] Art. 443 : Si d’après les débats la déposition d’un témoin paraît fausse, le\nprésident, soit d’office, soit à la requête du ministère public ou de l’une des\nparties, fait consigner au plumitif d’audience les dires précis du témoin.\nIl peut enjoindre spécialement à ce témoin de demeurer à la disposition du\ntribunal, qui l’entendra à nouveau, s’il y a lieu.\n\nSi le jugement doit être rendu le jour même, le président peut également\nfaire garder ce témoin par la force publique dans ou hors la salle d’audience.\nAprès lecture du jugement sur le fond, le tribunal ordonne sa conduite\ndevant le procureur de la République qui requiert l’ouverture d’une\ninformation pour faux témoignage.\nIl est dressé séance tenante par le tribunal, après la lecture du jugement\nsur le fond, un procès-verbal des faits ou des dires d’où peut résulter le\nfaux témoignage.\nCe procès-verbal et une expédition des notes d’audience sont transmis\nsans délai au procureur de la République.\nParagraphe IV : DE LA DISCUTION PAR LES PARTIES","[CPPN] Art. 444 : Le procureur de la République prend, au nom de la loi, les\nréquisitions tant écrites qu’orales qu’il croit convenables au bien de la\njustice.\nDans le cas où des réquisitions écrites sont prises, mention en est faite\ndans les notes tenues par le greffier et le tribunal est tenu d’y répondre.","[CPPN] Art. 445 : Le prévenu, les autres parties et leurs conseils, peuvent déposer\ndes conclusions. Ces conclusions sont visées par le président et le greffier;\nce dernier mentionne ce dépôt au plumitif.\nLe tribunal qui est tenu de répondre aux conclusions ainsi régulièrement\ndéposées doit joindre au fond les incidents et exceptions dont il est saisi, et\ny statuer par un seul et même jugement en se prononçant en premier lieu\nsur l’exception et ensuite sur le fond.\n(Loi n° 70-9 du 17 mars 1970). Il ne peut en être autrement qu’au cas\nd’impossibilité absolue ou encore lorsqu’une décision immédiate sur l’incident\nou sur l’exception est commandée par une disposition qui touche à l’ordre\npublic.","[CPPN] Art. 446 : L’instruction à l’audience terminée, la partie civile est entendue\nen sa demande, le ministère public prend ses réquisitions, la personne\ncivilement responsable s’il y a lieu et le prévenu présentent leur défense.\n\nLa partie civile et le ministère public peuvent répliquer. Le prévenu ou son\nconseil auront toujours la parole les derniers.","[CPPN] Art. 447 : Si les débats ne peuvent être terminés au cours de la même\naudience, le tribunal fixe par inscription au plumitif le jour où ils seront\ncontinués.\nLes parties et les témoins non entendus, ou ceux qui ont été invités à rester\nà la disposition du tribunal, sont tenus de comparaître, sans aucune citation,\nà l’audience de renvoi.\nSection VI : Du jugement","[CPPN] Art. 448 : Le jugement est rendu soit à l’audience même à laquelle ont eu\nlieu les débats, soit à une date ultérieure.\nDans ce dernier cas, le président informe les parties présentes du jour où le\njugement sera prononcé.","[CPPN] Art. 449 : S’il y a lieu de procéder à un supplément d’information, le\ntribunal commet par jugement un de ses membres qui dispose des pouvoirs\nprévus aux articles 144 à 148.\nCe supplément d’information obéit aux règles édictées par les articles 112\nà 115.\nLe procureur de la République peut obtenir, au besoin par voie de réquisitions,\nla communication du dossier de la procédure à toute époque du supplément\nd’information, à charge de rendre les pièces dans les quarante-huit heures.","[CPPN] Art. 450 : Si le tribunal estime que le fait constitue un délit, il prononce la\npeine. Il statue, par le même jugement, sur l’action civile.\nIl a aussi la faculté, s’il ne peut se prononcer en l’état sur la demande en\ndommages-intérêts, d’accorder à la partie civile une provision exécutoire\nnonobstant opposition ou appel.","[CPPN] Art. 451 : Dans le cas visé à l’article 450, premier alinéa, s’il s’agit d’un\ndélit de droit commun et si la peine prononcée est au moins de six mois\nd’emprisonnement, le tribunal peut, par décision spéciale et motivée,\ndécerner mandat de dépôt ou d’arrêt contre le prévenu.\n\nLe mandat d’arrêt continue à produire son effet, même si le tribunal, sur\nopposition, ou la Cour sur appel, réduit la peine à moins de six mois\nd’emprisonnement.\nLe mandat de dépôt décerné par le tribunal produit également effet lorsque,\nsur appel, la Cour réduit la peine d’emprisonnement à moins de six mois.\n(Loi n° 69-5 du 18 février 1969). Toutefois, le tribunal, sur opposition, ou\nla cour, sur appel, a la faculté, par décision spéciale et motivée, de donner\nmain-levée de ces mandats.\nEn toutes circonstances, les mandats décernés dans les cas susvisés\ncontinuent à produire leur effet, nonobstant le pourvoi en cassation.\n(Loi n° 66-18 du 29 mars 1966). En cas d’opposition au jugement, dans\nles cas prévus par les articles 477 et 478, l’affaire doit venir devant le\ntribunal à la première audience ou au plus tard dans les 30 jours à dater de\nl’opposition, faute de quoi le prévenu doit être mis en liberté d’office.\nS’il y a lieu à remise, le tribunal doit statuer d’office par une décision motivée\nsur le maintien ou la main-levée du mandat, le ministère public entendu. Le\ntout sans préjudice de la faculté pour le prévenu de former une demande\nde mise en liberté provisoire dans les conditions prévues par les ","[CPPN] Art. 452 : Si le tribunal régulièrement saisi d’un fait qualifié délit par la loi,\nestime, au résultat des débats, que ce fait ne constitue qu’une contravention,\nil prononce la peine et statue, s’il y a lieu, sur l’action civile.","[CPPN] Art. 453 : Si le fait est une contravention connexe à un délit, le tribunal\nstatue par un seul et même jugement, à charge d’appel sur le tout.","[CPPN] Art. 454 : Si le prévenu bénéficie d’une excuse absolutoire, le tribunal\nprononce son absolution et statue, s’il y a lieu, sur l’action civile, ainsi qu’il\nest dit à l’article 450, alinéa 2.","[CPPN] Art. 455 : Si le fait déféré au tribunal correctionnel sous la qualification de\ndélit est de nature à entraîner une peine criminelle, le tribunal renvoie le\nministère public à se pourvoir ainsi qu’il avisera.\nIl peut, le ministère public entendu, décerner, par la même décision, mandat\nde dépôt ou d’arrêt contre le prévenu.\n\nCode de procédure pénale","[CPPN] Art. 456 : Si le tribunal estime que le fait poursuivi ne constitue aucune\ninfraction à la loi pénale, ou que le fait n’est pas établi, ou qu’il n’est pas\nimputable au prévenu, il renvoie celui-ci des fins de la poursuite.","[CPPN] Art. 457 : Est, nonobstant appel, mis en liberté, immédiatement après le\njugement, le prévenu détenu qui a été acquitté ou absous, ou condamné soit\nà l’emprisonnement avec sursis, soit à l’amende.\nIl en est de même du prévenu détenu condamné à une peine\nd’emprisonnement aussitôt que la durée de la détention aura atteint celle\nde la peine prononcée sous réserve de l’application de l’article 490.","[CPPN] Art. 458 : Dans le cas prévu à l’article 456, lorsque la partie civile a ellemême mis en mouvement l’action publique, le tribunal statue par le même\njugement sur la demande en dommages-intérêts formée par la personne\nacquittée contre la partie civile.","[CPPN] Art. 459 : Tout jugement de condamnation rendu contre le prévenu et\néventuellement contre la partie civilement responsable les condamne aux\nfrais et dépens envers l’Etat. Il se prononce à l’égard du prévenu sur la\ndurée de la contrainte par corps.\nIl en est de même au cas de transaction ayant éteint l’action publique,\nconformément à l’article 6, au cas d’absolution, sauf si le tribunal, par\ndécision spéciale et motivée, décharge le prévenu et la personne civilement\nresponsable de tout ou partie des frais.\nLa partie civile dont l’action a été déclarée recevable n’est pas tenue des\nfrais dès lors que l’individu contre lequel elle s’est constituée a été reconnu\ncoupable d’une infraction.","[CPPN] Art. 460 : Au cas d’acquittement, le prévenu ne peut être condamné aux\nfrais du procès. Toutefois, si le prévenu est acquitté à raison de son état de\ndémence au moment des faits, le tribunal peut mettre à sa charge tout ou\npartie des dépens.","[CPPN] Art. 461 : (Loi n° 66-18 du 29 mars 1966). La partie civile qui succombe\nest tenue des frais.\nLe tribunal peut, toutefois, par décision spéciale et motivée, l’en décharger\nen tout ou partie.\n\nCode de procédure pénale","[CPPN] Art. 462 : Dans le cas où la condamnation n’intervient pas pour toutes les\ninfractions qui ont\nfait l’objet de la poursuite ou n’intervient qu’à raison d’infractions qui ont\nfait l’objet d’une disqualification, soit au cours de l’instruction, soit au moment\ndu prononcé du jugement, comme aussi dans le cas de mise hors de cause\nde certains prévenus, le tribunal peut, par une disposition motivée, décharger\nle condamné de la part des frais de justice qui ne résulte pas directement\nde l’infraction ayant entraîné la condamnation au fond. Le tribunal fixe luimême le montant des frais dont est alors déchargé le condamné, ces frais\nétant laissés, selon les circonstances, à la charge du trésor ou de la partie\ncivile.","[CPPN] Art. 463 : Les frais et dépens sont liquidés par le jugement. A défaut de\ndécisions sur l’application des articles 459 et suivants ou en cas de difficultés\nd’exécution portant sur la condamnation aux frais et dépens, la juridiction\nqui a statué au fond peut être saisie par tout intéressé, conformément aux\nrègles établies en matière d’incidents d’exécution, et compléter son jugement\nsur ce point.","[CPPN] Art. 464 : Le prévenu, la partie civile ou la personne civilement responsable\npeut réclamer au tribunal saisi de la poursuite la restitution des objets placés\nsous la main de la justice.\nLe tribunal peut ordonner d’office cette restitution.","[CPPN] Art. 465 : Toute personne autre que le prévenu, la partie civile ou la\npersonne civilement responsable, qui prétend avoir droit sur des objets placés\nsous la main de la justice, peut également en réclamer la restitution au\ntribunal saisi de la poursuite.\nSeuls, les procès-verbaux relatifs à la saisie des objets peuvent lui être\ncommuniqués. Le tribunal statue par jugement séparé, les parties entendues.","[CPPN] Art. 466 : Si le tribunal accorde la restitution, il peut prendre toutes mesures\nconservatoires pour assurer jusqu’à la décision définitive sur le fond la\nreprésentation des objets restitués.","[CPPN] Art. 467 : Si le tribunal estime que les objets placés sous la main de la\njustice sont utiles à la manifestation de la vérité ou susceptibles de\nconfiscation, il surseoit jusqu’à sa décision sur le fond.\n\nDans ce cas, le jugement n’est susceptible d’aucun recours.","[CPPN] Art. 468 : Le jugement qui rejette une demande de restitution est susceptible\nd’appel de la part de la personne qui a formé cette demande.\nLe jugement qui accorde la restitution est susceptible d’appel de la part du\nministère public et de la part du prévenu, de la personne civilement\nresponsable, ou de la partie civile à qui cette décision ferait grief.\nLa Cour ne peut être saisie qu’après que le tribunal a statué au fond.","[CPPN] Art. 469 : Le tribunal qui a connu de l’affaire demeure compétent pour\nordonner la restitution des objets placés sous la main de la justice si aucune\nvoie de recours n’a été exercée contre le jugement sur le fond.\nIl statue sur requête de toute personne qui prétend avoir droit sur l’objet ou\nà la demande du ministère public.\nSa décision peut être déférée à la Cour d’appel, conformément aux\ndispositions de l’article 468.","[CPPN] Art. 470 : Lorsque la Cour d’appel est saisie du fond de l’affaire, elle est\ncompétente pour statuer sur les restitutions dans les conditions prévues par\nles articles 464 à 467.\nElle demeure compétente, même après décision définitive sur le fond, pour\nordonner la restitution dans les conditions prévues aux alinéas 1 et 2 de\nl’article 469.","[CPPN] Art. 471 : Tout jugement doit contenir des motifs et un dispositif. Les\nmotifs constituent la base de la décision.\nLe dispositif énonce les infractions dont les personnes citées sont déclarées\ncoupables ou responsables, ainsi que la peine, les textes de loi appliqués et\nles condamnations civiles.\nIl est donné lecture du jugement par le président.","[CPPN] Art. 472 : La minute du jugement est datée et mentionne le nom du magistrat\nqui l’a rendu; la présence du ministère public à l’audience doit y être\nconstatée, le cas échéant.\n\nAprès avoir été signée par le président et le greffier, la minute est déposée\nau greffe du tribunal dans les huit jours au plus tard du prononcé du\njugement. Ce dépôt est mentionné sur le registre spécialement tenu au\ngreffe à cet effet.\nSection VII : Du jugement par défaut et de l’opposition\nParagraphe premier : DU DEFAUT","[CPPN] Art. 473 : Sauf les cas prévus par les articles 396, 397,401, 402, 403 et\n411, toute personne régulièrement citée qui ne comparaît pas au jour et à\nl’heure fixés par la citation est jugée par défaut, ainsi qu’il est dit à l’article\n399.\nDans tous les cas, le tribunal est tenu de juger l’affaire à l’audience à\nlaquelle elle a été immédiatement renvoyée, quel que soit le mode de citation\ndes parties et des témoins.","[CPPN] Art. 474 : Le jugement prononcé par défaut est signifié par exploit\nd’huissier, conformément aux dispositions des articles 546 et suivants.\nParagraphe II : DE L’OPPOSITION","[CPPN] Art. 475 : Le jugement par défaut est non avenu dans toutes ses dispositions,\nsi le prévenu forme opposition à son exécution.\nIl peut toutefois limiter cette opposition aux dispositions civiles du jugement.","[CPPN] Art. 476 : L’opposition est notifiée par tous moyens utiles au ministère\npublic, à charge par lui d’en aviser la partie civile.\nDans le cas où l’opposition est limitée aux dispositions civiles du jugement,\nle prévenu doit adresser la notification directement à la partie civile.","[CPPN] Art. 477 : Si la signification du jugement a été faite à la personne du\nprévenu, l’opposition doit être formée dans les délais ci-après qui courent à\ncompter de cette signification : dix jours si le prévenu réside sur le territoire\nde la République, un mois dans les autres cas.","[CPPN] Art. 478 : Si la signification du jugement n’a pas été faite à la personne du\nprévenu, l’opposition doit être formée dans les délais ci-après, qui courent à\ncompter de la signification du jugement faite à domicile, à mairie ou à parquet :\ndix jours si le prévenu réside au Niger, un mois dans les autres cas.\n\n(Loi n° 63-43 du 10 juillet 1963). Toutefois, s’il ne résulte pas d’un acte\nquelconque que le prévenu a eu connaissance du jugement, l’opposition\nreste recevable jusqu’à l’expiration des délais de prescription de la peine,\nce, tant en ce qui concerne les intérêts civils que la condamnation pénale.\nDans les cas visés à l’alinéa précédent, le délai d’opposition court à compter\ndu jour où le prévenu a eu cette connaissance.","[CPPN] Art. 479 : La personne civilement responsable et la partie civile peuvent\nformer opposition à tout jugement par défaut à leur encontre, dans les\ndélais fixés à l’article 477, lesquels courent à compter de la signification du\njugement, quel qu’en soit le mode.\nParagraphe III : DE L’ITERATIF DEFAUT","[CPPN] Art. 480 : L’opposition est non avenue si l’opposant ne comparaît pas à\nla date qui lui est fixée soit par la notification à lui faite verbalement et\nconstatée par procès-verbal au moment où l’opposition a été formée, soit\npar une nouvelle citation, délivrée à l’intéressé, conformément aux\ndispositions des articles 546 et suivants.","[CPPN] Art. 481 : Dans tous les cas, les frais de la signification du jugement par\ndéfaut et de l’opposition peuvent être laissés à la charge de la partie opposante.\nCHAPITRE II : DE LA COUR D’APPEL EN MATIERE\nCORRECTIONNELLE\nSection 1 : De l’exercice du droit d’appel","[CPPN] Art. 482 : Les jugements rendus en matière correctionnelle peuvent être\nattaqués par la voie de l’appel.","[CPPN] Art. 483 : (Loi n° 70-9 du 17 mars 1970). Lorsque le tribunal statue par\njugement distinct du jugement sur le fond, l’appel est immédiatement\nrecevable si ce jugement met fin à la procédure.\nDans le cas contraire et jusqu’à l’expiration des délais d’appel, le jugement\nn’est pas exécutoire et le tribunal ne peut statuer au fond.\nSi l’appel n’a pas été interjeté ou si avant l’expiration du délai d’appel la\npartie appelante n’a pas déposé au greffe la requête prévue à l’alinéa\nsuivant, le jugement est exécutoire et le tribunal statue au fond.\n\nLa partie appelante peut déposer au greffe, avant l’expiration des délais\nd’appel, une requête adressée au président de la Cour d’appel et tendant à\nfaire déclarer l’appel immédiatement recevable.\nLe greffier avise le président du tribunal du dépôt de cette requête. Le\njugement n’est pas exécutoire et le tribunal ne peut statuer au fond tant\nqu’il n’a pas été prononcé sur ladite requête.\nDès que le greffier a reçu l’appel et la requête, il fait parvenir celle-ci au\nprésident de la Cour d’appel ainsi qu’une expédition du jugement et de\nl’acte d’appel.\nLe président statue sur la requête, par ordonnance non motivée, dans les\nhuit jours de la réception de ce dossier.\nS’il rejette la requête, le jugement est exécutoire et le tribunal se prononce\nau fond : aucun recours n’est recevable contre l’ordonnance du président\net l’appel n’est alors jugé qu’en même temps que l’appel formé contre le\njugement sur le fond.\nSi, dans l’intérêt de l’ordre publ","[CPPN] Art. 484 : L’appel est porté devant la Cour d’appel.","[CPPN] Art. 485:La faculté d’appeler appartient :\n1) au prévenu;\n2) à la personne civilement responsable;\n3) à la partie civile, quant à ses intérêts civils seulement;\n4) au procureur de la République;\n5) aux administrations publiques, dans les cas où celles-ci exercent l’action\npublique;\n6) au procureur général près la Cour d’appel.\n\nCode de procédure pénale","[CPPN] Art. 486 : (Loi n° 66-18 du 29 mars 1966). Sauf dans le cas prévu à\nl’article 495, l’appel est interjeté dans le délai de dix jours à compter du\nprononcé du jugement contradictoire.\nToutefois, le délai d’appel ne court qu’à compter de la signification du\njugement, quel qu’en soit le mode :\n1) pour la partie qui, après débat contradictoire, n’était pas présente ou\nreprésentée à l’audience où le jugement a été prononcé, mais seulement\ndans le cas où elle-même ou son représentant n’auraient pas été informés\ndu jour où le jugement serait prononcé;\n2) pour le prévenu qui n’a pas comparu, dans les conditions prévues par\nl’article 398 alinéas 4 et 5.\nIl en est de même dans le cas prévu à l’article 396.","[CPPN] Art. 487 : Toutefois, l’appel par le procureur de la République des jugements\nrendus par les tribunaux d’instance est recevable dans le délai de dix jours\nà compter du jour de la réception du compte-rendu d’audience à son parquet,\nsans que ce délai puisse excéder trois mois à compter du jour du prononcé\ndu jugement.\nEn tout état de cause, le juge qui a rendu la décision doit rédiger dans un\ndélai de 2 mois à compter de son prononcé sous peine de sanctions\ndisciplinaires, conformément au statut de la magistrature.","[CPPN] Art. 488 : Si le jugement est rendu par défaut ou par itératif défaut, le\ndélai d’appel ne court qu’à compter de la signification faite à personne, à\ndomicile, à mairie ou à parquet.\nToutefois, si la signification n’a pas été faite à personne et s’il ne résulte\npas d’un acte quelconque que le prévenu a eu connaissance du jugement,\nl’appel sera recevable dans le même délai que l’opposition.","[CPPN] Art. 489 : En cas d’appel d’une des parties pendant les délais ci-dessus,\nles autres parties ont un délai supplémentaire de cinq jours pour interjeter\nappel.","[CPPN] Art. 490 :\n\n(Abrogé)\n\nCode de procédure pénale","[CPPN] Art. 491 : Lorsque le tribunal statue sur une demande de mise en liberté\nprovisoire en conformité avec les articles 135 et 136, l’appel doit être formé\ndans un délai de vingt-quatre heures.\nLe prévenu détenu est maintenu en prison jusqu’à ce qu’il ait été statué sur\nl’appel du procureur de la République, et dans tous les cas jusqu’à\nl’expiration du délai de cet appel.","[CPPN] Art. 492 : La déclaration d’appel doit être faite au greffier de la juridiction\nqui a rendu la décision attaquée.\nElle doit être signée par le greffier et par l’appelant lui-même, ou par un\navocat-défenseur ou par un fondé de pouvoir spécial; dans ce dernier cas,\nle pouvoir est annexé à l’acte dressé par le greffier. Si l’appelant ne peut\nsigner, il en sera fait mention par le greffier.\nElle est inscrite sur un registre public à ce destiné et toute personne a le\ndroit de s’en faire délivrer une copie.\nEn ce qui concerne les jugements rendus par les sections de tribunaux et\nles justices de paix, le procureur de la République fait sa déclaration au\ngreffe de son tribunal qui en transmet expédition, sans délai, au greffe de la\njuridiction qui a statué.\nLorsque le jugement a été rendu en audience foraine, la déclaration d’appel\npourra être valablement effectuée par lettre recommandée. Le cachet du\nbureau postal d’émission fera foi de la date d’appel. Ce document est\ntranscrit sur le registre public tenu au greffe de la juridiction qui a rendu la\ndécision attaquée et est annexé à l’acte dressé par le greffier.","[CPPN] Art. 493 : Lorsque l’appelant est détenu, il peut également faire connaître\nsa volonté d’interjeter appel par une lettre qu’il remet au régisseur de la\nprison; ce dernier lui en délivre récépissé.\nLe régisseur certifie sur cette lettre même que celle-ci lui a été remise par\nl’intéressé, et il précise la date de la remise.\nCe document est transmis immédiatement au greffe de la juridiction qui a\nrendu la décision attaquée; il est transcrit sur le registre prévu par l’article\n492, alinéa 3 et est annexé à l’acte dressé par le greffier.\n\nCode de procédure pénale","[CPPN] Art. 494 : Une requête contenant les moyens d’appel peut être remise\ndans les délais prévus pour la déclaration d’appel au greffe du tribunal; elle\nest signée de l’appelant ou d’un avocat-défenseur ou d’un fondé de pouvoir\nspécial. Dans ce dernier cas, le pouvoir sera annexé à la requête.\nLa requête, ainsi que les pièces de la procédure, sont envoyées par le\nprocureur de la République au parquet de la Cour dans le plus bref délai.","[CPPN] Art. 495 : le procureur général forme son appel dans un délai de trois mois\nà compter du jour du prononcé du jugement, au greffe de la Cour d’appel\nqui en transmet expédition immédiatement au greffe de la juridiction qui a\nstatué.\nNotification doit être faite dans les mêmes conditions aux autres parties.","[CPPN] Art. 496 : (Loi n° 70-9 du 17 mars 1970). Pendant les délais d’appel et\ndurant l’instance d’appel, il est sursis à l’exécution du jugement, sous\nréserve des dispositions des articles 451, alinéas 2 et 3, 457, 483 et 651.","[CPPN] Art. 497 : (Alinéa 1, Loi n° 69-5 du 18 février 1969). L’affaire est\ndévolue à la Cour d’appel dans la limite fixée par l’acte d’appel et par la\nqualité de l’appelant ainsi qu’il est dit à l’article 504.\nLa Cour doit statuer dans les trois mois de la déclaration d’appel.\nSection II : De la composition de la Cour d’appel statuant en\nmatière correctionnelle","[CPPN] Art. 498 : La Cour d’appel statuant en matière correctionnelle est composée\ndu président et de deux conseillers.\nLes fonctions du ministère public sont exercées par le procureur général\nou par son substitut ; celles du greffe par un greffier de la Cour d’appel.","[CPPN] Art. 499 : Le nombre des audiences correctionnelles est déterminé à la\nfin de chaque année judiciaire pour l’année suivante par arrêté du garde\ndes sceaux, ministre de la justice.\nIl peut être modifié dans les mêmes conditions, en cours d’année, suivant\nles nécessités.\n\nSection III : De la procédure devant la Cour d’appel statuant en\nmatière correctionnelle","[CPPN] Art. 500 : Les règles édictées pour le tribunal correctionnel sont applicables\ndevant la Cour d’appel sous réserve des dispositions suivantes.","[CPPN] Art. 501 : (Loi n° 66-18 du 29 mars 1966). Les prévenus en état de\ndétention préventive en dehors du siège de la Cour d’appel, appelants ou\nintimés sont jugés sur pièces, à moins que la Cour n’estime leur présence\nindispensable.\nIls reçoivent notification de la date d’audience et ils ont la faculté de se\nfaire représenter par un avocat défenseur ou de produire un mémoire.\nLes prévenus en liberté, appelants ou intimés, qui résident en dehors du\nsiège de la cour, ont la faculté de déclarer qu’ils renoncent à comparaître.\nCette déclaration est faite par les appelants au greffier qui en fait mention\nà l’acte d’appel et, pour les intimités, à l’huissier qui leur délivre la citation.\nLe greffier et l’huissier sont tenus de les interpeller à ce sujet et de\nmentionner à l’acte la réponse faite. Ils ont la faculté de se faire représenter\npar un avocat défenseur ou de produire un mémoire.\nToutefois, si la Cour estime leur comparution nécessaire, il est procédé\ncomme il est dit à l’article 398 alinéas 3 et 4.\nDans les actes prévus au présent article, les prévenus sont jugés\ncontradictoirement, mais l’arrêt leur est signifié.","[CPPN] Art. 502 : L’appel est jugé à l’audience sur le rapport oral d’un conseiller;\nle prévenu est interrogé.\nLes témoins ne sont entendus que si la Cour a ordonné leur audition. Les\nparties en cause ont la parole dans l’ordre suivant : d’abord les parties\nappelantes, puis les parties intimées; s’il y a plusieurs parties appelantes ou\nintimées, elles sont entendues dans l’ordre fixé par le président.\nLe prévenu ou son conseil auront toujours la parole les derniers.","[CPPN] Art. 503 : Si la Cour estime que l’appel est tardif ou irrégulièrement formé,\nelle le déclare irrecevable.\n\nSi elle estime que l’appel, bien que recevable n’est pas fondé, elle confirme\nle jugement attaqué.\nDans les deux cas, elle condamne l’appelant aux dépens, à moins que\nl’appel n’émane du ministère public, les dépens étant alors laissés à la\ncharge du trésor.","[CPPN] Art. 504 : La Cour peut, sur l’appel du ministère public, soit confirmer le\njugement, soit l’infirmer en tout ou en partie dans un sens favorable ou\ndéfavorable au prévenu.\nLa Cour ne peut, sur le seul appel du prévenu ou du civilement responsable,\naggraver le sort de l’appelant.\nElle ne peut, sur le seul appel de la partie civile, modifier le jugement dans\nun sens défavorable à celle-ci.\nLa partie civile ne peut, en cause d’appel, former aucune demande nouvelle;\ntoutefois elle peut demander une augmentation des dommages-intérêts pour\nle préjudice souffert depuis la décision de première instance.\nSi la Cour d’appel prononce une peine d’emprisonnement, elle décerne\nmandat de dépôt ou d’arrêt contre le prévenu.\nCes mandats produiront effet nonobstant pourvoi en cassation.","[CPPN] Art. 505 : Si le jugement est réformé parce que la Cour estime qu’il n’y a\nni crime, ni délit, ni contravention, ou que le fait n’est pas établi ou qu’il\nn’est pas imputable au prévenu, elle renvoie celui-ci des fins de la poursuite.\nDans ce cas, si le prévenu acquitté demande, des dommages-intérêts, dans\nles conditions prévues à l’article 458, il porte directement sa demande devant\nla Cour d’appel.","[CPPN] Art. 506 : Si le jugement est réformé parce que la Cour estime que le\nprévenu bénéficie d’une excuse absolutoire, elle se conforme aux dispositions\nde l’article 454.","[CPPN] Art. 507 : Si le jugement est annulé parce que la Cour estime que le fait ne\nconstitue qu’une contravention, elle prononce la peine et statue, s’il y a\nlieu, sur l’action civile.\n\nCode de procédure pénale","[CPPN] Art. 508 : Si le jugement est annulé parce que la Cour estime que le fait\nest de nature à entraîner une peine criminelle, la Cour d’appel se déclare\nincompétente. Elle renvoie le ministère public à se pourvoir ainsi qu’il avisera.\nElle peut, le ministère public entendu, décerner par la même décision, mandat\nde dépôt ou d’arrêt contre le prévenu.","[CPPN] Art. 509 : Si le jugement est annulé pour violation ou omission non réparée\nde formes prescrites par la loi à peine de nullité, la Cour évoque et statue\nsur le fond.","[CPPN] Art. 510 : En matière de défaut, les dispositions des articles 473 à 481\nsont applicables devant la Cour d’appel.\nTITRE III : DU JUGEMENT DES CONTRAVENTIONS\nCHAPITRE PREMIER : DE LA COMPETENCE DU\nTRIBUNAL DE SIMPLE POLICE","[CPPN] Art. 511 : Le tribunal de simple police connaît des contraventions.","[CPPN] Art. 512 : La connaissance des contraventions est attribuée exclusivement\nau tribunal de simple police du ressort dans l’étendue duquel elles ont été\ncommises.\nLes articles 364 à 368 sont applicables au jugement des infractions de la\ncompétence du tribunal de simple police.","[CPPN] Art. 513 : Le tribunal de simple police est constitué par le président de la\njuridiction d’instance, un magistrat du ministère public et un greffier. Dans\nles sections de tribunaux et les justices de paix, la présence du ministère\npublic est facultative.\nCHAPITRE II : DE L’AMENDE FORFAITAIRE","[CPPN] Art. 514 : En toutes matières, lorsqu’une contravention passible d’une\namende dont le montant minimum n’excède pas 50.000 frs est constatée\npar un agent verbalisateur spécialement habilité, le contrevenant a la faculté\nd’effectuer immédiatement entre les mains de cet agent le payement d’une\namende forfaitaire.\n\nCode de procédure pénale","[CPPN] Art. 515 : Les dispositions qui précèdent ne s’appliquent pas :\n1) si la contravention constatée expose son auteur, soit à la réparation de\ndommages causés aux personnes ou aux biens, soit aux peines qui s’attachent\nà la récidive;\n2) si l’infraction constatée est connexe à un délit ou à un crime;\n3) si la contravention est prévue et réprimée par la législation des eaux et\nforêts ou par le code du travail, ainsi que dans les cas où une législation\nparticulière a exclu la procédure de l’amende forfaitaire.","[CPPN] Art. 516 : Le montant de l’amende forfaitaire est fixé au minimum prévu\npar le texte applicable.","[CPPN] Art. 517 : Le versement de l’amende forfaitaire a pour effet d’éteindre l’action\npublique. Toutefois, lorsque l’agent verbalisateur ignorait la qualité de récidiviste\ndu contrevenant ou lorsqu’une peine d’emprisonnement est également encourue,\nle paiement reste valable, mais le contrevenant peut être poursuivi\nultérieurement devant le tribunal de simple police; en ce cas, l’amende déjà\npayée s’impute sur celle à laquelle il pourra être condamné. Elle lui est restituée\nau vu d’un ordre donné par le ministère public s’il est relaxé.\nL’agent verbalisateur est tenu de délivrer au contrevenant une quittance\ndétachée d’un carnet à souche conforme à un modèle règlementaire.","[CPPN] Art. 518 : En matière de circulation routière, lorsque l’auteur de l’infraction,\ndomicilié hors du territoire de la République du Niger, refuse de payer\nl’amende forfaitaire, le véhicule ayant servi à commettre la contravention\nest placé en fourrière et les frais en résultant sont mis à sa charge.","[CPPN] Art. 519 : Les agents verbalisateurs habilités à la perception des amendes\nforfaitaires sont :\n1) les officiers de police judiciaire;\n2) (Loi n° 66-18 du 29 mars 1966). Les agents de police judiciaire désignés\nnominativement par le garde des sceaux, ministre de la justice, sur proposition\ndu ministre dont ils relèvent;\n3) les agents assermentés de certaines administrations désignés\nnominativement par le garde des sceaux, ministre de la justice, sur proposition\ndu ministre dont relèvent ces administrations.\n\nCHAPITRE III : DE L’AMENDE DE COMPOSITION","[CPPN] Art. 520 : Sauf le cas de paiement de l’amende forfaitaire, l’agent\nverbalisateur rédige un procès-verbal dans les formes légales.\nCe procès-verbal est transmis au parquet compétent.","[CPPN] Art. 521 : Le procès-verbal constatant l’infraction est soumis au juge de\nsimple police qui, dans une ordonnance rendue sans frais, fixe la somme\nque le contrevenant a la faculté de payer à titre d’amende de composition.\nNéanmoins si ce magistrat considère qu’une peine pécuniaire est\ninsuffisante, il refuse à l’auteur de l’infraction le bénéfice de l’amende\ntransactionnelle. Il est alors procédé conformément aux dispositions des\narticles 527 et suivants.","[CPPN] Art. 522 : (Loi n° 66-18 du 29 mars 1966). L’ordonnance déterminant\nle montant de l’amende de composition n’est susceptible de recours que\ndans les conditions prévues par l’article 542 alinéa 5. Elle est notifiée par le\nministère public au contrevenant qui est libre d’y acquiescer ou non.\nS’il acquiesce, il verse le montant de l’amende entre les mains d’un des\nagents énumérés en l’article 519, lequel délivre quittance, opère la mention\ndu paiement sur le procès-verbal et l’adresse au parquet compétent pour\nclassement au greffe.\nSi les recherches faites en vue de découvrir le contrevenant n’ont pas\nabouti, ce dernier est traduit devant le tribunal de simple police dans les\nformes ordinaires.","[CPPN] Art. 523 : Si le contrevenant verse le montant de l’amende de composition,\nl’action publique est éteinte.\nLe payement de l’amende implique la reconnaissance de l’infraction.\nIl tient lieu de premier jugement pour la détermination de l’état de récidive.","[CPPN] Art. 524 : Si le contrevenant ne paie pas l’amende pour quelque motif que\nce soit, il est traduit devant le tribunal de simple police suivant la procédure\nordinaire. La décision qui est rendue est réputée contradictoire, même en\ncas de défaut et quel que soit le mode de citation.\nTout contrevenant, qui a été condamné, a la faculté d’acquitter, dans les cinq\njours qui suivent la condamnation, le montant de l’amende et des frais à sa charge.\nLe payement a lieu entre les mains du greffier de la juridiction qui a statué.\n\nCode de procédure pénale","[CPPN] Art. 525 : Il est tenu, au parquet de chaque tribunal de simple police, un\nregistre spécial où sont mentionnés, pour chaque contravention, la nature\net la date de la décision, le montant de l’amende prononcée, et, s’il y a lieu,\nle recouvrement effectué dans les conditions sus-indiquées.","[CPPN] Art. 526 : (Loi n° 69-5 du 18 février 1969). Les dispositions des articles\n521 à 525 ne sont pas applicables si la contravention constatée expose son\nauteur, soit à la réparation de dommages causés aux personnes ou aux\nbiens, soit aux peines qui s’attachent à la récidive, de même que dans les\ncas prévus à l’article 515 alinéas 2 et 3.\nCHAPITRE IV : DE LA SAISINE DU TRIBUNAL DE SIMPLE POLICE","[CPPN] Art. 527 : Le tribunal de simple police est saisi des infractions de sa\ncompétence soit par le renvoi qui lui en est fait par la juridiction d’instruction,\nsoit par la comparution volontaire des parties, soit par la citation délivrée\ndirectement au prévenu et à la personne civilement responsable de l’infraction.","[CPPN] Art. 528 : L’avertissement délivré par le ministère public dispense de\ncitation s’il est suivi de la comparution volontaire de la personne à laquelle\nil est adressé.\nIl indique l’infraction poursuivie et vise le texte de loi qui la réprime.","[CPPN] Art. 529 : Les articles 371 à 373 sont applicables à la procédure devant le\ntribunal de simple police.\nCHAPITRE V : DE L’INSTRUCTION DEFINITIVE DEVANT\nLE TRIBUNAL DE SIMPLE POLICE","[CPPN] Art. 530 : Avant le jour de l’audience, le président peut, sur la requête du\nministère public ou de la partie civile, estimer ou faire estimer les dommages,\ndresser ou faire dresser des procès-verbaux, faire ou ordonner tous les\nactes requérant célérité.","[CPPN] Art. 531 : Les dispositions des articles 386 à 391, 392 à 394, sont applicables\nà la procédure devant le tribunal de simple police.\nToutefois, les sanctions prévues par l’article 390, alinéa 2, ne peuvent être\nprononcées que par le tribunal correctionnel, saisi par le ministère public, au vu\ndu procès-verbal dressé par le juge du tribunal de simple police relatant l’incident.\n\nCode de procédure pénale","[CPPN] Art. 532 : (Loi n° 69-5 du 18 février 1969). Sont également applicables\nles règles édictées par les articles 405 à 413 concernant la constitution de\npartie civile; par les articles 414 à 443 relatifs à l’administration de la preuve\nsous réserve de ce qui est dit à l’article 533 ; par les articles 444 à 447\nconcernant la discussion par les parties; par l’article 448 relatif au jugement.","[CPPN] Art. 533 : Les contraventions sont prouvées soit par procès-verbaux ou\nrapports, soit par témoins à défaut de rapports et procès-verbaux ou à leur\nappui.\nSauf dans les cas où la loi en dispose autrement, les procès-verbaux ou\nrapports établis par les officiers et agents de police judiciaire, ou les\nfonctionnaires ou agents chargés de certaines fonctions de police judiciaire\nauxquels la loi a attribué le pouvoir de constater les contraventions, font foi\njusqu’à preuve contraire.\nLa preuve contraire ne peut être rapportée que par écrit ou par témoins.","[CPPN] Art. 534 : S’il y a lieu à supplément d’information, il y est procédé par le\njuge du tribunal de simple police, conformément aux articles 112 à 115.\nLes dispositions de l’article 449, alinéa 3, sont applicables.","[CPPN] Art. 535 : Si le tribunal de simple police estime que le fait constitue une\ncontravention, il prononce la peine.\n(Loi n° 69-5 du 18 février 1969). Il statue s’il y a lieu sur l’action civile\nconformément aux dispositions de l’article 450, alinéas 2 et 3.","[CPPN] Art. 536 : Si le tribunal de simple police estime que le fait constitue un\ncrime ou un délit, il se déclare incompétent. Il renvoie le ministère public à\nse pourvoir ainsi qu’il avisera.","[CPPN] Art. 537 : Si le tribunal de simple police estime que le fait ne constitue\naucune infraction à la loi pénale, ou que le fait n’est pas établi, ou qu’il\nn’est pas imputable au prévenu, il renvoie celui-ci des fins de la poursuite.","[CPPN] Art. 538 : Si le prévenu bénéficie d’une excuse absolutoire, le tribunal de\nsimple police prononce son absolution et statue s’il y a lieu sur l’action\ncivile, ainsi qu’il est dit à l’article 535.","[CPPN] Art. 539 : Sont applicables à la procédure devant le tribunal de simple police\nles articles 459 à 472 concernant les frais de justice et dépens, la restitution\ndes objets placés sous la main de la justice et la forme des jugements.\n\nCHAPITRE VI : DU JUGEMENT PAR DEFAUT ET DE\nL’OPPOSITION","[CPPN] Art. 540 : Sont applicables devant le tribunal de simple police les\ndispositions des articles 396 à 402 relatives à la comparution et à la\nreprésentation du prévenu et de la personne civilement responsable devant\nle tribunal correctionnel.\nToutefois, lorsque la contravention poursuivie n’est passible que d’une peine\nd’amende, le prévenu peut se faire représenter par un avocat ou par un\nfondé de procuration spéciale.\nSi le tribunal estime nécessaire la comparution du prévenu en personne, il\nest procédé à la réassignation du prévenu, à la diligence du ministère public,\npour une audience dont la date est fixée par le tribunal.\nLe prévenu qui ne répondrait pas à cette invitation est jugé\ncontradictoirement.","[CPPN] Art. 541 : Sont également applicables les dispositions des articles 473 et\n474 relatives aux jugements par défaut et 475 à 481 relatives à l’opposition.\nCHAPITRE VII : DE L’APPEL DES JUGEMENTS DE SIMPLE\nPOLICE","[CPPN] Art. 542 : (Loi n° 66-18 du 29 mars 1966). La faculté d’appeler appartient\nau prévenu, à la personne civilement responsable et au procureur de la\nRépublique, lorsque le jugement prononce une peine d’emprisonnement ou\nlorsque la peine encourue excède 5 jours d’emprisonnement ou 5.000 francs\nd’amende. Lorsque des dommages et intérêts ont été alloués, la faculté d’appeler\nappartient dans tous les cas au prévenu et à la personne civilement responsable.\nCette faculté appartient dans tous les cas à la partie civile quant à ses\nintérêts civils seulement. Dans les affaires poursuivies à la requête de\nl’administration des eaux et forêts, l’appel est toujours possible de la part\nde toutes les parties, quelles que soient la nature et l’importance des\ncondamnations.\nLe procureur général peut faire appel de tous les jugements rendus en\nmatière de simple police.\n\n(Loi n° 66-18 du 29 mars 1966). Le procureur de la République et le\nprocureur général peuvent également attaquer par la voie de l’appel, toute\nordonnance déterminant une amende de composition, même acceptée par\nle contrevenant.","[CPPN] Art. 543 : (Loi n° 66-18 du 29 mars 1966). L’appel des jugements de\nsimple police et de l’ordonnance déterminant une amende de composition\ndans le cas prévu par l’article 542, alinéa 5, est porté devant la Cour d’appel.\nCet appel est interjeté dans les délais prévus par les articles 486 à 488.\nL’appel est suivi et jugé dans la même forme que les appels des jugements\ncorrectionnels.\nLes articles 492 à 494, alinéas 1er et 2, sont applicables à l’appel des jugements\nde simple police.","[CPPN] Art. 544. Le procureur général forme sont appel, dans un délai de trois\nmois à compter du jour du prononcé du jugement, au greffe de la Cour\nd’appel qui en transmet expédition immédiatement au greffe de la juridiction\nqui a statué. Notification doit être faite dans les mêmes conditions aux\nautres parties.","[CPPN] Art. 545 : Les dispositions des articles 496 et 497, 498 à 509, sont applicables\naux jugements rendus par les tribunaux de simple police.\nLa Cour d’appel, saisie de l’appel d’un jugement d’incompétence du tribunal\nde simple police, si elle constate que le fait poursuivi constitue un délit,\nprononce la peine et statue, s’il y a lieu, sur les dommages-intérêts.\nTITRE IV : DES CITATIONS ET SIGNIFICATIONS","[CPPN] Art. 546 : Les citations et significations, sauf disposition contraire des lois\net règlements, sont faites par exploit d’huissier de justice.\nLes notifications sont faites par voie administrative.\nL’huissier ne peut instrumenter pour lui-même, pour son conjoint, pour ses\nparents et alliés et ceux de son conjoint, en ligne directe à l’infini, ni pour\nses parents et alliés collatéraux, jusqu’au degré de cousin, issu de germain\ninclusivement.\nL’exploit de citation ou de signification contient la désignation du requérant,\nla date, les nom et prénoms et adresse de l’huissier, ainsi que les noms,\nprénoms et adresse du destinataire.\n\nLa personne qui reçoit copie de l’exploit signe l’original; si elle ne veut ou\nne peut pas signer, mention en est faite par l’huissier.","[CPPN] Art. 547 : La citation est délivrée à la requête du ministère public, de la\npartie civile et de toute administration qui y est légalement habilitée.\nL’huissier doit déférer sans délai à leur réquisition.\nLa citation énonce le fait poursuivi et vise le texte de loi qui le réprime.\nElle indique le tribunal saisi, le lieu, l’heure et la date de l’audience et précise\nla qualité de prévenu, de civilement responsable, ou de témoin de la personne\ncitée.\nSi elle est délivrée à la requête de la partie civile, elle mentionne les nom,\nprénoms, profession et domicile réel ou élu de celle-ci.\nLa citation délivrée à un témoin doit en outre mentionner que la noncomparution, le refus de témoigner et le faux témoignage sont punis par la loi.","[CPPN] Art. 548 : Le délai entre le jour où la citation est délivrée et le jour fixé\npour la comparution devant le tribunal correctionnel ou de simple police est\nd’au moins huit jours si la partie citée réside dans la ville où siège le tribunal,\ntrente jours si elle réside dans une circonscription limitrophe, quarante-cinq\njours si elle réside en tout autre lieu du territoire de la République du Niger.\nSi la partie citée demeure hors du territoire visé à l’alinéa précédent, ce\ndélai est porté :\n1) à soixante jours si elle demeure en Afrique ou en France;\n2) à quatre-vingt-dix jours si elle demeure en tout autre pays du monde.","[CPPN] Art. 549 : Si les délais prescrits à l’article précédent n’ont pas été observés,\nles règles suivantes sont applicables :\n1) dans le cas où la partie citée ne se présente pas, la citation doit être\ndéclarée nulle par le tribunal;\n2) dans le cas où la partie citée se présente, la citation n’est pas nulle, mais\nle tribunal doit, sur la demande de la partie citée, ordonner le renvoi à une\naudience ultérieure.\nCette demande doit être présentée avant toute défense au fond, ainsi qu’il\nest dit à l’article 366.\n\nCode de procédure pénale","[CPPN] Art. 550 : La signification des décisions, dans les cas où elle est nécessaire,\nest effectuée à la requête du ministère public ou de la partie civile.","[CPPN] Art. 551 : L’huissier doit faire toutes diligences pour parvenir à la délivrance\nde son exploit à la personne même de l’intéressé et lui en remettre une\ncopie.","[CPPN] Art. 552 : Si la personne visée par l’exploit est absente de son domicile, la\ncopie est remise à un parent, allié, employé de maison ou à une personne\nrésidant à ce domicile.\nL’huissier indique dans l’exploit la qualité déclarée par la personne à laquelle\nest faite cette remise.","[CPPN] Art. 553 : (Abrogé par la Loi n° 63-43 du 10 juillet 1963).","[CPPN] Art. 554 : Si l’huissier ne trouve personne au domicile de celui que l’exploit\nconcerne, il vérifie immédiatement l’exactitude de ce domicile.\nLorsque le domicile indiqué est bien celui de l’intéressé, l’huissier mentionne\ndans l’exploit ses diligences et constatations, puis il remet une copie de cet\nexploit soit à la mairie, au maire ou, à défaut, à un adjoint ou à un conseiller\nmunicipal délégué, ou au secrétaire de mairie, soit, à défaut, au chef de\ncirconscription administrative.\n(Alinéas 3 à 5 abrogés par la Loi n° 63-43 du 10 juillet 1963).","[CPPN] Art. 555 : Si la personne visée par l’exploit est sans domicile ou résidence\nconnus, l’huissier remet une copie de l’exploit au parquet du procureur de\nla République du tribunal saisi.","[CPPN] Art. 556 : (Loi n° 63-43 du 10 juillet 1963). Lorsque l’exploit n’a pas\nété délivré à personne, un officier de police judiciaire peut être requis par\nle procureur de la République à l’effet de procéder à des recherches en\nvue de découvrir l’intéressé.\nEn cas de découverte, l’officier de police judiciaire lui donne connaissance de\nl’exploit, qui produit alors les mêmes effets que s’il avait été délivré à personne.\nDans tous les cas, l’officier de police judiciaire dresse procès-verbal de\nses recherches et le transmet sans délai au procureur de la République.\n\nCode de procédure pénale","[CPPN] Art. 557 : Dans les cas prévus aux articles 553 et 554, la copie est délivrée\nsous enveloppe fermée ne portant d’autres indications, d’un côté que les\nnoms, prénoms, adresse de l’intéressé, et de l’autre que le cachet de l’étude\nde l’huissier apposé sur la fermeture du pli.","[CPPN] Art. 558 : Ceux qui habitent à l’étranger sont cités au parquet du procureur\nde la République près le tribunal saisi, lequel vise l’original et envoie la\ncopie au ministre des affaires étrangères ou à toute autre autorité déterminée\npar les conventions diplomatiques.","[CPPN] Art. 559 : Dans tous les cas, l’huissier doit mentionner, sur l’original de\nl’exploit et sous forme de procès-verbal, ses diligences ainsi que les réponses\nqui ont été faites à ses différentes interpellations.\nLe procureur de la République peut prescrire à l’huissier de nouvelles\nrecherches, s’il estime incomplètes celles qui ont été effectuées.\nL’original de l’exploit doit être adressé à la personne à la requête de qui il\na été délivré, dans les vingt-quatre heures.\nEn outre, si l’exploit a été délivré à la requête du procureur de la République,\nune copie de l’exploit doit être jointe à l’original.","[CPPN] Art. 560 : Les huissiers sont tenus de mettre, à la fin de l’original et de la\ncopie de l’exploit, le coût de celui-ci, à peine d’une amende civile de 2.000\nà 10.000 francs; cette amende est prononcée par le président de la juridiction\nsaisie de l’affaire.","[CPPN] Art. 561 : La nullité d’un exploit ne peut être prononcée que lorsqu’elle a\neu pour effet de porter atteinte aux intérêts de la personne qu’il concerne,\nsous réserve, pour les délais de citation, des dispositions de l’article 549,2°.","[CPPN] Art. 562 : Si un exploit est déclaré nul par le fait de l’huissier, celui-ci peut\nêtre condamné aux frais de l’exploit et de la procédure annulée, et\néventuellement à des dommages-intérêts envers la partie à laquelle il est\nporté préjudice.\nLa juridiction qui déclare la nullité a compétence pour prononcer ces\ncondamnations.\n\nLIVRE III\nDES VOIES DE RECOURS EXTRAORDINAIRES\n\nTITRE I : DU POURVOI EN CASSATION\nCHAPITRE PREMIER : DES DECISIONS SUSCEPTIBLES\nD’ETRE ATTAQUEES ET DES CONDITIONS DU POURVOI","[CPPN] Art. 563 : Les arrêts de la Chambre d’accusation et les arrêts et jugements\nrendus en dernier ressort en matière criminelle, correctionnelle et de simple\npolice peuvent être annulés en cas de violation de la loi sur pourvoi en\ncassation formé par le ministère public ou par la partie à laquelle il est fait\ngrief, suivant les distinctions qui vont être établies.\nLe recours est porté devant la Chambre judiciaire de la Cour suprême.","[CPPN] Art. 564 : Le ministère public et toutes les parties ont cinq jours francs\naprès celui où la décision attaquée a été prononcée pour se pourvoir en\ncassation.\nToutefois, le délai de pourvoi ne court qu’à compter de la signification de\nl’arrêt, quel qu’en soit le mode :\n1) pour la partie qui, après débat contradictoire, n’était pas présente ou\nreprésentée à l’audience où l’arrêt a été prononcé, si elle n’avait pas été\ninformée ainsi qu’il est dit à l’article 448, alinéa 2 ;\n2) pour le prévenu qui a demandé à être jugé en son absence dans les\nconditions prévues à l’article 398, alinéa 1;\n3) (Loi n° 66-18 du 29 mars 1966) pour le prévenu qui n’a pas comparu\ndans le cas prévu aux articles 396 et 398, alinéa 4 ;\n4) pour le prévenu qui a été jugé par itératif défaut;\n5) (Loi n° 66-18 du 29 mars 1966) pour le prévenu jugé dans les conditions\nfixées à l’article 501.\n(Loi n° 69-5 du 18 février 1969). Lorsque les assises sont tenues ailleurs\nqu’au siège de la Cour d’appel, le délai de pourvoi du procureur général\nprès la Cour d’appel est porté à quinze jours francs.\nLe délai de pourvoi contre les arrêts ou les jugements par défaut ne court,\nà l’égard du prévenu, que du jour où ils ne sont plus susceptibles d’opposition.\nA l’égard du ministère public, le délai court à compter de l’expiration du\ndélai de dix jours qui suit la signification.\n\nA l’égard de la partie civile, ce délai court à compter de l’expiration des\ndélais fixés à l’article 477.","[CPPN] Art. 565 : Le pourvoi en cassation n’est pas suspensif. Pendant les délais\ndu recours en cassation et s’il y a eu recours, jusqu’au prononcé de l’arrêt\nde la Cour suprême, il n’est pas sursis à l’exécution de l’arrêt de la Cour\nd’appel.\nEst, nonobstant pourvoi, mis en liberté, immédiatement après l’arrêt, le\nprévenu détenu qui a été acquitté, ou absous, ou condamné soit à\nl’emprisonnement assorti du sursis soit à l’amende.\nIl en est de même du prévenu détenu condamné à une peine\nd’emprisonnement, aussitôt que la durée de la détention aura atteint celle\nde la peine prononcée.","[CPPN] Art. 566 : (Loi n° 70-9 du 17 mars 1970). Lorsque le tribunal ou la Cour\nd’appel statue par jugement ou arrêt distinct de l’arrêt sur le fond, le pourvoi\nen cassation est immédiatement recevable si cette décision met fin à la\nprocédure. Si le président de la Chambre judiciaire de la Cour suprême\nconstate qu’une décision a été à tort considérée par la partie intéressée\ncomme mettant fin à la procédure, il apprécie si le pourvoi doit néanmoins\nêtre reçu dans l’intérêt de l’ordre public ou d’une bonne administration de\nla justice, ou si, au contraire, il ne doit pas être reçu, et rend d’office à cet\neffet une ordonnance d’admission ou de non admission.\nDans le cas où la décision n’a pas mis fin à la procédure et jusqu’à\nl’expiration des délais de pourvoi, l’arrêt n’est pas exécutoire et la Cour\nd’appel ne peut statuer au fond.\nSi aucun pourvoi n’a été interjeté ou si, avant l’expiration du délai du pourvoi,\nla partie demanderesse au pourvoi n’a pas déposé au greffe la requête\nprévue par l’alinéa suivant, le jugement ou l’arrêt est exécutoire et le tribunal\nou la Cour d’appel statue au fond. Dans ce cas, si la procédure a été\nnéanmoins transmise à la Cour suprême, le président de la Chambre\njudiciaire ordonne qu’il en soit fait retour à la juridiction saisie.\nLe demandeur en cassation peut déposer au greffe, avant l’expiration des\ndélais de pourvoi, une requête adressée au président de la Chambre judiciaire\nde la Cour suprême et tendant à faire déclarer son pourvoi immédiatement\n","[CPPN] Art. 567 : (Loi n° 70-9 du 17 mars 1970). Le greffier avise le président\ndu tribunal ou le président de la Cour d’appel du dépôt de cette requête. Le\njugement ou l’arrêt n’est pas exécutoire et il ne peut être statué au fond\ntant qu’il n’a pas été prononcé sur ladite requête.\nDès que le greffier a reçu le pourvoi et la requête, il fait parvenir celle-ci\nau président de la Chambre judiciaire, ainsi qu’une expédition du jugement\nou de l’arrêt de la déclaration de pourvoi.\nLe président de la Chambre judiciaire statue sur la requête par ordonnance\ndans les huit jours de la réception de ce dossier.\nS’il rejette, le jugement ou l’arrêt est exécutoire et le tribunal ou la Cour\nd’appel se prononce au fond; aucun recours n’est recevable contre\nl’ordonnance du président et le pourvoi n’est alors jugé qu’en même temps\nque le pourvoi formé contre le jugement ou l’arrêt sur le fond.\nSi, dans l’intérêt de l’ordre public ou d’une bonne administration de la justice,\nle président fait droit à la requête, il fixe la date à laquelle le pourvoi sera\njugé.\nLa Chambre judiciaire doit statuer dans les deux mois qui suivent\nl’ordonnance du président, sans que puisse être soulevée devant elle une\nexception tirée de ce que le pourvoi formé contre la décision entreprise ne\nserait pas suspensif. L’exécution du jugement ou de l’arrêt est suspendue\njusqu’à ce qu’intervienne l’arrêt de la Chambre judiciaire.\nLes dispositions de l’article 566 du présent article sont applicables aux\npourvois formés contre le","[CPPN] Art. 568 : (Abrogé par la Loi n° 69-5 du 18 février 1969).","[CPPN] Art. 569 : (Abrogé par la Loi n° 69-5 du 18 février 1969).","[CPPN] Art. 570 : L’arrêt de la Chambre d’accusation portant renvoi du prévenu\ndevant le tribunal correctionnel ou de simple police ne peut être attaqué\ndevant la Cour suprême que lorsqu’il statue, d’office ou sur déclinatoire\ndes parties, sur la compétence ou qu’il présente des dispositions définitives\nque le tribunal, saisi de la prévention, n’a pas le pouvoir de modifier.\n(Alinéa 2 abrogé par la loi n° 70-9 du 17 mars 1970).\n\nCode de procédure pénale","[CPPN] Art. 571 : La partie civile ne peut se pourvoir en cassation contre les\narrêts de la Chambre d’accusation que s’il y a pourvoi du ministère public.\nToutefois son seul pourvoi est recevable dans les cas suivants :\n1) lorsque l’arrêt de la Chambre d’accusation a dit n’y avoir lieu à informer;\n2) lorsque l’arrêt a déclaré l’irrecevabilité de l’action de la partie civile;\n3) (Loi n° 70-9 du 17 mars 1970). Lorsque l’arrêt a admis une exception\nmettant fin à l’action publique;\n4) lorsque l’arrêt a, d’office ou sur déclinatoire des parties, prononcé\nl’incompétence de la juridiction saisie;\n5) lorsque l’arrêt a omis de statuer sur un chef d’inculpation;\n6) (Loi n° 70-9 du 17 mars 1970). Lorsque l’arrêt ne satisfait pas en la\nforme aux conditions essentielles de son existence légale.\nCHAPITRE II - DES FORMES DU POURVOI","[CPPN] Art. 572 : La déclaration de pourvoi doit être faite au greffier de la juridiction\nqui a rendu la décision attaquée ou au greffier de la juridiction de la résidence\ndu demandeur en cassation.\nElle doit être signée par le greffier et par le demandeur en cassation luimême ou par un avocat-défenseur ou par un fondé de pouvoir spécial :\ndans ce dernier cas, le pourvoi est annexé à l’acte dressé par le greffier. Si\nle déclarant ne peut signer, le greffier en fera mention.\nElle est inscrite sur un registre public à ce destiné et toute personne a le\ndroit de s’en faire délivrer une copie.\nDans le cas où le pourvoi est reçu par le greffe de la résidence, le greffier qui\na dressé l’acte le transmet sans délai au greffe de la juridiction qui a statué.","[CPPN] Art. 573 : Lorsque le demandeur en cassation est détenu, il peut également\nfaire connaître sa volonté de se pourvoir par une lettre qu’il remet au\nrégisseur de l’établissement pénitentiaire, ce dernier lui en délivre récépissé.\nLe régisseur certifie sur cette lettre même que celle-ci lui a été remise par\nl’intéressé et il précise la date de la remise.\n\nCe document est transmis immédiatement au greffe de la juridiction qui a\nrendu la décision attaquée; il est transcrit sur le registre prévu par l’article\n572, alinéa 3 et est annexé à l’acte dressé par le greffier.","[CPPN] Art. 574 : Le recours est notifié par le greffier de la juridiction qui a\nstatué, au ministère public et aux autres parties par lettre recommandée\navec demande d’avis de réception, dans un délai de trois jours.","[CPPN] Art. 575 : (Loi n° 70-9 du 17 mars 1970). La partie qui n’a pas reçu la\nnotification prévue à l’article 574 a le droit de former opposition à l’arrêt\nrendu par la Cour suprême, par déclaration au greffe de la juridiction qui a\nrendu la décision frappée de pourvoi, dans les cinq jours de la signification\ndudit arrêt.","[CPPN] Art. 576 : (Abrogé par la loi n° 65-20 du 15 mai 1965).","[CPPN] Art. 577 : (Loi n° 65-20 du 15 mai 1965). Aucune consignation d’amende\nn’est exigée du demandeur au pourvoi. Cependant celui-ci, s’il succombe,\npeut être condamné à une amende portée à 20.000 francs.","[CPPN] Art. 578 : (Loi n° 65-20 du 15 mai 1965). Sont dispensés de l’amende\nprévue ci-dessus :\n1) les condamnés à une peine criminelle;\n2) les agents publics pour les affaires concernant directement\nl’administration et les domaines de l’Etat et des collectivités publiques.","[CPPN] Art. 579 : Sont déclarés déchus de leur pourvoi les condamnés à une\npeine d’emprisonnement d’une durée de plus de six mois qui ne sont pas en\nétat ou qui n’ont pas obtenu, de la juridiction qui a prononcé, dispense, avec\nou sans caution, de se mettre en état.\nL’acte de leur écrou ou l’arrêt leur accordant la dispense est produit devant\nla Cour suprême, au plus tard au moment où l’affaire y est appelée.\nPour que son recours soit recevable, il suffit au demandeur de justifier qu’il\ns’est constitué dans un établissement pénitentiaire, soit du lieu où siège la\nCour suprême, soit du lieu où a été prononcée la condamnation; le régisseur\nde cette prison l’y reçoit sur l’ordre du procureur général près la Cour\nsuprême ou du chef du parquet de la juridiction du jugement.\n\nCode de procédure pénale","[CPPN] Art. 580 : Le demandeur en cassation, soit en faisant sa déclaration, soit dans\nles dix jours suivants, peut déposer, au greffe de la juridiction qui a rendu la\ndécision attaquée, un mémoire, signé par lui ou par son avocat-défenseur,\ncontenant ses moyens de cassation. Le greffier lui en délivre reçu.","[CPPN] Art. 581 : Après l’expiration de ce délai, le demandeur condamné\npénalement peut transmettre son mémoire directement au greffe de la\nChambre judiciaire de la Cour suprême.\nDans tous les cas, le mémoire doit être accompagné d’autant de copies\nqu’il y a de parties en cause.","[CPPN] Art. 582 : Sous peine d’une amende civile de 5.000 francs prononcée par la\nCour suprême, le greffier, dans le délai maximum de vingt jours à dater de la\ndéclaration de pourvoi, cote et paraphe les pièces du dossier, auquel il joint\nune expédition de la décision attaquée, une expédition de l’acte de pourvoi et,\ns’il y a lieu, le mémoire du demandeur. Du tout, il dresse inventaire.","[CPPN] Art. 583 : Lorsque le dossier est ainsi en état, le greffier le remet au\nmagistrat du ministère public, qui l’adresse immédiatement au procureur\ngénéral près la Cour suprême.\nCHAPITRE III : DES OUVERTURES A CASSATION","[CPPN] Art. 584 : Les arrêts de la Chambre d’accusation ainsi que les arrêts et\njugements rendus en dernier ressort par les juridictions de jugement, lorsqu’ils\nsont revêtus des formes prescrites par la loi, ne peuvent être cassés que\npour violation de la loi.","[CPPN] Art. 585 : Ces décisions sont déclarées nulles lorsqu’elles ne sont pas\nrendues par le nombre de juges prescrit ou qu’elles ont été rendues par des\njuges qui n’ont pas assisté à toutes les audiences de la cause. Lorsque\nplusieurs audiences ont été consacrées à la même affaire, les juges qui ont\nconcouru à la décision sont présumés avoir assisté à toutes ces audiences.\nCes décisions sont également déclarées nulles lorsqu’elles ont été rendues sans\nque le ministère public ait été entendu dans les cas où cette audition est obligatoire.","[CPPN] Art. 586 : Les arrêts de la Chambre d’accusation ainsi que les arrêts et\njugements en dernier ressort sont déclarés nuls s’ils ne contiennent pas de\nmotifs ou si leurs motifs sont insuffisants et ne permettent pas à la Cour suprême\nd’exercer son contrôle et de reconnaître si la loi a été respectée dans le dispositif.\n\nIl en est de même lorsqu’il a été omis ou refusé de prononcer soit sur une\nou plusieurs demandes des parties, soit sur une ou plusieurs réquisitions du\nministère public.","[CPPN] Art. 587 : En matière criminelle, l’arrêt de renvoi de la Chambre\nd’accusation, devenu définitif, fixe la compétence de la Cour d’assises et\ncouvre, s’il en existe, les vices et la procédure antérieure.","[CPPN] Art. 588 : (Loi n° 69-5 du 18 février 1969). Lorsque la Chambre\nd’accusation statue sur le règlement d’une procédure dans un cas autre\nque celui visé à l’article précédent, tous moyens pris de nullités de\nl’information doivent lui être proposés, faute de quoi l’inculpé ou la partie\ncivile ne sont plus recevables à en faire état, sauf le cas du droit qui\nappartient à la Cour suprême de relever tous les moyens d’office.","[CPPN] Art. 589 : En matière criminelle et dans le cas où l’accusé a été condamné,\nsi l’arrêt a prononcé une peine autre que celle appliquée par la loi à la\nnature du crime, l’annulation de l’arrêt pourra être poursuivie tant par le\nministère public que par la partie condamnée.","[CPPN] Art. 590 :\n\n(Abrogé par la Loi n° 69-5 du 18 février 1969).","[CPPN] Art. 591 : Lorsque la peine prononcée est la même que celle portée par la\nloi qui s’applique à l’infraction, nul ne peut demander l’annulation de l’arrêt\nsous le prétexte qu’il y aurait erreur dans la citation du texte de la loi.","[CPPN] Art. 592 : En matière correctionnelle, le prévenu n’est pas recevable à\nprésenter comme moyen de cassation les nullités commises en première\ninstance s’il ne les a pas opposées devant la Cour d’appel, à l’exception de la\nnullité pour cause d’incompétence lorsqu’il ya eu appel du ministère public.","[CPPN] Art. 593 : Nul ne peut, en aucun cas, se prévaloir contre la partie poursuivie de\nla violation ou omission des règles établies pour assurer la défense de celle-ci.\nCHAPITRE IV : DU POURVOI DANS L’INTERET DE LA LOI","[CPPN] Art. 594 : Lorsque, sur l’initiative du ministre de la justice, le procureur\ngénéral près la Cour suprême dénonce à la Cour suprême des actes\njudiciaires, arrêts ou jugements contraires à la loi, ces actes, arrêts ou\njugements peuvent être annulés.\n\nCode de procédure pénale","[CPPN] Art. 595 : Lorsqu’il a été rendu par la Cour d’appel ou d’assises ou par un\ntribunal correctionnel ou de simple police, un arrêt ou jugement en dernier\nressort, sujet à cassation, et contre lequel néanmoins aucune des parties ne\ns’est pourvue dans le délai déterminé, le procureur général près la Cour\nsuprême peut d’office et nonobstant l’expiration du délai se pourvoir, mais\ndans le seul intérêt de la loi, contre ledit jugement ou arrêt. La Cour se\nprononce sur la recevabilité et le bien-fondé de ce pourvoi. Si le pourvoi est\naccueilli, la cassation est prononcée, sans que les parties puissent s’en\nprévaloir et s’opposer à l’exécution de la décision annulée.\nTITRE II : DES DEMANDES EN REVISION","[CPPN] Art. 596 : La révision peut être demandée, quelle que soit la juridiction qui\na statué, au bénéfice de toute personne reconnue auteur d’un crime ou\nd’un délit :\n1) lorsque, après une condamnation pour homicide, des pièces sont\nreprésentées propres à faire naître de suffisants indices sur l’existence de\nla prétendue victime de l’homicide;\n2) lorsque, après une condamnation pour crime ou délit, un nouvel arrêt ou\njugement a condamné pour le même fait un autre accusé ou prévenu et\nque, les deux condamnations ne pouvant se concilier, leur contradiction est\nla preuve de l’innocence de l’un ou de l’autre condamné.\n3) lorsqu’un des témoins entendus a été, postérieurement à la condamnation,\npoursuivi et condamné pour faux témoignage contre l’accusé ou le prévenu;\nle témoin ainsi condamné ne peut pas être entendu dans les nouveaux débats;\n4) lorsque, après une condamnation, un fait vient à se produire ou à se\nrévéler, ou lorsque des pièces inconnues lors des débats sont représentées,\nde nature à établir l’innocence du condamné.","[CPPN] Art. 597 : Le droit de demander la révision appartient dans les trois premiers cas :\n1) au ministre de la justice;\n2) au condamné ou, en cas d’incapacité, à son représentant légal;\n3) après la mort ou l’absence déclarée du condamné, à son conjoint, à ses\nenfants, à ses parents, à ses légataires universels ou à titre universel, à\nceux qui en ont reçu de lui la mission expresse.\n\nLa Cour suprême est saisie par son procureur général en vertu de l’ordre\nexprès que le ministre de la justice a donné soit d’office, soit sur la réclamation\ndes parties.\nDans le quatrième cas, le droit de demander la révision appartient au ministre\nde la justice seul, qui statue après avoir fait procéder à toutes recherches\net vérifications utiles et pris avis de la Cour d’appel en assemblée générale.\nSi la demande de révision lui paraît devoir être admise, le ministre transmet\nle dossier de la procédure au procureur général qui saisit la Cour suprême.","[CPPN] Art. 598 : Si l’arrêt ou le jugement de condamnation n’a pas été exécuté,\nl’exécution en est suspendue de plein droit à partir de la demande formée\npar le ministre de la justice à la Cour suprême.\nAvant la transmission à la Chambre judiciaire de la Cour suprême, si le\ncondamné est en état de détention, l’exécution peut être suspendue sur\nl’ordre du ministre de la justice. A partir de la transmission de la demande,\nla suspension peut être prononcée par arrêt de la Cour suprême.","[CPPN] Art. 599 : Si l’affaire n’est pas en état, la Cour suprême se prononce sur\nla recevabilité en la forme de la demande et procède directement ou par\ncommission rogatoire à toutes enquêtes sur le fond, confrontations,\nreconnaissances d’identité et moyens propres à mettre la vérité en évidence.\nLorsque l’affaire est en état, la Cour examine au fond. Elle rejette la\ndemande si elle l’estime mal fondée. Si, au contraire, elle l’estime fondée,\nelle annule la condamnation prononcée. Elle apprécie s’il est possible de\nprocéder à de nouveaux débats contradictoires. En cas d’affirmative, elle\nrenvoie les accusés ou prévenus devant une juridiction de même ordre et\nde même degré mais autre que celle dont émane la décision annulée.\nS’il y a impossibilité de procéder à de nouveaux débats, notamment en cas\nde décès, de démence, de défaut d’un ou plusieurs condamnés,\nd’irresponsabilité pénale ou d’excusabilité, en cas de prescription de l’action\nou de la peine, la Cour suprême, après l’avoir expressément constatée,\nstatue au fond en présence des parties civiles, s’il y en a au procès et des\ncurateurs nommés par elle à la mémoire de chacun des morts; en ce cas,\nelle annule seulement celles des condamnations qui lui paraissent non\njustifiées et décharge, s’il y a lieu, la mémoire des morts.\n\nSi l’impossibilité de procéder à de nouveaux débats ne se révèle qu’après\nl’arrêt de la Cour suprême annulant l’arrêt ou le jugement de condamnation\net prononçant le renvoi, la Cour suprême, sur la réquisit","[CPPN] Art. 600 : La décision d’où résulte l’innocence d’un condamné peut, sur\nla demande de celui-ci, lui allouer des dommages-intérêts à raison du\npréjudice que lui a causé la condamnation.\nSi la victime de l’erreur judiciaire est décédée, le droit de demander des\ndommages-intérêts appartient, dans les mêmes conditions, à son conjoint, à\nses ascendants et descendants.\nIl n’appartient aux parents d’un degré plus éloigné qu’autant qu’ils justifient\nd’un préjudice matériel résultant pour eux de la condamnation.\nLa demande est recevable en tout état de la procédure en révision.\nLes dommages-intérêts alloués sont à la charge de l’Etat, sauf son recours\ncontre la partie civile, le dénonciateur ou le faux témoin par la faute desquels la\ncondamnation a été prononcée. Ils sont payés comme frais de justice criminelle.\nLes frais de l’instance en révision sont avancés par le trésor à partir de la\ntransmission de la demande de la Cour suprême.Si l’arrêt ou le jugement\ndéfinitif de révision prononce une condamnation, il met à la charge du\ncondamné ou, s’il y a lieu, des demandeurs en révision, les frais dont l’Etat\npeut demander le remboursement.\nLe demandeur en révision qui succombe dans son instance est condamné\nà tous les frais. L’arrêt ou le jugement de révision d’où il résulte l’innocence\nd’un condamné sera affiché dans la ville où a été prononcée la condamnation,\ndans celle où siège la juridiction de révision, dans la commune ou le cheflieu de circonscription administrative du lieu où le ","[CPPN] Art. 601 : Lorsqu’il est porté à la connaissance du procureur de la\nRépublique qu’une pièce arguée de faux figure dans un dépôt public ou a\nété établie dans un dépôt public, le procureur de la République peut se\ntransporter dans ce dépôt pour procéder à tous examens et vérifications\nnécessaires.\nLe procureur de la République ne peut déléguer les pouvoirs ci-dessus à un\nofficier de police judiciaire.\nLe procureur de la République peut, en cas d’urgence, ordonner le transport\nau greffe des documents suspectés.","[CPPN] Art. 602 : Dans toute information pour faux en écriture, le juge d’instruction,\naussitôt que la pièce arguée de faux produite devant lui ou a été placée\nsous main de justice, en ordonne le dépôt au greffe. Il la revêt de sa\nsignature, ainsi que le greffier en chef qui dresse du dépôt un acte décrivant\nl’état de la pièce.\nToutefois, avant le dépôt au greffe, le juge d’instruction peut ordonner que\nla pièce soit reproduite par photographie ou par tout autre moyen.","[CPPN] Art. 603 : Le juge d’instruction peut se faire remettre par qui il appartiendra\net saisir toutes pièces de comparaison. Celles-ci sont revêtues de sa signature\net celle du greffier en chef qui en fait un acte descriptif comme il est dit à\nl’article précédent.","[CPPN] Art. 604 : Tout dépositaire public de pièces arguées de faux, ou ayant\nservi à établir des faux, est tenu, sur ordonnance du juge d’instruction, de\nles lui remettre et de fournir, le cas échéant, les pièces de comparaison qui\nsont en sa possession.\nSi les pièces ainsi remises par un officier public ou saisies entre ses mains\nont le caractère d’actes authentiques, il peut demander qu’il lui en soit\nlaissé une copie certifiée conforme par le greffier en chef, ou une\nreproduction par photographie ou par tout autre moyen.\nLadite copie ou reproduction est mise au rang des minutes de l’office jusqu’à\nrestitution de la pièce originale.\n\nCode de procédure pénale","[CPPN] Art. 605 : Si au cours d’une audience d’un tribunal ou de la Cour une\npièce de la procédure ou une pièce produite est arguée de faux, la juridiction\ndécide, après avoir recueilli les observations du ministère public et des\nparties, s’il y a lieu, ou non, de surseoir jusqu’à ce qu’il ait été prononcé sur\nle faux par la juridiction compétente.\nSi l’action publique est éteinte ou ne peut être exercée du chef de faux, et\ns’il n’apparaît pas que celui qui a produit la pièce ait fait sciemment usage\nd’un faux, le tribunal ou la Cour saisi de l’action principale statue\nincidemment sur le caractère de la pièce prétendue entachée de faux.\nTITRE 1 (BIS) (NOUVEAU) : DE LA CRIMINALITE\nTRANSNATIONALE ORGANISEE, DU TERRORISME ET DU\nFINANCEMENT DU TERRORISME.\n(Loi n° 2017-07 du 31 mars 2017)\nCHAPITRE I : DE LA COMPETENCE DES JURIDICTIONS\nNATIONALES","[CPPN] Art. 605.1 (nouveau) : (Loi n° 2017-07 du 31 mars 2017) Les juridictions\nde la République du Niger sont compétentes pour poursuivre les auteurs\ndes infractions en matière de terrorisme et de criminalité transnationale\norganisée prévues par le code pénal et d’autres textes dans les cas où\nl’auteur présumé de l’une de ces infractions se trouve sur le territoire de la\nRépublique du Niger et indépendamment de la nationalité de l’auteur\nprésumé ou de son statut d’apatride, à bord d’un navire battant pavillon\nnigérien ou d’un aéronef immatriculé conformément au droit interne.\nElles sont également compétentes, lorsque l’infraction :\n- a été commise hors du territoire national en vue de la commission sur le\nterritoire nigérien d’une infraction prévue à la présente loi;\n- a eu des effets ou des conséquences importantes sur le territoire national;\n- a eu des effets ou des conséquences importantes sur des biens du Niger\nsitués à l’étranger.\nEn matière de lutte contre le terrorisme et la criminalité transnationale\norganisée l’affaire doit être soumise au pôle judiciaire pour qu’il engage\n\ndes poursuites pénales, sans retard excessif et sans aucune exception, que\nl’infraction ait été commise ou non sur le territoire national, à moins qu’une\ndécision n’ait été prise par l’autorité compétente pour extrader la ou les\npersonne (s) impliquée (s).\nPour le besoin de l’extradition ou de l’entraide judiciaire :\n- les infractions prévues par la présente loi ne sont pas considérées comme\ndes infract","[CPPN] Art. 605.1 (bis) : (Loi n° 2016-21 du 16 juin 2016) Les Tribunaux\ncorrectionnels sont compétents pour connaitre des infractions commises\nen matière de détournement de deniers ou biens publics ou privés ou d’usage\nillicite, jusqu’à concurrence du montant de cent millions (100.000.000) de\nfrancs détournés, soustraits ou dissipés, ou si les biens détournés, soustraits\nou dissipés sont d’une valeur équivalente.","[CPPN] Art. 605.1 (ter) : (Loi n° 2016-21 du 16 juin 2016) Une infraction est\nde nature transnationale si :\na) elle est commise dans plus d’un État ;\nb) elle est commise dans un État mais qu’une partie de sa préparation, de sa\nplanification, de sa conduite ou de son contrôle a lieu dans un autre État ;\nc) elle est commise dans un État, mais implique un groupe criminel qui se\nLivre à des activités criminelles dans plus d’un État ;\nd) elle est commise dans un État mais a des effets dans un autre État.\n\nCHAPITRE II : DE LA PROCEDURE DEVANT LE POLE\nJUDICIAIRE EN MATIERE DE LUTTE CONTRE LE\nTERRORISME.\nSection I : De l’enquête :","[CPPN] Art. 605.2 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) L’enquête\nest assurée par le service central de lutte contre le terrorisme et la criminalité\ntransnationale organisée sur toute l’étendue du territoire national, sous la\ndirection et le contrôle du parquet du pôle judiciaire spécialisé en matière\nde lutte contre le terrorisme et la criminalité transnationale organisée.\nDans tous les cas, le procureur de la République dans le ressort duquel\nl’enquête est réalisée est régulièrement tenu informé par tout moyen de\nl’évolution de l’enquête.","[CPPN] Art. 605.2 (bis) : (Loi n° 2016-21 du 16 juin 2016) La procédure\napplicable à l’enquête sur les infractions en matière de terrorisme et de\nfinancement du terrorisme visées aux articles 399.1 à 399.1.24 du Code\npénal et sur les infractions connexes devant le Pôle judiciaire spécialisé en\nmatière de lutte contre le terrorisme et la criminalité transnationale organisée,\nest celle prévue par la présente loi.\nToutefois, la procédure applicable à l’enquête sur les infractions de nature\ntransnationale, notamment en matière de traite des personnes, de trafic\nillicite des migrants, de trafic de drogue, de trafic d’armes et de munitions,\nainsi que le blanchiment lié à ces infractions, est celle prévue par les\ndispositions les régissant1.\nS’il ressort d’actes de procédure que ces infractions de nature transnationale\nsont liées au terrorisme, les dispositions du présent titre sont applicables.","[CPPN] Art. 605.3 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) Les officiers\nde police judiciaire sous la direction et le contrôle des procureurs de la\nRépublique près les tribunaux de grande instance sont habilités à procéder\nVoir – l’Ord. n°2010-86 du 16 décembre 2010, relative à la lutte contre la traite des\npersonnes (JO n°4 du 15 février 2011) ;\n\n- La loi n°2015-36 du 26 mai 2015, relative au trafic illicite de migrants (JO n°15 du 1er\naout 2015) ;et la Loi n°2016-33 du 31 octobre 2016, relative à la lutte contre le blanchiment\ndes capitaux et le financement du terrorisme (JOSP n°08 du 22 mars 2017).\n\naux actes urgents d’enquête en vue de constater l’infraction commise dans\nleur ressort, d’en rassembler les preuves et d’en rechercher les auteurs.\nIls reçoivent, en outre, les dénonciations volontaires, plaintes, procès-verbaux\net rapports y relatifs. Le parquet du pôle judiciaire spécialisé en matière de\nlutte contre le terrorisme et la criminalité transnationale organisée est\nrégulièrement tenu informé, par tout moyen, des diligences effectuées.\nIls mettent, dans les plus brefs délais, à la disposition du parquet du pôle\njudiciaire spécialisé en matière de lutte contre le terrorisme et la criminalité\ntransnationale organisée, la ou les personnes mise (s) en cause, les rapports,\nprocès-verbaux et pièces à conviction.\nEn cas d’urgence ou dans le cas où le parquet du Tribunal de grande\ninstance dans le ressort duquel l’infraction a été commise ne peut mettre à\nla disposition du pa","[CPPN] Art. 605.4 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) Pour les\nbesoins de l’enquête et en cas de présomption d’existence d’indices en\nrelation avec une entreprise terroriste, les officiers de police judiciaire sont\nautorisés provisoirement, en vertu d’une autorisation écrite, soit du parquet\ndu pôle judiciaire spécialisé en matière de lutte contre le terrorisme et la\ncriminalité transnationale organisée, soit des procureurs de la République\nterritorialement compétents, soit des juges d’instruction près le pôle judiciaire\nspécialisé en matière de lutte contre le terrorisme et la criminalité\ntransnationale organisée ou du juge d’instruction habilité agissant en vertu\nd’une commission rogatoire, à :\n- intercepter les communications téléphoniques, les messages électroniques et\nautres courriers des suspects ou de toute personne en rapport avec eux pendant\nune durée maximum de trois (3) mois renouvelable en cas de nécessité ;\n\n- infiltrer en vue de la recherche d’éléments de preuve, les organisations terroristes\net les associations de malfaiteurs en relation avec une entreprise terroriste.\nLes éléments de preuve obtenus par cette procédure sont consignés dans\ndes procès-verbaux spéciaux annexés à la procédure et peuvent être utilisés\nau besoin comme élément de preuve devant les juridictions compétentes.\nLes procès-verbaux annexés mentionneront les noms, prénoms et qualité\nde ou des officiers de police judiciaire ayant procédé à l’interception des\ncorrespondances ci-dessus spécifi","[CPPN] Art. 605.5 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) Le délai de\ngarde à vue est de quinze (15) jours. Ce délai peut être prolongé d’un\nnouveau délai de même durée par autorisation écrite du parquet du pôle\njudiciaire spécialisé en matière de lutte contre le terrorisme et la criminalité\ntransnationale organisée ou du juge d’instruction de ladite juridiction.\nIl est notifié au suspect son droit de prendre un avocat à partir de la 48ème\nheure de garde à vue.\nLorsque la fin de la garde à vue coïncide avec un jour férié, la personne\ngardée à vue est déférée au premier jour ouvrable suivant.\nLa personne déférée doit être accompagnée d’un certificat médical attestant\nqu’elle n’a pas subi de sévices corporels.","[CPPN] Art. 605.6 (Ord. n° 2011-13 du 27 janvier 2011) Les officiers de police\njudiciaire agissant en matière de lutte contre le terrorisme peuvent procéder\nà des perquisitions domiciliaires et à toute saisie en cas de présomption\nd’existence d’indices en relation avec une entreprise terroriste.\nCes perquisitions et saisies peuvent être menées à tout moment et en tout lieu.","[CPPN] Art. 605.7 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) L’ouverture\nd’une information judiciaire est obligatoire. Le doyen des juges d’instruction du\nTribunal de Grande Instance Hors Classe de Niamey ou les juges d’instruction\naffectés au pôle judiciaire spécialisé en matière de lutte contre le terrorisme et\nla criminalité transnationale organisée sont chargés d’y procéder.\nSauf dispositions dérogatoires prévues par la présente section, l’instruction\nest conduite conformément aux règles de droit commun.","[CPPN] Art. 605.7 (bis) : (Loi n° 2016-21 du 16 juin 2016) En cas d’enquête\nen matière de lutte contre le terrorisme, le procureur de la République près\nle pôle judiciaire spécialisé peut autoriser les officiers de police judiciaire à\ninterdire à toute personne mise en cause de sortir du territoire national.\n\nSection II : De l’instruction","[CPPN] Art. 605.7 (ter) : (Loi n° 2016-21 du 16 juin 2016) La procédure\napplicable à l’instruction des infractions en matière de terrorisme et de\nfinancement du terrorisme visées aux articles 399.1 à 399.1.24 du code\npénal et d’infractions connexes devant le pôle judiciaire spécialisé en matière\nde lutte contre le terrorisme et la criminalité transnationale organisée, est\ncelle prévue par la présente loi.\nToutefois, la procédure applicable à l’instruction des infractions de nature\ntransnationale, notamment en matière de traite des personnes, de trafic\nillicite des migrants, de trafic de drogue, de trafic d’armes et de munitions,\nainsi que le blanchiment lié à ces infractions est celle prévue par les\ndispositions les régissant.\nL’instruction des procédures en matière de lutte contre le terrorisme et la\ncriminalité transnationale organisée concernant les mineurs est faite\nconformément aux dispositions de la loi sur les juridictions pour mineurs.\nS’il ressort d’actes de procédure que ces infractions sont liées au terrorisme,\nles dispositions du présent titre sont applicables.","[CPPN] Art. 605.8 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) La durée\ntotale de la détention préventive ne peut excéder quatre (4) ans en matière\ncriminelle et deux (2) ans en matière délictuelle.","[CPPN] Art. 605.9 : (Ord. n° 2011-12 du 27 janvier 2011) - Le gel des avoirs,\nfonds, valeurs ou biens sera opéré dès le déclenchement de la procédure.","[CPPN] Art. 605.10 : (Ord. n° 2011-12 du 27 janvier 2011) A l’exception des\narmes, munitions et explosifs qui sont confisqués au profit du service central\nde lutte contre le terrorisme, les matériels, matériaux, fournitures,\néquipements et biens de toute nature, saisis à l’occasion de la préparation\nou de la commission de l’infraction terroriste sont confisqués au profit du\nTrésor public par la juridiction de jugement, selon les modalités prévues par\nl’article 45 de la Loi n° 2004-41 du 8 juin 2004 portant lutte contre le\nblanchiment de capitaux.","[CPPN] Art. 605.11 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) Sauf dans le\ncas prévu à l’article 399.1.20 du code pénal, en matière terroriste, il ne\npourra être fait application des dispositions relatives aux circonstances\natténuantes et au sursis.\n\nCode de procédure pénale","[CPPN] Art. 605.11 (bis) : (Loi n° 2016-21 du 16 juin 2016) En cours d’instruction,\nle juge d’instruction du pôle judiciaire spécialisé peut, par ordonnance, interdire\nà toute personne mise en cause de sortir du territoire national.\nSection III : Du jugement\n(Loi n° 2016-21 du 16 juin 2016)","[CPPN] Art. 605.11 (ter) : (Loi n° 2016-21 du 16 juin 2016) La procédure du\njugement à suivre devant le pôle judiciaire spécialisé en matière de lutte\ncontre le terrorisme et la criminalité transnationale organisée est celle du\ndroit commun.\nToutefois, le pôle judiciaire spécialisé en matière de lutte contre le terrorisme\net la criminalité transnationale organisée statue en la forme collégiale.\nLe jugement des procédures en matière de terrorisme et de criminalité\ntransnationale organisée concernant les mineurs est fait conformément aux\ndispositions de la loi sur les juridictions pour mineurs.","[CPPN] Art. 605.11 (quarto) : (Loi n° 2016-21 du 16 juin 2016) En cas de\nbesoin tant en matière d’instruction, que de jugement, le pôle judiciaire\nspécialisé peut faire appel à des assistants spécialistes ou experts, suivant\nleur domaine de compétence, mis à sa disposition par l’autorité compétente.\nSection IV : De l’interdiction de séjour","[CPPN] Art. 605.12 : (Ord. n° 2011-12 du 27 janvier 2011) L’interdiction de\nséjour pourra être prononcée en application des dispositions des articles 26\nà 33 du Code pénal.\nSection V : De la prescription","[CPPN] Art. 605.13 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) L’action\npublique en matière délictuelle se prescrit par dix (10) ans.\nLes peines portées par un arrêt ou un jugement correctionnel en matière\nde terrorisme se prescrivent par quinze (15) ans à compter de la date à\nlaquelle cet arrêt ou jugement est devenu irrévocable.\nL’action publique en matière criminelle se prescrit par vingt (20) ans.\n\nLes peines portées par un arrêt criminel en matière de terrorisme se\nprescrivent par trente (30) ans à compter de la date à laquelle cet arrêt est\ndevenu irrévocable.\nCHAPITRE II 2 : DE LA PROCEDURE DEVANT LES\nCHAMBRES SPECIALISEES EN MATIERE DE LUTTE\nCONTRE LE TERRORISME","[CPPN] Art. 605.14 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) La procédure\nà suivre devant la Chambre de contrôle en matière de lutte contre le terrorisme\net la criminalité transnationale organisée est la même que celle applicable\ndevant la chambre d’accusation, sauf disposition contraire prévue par la loi.\nToutefois, la chambre de contrôle doit se prononcer en matière de détention\nprovisoire dans les plus brefs délais et au plus tard dans les quarante-cinq\n(45) jours suivant la première audience à laquelle l’affaire est appelée,\nfaute de quoi l’inculpé est mis d’office en liberté provisoire, sauf si des\nvérifications concernant sa demande ont été ordonnées ou si des\ncirconstances imprévisibles et insurmontables mettent obstacle au jugement\nde l’affaire dans le délai prévu au présent article.","[CPPN] Art. 605.14 : (bis) : (Loi n° 2016-21 du 16 juin 2016) En cas d’appel\ninterjeté par le parquet du pôle judiciaire spécialisé en matière de lutte\ncontre le terrorisme et la criminalité transnationale organisée contre une\nordonnance de refus d’informer ou de refus de placement en détention, le\ndossier de la procédure est transmis sans délai au parquet général des\nchambres spécialisées.\nSur réquisition spéciale du parquet général, le président de la chambre de\ncontrôle ou en cas d’empêchement le conseiller le plus ancien de la chambre,\nplace immédiatement l’inculpé sous mandat de dépôt, en attendant que\nladite chambre statue sur l’appel. Le cas échéant la chambre statue dans\nles soixante-douze (72) heures sur le maintien du mandat.\nL’appel interjeté par le parquet du pôle judiciaire spécialisé en matière de\nlutte contre le terrorisme et la criminalité transnationale organisée contre\nles ordonnances de non-lieu est suspensif.\nErreur de numérotation des chapitres contenue dans l’Ordonnance n° 2011-12 du 27\njanvier 2011, le Chapitre II est cité deux fois. Et cette eurreur a été reprise dans la loi\nn° 2016-21 du 16 juin 2016.\n\nCode de procédure pénale","[CPPN] Art. 605.15 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) La procédure\nà suivre devant la Chambre de jugement en matière de lutte contre le terrorisme\net la criminalité transnationale organisée est la même que celle applicable\ndevant la Cour d’Assises, à l’exception des règles relatives aux jurés.\nLes mesures de protection sont également applicables aux auxiliaires de\njustice, aux victimes, aux témoins ou à toute personne qui se serait chargée,\nà quelque titre que ce soit, d’alerter les autorités compétentes.\nLesdites mesures sont étendues le cas échéant aux membres des familles\ndes personnes visées aux deux alinéas précédents et à tous ceux pouvant\nêtre ciblés parmi leurs proches.\nLe service central de lutte contre le terrorisme et la criminalité transnationale\norganisée est chargé de la mise en œuvre des mesures de protection.\nUn décret pris en Conseil des ministres précise les conditions de mise en\nœuvre desdites mesures et les personnes qui doivent en bénéficier.\nCHAPITRE III (NOUVEAU) : DES MESURES DE\nPROTECTION DES VICTIMES, DES TEMOINS, DES\nEXPERTS, DES PERSONNES QUI COMMUNIQUENT DES\nINFORMATIONS EN MATIERE DE CRIMINALITE\nTRANSNATIONALE ORGANISEE, DU TERRORISME ET DU\nFINANCEMENT DU TERRORISME.\n(Loi n° 2017-07 du 31 mars 2017)","[CPPN] Art. 605.16 : (Loi n° 2017-07 du 31 mars 2017) Les mesures nécessaires\nà la protection des personnes auxquelles la loi a confié la constatation et la\nrépression des infractions terroristes doivent être prises.\nLes mesures de protection sont également applicables aux auxiliaires de\njustice, victimes, témoins ou à toute personne qui se serait chargée, à quelque\ntitre que ce soit, d’alerter les autorités compétentes.\nLesdites mesures sont étendues, le cas échéant, aux membres des familles\ndes personnes visées aux deux alinéas précédents et à tous ceux pouvant\nêtre ciblés parmi leurs proches.\n\nLe service central de lutte contre le terrorisme et la criminalité transnationale\norganisée est chargé de la mise en œuvre des mesures de protection.","[CPPN] Art. 605.17 : (Loi n° 2017-07 du 31 mars 2017) Dans le cadre de la\nrépression des infractions en matière de criminalité transnationale organisée,\ndu terrorisme et du financement du terrorisme, les victimes, les témoins,\nles experts, les dénonciateurs et leurs proches bénéficient d’une protection\nspéciale de l’Etat contre les actes éventuels de représailles ou d’intimidation.\nLes conditions de cette protection spéciale sont définies par décret pris en\nConseil des ministres.","[CPPN] Art. 605.18 : (Loi n° 2017-07 du 31 mars 2017) En cas de procédure\nportant sur une infraction en matière de criminalité transnationale organisée,\ndu terrorisme et du financement du terrorisme, lorsque l’audition d’une\nvictime, d’un témoin, d’un expert, d’un dénonciateur, est susceptible de\nmettre gravement en danger la vie ou l’intégrité physique de cette personne,\ndes membres de sa famille ou de ses proches, le juge d’instruction, d’office\nou sur réquisition du procureur de la République, peut autoriser que les\ndéclarations de cette personne soient recueillies sans que son identité\nn’apparaisse dans le dossier de la procédure.\nLa décision motivée du juge d’instruction est jointe au procès-verbal\nd’audition des victimes, des témoins, des experts et des dénonciateurs sur\nlequel ne figure pas la signature des intéressés.\nL’identité et l’adresse de la personne sont inscrites dans un autre procèsverbal signé par l’intéressé, qui est versé dans un dossier distinct du dossier\nde la procédure et dans lequel figure la décision du juge d’instruction.\nL’inculpé peut, dans un délai de dix (10) jours, après avoir pris connaissance\nde l’audition, contester le recours à cette procédure devant la chambre\nd’accusation. Si, au vu des pièces de la procédure et de celles figurant\ndans le dossier mentionné à l’alinéa précédent, la chambre d’accusation\nestime la contestation justifiée, elle ordonne l’annulation de l’audition. Elle\npeut également ordonner que l’identité de la victime, du témoin, d","[CPPN] Art. 605.19 : (Loi n° 2017-07 du 31 mars 2017) En aucune circonstance,\nl’identité ou l’adresse d’une victime, d’un témoin, d’un expert, d’un\ndénonciateur ou de ses proches ayant bénéficié de la protection prévue à\nl’article 605.17 ne peut être révélée, sauf dans les conditions prévues à\nl’article 605.20 ci-dessous.","[CPPN] Art. 605.20 : (Loi n° 2017-07 du 31 mars 2017) L’anonymat de la\ndénonciation ou du témoignage n’est pas possible si, au regard des\ncirconstances dans lesquelles l’infraction a été commise ou de la personnalité\nde la victime, du témoin, de l’expert, du dénonciateur, la connaissance de\nl’identité de la personne est indispensable à l’exercice des droits de la\ndéfense.","[CPPN] Art. 605.21 : (Loi n° 2017-07 du 31 mars 2017) Aucune condamnation\nne peut être prononcée sur le seul fondement de déclarations recueillies\nsous anonymat.\nTITRE II : DE LA MANIERE DE PROCEDURE EN CAS DE\nDISPARITION DES PIECES D’UNE PROCEDURE","[CPPN] Art. 606 : Lorsque, par suite d’une cause extraordinaire, des minutes\nd’arrêts ou de jugements rendus en matière criminelle, correctionnelle ou\nde simple police, et non encore exécutés, ou des procédures en cours, ont\nété détruites, enlevées, ou se trouvent égarées, et qu’il n’a pas été possible\nde les rétablir, il est procédé ainsi qu’il suit.","[CPPN] Art. 607 : S’il existe une expédition ou copie authentique du jugement ou de\nl’arrêt, elle est considérée comme minute et en conséquence remise par tout\nofficier public ou tout dépositaire au greffe de la juridiction qui a rendu la\ndécision, sur l’ordre qui lui en est donné par le président de cette juridiction.\nCet ordre lui sert de décharge.\nLe dépositaire de l’expédition ou de la copie authentique de la minute\ndétruite, enlevée ou égarée, aura la liberté, en la remettant au greffe, de\ns’en faire délivrer une expédition sans frais.\n\nCode de procédure pénale","[CPPN] Art. 608 : Lorsqu’il n’existe plus d’expédition ni de copie authentique de\nl’arrêt ou du jugement, il est procédé, au vu des mentions portées au plumitif\nd’audience, au prononcé d’un nouvel arrêt ou jugement.","[CPPN] Art. 609 : Lorsque les mentions portées au plumitif sont insuffisantes ou\nne peuvent plus être représentées, l’instruction est recommencée à partir\ndu point où les pièces se trouvent manquer.\nTITRE III : DE LA MANIERE DONT SONT RECUES LES\nDEPOSITIONS DES MEMBRES DU GOUVERNEMENT, DES\nREPRESENTANTS DES PUISSANCES ETRANGERES","[CPPN] Art. 610 : Les membres du Gouvernement ne peuvent comparaître comme\ntémoins qu’après l’autorisation du Président de la République. Cette\nautorisation est donnée par décret.","[CPPN] Art. 611 : Lorsque la comparution a lieu en vertu de l’autorisation prévue\nà l’article précédent, la déposition est reçue dans les formes ordinaires.","[CPPN] Art. 612 : Lorsque la comparution n’a pas été demandée ou n’a pas été\nautorisée, la déposition est reçue par écrit dans la demeure du témoin ou à son\nbureau ministériel par le président de la Cour d’appel ou, si le témoin réside\nhors du chef-lieu de la Cour d’appel, par le président du tribunal de sa résidence.\nIl sera, à cet effet, adressé par la juridiction saisie de l’affaire au magistrat\nci-dessus désigné, un exposé des faits ainsi qu’une liste des demandes et\nquestions sur lesquelles le témoin est requis.","[CPPN] Art. 613 : La déposition ainsi reçue est immédiatement remise au greffe ou\nenvoyée, close et cachetée, à celui de la juridiction requérante et communiquée,\nsans délai, au ministère public, ainsi qu’aux parties intéressées.\nA la Cour d’assises, elle est lue publiquement et soumise aux débats.","[CPPN] Art. 614 : La déposition écrite d’un représentant d’une puissance étrangère\nest demandée par l’entremise de l’autorité chargée de la politique étrangère.\nSi la demande est agréée, cette déposition est reçue par le président de la\nCour d’appel ou par le magistrat qu’il aura délégué.\nIl est alors procédé dans les formes prévues aux articles 612, alinéa 2, et 613.\n\nTITRE IV : DES REGLEMENTS DE JUGES","[CPPN] Art. 615 : Lorsque deux juges d’instruction, appartenant à des tribunaux\ndifférents, se trouvent simultanément saisis de la même infraction, le\nministère public peut, dans l’intérêt d’une bonne administration de la justice,\nrequérir l’un des juges de se dessaisir au profit de l’autre. Si le conflit de\ncompétence subsiste, il est réglé de juges conformément aux articles 616 à\n620.","[CPPN] Art. 616 : Lorsque deux tribunaux correctionnels, deux juges d’instruction\nou deux tribunaux de simple police se trouvent saisis simultanément de la\nmême infraction, il est réglé de juges par la Chambre d’accusation qui\nstatue sur requête présentée par le ministère public, l’inculpé ou la partie\ncivile. Cette décision n’est susceptible d’un recours en cassation.","[CPPN] Art. 617 : Lorsqu’après renvoi ordonné par le juge d’instruction devant le\ntribunal correctionnel ou le tribunal de simple police cette juridiction de\njugement s’est, par décision devenue définitive, déclarée incompétente, il\nest réglé de juges par la Chambre d’accusation. Cette décision n’est pas\nsusceptible d’un recours en cassation.","[CPPN] Art. 618 : (Loi n° 69-5 du 18 février 1969). Hors les cas prévus aux\narticles 616 et 617, tous conflits de compétence sont portés devant la Cour\nsuprême, laquelle est saisie par requête du ministère public, de l’inculpé ou\nde la partie civile. La Cour suprême peut aussi, à l’occasion d’un pourvoi\ndont elle est saisie, régler de juges d’office et même par avance. Elle peut\nstatuer sur tous actes faits par la juridiction qu’elle dessaisit.","[CPPN] Art. 619 : (Loi n° 69-5 du 18 février 1969). La Cour suprême peut,\navant de régler de juges, ordonner la communication de la requête aux\nparties. Dans ce cas, les pièces de la procédure lui sont transmises, dans le\ndélai par elle fixé, avec les observations des intéressés, et le cours de la\nprocédure est suspendu.","[CPPN] Art. 620 : (Loi n° 69-5 du 18 février 1969). L’arrêt portant règlement\nde juges est signifié aux parties intéressées. Celles-ci peuvent, hors le cas\noù la communication de la requête a été ordonnée, former opposition à cet\narrêt, par acte reçu au greffe du lieu où siège l’une des juridictions en\nconflit, dans les formes et délais du pourvoi en cassation.\n\nL’opposition emporte effet suspensif si la Cour suprême en décide ainsi.\nL’opposition est jugée dans les quinze jours de l’arrivée des pièces au greffe\nde la Cour suprême.\nTITRE V : DES RENVOIS D’UN TRIBUNAL A UN AUTRE","[CPPN] Art. 621 : En matière criminelle, correctionnelle ou de simple police, la\nCour suprême peut dessaisir toute juridiction d’instruction ou de jugement\net renvoyer la connaissance de l’affaire à une autre juridiction du même\nordre, soit si la juridiction normalement compétente ne peut être légalement\ncomposée, ou si le cours de la justice se trouve autrement interrompu, soit\npour cause de suspicion légitime.\nLa requête aux fins de renvoi peut être présentée soit par le procureur\ngénéral près la Cour suprême, soit par le ministère public établi près la\njuridiction saisie, soit par l’inculpé, soit par la partie civile.\nLa requête doit être signifiée à toutes parties intéressées qui ont un délai\nde trente jours pour déposer un mémoire au greffe de la Cour suprême.\nLa présentation de la requête n’a point d’effet suspensif à moins qu’il n’en\nsoit autrement ordonné par la Cour suprême.\nEn cas de rejet d’une demande de renvoi pour cause de suspicion légitime,\nla Cour suprême peut cependant ordonner le renvoi dans l’intérêt d’une\nmeilleure administration de la justice.","[CPPN] Art. 622 : Lorsqu’un condamné à une peine privative de liberté est détenu\nau siège de la juridiction qui a prononcé cette condamnation, définitive ou\nnon, le procureur de la République, le juge d’instruction, les tribunaux de ce\nlieu de détention, auront compétence, en dehors des règles prescrites par\nles articles 42, 47 et 363, alinéa premier, pour connaître de toutes les\ninfractions qui lui sont imputées.","[CPPN] Art. 623 : Lorsqu’un condamné à une peine privative de liberté est détenu\nsans que l’article 622 puisse recevoir application, il doit être procédé comme\nen matière de suspicion légitime, mais à la demande du ministère public\nseulement, en vue du renvoi de la procédure de la juridiction saisie du lieu\nde détention.\n\nCode de procédure pénale","[CPPN] Art. 624 : Le renvoi peut être également ordonné pour cause de sûreté\npublique par la Cour suprême, mais seulement à la requête de son procureur\ngénéral.","[CPPN] Art. 625 : Tout arrêt qui a statué sur une demande en renvoi pour l’une\ndes causes précitées sera signifié aux parties intéressées à la diligence du\nprocureur général près la Cour suprême.","[CPPN] Art. 626 : L’arrêt qui a rejeté une demande en renvoi pour sûreté publique\nn’exclut pas une nouvelle demande en renvoi fondée sur des faits survenus\ndepuis.\nTITRE VI : DE LA RECUSATION","[CPPN] Art. 627 : Tout juge ou conseiller peut être récusé pour les causes ciaprès :\n1) si le juge ou son conjoint sont parents ou alliés de l’une des parties ou de\nson conjoint jusqu’au degré de cousin issu de germain inclusivement.\nLa récusation peut être exercée contre le juge, même au cas de divorce ou\nde décès de son conjoint, s’il a été allié d’une des parties jusqu’au deuxième\ndegré inclusivement;\n2) si le juge ou son conjoint, si les personnes dont il est tuteur, subrogé\ntuteur, curateur ou conseil judiciaire, si les sociétés ou associations à\nl’administration ou à la surveillance desquelles il participe ont intérêt dans\nla contestation;\n3) si le juge ou son conjoint est parent ou allié, jusqu’au degré indiqué cidessus, du tuteur, subrogé tuteur, curateur ou conseil judiciaire d’une des\nparties ou d’un administrateur, directeur ou gérant d’une société, partie en\ncause;\n4) si le juge ou son conjoint se trouve dans une situation de dépendance\nvis-à-vis des parties;\n5) si le juge a connu du procès comme magistrat, arbitre ou conseil, ou s’il\na déposé comme témoin sur les faits du procès;\n6) s’il y a eu procès entre le juge, son conjoint, leurs parents ou alliés en\nligne directe, et l’une des parties, son conjoint ou ses parents ou alliés dans\nla même ligne;\n\n7) si le juge ou son conjoint ont un procès devant un tribunal où l’une des\nparties est juge;\n8) si le juge ou son conjoint, leurs parents ou alliés en ligne directe ont un\ndifférend sur pareille question que celle débattue","[CPPN] Art. 628 : L’inculpé, le prévenu, l’accusé et toute partie à l’instance qui\nveut récuser un juge d’instruction, un juge de simple police, un juge du\ntribunal correctionnel, des conseillers de la Cour d’appel ou de la Cour\nd’assises doit, à peine de nullité, présenter requête au président de la Cour\nd’appel.\nLes magistrats du ministère public ne peuvent être récusés.\nLa requête doit désigner nommément le ou les magistrats récusés et contenir\nl’exposé des moyens invoqués avec toutes les justifications utiles à l’appui\nde la demande.\nLa partie qui aura procédé volontairement devant une cour, un tribunal ou\nun juge d’instruction ne sera reçue à demander la récusation qu’à raison\ndes circonstances survenues depuis, lorsqu’elles seront de nature à constituer\nune cause de la récusation.","[CPPN] Art. 629 : Le président notifie en la forme administrative la requête dont il\na été saisi au président de la juridiction à laquelle appartient le magistrat\nrécusé.\nLa requête en récusation ne dessaisit pas le magistrat dont la récusation\nest proposée.\nToutefois, le président peut, après avis du procureur général, ordonner qu’il\nsera sursis soit à la continuation de l’information ou des débats, soit au\nprononcé du jugement.","[CPPN] Art. 630 : Le président reçoit le mémoire complémentaire du demandeur,\ns’il y a lieu, et celui du magistrat dont la récusation est proposée; il prend\nl’avis du procureur général et statue sur la requête.\nL’ordonnance statuant sur la récusation n’est susceptible d’aucune voie de\nrecours. Elle produit effet de plein droit.\n\nCode de procédure pénale","[CPPN] Art. 631 : Toute demande de récusation visant le président de la Cour\nd’appel doit faire l’objet d’une requête adressée au président de la Chambre\njudiciaire de la Cour suprême qui, après avis du procureur général près\nladite cour, statue sur une ordonnance laquelle n’est susceptible d’aucune\nvoie de recours. Les dispositions de l’article 629 sont applicables.","[CPPN] Art. 632 : Toute ordonnance rejetant une demande de récusation prononce\nla condamnation du demandeur à une amende civile de 10.000 à 100.000\nfrancs.","[CPPN] Art. 633 : Aucun des juges ou conseillers visés à l’article 627 ne peut se\nrécuser d’office sans l’autorisation du président de la Cour d’appel dont la\ndécision, rendue après avis du procureur général, n’est susceptible d’aucune\nvoie de recours.\nTITRE VII : DU JUGEMENT DES INFRACTIONS\nCOMMISES A L’AUDIENCE DES COURS ET TRIBUNAUX","[CPPN] Art. 634 : Sous réserve des dispositions des articles 329 et 443, les\ninfractions commises à l’audience sont jugées, d’office ou sur les réquisitions\ndu ministère public, suivant les dispositions ci-après, nonobstant toutes règles\nspéciales de compétence ou de procédure.","[CPPN] Art. 635 : S’il se commet une contravention de simple police pendant la\ndurée de l’audience, le tribunal ou la Cour dresse procès-verbal du fait,\nentend le prévenu, les témoins, le ministère public et éventuellement le\ndéfenseur, et applique sans désemparer les peines portées par la loi.","[CPPN] Art. 636 : Si le fait commis pendant la durée de l’audience d’un tribunal\ncorrectionnel ou d’une Cour est un délit, il peut être procédé comme il est\ndit à l’article précédent. Dans ce cas, si la peine prononcée est supérieure\nà un mois d’emprisonnement, un mandat de dépôt peut être décerné.\nSi le fait, qualifié de délit, a été commis à l’audience d’un tribunal de simple\npolice, le président en dresse procès-verbal, qu’il transmet au procureur de\nla République; il peut, si la peine encourue est supérieure à trois mois\nd’emprisonnement, ordonner l’arrestation de l’auteur et sa conduite\nimmédiate devant le procureur de la République.\n\nCode de procédure pénale","[CPPN] Art. 637 : Si le fait commis est un crime, la Cour ou le tribunal, après avoir\nfait arrêter l’auteur, l’interroge et dresse procès-verbal des faits; cette\njuridiction transmet les pièces et ordonne la conduite immédiate de l’auteur\ndevant le procureur de la République compétent qui requiert l’ouverture\nd’une information.\nTITRE VIII. DES CRIMES ET DELITS COMMIS PAR DES\nMAGISTRATS ET CERTAINS FONCTIONNAIRES\nArt. 638 (nouveau) : (Loi n° 2016-21 du 16 juin 2016) (Alinéa 1.\nLoi n° 69-5 du 18 février 1969). Lorsqu’un magistrat de l’ordre judiciaire, ou un gouverneur, ou un préfet ou un sultan, ou un chef de province,\nou un chef de canton, ou un chef de groupement, est susceptible d’être\ninculpé d’un crime ou délit commis hors ou dans l’exercice de ses fonctions, le procureur de la République saisi de l’affaire transmet sans délai le\ndossier au procureur général près la Cour de cassation qui reçoit compétence pour engager et exercer l’action publique.\nS’il estime qu’il y a lieu à poursuite ou s’il y a plainte avec constitution\nde partie civile, le procureur général requiert l’ouverture d’une information.\nCelle-ci est commune aux complices de la personne poursuivie, alors même\nqu’ils n’exerceraient point de fonctions judiciaires ou administratives.\nLa chambre judiciaire de la Cour de cassation est chargée de cette\ninformation. Elle commet un de ses membres qui prescrira tous actes d’instruction nécessaires, dans les formes et conditions prévues par le chapitre\npremier du titre III du","[CPPN] Art. 639 : Lorsque l’instruction est terminée, la Chambre peut :\n- soit dire qu’il n’y a lieu à suivre;\n- soit, si l’infraction retenue à la charge de l’inculpé constitue un délit, le\nrenvoyer devant une juridiction correctionnelle du premier degré autre que\ncelle dans la circonscription de laquelle l’inculpé exerçait ses fonctions;\n- soit, si l’infraction retenue à la charge de l’inculpé constitue un crime,\nsaisir une Cour d’assises.\nEn cas de renvoi devant la juridiction criminelle, elle désigne une Cour\nd’assises autre que celle dans le ressort de laquelle l’accusé exerçait ses\nfonctions.\nLes arrêts prononcés par la Cour suprême, dans les cas prévus par les\nprécédents articles, ne sont susceptibles d’aucun recours.","[CPPN] Art. 640 : Lorsqu’un officier de police judiciaire est susceptible d’être\ninculpé d’un crime ou d’un délit, qui aurait été commis dans la circonscription\noù il est territorialement compétent, hors ou dans l’exercice de ses fonctions,\nle procureur de la République saisi de l’affaire présente sans délai requête\nà la Cour suprême qui procède et statue comme en matière de règlement\nde juges et désigne la juridiction chargée de l’instruction ou du jugement de\nl’affaire.\nLa Cour suprême se prononce dans la huitaine qui suit le jour auquel la\nrequête lui est parvenue.","[CPPN] Art. 641 : Jusqu’à la désignation de la juridiction compétente comme il est\ndit ci-dessus, la procédure est suivie conformément aux règles de\ncompétence du droit commun.\nTITRE IX : DES CRIMES ET DELITS COMMIS A\nL’ETRANGER","[CPPN] Art. 642 : Tout ressortissant du Niger qui, en dehors du territoire de la\nRépublique, s’est rendu coupable d’un fait qualifié crime puni par la loi du\nNiger, peut être poursuivi et jugé par les juridictions du Niger.\n\nTout ressortissant du Niger qui, en dehors du territoire de la République,\ns’est rendu coupable d’un fait qualifié délit par la loi du Niger, peut être\npoursuivi et jugé par les juridictions du Niger si le fait est puni par la législation\ndu pays où il a été commis.\nLes dispositions des alinéas 1 et 2 sont applicables à l’auteur du fait qui n’a\nacquis la qualité de national du Niger que postérieurement au fait qui lui est\nimputé.\nArt. 642-1.-(Loi n°2003-26 du 13 juin 2003) Tout étranger qui hors du\nterritoire de la République s’est rendu coupable d’un crime, soit comme\nauteur, soit comme complice, peut être poursuivi et jugé d’après les\ndispositions des lois nigériennes, lorsque la victime est de nationalité\nnigérienne.","[CPPN] Art. 642.13 : (Loi n° 2016-21 du 16 juin 2016) Tout étranger qui, hors\ndu territoire de la République, s’est rendu coupable d’un acte de torture,\npeut être poursuivi et jugé, d’après les dispositions des lois du Niger ou\napplicables au Niger, s’il se trouve sur le territoire ou sous la juridiction de\nla République et s’il n’est pas extradé vers l’État dont il est un ressortissant\nou sur le territoire duquel le crime a été commis ou dont la victime est un\nressortissant.","[CPPN] Art. 643 : Quiconque s’est, sur le territoire de la République, rendu complice\nd’un crime ou d’un délit commis à l’étranger, peut être poursuivi et jugé par\nles juridictions du Niger si le fait est puni à la fois par la loi étrangère et par\nla loi du Niger, à la condition que le fait qualifié crime ou délit ait été constaté\npar une décision définitive de la juridiction étrangère.","[CPPN] Art. 644 : En cas de délit commis contre un particulier, la poursuite ne\npeut être intentée qu’à la requête du ministère public; elle doit être précédée\nd’une plainte de la partie offensée ou d’une dénonciation officielle à l’autorité\ndu Niger par l’autorité du pays où le fait a été commis.","[CPPN] Art. 645 : Dans les cas visés aux articles précédents, qu’il s’agisse d’un\ncrime ou d’un délit, aucune poursuite n’a lieu si l’inculpé justifie qu’il a été\njugé définitivement à l’étranger et, en cas de condamnation, qu’il a subi ou\nprescrit sa peine ou obtenu sa grâce.\n\nErreur de numérotation, il existait un article 642.1 depuis la modification de 2003.\n\nCode de procédure pénale","[CPPN] Art. 646 : Est réputée commise sur le territoire de la République, toute\ninfraction dont un acte caractérisant un de ses éléments constitutifs a été\naccompli au Niger.","[CPPN] Art. 647 : Tout étranger, qui, hors du territoire de la République, s’est\nrendu coupable soit comme auteur, soit comme complice, d’un crime ou\nd’un délit attentatoire à la sûreté de l’Etat ou de contrefaçon du sceau de\nl’Etat, de monnaies nationales ayant cours, peut être poursuivi et jugé d’après\nles dispositions des lois du Niger ou applicables au Niger, s’il est arrêté au\nNiger ou si le Gouvernement obtient son extradition.","[CPPN] Art. 648 : Tout ressortissant du Niger qui s’est rendu coupable de délits et\ncontraventions en matière forestière, rurale, de pêche, de douanes, de\ncontributions indirectes, sur le territoire de l’un des Etats limitrophes, peut\nêtre poursuivi et jugé au Niger, d’après la loi du Niger, si cet Etat autorise\nla poursuite des nationaux pour les mêmes faits commis au Niger.\nLa réciprocité sera légalement constatée par des conventions internationales\nou par décret.","[CPPN] Art. 649 : Dans les cas prévus au présent titre, la poursuite est intentée à\nla requête du ministère public du lieu où réside le prévenu ou de sa dernière\nrésidence connue, ou du lieu où il est trouvé.\nLa Cour suprême peut, sur la demande du ministère public, ou des parties,\nrenvoyer la connaissance de l’affaire devant une Cour ou un tribunal plus\nvoisin du lieu du crime ou du délit.\nTITRE X : DE L’EXTRADITION\n(Loi n° 2016-21 du 16 juin 2016)","[CPPN] Art. 649.1 : (Loi n° 2016-21 du 16 juin 2016) En matière d’extradition,\nle ministère de la justice est l’autorité centrale.","[CPPN] Art. 649.2 : (Loi n° 2016-21 du 16 juin 2016) On entend par extradition\nla procédure par laquelle un Etat, appelé Etat requis, accepte de livrer une\npersonne qui se trouve sur son territoire à un autre Etat, l’Etat requérant,\npour que ce dernier puisse poursuivre ou juger cette personne ou, si elle a\ndéjà été condamnée, pour lui faire subir sa peine.\n\nCode de procédure pénale","[CPPN] Art. 649.3 : (Loi n° 2016-21 du 16 juin 2016) Les dispositions du présent\nchapitre s’appliquent également aux points qui n’auraient pas été\nréglementés par les traités.\nL’extradition peut aussi être accordée en vertu de la courtoisie internationale,\nde l’entente de réciprocité ou en se fondant sur les assurances données\npar les autorités compétentes de l’État requérant.","[CPPN] Art. 649.4 : (Loi n° 2016-21 du 16 juin 2016) L’extradition est fondée\nsur la base de traité ou d’accord signé entre le Niger et tout autre Etat.\nSection 1 : Des conditions de fond relatives à l’extradition","[CPPN] Art. 649.5 : (Loi n° 2016-21 du 16 juin 2016) En l’absence de traité ou\nd’accord d’extradition, les conditions, la procédure et les effets de\nl’extradition sont déterminés par les dispositions de la présente section.","[CPPN] Art. 649.6 : (Loi n° 2016-21 du 16 juin 2016) Aucune extradition ne peut\nêtre accordée à un Etat requérant de personnes n’ayant pas fait l’objet :\n- soit d’un jugement ou d’un arrêt de condamnation ;\n- soit d’un acte de procédure renvoyant l’inculpé ou l’accusé devant la\njuridiction répressive ;\n- soit d’un mandat d’arrêt ou de tout autre acte ayant la même force et\ndécerné par l’autorité judiciaire, pourvu que ces actes renferment l’indication\nprécise des faits pour lesquels ils sont délivrés et la date de ces faits.","[CPPN] Art. 649.7 : (Loi n° 2016-21 du 16 juin 2016) L’extradition est accordée\nlorsque :\n- l’infraction pour laquelle elle est demandée est punie par les lois de l’État\nrequérant d’une peine d’emprisonnement ou d’autre forme de privation de\nliberté d’une durée d’au moins deux (2) ans, ou d’une peine plus sévère ;\n- les faits objet de la requête, s’ils sont commis au Niger, constituent une\ninfraction punie d’une peine d’emprisonnement ou d’une autre forme de\nprivation de liberté d’une durée d’au moins deux (2) ans ;\n- en cas de condamnation à une peine d’emprisonnement ou à toute autre\nforme de privation de liberté infligée pour une telle infraction si la durée de\nla peine restant à purger est d’au moins six (6) mois.\n\nCode de procédure pénale","[CPPN] Art. 649.8 : (Loi n° 2016-21 du 16 juin 2016) L’Etat du Niger ne peut\nfaire droit à la demande d’extradition d’un de ses ressortissants. Toutefois,\nl’Etat du Niger accepte de tout autre Etat, une demande de dénonciation\nofficielle afin de soumettre à ses juridictions, dans les meilleurs délais, les\nfaits concernant un de ses ressortissants.","[CPPN] Art. 649.9 : (Loi n° 2016-21 du 16 juin 2016) Lorsqu’un Etat requérant\ndemande l’extradition d’un national et que l’Etat du Niger refuse l’extradition\npour ce motif, il soumet l’affaire sans retard excessif à ses autorités\ncompétentes aux fins de poursuites. Lesdites autorités prennent leur décision\net mènent les poursuites de la même manière que pour toute autre infraction\ngrave en vertu du droit national.\nLes autorités compétentes de l’Etat du Niger coopèrent avec les autorités\ncompétentes de l’autre Etat en matière de procédure et de preuve afin\nd’assurer l’efficacité des poursuites.","[CPPN] Art. 649.10 : (Loi n° 2016-21 du 16 juin 2016) L’Etat du Niger peut\nextrader tout individu non nigérien qui, faisant l’objet d’une poursuite intentée\nau nom de l’État requérant ou d’une condamnation prononcée par ses\ntribunaux, est trouvé sur le territoire national.\nNéanmoins, l’extradition n’est accordée que si l’infraction, cause de la\ndemande, a été commise :\n- soit sur le territoire de l’État requérant par un ressortissant de cet État\nou par un étranger ;\n- soit en dehors de son territoire par un ressortissant de cet État ;\n- soit en dehors de son territoire par un individu étranger à cet État, quand\nl’infraction est au nombre de celles dont la loi nigérienne autorise la poursuite\nau Niger, alors même qu’elles ont été commises par un étranger à l’étranger.","[CPPN] Art. 649.11 : (Loi n° 2016-21 du 16 juin 2016) Peuvent donner lieu à\nextradition :\n1) les faits punis de peines criminelles par la loi de l’État requérant ;\n2) les faits punis de peines correctionnelles par la loi de l’État requérant,\nquand le maximum de la peine encourue, aux termes de cette loi, est de\ndeux (2) ans ou au-dessus, ou, s’il s’agit d’un condamné, quand la peine\n\nprononcée par la juridiction de l’État requérant est égale ou supérieure à\nsix (6) mois d’emprisonnement.\nEn aucun cas l’extradition n’est accordée par l’Etat du Niger si le fait n’est\npas puni par la loi de l’Etat requérant d’une peine criminelle ou\ncorrectionnelle.\nLes faits constitutifs de tentative ou de complicité sont soumis aux règles\nprécédentes, à condition qu’ils soient punissables d’après la loi de l’État\nrequérant et d’après celle de l’État du Niger.\nSi la demande a pour objet plusieurs infractions commises par l’individu\nréclamé et qui n’ont pas encore été jugées, l’extradition n’est accordée\nque si le maximum de la peine encourue, d’après la loi de l’État requérant,\npour l’ensemble de ces infractions, est égal ou supérieur à deux (02) ans\nd’emprisonnement.\nSi l’individu réclamé a fait l’objet, en quelque pays que ce soit, d’une\ncondamnation définitive à deux (02) mois d’emprisonnement, ou plus, pour\nun délit de droit commun, l’extradition est accordée, suivant les règles\nprécédentes, c’est-à-dire seulement pour les crimes ou délits, mais sans\négard au taux de la peine encourue ou prononcée","[CPPN] Art. 649.12 : (Loi n° 2016-21 du 16 juin 2016) Si, pour une infraction\nunique, l’extradition est demandée concurremment par plusieurs États, elle\nest accordée de préférence à l’État contre les intérêts duquel l’infraction\nétait dirigée, ou à celui sur le territoire duquel elle a été commise.\nSi les demandes concurrentes ont pour cause des infractions différentes, il\nest tenu compte, pour décider de la priorité, de toutes circonstances de fait\net, notamment de la gravité relative et du lieu des infractions, de la date\nrespective des demandes, de l’engagement qui serait pris par l’un des États\nrequérants de procéder à la ré extradition, de l’ordre chronologique de\nréception des demandes, de la nationalité de la personne recherchée et\ncelle(s) de la ou des victime (s), du lieu de résidence habituelle de la\npersonne recherchée et de celui ou de ceux de la ou des victime (s).\n\nCode de procédure pénale","[CPPN] Art. 649.13 : (Loi n° 2016-21 du 16 juin 2016) L’extradition n’est\naccordée qu’à la condition que l’individu extradé ne sera ni poursuivi, ni\npuni pour une infraction autre que celle ayant motivé l’extradition.","[CPPN] Art. 649.14 : (Loi n° 2016-21 du 16 juin 2016) Les juridictions\nnigériennes ont compétence pour poursuivre toute infraction dans le cas où\nl’auteur présumé de l’infraction se trouve sur le territoire de l’Etat du Niger\net au cas où celui-ci ne l’extrade pas vers un autre Etat qui en a fait la\ndemande.\nCette compétence est établie indépendamment de la nationalité de l’auteur\nprésumé ou de son statut d’apatride et indépendamment du lieu où l’infraction\na été commise.\nSection 2 : Des motifs du refus d’une extradition demandée","[CPPN] Art. 649.15 : (Loi n° 2016-21 du 16 juin 2016) L’extradition peut être\nrefusée si l’infraction pour laquelle elle est demandée est une infraction à\ncaractère politique.\nSi l’extradition n’est pas accordée pour la raison visée à l’alinéa 1, les\nautorités compétentes du Niger et celles de l’État requérant se concerteront\ncomme il convient dans la perspective de régler cette affaire.\nL’alinéa 1 ne saurait s’appliquer aux infractions pour lesquelles le Niger a\ncontracté l’obligation, en vertu d’une convention multilatérale ou d’un traité\nou d’une entente bilatérale, soit de ne pas considérer celles-ci comme des\ninfractions à caractère politique aux fins de l’extradition, soit de poursuivre\nelle-même le délinquant en lieu et place d’une extradition.","[CPPN] Art. 649.16 : (Loi n° 2016-21 du 16 juin 2016) L’extradition d’une\npersonne peut être refusée, s’il y a de sérieuses raisons de penser que la\ndemande a été présentée aux fins de poursuivre ou de punir cette personne\nen raison de son sexe, de sa race, de sa religion, de sa nationalité, de son\norigine ethnique ou de ses opinions politiques, ou que donner suite à cette\ndemande causerait un préjudice à cette personne pour l’une quelconque de\nces raisons.","[CPPN] Art. 649.17 : (Loi n° 2016-21 du 16 juin 2016) L’extradition d’une\npersonne peut être refusée si :\n\n- la personne recherchée a été ou risque d’être soumise, dans l’État\nrequérant, à la torture ou à un traitement cruel, inhumain ou dégradant ;\n- la personne recherchée ne s’est pas vue donner ou ne se verra pas\ndonner les garanties minimales d’un jugement équitable dans le cadre d’une\nprocédure au pénal engagée dans l’État requérant ;\n- un jugement définitif a été rendu et exécuté à l’encontre de la personne\nrecherchée au Niger ou dans un État tiers suite à l’infraction pour laquelle\nl’extradition est demandée ;\n- les poursuites à l’encontre de la personne recherchée sont prescrites\naux termes du droit nigérien ou de celui de l’État requérant au moment de\nla réception de la demande ;\n- les faits objet de la poursuite ou de la condamnation ont été amnistiés\nau Niger ou par l’autre Etat.","[CPPN] Art. 649.18 : (Loi n° 2016-21 du 16 juin 2016) Avant de refuser de\nfaire droit à une demande d’extradition, L’Etat du Niger consulte, le cas\néchéant, l’Etat requérant afin de lui donner toute possibilité de présenter\nses opinions et de donner des informations à l’appui de ses allégations.","[CPPN] Art. 649.19 : (Loi n° 2016-21 du 16 juin 2016) L’Etat du Niger ne peut\nrefuser de faire droit à une demande d’extradition au seul motif que\nl’infraction est considérée, comme touchant à des questions fiscales.","[CPPN] Art. 649.20 : (Loi n° 2016-21 du 16 juin 2016) Lorsque l’Etat du\nNiger refuse de faire droit à une demande d’extradition portant sur un de\nses ressortissants, il peut néanmoins envisager, sur demande de l’Etat\nrequérant, de faire exécuter lui-même tout ou partie de la peine qui a été\nprononcée conformément à son droit interne.\nSection 3 : De la procédure d’extradition","[CPPN] Art. 649.21 : (Loi n° 2016-21 du 16 juin 2016) La requête aux fins\nd’extradition est adressée par écrit à l’autorité centrale du Niger par l’Etat requérant\net doit être accompagnée des documents et informations suivants à l’appui :\n- une description aussi exacte que possible de la personne recherchée,\ncomplétée par d’autres informations susceptibles d’aider à établir l’identité\net la nationalité de cette personne et l’endroit où celle-ci se trouve ;\n\n- l’extrait des dispositions légales qui prévoient et punissent l’infraction ;\n- l’original ou la copie certifiée du mandat d’arrêt délivré par l’autorité\njudiciaire compétente, un résumé des faits indiquant la date et le lieu de\ncommission de l’infraction, ainsi que le degré de participation de la personne\nrecherchée ;\n- si la personne recherchée a été condamnée pour une infraction, l’original\nou la copie certifiée du jugement ou tout autre document attestant la\ncondamnation ou la peine prononcée, le caractère définitif et exécutoire de\nla peine et la durée dans laquelle cette peine reste à purger ;\n- si la personne recherchée a été condamnée par contumace, la demande\nd’extradition de l’État requérant doit être accompagnée des documents\nvisés aux tirets précédents, complétés par tout document attestant que la\npersonne a été régulièrement citée à l’audience qui a conduit à la décision.","[CPPN] Art. 649.22 : (Loi n° 2016-21 du 16 juin 2016) Dans les vingt-quatre\nheures de l’arrestation, il est procédé, par les soins du Procureur de la\nRépublique, à un interrogatoire d’identité dont il est dressé procès-verbal.\nLe procureur de la République décerne contre cette personne un mandat\nd’écrou extraditionnel.","[CPPN] Art. 649.23 : (Loi n° 2016-21 du 16 juin 2016) La personne est\ntransférée dans le plus bref délai et écrouée à la maison d’arrêt du cheflieu de la Cour d’appel dans le ressort de laquelle elle a été arrêtée.","[CPPN] Art. 649.24 : (Loi n° 2016-21 du 16 juin 2016) La requête d’extradition\nainsi que les pièces produites à l’appui sont transmises par le procureur de\nla République au Procureur général.\nDans les vingt-quatre (24) heures de leur réception, le titre, en vertu duquel\nl’arrestation a lieu, est notifié à la personne.\nLe Procureur général, procède dans le même délai à un interrogatoire dont\nil est dressé procès-verbal.","[CPPN] Art. 649.25 : (Loi n° 2016-21 du 16 juin 2016) La chambre d’accusation\nest saisie sur le champ des procès-verbaux susvisés et de tous autres documents.\nLa personne objet de la requête d’extradition comparaît devant elle dans un\ndélai maximum de huit (08) jours, à compter de la notification des pièces.\n\nSur la demande du ministère public ou du comparant, un délai supplémentaire\nde huit (08) jours peut être accordé, avant les débats. Il est ensuite procédé\nà un interrogatoire dont le procès-verbal est dressé.\nL’audience est publique, à moins qu’il n’en soit décidé autrement, sur la\ndemande du ministère public ou du comparant.\nLe ministère public et l’intéressé sont entendus ; ce dernier peut se faire\nassister d’un avocat inscrit et d’un interprète. Il peut être mis en liberté\nprovisoire à tout moment de la procédure, et conformément aux règles qui\ngouvernent la matière.","[CPPN] Art. 649.26 : (Loi n° 2016-21 du 16 juin 2016) Si, lors de sa comparution,\nl’intéressé déclare renoncer au bénéfice du présent chapitre et consent\nformellement à être livré aux autorités du pays requérant, il lui est donné\nacte par la chambre d’accusation de cette déclaration.\nCopie de cette décision est transmise sans délai par les soins du Procureur\ngénéral au Ministre de la Justice, pour toutes fins utiles.","[CPPN] Art. 649.27 : (Loi n° 2016-21 du 16 juin 2016) Dans le cas contraire,\nla chambre d’accusation donne son avis motivé sur la demande d’extradition.\nSi la chambre estime que les conditions légales ne sont pas remplies, ou\nqu’il y a erreur évidente, elle donne un avis défavorable.\nLe dossier doit être envoyé au Ministère de la justice dans un délai de huit\n(08) jours à compter de la date de la décision de la chambre d’accusation.","[CPPN] Art. 649.28 : (Loi n° 2016-21 du 16 juin 2016) Lorsque la chambre\nd’accusation donne un avis défavorable à la demande d’extradition, celleci ne peut être accordée. L’individu est alors, sans délais, mis en liberté.","[CPPN] Art. 649.29 : (Loi n° 2016-21 du 16 juin 2016) Dans le cas contraire,\nl’extradition est autorisée par décret.\nLorsque, dans le délai d’un (01) mois à compter de la notification de cet\nacte aux autorités compétentes de l’Etat requérant, l’extradé n’a pas été\nreçu par les agents de cet Etat, il est mis en liberté d’office et ne peut être\nréclamé pour la même cause.\n\nCode de procédure pénale","[CPPN] Art. 649.30 : (Loi n° 2016-21 du 16 juin 2016) L’individu arrêté\nprovisoirement dans les conditions prévues par les articles 649.22 et 649.35\ndu présent Code peut, s’il n’a pas lieu de procéder à son extradition, être\nmis en liberté d’office si, dans un délai de vingt (20) jours à dater de son\narrestation, lorsqu’elle aura été opérée à la demande du Gouvernement\nd’un pays limitrophe, l’Etat du Niger ne reçoit l’un des documents\nmentionnés à l’article 649.21 ci-dessus.\nLe délai de vingt (20) jours précité est porté à un mois, si le territoire du\npays requérant est non limitrophe, et à deux (2) mois si ce territoire est\nhors d’Afrique.","[CPPN] Art. 649.31 : (Loi n° 2016-21 du 16 juin 2016) La chambre d’accusation\nest tenue de statuer non seulement sur la demande d’extradition, mais\négalement sur le sort des objets saisis lors de l’arrestation de l’individu\nrecherché.","[CPPN] Art. 649.32 : (Loi n° 2016-21 du 16 juin 2016) L’individu réclamé ne\npourra être remis à l’Etat requérant avant l’expiration d’un délai de quinze\n(15) jours à compter du jour où la chambre d’accusation a donné son avis\nfavorable.","[CPPN] Art. 649.33 : (Loi n° 2016-21 du 16 juin 2016) Lorsque la personne\nrecherchée est arrêtée conformément à l’article 649.22 ci-dessus et l’article\n649.35 ci-dessous et sur demande de l’État requérant, les locaux dans\nlesquels cette personne a été trouvée font l’objet d’une fouille et tous les\nbiens trouvés en sa possession ou découverts ultérieurement, sont saisis,\ns’il y a des motifs suffisants de croire que ces biens :\n- ont été acquis en conséquence de l’infraction pour laquelle l’arrestation\nprovisoire à des fins d’extradition a été demandée ou pour laquelle la\ndemande d’extradition correspondante a été présentée;\n- pourront être demandés à titre de preuve destinée à démontrer l’existence\nde l’infraction considérée.","[CPPN] Art. 649.34 : (Loi n° 2016-21 du 16 juin 2016) Lorsqu’il y a lieu à\nl’extradition, tous les objets pouvant servir de pièces à conviction ou\nprovenant de l’infraction et trouvés en la possession de l’individu réclamé\nau moment de son arrestation ou découverts ultérieurement seront saisis et\nà la demande des autorités de l’Etat requérant, remis à celles-ci.\n\nCette remise pourra être effectuée même si l’extradition ne peut s’accomplir\npar suite de l’évasion ou de la mort de l’individu réclamé.\nSeront toutefois réservés les droits que les tiers ont sur lesdits objets qui\ndevront, être rendus le plus tôt possible et sans délai à l’Etat du Niger, à\nl’issue des poursuites exercées dans l’Etat requérant.\nS’il l’estime nécessaire pour une procédure pénale, l’Etat du Niger peut\nretenir temporairement les objets saisis. Il peut, en les transmettant, se\nréserver le droit d’en demander le retour.","[CPPN] Art. 649.35 : (Loi n° 2016-21 du 16 juin 2016) En cas d’urgence et si\nles circonstances le justifient, à la demande des autorités compétentes de\nl’Etat requérant, soit directement, soit par l’entremise des services de\nl’Organisation internationale de Police criminelle (OIPC/INTERPOL) , les\nprocureurs de la République peuvent, sur un simple avis transmis, soit par\nla poste, soit par tout mode de transmission plus rapide laissant une trace\nécrite, ou matériellement équivalente, de l’existence d’une des pièces\nindiquées par l’article 649.21 ci-dessus, procédé à l’arrestation provisoire\nde la personne dont l’extradition est demandée ou de prendre à son égard\ntoutes autres mesures appropriées pour assurer sa présence lors de la\nprocédure d’extradition en attendant l’arrivée de la demande formelle\nd’extradition et des pièces qui l’accompagnent.\nL’individu arrêté provisoirement est placé sous mandat d’écrou\nextraditionnel par le procureur de la République du lieu d’arrestation.\nLa demande formelle d’extradition devra être transmise, en même temps,\npar voie diplomatique, par la poste, par le télégraphe ou par tout mode de\ntransmission laissant une trace écrite, au ministère des affaires étrangères.\nLe procureur de la République doit donner avis de cette arrestation au\nministre de la justice et au procureur général.","[CPPN] Art. 649.36 : (Loi n° 2016-21 du 16 juin 2016) Après la décision de\nl’autorité administrative compétente autorisant l’extradition, et après avoir\nété informée de ses droits et des conséquences légales d’une procédure\nsimplifiée d’extradition par le procureur de la République, la personne\nrecherchée pourra, le cas échéant, consentir à être remise à l’État requérant\nsans suivre la procédure officielle d’extradition visée aux articles 649.26,\n649.27, 649.28 et 649.29 ci-dessus.\n\nLa personne pourra également renoncer expressément à son droit au\nprincipe de spécialité.\nLe procureur de la République saisit alors le procureur général de la Cour\nd’appel, qui saisit la chambre d’accusation pour ordonner la remise de\nl’intéressé à l’Etat requérant.\nSection 4 : Des effets de l’extradition","[CPPN] Art. 649.37 : (Loi n° 2016-21 du 16 juin 2016) Toute personne qui a\nété extradée vers l’Etat du Niger, ne peut faire l’objet ni d’un procès, ni\nd’une peine, ni d’une détention, ni d’une autre peine restrictive sur le\nterritoire national, ni d’une ré-extradition vers un État tiers en raison de\ntoute infraction commise avant son extradition, hormis celle pour laquelle\nelle a été extradée, sauf si :\n- l’Etat ayant procédé à son extradition y a expressément consenti ;\n- la personne extradée, après avoir eu la possibilité de quitter de son plein\ngré le territoire nigérien, ne l’a pas fait, après sa relaxe pour l’infraction pour\nlaquelle elle a été extradée, ou sauf si elle y est retournée de son plein gré ;\n- l’extradition a eu lieu conformément à l’article 649.36 ci-dessus et que\nla personne extradée a renoncé expressément à son droit au principe de\nspécialité.","[CPPN] Art. 649.38 : (Loi n° 2016-21 du 16 juin 2016) Dans le cas où l’Etat\nrequérant demande, pour une infraction antérieure à l’extradition,\nl’autorisation de poursuivre l’individu livré, l’avis de la chambre d’accusation\ndevant laquelle l’inculpé avait comparu est demandé sur la seule production\ndes pièces transmises à l’appui de la nouvelle demande.\nSont également transmises par l‘Etat requérant et soumises à la chambre\nd’accusation, les pièces contenant les observations de l’individu livré ou la\ndéclaration qu’il entend n’en présenter aucune. Ces explications peuvent\nêtre complétées par un avocat de son choix, ou commis d’office.","[CPPN] Art. 649.39 : (Loi n° 2016-21 du 16 juin 2016) L’extradition obtenue\npar l’Etat du Niger est nulle, si elle est intervenue en dehors des cas prévus\npar le présent chapitre.\n\nLa nullité est prononcée, même d’office, par la juridiction d’instruction ou\nde jugement dont l’extradé relève, après sa remise.\nSi l’extradition a été accordée en vertu d’un arrêt ou d’un jugement définitif,\nla nullité est prononcée par la chambre d’accusation dans le ressort de\nlaquelle cette remise a eu lieu.\nLa demande en nullité formulée par l’extradé n’est recevable que si elle\nest présentée dans un délai de trois (3) jours à compter de la mise en\ndemeure qui lui est adressée, aussitôt après son incarcération par le\nProcureur de la République. L’extradé est informé en même temps du\ndroit qui lui appartient de se choisir ou de se faire désigner un défenseur.","[CPPN] Art. 649.40 : (Loi n° 2016-21 du 16 juin 2016) Dans le cas où\nl’extradition est annulée, l’extradé, s’il n’est pas réclamé par l’Etat requis,\nest mis en liberté d’office et ne peut être repris, soit en raison des faits qui\nont motivé son extradition, soit en raison de faits antérieurs, que si dans les\ntrente (30) jours qui suivent sa mise en liberté, il est arrêté sur le territoire\nnational.","[CPPN] Art. 649.41 : (Loi n° 2016-21 du 16 juin 2016) Est considéré comme\nsoumis sans réserve à l’application des lois de l’Etat requérant, en raison\nd’un fait quelconque antérieur à l’extradition et différant l’infraction qui a\nmotivé cette mesure, l’individu livré qui a eu pendant trente (30) jours à\ncompter de son élargissement définitif la possibilité de quitter le territoire\nde cet Etat.","[CPPN] Art. 649.42 : (Loi n° 2016-21 du 16 juin 2016) Lorsqu’un Etat tiers\nsollicite l’extradition d’un individu extradé vers le Niger pour un fait antérieur\nà l’extradition, ou pour un fait autre que celui jugé au Niger, et non connexe\nà ce fait, l’Etat ne défère, s’il y a lieu, à cette requête qu’après s’être\nassuré du consentement de l’Etat par lequel l’extradition a été accordée.\nToutefois, cette réserve n’a pas lieu d’être appliquée lorsque l’individu\nextradé a eu, pendant le délai fixé à l’article précédent, la faculté de quitter\nle territoire national.\n\nCHAPITRE 3 : DU TRANSFEREMENT, DE LA REMISE ET\nDU TRANSIT DES PERSONNES","[CPPN] Art. 649.43 : (Loi n° 2016-21 du 16 juin 2016) Toute personne détenue\nou purgeant une peine sur le territoire national dont la présence est requise\ndans un autre Etat, à des fins d’identification ou de témoignage ou pour qu’elle\napporte de toute autre manière son concours dans l’obtention de preuves dans\nle cadre d’enquêtes, de poursuites ou de procédures judiciaires , peut faire\nl’objet d’un transfèrement si les conditions ci-après sont réunies :\n- ladite personne y consent librement et en toute connaissance de cause ;\n- l’Etat du Niger et l’Etat requérant, y consentent sous réserve des\nconditions qu’ils peuvent juger appropriées.","[CPPN] Art. 649.44 : (Loi n° 2016-21 du 16 juin 2016) L’Etat requérant vers\nlequel le transfèrement d’une personne détenue est effectué a l’obligation\nde la garder en détention, sauf demande ou autorisation contraire de la part\nde l’Etat du Niger à partir duquel elle a été transférée.\nSauf accord contraire, la personne détenue est remise sans délai à l’Etat du\nNiger à partir duquel elle a été transférée lorsque son concours a pris fin.","[CPPN] Art. 649.45 : (Loi n° 2016-21 du 16 juin 2016) Aucune extradition de\nla personne détenue ne pourra être demandée durant le temps de son\ntransfèrement.\nIl est tenu compte de la période que l’intéressé a passé en détention aux\nfins du décompte de la peine à purger.","[CPPN] Art. 649.46 : (Loi n° 2016-21 du 16 juin 2016) Toute personne\ncondamnée et détenue peut faire l’objet de transfèrement dans un autre\nEtat, aux fins de poursuivre l’exécution des peines privatives de libertés,\nrégulièrement et définitivement prononcées contre elle.\nLa demande de transfèrement peut être faite par :\n- l’Etat de condamnation ;\n- l’Etat dont l’intéressé est national;\n- le condamné lui-même ou par son représentant légal. Ces derniers peuvent\nprésenter la demande à l’un ou l’autre des deux Etats de leur choix.\n\nCode de procédure pénale","[CPPN] Art. 649.47 : (Loi n° 2016-21 du 16 juin 2016) Si une personne est\nextradée depuis un État tiers vers un autre État tiers en passant par le\nterritoire du Niger, le transit peut être autorisé par l’Etat du Niger à la\ndemande de l’Etat de destination.\nCette autorisation ne peut être donnée qu’aux Etats qui accordent, sur leur\nterritoire, la même faculté à l’Etat du Niger.\nTITRE XI : DE L’ENTRAIDE JUDICIAIRE","[CPPN] Art. 649.48 : (Loi n° 2016-21 du 16 juin 2016) En matière d’entraide\njudiciaire, le ministère de la justice est l’autorité centrale.","[CPPN] Art. 649.49 : (Loi n° 2016-21 du 16 juin 2016) On entend par entraide\njudiciaire toutes mesures prises par l’Etat requis sur demande de l’Etat\nrequérant, en vue de :\n- réunir des preuves dans le cadre de la poursuite et de la répression\nd’infraction pénale dans l’Etat requérant ;\n- notifier des actes judiciaires et extrajudiciaires provenant de l’étranger\nou destinés à l’étranger, conformément aux conventions ratifiées et aux\nlois et règlements en vigueur.","[CPPN] Art. 649.50 : (Loi n° 2016-21 du 16 juin 2016) L’entraide la plus large\npossible est apportée par l’Etat du Niger à tout État requérant sur la base\nd’un accord ou non.\nElle est également apportée à toute demande d’aide émanant de la Cour\nPénale Internationale ou d’un autre Tribunal International.","[CPPN] Art. 649.51 : (Loi n° 2016-21 du 16 juin 2016) L’entraide la plus large\npossible est accordée lors des enquêtes, poursuites et procédures judiciaires,\nque les demandes d’entraide concernent les personnes physiques ou\nmorales.","[CPPN] Art. 649.52 : (Loi n° 2016-21 du 16 juin 2016) Le ministère de la\njustice accepte toute demande d’aide provenant d’un État requérant faite\npar tout moyen de communication qui en laisse une trace écrite et\nnotamment, à titre indicatif et non exhaustif, par courriel ou télécopie.\n\nIl accepte également toute demande faite par l’entremise des services de\nl’Organisation internationale de Police criminelle (OIPC/INTERPOL) ou\nles réseaux de coopération judiciaire.\nEn cas d’urgence, le ministère de la justice accepte une demande orale\nsous réserve que celle-ci soit confirmée par tout moyen qui en laisse une\ntrace écrite dans les vingt-quatre (24) heures.","[CPPN] Art. 649.53 : (Loi n° 2016-21 du 16 juin 2016) L’entraide judiciaire\npeut être demandée aux fins suivantes :\n- recueillir des témoignages ou des dépositions ;\n- signifier des actes judiciaires ;\n- effectuer des perquisitions, des saisies ainsi que des gels d’avoirs;\n- examiner des objets et visiter des lieux ;\n- fournir des informations, des pièces à conviction et des estimations\nd’experts ;\n- fournir des originaux ou des copies certifiées conformes de documents\net dossiers pertinents, y compris des documents administratifs, bancaires,\nfinanciers ou commerciaux et des documents de sociétés ;\n- identifier ou localiser des produits de l’infraction, des biens, des\ninstruments ou d’autres choses afin de recueillir des éléments de preuve ;\n- faciliter la comparution volontaire de personnes dans l’Etat requérant ;\n- fournir tout autre type d’assistance compatible avec le droit interne de\nl’Etat du Niger ;\n- localiser, identifier et geler le produit de l’infraction conformément aux\ndispositions du présent chapitre.","[CPPN] Art. 649.54 : (Loi n° 2016-21 du 16 juin 2016) Si la demande d’entraide\na pour objet de prendre la déclaration ou le témoignage d’une personne, de\nproduire une preuve documentaire ou autre, d’identifier une personne ou\nun objet, l’autorité compétente prend une ordonnance pour rassembler les\npreuves si elle a l’assurance qu’il existe des motifs raisonnables de croire\nque les preuves se trouvent au Niger.\n\nL’ordonnance indiquera expressément la procédure à observer pour\nrassembler les preuves documentaires de manière à donner effet à la\ndemande.\nElle indiquera également, le cas échéant, les conditions jugées opportunes,\nnotamment celles relatives :\n- aux titres de propriété de la personne nommée dans la demande ou de tiers ;\n- à l’obligation de comparaître à une date, heure et en un lieu expressément\nprécisés pour une vérification ou pour produire des documents ou des objets ;\n- à la désignation de la personne devant laquelle la vérification devra\navoir lieu ;\n- à l’obligation de se présenter dans des installations équipées de vidéo ou\nd’une liaison par satellite ;\n- à l’interdiction de divulguer les informations concernant la demande et\nson exécution.","[CPPN] Art. 649.55 : (Loi n° 2016-21 du 16 juin 2016) Si la demande a pour\nobjet de prendre une déclaration ou un témoignage, notamment d’un expert\nou d’un défendeur, l’autorité compétente permettra le cas échéant, à toute\npersonne sur laquelle porte, l’enquête, les poursuites ou la procédure\nconsidérée, et/ou au représentant légal de cette personne, ou au représentant\nlégal de l’État requérant, de participer à la procédure et d’interroger le\ntémoin.","[CPPN] Art. 649.56 : (Loi n° 2016-21 du 16 juin 2016) L’autorité compétente\npeut ordonner que le témoignage ou la déclaration soient faites, qu’une\npersonne ou un objet soit identifié(e) ou que toute autre forme d’aide soit\napportée par l’utilisation de la technique de transmission vidéo ou\ntéléphonique.\nUne ordonnance prise en application de l’alinéa précédent imposera à la\npersonne de :\n- se présenter à une heure, une date et en un lieu fixés pour faire une\ndéclaration, témoigner ou prêter toute autre aide par vidéoconférence, et\nrester présente jusqu’à ce qu’elle soit dispensée de l’être par les autorités\nde l’État requérant;\n\n- répondre à toutes questions posées par les autorités de l’État requérant\nou par les personnes autorisées à cette fin par lesdites autorités ;\n- produire ou montrer à ces autorités à l’heure, à la date et au lieu fixés\npar l’autorité compétente, toute pièce et notamment tout document ou copie\nde ce dernier.\nLes frais engagés pour établir une liaison par vidéo ou par téléphone, les\nfrais de maintenance d’une liaison vidéo ou par téléphone sont à la charge\nde l’État requérant, sauf accord contraire.","[CPPN] Art. 649.57 : (Loi n° 2016-21 du 16 juin 2016) Si un État requérant\ndemande de procéder à des fouilles et à des saisies, l’autorité compétente\nprend une ordonnance si elle a l’assurance que les preuves afférentes à\nl’enquête, aux poursuites ou à la procédure sont susceptibles d’être trouvées\nau Niger.\nL’autorité compétente peut autoriser des fonctionnaires de l’État requérant\nà assister et participer aux opérations ci-dessus.","[CPPN] Art. 649.58 : (Loi n° 2016-21 du 16 juin 2016) Les requêtes d’entraide\njudiciaire sont adressées par écrit ou, si possible, par tout moyen laissant\ntrace écrite, en français et dans des conditions permettant d’en établir\nl’authenticité.\nEn cas d’urgence et si les Etats en conviennent, les demandes peuvent\nêtre faites oralement, à condition d’être confirmées sans délai par écrit.","[CPPN] Art. 649.59 : (Loi n° 2016-21 du 16 juin 2016) Toute demande d’entraide\njudiciaire doit contenir les renseignements suivants :\n- le nom de l’autorité chargée de l’enquête, des poursuites ou de la\nprocédure judiciaire sur laquelle ou lesquelles porte la demande, et les\ncoordonnées de la personne habilitée à répondre aux questions concernant\nla demande ;\n- un résumé des faits sauf pour les demandes adressées aux fins de\nsignification d’actes judiciaires ;\n- la description des objets de la demande d’aide, de la nature de l’aide\nrequise et le détail de toute procédure particulière que l’Etat requérant\nsouhaite voir appliquée ;\n\n- l’identité, l’adresse et la nationalité de toute personne visée, si possible ;\n- le but dans lequel le témoignage, les informations ou les mesures sont\ndemandés.","[CPPN] Art. 649.60 : (Loi n° 2016-21 du 16 juin 2016) L’autorité compétente\npeut demander un complément d’information, lorsque cela apparaît\nnécessaire pour exécuter la demande ou lorsque cela peut faciliter\nl’exécution.","[CPPN] Art. 649.61 : (Loi n° 2016-21 du 16 juin 2016) Toute demande est\nexécutée conformément à la législation nigérienne et lorsque cela est possible\nconformément aux procédures spécifiées dans la demande.","[CPPN] Art. 649.62 : (Loi n° 2016-21 du 16 juin 2016) Tout témoin, toute\nvictime ou tout expert qui se trouve sur le territoire national, peut être\nentendu par vidéoconférence par les autorités judiciaires à la demande\nd’un Etat requérant, conformément au droit interne nigérien.","[CPPN] Art. 649.63 : (Loi n° 2016-21 du 16 juin 2016) L’Etat requérant ne doit\ncommuniquer, ni utiliser les informations ou les éléments de preuve fournis par\nl’Etat du Niger pour des enquêtes, poursuites ou procédures judiciaires autres\nque celles visées dans la demande d’entraide sans son consentement préalable.","[CPPN] Art. 649.64 : (Loi n° 2016-21 du 16 juin 2016) L’entraide judiciaire\npeut être refusée :\n- si la demande n’est pas faite conformément aux dispositions du présent\nchapitre ;\n- si la demande est susceptible de porter atteinte à la souveraineté, à la\nsécurité, à l’ordre public ou à d’autres intérêts essentiels de l’Etat du Niger ;\n- si le droit interne de l’Etat du Niger interdit à ses autorités de prendre\nles mesures demandées.","[CPPN] Art. 649.65 : (Loi n° 2016-21 du 16 juin 2016) Aucune entraide judiciaire\nne peut être refusée :\n-\n\nau motif du secret bancaire ;\n\n- au seul motif que l’infraction pour laquelle cette aide est recherchée est\nconsidérée comme touchant aussi à des questions fiscales.\n\nCode de procédure pénale","[CPPN] Art. 649.66 : (Loi n° 2016-21 du 16 juin 2016) En matière pénale, les\nautorités judiciaires compétentes peuvent invoquer l’absence de double\nincrimination pour refuser de donner suite à une demande d’entraide\njudiciaire.\nCependant, elles peuvent notamment décider de s’attacher au\ncomportement criminel à l’origine de l’infraction et non à la dénomination\nde l’infraction en droit interne.","[CPPN] Art. 649.67 : (Loi n° 2016-21 du 16 juin 2016) Tout refus d’entraide\njudiciaire doit être motivé.","[CPPN] Art. 649.68 : (Loi n° 2016-21 du 16 juin 2016) L’entraide judiciaire\npeut être différée par l’autorité compétente, au motif qu’elle entraverait\nune enquête, des poursuites ou une procédure judiciaire en cours.","[CPPN] Art. 649.69 : (Loi n° 2016-21 du 16 juin 2016) Avant de refuser une\ndemande ou d’en différer l’exécution au motif qu’elle entraverait une\nenquête, des poursuites ou une procédure judiciaire en cours, l’autorité\ncompétente étudie avec l’Etat requérant la possibilité d’accorder l’entraide\nsous réserve des conditions qu’elle juge nécessaires.","[CPPN] Art. 649.70 : (Loi n° 2016-21 du 16 juin 2016) La demande d’entraide\njudiciaire est exécutée aussi promptement que possible et tient compte,\ndans la mesure du possible, de tous délais suggérés et motivés par l’Etat\nrequérant.\nL’Etat requérant peut présenter des demandes d’informations sur l’état\nd’avancement des mesures prises pour faire droit à sa demande. L’autorité\ncompétente répond aux demandes de l’Etat requérant concernant les progrès\nréalisés dans l’exécution de la demande.\nQuand l’entraide demandée n’est plus nécessaire, l’Etat requérant en\ninforme l’autorité compétente.","[CPPN] Art. 649.71 : (Loi n° 2016-21 du 16 juin 2016) Sauf autorisation de la\nrèglementation en vigueur, toute personne qui, en raison de sa qualité ou de\nses fonctions officielles a connaissance de la nature confidentielle d’une\ndemande d’entraide, ne saurait divulguer sa teneur, sauf si cette divulgation\nest nécessaire pour son exécution.\n\nTout contrevenant aux dispositions de l’alinéa précédent est puni\nconformément aux dispositions du code pénal relatives à la révélation du\nsecret professionnel.","[CPPN] Art. 649.72 : (Loi n° 2016-21 du 16 juin 2016) Les frais ordinaires\nexposés pour exécuter une demande sont à la charge du Trésor National, à\nmoins qu’il en soit convenu autrement entre l’Etat du Niger et l’Etat\nrequérant.\nLorsque des dépenses importantes ou extraordinaires sont ou se révèlent\nultérieurement nécessaires pour exécuter la demande, l’Etat du Niger peut\nconsulter l’Etat requérant pour fixer les conditions selon lesquelles la\ndemande sera exécutée, ainsi que la manière dont les frais seront assumés.","[CPPN] Art. 649.73 : (Loi n° 2016-21 du 16 juin 2016) L’autorité compétente\npeut fournir à l’Etat requérant copie des dossiers, documents ou\nrenseignements administratifs en sa possession auxquels le public a ou non\naccès, conformément au droit interne.\nTITRE XII : DES AUTRES FORMES DE COOPERATION\nCHAPITRE PREMIER : DU TRANSFERT DES\nPROCEDURES PENALES","[CPPN] Art. 649.74 : (Loi n° 2016-21 du 16 juin 2016) L’Etat du Niger peut\ntransférer ou recevoir des procédures relatives à des poursuites d’une\ninfraction dans les cas où ce transfert ou cette réception est jugé nécessaire\ndans l’intérêt d’une bonne administration de la justice et, en particulier\nlorsque plusieurs juridictions sont concernées, en vue de les centraliser\nCHAPITRE 2 : DE LA COOPERATION ENTRE LES\nSERVICES DE DETECTION ET DE REPRESSION","[CPPN] Art. 649.75 : (Loi n° 2016-21 du 16 juin 2016) L’autorité compétente\npeut, sous réserve de réciprocité, coopérer étroitement dans les domaines\ndu renforcement des voies de communication entre les services compétents,\nafin de faciliter l’échange sûr et rapide d’informations concernant tous les\naspects des infractions poursuivies et de la conduite des enquêtes avec\nd’autres Etats.\n\nCode de procédure pénale","[CPPN] Art. 649.76 : (Loi n° 2016-21 du 16 juin 2016) L’Etat du Niger peut\nconclure des accords ou des engagements bilatéraux ou multilatéraux\nprévoyant une coopération directe entre services de détection et de\nrépression.\nCHAPITRE 3 : DES ENQUETES CONJOINTES","[CPPN] Art. 649.77 : (Loi n° 2016-21 du 16 juin 2016) L’Etat du Niger peut\nconclure des accords ou des engagements bilatéraux ou multilatéraux afin\nde mener des enquêtes conjointes.\nEn l’absence de tels accords ou engagements, la possibilité de mener des\nenquêtes conjointes peut être décidée au cas par cas.\nCHAPITRE 4 : DES TECHNIQUES D’ENQUETES\nSPECIALES","[CPPN] Art. 649.78 : (Loi n° 2016-21 du 16 juin 2016) Pour les besoins de\nl’exécution des demandes d’entraide judiciaire, les officiers de police judiciaire\npeuvent procéder, en vertu d’une autorisation écrite d’un Procureur de la\nRépublique, ou d’une commission rogatoire d’un juge d’instruction à :\n- l’interception des communications téléphoniques, des messages\nélectroniques et autres courriers des suspects ou de toute personne en\nrapport avec eux. ;\n-\n\nla livraison surveillée ;\n\n- la surveillance des comptes bancaires ;\n- la surveillance électronique ou d’autres formes de surveillance ;\n- l’infiltration en vue de la recherche d’éléments de preuve.\nToutefois ces mesures ne peuvent pas excéder une durée maximum de\ntrois (3) mois renouvelable, une fois en cas de nécessité.\n\nTITRE XIII : DES PROCEDURES PARTICULIERES\nCONCERNANT LES SAISIES, GELS, CONFISCATIONS ET\nRECOUVREMENTS D’AVOIRS\nSection 1 : Des Procédures de Gestion\nParagraphe 1 : Des Procédures de gestion des données","[CPPN] Art. 649.79 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique ou le juge d’instruction notifie à l’Agence centrale, les biens\nsaisis et le mode de stockage ou de conservation des biens saisis,\néventuellement leur aliénation.\nIls peuvent, sous leur propre responsabilité, charger les services de police\nde cette notification.\nIls informent également l’Agence centrale de gestion des saisies, des\nconfiscations, des gels et des recouvrements d’avoirs en matière pénale de\ntoute nouvelle décision concernant les biens saisis, confisqués, gelés ou les\navoirs recouvrés.","[CPPN] Art. 649.80 : (Loi n° 2016-21 du 16 juin 2016) Les préposés de\nl’administration de l’enregistrement et des domaines ainsi que les services\ndu ministère de la justice chargés de l’exécution des jugements de\ncondamnation emportant la confiscation spéciale des choses se trouvant\nhors du territoire national, informent l’Agence centrale de toutes les données\nutiles se rapportant à l’exécution.\nParagraphe 2 : Des Procédures de gestion à valeur constante\nI. Des généralités","[CPPN] Art. 649.81 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique est responsable de la gestion à valeur constante de biens saisis\nou recouvrés autant qu’une information n’est pas ouverte.\nLe juge d’instruction est responsable de la gestion à valeur constante des\nbiens saisis, gelés ou des avoirs recouvrés pendant l’instruction.\n\nII. De la restitution ou de l’autorisation d’aliéner :\nA. De la restitution ou de l’autorisation d’aliéner d’office :","[CPPN] Art. 649.82 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique ou le juge d’instruction peut, d’office, décider de restituer, sous\ngarantie, les biens saisis, gelés ou les avoirs recouvrés ou autoriser l’Agence\ncentrale à les aliéner.","[CPPN] Art. 649.83 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique dresse, le cas échéant, un procès-verbal de restitution sous\nconditions précises et le juge d’instruction procède par ordonnance motivée,\naprès avoir dûment provoqué les réquisitions du procureur de la République\net informé l’Agence centrale.\nToutefois, l’autorisation d’aliénation ne portera uniquement que sur des\nbiens dont le stockage, même pendant une période limitée, est susceptible\nd’entrainer une dépréciation importante ou dont les frais de conservation\nne sont pas raisonnablement proportionnels à la valeur, et seulement lorsque\nces biens sont remplaçables et leur contre-valeur aisément déterminable.\nB. De la restitution ou de l’autorisation d’aliéner à la demande\n1. De l’Agence centrale","[CPPN] Art. 649.84 : (Loi n° 2016-21 du 16 juin 2016) L’Agence centrale doit,\npour les biens dont le stockage, même pendant une période limitée, est\nsusceptible d’entrainer une dépréciation importante ou dont les frais de\nconservation ne sont pas raisonnablement proportionnels à la valeur, adresser\nune requête pour l’aliénation ou la restitution sous caution de ces biens au\nprocureur de la République ou au juge d’instruction.","[CPPN] Art. 649.85 : (Loi n° 2016-21 du 16 juin 2016) Cette requête est déposée\nau secrétariat du parquet ou au greffe de la juridiction d’instruction et est\ninscrite dans un registre ouvert à cet effet.","[CPPN] Art. 649.86 : L’aliénation prévue à l’article 649.82 ci-dessus est réalisée\ndans le respect des dispositions de l’article 649.121 et suivants ci-dessous.\n\n2. Du Parquet","[CPPN] Art. 649.87 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique peut, d’office pour tout ou partie des biens saisis ou des avoirs\nrecouvrés, demander au juge d’instruction d’autoriser l’Agence centrale\nde procéder à leur aliénation ou à les restituer sous garantie.","[CPPN] Art. 649.88 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique procède aux réquisitions qu’il juge utiles, le cas échéant, après\navoir consulté l’Agence centrale. Il transmet copie de sa demande à\nl’Agence centrale.\n3. De la personne lésée","[CPPN] Art. 649.89 : (Loi n° 2016-21 du 16 juin 2016) Toute personne qui\ns’estime lésée par un acte de poursuite ou d’instruction relatif aux biens\npeut, pour tout ou partie de ces biens saisis, confisqués, gelés ou des avoirs\nrecouvrés, demander au procureur de la République ou au juge d’instruction\nd’autoriser l’Agence centrale à procéder à leur aliénation ou à les restituer\nsous caution.\nLa requête est motivée et contient élection de domicile au Niger.\nLa requête est déposée, selon le cas, au secrétariat du parquet ou au greffe\nde la juridiction d’instruction et est inscrite dans le registre ouvert à cet effet.","[CPPN] Art. 649.90 : (Loi n° 2016-21 du 16 juin 2016) Dans le second cas, le\ngreffier d’instruction communique immédiatement une copie de la requête\net des notifications au procureur de la République et à l’Agence centrale.","[CPPN] Art. 649.91 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique procède aux réquisitions qu’il juge utiles, le cas échéant, après\navoir consulté l’Agence centrale.\nC. De la procédure à suivre devant le Parquet","[CPPN] Art. 649.92 : (Loi n° 2016-21 du 16 juin 2016) Lorsque le procureur\nde la République reçoit la requête de la personne qui s’estime lésée ou de\nl’Agence centrale, il en informe immédiatement les personnes qui font l’objet\nde la saisie ou des avoirs recouvrés, si elles sont identifiables, les personnes\nchez lesquelles ou entre les mains desquelles les biens ont été saisis et les\npersonnes qui, d’après les données du dossier se sont expressément\nmanifestées comme étant lésées par l’acte de poursuite.\n\nCode de procédure pénale","[CPPN] Art. 649.93 : (Loi n° 2016-21 du 16 juin 2016) Lorsque les biens saisis\nou les avoirs recouvrés sont des immeubles, il en informe également les\ncréanciers qui sont connus selon l’état hypothécaire.","[CPPN] Art. 649.94 : (Loi n° 2016-21 du 16 juin 2016) La notification est\nadressée par tout moyen de communication laissant trace et justifiant la\nréception, à ces personnes et, le cas échéant, à leurs conseils.","[CPPN] Art. 649.95 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique transmet, en cas de demande provenant de la personne lésée,\ncopie de la requête et des notifications à l’Agence centrale.","[CPPN] Art. 649.96 : (Loi n° 2016-21 du 16 juin 2016) Les personnes auxquelles\nla notification est adressée, l’Agence centrale ainsi que toutes les personnes\nqui font preuve d’intérêts, peuvent faire connaitre au procureur de la\nRépublique leurs objections à l’autorisation demandée dans un délai de\ncinq (05) jours francs à compter de la date de la notification, si ces personnes\nsont domiciliées dans la localité où siège le parquet et trente (30) jours\nfrancs si elles sont domiciliées dans tout autre lieu du territoire national.\nSi une des personnes se trouve à l’étranger, le délai est porté à soixante\n(60) jours francs.","[CPPN] Art. 649.97 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique se prononce dans les cinq (5) jours francs après l’expiration\ndes délais prévue à l’article ci-dessus.","[CPPN] Art. 649.98 : (Loi n° 2016-21 du 16 juin 2016) La décision motivée est\ncommuniquée à l’Agence centrale et notifiée par lettre recommandée au\nrequérant, aux personnes auxquelles la notification a été adressée ou qui\nont fait connaitre leur objection et, le cas échéant, à leur conseils dans le\ndélai de huit (08) jours francs à compter de la décision.","[CPPN] Art. 649.99 : (Loi n° 2016-21 du 16 juin 2016) S’il constate que les\nnécessités de l’enquête s’y opposent, ou si l’aliénation ou la restitution\nsous garantie compromet la sauvegarde des droits des parties ou des tiers\nou si la restitution sous garantie présente un danger pour les personnes ou\nles biens ou si les biens ne satisfont pas aux conditions posées, le procureur\nde la République peut refuser de restituer, d’autoriser l’aliénation ou rejeter\ncatégoriquement la requête introduite à cet effet.\n\nToutefois, il peut décider d’une aliénation ou d’une restitution sous garantie\ntotale, partielle ou assortie de conditions.","[CPPN] Art. 649.100 : (Loi n° 2016-21 du 16 juin 2016) Dans tous les cas, les\ndécisions de refus de restituer, d’autoriser l’aliénation ou de rejet rendues\npar le procureur de la République ne sont pas susceptibles de recours.\nD. De la procédure à suivre devant la juridiction d’instruction","[CPPN] Art. 649.101 : (Loi n° 2016-21 du 16 juin 2016) Nonobstant les\nprérogatives de l’Agence centrale, le procureur de la République, peut,\ndans les conditions de l’article 649.82 ci-dessus, d’office ou après demande\nde l’Agence centrale, adresser au juge d’instruction des réquisitions afin\nde procéder à l’aliénation ou à la restitution sans caution.\nLe cas échéant, il communique une copie de ses réquisitions à l’Agence\ncentrale.","[CPPN] Art. 649.102 : (Loi n° 2016-21 du 16 juin 2016) Lorsque le juge\nd’instruction reçoit une requête, de l’Agence centrale, de la personne lésée\nou des réquisitions du ministère public tendant à l’aliénation ou la restitution\navec ou sans caution, il en informe immédiatement les personnes qui font\nl’objet de la saisie, du gel ou des avoirs recouvrés, si elles sont identifiables,\nles personnes chez qui ou entre les mains de qui les biens ont été saisis et\nles personnes qui, d’après les données du dossier se sont expressément\nmanifestées comme étant lésées par l’acte d’instruction.","[CPPN] Art. 649.103 : (Loi n° 2016-21 du 16 juin 2016) Lorsque la saisie ou\nles recouvrements des avoirs porte sur un immeuble, il en informe également\nles créanciers qui sont connus selon l’état hypothécaire.","[CPPN] Art. 649.104 : (Loi n° 2016-21 du 16 juin 2016) La notification est\nadressée par tout moyen de communication laissant trace et justifiant la\nréception et, le cas échéant, à leurs conseils.","[CPPN] Art. 649.105 : (Loi n° 2016-21 du 16 juin 2016) Les personnes\nauxquelles la notification est adressée ainsi que toutes les personnes qui\nfont preuve d’intérêts, peuvent faire connaitre au juge d’instruction leurs\nobjections à l’autorisation demandée dans un délai de quinze (15) jours\nfrancs à compter de l’envoi de la notification, si ces personnes sont\n\ndomiciliées dans la localité où siège la juridiction d’instruction, un mois (01)\nsi elles sont domiciliées dans tout autre endroit du territoire national. Si, une\nde ces personnes se trouve à l’étranger, le délai est porté à soixante (60)\njours francs.","[CPPN] Art. 649.106 : (Loi n° 2016-21 du 16 juin 2016) Le juge d’instruction\nstatue par ordonnance, dans les dix (10) jours francs suivant sa saisine.\nL’ordonnance motivée est communiquée par le greffier au procureur de la\nRépublique et à l’Agence centrale et notifiée par tout moyen de communication\nlaissant trace et justifiant la réception au requérant (lorsqu’il s’agit de la\npersonne lésée), aux personnes auxquelles la notification a été adressée ou\nqui ont fait connaitre leurs objections et, le cas échéant, leurs conseils dans\nun délai de huit (8) jours francs à compter de la date de la décision.\nDans tous les cas, les décisions du juge d’instruction peuvent faire l’objet\nd’appel devant la chambre d’accusation de la Cour d’appel.","[CPPN] Art. 649.107 : (Loi n° 2016-21 du 16 juin 2016) Le juge d’instruction\npeut décider de l’aliénation ou de la restitution sous garantie totale, partielle\nou assortie de conditions.","[CPPN] Art. 649.108 : (Loi n° 2016-21 du 16 juin 2016) Lorsque le juge d’instruction\ndécide, d’office, d’autoriser l’aliénation ou la restitution sous garantie ou lorsqu’il\naccède à la demande ou à la réquisition, il peut prononcer l’exécution provisoire\nde l’ordonnance, si un retard conduit à un préjudice irréparable.","[CPPN] Art. 649.109 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique et les personnes visées aux articles 649.91 et 649.105 ci-dessus\npeuvent interjeter appel contre l’ordonnance du juge d’instruction dans les\nquinze jours. Pour le procureur de la République, ce délai commence à\ncourir le jour où l’ordonnance lui est communiquée et pour les personnes\nvisées à l’article 649.105 ci-dessus, le jour ou l’ordonnance leur est notifiée.\nL’appel est interjeté par simple déclaration au greffe du Tribunal de Grande\nInstance et est inscrit dans un registre ouvert à cet effet.","[CPPN] Art. 649.110 : (Loi n° 2016-21 du 16 juin 2016) Le procureur de la\nRépublique transmet, sous huitaine, les pièces au procureur Général près\nla Cour d’appel qui les dépose au greffe de la Cour d’appel.\n\nCode de procédure pénale","[CPPN] Art. 649.111 : (Loi n° 2016-21 du 16 juin 2016) La chambre\nd’accusation statue dans un (1) mois à compter de la date de réception de\nla déclaration d’appel au secrétariat du parquet Général.","[CPPN] Art. 649.112 : (Loi n° 2016-21 du 16 juin 2016) Le greffier en Chef de\nla Cour d’appel donne avis aux parties et à leurs conseils par lettre\nrecommandée, des lieux, date et heure de l’audience au plus tard sept (07)\njours francs à l’avance.","[CPPN] Art. 649.113 : (Loi n° 2016-21 du 16 juin 2016) Le procureur Général,\nles parties et leurs conseils sont entendus.","[CPPN] Art. 649.114 : (Loi n° 2016-21 du 16 juin 2016) L’appel est suspensif,\nsauf si l’exécution provisoire a été ordonnée.","[CPPN] Art. 649.115 : (Loi n° 2016-21 du 16 juin 2016) L’appelant qui\nsuccombe peut être condamné aux frais.","[CPPN] Art. 649.116 : (Loi n° 2016-21 du 16 juin 2016) Le greffier en Chef\ncommunique sans délai une copie de l’arrêt à l’Agence centrale.","[CPPN] Art. 649.117 : (Loi n° 2016-21 du 16 juin 2016) Si le juge d’instruction\nn’a pas statué dans le délai qui lui est imparti, les personnes auxquelles la\nnotification a été adressée ou qui lui ont fait connaitre leurs objections\npeuvent s’adresser à la chambre d’accusation.\nToutefois, ce droit s’éteint si la requête motivée n’est pas déposée dans les\nhuit (08) jours francs au greffe du Tribunal de Grande Instance.","[CPPN] Art. 649.118 : (Loi n° 2016-21 du 16 juin 2016) Le requérant ou les\npersonnes auxquelles la notification a été dressée ou qui ont fait connaitre\nleurs objections ne peuvent pas envoyer ou déposer de requête ayant le\nmême objet avant l’expiration d’un délai de six (06) mois à compter de la\ndernière décision portant sur le même objet.","[CPPN] Art. 649.119 : (Loi n° 2016-21 du 16 juin 2016) Pour autant que le\nprocureur de la République, le juge d’instruction ou la chambre d’accusation\nait donné l’autorisation à cet effet, l’Agence centrale fait procéder à\nl’aliénation des biens saisis ou des avoirs recouvrés par les services\ncompétents.\n\nCode de procédure pénale","[CPPN] Art. 649.120 : (Loi n° 2016-21 du 16 juin 2016) L’aliénation des biens\nsaisis ou des avoirs recouvrés a lieu comme suit :\n- au cas où elle concerne la vente des biens immeubles ou des biens meubles,\nautres que des valeurs, l’aliénation est exécutée par l’Agence centrale.\n- les biens sont vendus à un prix qui ne peut être inférieur au prix qui\ncorrespond à la valeur minimale évaluée au préalable par expertise.\nLorsque la nature des biens l’exige, l’Agence centrale fait appel à des\nexperts de l’administration ou à défaut à des spécialistes externes en vue\nde l’évaluation de ces biens et ou de leur vente. Sauf circonstances\nparticulières la vente est publique.\nL’aliénation est exécutée par l’Agence centrale.","[CPPN] Art. 649.121 : (Loi n° 2016-21 du 16 juin 2016) Les frais de l’aliénation,\net d’expertise sont à la charge des acheteurs.","[CPPN] Art. 649.122 : (Loi n° 2016-21 du 16 juin 2016) Les sommes tirées de\nl’aliénation et les valeurs obtenues à titre de cautionnement sont gérées\npar l’Agence centrale selon les règles de la comptabilité publique.","[CPPN] Art. 649.123 : (Loi n° 2016-21 du 16 juin 2016) En vue de l’exécution\nde cette gestion, l’Agence centrale peut, sous sa propre responsabilité faire\nappel aux institutions financières ou procéder, selon les cas, à la désignation\nd’un ou de plusieurs autres mandataires ou gestionnaires. Les frais liés à\ncette gestion doivent être considérés comme frais de justice.","[CPPN] Art. 649.124 : (Loi n° 2016-21 du 16 juin 2016) Lors de la restitution\nou de la confiscation spéciale des sommes tirées de l’aliénation, ces montants\nsont complétés par l’intérêt intermédiaire produit par ces sommes auprès\ndes institutions financières auxquelles ils ont été confiés.\nParagraphe 3 : Des Procédures de la gestion particulière","[CPPN] Art. 649.125 : (Loi n° 2016-21 du 16 juin 2016) L’Agence centrale\nassure la gestion des sommes saisies, sauf si elles ont été saisies ou bloquées\ndans un compte bancaire.\nL’Agence centrale est responsable de cette gestion dès qu’elle reçoit les\nsommes.\n\nCode de procédure pénale","[CPPN] Art. 649.126 : (Loi n° 2016-21 du 16 juin 2016) L’Agence centrale\nveille à la gestion des titres nominatifs ou au porteur, d’autres biens qui\nnécessitent une gestion particulière ou spécialisée ou des sommes qui ont\ndéjà été confiées à une institution financière ou qui ont été saisies ou\nbloquées.\nLorsque l’Agence centrale assure une telle gestion, elle en assume la\nresponsabilité jusqu’à la révocation ou jusqu’à la décision définitive\nconcernant l’affectation des valeurs ou des biens gérés.","[CPPN] Art. 649.127 : (Loi n° 2016-21 du 16 juin 2016) La gestion visée à\nl’article 649.122 ci-dessus peut porter sur la conservation des biens par\nl’Agence centrale ou par un gestionnaire ou mandataire désigné par elle,\nsur des directives contraignantes et des missions à donner par l’Agence\ncentrale à un gestionnaire ou un mandataire déjà désigné par elle ou sur\nd’autres actes de gestion.\nParagraphe 4 : Des Procédures d’exécution","[CPPN] Art. 649.128 : (Loi n° 2016-21 du 16 juin 2016) Sans préjudice de la\ncompétence du directeur de l’enregistrement et des domaines de consulter\nles données disponibles pour évaluer la solvabilité de la personne condamnée\nà une sanction patrimoniale définitive, l’Agence centrale peut, en vue de\nl’exécution effective de la confiscation, examiner les possibilités du\ncondamné à subir des peines qui lui sont infligées et communiquer ces\ndonnées au directeur de l’enregistrement et des domaines.\nDans le cadre de cet examen et sauf dispositions contraires de la loi,\nl’Agence centrale peut demander aux entreprises privées, aux services\nadministratifs de l’Etat et aux entreprises publiques de lui communiquer\ndans le délai qu’elle fixe, toutes informations qu’elle juge nécessaires, sans\nqu’il ne puisse lui être opposé le secret professionnel.","[CPPN] Art. 649.129 : (Loi n° 2016-21 du 16 juin 2016) L’Agence centrale\npeut également demander au procureur de la République de charger les\nservices de police judiciaire d’examiner la solvabilité du condamné.\n\nSection 2 : Du recouvrement d’avoirs\n(Loi n° 2017-07 du 31 mars 2017)","[CPPN] Art. 649.130: (Loi n° 2017-07 du 31 mars 2017) Les dispositions légales\nrelatives à la lutte contre le blanchiment des capitaux et le financement du\nterrorisme sont applicables dans le cadre de la présente loi et régissent les\nrapports entre l’Etat du Niger et les Etats Parties à la Convention des\nNations Unies Contre la Corruption.","[CPPN] Art. 649.131 : (Loi n° 2017-07 du 31 mars 2017) Les banques et les\nétablissements financiers doivent soumettre les comptes ouverts ou détenus,\ndirectement ou indirectement par des personnes physiques exerçant ou\nayant exercé des fonctions publiques, des membres de leur famille et leur\nproche entourage, à une surveillance accrue et en signaler les opérations\nsuspectes aux autorités compétentes, conformément à la réglementation\nrelative au blanchiment de capitaux.\nLorsque les personnes physiques visées à l’alinéa premier du présent article\nont un droit ou une délégation de signature ou tout autre pouvoir sur un\ncompte financier domicilié à l’étranger, elles sont tenues de le signaler à\nleurs autorités hiérarchiques et de la déclarer à l’organisme national de\ntraitement des informations financières.\nA la demande d’un Etat étranger ou sur sa propre initiative, l’Etat du Niger\npeut notifier aux organismes financiers, l’identité des personnes dont ils\ndevront soumettre les comptes à un examen particulier.","[CPPN] Art. 649.132 : (Loi n° 2017-07 du 31 mars 2017) Les demandes en\nrecouvrement des biens saisis ou confisqués présentées par une autorité\njudiciaire étrangère sur le fondement de la convention des Nations-Unies\nsur la corruption sont reçues et exécutées par les juridictions nigériennes\ncompétentes.\nLes demandes d’entraide judiciaire portant sur des mesures conservatoires\net d’instruction sont reçues et exécutées par les juridictions nigériennes\ncompétentes.\n\nCode de procédure pénale","[CPPN] Art. 649.133 : (Loi n° 2017-07 du 31 mars 2017) Les demandes\nd’entraide judiciaire concernent :\n- le gel, la saisie en vue de leur confiscation ultérieure, des biens susceptibles\nd’être le produit d’une infraction ainsi que de ceux qui ont servi ou\nétaient destinés à commettre cette infraction ou de tout bien dont la\nvaleur correspond au produit de cette infraction;\n- la confiscation desdits biens.","[CPPN] Art. 649.134 : (Loi n° 2017-07 du 31 mars 2017) Si elle l’estime utile,\nla juridiction saisie notifie la demande au propriétaire du bien saisi, à la\npersonne condamnée ainsi qu’à toute personne ayant des droits sur les\nbiens qui ont fait l’objet de la décision étrangère de confiscation.\nLes personnes visées à l’alinéa précédent peuvent se faire représenter par\nun avocat.\nLa juridiction saisie est liée par les constatations de fait de la décision\nétrangère. Si ces constatations sont insuffisantes, elle peut ordonner un\nsupplément d’informations.","[CPPN] Art. 649.135 : (Loi n° 2017-07 du 31 mars 2017) Les demandes\nprésentées en application des dispositions de l’article 649.132 ci-dessus\nsont rejetées si :\n- leur exécution est de nature à porter atteinte à l’ordre public, à la\nsouveraineté nationale, à la sécurité ou à d’autres intérêts essentiels de\nl’Etat du Niger;\n- les faits à 1 origine de la demande ne sont pas constitutifs d’une infraction\nselon le droit interne de l’Etat du Niger;\n- les biens sur lesquels elles portent ne sont pas susceptibles de faire l’objet\nd’une confiscation dans des circonstances analogues selon la législation\nnigérienne.","[CPPN] Art. 649.136 : (Loi n° 2017-07 du 31 mars 2017) L’exécution de la\ndemande de confiscation présentée par une autorité judiciaire étrangère\nest autorisée à la condition que la décision étrangère soit devenue définitive\net exécutoire selon la législation de l’Etat requérant.\n\nLes modalités de partage de produit de la vente des biens confisqués à la\ndemande d’un Etat requérant sont définies d’accord parties.","[CPPN] Art. 649.137 : (Loi n° 2017-07 du 31 mars 2017) Le refus d’autoriser\nl’exécution de la décision de confiscation prononcée par la juridiction\nétrangère emporte de plein droit mainlevée de la saisie.\nIl en est de même lorsque les poursuites engagées à l’étranger ont pris fin\nou n’ont pas abouti à la confiscation des biens saisis.","[CPPN] Art. 649.138 : (Loi n° 2017-07 du 31 mars 2017) L’autorisation\nd’exécution des demandes d’entraide judiciaire ne peut avoir pour effet de\nporter atteinte aux droits licitement constitués à l’égard des tiers en\napplication de la législation nigérienne, sur les biens dont la confiscation a\nété prononcée par la décision étrangère.\nToutefois, si cette décision contient des dispositions relatives aux droits des\ntiers, elle s’impose aux juridictions nigériennes à moins que les tiers n’aient\nété mis à même de faire valoir leurs droits devant la juridiction étrangère\ndans des conditions analogues à celles prévues par la législation nigérienne.\n\nTITRE XIV : DES PROCEDURES PARTICULIERES EN\nMATIERE DE CORRUPTION ET INFRACTIONS\nASSIMILEES\n(Loi n° 2017-07 du 31 mars 2017)\nCHAPITRE PREMIER : DES CONSEQUENCES D’ACTES DE\nCORRUPTION ET D’INFRACTIONS ASSIMILEES.\n(Loi n° 2017-07 du 31 mars 2017)","[CPPN] Art. 649.139 : (Loi n° 2017-07 du 31 mars 2017) Si le tribunal estime\nque le fait constitue lm délit de corruption ou d’infractions assimilées, il\nprononce la peine. Il statue, par le même jugement, sur l’action civile. Il\npeut également, sans préjudice des droits des tiers acquis de bonne foi,\nprononcer la confiscation :\n- du produit provenant d’infractions visées à la présente loi ou de biens\ndont la valeur correspond à celle de ce produit;\n- des biens matériels et autres instruments ayant servi ou destinés à la\ncommission desdites infractions.\nLe tribunal peut aussi décider de l’annulation ou de la rescision d’un contrat,\ndu retrait d’une concession ou de la restitution des biens matériels et des\nautres instruments ayant servi ou destinés à commettre lesdites infractions.\nSi le produit de l’infraction a été transformé ou converti, en partie ou en\ntotalité, en d’autres biens, ces derniers peuvent faire l’objet des mesures\nvisées au présent article.\nSi le produit de l’infraction a été mêlé à des biens acquis légitimement, ces\nbiens sont confiscables à concurrence de la valeur estimée du produit qui y\na été mêlé.\nLes revenus ou autres avantages tirés du produit de l’infraction, des biens\nen lesquels le produit a été transformé ou converti ou des biens auxquels il\na été mêlé peuvent aussi faire l’objet de mesures visées au présent article,\nde la même manière et dans la même mesure que le produit de l’infraction.\n\nLe tribunal peut ordonner la production ou la saisie de document","[CPPN] Art. 649.140 : (Loi n° 2017-07 du 31 mars 2017) Les autorités publiques\net les agents publics, de leur propre initiative ou sur demande des autorités\nchargées des enquêtes et des poursuites, fournissent à celles-ci toutes les\ninformations nécessaires sur la commission d’actes de corruption et\nd’infractions assimilées.\nLes entités du secteur privé et en particulier les institutions financières\nfournissent, aux autorités chargées des enquêtes et des poursuites, les\ninformations sur la commission d’actes de corruption et d’infractions\nassimilées.\nLes personnes physiques ou morales ayant leur résidence habituelle ou\nleur siège sur le territoire national fournissent, aux autorités chargées des\nenquêtes et des poursuites, des informations sur la commission d’actes de\ncorruption et d’infractions assimilées.\nCHAPITRE III : DE LA PRESCRIPTION EN MATIERE DE\nCORRUPTION ET D’INFRACTIONS ASSIMILEES.\n(Loi n° 2017-07 du 31 mars 2017)","[CPPN] Art. 649.141 : (Loi n° 2017-07 du 31 mars 2017) L’action publique des\ndélits en matière de corruption et d’infractions assimilées se prescrit par\ndix (10) ans.\n\nLes peines portées par un arrêt ou un jugement correctionnel en matière\nde corruption et d’infractions assimilées se prescrivent par quinze (15) ans\nà compter de la date à laquelle cet arrêt ou jugement est devenu définitif.\nL’action publique des crimes en matière de corruption et les infractions\nassimilées se prescrit par vingt (20) ans.\nLes peines portées par un arrêt criminel en matière de corruption et\nd’infractions assimilées se prescrivent par trente (30) ans à compter de la\ndate à laquelle cet arrêt est devenu définitif.\nL’action publique et les peines relatives à la corruption et les infractions\nassimilées sont imprescriptibles lorsque le produit du crime est transféré en\ndehors du territoire national.\n\nLIVRE V\nDES PROCEDURES D’EXECUTION\n\nTITRE I : DE L’EXECUTION DES SENTENCES PENALES","[CPPN] Art. 650 : Le ministère public et les parties poursuivent l’exécution de la\nsentence chacun en ce qui le concerne.\nNéanmoins, les poursuites pour le recouvrement des amendes et confiscation\nsont faites, au nom du procureur de la République, par le trésor.\n(Ord. n° 92-02 du 21 février 1992). En cas de condamnation pour\ndétournement de deniers publics, il sera procédé à la vente des biens saisis\njusqu’à concurrence du montant des détournements, de l’amende et des\nfrais de justice.\n(Ord. n° 92-02 du 21 février 1992). Le reliquat du produit de la vente et\nle reste des biens seront restitués.\n((Ord. n° 92-02 du 21 février 1992). Dans le cas où la vente des biens\nne suffit pas pour couvrir le montant des détournements, de l’amende et\ndes frais de justice, les poursuites pour leur recouvrement seront faites par\nle trésor sur réquisition du ministère public.","[CPPN] Art. 651 : L’exécution à la requête du ministère public a lieu lorsque la\ndécision est devenue définitive.\nToutefois, le délai d’appel accordé au procureur général par les articles\n495 et 544 ne fait point obstacle à l’exécution de la peine.","[CPPN] Art. 652 : Le procureur de la République et le procureur général ont le\ndroit de requérir directement l’assistance de la force publique à l’effet\nd’assurer cette exécution.","[CPPN] Art. 653 : Tous incidents contentieux relatifs à l’exécution sont portés\ndevant le tribunal ou la Cour qui a prononcé la sentence; cette juridiction\npeut également procéder à la rectification des erreurs purement matérielles\ncontenues dans ses décisions.\nPar exception, la Chambre d’accusation connaît des rectifications et des\nincidents d’exécution auxquels peuvent donner lieu les arrêts de la Cour\nd’assises.","[CPPN] Art. 654 : Le tribunal ou la cour, sur requête du ministère public ou de la\npartie intéressée, statue en Chambre du conseil après avoir entendu le\n\nministère public, le conseil de la partie s’il le demande et, s’il échet, la\npartie elle-même, sous réserve des dispositions de l’article 655.\nL’exécution de la décision en litige est suspendue si le tribunal ou la Cour\nl’ordonne.\nLe jugement sur l’incident est signifié à la requête du ministère public, aux\nparties intéressées.","[CPPN] Art. 655 : (Loi n° 2003-26 du 13 juin 2003). Dans toutes les hypothèses\noù il paraît nécessaire d’entendre un condamné qui se trouve détenu, la\njuridiction saisie peut donner commission rogatoire au président du tribunal,\nau juge d’instance le plus proche du lieu de détention.","[CPPN] Art. 656 : Lorsque la peine prononcée est la mort, le ministère public, dès\nque la condamnation est devenue définitive, la porte à la connaissance du\nministre de la justice.\nLa condamnation ne peut être mise à exécution que lorsque la grâce a été\nrefusée.\nSi le condamné veut faire une déclaration, elle est reçue par un des juges\ndu lieu de l’exécution, assisté du greffier.\nTITRE II : DE LA DETENTION\nCHAPITRE PREMIER : DE L’EXECUTION DE LA\nDETENTION PREVENTIVE","[CPPN] Art. 657 : (Loi n° 2003-26 du 13 juin 2003). Les inculpés, prévenus et\naccusés soumis à la détention préventive la subissent dans un établissement\npénitentiaire.\nIl y a un établissement pénitentiaire près de chaque tribunal de grande\ninstance et chaque tribunal d’instance.","[CPPN] Art. 658 : (Loi n° 2003-26 du 13 juin 2003). Le juge d’instruction, le\nprésident de la Chambre d’accusation et le président de la Cour d’assises,\nainsi que le procureur de la République et le procureur général, peuvent\ndonner tous les ordres nécessaires soit pour l’instruction, soit pour le\njugement, qui devront être exécutés dans les établissements pénitentiaires.\n\nCode de procédure pénale","[CPPN] Art. 659 : (Loi n° 2003-26 du 13 juin 2003). Les détenus préventifs\nsont séparés des condamnés qui purgent leur peine.\nLe quartier de l’établissement pénitentiaire qui leur est réservé est divisé\nen sous-quartiers pour les hommes et pour les femmes, de telle sorte qu’il\nne puisse y avoir aucune communication entre eux.\nLes mineurs sont détenus dans un quartier qui leur est spécialement réservé.\nLes distinctions prévues aux alinéas précédents leur sont applicables.","[CPPN] Art. 660 : (Loi n° 2003-26 du 13 juin 2003). Toutes communications\net toutes facilités compatibles avec les exigences de la discipline et de la\nsécurité de l’établissement pénitentiaire sont accordées aux inculpés,\nprévenus et accusés pour l’exercice de leur défense.","[CPPN] Art. 661 : (Loi n° 2003-26 du 13 juin 2003). Les détenus préventifs ne\nsont pas soumis au travail à moins qu’ils n’en fassent expressément la\ndemande.\nEn aucun cas, ils ne peuvent être employés à des travaux à l’intérieur de\nl’établissement pénitentiaire.\nCHAPITRE II : DE L’EXECUTION DES PEINES PRIVATIVES\nDE LIBERTE","[CPPN] Art. 662 : Les condamnés à l’emprisonnement purgent leur peine dans\nune prison ou un camp pénal.","[CPPN] Art. 663 : (Loi n° 2003-26 du 13 juin 2003). Les condamnés sont\nrépartis dans des quartiers différents suivant leur âge, sexe ainsi qu’il est\ndit à l’article 659.","[CPPN] Art. 664 : Les condamnés sont soumis dans le camp pénal et dans la\nprison au régime de l’emprisonnement collectif.","[CPPN] Art. 665 : Les condamnés à des peines privatives de liberté, pour des faits\nqualifiés crimes ou délits de droit commun, sont employés à des travaux\nsous les distinctions portées aux articles 17 et 24 du code pénal.\n\nCHAPITRE III : DES DISPOSITIONS COMMUNES AUX\nDIFFERENTS ETABLISSEMENTS PENITENTIAIRES","[CPPN] Art. 666 : (Loi n° 2003-26 du 13 juin 2003). Le procureur général a la\nsurveillance des établissements pénitentiaires et tient la main à ce que\npersonne n’y soit détenu illégalement.\nLe juge d’instruction, une fois par mois, le président de la Chambre\nd’accusation, le juge d’instance, le procureur de la République et le procureur\ngénéral, chaque fois qu’ils l’estiment nécessaire, visitent les établissements\npénitentiaires.\nLe président de la Cour d’assises, une fois au moins au cours de chaque\nsession, visite les accusés internés dans la prison du siège de la cour.","[CPPN] Art. 667 : Dès réception d’un arrêt ou d’un jugement de condamnation,\nd’une ordonnance de prise de corps, d’un mandat de dépôt ou d’arrêt, d’un\nmandat d’amener lorsque ce mandat doit être suivi d’incarcération provisoire,\nou d’un ordre d’arrestation établi conformément à la loi, le chef de\nl’établissement est tenu d’inscrire sur le registre l’acte qui lui est remis.\nEn cas d’exécution volontaire de la peine, le chef de l’établissement recopie\nsur le registre d’écrou l’extrait de l’arrêt ou du jugement de condamnation qui\nlui a été transmis par le procureur général ou par le procureur de la République.\nEn toute hypothèse, l’avis de l’écrou est donné par le chef de\nl’établissement, selon le cas, au procureur général ou au procureur de la\nRépublique.\nLe registre d’écrou mentionne également, en regard de l’acte de remise, la\ndate de la sortie du détenu ainsi que, s’il y a lieu, la décision ou le texte de\nla loi motivant la libération.","[CPPN] Art. 668 : Nul agent de l’administration pénitentiaire ne peut, à peine\nd’être poursuivi et puni comme coupable de détention arbitraire, recevoir,\nni retenir aucune personne qu’en vertu d’un arrêt ou jugement de\ncondamnation, d’une ordonnance de prise de corps, d’un mandat de dépôt\nou d’arrêt, d’un mandat d’amener lorsque ce mandat doit être suivi\nd’incarcération provisoire, ou d’un ordre d’arrestation établi conformément\nà la loi et sans que l’inscription sur le registre d’écrou prévu à l’article\nprécédent ait été faite.\n\nCode de procédure pénale","[CPPN] Art. 669 : Si quelque détenu use de menaces, injures ou violences, ou\ncommet une infraction à la discipline, il peut être enfermé seul dans une\ncellule aménagée à cet effet ou même être soumis à des moyens de\ncoercition en cas de fureur ou de violence grave, sans préjudice des\npoursuites auxquelles il peut y avoir lieu.","[CPPN] Art. 670 : Un décret détermine l’organisation et le régime intérieur des\nétablissements pénitentiaires.\nTITRE III : DE LA LIBERATION CONDITIONNELLE","[CPPN] Art. 671 : Les condamnés ayant à subir une ou plusieurs peines privatives\nde liberté peuvent bénéficier d’une libération conditionnelle s’ils ont donné\ndes preuves suffisantes de bonne conduite et présentent des gages sérieux\nde réadaptation sociale.\nLa libération conditionnelle est réservée aux condamnés ayant accompli\ntrois mois de leur peine, si cette peine est inférieure à six mois, et la moitié\nde la peine dans le cas contraire. Pour les condamnés en état de récidive\nlégale, le temps d’épreuve est porté à six mois si la peine est inférieure à\nneuf mois et aux deux tiers de la peine dans le cas contraire.\nPour les condamnés à l’emprisonnement à vie, le temps d’épreuve est de\nquinze années.","[CPPN] Art. 672 : Le droit d’accorder la libération conditionnelle appartient au\nministre de la justice, sur avis du ministre de l’intérieur.\nLe dossier de proposition comporte les avis du chef de l’établissement\ndans lequel l’intéressé est détenu et du ministère public près la juridiction\nqui a prononcé la condamnation.","[CPPN] Art. 673 : Le bénéfice de la libération conditionnelle peut être assorti de\nconditions particulières ainsi que de mesures d’assistance et de contrôle\ndestinées à faciliter et à vérifier le reclassement du libéré.","[CPPN] Art. 674 : L’arrêt de libération conditionnelle fixe les modalités d’exécution\net les conditions auxquelles l’octroi ou le maintien de la liberté peut être\nsubordonné, ainsi que la nature et la durée des mesures d’assistance et de\ncontrôle.\n\nCette durée ne peut être inférieure à la durée de la partie de la peine non\nsubie au moment de la libération s’il s’agit d’une peine temporaire.\nPendant toute la durée de la liberté conditionnelle, les dispositions de l’arrêté\nde libération peuvent être modifiées.","[CPPN] Art. 675 : En cas de nouvelle condamnation, d’inconduite notoire,\nd’infraction aux conditions ou d’inobservation des mesures énoncées dans\nla décision de mise en liberté conditionnelle, le ministre de la justice peut\nprononcer la révocation de cette décision.\nEn cas d’urgence, l’arrestation peut être provisoirement ordonnée par le\nministère public, à charge de saisir immédiatement le ministre de la justice.\nAprès révocation, le condamné doit subir, selon les dispositions de l’arrêt de\nrévocation, tout ou partie de la durée de la peine qui lui restait à subir au\nmoment de sa mise en liberté conditionnelle, cumulativement, s’il y a lieu, avec\ntoute nouvelle peine qu’il aurait encourue; le temps pendant lequel il a été placé\nen état d’arrestation provisoire compte toutefois pour l’exécution de sa peine.\nSi la révocation n’est pas intervenue avant l’expiration de la libération\nconditionnelle, la libération est définitive. Dans ce cas, la peine est réputée\nterminée depuis le jour de la libération conditionnelle.\nTITRE IV : DU SURSIS","[CPPN] Art. 676 : (Loi n° 2003-26 du 13 juin 2003). En cas de condamnation\nà l’emprisonnement et l’amende ou à l’une de ces deux peines seulement,\nsi le condamné n’a pas fait l’objet de condamnation antérieure à\nl’emprisonnement pour crime ou délit de droit commun, les cours et tribunaux\npeuvent ordonner, en matière correctionnelle, par le même jugement et par\ndécision motivée, qu’il sera sursis à l’exécution de la peine.\nLorsqu’ils prononceront une peine supérieure à dix jours d’emprisonnement\nou à 50.000 francs d’amende, les tribunaux de simple police pourront\négalement ordonner le sursis si le condamné n’a pas fait l’objet de\ncondamnation antérieure à l’emprisonnement pour crime, délit ou\ncontravention de droit commun.\nLa juridiction peut décider que le sursis ne s’appliquera à l’exécution de\nl’emprisonnement que pour une partie dont elle déterminera la durée dans\nla limite de 5 ans.\n\nCode de procédure pénale","[CPPN] Art. 677 : (Loi n° 2003-26 du 13 juin 2003). Si, pendant le délai de cinq\nans à dater du jugement ou de l’arrêt devenu définitif, le condamné n’a\nencouru aucune poursuite suivie de condamnation à l’emprisonnement ou\nà une peine plus grave pour crime ou délit de droit commun, la condamnation\nsera comme non avenue.\nDans le cas contraire, la première prise sera d’abord exécutée sans qu’elle\npuisse se confondre avec la seconde.\nToutefois, la juridiction peut, par décision spéciale et motivée, dire que la\ncondamnation qu’elle prononce n’entraînera pas la révocation du sursis\nantérieurement accordé ou n’entraîne qu’une révocation partielle, pour une\ndurée déterminée, du sursis antérieurement accordé. Elle peut également\nlimiter les effets de la dispense de révocation à l’un ou plusieurs des sursis\nantérieurement accordés.\nLe délai de cinq ans prévu à l’alinéa 1 du présent article sera réduit à deux\nans lorsque la peine précédemment prononcée sera une contravention.","[CPPN] Art. 678 : La suspension de la peine ne s’étend pas au payement des frais\ndu procès et des dommages-intérêts.\nElle ne s’étend pas non plus aux peines accessoires et aux incapacités\nrésultant de la condamnation.\nToutefois, les peines accessoires et les incapacités cesseront d’avoir effet\ndu jour où, par l’application des dispositions de l’article 677, la condamnation\naura été réputée non avenue.","[CPPN] Art. 679 : Le président de la Cour ou du tribunal, après avoir prononcé la\ndécision de condamnation prévue à l’article 676, avertit le condamné qu’en\ncas de nouvelle condamnation la première peine sera exécutée sans\nconfusion possible avec la seconde et que les peines de la récidive seront\nencourues dans les termes des articles 56 et suivants ou 406 du code pénal.\nTITRE IV BIS : DU SURSIS AVEC MISE A L’EPREUVE\nArt. 679-1 : (Loi n° 2003-026 du 13 juin 2003). La juridiction qui\nprononce un emprisonnement peut, dans les conditions prévues ci-après,\nordonner qu’il sera sursis à son exécution, la personne condamnée étant\nplacée sous le régime de la mise à l’épreuve.\n\nAprès le prononcé de l’emprisonnement assorti du sursis avec mise à\nl’épreuve, le Président de la juridiction avertit le condamné lorsqu’il est\nprésent, des conséquences qu’entraîne la condamnation pour une nouvelle\ninfraction commise au cours du délai d’épreuve ou un manquement aux\nmesures de contrôle et aux obligations particulières qui lui sont imposées. Il\nl’informe de la possibilité qu’il aura de voir déclarer sa condamnation non\navenue s’il observe une conduite satisfaisante.\nArt. 679-2 : Le sursis avec mise à l’épreuve est applicable aux\ncondamnations à l’emprisonnement prononcé pour une durée de 5 ans au\nplus, en raison d’un crime ou d’un délit de droit commun.\nLa mise à l’épreuve n’est applicable qu’à compter du jour où la\ncondamnation devient exécutoire.\nArt. 679-3 : La juridiction de jugement fixe le délai ","[CPPN] Art. 680 : Lorsqu’après une évasion suivie de reprise ou dans toute\nautre circonstance, l’identité d’un condamné fait l’objet d’une contestation,\ncette contestation est tranchée suivant les règles établies en matière\nd’incidents d’exécution. Toutefois, l’audience est publique.\nSi la contestation s’élève au cours et à l’occasion d’une nouvelle poursuite,\nelle est tranchée par la Cour ou le tribunal saisi de cette poursuite.\nTITRE VI : DE CONTRAINTE PAR CORPS","[CPPN] Art. 681 : Lorsqu’une condamnation à l’amende, ou aux frais ou à tout\nautre payement au profit du trésor public ou à tous dommages-intérêts au\nprofit de toute partie civile, est prononcée pour une infraction n’ayant pas\nun caractère politique et n’emportant pas peine perpétuelle, par une\njuridiction répressive, celle-ci fixe, pour le cas où la condamnation\ndemeurerait inexécutée, la durée de la contrainte par corps dans les limites\nci-dessous prévues.\n\nLorsque la contrainte par corps garantit le recouvrement de plusieurs\ncréances, sa durée est fixée d’après le total des condamnations.","[CPPN] Art. 682 : La durée de la contrainte par corps est réglée ainsi qu’il suit :\n- de cinq à dix jours lorsque l’amende et les condamnations pécuniaires\nn’excédent pas 5.000 francs;\n- de dix à vingt jours lorsque supérieures à 5.000 francs, elles n’excèdent\npas 25.000 francs;\n- de vingt à quarante jours lorsque, supérieures à 25.000 francs, elles\nn’excèdent pas 50.000 francs;\n- de quarante à soixante jours lorsque, supérieures à 50.000 francs, elles\nn’excèdent pas 100.000 francs;\n- de deux à quatre mois, lorsque, supérieures à 100.000 francs, elles\nn’excèdent pas 200.000 francs;\n- de quatre à huit mois, lorsque supérieures à 200.000 francs, elles n’excèdent\npas 400.000 francs;\n- de huit mois à un an, lorsque, supérieures à 400.000 francs, elles n’excèdent\npas 800.000 francs;\n- d’un an à deux ans lorsqu’elles excèdent 800.000 francs.","[CPPN] Art. 683 : La contrainte par corps ne peut être prononcée ni contre les\nindividus âgés de moins de dix-huit ans accomplis à l’époque des faits qui\nont motivé la poursuite, ni contre ceux qui ont commencé leur soixantième\nannée au moment de la condamnation.","[CPPN] Art. 684 : Elle est réduite de moitié pour les condamnés qui justifient de\nleur insolvabilité en produisant :\n1) un certificat de l’agent du trésor de leur domicile, constatant qu’ils ne\nsont pas imposés à un impôt autre que celui du minimum fiscal;\n2) un certificat du maire de la commune ou du commissaire de police ou du\nchef de la circonscription administrative de leur domicile.\nElle pourra être supprimée, après enquête, par décision du procureur de la\nRépublique.\n\nCode de procédure pénale","[CPPN] Art. 685 : Elle ne peut être exercée simultanément contre le mari et la\nfemme, même pour le recouvrement de sommes afférentes à des\ncondamnations différentes.","[CPPN] Art. 686 : Toute condamnation à l’amende, ou aux frais ou à tout autre\npayement au profit du trésor public, prononcée par une juridiction répressive,\ndevra être exécutée volontairement par le condamné dans les conditions\nci-dessous prévues.","[CPPN] Art. 687 : Dans le délai de deux mois à compter du jour où la décision est\ndevenue définitive, la partie condamnée doit s’acquitter spontanément entre\nles mains du receveur de l’enregistrement, du préposé du trésor ou l’agent\nspécial, du paiement des condamnations pécuniaires prononcées au profit\nde l’Etat.\nCe délai de deux mois ne court, contre ceux détenus préventivement au\nmoment de la condamnation, qu’à compter de leur libération.\nL’agent de recouvrement compétent est celui du siège de la juridiction qui\na condamné; toutefois, en ce qui concerne les condamnations prononcées\npar la Cour d’appel, l’agent du siège de la juridiction du lieu de résidence\ndu condamné est également compétent.","[CPPN] Art. 688 : Sur sa demande, il sera délivré à la partie condamnée, soit par\nle greffier en chef de la juridiction de condamnation, soit par le greffier en\nchef de la juridiction du lieu de sa résidence pour les condamnations\nprononcées par la Cour d’appel, un extrait de la décision, en triple exemplaire,\ncomprenant le décompte des condamnations pécuniaires, y compris les\ndroits d’enregistrement.\n(Loi n° 2003-26 du 13 juin 2003). Dans ce dernier cas, cet extrait en\ntriple exemplaires, sera dressé aux fins de recouvrement, par le greffier en\nchef de la Cour d’appel, aux greffiers en chef des juridictions de la résidence\ndes condamnés, à l’exception toutefois de ceux des tribunaux régionaux de\nNiamey et Zinder.","[CPPN] Art. 689 : La partie condamnée remettra les trois extraits à l’agent chargé\ndu recouvrement. Les extraits revêtus de la mention du paiement seront\nremis l’un à l’intéressé, le deuxième au greffier en chef qui les a établis, le\ntroisième sera conservé comme titre de recette.\n\nCode de procédure pénale","[CPPN] Art. 690 : A l’expiration du délai de deux mois, visé à l’article 687, le\ngreffier en chef transmet soit au procureur général, soit au procureur de la\nRépublique ou au juge du tribunal de grande instance ou d’instance\ncompétent, les extraits des condamnations pécuniaires non exécutées.\nIl est alors délivré d’office, et sans commandement préalable, un réquisitoire\nd’incarcération contre tout condamné qui ne s’est pas acquitté\nvolontairement du paiement de ses condamnations pécuniaires. L’intéressé\nest conduit au parquet du magistrat requérant qui peut suspendre l’exécution\nde la contrainte pour un délai de trois mois.","[CPPN] Art. 691 : Les parties qui désirent s’acquitter des condamnations pécuniaires\nmises à leur charge, avant que la condamnation soit devenue définitive, ont la\nfaculté d’utiliser la procédure prévue aux articles 688 et 689.","[CPPN] Art. 692 : Le président de la Cour ou du tribunal doit, après avoir prononcé\nla décision de condamnation, avertir le condamné qu’il dispose d’un délai\nde deux mois à compter du jour où la condamnation sera devenue définitive,\npour s’acquitter de tout paiement prononcé au profit du trésor public.\nMention de cet avertissement doit être portée dans le jugement ou dans\nl’arrêt.","[CPPN] Art. 693 : Les règles sur l’exécution des mandats de justice sont applicables\nà la contrainte par corps.","[CPPN] Art. 694 : Les arrêts et jugements contenant des condamnations en faveur\ndes particuliers pour réparation de crimes, délits ou contraventions, commis\nà leur préjudice, sont exécutés à leur diligence, à compter du jour où ces\narrêts ou jugements sont devenus définitifs.\nLa contrainte par corps ne peut être exercée que deux mois après le\ncommandement de payer fait au condamné. Si au moment du\ncommandement, le condamné est détenu, la contrainte par corps ne pourra\nêtre exercée qu’après expiration d’un délai de deux mois à compter de sa\nlibération.\nLes dispositions des deux alinéas précédents s’étendent au cas où les\ncondamnations ont été prononcées par les tribunaux civils au profit d’une\n\npartie lésée, pour réparation d’un crime, d’un délit ou d’une contravention\nreconnus par la juridiction pénale.","[CPPN] Art. 695 : La contrainte par corps exercée à la requête et dans l’intérêt\ndes particuliers est mise à la charge du trésor public.\nIl en est de même du commandement à payer, prévu à l’alinéa 2 de l’article\nprécédent, en cas d’indigence de la partie lésée dûment constatée.","[CPPN] Art. 696 : (Loi n° 2003-26 du 13 juin 2003). La contrainte par corps\nest subie en établissement pénitentiaire, dans un quartier à ce destiné.","[CPPN] Art. 697 : Les individus contre lesquels la contrainte a été prononcée\npeuvent en prévenir ou en faire cesser les effets soit en payant ou consignant\nune somme suffisante pour éteindre leur dette, soit en fournissant une caution\nsolidaire, reconnue bonne et valable ou une sûreté réelle.\nLa caution est admise pour l’Etat par l’agent du trésor, pour les particuliers\npar la partie intéressée. En cas de contestation, elle est déclarée, s’il y a\nlieu, bonne et valable par le président du tribunal agissant par voie de référé.\nLa caution doit se libérer dans le mois, faute de quoi elle peut être poursuivie.\nLorsque le paiement intégral n’a pas été effectué, et sous réserve des\ndispositions de l’article 698, la contrainte par corps ne peut être requise à\nnouveau pour le montant des sommes restant dues.","[CPPN] Art. 698 : Lorsque la contrainte par corps, exercée soit à la requête du\nministère public, soit à la requête de la partie lésée, a pris fin pour une\ncause quelconque, elle ne peut plus être exercée ni pour la même dette, ni\npour des condamnations antérieures à son exécution, à moins que ces\ncondamnations n’entraînent par leur quotité une contrainte plus longue que\ncelle déjà subie, auquel cas la première incarcération doit toujours être\ndéduite de la nouvelle contrainte.","[CPPN] Art. 699 : Le débiteur détenu est soumis au même régime que les\ncondamnés.","[CPPN] Art. 700 : Le condamné qui a subi une contrainte par corps n’est pas\nlibéré du montant des condamnations pour lesquelles elle a été exercée.\n\nTITRE VII : DE LA PRESCRIPTION DE LA PEINE","[CPPN] Art. 701 : Les peines portées par un arrêt rendu en matière criminelle se\nprescrivent par vingt années révolues, à compter de la date où cet arrêt est\ndevenu définitif.","[CPPN] Art. 702 : Les peines portées par un arrêt ou jugement rendu en matière\ncorrectionnelle se prescrivent par cinq années révolues, à compter de la\ndate où cet arrêt ou jugement est devenu définitif.","[CPPN] Art. 703 : Les peines portées par un arrêt ou jugement rendu pour\ncontravention de simple police se prescrivent par deux années révolues, à\ncompter de la date où cet arrêt ou jugement est devenu définitif.\nToutefois, les peines prononcées pour une contravention de simple police,\nconnexe à un délit, se prescrivent selon les dispositions de l’article 702.","[CPPN] Art. 704 : En aucun cas les condamnés par défaut dont la peine est prescrite\nne peuvent être admis à se présenter pour purger le défaut.","[CPPN] Art. 705 : Les condamnations civiles portées par les arrêts ou jugements\nrendus en matière criminelle, correctionnelle et de simple police, et devenus\nirrévocables, se prescrivent d’après les règles établies par le code civil.\nTITRE VIII : DU CASIER JUDICIAIRE","[CPPN] Art. 706 : Le greffe de chaque tribunal ou section de tribunal reçoit, en ce\nqui concerne les personnes nées dans la circonscription du tribunal ou de la\nsection du tribunal et après vérification de leur identité aux registres de\nl’état civil, des fiches constatant :\n1) (Loi n° 64-10 du 18 mars 1964) les condamnations contradictoires et\nles condamnations par défaut non frappées d’opposition prononcées par\ntoute juridiction répressive pour crime, ou délit ou contravention passible\nd’un emprisonnement supérieur à dix jours ou d’une amende supérieure à\n50.000 francs y compris les condamnations avec sursis;\n2) les décisions prononcées par application des textes relatifs à l’enfance\ndélinquante;\n3) les dispositions disciplinaires prononcées par l’autorité judiciaire ou par\nune autorité administrative lorsqu’elles entraînent ou édictent des incapacités;\n\n4) les jugements déclaratifs de faillite ou de liquidation judiciaire;\n5) tous les jugements prononçant la déchéance de la puissance paternelle\nou le retrait de tout ou partie des droits y attachés;\n6) les arrêtés d’expulsion.","[CPPN] Art. 707 : Il est fait mention sur les fiches du casier judiciaire des grâces,\ncommutations ou réductions de peines, des décisions qui suspendent ou qui\nordonnent l’exécution d’une première condamnation, des arrêts de mise en liberté\nconditionnelle et de révocation, des décisions de suspension de peine, des\nréhabilitations, des décisions qui rapportent ou suspendent les arrêtés d’expulsion,\nainsi que la date de l’expiration de la peine et du paiement de l’amende.\nSont retirées du casier judiciaire les fiches relatives à des condamnations\neffacées par une amnistie ou réformées en conformité d’une décision de\nrectification du casier judiciaire.","[CPPN] Art. 708 : Lorsque, à la suite d’une décision de rééducation prise à l’égard\nd’un mineur, celle-ci apparaît comme acquise, le tribunal peut, après\nl’expiration d’un délai de cinq ans à compter de la date de la décision et\nmême si le mineur atteint sa majorité, décider, à sa requête, à celle du\nministère public ou d’office, la suppression du casier judiciaire de la fiche\nconcernant la décision dont il s’agit.\nLe tribunal statue en dernier ressort. Lorsque la suppression de la fiche a\nété prononcée, la mention de la décision initiale ne doit plus figurer au\ncasier judiciaire du mineur. La fiche afférente à ladite décision est détruite.\nLe tribunal de la poursuite initiale, celui du lieu du domicile actuel du mineur\net celui de sa naissance sont compétents pour connaître de la requête.","[CPPN] Art. 709 : Le greffier en chef de la Cour d’appel tient un casier judiciaire\ncentral qui reçoit les fiches concernant les personnes nées hors du territoire\nde la République du Niger et celle dont l’identité est douteuse.","[CPPN] Art. 710 : Il est donné connaissance aux autorités militaires, par l’envoi\nd’une copie de la fiche du casier judiciaire, des condamnations ou des\ndécisions de nature à modifier les conditions d’incorporation des individus\nsoumis à l’obligation du service militaire, par référence aux lois relatives\nau recrutement de l’armée.\n\nIl est donné avis également aux mêmes autorités de toutes modifications\napportées à la fiche ou au casier judiciaire en vertu des articles 707 et 708.","[CPPN] Art. 711 : Une copie de chaque fiche constatant une décision entraînant la\nprivation des droits électoraux est adressée par greffe compétent à l’autorité\nchargée d’établir les listes électorales.","[CPPN] Art. 712 : Le relevé intégral des fiches du casier judiciaire applicables à la\nmême personne est porté sur un bulletin appelé bulletin n° 1.\nLe bulletin n° 1 n’est délivré qu’aux autorités judiciaires.\nLorsqu’il n’existe pas de fiche au casier judiciaire, le bulletin n° 1 porte la\nmention «néant».","[CPPN] Art. 713 : Le bulletin n° 2 est le relevé des fiches du casier judiciaire\napplicables à la même personne, à l’exclusion de celles concernant les\ndécisions suivantes :\n1) les décisions prononcées en vertu des textes relatifs à l’enfance\ndélinquante;\n2) les condamnations assorties du bénéfice du sursis, lorsqu’elles doivent\nêtre considérées comme non avenues;\n3) les condamnations effacées par la réhabilitation de plein droit ou judiciaire;\n4) les condamnations auxquelles sont applicables les dispositions de l’article\n112, alinéa 5, du code de justice militaire pour l’armée de terre;\n5) les jugements de faillite effacés par la réhabilitation;\n6) les décisions disciplinaires effacées par la réhabilitation;\nLes bulletins n° 2 fournis en cas de contestation concernant l’inscription\nsur les listes électorales ne comprennent que les décisions entraînant des\nincapacités en matière d’exercice du droit de vote.\nLorsqu’il n’existe pas au casier judiciaire de fiches concernant des décisions\nà relever sur le bulletin n° 2, celui-ci porte la mention : «néant».","[CPPN] Art. 714 : Le bulletin n° 2 du casier judiciaire est délivré;\n1) aux administrations publiques de l’Etat saisies de demandes d’emplois\npublics, de propositions relatives à des distinctions honorifiques ou de\n\nsoumissions pour les adjudications de travaux ou de marchés publics ou en\nvue de poursuites disciplinaires ou de l’ouverture d’une école privée;\n2) aux autorités militaires pour les appels des classes et pour les jeunes\ngens qui demandent à contracter un engagement ainsi qu’aux autorités\ncompétentes en cas de contestation sur l’exercice de droits électoraux.","[CPPN] Art. 715 : Le bulletin n° 3 est le relevé des condamnations à des peines\nprivatives de liberté prononcées par une juridiction de répression pour crime\nou délit. Il indique expressément que tel est son objet. N’y sont inscrites\nque les condamnations de la nature ci-dessus précités autres que celles\nmentionnées du 1° au 6° de l’article 713 et pour lesquelles le sursis n’a pas\nété ordonné, sauf révocation de cette mesure.\nLe bulletin n° 3 peut être réclamé par la personne qu’il concerne. Il ne doit,\nen aucun cas, être délivré à un tiers.","[CPPN] Art. 716 : Lorsque au cours d’une procédure quelconque, le procureur de\nla République ou le juge d’instruction constate qu’un individu a été condamné\nsous une fausse identité ou a usurpé un état civil, il est immédiatement\nprocédé d’office, à la diligence du procureur de la République, aux\nrectifications nécessaires avant la clôture de la procédure.\nLa rectification est demandée par requête au président du tribunal ou de la\nCour qui a rendu la décision. Si la décision a été rendue par une Cour\nd’assises, la requête est soumise à la Chambre d’accusation.\nLe président communique la requête au ministère public et commet, le cas\néchéant, un magistrat pour faire le rapport. Les débats ont lieu et le jugement\nest rendu en Chambre du conseil. Le tribunal ou la Cour peut ordonner\nd’assigner la personne objet de la condamnation.\nSi la requête est admise, les frais sont supportés par celui qui a été la cause\nde l’inscription erronée s’il a été appelé dans l’instance. Dans le cas\ncontraire ou dans celui de son insolvabilité, ils sont supportés par le trésor.\nToute personne qui veut faire rectifier une mention portée à son casier\njudiciaire peut agir dans la même forme. Dans le cas où la requête est\nrejetée, le requérant est condamné aux frais.\nMention de la décision est faite en marge du jugement ou de l’arrêt visé\npar la demande en rectification.\n\nLa même procédure est applicable au cas de contestation sur la\nréhabilitation de droit, ou de difficultés soulevées par l’interprétation d’u","[CPPN] Art. 717 : Un décret pris en Conseil des ministres détermine les mesures\nnécessaires à l’exécution des articles 706 à 716, et notamment les conditions\ndans lesquelles doivent être demandés, établis et délivrés les bulletins n° l,\n2 et 3 du casier judiciaire.","[CPPN] Art. 718 : Quiconque a pris le nom d’un tiers, dans les circonstances qui\nont déterminé ou auraient pu déterminer l’inscription d’une condamnation\nau casier judiciaire de celui-ci, est puni de six mois à cinq ans\nd’emprisonnement et de 50.000 à 1.000.000 de francs d’amende, sans\npréjudice des poursuites à exercer éventuellement du chef de faux.\nLa peine ainsi prononcée est subie immédiatement après celle encourue\npour l’infraction à l’occasion de laquelle l’usurpation de nom a été commise.\nEst puni des peines prévues à l’alinéa premier celui qui, par de fausses déclarations\nrelatives à l’état civil d’un inculpé, a sciemment été la cause de l’inscription\nd’une condamnation sur le casier judiciaire d’un autre que cet inculpé.","[CPPN] Art. 719 : Quiconque, en prenant un faux nom ou une fausse qualité, s’est\nfait délivrer un extrait du casier judiciaire d’un tiers est puni de dix jours à\ndeux mois d’emprisonnement et de 40.000 à 200.000 francs d’amende.\nEst puni des mêmes peines celui qui aura fourni des renseignements\nd’identité imaginaires qui ont provoqué ou auraient pu provoquer des\nmentions erronées au casier judiciaire.\nTITRE IX : DE LA REHABILITATION DES CONDAMNES","[CPPN] Art. 720 : Toute personne condamnée par une juridiction du Niger à une\npeine criminelle ou correctionnelle peut être réhabilitée.","[CPPN] Art. 721 : La réhabilitation est soit acquise de plein droit, soit accordée\npar arrêt de la Chambre d’accusation.","[CPPN] Art. 722 : Elle est acquise de plein droit au condamné qui n’a, dans les\ndélais ci-après déterminés, subi aucune condamnation nouvelle à\nl’emprisonnement ou à une peine plus grave pour crime ou délit :\n\n1) pour la condamnation à l’amende, après un délai de cinq ans, à compter\ndu jour du paiement de l’amende ou de l’expiration de la contrainte par\ncorps ou de la prescription accomplie;\n2) pour la condamnation unique à une peine d’emprisonnement ne dépassant\npas six mois, après un délai de dix ans, à compter soit de l’expiration de la\npeine subie, soit de la prescription accomplie;\n3) pour la condamnation unique à une peine d’emprisonnement ne dépassant\npas deux ans ou pour les condamnations multiples dont l’ensemble ne dépasse\npas un an, après un délai de quinze ans compté comme il est dit au paragraphe\nprécédent ;\n4) pour la condamnation unique à une peine supérieure à deux ans\nd’emprisonnement ou pour les condamnations multiples dont l’ensemble\nne dépasse pas deux ans, après un délai de vingt ans compté de la même\nmanière.\nSont, pour l’application des dispositions qui précèdent, considérées comme\nconstituant une condamnation unique, les condamnations dont la confusion\na été accordée.\nLa remise totale ou partielle d’une peine par voie de grâce équivaut à son\nexécution totale ou partielle.","[CPPN] Art. 723 : La réhabilitation ne peut être demandée en justice, du vivant du\ncondamné, que par celui-ci, ou, s’il est interdit, par son représentant légal;\nen cas de décès, et si les conditions légales sont remplies, la demande peut\nêtre suivie par son conjoint ou par ses ascendants ou descendants, et même\nformée par eux, mais dans le délai d’une année seulement à dater du décès.\nLa demande doit porter sur l’ensemble des condamnations prononcées qui\nn’ont pas été effacées ni par une réhabilitation antérieure ni par l’amnistie.","[CPPN] Art. 724 : La demande en réhabilitation ne peut être formée qu’après un\ndélai de sept ans pour les condamnés à une peine criminelle et de quatre\nans pour les condamnés à une peine correctionnelle.\nCe délai part, pour les condamnés à une amende, du jour où la condamnation\nest devenue irrévocable et, pour les condamnés à une peine privative de\nliberté, du jour de leur libération définitive, ou conformément aux dispositions\n\nde l’article 675, alinéa 4, du jour de leur libération conditionnelle lorsque\ncelle-ci n’a pas été suivie de révocation.","[CPPN] Art. 725 : Les condamnés qui sont en état de récidive légale, ceux qui,\naprès avoir obtenu la réhabilitation, ont encouru une nouvelle condamnation,\nceux qui, condamnés contradictoirement ou par défaut à une peine criminelle,\nont prescrit contre l’exécution de la peine, ne sont admis à demander leur\nréhabilitation qu’après un délai de douze années écoulées depuis leur\nlibération ou depuis la prescription.\nNéanmoins, les récidivistes qui n’ont subi aucune peine criminelle et les\nréhabilités qui n’ont encouru qu’une condamnation à une peine\ncorrectionnelle sont admis à demander la réhabilitation après un délai de\nhuit années écoulées depuis leur libération.Sont également admis à demander\nleur réhabilitation, après un délai de huit années écoulées depuis la\nprescription, les condamnés contradictoirement ou par défaut à une peine\ncorrectionnelle qui ont prescrit contre l’exécution de la peine.\nLes condamnés contradictoirement, les condamnés par défaut, qui ont\nprescrit contre l’exécution de la peine, sont tenus, outre les conditions qui\nvont être énoncées, de justifier qu’ils n’ont encouru, pendant les délais de\nla prescription, aucune condamnation pour faits qualifiés crimes ou délits et\nqu’ils ont eu une conduite irréprochable.","[CPPN] Art. 726 : Le condamné doit, sauf le cas de prescription, justifier du paiement\ndes frais de justice, de l’amende et des dommages-intérêts ou de la remise\nqui lui en est faite;\nA défaut de cette justification, il doit établir qu’il a subi le temps de contrainte\npar corps déterminé par la loi ou que le trésor a renoncé à ce moyen d’exécution.\nS’il est condamné pour banqueroute frauduleuse, il doit justifier du paiement\ndu passif de la faillite en capital, intérêts et frais ou de la remise qui lui en\nest faite.\nNéanmoins, si le condamné justifie qu’il est hors d’état de se libérer des\nfrais de justice, il peut être réhabilité même dans le cas où ces frais n’auraient\npas été payés ou ne l’auraient été qu’en partie.\nEn cas de condamnation solidaire, la Cour fixe la part des frais de justice,\ndes dommages-intérêts ou du passif qui doit être payé par le demandeur.\n\nSi la partie lésée ne peut être retrouvée, ou si elle refuse de recevoir la\nsomme due, celle-ci est versée à la caisse des dépôts et consignations\ncomme en matière d’offres de paiement et de consignation. Si la partie ne\nse présente pas dans un délai de cinq ans pour se faire attribuer la somme\nconsignée, cette somme est restituée au déposant sur sa simple demande.","[CPPN] Art. 727 : Si depuis l’infraction le condamné a rendu des services éminents\nau pays, la demande de réhabilitation n’est soumise à aucune condition de\ntemps ni d’exécution de peine. En ce cas, la Cour peut accorder la\nréhabilitation même si les frais, l’amende et les dommages-intérêts n’ont\npas été payés.","[CPPN] Art. 728 : Le condamné adresse la demande en réhabilitation au procureur\nde la République de sa résidence actuelle.\nCette demande précise :\n1)\n\nla date de la condamnation;\n\n2)\n\nles lieux où le condamné a résidé depuis sa libération.","[CPPN] Art. 729 : Le procureur de la République s’entoure de tous renseignements\nutiles aux différents lieux où le condamné a pu séjourner.","[CPPN] Art. 730 : Le procureur de la République se fait délivrer :\n1)\n\nune expédition des jugements de condamnation;\n\n2) un extrait du registre des lieux de détention où la peine a été subie\nconstatant quelle a été la conduite du condamné;\n3) un bulletin n° 1 du casier judiciaire.\nIl transmet les pièces avec son avis au procureur général.","[CPPN] Art. 731 : La Cour est saisie par le procureur général.\nLe demandeur peut soumettre directement à la Cour toutes pièces utiles.","[CPPN] Art. 732 : La Cour statue dans le mois sur les conclusions du procureur\ngénéral, la partie ou son conseil entendu ou dûment convoqué.","[CPPN] Art. 733 : L’arrêt de la Chambre d’accusation peut être déféré à la\nChambre judiciaire de la Cour suprême dans les formes prévues par le\nprésent code.\n\nCode de procédure pénale","[CPPN] Art. 734 : Dans les cas visés par l’article 727, le pourvoi en cassation\nformé contre l’arrêt rejetant la demande en réhabilitation est formé sans\nconsignation ni frais. Tous les actes de la procédure sont visés pour timbre\net enregistrés gratis.","[CPPN] Art. 735 : En cas de rejet de la demande, une nouvelle demande ne peut\nêtre formée avant l’expiration d’un délai de deux années, à moins que le\nrejet de la première ait été motivé par l’insuffisance des délais d’épreuve.\nEn ce cas la demande peut être renouvelée dès l’expiration de ces délais.","[CPPN] Art. 736 : Mention de l’arrêt prononçant la réhabilitation est faite en marge\ndes arrêts ou jugements de condamnation et au casier judiciaire.\nDans ce cas, les bulletins n° 2 et 3 du casier judiciaire ne doivent pas\nmentionner la condamnation.\nLe réhabilité peut se faire délivrer sans frais une expédition de l’arrêt de\nréhabilitation et un extrait du casier judiciaire.","[CPPN] Art. 737 : La réhabilitation efface la condamnation et fait cesser pour\nl’avenir toutes les incapacités qui en résultent.\nTITRE X : DES FRAIS DE JUSTICE","[CPPN] Art. 738 : Un décret pris en Conseil des ministres détermine les frais qui\ndoivent être compris sous la dénomination de frais de justice criminelle,\ncorrectionnelle et de simple police; il en établit le tarif, en règle le paiement\net le recouvrement, détermine les voies de recours, fixe les conditions que\ndoivent remplir les parties prenantes et, d’une façon générale, règle tout ce\nqui touche aux frais de justice en matière criminelle, correctionnelle et de\nsimple police.\nTITRE XI : DISPOSITIONS GENERALES","[CPPN] Art. 739 : Sont abrogées toutes dispositions contraires et antérieures au\nprésent code.","[CPPN] Art. 741 : La présente loi sera publiée au Journal Officiel de la République\ndu Niger et exécutée comme loi de l’Etat.\n\nAnnexes\n\nANNEXES\n\ni\n\nAnnexes\n\nii\n\nAnnexes\n\nSOMMAIRE\n♦","[CPCN] Article premier : Les dispositions du présent code s’appliquent devant toutes les\njuridictions civiles, commerciales et sociales, sous réserve des règles spéciales à chacune\nd’elles.\nTITRE PREMIER – DES PRINCIPES DIRECTEURS DU PROCÈS\nCHAPITRE PREMIER – DES DROITS FONDAMENTAUX\n\nSection 1 : Du droit d’accès à la Justice","[CPCN] Article 2 : Toute personne a le droit de saisir les juridictions nationales compétentes de\ntout acte violant les droits fondamentaux qui lui sont reconnus et garantis par la\nConstitution, les conventions internationales, les lois et les règlements en vigueur.","[CPCN] Article 3 : Toute personne a le droit à ce que sa cause soit entendue par une juridiction\nindépendante et impartiale, dans un délai raisonnable.\nLe juge est obligé d’appliquer la loi. Il ne peut tirer prétexte du silence ou de\nl’obscurité de la loi pour refuser de statuer, sous peine de déni de justice.\nSection 2 : Des droits de la défense","[CPCN] Article 4 : Les parties peuvent se défendre elles-mêmes, sous réserve des cas dans\nlesquels la représentation est obligatoire.\n\nElles peuvent se faire représenter ou se faire assister par toute personne de leur\nchoix suivant ce que la loi permet ou ordonne.","[CPCN] Article 5 : Nulle partie ne peut être jugée sans avoir été entendue ou dûment appelée.","[CPCN] Article 6 : Les parties doivent se faire connaître, mutuellement et en temps utile, les\nmoyens de fait sur lesquels elles fondent leurs prétentions, les éléments de preuve\nqu’elles produisent et les moyens de droit qu’elles invoquent afin que chacune puisse\norganiser sa défense.","[CPCN] Article 7 : En toutes circonstances, le juge doit faire observer et observer lui-même le\nprincipe du contradictoire. Il ne peut fonder sa décision sur les moyens de droit qu’il a\nrelevés d’office ou sur les explications complémentaires qu’il a demandées, sans avoir au\npréalable invité les parties à présenter leurs observations.","[CPCN] Article 8 : Le juge peut recourir aux services d’un ou de plusieurs interprètes.\nSection 3 : De la publicité des débats et des jugements","[CPCN] Article 9 : Les débats sont publics sauf lorsque la loi permet qu’ils se déroulent\n\nen\n\nchambre de conseil ou à huis clos.\nLes arrêts et jugements sont prononcés publiquement sauf dispositions contraires\nde la loi.\nCHAPITRE 2 – DU RESPECT DÛ À LA JUSTICE","[CPCN] Article 10 : Les parties sont tenues d’observer en tout temps le respect dû à la justice.\nLe juge peut, suivant la gravité des manquements, prononcer, même d’office, des\ninjonctions, supprimer des écrits, les déclarer calomnieux, ordonner l’impression et\nl’affichage des jugements ou leur publication par voie de presse.\nCHAPITRE 3 – DE L’ACTION EN JUSTICE\n\nSection 1 : De la définition et des conditions","[CPCN] Article 11 : L’action est le droit pour l’auteur d’une prétention d’être entendu sur le fond de\ncelle-ci, afin que le juge la dise bien ou mal fondée.\nPour l’adversaire, l’action est le droit de discuter le bien-fondé de cette prétention.","[CPCN] Article 12 : L’action est ouverte à tous ceux qui ont un intérêt légitime au succès ou au\nrejet d’une prétention, sous réserve des cas dans lesquels la loi attribue le droit d’agir aux\nseules personnes qu’elle qualifie pour élever ou combattre une prétention, ou pour\ndéfendre un intérêt déterminé.\n\n2","[CPCN] Article 13 : Est irrecevable toute prétention émise par ou contre une personne dépourvue\ndu droit d’agir.","[CPCN] Article 14 : L’action se prescrit suivant les distinctions prévues au Code Civil ou par la loi\ndans les matières qui font l’objet d’une législation particulière.","[CPCN] Article 15 : L’action malicieuse, vexatoire, dilatoire, ou qui n’est pas fondée sur des\nmoyens sérieux, constitue une faute ouvrant droit à réparation. Il en est de même de la\nrésistance abusive à une action bien fondée.\nSection 2 : De l’instance","[CPCN] Article 16 : L’instance est la mise en œuvre de l’action.\nSeules les parties introduisent l’instance, hors les cas où la loi en dispose\nautrement. Elles ont la liberté d'y mettre fin avant qu'elle ne s'éteigne par l'effet du\njugement ou en vertu de la loi.","[CPCN] Article 17 : Les parties conduisent l’instance sous les charges qui leur incombent. Il leur\nappartient d’accomplir les actes de la procédure dans les formes et délais requis.\nToutefois, lorsque la loi permet ou la nécessité commande qu’une mesure soit\nordonnée à l’insu d’une partie, celle-ci dispose d’un recours approprié contre la décision\nqui lui fait grief.","[CPCN] Article 18 : Le juge veille au bon déroulement de l’instance ; il a le pouvoir d’impartir des\ndélais et d’ordonner les mesures nécessaires.\nIl entre dans sa mission de concilier les parties.\nSection 3 : De l’objet du litige","[CPCN] Article 19 : L’objet du litige est déterminé par les prétentions respectives des parties, qui\nsont fixées par l’acte introductif d’instance et par les conclusions en défense, sous réserve\ndes dispositions relatives à la procédure orale telles qu’elles sont prévues à l’article 474 du\nprésent Code.\nToutefois, l’objet du litige peut être modifié par des demandes incidentes lorsque\ncelles-ci se rattachent aux prétentions originales par un lien suffisant.","[CPCN] Article 20 : Le juge doit se prononcer sur tout ce qui est demandé et seulement sur ce qui\nest demandé.\n\nSection 4 : Des faits","[CPCN] Article 21 : À l’appui de leurs prétentions, les parties ont la charge d’alléguer les faits\npropres à les fonder.","[CPCN] Article 22 : Le juge ne peut fonder sa décision que sur des faits qui sont dans les débats.","[CPCN] Article 23 : Le juge peut inviter les parties à fournir les explications de fait qu’il estime\nnécessaires à la solution du litige.\nSection 5 : Des preuves","[CPCN] Article 24 : Il incombe à chaque partie de prouver, conformément à la loi, les faits\nnécessaires au succès de sa prétention.","[CPCN] Article 25 : Le juge a le pouvoir d’ordonner d’office toutes les mesures d’instruction\nlégalement admissibles.","[CPCN] Article 26 : Les parties sont tenues d’apporter leur concours aux mesures d’instruction,\nsauf au juge à tirer toute conséquence d’une abstention ou d’un refus.\nSi une partie détient un élément de preuve, le juge peut à la requête de l’autre\npartie, lui enjoindre de le produire, au besoin sous peine d’astreinte. Il peut à la requête de\nl’une des parties, demander sous la même peine, la production de tous documents\ndétenus par des tiers s’il n’existe pas d’empêchement légitime.\nSection 6 : Du droit","[CPCN] Article 27 : Le juge tranche le litige conformément aux règles de droit qui lui sont\napplicables.\nIl doit donner ou restituer leur exacte qualification aux faits et actes litigieux,\nnonobstant la dénomination que les parties en auraient proposée. Il ne peut d’office\nrelever les moyens de pur droit, sans avoir invité les parties à présenter leurs\nobservations.","[CPCN] Article 28 : Le juge peut inviter les parties à fournir les explications de droit qu’il estime\nnécessaires à la solution du litige.\nSection 7 : Des règles propres à la matière gracieuse","[CPCN] Article 29 : Le juge statue en matière gracieuse lorsqu’en l’absence de litige, il est saisi\nd’une demande dont la loi exige, en raison de la nature de l’affaire ou de la qualité du\nrequérant, qu’elle soit soumise à son contrôle.\n4","[CPCN] Article 30 : Le juge ne peut procéder à toutes investigations utiles, entendre toute\npersonne, sans que le demandeur ait été préalablement informé et appelé à présenter ses\nobservations.","[CPCN] Article 31 : Le juge peut fonder sa décision sur tous les faits relatifs au cas qui lui est\nsoumis y compris ceux qui n’auraient pas été allégués. Il peut se prononcer sans débats\ndans la mesure où il est fait droit à la requête.","[CPCN] Article 32 : Un tiers peut être autorisé par le juge à consulter le dossier de l'affaire et à\ns'en faire délivrer copie, s'il justifie d'un intérêt légitime.\nTITRE II – DE LA COMPÉTENCE\nCHAPITRE PREMIER – DE LA COMPÉTENCE D’ATTRIBUTION","[CPCN] Article 33 : La compétence, en raison de la matière, est déterminée par les règles\nd’organisation judiciaire et par les dispositions particulières.","[CPCN] Article 34 : La compétence en raison du montant de la demande ainsi que le taux du\nressort en dessous duquel l’appel n’est pas ouvert sont déterminés par les règles propres\nà chaque juridiction et par les dispositions ci-après.","[CPCN] Article 35 : Toute juridiction saisie d’une demande de sa compétence connaît de tous les\nmoyens de défense à l’exception de ceux qui soulèvent une question relevant de la\ncompétence exclusive d’une autre juridiction, même s'ils exigent l'interprétation d'un\ncontrat.","[CPCN] Article 36 : Les incidents d’instance sont tranchés par la juridiction devant laquelle se\ndéroule l’instance qu’ils affectent.","[CPCN] Article 37 : Le tribunal de grande instance connaît de toutes les demandes incidentes qui\nne relèvent pas de la compétence exclusive d’une autre juridiction.\nLes autres juridictions ne connaissent que des demandes incidentes qui entrent\ndans leur compétence d’attribution.","[CPCN] Article 38 : Lorsque plusieurs prétentions fondées sur des faits différents et non connexes\nsont émises par un demandeur contre le même adversaire et réunies en une même\ninstance, le taux du ressort est déterminé par la valeur de chaque prétention considérée\nisolément.\nLorsque les prétentions réunies sont fondées sur les mêmes faits ou sont\nconnexes, le taux du ressort est déterminé par la valeur totale de ces prétentions.\n5","[CPCN] Article 39 : Lorsque les prétentions sont émises, dans une même instance et en vertu\nd’un titre commun par plusieurs demandeurs ou contre plusieurs défendeurs, le taux du\nressort est déterminé pour l’ensemble des prétentions par la plus élevée d’entre elles.","[CPCN] Article 40 : Le juge se prononce toutefois en dernier ressort si la seule demande qui\nexcède le taux du dernier ressort est une demande reconventionnelle en dommagesintérêts fondée exclusivement sur la demande initiale.","[CPCN] Article 41 : Le jugement qui statue sur une demande indéterminée est, sauf disposition\ncontraire, susceptible d’appel.\nCHAPITRE II – DE LA COMPÉTENCE TERRITORIALE","[CPCN] Article 42 : Le tribunal territorialement compétent est, sauf disposition contraire de la loi,\ncelui du domicile du défendeur ou, à défaut, de sa résidence.\nS’il y a plusieurs défendeurs, le demandeur saisit, à son choix, la juridiction du\ndomicile ou, à défaut, de la résidence de l’un d’eux.\nSi le défendeur n’a ni domicile ni résidence connus, le demandeur peut saisir la\njuridiction du lieu où il demeure ou celle de son choix s'il demeure à l'étranger.\nLe domicile se détermine selon les règles du Code Civil.\nEn cas d’élection de domicile, la demande peut être portée devant le tribunal du\ndomicile élu.","[CPCN] Article 43 : En matière réelle immobilière, le tribunal du lieu où est situé l’immeuble est\nseul compétent.\nEn matière de succession, les demandes entre héritiers, les demandes formées par\nles créanciers du défunt et les demandes relatives à l’exécution des dispositions à cause\nde mort sont portées devant le tribunal dans le ressort duquel est ouverte la succession,\njusqu’au partage inclusivement.","[CPCN] Article 44 : Le demandeur peut saisir à son choix, outre le tribunal du domicile du\ndéfendeur :\n-\n\nen matière contractuelle, le tribunal du lieu où le contrat s’est formé ou celui\n\ndu lieu où l’obligation doit être ou a été exécutée ;\n-\n\nen matière délictuelle, le tribunal du lieu du fait dommageable ;\n\n-\n\nen matière mixte, la juridiction du lieu où est situé l’immeuble ;\n\n- en matière d’aliments ou de contribution aux charges du mariage, le tribunal\ndu lieu où demeure le créancier.","[CPCN] Article 45 : En matière commerciale, le demandeur peut assigner à son choix :\n- devant le tribunal du domicile du défendeur ;\n- devant celui dans le ressort duquel la promesse a été faite ou la marchandise\nlivrée ;\n- devant celui dans le ressort duquel le paiement devait être exécuté.","[CPCN] Article 46 : En matière de procédure collective et d’apurement du passif, le tribunal\ncompétent est celui du domicile du débiteur.","[CPCN] Article 47 : Lorsqu’un magistrat ou un auxiliaire de justice est partie à un litige qui relève\nde la compétence d’une juridiction dans le ressort de laquelle celui-ci exerce ses fonctions,\nle demandeur peut saisir une juridiction située dans un ressort limitrophe.","[CPCN] Article 48 : Le défendeur ou toutes les parties en cause peuvent également demander le\nrenvoi devant une juridiction choisie dans les mêmes conditions que celles prévues à\nl’article précédent ; il est alors procédé comme il est dit à l’article 347 de la présente loi.","[CPCN] Article 49 : Les demandes formées pour frais par les conseils, les huissiers de justice ou\nles officiers ministériels sont portées devant le tribunal où les frais ont été faits.","[CPCN] Article 50 : Il n’est pas dérogé aux règles spéciales de compétence édictées par les lois\nparticulières.\nToute clause qui, directement ou indirectement, déroge aux règles de compétence\nterritoriale est réputée non écrite, à moins qu’elle n’ait été convenue entre des personnes\nayant toutes contracté en qualité de commerçants et qu’elle n’ait été spécifiée de façon\napparente dans l’engagement de la partie à qui elle est opposée.\nTITRE III – DE LA REPRÉSENTATION ET DE L’ASSISTANCE EN JUSTICE\nCHAPITRE PREMIER– DE LA REPRÉSENTATION EN JUSTICE","[CPCN] Article 51 : En toute matière et devant toutes les juridictions, les parties peuvent se faire\nreprésenter ou assister par un conseil.","[CPCN] Article 52 : Le mandat de représentation en justice emporte pouvoir d’engager le mandant\net obligation d’accomplir en son nom tous les actes de procédure nécessaires ou utiles à\nl’instance.\n\nLe mandat de représentation emporte mission d’assistance sauf disposition ou\nconvention contraire.\nLa mission d’assistance en justice emporte pouvoir et devoir de conseiller la partie\net de présenter sa défense sans l’obliger.","[CPCN] Article 53 : Sous réserve des dispositions législatives ou réglementaires y dérogeant, nul\nne peut, s’il n’est avocat, postuler ou plaider devant les juridictions et les organismes\njuridictionnels ou disciplinaires de quelque nature que ce soit.","[CPCN] Article 54 : Le mandataire justifie de son mandat par un pouvoir spécial écrit ou par\ndéclaration verbale de la partie comparaissant avec lui devant le juge.\nLes avocats sont dispensés d’avoir à justifier de leur mandat.","[CPCN] Article 55 : La personne investie d’un mandat de représentation en justice est réputée, à\nl’égard du juge et de la partie adverse, avoir reçu pouvoir spécial de faire accepter un\ndésistement, d’acquiescer ou de transiger.","[CPCN] Article 56 : La constitution d’un mandataire vaut élection de domicile chez celui-ci. À\ndéfaut, toutes les significations seront valablement faites au greffe de la juridiction saisie.\nUn avocat est légalement domicilié en son cabinet.\nCHAPITRE II – DE LA RENONCIATION ET DE LA RÉVOCATION DU MANDATAIRE","[CPCN] Article 57 : Le représentant qui entend mettre fin à son mandat n’en est déchargé\nqu’après avoir informé son mandant, le juge et la partie adverse de son intention.","[CPCN] Article 58 : La partie qui révoque son mandataire doit immédiatement, soit pourvoir à son\nremplacement, soit informer le juge et la partie adverse de son intention de se défendre\nelle-même, faute de quoi, son adversaire est fondé à poursuivre la procédure et à obtenir\njugement en continuant à reconnaître le représentant révoqué.\nCHAPITRE III – DE LA CONSTITUTION ET DE LA RÉNONCIATION DU MANDATAIRE","[CPCN] Article 59 : Les parties peuvent constituer conseil à tout moment de la procédure, par\ndéclaration écrite ou verbale faite au greffe de la juridiction ou à l’audience. La constitution\ndoit être notifiée à la partie adverse.","[CPCN] Article 60 : Le conseil ne peut se décharger de son mandat de représentation que par\ndéclaration écrite à laquelle est annexée la justification de l’avis à son mandant de sa\nrenonciation, de la date de l’audience à laquelle l’affaire sera appelée et des\nconséquences qui pourront en résulter. Si à l’audience à laquelle l’affaire est appelée, la\n\npartie ne se présente pas sans motif légitime, ni personne pour elle, l’affaire est\nobligatoirement retenue pour être jugée contradictoirement. L’avocat qui s’est déporté ne\npeut en aucun cas se constituer dans la même affaire et pour la partie adverse.\nCHAPITRE IV – DE L’ASSISTANCE JUDICIAIRE","[CPCN] Article 61 : L’assistance judiciaire peut être accordée en tout état de cause à tout\nplaideur, lorsqu’en raison de sa vulnérabilité, de l’insuffisance de ses ressources, il se\nretrouve dans l’impossibilité d’exercer ses droits en justice, soit en demandant, soit en\ndéfendant. Elle est également applicable à tous actes de juridiction gracieuse.","[CPCN] Article 62 : Le bénéficiaire est dispensé de consigner les frais et droits qui sont avancés\npar l’Agence Nationale de l’Assistance Juridique et Judiciaire.\nIl bénéficie du concours gratuit d’un huissier et de l’assistance gratuite d’un conseil\ndont les rémunérations sont prises en charge par l’’Agence Nationale de l’Assistance\nJuridique et Judiciaire.\nL’assistance s’étend de plein droit aux actes et procédures d’exécution.","[CPCN] Article 63 : Les conditions de l’admission au bénéfice de l’assistance judiciaire, les\nconditions de retrait et les modalités de recouvrement des frais sont fixées par les lois et\nles règlements en vigueur.\nCHAPITRE V– DU MINISTÈRE PUBLIC","[CPCN] Article 64 : Le ministère public peut agir comme partie principale ou intervenir comme\npartie jointe. Il représente autrui dans les cas que la loi détermine.\nSection 1 : Du ministère public partie principale","[CPCN] Article 65 : Le ministère public agit d’office dans les cas spécifiés par la loi et dans tous\nles cas où l’ordre public se trouve directement et principalement intéressé. L’action est\nalors exercée par le procureur de la République quelle que soit la juridiction compétente ;\nen cause d’appel, elle est exercée par le procureur général.\nSection 2 : Du ministère public partie jointe","[CPCN] Article 66 : Le ministère public doit avoir communication des causes relatives à l’état des\npersonnes, ainsi que de toutes les causes dans lesquelles la loi dispose qu’il doit être\nentendu. Il en est de même en cas de procédures collectives d’apurement du passif.\nLe dossier de la procédure ainsi que les conclusions écrites du ministère public sont\ndéposés au greffe dans un délai raisonnable.\n9","[CPCN] Article 67 : Le ministère public peut prendre communication des autres causes dans\nlesquelles il estime devoir intervenir. Le juge peut décider d’office la communication de\ntoute cause au ministère public.\nTITRE IV – DES DÉLAIS ET DES ACTES DE PROCÉDURE\nCHAPITRE PREMIER – DE LA NOTIFICATION DES ACTES DE PROCÉDURE","[CPCN] Article 68 : Les actes sont portés à la connaissance des intéressés par la notification qui\nleur en est faite soit en la forme ordinaire par la voie postale ou la remise contre\némargement, récépissé, ou accusé de réception, soit par acte d’huissier ou par tout\nmoyen probant laissant trace écrite.\nSection 1 : De la notification en la forme ordinaire","[CPCN] Article 69 : La notification par voie administrative, postale ou par remise par personne\nqualifiée doit contenir toutes les indications relatives aux nom et prénoms, ou tout autre\nmoyen d’identification, ou à la dénomination ou la raison sociale de la personne dont elle\némane, et au domicile ou siège social de cette personne.\nElle doit désigner de la même manière la personne du destinataire.\nLes autres mentions que doit comporter la notification sont déterminées selon la\nnature de l’acte notifié par les règles particulières à chaque matière.","[CPCN] Article 70 : La notification par voie administrative, postale ou par remise contre apposition\nde l’empreinte digitale, émargement ou récépissé est faite sous enveloppe ou pli fermé.","[CPCN] Article 71 : La date de l’expédition d’une notification faite par la voie postale est celle qui\nfigure sur le cachet du bureau d’émission.\nLa date de la remise est celle du récépissé ou de l’émargement. La date de\nréception d’une notification faite par lettre recommandée avec demande d’avis de\nréception est celle qui est apposée par l’administration des postes lors de la remise de la\nlettre à son destinataire.\nSection 2 : De la notification par acte d’huissier","[CPCN] Article 72 : La notification faite par acte d’huissier de justice est une signification.\nLa notification peut toujours être faite par voie de signification alors même que la loi\nne l’aurait pas prévue.\n\n10","[CPCN] Article 73 : La date de la signification d’un acte d’huissier est celle du jour où elle est faite\nà personne, à domicile, à tout voisin qui l’accepte, à chef de quartier, à hameau, à village,\nà groupement, à canton, à mairie ou à parquet.\nCHAPITRE II – DES DÉLAIS DE PROCÉDURE","[CPCN] Article 74 : Lorsqu’un délai est exprimé en jours, le jour de l’acte, de l’événement, de la\ndécision ou de la notification qui le fait courir, ne compte pas.","[CPCN] Article 75 : Lorsqu’un délai est exprimé en mois ou en années, ce délai expire le jour du\ndernier mois ou de la dernière année qui porte le même quantième que le jour de l’acte,\nde l’événement, de la décision ou de la notification qui le fait courir. À défaut d’un\nquantième identique, le délai expire le dernier jour du mois.\nLorsqu'un délai est exprimé en mois et en jours, les mois sont d'abord décomptés,\npuis les jours.","[CPCN] Article 76 : Tout délai expire le dernier jour à la fin de la vingt-quatrième (24ème) heure.\nLe délai qui expire normalement un samedi, un dimanche ou un jour férié ou chômé, est\nprorogé jusqu’au premier jour ouvrable suivant.","[CPCN] Article 77 : Lorsqu’une demande est portée devant une juridiction, les délais de\ncomparution, d’opposition, d’appel et de pourvoi en cassation sont augmentés de :\n1) un (1) mois pour les personnes qui sont domiciliées hors du siège de la\njuridiction ;\n2) deux (2) mois pour celles qui demeurent à l’étranger.","[CPCN] Article 78 : Lorsqu’un acte destiné à une partie domiciliée hors du territoire, est délivré à\nsa personne au Niger, il n’emporte que les délais accordés à ceux qui y demeurent.\nCHAPITRE III – DES ACTES D’HUISSIER DE JUSTICE","[CPCN] Article 79 : Les actes d’huissier de justice indiquent indépendamment des mentions\nprescrites par ailleurs :\n1) la date : jour, mois et an ;\n2) si le requérant est une personne physique, ses nom, prénoms, profession,\nnationalités, date et lieu de naissance, domicile et, s’il y a lieu, l’élection du\ndomicile ;\n3) si le requérant est une personne morale, sa forme, sa dénomination, son siège\nsocial, son adresse complète et l’organe qui la représente légalement ;\n\n4) l’objet de l’acte ;\n5) les nom, prénoms et domicile de l’huissier et sa signature.\nCes mentions sont prescrites à peine de nullité.","[CPCN] Article 80 : Les originaux des actes d’huissier de justice doivent porter mention des\nformalités et diligences auxquelles donne lieu l’application des dispositions des articles cidessous, avec l’indication de leur date.\nSection 1 : De la signification des actes","[CPCN] Article 81 : Aucune signification ne peut être faite avant six heures du matin et après sept\nheures du soir, non plus les dimanches, les jours fériés ou chômés, si ce n’est en vertu de\nla permission du juge dans le cas où il y aurait péril en la demeure.","[CPCN] Article 82 : Lorsqu’un acte doit être délivré dans une localité située au-delà d’un rayon de\nvingt (20) kilomètres de sa résidence, l’huissier peut le faire signifier par un huissier ad hoc\nou par la voie administrative dans les conditions fixées par arrêté du ministre de la justice.\nSous-section 1 : De la signification à personne","[CPCN] Article 83 : La signification doit être faite à personne. Elle est valable quel que soit le lieu\noù l’acte est délivré y compris le lieu du travail. L’huissier remet à la personne désignée à\nl’acte, copie de l’acte en précisant qu’il a été délivré parlant à la personne, en tel lieu et à\ntelle date.","[CPCN] Article 84 : La signification faite à une personne morale n’est à personne que lorsque\nl’acte est délivré à son représentant légal, à un fondé de pouvoir de ce dernier ou à toute\nautre personne habilitée à cet effet ou à toute personne recevant habituellement le\ncourrier.\nSi la personne physique ou morale refuse de signer et ou de prendre copie de\nl’acte, mention en est faite sur l’acte et la signification n’en est pas moins valable.","[CPCN] Article 85 : La signification faite à une personne morale de droit public est reçue par le\npréposé pour la recevoir qui vise l’original. En cas de refus, l’original est visé par le\nProcureur de la République. Sous-section 2 : De la signification à domicile","[CPCN] Article 86 : Si la signification à personne s’avère impossible, l’acte peut être délivré à\ndomicile. La copie peut être remise à toute personne présente et à défaut, à un voisin, s’il\n\nl’accepte. L’huissier indique sur l’acte, les nom, prénoms et qualité de la personne\nprésente ou du voisin en précisant que l’acte a été délivré au domicile du destinataire.\nDans tous les cas, l’huissier doit laisser au domicile du destinataire un avis de\npassage daté, l’avertissant de la remise de la copie et mentionnant la nature de l’acte, le\nnom du requérant ainsi que l’indication de la personne à laquelle la copie a été remise.\nSous-section 3 : De la signification à quartier, à village, à groupement,\nà canton, à mairie","[CPCN] Article 87 : Si l’huissier ne trouve aucune personne au domicile du destinataire de l’acte,\nou si la personne présente ne peut ou ne veut recevoir la copie, il remet sans délai la\ncopie au maire ou à défaut à son adjoint, au secrétaire de la mairie, à l’autorité\nadministrative ou coutumière.\nL’huissier précise alors, sur l’acte, qu’il a été délivré au maire ou à l’une des\nautorités citées au présent article.\nSous-section 4 : De la signification à parquet","[CPCN] Article 88 : Lorsque la personne visée à l’acte est sans domicile connu ou si elle\ndemeure hors du territoire national, l’huissier remet une copie au parquet en précisant le\nmode de délivrance de l’acte, le dernier domicile ou le dernier lieu de travail connu.\nLe procureur vise l’original et fait rechercher le destinataire aux fins de remise de la copie.\nIl informe l’huissier de justice des diligences faites et lui transmet le cas échéant tout\nprocès-verbal ou récépissé constatant la remise de la copie au destinataire pour être\nannexé à l’original. Ces documents sont transmis par l’huissier à la juridiction.\nSi l’intéressé n’est pas retrouvé, ou s’il n’est pas établi que le destinataire a été\neffectivement avisé, le juge peut prescrire d’office toutes diligences complémentaires sauf\nà ordonner les mesures provisoires ou conservatoires nécessaires à la sauvegarde des\ndroits du demandeur.","[CPCN] Article 89 :Lorsque la copie d’un acte est remise à toute autre personne qu’à la partie\nelle-même ou au Procureur de la République, elle est délivrée sous enveloppe fermée ne\nportant d’autre indication d’un côté, que les noms, prénoms et domicile de la partie et de\nl’autre, le cachet de l’étude de l’huissier apposé sur la fermeture du pli.\n\nSous-section 5 : Des règles particulières aux significations à l’étranger","[CPCN] Article 90 : La signification d’un acte destiné à une personne domiciliée à l’étranger est\nfaite au parquet qui est, selon le cas, celui de la juridiction devant laquelle la demande est\nportée, celui de la juridiction qui a statué, ou celui du domicile du requérant.\nL’huissier remet deux copies de l’acte au procureur qui vise l’original. Le procureur\nfait parvenir les copies de l’acte au ministre de la justice aux fins de transmission, sous\nréserve des cas où la transmission peut être faite de parquet à parquet.","[CPCN] Article 91 : Le jour même de la signification, ou au plus tard le premier jour ouvrable qui\nsuit, l’huissier doit expédier au destinataire par lettre recommandée une copie certifiée\nconforme de l’acte signifié. Le récépissé d’expédition est annexé à l’original.","[CPCN] Article 92 : L’acte destiné à un Etat étranger ou à un agent diplomatique étranger au\nNiger est signifié au parquet et transmis par l’intermédiaire du ministre de la justice.\nSection 2 : De la nullité des actes d’huissiers","[CPCN] Article 93 : Les dispositions des articles 79 à 92 de la présente loi sont observées sous\npeine de nullité. Toutefois, cette nullité ne pourra être prononcée que s’il a été porté\natteinte aux intérêts de la défense ou si elle nuit aux intérêts de celui qui l’invoque.","[CPCN] Article 94 : Nonobstant les dispositions de l’article précédent, la nullité d’un acte de\nprocédure peut être prononcée si une formalité substantielle a été omise. Le caractère\nsubstantiel est attaché, dans un acte de procédure, à ce qui tient à sa raison d’être et lui\nest indispensable pour remplir son objet.","[CPCN] Article 95 : Tous les moyens de nullité contre un acte doivent être soulevés\nconjointement.","[CPCN] Article 96 : Si un acte est déclaré nul par le fait d’un huissier celui-ci est condamné aux\nfrais de l’acte et de la procédure annulés, sans préjudice de tous autres dommagesintérêts qui pourront lui être réclamés.\nTITRE V – DE LA DEMANDE EN JUSTICE\nCHAPITRE PREMIER – DE LA DEMANDE PRINCIPALE","[CPCN] Article 97 : La demande principale est celle par laquelle un plaideur prend l’initiative d’un\nprocès en soumettant au juge ses prétentions. Elle introduit l’instance.\n\n14","[CPCN] Article 98 : Sous réserve des cas où l’instance est introduite par requête ou par la\nprésentation volontaire des parties devant le juge, la demande principale est formée par\nassignation ou par requête conjointe au greffe de la juridiction.","[CPCN] Article 99 : L’assignation est l’acte d’huissier de justice par lequel le demandeur cite son\nadversaire à comparaître devant le juge.\nLa requête conjointe est l’acte commun par lequel les parties soumettent au juge\nleurs prétentions respectives et les points sur lesquels elles sont en désaccord ainsi que\nleurs moyens respectifs.\nCHAPITRE II : DES DEMANDES INCIDENTES","[CPCN] Article 100 : Les demandes incidentes à la demande principale sont la demande\nreconventionnelle, la demande additionnelle et l’intervention.","[CPCN] Article 101 : La juridiction saisie statue par un seul et même jugement sur la demande\nprincipale et sur la demande incidente. Toutefois, si la demande incidente est de nature à\nretarder le jugement sur la demande principale, le juge peut statuer sur la demande\nprincipale, puis sur la demande incidente par un jugement distinct.\nSection 1 : Des demandes additionnelles et reconventionnelles","[CPCN] Article 102 : La demande additionnelle est formée par une partie pour modifier ses\nprétentions antérieures.\nLa demande reconventionnelle est formée par le défendeur en réplique à la\ndemande principale pour obtenir un avantage distinct du seul rejet de la prétention de son\nadversaire.","[CPCN] Article 103 : Les demandes additionnelles et reconventionnelles sont formées jusqu’à la\nclôture des débats par conclusions ou verbalement à l’audience suivant que les parties\nsont représentées ou non.\nElles ne sont recevables que si elles sont de la compétence de la juridiction saisie\nde la demande principale et si elles se rattachent aux prétentions originaires par un lien\nsuffisant.\nToutefois, la demande en compensation est recevable même en l’absence d’un tel\nlien, sauf au juge à la disjoindre si elle risque de retarder le jugement sur le fond.\n\nSection 2 : De l’intervention","[CPCN] Article 104 : Constitue une intervention, la demande dont l’objet est de rendre un tiers\npartie au procès engagé entre les parties originales.\nL’intervention n’est recevable que si elle se rattache aux prétentions des parties par\nun lien suffisant.","[CPCN] Article 105 : Lorsque la demande émane d’un tiers, l’intervention est volontaire. Lorsque\nle tiers est mis en cause par une partie, l’intervention est forcée.","[CPCN] Article 106 : Si l’intervention risque de retarder à l’excès le jugement sur le tout, le juge\nstatue d’abord sur la demande principale, sauf à statuer ensuite sur l’intervention.","[CPCN] Article 107 : L’intervenant conserve, malgré le désistement du demandeur principal, le\ndroit de faire juger le procès à son profit lorsqu’il excipe d’un droit propre distinct de celui\ndont se prévalait le demandeur.\nSous-section 1 : De l’intervention volontaire","[CPCN] Article 108 : L’intervention volontaire est principale ou accessoire.\nElle est principale lorsque son auteur élève une prétention à son profit ; dans ce cas\nelle n’est recevable que si celui-ci a le droit d’agir relativement à cette prétention.\nElle est accessoire lorsqu’elle appuie les prétentions d’une partie. Elle n’est alors\nrecevable que si son auteur a intérêt pour la conservation de ses droits à soutenir cette\npartie.\nL’intervenant à titre accessoire peut se désister unilatéralement de son intervention.\nSous-section 2 : De l’intervention forcée et de l’appel en garantie","[CPCN] Article 109 : Un tiers peut être mis en cause aux fins de condamnation par toute partie qui\nest en droit d’agir contre lui à titre principal.\nIl peut également être mis en cause par la partie qui y a intérêt afin de lui rendre\ncommun le jugement. Le tiers doit être appelé en temps utile pour faire valoir sa défense.\nL’intervention forcée est formée par voie d’assignation.","[CPCN] Article 110 : Le juge peut inviter les parties à mettre en cause tous les intéressés dont la\nprésence lui paraît nécessaire à la solution du litige.\nEn matière gracieuse, il peut ordonner la mise en cause des personnes dont les\ndroits ou les charges risquent d’être affectés par la décision à prendre.\n16","[CPCN] Article 111 : Le tiers mis en cause est tenu de procéder devant la juridiction saisie de la\ndemande originale, sans qu’il puisse décliner la compétence territoriale de cette juridiction,\nmême en invoquant une clause attributive de compétence.","[CPCN] Article 112 : La garantie est simple ou formelle.\nLa garantie est simple, lorsque le demandeur en garantie est lui-même poursuivi comme\npersonnellement obligé ; il demeure partie principale.\nLa garantie est formelle lorsque le demandeur en garantie est seulement poursuivi comme\ndétenteur d’un bien; il peut toujours requérir avec sa mise hors de cause que le garant lui\nsoit substitué comme partie principale.\nCependant le garanti, quoique mis hors de cause comme partie principale peut y\ndemeurer pour la conservation de ses droits; le demandeur originaire peut demander qu’il\ny reste pour la conservation des siens.","[CPCN] Article 113 : Le jugement rendu contre le garant formel peut dans tous les cas être mis en\nexécution contre le garanti sous la seule condition qu’il lui ait été notifié.\nLes dépens ne sont recouvrables contre le garanti qu’en cas d’insolvabilité du\ngarant formel et sous réserve que le garanti soit demeuré en la cause, même à titre\naccessoire.\nTITRE VI – DES MOYENS DE DÉFENSE\nCHAPITRE PREMIER – DES DÉFENSES AU FOND","[CPCN] Article 114 : Constitue une défense au fond, tout moyen qui tend à faire rejeter comme\nnon justifiée la prétention de l’adversaire. Les défenses au fond peuvent être exposées en\ntout état de cause.\nCHAPITRE II – DES EXCEPTIONS DE PROCÉDURE","[CPCN] Article 115 : Constitue une exception de procédure, tout moyen qui tend, soit à faire\ndéclarer la procédure irrégulière ou éteinte, soit à en suspendre le cours. Les exceptions\nsont :\n-\n\nl’exception de caution à fournir par les étrangers ;\n\n-\n\nles exceptions d’incompétence ;\n\n-\n\nles exceptions de litispendance et de connexité ;\n\n-\n\nles exceptions dilatoires ;\n\n-\n\nles exceptions de nullité.\n17","[CPCN] Article 116 : Les\n\nexceptions\n\ndoivent,\n\nà\n\npeine\n\nd’irrecevabilité,\n\nêtre\n\nsoulevées\n\nsimultanément et avant toute défense au fond ou fin de non-recevoir. Il en est ainsi alors\nmême que les règles invoquées au soutien de l’exception sont d’ordre public.\nToutefois l’exception de connexité et les exceptions de nullité des actes de\nprocédure, soit pour vice de forme, soit pour inobservation des règles de fond peuvent être\nsoulevées en tout état de cause.\nSection 1 : De la caution à fournir par les étrangers","[CPCN] Article 117 : Sous réserve des conventions et accords internationaux, tout étranger,\ndemandeur principal ou intervenant, est tenu, si le défendeur le requiert avant toute\nexception, de fournir caution destinée au payement des frais et des dommages intérêts\nauxquels il pourrait être condamné.","[CPCN] Article 118 : Le jugement qui ordonne la caution en fixe le montant ; le demandeur est\ndispensé de fournir caution s’il justifie que ses immeubles situés au Niger sont suffisants\npour en répondre.\nSection 2 : Des exceptions d’incompétence","[CPCN] Article 119 : Sauf si l’incompétence est d’ordre public, les parties ne peuvent soulever les\nexceptions d’incompétence et de litispendance qu’après l’exception de caution et avant\ntoutes autres exceptions et défenses.","[CPCN] Article 120 : Si le tribunal saisi est incompétent en raison du lieu ou de la matière, la\npartie qui soulève cette exception doit faire connaître en même temps et à peine\nd’irrecevabilité, devant quelle juridiction elle demande que l’affaire soit portée.\nLe tribunal doit statuer sans délai sur la compétence s’il en est requis par le\ndemandeur à l’exception ; dans le cas contraire, il peut joindre l’incident au fond.\nLe délai d’appel des jugements statuant uniquement sur la compétence est de\nquinze (15) jours à compter du prononcé de la décision, sauf augmentation de délais en\nraison de la distance.\nLe délai est calculé comme il est dit aux articles 75 à 77 du présent Code.","[CPCN] Article 121 : L’incompétence en raison de la matière ne peut être prononcée d’office que :\n1°) lorsque la loi attribue compétence à une juridiction sociale, répressive ou\nadministrative ou commerciale ;\n2°) dans les instances où les règles de compétence sont d’ordre public ;\n\n3°) lorsque le défendeur ne comparait pas.\nLorsque le juge se déclare d’office incompétent, il désigne la juridiction\ncompétente ; cette désignation s’impose aux parties comme au juge de renvoi.","[CPCN] Article 122 : Lorsque le juge en se prononçant sur la compétence, tranche la question de\nfond dont elle dépend, sa décision a autorité de la chose jugée sur cette question de fond.\nSection 3 : Des exceptions de litispendance et de connexité","[CPCN] Article 123 : S’il a été formé précédemment devant un autre tribunal une demande ayant\nle même objet, ou si la contestation est connexe à une cause déjà pendante devant un\nautre tribunal, la juridiction saisie en second lieu doit se dessaisir au profit de l’autre, soit\nd’office, soit à la demande de l’une des parties. Il y a litispendance dans le premier cas,\nconnexité dans le second.","[CPCN] Article 124 : Lorsque les juridictions saisies ne sont pas de même degré, l’exception de\nlitispendance ou de connexité ne peut être soulevée que devant la juridiction du degré\ninférieur.","[CPCN] Article 125 : L’exception de connexité peut être soulevée en tout état de cause, sauf à\nêtre écartée si elle a été soulevée tardivement dans une intention dilatoire.","[CPCN] Article 126 : L’appel contre la décision rendue sur la litispendance ou la connexité par les\njuridictions du premier degré est formé comme en matière d’exception d’incompétence.","[CPCN] Article 127 : La décision rendue sur l’exception, soit par la juridiction qui en est saisie, soit\nà la suite d’un recours s’impose, tant à la juridiction de renvoi, qu’à celle dont le\ndessaisissement est ordonné.","[CPCN] Article 128 : Dans le cas où les deux (2) juridictions se sont\n\ndessaisies, la décision\n\nintervenue la dernière en date est considérée comme non avenue.\nSection 4 : Des exceptions dilatoires","[CPCN] Article 129 : Le juge doit suspendre l’instance lorsque la partie qui le demande jouit, soit\nd’un délai pour faire inventaire et délibérer, soit d’un bénéfice de discussion ou de division,\nsoit de quelque autre délai d’attente en vertu de la loi. Le bénéficiaire d’un délai pour faire\ninventaire et délibérer peut ne proposer ses autres exceptions qu’après l’expiration de ce\ndélai.","[CPCN] Article 130 : Le juge peut accorder un délai au défendeur pour appeler un garant.\n\nL’instance reprend son cours à l’expiration du délai dont dispose le garant pour\ncomparaître, sauf à ce qu’il soit statué séparément sur la demande en garantie si\nl’assignation n’a pas été faite dans le délai ou si le garant n’a pas comparu.\nSection 5 : Des exceptions de nullité\nSous-section 1 : De la nullité des actes pour vice de forme","[CPCN] Article 131 : La nullité des actes de procédure pour vice de forme ne peut être soulevée\nd’office par le juge.\nElle peut être invoquée au fur et à mesure de l’accomplissement des actes. Par\ncontre elle est couverte si celui qui l’invoque a, postérieurement à l’acte critiqué, fait valoir\ndes défenses au fond ou soulevé une fin de non-recevoir.","[CPCN] Article 132 : Tous les moyens de nullité pour vice de forme contre les actes de procédure\ndéjà faits doivent être invoqués simultanément à peine d’irrecevabilité de ceux qui ne l’ont\npas été.","[CPCN] Article 133 : Aucun acte de procédure ne peut être déclaré nul pour vice de forme si la\nnullité n’en est pas expressément prévue par la loi, sauf les cas d’inobservation d’une\nformalité substantielle ou d’ordre public.\nConstituent des formalités substantielles la signature de l’huissier, la désignation du\nrequérant et du destinataire, la date à laquelle l’acte a été signé, les énonciations relatives\nà la personne à laquelle l’acte a été remis ou signifié.","[CPCN] Article 134 : La nullité ne peut être prononcée qu’à charge par celui qui l’invoque de\nprouver le préjudice que lui cause l’irrégularité, même lorsqu’il s’agit d’une formalité\nsubstantielle ou d’ordre public.\nLa nullité est couverte par la régularisation ultérieure de l’acte si aucune forclusion\nn’est intervenue et si la régularisation ne laisse subsister aucun préjudice.\nSous-section 2 : De la nullité pour irrégularité de fond","[CPCN] Article 135 : Constituent des irrégularités de fond affectant la validité de l’acte :\n-\n\nle défaut de capacité du requérant ou du destinataire de l’acte ;\n\n-\n\nla violation des règles fondamentales qui tiennent à l’organisation judiciaire,\nnotamment celle fixant la compétence territoriale des huissiers de justice ;\n\n- le défaut de pouvoir d’une partie ou d’une personne figurant au procès comme\nreprésentant, soit d’une personne morale, soit d’une personne atteinte\nd’incapacité ;\n\n- le défaut de capacité ou de pouvoir d’une personne assurant la représentation\nd’une partie en justice.","[CPCN] Article 136 : Les exceptions de nullité fondées sur l’inobservation des règles de fond\nrelatives aux actes de procédure peuvent être soulevées en tout état de cause, sauf la\npossibilité pour le juge de condamner à des dommages-intérêts ceux qui se sont\nabstenus, dans une intention dilatoire, de les soulever plus tôt.","[CPCN] Article 137 : Les exceptions de nullité fondées sur l’inobservation des règles de fond\nrelatives aux actes de procédure doivent être relevées d’office lorsqu’elles ont un\ncaractère d’ordre public et être accueillies sans que celui qui les invoque ait à justifier d’un\npréjudice et alors même que la nullité ne résulte d’aucune disposition expresse.","[CPCN] Article 138 : Dans les cas où elle est susceptible d’être couverte, la nullité ne sera pas\nprononcée si la cause a disparu au moment où le juge statue.\nCHAPITRE III– DES FINS DE NON-RECEVOIR","[CPCN] Article 139 : Constitue une fin de non-recevoir tout moyen qui tend à faire déclarer\nl’adversaire irrecevable en sa demande sans examen au fond, pour défaut du droit d’agir\ntels le défaut de qualité, le défaut d’intérêt, la prescription, l’expiration d’un délai préfix, la\nchose jugée.","[CPCN] Article 140 : Les fins de non-recevoir peuvent être soulevées en tout état de cause, sauf\nla possibilité pour le juge de condamner à des dommages-intérêts ceux qui se sont\nabstenus, dans une intention dilatoire, de les soulever plus tôt.","[CPCN] Article 141 : Les fins de non-recevoir doivent être accueillies sans que celui qui les\ninvoque ait à justifier d’un préjudice et alors même que l’irrecevabilité ne résulte d’aucune\ndisposition expresse.","[CPCN] Article 142 : Les fins de non-recevoir doivent être relevées d’office lorsqu’elles ont un\ncaractère d’ordre public, notamment lorsqu’elles résultent de l’inobservation des délais\ndans lesquels doivent être exercées les voies de recours ou de l’absence d’ouverture\nd’une voie de recours.\nLe juge peut également relever d’office la fin de non-recevoir tirée du défaut\nd’intérêt.","[CPCN] Article 143 : Dans le cas où la situation donnant lieu à la fin de non-recevoir est\nsusceptible d’être régularisée, l’irrecevabilité sera écartée si sa cause a disparu au\nmoment où le juge statue.\n\nIl en est de même lorsqu’avant toute forclusion, la personne ayant qualité pour agir\ndevient partie à l’instance.\nTITRE VII – DE LA CONCILIATION","[CPCN] Article 144 : Les parties peuvent se concilier, d'elles-mêmes ou à l'initiative du juge, tout\nau long de l'instance.","[CPCN] Article 145 : La conciliation est tentée, sauf disposition particulière, au lieu et au moment\nque le juge estime favorables.","[CPCN] Article 146 : Les parties peuvent toujours demander au juge de constater leur conciliation.","[CPCN] Article 147 : La teneur de l'accord, même partiel, est constatée soit dans un procès-verbal\nsigné par le juge et les parties, soit dans un jugement de donner acte.","[CPCN] Article 148 : Des extraits du procès-verbal constatant la conciliation peuvent être\ndélivrés ; ils valent titre exécutoire.\nTITRE VIII – DE L’ADMINISTRATION JUDICIAIRE DE LA PREUVE\nCHAPITRE PREMIER – DES PIÈCES\n\nSection 1 : De la communication des pièces entre les parties","[CPCN] Article 149 : La partie qui fait état d’une pièce s’oblige à la communiquer à toute autre\npartie à l’instance.\nLa communication des pièces doit être préalable, spontanée et complète. Elle est\nvalablement attestée par la signature du conseil destinataire apposée sur le bordereau\nétabli par le conseil qui procède à la communication.\nEn cause d'appel, une nouvelle communication des pièces déjà versées aux débats\nde première instance n'est pas exigée, sauf en cas de demande de l’une des parties.","[CPCN] Article 150 : Si la communication des pièces n’est pas faite, il peut être demandé sans\nforme au juge d’enjoindre cette communication.\nLe juge impartit un délai, en fixe les modalités, le cas échéant à peine d’astreinte.\nLe juge peut écarter du débat les pièces qui n’ont pas été communiquées en temps\nutile.","[CPCN] Article 151 : La partie qui ne restitue pas les pièces communiquées, peut y être\ncontrainte, éventuellement sous astreinte.\nL’astreinte peut être liquidée par le juge qui l'a prononcée.\n\nSection 2 : De l’obtention des pièces détenues par un tiers","[CPCN] Article 152 : Lorsque dans le cours d’une instance, une partie entend faire état d’un acte\nauquel elle n’a pas été partie, ou d’une pièce détenue par un tiers dont elle ne peut obtenir\nune expédition ou la production, elle peut demander au juge saisi de l’affaire d’ordonner la\ndélivrance de l’expédition ou la production de la pièce.\nLa demande est faite sans forme.","[CPCN] Article 153 : Si le juge estime cette demande fondée, il ordonne la délivrance de l’acte ou\nde la pièce en original, en copie ou extrait selon le cas, dans les conditions et sous les\ngaranties qu’il fixe.\nLa décision est exécutée par provision sur minute s’il y a lieu.\nEn cas de difficulté, ou s'il est invoqué quelque empêchement légitime, le juge qui a\nordonné la délivrance ou la production peut, sur la demande sans forme qui lui en est\nfaite, rétracter ou modifier sa décision. Le tiers peut interjeter appel de la nouvelle décision\ndans les quinze (15) jours de son prononcé.","[CPCN] Article 154 : Si le tiers détenteur de l’acte ou de la pièce est une personne morale ou\nphysique, autre qu’une autorité administrative ou judiciaire ou un officier ministériel, le juge\nne pourra ordonner la production de l’acte ou de la pièce qu’à la condition que ce tiers ait\nété appelé dans la cause par voie d’intervention forcée.\nCHAPITRE II – DES CONTESTATIONS RELATIVES À LA PREUVE LITTÉRALE","[CPCN] Article 155 : La vérification des écritures sous seing privé relève de la compétence du\njuge saisi du principal lorsqu’elle est demandée incidemment. Elle relève de la\ncompétence du tribunal de grande instance lorsqu’elle est demandée à titre principal.","[CPCN] Article 156 : L’inscription de faux contre un acte authentique relève de la compétence du\njuge saisi du principal lorsqu’elle est formée incidemment devant un tribunal de grande\ninstance ou devant une Cour d’Appel. Dans les autres cas, l’inscription de faux relève de\nla compétence du tribunal de grande instance.\nSection 1 : Des contestations relatives aux actes sous seing privé\nSous-section 1 : De la vérification d’écriture demandée à titre incident","[CPCN] Article 157 : Si l’une des parties dénie l’écriture ou la signature qui lui est attribuée, ou\ndéclare ne pas reconnaître celle qui est attribuée à un tiers, le juge vérifie l’écrit contesté à\n\nmoins qu’il ne puisse statuer sans en tenir compte. Lorsque l’écrit contesté n’est relatif\nqu’à certains chefs de la demande, il peut être statué sur les autres.","[CPCN] Article 158 : Il appartient au juge de procéder à la vérification d’écriture au vu des\néléments dont il dispose après avoir, s’il y a lieu, enjoint aux parties de produire tous\ndocuments à lui comparer et fait composer sous sa dictée des échantillons d’écriture.","[CPCN] Article 159 : S’il ne statue pas sur le champ, le juge retient l’écrit à vérifier et les pièces de\ncomparaison ou ordonne leur dépôt au greffe de la juridiction.","[CPCN] Article 160 : Lorsqu’il est utile de comparer l’écrit contesté à des documents détenus par\ndes tiers, le juge peut ordonner même d’office ou à peine d’astreinte, que ces documents\nsoient déposés au greffe de la juridiction en original ou en reproduction. Il prescrit toutes\nles mesures nécessaires, notamment celles qui sont relatives à la conservation, la\nconsultation, la reproduction et la restitution des documents.","[CPCN] Article 161 : En cas de nécessité, le juge ordonne la comparution personnelle des parties,\nle cas échéant en présence d’un consultant, ou toute autre mesure d’instruction. Il peut\nentendre l’auteur de l’écrit contesté.","[CPCN] Article 162 : Peuvent être entendus comme témoins, ceux qui ont vu écrire ou signer\nl’écrit contesté ou dont l’audition paraît utile à la manifestation de la vérité.","[CPCN] Article 163 : Si le juge fait appel à un technicien, celui-ci peut être autorisé à retirer contre\némargement l’écrit contesté et les pièces de comparaison ou à se les faire adresser par le\ngreffe de la juridiction.","[CPCN] Article 164 : Le juge règle les difficultés d’exécution de la vérification d’écriture\nnotamment quant à la détermination des pièces de comparaison.\nSa décision revêt soit la forme d’une simple mention au dossier et au registre\nd’audience, soit en cas de nécessité celle d’une ordonnance ou d’un jugement.","[CPCN] Article 165 : S’il est jugé que la pièce a été écrite ou signée par la personne qui la dénie,\ncelle-ci est condamnée à une amende civile de cinquante mille (50.000) à deux cent\ncinquante mille (250.000) francs CFA, sans préjudice des dommages-intérêts qui peuvent\nêtre réclamés.\nSous-section 2 : De la vérification d’écriture demandée à titre principal","[CPCN] Article 166 : Lorsque la vérification d’écriture est demandée à titre principal, le juge tient\nl’écrit pour reconnu si le défendeur cité à personne ne comparaît pas.\n24","[CPCN] Article 167 : Si le défendeur reconnaît l’écriture, le juge en donne acte au demandeur.\nSi le défendeur dénie ou ne reconnaît pas l’écriture, il est procédé comme il est dit\naux articles 157 à 165 de la présente loi.\nIl en est de même lorsque le défendeur qui n’a pas été cité à personne ne\ncomparaît pas.\nSous-section 3 : Du faux demandé à titre incident","[CPCN] Article 168 : Si un écrit sous seing privé, produit en cours d’instance est argué de faux, il\nest procédé à l’examen de l’écrit litigieux comme il est dit aux articles 158 à 166 du\nprésent Code.\nSous-section 4 : Du faux demandé à titre principal","[CPCN] Article 169 : Si un écrit sous seing privé est argué de faux à titre principal, l’assignation\nindique les moyens de faux et fait sommation au défendeur de déclarer s’il entend ou non\nfaire usage de l’acte prétendu faux ou falsifié.","[CPCN] Article 170 : Si le défendeur déclare ne pas vouloir se servir de l’écrit argué de faux, le\njuge en donne acte au demandeur.\nSi le défendeur ne comparaît pas ou déclare vouloir se servir de l’écrit litigieux, il est\nprocédé comme il est dit aux articles 158 à 166 de ladite loi.\nSection 2 : De l’inscription de faux contre les actes authentiques","[CPCN] Article 171 : L’inscription de faux contre un acte authentique donne lieu à une\ncommunication au ministère public.","[CPCN] Article 172 : Le juge peut ordonner l’audition de celui qui a dressé l’acte litigieux.","[CPCN] Article 173 : Le demandeur en faux qui succombe est condamné à une amende civile de\ncinquante mille (50.000) à deux cent cinquante mille (250.000) francs CFA, sans préjudice\ndes dommages-intérêts qui peuvent être réclamés.\n\nSous-section 1 : De l’inscription de faux à titre incident","[CPCN] Article 174 : Lorsque l’incident est soulevé devant le tribunal de grande instance ou la\nCour d’Appel, l’inscription de faux est formée par acte remis au greffe par la partie ou son\nmandataire muni d’un pouvoir spécial.\n\nL’acte établi en double exemplaire doit, à peine d’irrecevabilité, articuler avec\nprécision les moyens que la partie invoque pour établir le faux.\nL’un des exemplaires est versé au dossier de l’affaire, l’autre, daté et visé par le\ngreffier, est restitué à la partie en vue de la dénonciation au défendeur, qui doit être faite\npar signification dans le mois de l’inscription.","[CPCN] Article 175 : Le juge se prononce sur le faux, à moins qu’il ne puisse statuer sans avoir\négard à la pièce arguée de faux. Si l’acte argué de faux n’est relatif qu’à un chef de la\ndemande, il peut être statué sur les autres.","[CPCN] Article 176 : Il appartient au juge d’admettre ou de rejeter l’acte litigieux au vu des\néléments dont il dispose. S’il y a lieu, il ordonne sur le faux toutes mesures nécessaires et\nil est procédé comme en matière de vérification d’écriture.\nLe juge statue au vu des moyens articulés par les parties ou de ceux qu'il relève\nd'office.","[CPCN] Article 177 : Le jugement qui déclare le faux est mentionné en marge de l’acte reconnu\nfaux et précise si la minute de l’acte authentique sera rétablie dans le dépôt d’où il avait\nété extrait. Il est sursis à l’exécution de ces prescriptions tant que le jugement n’est pas\npassé en force de chose jugée, ou jusqu’à l’acquiescement de la partie condamnée.","[CPCN] Article 178 : En cas de renonciation ou de transaction sur l’inscription de faux, le\nministère public peut requérir toutes les mesures propres à préserver l’exercice de\npoursuites pénales.","[CPCN] Article 179 : Si des poursuites pénales sont engagées contre les auteurs ou les complices\ndu faux, il est sursis au jugement civil jusqu’à ce qu’il ait été statué au pénal, à moins que\nle principal puisse être jugé sans avoir égard à la pièce de faux ou qu’il y ait eu sur le faux,\nrenonciation ou transaction.","[CPCN] Article 180 : Lorsque l’incident est soulevé devant une juridiction autre que le tribunal de\ngrande instance ou la Cour d’Appel, il est sursis à statuer jusqu’à jugement sur le faux, à\nmoins que la pièce litigieuse ne soit écartée du débat ou qu’il puisse être statué au\nprincipal sans y avoir égard.\nIl est procédé à l’inscription de faux comme il est dit aux articles 181 à 183 ci-après.\n\nSous-section 2 : De l’inscription de faux à titre principal","[CPCN] Article 181 : La demande principale en faux est précédée d’une inscription de faux\ncomme il est dit à l’article 172 de la présente loi. La copie de l’acte d’inscription est jointe à\nl’assignation qui contient sommation pour le défendeur de déclarer s’il entend ou non faire\nusage de l’acte prétendu faux ou falsifié. L’assignation doit être délivrée dans le mois de\nl’inscription de faux à peine de caducité de celle-ci.","[CPCN] Article 182 : Si le défendeur déclare ne pas vouloir se servir de la pièce arguée de faux,\nle juge en donne acte au demandeur.","[CPCN] Article 183 : Si le défendeur ne comparaît pas ou déclare vouloir se servir de la pièce\nlitigieuse, il est procédé comme il est dit aux articles 157 à 165 et 175 à 179 du présent\nCode.\nCHAPITRE III – DU SERMENT JUDICIAIRE\n\nSection 1 : Du serment décisoire","[CPCN] Article 184 : En l’absence de titre ou devant l’insuffisance des preuves, une des parties\npeut s’en remettre à la bonne foi de l’autre et lui déférer le serment, qui est appelé\ndécisoire. Le serment est ordonné par un jugement qui énonce les faits sur lesquels il sera\nreçu et indique que le faux serment expose son auteur à des sanctions pénales.","[CPCN] Article 185 : Si la partie à qui le serment est déféré le prête, sa prétention sur ce point est\nréputée prouvée. La partie à qui le serment est déféré, peut le référer à son adversaire sur\nle fait à prouver.\nDans l’un et l’autre cas, si la partie à qui le serment est déféré refuse de le prêter, la\nprétention qu’elle n’a pu soutenir par serment est réputée non prouvée.\nSection 2 : Du serment supplétoire","[CPCN] Article 186 : Le juge peut aussi déférer d’office le serment à l’une des parties pour en\nfaire dépendre sa décision, soit sur l’ensemble du procès, soit sur tel point particulier mais\nseulement lorsqu’aucune preuve suffisante n’a été produite de part et d’autre. Ce serment\nest appelé supplétoire et ne lie pas le juge ; il ne peut pas être référé à l’autre partie.","[CPCN] Article 187 : Le serment est prêté par la partie en personne et à l’audience, dans les\ntermes énoncés par le jugement qui l’a ordonné.\n\n27","[CPCN] Article 188 : Dans le cas d’empêchement légitime et dûment constaté, le serment peut\nêtre prêté devant le juge qui se transporte, assisté du greffier chez la partie à laquelle il a\nété déféré.","[CPCN] Article 189 : Dans tous les cas, le serment est fait en présence de l’autre partie ou celle-ci\ndûment appelée.\nCHAPITRE V – DES MESURES D’INSTRUCTION\n\nSection 1 : Des dispositions communes","[CPCN] Article 190 : Les faits dont dépend la solution du litige peuvent, en tout état de cause, à la\ndemande des parties ou d’office, être objet de toute mesure d’instruction légalement\nadmissible, dès lors que le juge ne dispose pas d’éléments suffisants pour statuer.","[CPCN] Article 191 : Les mesures d’instruction que le juge peut ordonner sur un fait non prouvé\nont pour objet de recueillir les déclarations des parties ou des tiers, de faire par lui-même\nou de faire faire par un tiers toute constatation utile et de prendre l’avis de toute personne\ncompétente à raison de sa technicité.","[CPCN] Article 192 : S’il existe un motif légitime de conserver ou d’établir, avant tout procès, la\npreuve des faits dont pourrait dépendre la solution d’un litige, les mesures d’instruction\nlégalement admissibles peuvent être ordonnées à la demande de tout intéressé sur\nrequête ou en référé.\nSous-section 1 : De la décision ordonnant la mesure d’instruction","[CPCN] Article 193 : Une mesure d’instruction ne peut être ordonnée sur un fait que s’il n’est pas\nsuffisamment démontré par les éléments du dossier.","[CPCN] Article 194 : Le juge doit limiter le choix de la mesure à ce qui est suffisant pour la\nsolution du litige en s’attachant à retenir la mesure la plus simple et la moins onéreuse.","[CPCN] Article 195 : Le juge peut conjuguer plusieurs mesures d’instruction. Il peut à tout\nmoment, accroître ou restreindre l’étendue des mesures prescrites, décider de joindre\ntoute autre mesure nécessaire à celles qui ont été déjà ordonnées.","[CPCN] Article 196 : La décision qui ordonne ou modifie une mesure d’instruction n’est pas\nsusceptible d’opposition ; elle ne peut être frappée d’appel ou de pourvoi en cassation\nindépendamment du jugement sur le fond que dans les cas spécifiés par la loi. Il en est de\nmême de la décision qui refuse d’ordonner ou de modifier une mesure.\n\n28","[CPCN] Article 197 : Lorsqu’elle ne peut être l’objet de recours indépendamment du jugement sur\nle fond, la décision peut revêtir la forme d’une simple mention au dossier et au registre\nd’audience.","[CPCN] Article 198 : La décision qui, en cours d’instance, se borne à ordonner ou à modifier une\nmesure d’instruction n’est pas notifiée. Il en est de même de la décision qui refuse\nd’ordonner ou de modifier la mesure. Le greffier adresse copie de la décision par lettre\nrecommandée ou par tout moyen probant laissant trace écrite aux parties défaillantes ou\nabsentes.","[CPCN] Article 199 : La décision qui ordonne une mesure d’instruction ne dessaisit pas le juge.\nSous-section 2 : De l’exécution de la mesure d’instruction","[CPCN] Article 200 : La mesure d’instruction est exécutée sous le contrôle du juge qui l’a\nordonnée lorsqu’il n’y procède pas par lui-même. Lorsque la mesure est ordonnée par une\njuridiction statuant en formation collégiale, le contrôle est exercé par le président, s’il ne l’a\npas confié à l’un des juges de cette formation.","[CPCN] Article 201 : Le juge peut se déplacer hors de son ressort pour procéder à une mesure\nd’instruction ou pour en contrôler l’exécution.","[CPCN] Article 202 : Lorsque l’éloignement des parties ou des personnes qui doivent apporter\nleur concours à la mesure ou l’éloignement des lieux rend le déplacement trop difficile ou\nonéreux, le juge peut charger une autre juridiction de degré égal ou inférieur de procéder à\ntout ou partie des opérations ordonnées.\nLa décision est transmise avec tous documents utiles par le greffe de la juridiction\ncommettante à la juridiction commise, qui procède, dès réception, aux opérations\nprescrites. Sitôt les opérations accomplies, le greffe de la juridiction qui y a procédé\ntransmet à la juridiction commettante les procès-verbaux accompagnés des pièces et\nobjets y annexés ou déposés.","[CPCN] Article 203 : Lorsque plusieurs mesures d’instruction ont été ordonnées, il est procédé\nsimultanément à leur exécution.","[CPCN] Article 204 : Les parties et les tiers qui doivent apporter leur concours aux mesures\nd’instruction sont convoqués, selon les cas, par le greffier du juge qui y procède ou par le\ntechnicien commis. La convocation est faite par lettre recommandée avec avis de\nréception ou par tout moyen probant laissant trace écrite. Les parties peuvent également\n\nêtre convoquées par remise à leur défenseur d’un simple bulletin. Les défenseurs des\nparties sont avisés par lettre simple s’ils ne l’ont pas été par bulletin.\nLes parties défaillantes sont avisées par lettre simple.","[CPCN] Article 205 : Les parties peuvent se faire assister lors de l’exécution d’une mesure\nd’instruction. Elles peuvent se dispenser de s’y rendre si la mesure n’implique pas leur\naudition personnelle.","[CPCN] Article 206 : Les parties ou leurs représentants qui suivent l’exécution peuvent formuler\ndes observations et présenter toutes demandes relatives à cette exécution.","[CPCN] Article 207 : Les mesures d’instruction exécutées devant la juridiction le sont en audience\npublique, ou en chambre de conseil selon les règles applicables aux débats sur le fond.","[CPCN] Article 208 : Le juge chargé de procéder à une mesure d’instruction ou d’en contrôler\nl’exécution peut ordonner telle autre mesure que rendrait opportune l’exécution de celle\nqui a déjà été prescrite.","[CPCN] Article 209 : Les difficultés auxquelles se heurte l’exécution d’une mesure d’instruction\nsont réglées à la demande des parties, à l’initiative du technicien commis ou d’office, soit\npar le juge qui y procède soit par le juge chargé du contrôle de l’exécution.","[CPCN] Article 210 : Le juge se prononce sur-le-champ si la difficulté survient au cours d’une\nopération à laquelle il procède ou assiste. Dans les autres cas, le juge saisi sans forme,\nfixe la date pour laquelle les parties et, s’il y a lieu, le technicien commis seront convoqués\npar le greffier.","[CPCN] Article 211 : En cas d’intervention d’un tiers à l’instance, le greffier en avise aussitôt le\njuge ou le technicien chargé d’exécuter la mesure d’instruction. L’intervenant est mis en\nmesure de présenter ses observations sur les opérations auxquelles il a déjà été procédé.","[CPCN] Article 212 : Les décisions relatives à l’exécution des mesures d’instruction ne sont pas\nsusceptibles d’opposition ; elles ne peuvent être frappées d’appel ou de pourvoi en\ncassation qu’en même temps que le jugement sur le fond. Elles revêtent la forme, soit\nd’une simple mention au dossier et au registre d’audience, soit en cas de nécessité, d’une\nordonnance ou d’un jugement. Les décisions prises par le juge commis ou par le juge\nchargé du contrôle n’ont pas autorité de la chose jugée au principal.","[CPCN] Article 213 : Dès que la mesure d’instruction est exécutée, l’instance se poursuit à la\ndiligence des parties. Les procès-verbaux, les avis ou les rapports établis à l’occasion ou à\nla suite de l’exécution, sont déposés en original au greffe et adressés ou remis en copie à\n\nchacune des parties par le greffier de la juridiction qui les a établis ou par le technicien qui\nles a rédigés selon les cas. Mention en est faite sur l’original.","[CPCN] Article 214 : La nullité des décisions et des actes d’exécution relatifs aux mesures\nd’instruction est soumise aux dispositions qui régissent la nullité des actes de procédure.\nLa nullité ne frappe que celles des opérations qu’affecte l’irrégularité.","[CPCN] Article 215 : Les opérations peuvent être régularisées ou recommencées même sur-lechamp, si le vice qui les entache peut être écarté.","[CPCN] Article 216 : L’omission ou l’inexactitude d’une mention destinée à établir la régularité\nd’une opération ne peut entraîner la nullité de celle-ci s’il est établi par tout moyen que les\nprescriptions légales ont été, en fait, observées.\nSection 2 : De la comparution personnelle des parties","[CPCN] Article 217 : La comparution personnelle peut être ordonnée en toute matière et a pour\nobjet d’obtenir des parties un exposé personnel et oral de leurs prétentions et\néventuellement la confirmation de leurs points de vue.","[CPCN] Article 218 : La comparution ne peut être ordonnée que par la formation de jugement ou\npar celui des membres de cette formation qui est chargé de la mise en état de l’affaire.","[CPCN] Article 219 : La comparution personnelle des parties a lieu devant le juge qui l’a prescrite.\nToutefois, lorsqu’elle est ordonnée par une formation collégiale, celle-ci peut prescrire que\nla comparution aura lieu devant l’un de ses membres. Lorsqu’elle est ordonnée par le\nmagistrat chargé de la mise en état, celui-ci peut décider que la comparution aura lieu\ndevant la formation de jugement.","[CPCN] Article 220 : Le juge en ordonnant la comparution personnelle, en fixe les lieu, jour et\nheure de la comparution personnelle, à moins qu’il n’y soit procédé sur-le-champ. Elle\npeut toujours avoir lieu en chambre de conseil.","[CPCN] Article 221 : Les parties sont interrogées en présence l’une de l’autre ou séparément ;\nelles peuvent être confrontées. L’absence d’une partie n’empêche pas d’entendre l’autre.\nElles peuvent être interrogées en présence d’un technicien et confrontées avec des\ntémoins.","[CPCN] Article 222 : Les parties répondent en personne aux questions qui leur sont posées sans\npouvoir lire aucun écrit. Leurs défenseurs peuvent les assister.\nLe juge pose, s’il l'estime nécessaire, les questions que les parties lui soumettent\naprès l’interrogatoire.\n\n31","[CPCN] Article 223 : Il est dressé procès-verbal des déclarations des parties, de leur absence ou\nde leur refus de répondre, à moins que l’affaire ne soit immédiatement jugée en dernier\nressort, auquel cas il en est fait mention au plumitif et dans le jugement.","[CPCN] Article 224 : Le procès-verbal est signé par les parties entendues après lecture faite ; s’il\ny a lieu, mention y est portée qu’elles ne veulent ou ne peuvent signer. Le procès-verbal\nest en outre daté et signé par le juge et le greffier.","[CPCN] Article 225 : Si l’une des parties est dans l’impossibilité de se présenter, le juge qui a\nordonné la comparution ou le juge commis pour y procéder, peut se transporter auprès\nd’elle après avoir, le cas échéant, convoqué la partie adverse.","[CPCN] Article 226 : Le\n\njuge\n\npeut\n\nfaire\n\ncomparaître\n\nles\n\nincapables\n\neux-mêmes,\n\nleurs\n\nreprésentants légaux ou ceux qui les assistent, ainsi que les personnes morales y compris\nles collectivités publiques et les établissements publics en la personne de leur\nreprésentant légal.","[CPCN] Article 227 : Le juge peut tirer toute conséquence de droit des déclarations des parties,\nde l’absence ou du refus de répondre de l’une d’elles et en faire état comme équivalent à\nun commencement ou un complément de preuve.\nSection 3 : Des vérifications personnelles du juge et du transport sur les lieux","[CPCN] Article 228 : Le juge peut, afin de les vérifier lui-même, prendre en toute matière une\nconnaissance personnelle des faits litigieux, les parties présentes ou appelées. Il procède\naux constatations, aux évaluations, aux appréciations ou aux reconstitutions qu’il estime\nnécessaires en se transportant, si besoin est, sur les lieux.","[CPCN] Article 229 : S’il n’y procède pas immédiatement, le juge fixe les lieu, jour et heure de la\nvérification.","[CPCN] Article 230 : Le juge peut, au cours des opérations de vérifications, se faire assister d’un\ntechnicien, entendre les parties elles-mêmes et toute personne dont l’audition paraît utile à\nla manifestation de la vérité.","[CPCN] Article 231 : Il est dressé procès-verbal des constatations, des reconstitutions, des\névaluations ou des déclarations, à moins que l’affaire ne soit jugée en dernier ressort,\nauquel cas il en est fait mention dans le jugement.\nSection 4 : Des déclarations des tiers : Des attestations et de l’enquête","[CPCN] Article 232 : Lorsque la preuve testimoniale est admissible, le juge peut recevoir des tiers\nles déclarations de nature à l’éclairer sur les faits litigieux dont ils ont personnellement\n\nconnaissance. Ces déclarations sont faites par attestations ou recueillies par voie\nd’enquête selon qu’elles sont écrites ou orales.\nSous-section 1 : Des attestations","[CPCN] Article 233 : Les attestations sont produites par les parties ou à la demande du juge. Elles\ndoivent être établies par des personnes qui remplissent les conditions requises pour être\nentendues comme témoins.","[CPCN] Article 234 : L’attestation contient la relation des faits auxquels son auteur a assisté ou\nqu’il a personnellement constatés. Elle mentionne les nom, prénoms, date et lieu de\nnaissance, domicile et profession de son auteur, ainsi que, s’il y a lieu, son lien de parenté\nou d’alliance avec les parties, de subordination à leur égard, de collaboration ou de\ncommunauté d’intérêts avec elles.\nElle indique en outre qu’elle est établie en vue de sa production en justice et que\nson auteur a connaissance qu’une fausse attestation de sa part l’expose à des sanctions\npénales.","[CPCN] Article 235 : L’attestation est écrite, datée et signée de la main de son auteur. Celui-ci doit\nlui annexer, en original ou en photocopie, tout document officiel justifiant de son identité et\ncomportant sa signature.","[CPCN] Article 236 : Le juge peut toujours procéder par voie d’enquête à l’audition de l’auteur\nd’une attestation.","[CPCN] Article 237 : Le juge peut à l’audience, en son cabinet ainsi qu’en tout lieu, à l’occasion\nd’une mesure d’instruction, entendre sur le champ les personnes dont l’audition lui paraît\nutile à la manifestation de la vérité.\nSous-section 2 : De l’enquête","[CPCN] Article 238 : L’enquête porte sur les faits de nature à être prouvés par témoins et dont la\nvérification paraît utile à la manifestation de la vérité. Elle peut être ordonnée par le juge\nau cours de la mise en état jusqu’à la clôture des débats ou par le tribunal, d’office ou à la\ndemande des parties.","[CPCN] Article 239 : Lorsque l’enquête est ordonnée, la preuve contraire peut être rapportée par\ntémoins sans nouvelle décision.\n\nParagraphe 1 : De la décision ordonnant l’enquête","[CPCN] Article 240 : L’enquête est prescrite par ordonnance ou jugement suivant qu’elle est\nordonnée par le juge chargé de la mise en état de la procédure ou par la juridiction de\njugement. Ces décisions sont exécutoires avant enregistrement.","[CPCN] Article 241 : La partie qui demande une enquête doit préciser soit verbalement, soit par\nsimple acte de conclusion :\n1.\n\nles faits dont elle entend rapporter la preuve ;\n\n2.\n\nles nom, prénoms et adresse des personnes dont elle sollicite l’audition.\n\nLa même charge incombe à l’adversaire qui se propose de rapporter la preuve\ncontraire.","[CPCN] Article 242 : La décision qui ordonne l’enquête énonce :\n1.\n\nles faits pertinents à prouver ;\n\n2.\n\nles nom, prénoms et domicile des personnes à entendre ;\n\n3.\n\nles date, heure et lieu où les témoignages sont reçus ou le délai dans lequel il\nsera procédé à l’enquête ;\n\n4.\n\nla juridiction ou le juge commis qui doit procéder à l’enquête.","[CPCN] Article 243 : Si l’enquête est ordonnée d’office sans que les noms des témoins à faire\nentendre ne puissent être indiqués, ou si les parties sont dans l’impossibilité d’indiquer\nd’emblée les noms des personnes à entendre, le juge peut autoriser les parties à faire\nconnaître au greffe de la juridiction dans le délai qu’il fixe, les noms, prénoms et domiciles\ndes personnes dont elles sollicitent l’audition. La partie qui n’a pas respecté le délai imparti\nne peut faire entendre ces personnes, si ce n’est sur autorisation du juge.","[CPCN] Article 244 : En cas de commission d’une autre juridiction, ou si le juge commis\nn’appartient pas à la juridiction de jugement, la décision qui ordonne l’enquête peut se\nborner à indiquer le délai dans lequel il devra y être procédé. Le juge commis fixe les jour,\nheure et lieu de l’enquête ; il peut proroger le délai à condition d’en informer le juge ayant\nprescrit l’enquête.\nParagraphe 2 : De la convocation des parties et des témoins.","[CPCN] Article 245 : Le greffier de la juridiction invite par lettre recommandée ou par tout moyen\nprobant laissant trace écrite, les parties ou leurs conseils à se présenter aux jour, heure et\nlieu fixés avec les témoins dont elles ont sollicité l’audition quinze (15) jours au moins\navant la date de l’enquête.\n34","[CPCN] Article 246 : Les convocations adressées aux témoins par lettre\n\nrecommandée\n\nmentionnent les nom et prénoms des parties ou par tout moyen probant laissant trace\nécrite et reproduisent les dispositions de l’article 251 ci-dessous.\nParagraphe 3 : Des témoins.","[CPCN] Article 247 : Toute personne peut être entendue comme témoin à l’exception de celles qui\nsont frappées d’une incapacité de témoigner en justice. Les personnes qui ne peuvent\ntémoigner peuvent cependant être entendues dans les mêmes conditions, mais sans\nprestation de serment. Toutefois les descendants ne peuvent jamais être entendus sur les\ngriefs invoqués par les époux à l’appui d’une demande en divorce ou en séparation de\ncorps.","[CPCN] Article 248 : Ne peuvent être entendus comme témoins :\n1.\n\nles parents ou alliés en ligne directe de l’une ou l’autre des parties jusqu’au\ndegré d’oncle ou de neveu inclus ;\n\n2.\n\nles domestiques ou les personnes au service des parties ;\n\n3.\n\nles personnes incapables de témoigner en justice.\n\nLes témoignages recueillis en violation des dispositions ci-dessus sont écartés des\ndébats.","[CPCN] Article 249 : Est tenu de témoigner quiconque en est légalement requis. Peuvent être\ndispensées de déposer les personnes qui justifient d’un motif légitime.","[CPCN] Article 250 : Les témoins défaillants peuvent être cités à leurs frais si leur audition est\njugée nécessaire.\nLes témoins et ceux qui, sans motif légitime, refusent de déposer ou de prêter\nserment peuvent être condamnés à une amende civile de cinq mille (5.000) à cinquante\nmille (50.000) francs CFA. Le témoin qui justifie n’avoir pu se présenter au jour fixé pourra\nêtre déchargé de l’amende et des frais de citation.\nParagraphe 4 : De l’audition des témoins.","[CPCN] Article 251 : Il est procédé à l’enquête soit à la barre du tribunal, soit dans le cabinet du\njuge, soit en tout autre lieu. Le juge entend les témoins en leur déposition séparément et\ndans l’ordre qu’il détermine. Les témoins sont entendus en présence des parties ou cellesci appelées.\n\n35","[CPCN] Article 252 : Les témoins déclarent leurs nom, prénoms, date et lieu de naissance,\ndomicile et profession, leur lien de parenté ou d’alliance avec les parties, de subordination\nà leur égard, de collaboration ou de communauté d’intérêts avec elles.","[CPCN] Article 253 : Les témoins prêtent serment de dire la vérité. Le juge leur rappelle qu’ils\nencourent des peines d’amende et d’emprisonnement en cas de faux témoignage. Les\npersonnes entendues en prestation de serment sont informées de leur obligation de dire la\nvérité.","[CPCN] Article 254 : Les témoins ne peuvent lire aucun écrit, mais ont la faculté jusqu’à la fin de\nl’enquête d’apporter à leurs dépositions tous changements et additions.","[CPCN] Article 255 : Le juge peut entendre ou interroger les témoins sur tous les faits dont la\npreuve est admise par la loi alors même que ces faits ne sont\n\npas indiqués dans la\n\ndécision prescrivant l’enquête.","[CPCN] Article 256 : Les parties ne doivent ni interrompre, ni interpeller, ni chercher à influencer les\ntémoins qui déposent, ni s’adresser directement à eux, à peine d’exclusion. Le juge pose,\ns’il l'estime nécessaire, les questions que les parties lui soumettent après l’audition du\ntémoin.","[CPCN] Article 257 : Le juge peut entendre à nouveau les témoins, les confronter entre eux ou\navec les parties ; le cas échéant il procède à l’audition en présence d’un technicien.","[CPCN] Article 258 : Les témoins après leur audition, restent à la disposition du juge jusqu’à la\nclôture de l’enquête à moins qu’il ne leur ait été permis ou enjoint de se retirer.","[CPCN] Article 259 : Si un témoin justifie qu’il est dans l’impossibilité de se déplacer au jour\nindiqué, le juge peut lui accorder un délai ou se transporter pour recevoir sa déposition.","[CPCN] Article 260 : Le juge qui procède à l’enquête peut d’office ou à la demande des parties\nconvoquer ou entendre toute personne dont l’audition lui paraît utile à la manifestation de la\nvérité.","[CPCN] Article 261 : Si avant la clôture de l’enquête, l’une ou l’autre des parties demande une\nprorogation de l’enquête ou l’audition de nouveaux témoins, le tribunal ou le juge décide\nsans recours s’il y a lieu ou non de faire droit à cette requête. Si l’audition est autorisée, la\ndate et l’heure en seront fixées par décision qui revêt la forme d’une simple mention au\nprocès-verbal ou au registre d’audience.","[CPCN] Article 262 : Les dépositions sont consignées dans un procès-verbal. Toutefois, si elles\nsont recueillies au cours des débats, il est seulement fait mention au plumitif de l’audience\n\nou dans le jugement du nom des témoins entendus et du résultat de leur déposition,\nlorsque l’affaire doit être immédiatement jugée en dernier ressort.","[CPCN] Article 263 : Le procès-verbal doit faire mention de la présence des parties, des nom,\nprénoms, date et lieu de naissance des personnes entendues, ainsi que, s’il y a lieu, du\nserment par elles prêté et de leurs déclarations relatives à leur lien de parenté ou d’alliance\navec les parties, de subordination à leur égard, de collaboration ou de communauté\nd’intérêts avec elles.\nChaque personne entendue signe sa déposition après lecture faite ; s’il y a lieu,\nmention est portée au procès-verbal qu’elle ne veut ou ne peut signer.\nLe juge peut consigner dans le procès-verbal des constatations relatives au\ncomportement du témoin lors de son audition. Les observations des parties sont\nconsignées dans le procès-verbal ou lui sont annexées lorsqu’elles sont écrites.\nLes documents versés à l’enquête sont également annexés. Le procès-verbal est\ndaté et signé par le juge et le greffier.","[CPCN] Article 264 : Le juge autorise le témoin, sur sa demande, à percevoir les indemnités\nauxquelles il peut prétendre.\nSection 5 : Des mesures d’instruction exécutées par un technicien\nSous-section 1 : Des dispositions communes","[CPCN] Article 265 : Le juge peut commettre toute personne de son choix pour l’éclairer par des\nconstatations, par une consultation ou une expertise sur une question de fait qui requiert\nl’avis d’un technicien.","[CPCN] Article 266 : Le technicien, commis par le juge en raison de sa qualification doit remplir\npersonnellement la mission qui lui a été confiée.","[CPCN] Article 267 : Les techniciens peuvent être récusés pour les mêmes causes que les juges.\nLa partie qui récuse le technicien doit le faire devant le juge chargé du contrôle avant le\ndébut des opérations ou dès la révélation de la cause de la récusation. Le technicien qui\ns’estime récusable doit immédiatement le déclarer au juge qui l’a commis ou au juge chargé\ndu contrôle.","[CPCN] Article 268 : Si la récusation est admise, si le technicien refuse la mission ou s’il existe un\nempêchement légitime, il est pourvu au remplacement du technicien par le juge qui l’a\ncommis ou par le juge qui est chargé du contrôle. Le juge peut également, à la demande\n\ndes parties ou d’office, remplacer le technicien qui manquerait à ses devoirs après avoir\nprovoqué ses explications.","[CPCN] Article 269 : Le juge qui a commis le technicien ou le juge chargé du contrôle peut\naccroître ou restreindre la mission confiée au technicien.","[CPCN] Article 270 : Le technicien commis doit accomplir sa mission avec conscience, objectivité\net impartialité dans les délais qui lui ont été impartis. Il doit donner son avis sur les points\npour l’examen desquels il a été commis et ne doit jamais porter d’appréciation d’ordre\njuridique. Si les parties se concilient devant lui, il constate leur accord.","[CPCN] Article 271 : Le juge du contrôle peut assister aux opérations. Il peut provoquer les\nexplications du technicien et lui impartir des délais.","[CPCN] Article 272 : Le technicien peut demander communication de tous documents aux parties\nou aux tiers, sauf au juge à l’ordonner en cas de difficulté.","[CPCN] Article 273 : Le technicien peut recueillir des informations écrites ou orales de toutes\npersonnes, à condition de préciser leurs nom, prénoms, domicile et profession, ainsi que s’il\ny a lieu, leur lien de parenté ou d’alliance avec les parties, de subordination à leur égard,\nde collaboration ou de communauté d’intérêts avec elles.\nSi le technicien ou les parties demandent que ces personnes soient entendues par\nle juge, celui-ci procède à leur audition, s’il l’estime utile.","[CPCN] Article 274 : Le technicien doit faire connaître dans son avis toutes les informations qui\napportent un éclaircissement sur les questions à examiner. Il ne peut faire état que des\ninformations légitimement recueillies.","[CPCN] Article 275 : L’avis du technicien dont la divulgation porterait atteinte à l’intimité de la vie\nprivée ou à tout autre intérêt légitime ne peut être utilisé en dehors de l’instance si ce n’est\navec le consentement de la partie intéressée ou sur autorisation du juge.","[CPCN] Article 276 : Le juge peut toujours inviter le technicien à compléter, à préciser ou à\nexpliquer, soit par écrit, soit à l’audience, ses constatations ou ses conclusions. Le\ntechnicien peut à tout moment demander au juge de l’entendre.","[CPCN] Article 277 : Le juge n’est pas lié par les constatations ou les conclusions du technicien.","[CPCN] Article 278 : Il est interdit au technicien de recevoir directement ou indirectement d’une\npartie, sous quelque forme que ce soit, une rémunération même à titre de remboursement\nde débours, si ce n’est sur décision du juge.\n\nSous-section 2 : Des constatations et de la consultation","[CPCN] Article 279 : Lorsqu’une question purement technique ne requiert pas d’investigations\ncomplexes, le juge peut charger la personne qu’il commet de procéder à des constatations\nou de lui fournir une simple consultation.\nCes mesures peuvent être prescrites à tout moment y compris en conciliation ou au\ncours du délibéré. Dans ce dernier cas les parties en sont avisées.","[CPCN] Article 280 : Les constatations sont consignées par écrit, à moins que le juge n’en décide\nla présentation orale.","[CPCN] Article 281 : Le juge qui prescrit des constatations ou une consultation fixe soit la date de\nl’audience à laquelle elles seront présentées oralement, soit le délai dans lequel elles sont\ndéposées. Il désigne la ou les parties qui sont tenues de verser par provision au constatant\nou au consultant une avance sur sa rémunération dont il fixe le montant.","[CPCN] Article 282 : Le constatant ou le consultant est avisé de sa mission par le greffier de la\njuridiction, qui le convoque s’il y a lieu. Le constat ou la consultation est déposé au greffe de\nla juridiction.","[CPCN] Article 283 : Lorsque les constatations ou la consultation sont présentées oralement, il est\ndressé procès-verbal à moins que l’affaire ne soit immédiatement jugée en dernier ressort,\nauquel cas il en est fait mention dans le jugement.","[CPCN] Article 284 : Lorsque les constatations ou la consultation ont été prescrites au cours du\ndélibéré, le juge, à la suite de l’exécution de la mesure, ordonne la réouverture des débats.","[CPCN] Article 285 : Le juge taxe les frais et les vacations du constatant ou du consultant à qui il\npeut délivrer un titre exécutoire.\nSous-section 3 : De l’expertise","[CPCN] Article 286 : Lorsqu’il y a lieu de procéder à des constatations, des recherches, ou des\nestimations qui requièrent la compétence d’un technicien, le juge, soit d’office, soit à la\ndemande des parties, ordonne une expertise.\nParagraphe 1 : De la décision ordonnant l’expertise","[CPCN] Article 287 : Il n’est désigné qu’un seul expert, à moins que le juge n’estime nécessaire\nd’en nommer plusieurs en raison de la nature et des difficultés de la matière.","[CPCN] Article 288 : La décision qui commet un ou plusieurs experts doit nécessairement :\n\n- exposer les circonstances qui rendent nécessaire l’expertise et, s’il y a lieu, la\nnomination de plusieurs experts ;\n- énoncer les chefs de la mission de l’expert ;\n- impartir un délai dans lequel l’expert devra donner son avis.","[CPCN] Article 289 : Dès le prononcé de la décision nommant l’expert, le greffier de la juridiction\nlui en notifie copie par simple lettre. L’expert fait connaître sans délai au juge son\nacceptation mais ne commence ses opérations qu’à l’initiative de l’une ou l’autre des\nparties.","[CPCN] Article 290 : Le juge qui ordonne, ou le juge qui est chargé du contrôle, peut fixer à la\ndemande de l’expert le montant d’une provision à valoir sur sa rémunération et désigner la\npartie qui doit consigner la provision au greffe de la juridiction dans un délai déterminé.","[CPCN] Article 291 : Le greffier de la juridiction informe l’expert de la consignation. A défaut de\nconsignation dans le délai imparti, le juge invite les parties à fournir leurs explications et\ns’il y a lieu, il ordonne la poursuite de l’instance, sauf à ce qu’il soit tiré toute conséquence\nde l’abstention ou du refus de consigner.\nParagraphe 2 : Des opérations d’expertise","[CPCN] Article 292 : Dès son acceptation, l’expert doit, contre émargement ou récépissé, retirer\nou se faire adresser par le greffier de la juridiction les dossiers ou documents des parties\nconservés au greffe.\nLes parties doivent remettre sans délai à l’expert tous les documents que celui-ci\nestime nécessaires à l’accomplissement de sa mission.\nEn cas de carence des parties, l’expert en informe le juge qui peut ordonner la\nproduction des documents, s’il y a lieu sous astreinte, ou bien, le cas échéant, l’autoriser à\npasser outre ou à déposer son rapport en l’état.","[CPCN] Article 293 : L’expert doit prendre en considération les observations et réclamations des\nparties et lorsqu’elles sont écrites les joindre à son avis si les parties le demandent. Il doit\nfaire mention dans son avis de la suite qu’il leur a donnée.","[CPCN] Article 294 : L’expert ne peut recueillir l’avis d’un autre expert que dans une spécialité\ndistincte de la sienne. Cet avis est joint selon le cas au rapport ou au procès-verbal\nd’audience.","[CPCN] Article 295 : L’expert doit informer le juge de l’avancement de ses opérations ; s’il se\nheurte à des difficultés qui font obstacle à l’accomplissement de sa mission ou si une\n\nextension de celle-ci s’avère nécessaire, il en fait rapport au juge. Celui-ci peut, en se\nprononçant, proroger le délai dans lequel l’expert doit donner son avis.","[CPCN] Article 296 : Si les parties viennent à se concilier, l’expert constate que sa mission est\ndevenue sans objet et en fait rapport au juge ; les parties peuvent demander au juge de\ndonner force exécutoire à l’acte exprimant leur accord.\nParagraphe 3 : De l’avis de l’expert","[CPCN] Article 297 : Si l’avis n’exige pas de développements écrits, le juge peut autoriser l’expert\nà l’exposer oralement à l’audience ; il est dressé procès-verbal à moins que l’affaire ne soit\nimmédiatement jugée en dernier ressort auquel cas il en est fait mention dans le jugement.\nDans les autres cas, l’expert doit déposer rapport au greffe de la juridiction.","[CPCN] Article 298 : Il n’est rédigé qu’un seul rapport, même s’il y a plusieurs experts. En cas de\ndivergence, chacun indique son opinion.","[CPCN] Article 299 : Si le juge ne trouve pas dans le rapport d’éclaircissements suffisants, il peut\nentendre l’expert, les parties présentes ou appelées.","[CPCN] Article 300 : Sur justifications de l’accomplissement de sa mission et après avoir entendu\nles parties en leurs observations, le juge taxe les frais et vacations de l’expert et l’autorise\nà se faire remettre s’il y a lieu jusqu’à due concurrence les sommes consignées au greffe.\nIl ordonne la restitution à la partie des sommes consignées en excédent ou le versement\nde sommes complémentaires à l’expert, auquel il peut délivrer un titre exécutoire.\nCHAPITRE V – DES COMMISSIONS ROGATOIRES\n\nSection 1 : Des commissions rogatoires internes","[CPCN] Article 301 : Lorsque l’éloignement des parties ou des personnes qui doivent apporter leur\nconcours à la justice, ou l’éloignement des lieux rend le déplacement trop difficile ou trop\nonéreux, le juge peut à la demande des parties ou d’office, commettre la juridiction de\ndegré égal ou inférieur qui lui paraît la mieux placée sur le territoire national, afin de\nprocéder à tous les actes judiciaires qu’il estime nécessaires.","[CPCN] Article 302 : La décision est transmise avec tous les documents utiles par le greffe de la\njuridiction commettante à la juridiction commise. Dès réception il est procédé aux\nopérations prescrites à l’initiative de la juridiction commise ou du juge que le président de\ncette juridiction désigne à cet effet.\nLes parties ou les personnes qui doivent apporter leurs concours sont directement\nconvoquées ou avisées par la juridiction commise.\n\nSitôt les opérations accomplies, le greffe de la juridiction commise transmet à la\njuridiction commettante les procès-verbaux accompagnés des pièces et objets annexés ou\ndéposés.\nSection 2 : Des commissions rogatoires internationales","[CPCN] Article 303 : Le juge peut, à la demande des parties ou d’office, faire procéder dans un\nEtat étranger aux mesures d’instruction ainsi qu’à d’autres actes judiciaires qu’il estime\nnécessaires, en donnant commission rogatoire, soit à toute autorité judiciaire compétente\nde cet Etat, soit aux autorités diplomatiques ou consulaires nigériennes. Le greffe de la\njuridiction commettante adresse au ministère public une expédition de la décision donnant\ncommission rogatoire accompagnée, s’il y a lieu, d’une traduction établie à la diligence des\nparties.\nLe ministère public fait aussitôt parvenir la commission rogatoire au Ministère de la\nJustice aux fins de transmission, à moins qu’en vertu d’un traité la transmission puisse\nêtre faite directement à l’autorité étrangère.\nTITRE IX – DES INCIDENTS D’INSTANCE\nCHAPITRE PREMIER – DES JONCTIONS ET DES DISJONCTIONS D’INSTANCE","[CPCN] Article 304 : Le juge peut à la demande des parties ou d’office ordonner la jonction de\nplusieurs instances pendantes devant lui, s’il existe entre les litiges un lien tel qu’il soit de\nl’intérêt d’une bonne administration de la justice de les faire instruire et juger ensemble. Il\npeut également ordonner la disjonction d’une instance en plusieurs.","[CPCN] Article 305 : Les décisions de jonction ou de disjonction d’instance sont des mesures\nd’administration judiciaire et sont dispensées d’enregistrement.\nCHAPITRE II – DE L’INTERRUPTION DE L’INSTANCE","[CPCN] Article 306 : L’instance est interrompue de plein droit par :\n-\n\nla majorité d’une partie ;\n\n-\n\nl’effet du jugement qui prononce une procédure collective d’apurement du\npassif, dans les causes où il emporte dessaisissement ou assistance du\ndébiteur.","[CPCN] Article 307 : L’instance est interrompue à compter de la notification qui en est faite par :\n-\n\nle décès d’une partie dans le cas où l’action est transmissible ;\n\n-\n\nla cessation de fonction du représentant légal d’un incapable ;\n\n-\n\nla perte ou le recouvrement par une partie de la capacité d’ester en justice.","[CPCN] Article 308 : En aucun cas l’instance n’est interrompue, si l’événement survient ou est\nnotifié après l’ouverture des débats.","[CPCN] Article 309 : Les actes accomplis et les jugements même passés en force de chose\njugée, obtenus après l’interruption de l’instance, sont réputés non avenus à moins qu’ils ne\nsoient expressément ou tacitement confirmés par la partie au profit de laquelle\nl’interruption est prévue.","[CPCN] Article 310 : L’instance peut être volontairement reprise dans les formes prévues pour la\nprésentation des moyens de défense. A défaut de reprise volontaire, elle peut l’être par\nvoie d’assignation.","[CPCN] Article 311 : L’instance reprend son cours en l’état où elle se trouvait au moment où elle a\nété interrompue. Si la partie assignée en reprise d’instance ne comparait pas, il est\nprocédé comme il est dit aux articles 374 et suivants du présent Code.","[CPCN] Article 312 : L’interruption d’instance ne dessaisit pas le juge. Celui-ci peut inviter les\nparties à lui faire part de leurs initiatives en vue de reprendre l’instance et radier l’affaire à\ndéfaut de diligence dans le délai par lui imparti.\nIl peut demander au ministère public de recueillir les renseignements nécessaires à\nla reprise d’instance.\nCHAPITRE III – DE LA SUSPENSION DE L’INSTANCE","[CPCN] Article 313 : L’instance est suspendue par la décision qui sursoit à statuer, radie l’affaire\nou ordonne son retrait du rôle, sauf disposition légale contraire.\nSection 1 : Du sursis à statuer","[CPCN] Article 314 : La décision de sursis suspend le cours de l’instance pour le temps ou jusqu’à\nla survenance de l’événement qu’elle détermine.","[CPCN] Article 315 : Le sursis à statuer ne dessaisit pas le juge. À l’expiration du sursis l’instance\nest poursuivie à l’initiative des parties. En cas de fait nouveau, le juge peut révoquer le\nsursis ou en abréger le délai à la requête d’une partie.\nLa décision de sursis peut être frappée d’appel.\nSection 2 : De la radiation","[CPCN] Article 316 : La radiation, mesure d’administration judiciaire, sanctionne dans les\nconditions de la loi, le défaut de diligence des parties. Elle emporte retrait de l’affaire du\n\nrang des affaires en cours. Elle peut être prononcée d’office par le juge ou à la demande\nmême verbale des parties.\nLa décision de radiation n’est pas susceptible de recours.","[CPCN] Article 317 : La radiation ne fait pas obstacle à la poursuite de l’instance après\nrétablissement de l’affaire au rôle s’il n’y a pas par ailleurs péremption.\nL’affaire n’est rétablie que sur justification de l’accomplissement des diligences dont\nle défaut a entraîné la radiation ou si le juge estime que le refus de diligence constitue une\nmanœuvre dilatoire.\nCHAPITRE IV – DE L’EXTINCTION DE L’INSTANCE","[CPCN] Article 318 : En dehors des cas où cet effet résulte du jugement, l’instance s’éteint\naccessoirement à l’action par l’effet de la transaction, de l’acquiescement, du désistement\nd’action ou, dans les actions non transmissibles, par le décès d’une partie.\nL’extinction de l’action est constatée par une décision de dessaisissement.\nIl appartient au juge de donner force exécutoire à l'acte constatant l'accord des\nparties, que celui-ci intervienne devant lui ou ait été conclu hors sa présence.","[CPCN] Article 319 : L’instance s’éteint à titre principal par l’effet de la péremption, du désistement\nd’instance ou de la caducité de l’assignation.\nLa constatation de l’extinction de l’instance ne fait pas obstacle à l’introduction\nd’une nouvelle instance, si l’action n’est pas éteinte par ailleurs.\nSection I – De l’acquiescement","[CPCN] Article 320 : L’acquiescement à la demande emporte reconnaissance du bien-fondé des\nprétentions de l’adversaire et renonciation à l’action. Il n’est admis que pour les droits dont\nla partie a la libre disposition.","[CPCN] Article 321 : L’acquiescement peut être exprès ou implicite. L’exécution sans réserve d’un\njugement non exécutoire vaut acquiescement, hors les cas où celui-ci n’est pas permis.","[CPCN] Article 322 : L’acquiescement au jugement emporte soumission aux chefs de celui-ci et\nrenonciation aux voies de recours sauf si, postérieurement, une autre partie interjette\nrégulièrement appel. Il est toujours admis sauf disposition contraire.\n\nSection 2 : Du désistement d’action","[CPCN] Article 323 : Le désistement d’action par lequel une partie renonce à sa prétention met fin\nà toute contestation présente ou future sur le droit litigieux. Le juge constate le\ndésistement d’action.\nSection 3 : Du désistement d’instance","[CPCN] Article 324 : Le demandeur peut en toute matière se désister de sa demande en vue de\nmettre fin à l’instance. Le désistement d’instance n’emporte pas renonciation à l’action,\nmais seulement extinction de l’instance.","[CPCN] Article 325 : Le désistement n’est parfait que par l’acceptation du défendeur. Toutefois,\ncette acceptation n’est pas nécessaire si le défendeur n’a présenté aucune défense au\nfond ou fin de non-recevoir au moment où le demandeur se désiste.","[CPCN] Article 326 : Le désistement d’instance est exprès ou implicite ; il en est de même de\nl’acceptation.\nLe juge déclare le désistement parfait, si la non acceptation du défendeur ne se\nfonde sur aucun motif légitime.","[CPCN] Article 327 : Le désistement d’instance emporte, sauf convention contraire, soumission de\npayer les frais de l’instance éteinte.","[CPCN] Article 328 : Le désistement de l’appel ou de l’opposition est admis en toute matière sauf\ndispositions contraires. Il emporte acquiescement au jugement. Les articles 326 et 327 cidessus sont applicables au désistement de l’appel ou de l’opposition.\nSection 4 : De la caducité de l’assignation","[CPCN] Article 329 : L’assignation est caduque dans les cas et conditions déterminés par la loi.\nLa décision qui constate la caducité de l’assignation peut être rapportée, en cas d’erreur,\npar le juge qui l’a rendue.\nSection 5 : De la péremption d’instance","[CPCN] Article 330 : L’instance est périmée lorsqu’aucune des parties n’accomplit de diligences\npendant six (6) mois.\nToutefois, en cas d’inertie des parties pendant plus de trois (3) mois, le dossier est\nrenvoyé au rôle général.\n\n45","[CPCN] Article 331 : La péremption peut être demandée par l’une quelconque des parties. Elle\npeut être opposée par voie d’exception à la partie qui accomplit un acte après l’expiration\ndu délai de péremption.","[CPCN] Article 332 : La péremption doit, à peine d’irrecevabilité, être demandée ou opposée\navant tout autre moyen ; elle est de droit. Elle ne peut être relevée d’office par le juge.","[CPCN] Article 333 : La péremption n’éteint pas l’action ; elle emporte seulement extinction de\nl’instance, sans qu’on puisse jamais opposer aucun des actes de la procédure périmée ou\ns’en prévaloir.","[CPCN] Article 334 : Le délai de péremption court contre toutes personnes physiques ou morales,\nmême incapables sauf leur recours contre les administrateurs et les tuteurs.\nL’interruption ou la suspension de l’instance emporte celle du délai de péremption.","[CPCN] Article 335 : La péremption en cause d’appel ou d’opposition confère au jugement la force\nde la chose jugée, même s’il n’a pas été notifié.","[CPCN] Article 336 :Les frais de l’instance périmée sont supportés par celui qui a introduit cette\ninstance.\nTITRE X– DU JUGEMENT\nCHAPITRE PREMIER – DE LA JURIDICTION DE JUGEMENT","[CPCN] Article 337 : La juridiction de jugement est composée conformément aux règles relatives\nà l’organisation judiciaire à peine de nullité absolue de la décision rendue.\nLes contestations relatives à la composition de la juridiction de jugement doivent\nêtre présentées à peine d’irrecevabilité dès l’ouverture des débats ou dès la révélation de\nl’irrégularité, si celle-ci survient postérieurement, faute de quoi aucune nullité ne pourra\nultérieurement être prononcée de ce chef, même d’office.\nSection 1 : De l’abstention, de la récusation, du renvoi et de la prise à partie\nSous-section 1 : De l’abstention du juge","[CPCN] Article 338 : Le juge qui suppose en sa personne une cause de récusation ou estime en\nconscience devoir s’abstenir se fait remplacer par un autre juge que désigne le Président\nde la juridiction à laquelle il appartient.\nLorsque l’abstention de plusieurs juges empêche la juridiction de se constituer, il est\nprocédé comme en matière de renvoi pour cause de suspicion légitime.\n\nSous-section 2 : De la récusation","[CPCN] Article 339 : La récusation est la faculté accordée aux parties de demander qu’un juge,\ndont elles mettent en cause l’impartialité, ne connaisse pas du procès qui lui est\nrégulièrement déféré.","[CPCN] Article 340 : La récusation d’un juge peut être demandée :\n1°) si lui-même ou son conjoint ou l’un de ses proches a un intérêt personnel à la\ncontestation ;\n2°) si lui-même ou son conjoint ou l’un de ses proches est créancier, débiteur,\nhéritier présomptif ou donataire de l’une des parties ;\n3°) si lui-même ou son conjoint est parent ou allié de l’une des parties ou de son\nconjoint jusqu’au degré de cousin germain inclusivement ;\n4°) s’il y a eu procès civil entre lui l’une des parties ou son conjoint ;\n5°) s’il a précédemment donné conseil, plaidé ou écrit sur le différend ;\n6°) si lui-même ou son conjoint est chargé d’administrer les biens de l’une des\nparties ;\n7°) s’il existe un lien de subordination entre lui-même ou son conjoint et l’une des\nparties ou son conjoint ;\n8°) s’il y a amitié ou inimitié notoire entre lui-même et l’une des parties ;\n9°) si dans les cinq (5) ans qui ont précédé la récusation, il y a eu procès criminel\nentre lui et l’une des parties ou son conjoint ou ses parents et alliés en ligne\ndirecte ;\n10°) s’il a bu ou mangé avec l’une ou l’autre des parties dans leur maison ou reçu\nd’elle des présents.\nLe représentant du ministère public, partie jointe, peut être récusé dans les mêmes\nconditions.","[CPCN] Article 341 : La demande de récusation doit être proposée par la partie elle-même ou par\nson mandataire muni d’un pouvoir spécial. Elle est formée par une déclaration qui est\nconsignée par le greffier dans le procès-verbal.\n\nLa demande doit, à peine d’irrecevabilité, indiquer avec précision les motifs de la\nrécusation et être accompagnée des pièces propres à la justifier.\nIl est délivré par le greffier récépissé de la demande de récusation.","[CPCN] Article 342 : Le greffier communique au juge la copie de la demande de récusation dont il\nest l’objet. Dès qu’il en a la communication, le juge doit s’abstenir jusqu’à ce qu’il ait été\nstatué sur la récusation.\nEn cas d’urgence, un autre juge peut être désigné, même d’office pour procéder\naux opérations nécessaires.","[CPCN] Article 343 : Dans les huit (8) jours de la communication, le juge fait connaître par écrit\nsoit son acquiescement à la récusation, soit les motifs pour lesquels il s’y oppose.\nS’il acquiesce, il est immédiatement remplacé.\nS’il s’oppose à la récusation ou ne répond pas, la demande est transmise par le\ngreffier à la Cour d’Appel et jugée sans délai. L’affaire est jugée au vu des observations\nécrites du magistrat, sans qu’il soit besoin d’appeler les parties en cause ni le juge récusé.\nL’arrêt sur la récusation n’est susceptible d’aucun recours.","[CPCN] Article 344 : La partie dont la demande de récusation a été rejetée peut être condamnée\nà une amende civile\n\nde dix mille (10.000) à cent mille (100.000) francs CFA sans\n\npréjudice des dommages-intérêts qui peuvent être réclamés.","[CPCN] Article 345 : Les actes accomplis par le juge récusé avant qu’il ait eu connaissance de la\ndemande ne peuvent être remis en cause.","[CPCN] Article 346 : Si la récusation vise un magistrat siégeant à juge unique ou plusieurs juges,\net que la juridiction ne puisse plus se constituer, il n’y a plus récusation, mais motif à\nrenvoi à une autre juridiction pour cause de suspicion légitime.\nSous-section 3 : Du renvoi à une autre juridiction","[CPCN] Article 347 : À la demande de l’une des parties, la Cour de Cassation peut dessaisir une\njuridiction de premier degré, soit si elle ne peut être légalement composée ou si le cours\nde la justice se trouve autrement interrompu, soit pour cause de suspicion légitime, soit\ndans l’intérêt d’une bonne administration de la justice. La cour renvoie à une autre\njuridiction. La décision de renvoi s’impose aux parties et à la juridiction de renvoi. Elle n’est\nsusceptible d’aucun recours.\nEn cas de rejet, l’article 344 ci-dessus est applicable.\n\nLe renvoi pour cause de sûreté publique est prononcé par la Cour de Cassation sur\nréquisition du Procureur Général près ladite Cour.\nSous-section 4 : De la prise à partie des juges","[CPCN] Article 348 : Les juges, les membres du ministère public et les officiers de police judiciaire\npeuvent être pris à partie dans les cas suivants :\n1°) s’il y a dol, fraude, concussion ou faute lourde professionnelle qu’on prétend\navoir été commis, soit dans le cours de l’instruction, soit lors du jugement ;\n2°) si la prise à partie est expressément prévue par la loi ;\n3°) si la loi déclare les juges responsables, à peine de dommages-intérêts ;\n4°) s’il y a déni de justice.","[CPCN] Article 349 : L’État est civilement responsable des condamnations en dommages-intérêts\nqui sont prononcées à raison des faits énoncés à l’article 348 ci-dessus contre les\nmagistrats ou les officiers de police judiciaire, sauf son recours contre ces derniers.","[CPCN] Article 350 :Tout juge ou tribunal, tout administrateur ou toute autorité administrative qui,\nsous quelque prétexte que ce soit, même du silence ou de l’obscurité de la loi, aura dénié\nde rendre la justice qu’il doit aux parties, après avoir été requis et qui aura persévéré dans\nson déni, après avertissement ou injonction de ses supérieurs, pourra être poursuivi et\nsera puni d’une amende de dix mille (10.000) à cent mille (100.000) francs CFA et de\nl’interdiction de l’exercice des fonctions publiques de cinq (5) ans jusqu’à vingt (20) ans.","[CPCN] Article 351 : Le déni de justice est constaté par deux réquisitions signifiées aux juges, à\npersonne ou à domicile de quinzaine à quinzaine. Après ces deux réquisitions, le juge\npeut être pris à partie.","[CPCN] Article 352 : La prise à partie est portée devant la Cour de Cassation. Il est présenté à cet\neffet une requête signée de la partie ou d’un mandataire désigné par procuration spéciale,\nlaquelle est annexée à la requête, ainsi que les pièces justificatives à peine de nullité.\nIl ne peut être employé dans la requête aucun terme injurieux contre les juges à\npeine d’une amende dont le montant ne peut excéder cinquante mille (50.000) francs CFA\ncontre la partie et d’une peine de suspension contre son conseil.","[CPCN] Article 353 : La requête peut être rejetée d’emblée. Si elle est admise, elle est\ncommuniquée dans les huit(8) jours au juge pris à partie qui sera tenu de fournir ses\ndéfenses dans le délai qui lui est imparti. La prise à partie est ensuite portée à l’audience.\n49","[CPCN] Article 354 : Pendant la durée de la procédure, le magistrat pris à partie s’abstient de la\nconnaissance du différend ; il s’abstiendra même, jusqu’au jugement définitif de la prise à\npartie, de toutes les causes que le demandeur ou ses parents en ligne directe ou son\nconjoint pourront avoir devant sa juridiction, à peine de nullité des jugements.","[CPCN] Article 355 : Lorsque la requête n’est pas admise, ou lorsque celle-ci ayant été admise\nest déclarée non fondée, le demandeur peut être condamné à une amende de dix mille\n(10.000) à cent mille (100.000) francs CFA, sans préjudice des dommages-intérêts s’il y a\nlieu.\nSection 2 : De la police de l’audience","[CPCN] Article 356 : Le Président exerce la police de l’audience. Tout ce qu’il ordonne pour le\nmaintien de l’ordre à l’audience est exécuté sur le champ. La même disposition est\nobservée dans les lieux où les magistrats et les greffiers exercent les fonctions de leur\nétat.\nCeux qui assistent aux audiences peuvent garder leur coiffure mais doivent\nobserver, à visage découvert, une attitude digne et garder le respect dû à la justice.","[CPCN] Article 357 : Si un ou plusieurs individus, quels qu’ils soient, interrompent le silence,\ndonnent des signes d’approbation ou de désapprobation, soit à la défense des parties, soit\naux discours et aux ordres des magistrats, causent ou entretiennent du tumulte de\nquelque manière que ce soit et si, après l’avertissement du Président ils ne rentrent pas\ndans l’ordre, il leur sera enjoint de se retirer. Ceux qui résistent sont expulsés de la salle\nsans préjudice des poursuites pénales.","[CPCN] Article 358 : Si le trouble est causé par une personne remplissant une fonction près le\ntribunal, elle peut être suspendue de ses fonctions. La suspension pour la première fois ne\npeut excéder trois (3) mois. Le jugement sera exécutoire par provision.\nSi le trouble est causé par un conseil, le président pourra après un avertissement\nresté sans effet, lui enjoindre de se retirer de l’audience. Les débats ainsi interrompus sont\nrenvoyés à une audience ultérieure.\nSi un crime ou un délit est commis à l’audience, le Président agit conformément aux\ndispositions du Code de Procédure Pénale. Si le fait commis ne constitue qu’une\ncontravention, le Président applique, audience tenante, les peines de simple police.\n\nCHAPITRE II – DES DÉBATS","[CPCN] Article 359 : Les débats ont lieu au jour et à l’heure préalablement fixés selon les\nmodalités propres à chaque juridiction. Ils peuvent se poursuivre au cours d’une audience\nultérieure.\nEn cas de changement survenu dans la composition du tribunal après l’ouverture\ndes débats, ceux-ci doivent être repris.","[CPCN] Article 360 : Les débats sont publics sauf le cas où la loi exige qu’ils doivent avoir lieu en\nchambre de conseil.\nLe Président peut décider que les débats auront lieu ou se poursuivent en chambre\nde conseil s’il doit résulter de leur publicité une atteinte à la vie privée, ou si toutes les\nparties le demandent, ou s’il survient des désordres de nature à troubler la sérénité de la\njustice.\nEn chambre de conseil, il est procédé hors la présence du public.","[CPCN] Article 361 : Le Président dirige les débats. Il donne la parole au demandeur, puis au\ndéfendeur pour exposer leurs prétentions, à moins que ceux-ci n’y aient renoncé et\ndéposent leur dossier. Lorsque la juridiction s’estime éclairée, le Président met fin aux\nplaidoiries ou aux observations présentées par les parties.","[CPCN] Article 362 : Les parties peuvent être autorisées à présenter elles-mêmes leur défense\noralement. Le Président a la faculté de leur retirer la parole si la passion ou l’inexpérience\nles empêche de discuter leur cause avec la décence convenable ou la clarté nécessaire.","[CPCN] Article 363 : Le Président et les juges peuvent inviter les parties à fournir des explications\nde droit ou de fait qu’ils estiment nécessaires ou à préciser ce qui est obscur. Le Président\ndoit avertir les parties des moyens qui paraissent pouvoir être relevés d’office et les inviter\nà présenter leurs observations, soit immédiatement, soit dans le délai qu’il fixe. Mention en\nest faite au procès-verbal d’audience.","[CPCN] Article 364 : Le ministère public n’est tenu d’assister aux débats que dans le cas où il est\npartie principale, dans ceux où il représente autrui, ou lorsque sa présence est rendue\nobligatoire par la loi. Dans tous les autres cas, il peut venir à l’audience prendre la parole\nou déposer des conclusions écrites.\nDans toutes les causes où il y a lieu à communication au ministère public, celle-ci\nest faite à la diligence du Président, sauf dispositions particulières. La communication doit\n\navoir lieu en temps voulu pour ne pas retarder le jugement. Le ministère public doit être\navisé de la date de l’audience.\nLe ministère public, partie jointe, prend la parole le dernier et s’il ne peut le faire, il\npeut demander que son audition soit reportée à une prochaine audience.","[CPCN] Article 365 : Le Président peut ordonner la réouverture des débats. Il doit le faire chaque\nfois que les parties n’ont pas été à même de s’expliquer sur des moyens que le tribunal se\npropose de soulever d’office.","[CPCN] Article 366 : Après la clôture des débats, les parties ne peuvent déposer aucune note à\nl’appui de leurs observations si ce n’est en vue de répondre aux arguments développés\npar le ministère public ou à la demande du Président dans les cas prévus aux articles 363\net 365 ci-dessus.\nCHAPITRE III– DU DÉLIBÉRÉ","[CPCN] Article 367 : Il appartient aux juges devant lesquels la cause a été débattue d’en\ndélibérer. Ils doivent être en nombre égal à celui que prescrivent les règles relatives à\nl’organisation judiciaire.\nLa délibération des juges est secrète.\nLa décision est prise à la majorité des voix si la juridiction est collégiale.\nCHAPITRE IV – DU PRONONCÉ DE LA DÉCISION","[CPCN] Article 368 : Si la décision n’est pas prononcée sur le champ, le prononcé en est renvoyé\npour plus ample délibéré à une date que le Président indique et qui est portée à la\nconnaissance des parties.\nLa date du jugement est celle à laquelle il est prononcé.","[CPCN] Article 369 : Les décisions contentieuses sont prononcées publiquement et les décisions\ngracieuses hors la présence du public, le tout sous réserve des dispositions particulières à\ncertaines matières.","[CPCN] Article 370 : Le prononcé du jugement peut se limiter au dispositif. Les décisions rendues\nsur requête ou en matière gracieuse peuvent être l’objet d’une simple communication aux\nparties.","[CPCN] Article 371 : À l’égard des parties le jugement est contradictoire, par défaut ou réputé\ncontradictoire.\n\nSection 1 : Du jugement contradictoire","[CPCN] Article 372 : Le jugement est contradictoire dès lors que les parties comparaissent en\npersonne ou par mandataire selon les modalités propres à la juridiction devant laquelle la\ndemande est portée.\nIl en est de même lorsque les parties ou leurs conseils comparants se retirent de la\nsalle d’audience, sans autorisation du Président et sans motif valable, alors que leur\ndossier est retenu pour être débattu.\nDans le cas où l’une des parties, après avoir comparu, s’abstient d’accomplir les\nactes de la procédure dans les délais requis, le jugement est contradictoire.","[CPCN] Article 373 : Si, sans motif légitime, le demandeur ne comparaît pas, le défendeur peut\nrequérir jugement sur le fond qui sera contradictoire.\nLe juge peut aussi renvoyer l’affaire à une audience ultérieure ou déclarer d’office\nl’assignation caduque. La déclaration de caducité peut être rapportée si le demandeur fait\nconnaître au greffe dans un délai de quinze (15) jours le motif légitime qu’il n’aurait pas été\nen mesure d’invoquer en temps utile. Dans ce cas les parties sont convoquées à une\naudience ultérieure.\nAucune affaire ne peut faire l’objet de plus d’un renvoi.\nSection 2 : Du jugement réputé contradictoire","[CPCN] Article 374 : Le juge statue par jugement réputé contradictoire si le défendeur, cité à\npersonne, ne comparaît pas sans motif légitime valable.\nSection 3 : Du jugement par défaut","[CPCN] Article 375 : Si l’assignation n’a pas été délivrée à personne et que le défendeur ne\ncomparaît pas, le juge statue à son égard par défaut.\nLe juge peut ordonner, à la requête du demandeur ou d’office, une nouvelle citation\ndu défendeur. Celle-ci contiendra la mention que, s’il ne comparaît pas, il sera néanmoins\nstatué sur le fond.\nLe juge ne fait droit à la demande que dans la mesure où il l’estime régulière,\nrecevable et bien fondée.","[CPCN] Article 376 : En cas de pluralité de défendeurs cités pour le même objet, le jugement est\ncontradictoire à l’égard de ceux qui comparaissent et réputé contradictoire à l’égard de\nceux qui ne comparaissent pas s’ils ont été cités à personne.\n53","[CPCN] Article 377 : En cas de pluralité de défendeurs, le juge ne peut statuer avant l’expiration\ndu plus long délai de comparution sur première ou seconde assignation. Il statue à l’égard\nde tous les défendeurs par un seul et même jugement sauf si les circonstances exigent\nqu’il soit statué à l’égard de certains d’entre eux seulement.","[CPCN] Article 378 : Les jugements par défaut peuvent être frappés d’opposition sauf dans le cas\noù cette voie de recours est écartée par une disposition expresse.\nLes jugements réputés contradictoires ne peuvent être frappés de recours que par\nles voies ouvertes contre les jugements contradictoires.","[CPCN] Article 379 : Les jugements par défaut et les jugements réputés contradictoires au seul\nmotif qu’ils sont susceptibles d’appel, seront non avenus s’ils n’ont pas été notifiés dans\nl’année de leur prononcé.\nLa procédure peut être reprise après réitération de l’assignation primitive.","[CPCN] Article 380 : Le jugement par défaut ou réputé contradictoire rendu contre une partie\ndemeurant à l’étranger doit constater expressément les diligences faites en vue de donner\nconnaissance de l’acte introductif d’instance au défendeur.\nCHAPITRE V – DES MENTIONS ET DU CONTENU DE LA DÉCISION","[CPCN] Article 381 : Tout arrêt, jugement ou ordonnance comporte obligatoirement :\n1°)\n\nl’indication de la juridiction dont il émane ;\n\n2°)\n\nles noms du juge ou des juges qui en ont délibéré ;\n\n3°)\n\nle nom du représentant du ministère public, s’il y a lieu ;\n\n4°)\n\nle nom du greffier ;\n\n5°)\n\nles nom, prénoms ou dénomination, profession et domicile des parties et la\nmention de leur comparution ou de leur défaut, avec en ce cas la\nconstatation qu’elles ont été régulièrement convoquées ;\n\n6°)\n\nle cas échéant, les nom et prénoms des conseils ou de toute personne ayant\nreprésenté ou assisté les parties ;\n\n7°)\n\nl’objet de la demande et l’analyse sommaire des moyens produits ;\n\n8°)\n\nles motifs retenus à l’appui de la décision avec référence à la règle juridique\ndont il est fait application ;\n\n9°)\n\nle dispositif contenant la décision ;\n\n10°)\n\nl’indication que la décision a été rendue en audience publique sous réserve\ndes dispositions particulières à certaines matières ;\n\n11°)\n\nla date du prononcé et la signature du Président et du greffier.\n\nEn cas d’empêchement du Président, mention est faite sur la minute, qui est signée\npar l’un des juges qui ont délibéré.\nEn cas d’empêchement absolu, le Président du tribunal est autorisé à signer\nlorsqu’il s’agit d’une composition à juge unique.","[CPCN] Article 382 : Chacune des parties a la faculté de se faire délivrer une expédition revêtue\nde la formule exécutoire. Une seconde expédition, revêtue de cette formule ne peut être\ndélivrée à la même partie qu’en vertu d’une ordonnance du Président de la juridiction qui a\nrendu la décision. En matière gracieuse, copie de la requête est annexée à l’expédition du\njugement.","[CPCN] Article 383 : Les expéditions des arrêts, des jugements, des ordonnances, des mandats\nde justice, les expéditions des contrats et de tous actes susceptibles d’exécution forcée,\nsont intitulées ainsi qu’il suit :\n«République du Niger. Au nom du peuple nigérien».\nEt terminés par la formule exécutoire suivante :\n«En conséquence, le Président de la République mande et ordonne à tous\nhuissiers, sur ce requis, de mettre ledit arrêt (ou jugement, etc.…) à exécution, aux\nProcureurs Généraux et aux Procureurs de la République d'y tenir la main, à tous\ncommandants ou officiers de la force publique de prêter main forte lorsqu'ils en\nseront légalement requis. En foi de quoi le présent arrêt (ou jugement, etc.…) a été\nsigné par…».","[CPCN] Article 384 : Les arrêts, les jugements et les ordonnances ont la force probante d’un acte\nauthentique. Cependant l’omission ou l’inexactitude d’une mention destinée à établir la\nrégularité d’une décision ne peut entraîner la nullité, s’il est établi par les pièces de la\nprocédure, par le procès-verbal d’audience ou par tout autre moyen que les prescriptions\nlégales ont été, en fait, observées.\nLa nullité d’une décision de justice ne peut être demandée que par les voies de\nrecours prévues par la loi.\n\n55","[CPCN] Article 385 : La décision qui statue sur tout ou partie du principal, sur une exception de\nprocédure, une fin de non-recevoir ou tout autre incident a l’autorité de la chose jugée\nrelativement à la contestation qu’elle tranche.\nLa décision qui se borne à ordonner une mesure d’instruction ou une mesure\nprovisoire n’a pas au principal, l’autorité de la chose jugée.\nCHAPITRE VI – DE LA RÉTRACTATION, DE L’INTERPRÉTATION\nET DE LA RECTIFICATION D’UNE DÉCISION","[CPCN] Article 386 : S’il n’est pas avant dire droit, le jugement dessaisit le juge qui l’a rendu.\nToutefois il appartient à tout juge de rétracter sa décision dans les cas déterminés par la\nloi, de l’interpréter à moins qu’elle ne soit frappée d’appel ou de la rectifier sous les\ndistinctions qui suivent.","[CPCN] Article 387 : Les erreurs et omissions matérielles qui affectent une décision, même\npassée en force de chose jugée, peuvent toujours être réparées par la juridiction qui l’a\nrendue ou par celle à laquelle elle est déférée, selon ce que le dossier révèle ou, à défaut,\nce que la raison commande.","[CPCN] Article 388 : Le juge est saisi par simple requête de l’une des parties ou par requête\ncommune ; il peut aussi se saisir d’office.\nLe juge statue après avoir entendu les parties ou celles-ci appelées. La décision\nrectificative est mentionnée sur la minute et les expéditions du jugement.\nSi la décision rectifiée est passée en force de chose jugée, la décision rectificative\nne peut être attaquée que par la voie du recours en cassation.","[CPCN] Article 389 : La juridiction qui a omis de statuer sur un chef de demande peut également\ncompléter sa décision sans porter atteinte à la chose jugée quant aux autres chefs, sauf à\nétablir, s’il y a lieu, le véritable exposé des prétentions respectives des parties et de leurs\nmoyens. La demande doit être présentée avant l’expiration des délais d’appel ou de\npourvoi en cassation et sous réserve qu’un recours ne soit déjà exercé.\nLe juge est saisi par simple requête de l’une des parties ou par requête commune. Il\nstatue après avoir entendu les parties, ou celles-ci appelées. La décision est mentionnée\nsur la minute et les expéditions du jugement. Elle est notifiée comme le jugement et donne\nouverture aux mêmes voies de recours que celui-ci.","[CPCN] Article 390 : Les dispositions de l’article précédent sont applicables s’il a été prononcé sur\ndes choses non demandées ou s’il a été adjugé plus qu’il n’a été demandé.\n\nCHAPITRE VII – DES FRAIS ET DES DÉPENS","[CPCN] Article 391 : Toute partie qui succombe est condamnée aux dépens sauf aux juges à\nlaisser la totalité ou une fraction des dépens à la charge d’une autre partie par décision\nspéciale et motivée.\nLes dépens afférents à l’instance, aux actes et aux procédures d’exécution\ncomprennent :\n1°)\n\nles droits, les taxes, les redevances ou les émoluments perçus par les\ngreffes des juridictions ou l’administration de l’enregistrement à l’exception\ndes droits, des taxes et des pénalités éventuellement dus sur les actes et les\ntitres produits à l’appui des prétentions des parties ;\n\n2°)\n\nles frais de transport des magistrats et des greffiers ;\n\n3°)\n\nles indemnités des témoins ;\n\n4°)\n\nla rémunération des techniciens ;\n\n5°)\n\nles débours tarifés ;\n\n6°)\n\nles émoluments des officiers publics et ministériels.\n\nPeuvent être compris dans les dépens, les frais afférents aux procédures\npréparatoires, ou se rattachant à l’instance par un lien évident de connexité, dès lors que\nleur utilité n’est pas contestée.","[CPCN] Article 392 : Dans toutes les instances, le juge condamne la partie tenue aux dépens ou,\nà défaut, la partie perdante à payer à l’autre partie la somme qu’il détermine, au titre des\nfrais exposés et non compris dans les dépens.\nLe juge tient compte de l’équité ou de la situation économique de la partie\ncondamnée. Il peut, même d’office, pour des raisons tirées des mêmes considérations,\ndire qu’il n’y a pas lieu à cette condamnation.","[CPCN] Article 393 : Les conseils et les huissiers qui auront excédé les bornes de leur ministère,\nles tuteurs, les curateurs, les héritiers bénéficiaires ou autres administrateurs qui auront\ncompromis les intérêts de leur administration pourront être condamnés aux dépens, en\nleur nom, et sans répétition, même aux dommages et intérêts, s’il y a lieu, sans préjudice\ndes poursuites disciplinaires contre les conseils et les huissiers et de la destitution contre\nles tuteurs et autres, suivant la gravité des circonstances.\n\n57","[CPCN] Article 394 : La distraction des dépens est un avantage qui permet au conseil créancier\ndes frais dont il a fait l’avance, d’en poursuivre directement le remboursement contre la\npartie adverse, condamnée aux dépens.\nLa distraction des dépens ne peut être prononcée que par le jugement qui en porte\nla condamnation. Dans ce cas la taxe est poursuivie et l’exécutoire est délivré au nom du\nconseil.\nTITRE XI – DE L’EXÉCUTION DE LA DÉCISION","[CPCN] Article 395 : Le jugement qui n’est susceptible d’aucun recours suspensif d’exécution a\nforce de chose jugée et est exécutoire sous les conditions édictées au livre IV de la\nprésente loi, à moins que le débiteur ne bénéficie d’un délai de grâce ou le créancier de\nl’exécution provisoire.\nCHAPITRE PREMIER – DU DÉLAI DE GRÂCE","[CPCN] Article 396 : Le juge peut, en considération de la bonne foi du débiteur et des\ncirconstances économiques accorder à celui-ci des délais modérés ne pouvant excéder\nune année pour le paiement de sa dette.\nLe délai de grâce peut être accordé par le tribunal lorsqu’il prononce son jugement\net par le président, statuant en la forme des référés conformément à l’article 459, point 1\nde la présente loi.\nL’octroi du délai de grâce doit être motivé. Ce délai court à compter du prononcé de\nla décision lorsque celle-ci est contradictoire et dans les autres cas, du jour de sa\nnotification.","[CPCN] Article 397 : Le délai de grâce ne peut être accordé au débiteur dont les biens sont saisis\npour d’autres créances, ni à celui qui fait l’objet d’une procédure collective d’apurement du\npassif, ou qui, par son fait, a diminué les garanties qu’il avait données par contrat à son\ncréancier.\nDans ces mêmes cas, le débiteur perd le bénéfice du délai de grâce qu’il aurait\nobtenu.\nLe délai de grâce ne fait pas obstacle aux mesures conservatoires.\nCHAPITRE II – DE L’EXÉCUTION PROVISOIRE","[CPCN] Article 398 : L’exécution provisoire ne peut être poursuivie sans avoir été ordonnée\nd’office ou à la demande des parties, si ce n’est pour les décisions qui en bénéficient de\n\nplein droit. Sont notamment exécutoires de droit à titre provisoire les ordonnances de\nréféré, les décisions qui ordonnent des mesures provisoires en cours d’instance ainsi que\ncelles qui ordonnent des mesures conservatoires.\nEn aucun cas, l’exécution provisoire ne pourra être prononcée pour les dépens.","[CPCN] Article 399 : La décision sur l’exécution provisoire doit être motivée. Le juge peut la\nprononcer pour la totalité ou pour partie seulement de la condamnation. Il peut également\nla subordonner à la constitution d’une garantie réelle ou personnelle suffisante pour\nrépondre de toute restitution ou réparation. Néanmoins il n’y aura pas lieu à garantie:\n1°)\n\nlorsqu’il y a titre authentique ou privé qui n’est pas contesté, promesse\nreconnue ou accord intervenu entre les parties ou condamnation précédente\npar jugement devenu définitif ;\n\n2°)\n\nlorsque les sommes à provenir de ladite exécution ont fait l’objet d’une\nconsignation.","[CPCN] Article 400 : La garantie que doit, le cas échéant, fournir le demandeur à l’exécution\nprovisoire est précisée dans le jugement et doit être suffisante pour répondre\néventuellement de toutes restitutions et réparations. Elle peut consister notamment dans\nla soumission d’une caution conformément aux dispositions relatives à la réception des\ncautions ou dans le dépôt d’espèces et de valeurs dont le tribunal, aux offres du\ndemandeur, arbitrera le montant et la nature.","[CPCN] Article 401 : Sauf dans le cas où il s’agit d’une dette de caractère alimentaire ou de\nréparation d’un dommage causé à la personne, la partie condamnée peut éviter que\nl’exécution provisoire soit poursuivie en obtenant du juge des référés, l’autorisation de\nconsigner les espèces ou les valeurs suffisantes pour garantir en principal, intérêts et frais\nle montant de la condamnation.","[CPCN] Article 402 : Dès l’instant où la consignation est effectuée, les garanties constituées par la\npartie au profit de laquelle l’exécution provisoire avait été prononcée, étant devenues sans\nobjet, sont libérées.","[CPCN] Article 403 : Le dépôt ou la consignation visée aux articles précédents sont effectués\nauprès d’organismes habilités à recevoir des dépôts et des consignations, ou entre les\nmains d’un tiers commis à cet effet, suivant les modalités fixées par la décision les\nprescrivant.\n\nIls emportent affectation spéciale et privilège au profit de la partie pour la sûreté des\ndroits de laquelle ils ont été effectués.","[CPCN] Article 404 : Lorsque l’exécution provisoire a été ordonnée, elle ne peut être arrêtée en\ncas d’appel que par le Président de la Cour d’Appel dans les conditions prévues à l’article\n405 ci-dessous.\nIl accorde des défenses à l’exécution provisoire lorsque notamment celle-ci :\n1°) est interdite par la loi ou a été ordonnée hors les cas prévus par la loi ;\n2°) est de nature à entraîner des conséquences manifestement excessives ou\nirréparables.\nDans ce dernier cas, il peut aussi subordonner l’exécution provisoire au paiement\nd’une caution suffisante pour garantir toutes restitutions ou réparations.\nLorsque l’exécution provisoire a été refusée par la juridiction de premier degré, ou si\nayant été demandée, la juridiction a omis de statuer, elle peut être demandée en cas\nd’appel, au Président de la Cour d’Appel.","[CPCN] Article 405 : La requête aux fins de défense à exécution provisoire est adressée au\nPrésident de la Cour d’Appel.\nElle est accompagnée du jugement qu’elle vise ou d’un extrait de son dispositif\ndélivré par le greffe de la juridiction de premier degré, ainsi que de l’acte de l’appel\ninterjeté contre le jugement.\nAu vu de ces pièces, le Président de la Cour d’Appel autorise, par ordonnance, le\nrequérant à assigner le défendeur à comparaître à bref délai.\nEntre la date de signification de l’acte d’assignation et celle de la comparution, il\nsera observé un délai de cinq (5) jours au moins et de huit (8) jours au plus.\nIl est sursis à l’exécution du jugement attaqué pour compter de la date de\nsignification de l’acte d’assignation et jusqu’au prononcé de l’ordonnance du Président de\nla Cour d’Appel.","[CPCN] Article 406 : Le Président de la Cour d’Appel statue au plus tard dans les soixante-douze\n(72) heures qui suivent le dépôt de l’acte d’appel ou de l’assignation à bref délai au greffe\nde la Cour d’Appel.\n\nLes délais visés à l’article 405 ci-dessus et au présent article sont prolongés\nd’autant de jours fériés et/ou chômés qu’ils renferment et impliquent interdiction de débats\njudiciaires ou de signification d’actes.\nCHAPITRE III – DE L’EXÉCUTION AMIABLE","[CPCN] Article 407 : Une partie peut toujours exécuter la décision de justice qui la condamne,\nmême sans attendre qu’elle soit devenue définitive.","[CPCN] Article 408 : Le juge, lorsqu’une décision est devenue définitive, peut désigner sans frais,\npour tentative d’exécution amiable, un huissier. Ce dernier, au vu d’une simple expédition\ndélivrée sans frais, convoque les parties, donne connaissance à la partie condamnée de la\ndécision et l’invite à l’exécuter. Si celle-ci acquiesce, il est dressé procès-verbal.","[CPCN] Article 409 : Les parties peuvent, en cas d’exécution amiable, prendre sur les modalités\nde règlement tous arrangements conformes à leur intérêt qui doivent être constatés par\nécrit, ou mentionnés dans le procès-verbal prévu à l’article précédent.","[CPCN] Article 410 : L’huissier commis ne perçoit à l’occasion de la tentative d’exécution amiable\nque le droit fixe prévu au tarif des frais de justice en matière civile et commerciale.\nCHAPITRE IV – DE L’EXÉCUTION FORCÉE DES JUGEMENTS ET DES ACTES","[CPCN] Article 411 : Nul jugement, nul acte ne peut être mis à exécution s’il ne porte la formule\nexécutoire et s’il n’a été notifié à moins que l’exécution ne soit volontaire ou que la loi en\ndispose autrement.","[CPCN] Article 412 : Sauf dispositions contraires résultant des conventions internationales, les\njugements rendus par les tribunaux étrangers et les actes reçus par les officiers\nministériels étrangers ne sont susceptibles d’être exécutés au Niger que dans les cas et\nsuivant les modalités prévus par les lois et règlements en vigueur.","[CPCN] Article 413 : Si le bénéficiaire d’un jugement ou d’un acte décède avant d’en avoir obtenu\nl’exécution, ses héritiers ou bien le légataire après acceptation du legs, sont tenus de faire\nla preuve de leur qualité.\nS’il s’élève une contestation de cette qualité, l’huissier en dresse procès-verbal et\nrenvoie les parties à se pourvoir. Néanmoins, il peut, après s’être fait autoriser par\nordonnance du président du tribunal, procéder à une saisie conservatoire pour\nsauvegarder les droits de la succession.","[CPCN] Article 414 : Si celui qui est poursuivi décède avant l’exécution totale ou partielle, le\njugement est notifié à ses héritiers qui ont un délai d’un (1) mois pour l’exécuter, à\n\nl’expiration duquel il sera procédé à l’exécution forcée. Les biens meubles de la\nsuccession peuvent être l’objet d’une saisie conservatoire dès la notification.","[CPCN] Article 415 : L’exécution commencée contre le poursuivi avant son décès est continuée\ncontre sa succession.","[CPCN] Article 416 : Si celui qui est poursuivi décède sans laisser d’héritiers connus ou\ndomiciliés, le poursuivant est renvoyé à provoquer la nomination d’un mandataire spécial\npour représenter la succession.","[CPCN] Article 417 : Les jugements qui ordonnent une mainlevée ou une radiation de sûretés, un\npaiement, une mention, une transcription, publication ou quelque chose à faire par un tiers\nou à sa charge, ne sont exécutoires par les tiers ou contre eux que sur présentation du\ncertificat du greffe attestant qu’il n’existe ni opposition, ni appel, et constatant la date de la\nsignification.","[CPCN] Article 418 : Aucune mesure d’exécution ne peut être commencée avant huit heures ou\naprès dix-huit heures, sauf cas de nécessité et avec l’autorisation écrite du président du\ntribunal de grande instance.\nLa partie saisissante ne peut, sauf nécessité constatée par le président du tribunal\nde grande instance, assister aux opérations de saisie.","[CPCN] Article 419 : Les difficultés qui s’élèvent en cours d’exécution sont portées devant le juge\ndu lieu de l’exécution qui statue immédiatement comme il est dit à l’article 430 ci-après.","[CPCN] Article 420 : Les huissiers ont seuls qualité pour procéder à l’exécution forcée des\ndécisions de justice et des actes. Ils ne peuvent agir que sur les réquisitions de celui à qui\nla décision profite, de son représentant légal ou de son mandataire.\nL’huissier compétent est celui dans le ressort duquel l’exécution doit être\npoursuivie.","[CPCN] Article 421 : L’huissier qui serait l’objet d’outrages, de résistance ou de violences lors de\nl’exécution forcée des titres exécutoires fait le constat de l’incident après en avoir informé\nl’auteur.\nCopie de ce constat sera adressée au Procureur de la République près le tribunal\nde grande instance compétent et il est procédé conformément aux dispositions du Code\nde Procédure Pénale et du Code Pénal.","[CPCN] Article 422 : Tout huissier de justice doit tenir un registre des exécutions en matière civile,\ncommerciale ou sociale où sont mentionnés au fur et à mesure de leur accomplissement\n\nles actes d’exécution auxquels il procède, les incidents qui naissent à l’occasion de ces\nactes et le montant des frais déboursés et émoluments perçus.\nCe registre peut être contrôlé par le président du tribunal à tout moment.\nCHAPITRE V – DE L’ASTREINTE","[CPCN] Article 423 : Les cours et tribunaux peuvent, même d’office, ordonner une astreinte pour\nassurer l’exécution de leurs décisions.","[CPCN] Article 424 : L’astreinte est indépendante des dommages-intérêts. Elle est provisoire ou\ndéfinitive. L’astreinte est considérée comme provisoire, à moins que le juge n’ait précisé\nson caractère définitif.","[CPCN] Article 425 : En cas d’inexécution totale ou partielle ou de retard dans l’exécution, la\njuridiction qui a ordonné l’astreinte doit procéder à sa liquidation.","[CPCN] Article 426 : Le taux de l’astreinte définitive ne peut être modifié par le juge lors de sa\nliquidation, sauf s’il est établi que l’inexécution de la décision judiciaire provient d’un cas\nfortuit ou d’une force majeure. Le juge peut modérer ou supprimer l’astreinte provisoire\nmême en cas d’inexécution constatée.\nCHAPITRE VI – DU TAUX DE L’INTÉRÊT LÉGAL","[CPCN] Article 427 : En toute matière, le taux de l’intérêt légal est fixé pour la durée de l’année\ncivile. Il est, pour l’année considérée, égal au taux d’escompte pratiqué par la Banque\ncentrale le 15 décembre de l’année précédente. Si le taux d’escompte au 15 juin de\nl’année considérée est différent de trois (3) points ou davantage, de celui pratiqué le 15\ndécembre précédent, le taux d’intérêt légal est égal, pour les six derniers mois de l’année,\nau nouveau taux d’escompte.","[CPCN] Article 428 : En cas de condamnation, le taux de l’intérêt légal est majoré de cinq (5)\npoints à l’expiration d’un délai de deux (2) mois à compter du jour où la décision de justice\nest devenue exécutoire, fut-ce par provision.\nEn cas de condamnation confirmée en appel, le taux majoré de l’intérêt légal\ns’applique à compter de la décision de première instance.","[CPCN] Article 429 : En matière extracontractuelle, les intérêts moratoires peuvent courir à partir\nde l’assignation.\n\nCHAPITRE VII – DES DIFFICULTÉS D’EXÉCUTION","[CPCN] Article 430 : Le président du tribunal de grande instance connaît, en la forme des référés,\nde toute difficulté ayant trait à l’exécution des décisions de justice et autres titres\nexécutoires.\nIl ne peut, en ce cas, ni modifier le dispositif de la décision servant de fondement\naux poursuites, ni en suspendre l’exécution si ce n’est dans le cas où il octroie un délai de\ngrâce.\n\nLIVRE II : DES DISPOSITIONS PARTICULIÈRES À CHAQUE JURIDICTION\nTITRE PREMIER – DE LA PROCÉDURE DEVANT LE TRIBUNAL DE GRANDE INSTANCE\nCHAPITRE PREMIER – DE LA PROCÉDURE EN MATIÈRE CONTENTIEUSE\n\nSection 1 : De l’introduction de l’instance par requête conjointe","[CPCN] Article 431 : Les parties peuvent se présenter volontairement, par requête conjointe,\ndevant le tribunal pour lui soumettre leur différend. Il en est fait mention au jugement. Elles\npeuvent se présenter devant un tribunal autre que celui de leur domicile.","[CPCN] Article 432 : La requête conjointe est l’acte commun par lequel les parties soumettent au\njuge leurs prétentions respectives, les points sur lesquels elles sont en désaccord ainsi\nque leurs moyens respectifs.\nElle contient, en outre, à peine d’irrecevabilité :\n-\n\npour les personnes physiques : les nom, prénoms, profession, domicile,\nrésidence, nationalité, date et lieu de naissance de chacun des requérants ;\n\n-\n\npour les personnes morales, leur forme, leur dénomination, leur siège social et\nl’organe qui les représente légalement ;\n\n-\n\nl’indication de la juridiction devant laquelle la demande est portée ;\n\n-\n\nl’indication des pièces sur lesquelles la demande est fondée.\n\nLa requête est datée et signée par les parties.\nElle vaut conclusions.","[CPCN] Article 433 : Le tribunal est saisi par la remise au greffe de la requête conjointe.\n\nLe président du tribunal fixe les jour et heure auxquels l’affaire sera appelée. Avis\nen est donné par le greffier aux parties ou en cas de constitution, à leurs conseils.\nIl est alors procédé comme il est dit aux articles 445 à 460 ci-dessous.\nSection 2 : De l’assignation","[CPCN] Article 434 : La demande en justice est formée par assignation. Sous réserve des cas\ndans lesquels le tribunal peut être saisi par simple requête, toutes les demandes initiales\nen matière civile et commerciale sont formées par assignation.\nL’assignation est l’acte par lequel l’huissier de justice notifie au défendeur qu’une\ndemande en justice est formée contre lui et qu’il doit se présenter devant le tribunal à la\ndate indiquée.\nLe tribunal est saisi, à la diligence de l’une ou l’autre partie, par la remise au greffe\nd’une copie de l’assignation.\nL’assignation est délivrée dans les conditions spécifiées aux articles 81 à 93 du\nprésent Code.","[CPCN] Article 435 : L’assignation contient à peine de nullité, outre les mentions prescrites pour\nles actes d’huissier de justice :\n-\n\nl’indication de la juridiction devant laquelle la demande est portée ainsi que les\ndate et heure de l’audience ;\n\n-\n\nl’objet de la demande avec un exposé des faits et moyens;\n\n-\n\nl’indication que, faute pour le défendeur de comparaître, il s’expose à ce qu’un\njugement soit rendu contre lui sur les seuls éléments fournis par son adversaire ;\n\n-\n\nl’indication des pièces sur lesquelles la demande est fondée;\n\n-\n\nle cas échéant, la constitution du conseil.\n\nL’assignation vaut conclusions.","[CPCN] Article 436 : Le défendeur doit, à peine d’être déclaré, même d’office, irrecevable en sa\ndéfense faire connaître :\n-\n\ns’il s’agit d’une personne physique, ses nom, prénoms, profession, domicile,\nrésidence, nationalité, date et lieu de naissance ;\n\n-\n\ns’il s’agit d’une personne morale, sa forme, sa dénomination, son siège social et\nl’organe qui le représente.\n\n65","[CPCN] Article 437 : Outre les personnes physiques et les personnes morales de droit privé,\npeuvent être assignés:\n1°)\n\nl’État, en la personne du Secrétaire Général du Gouvernement en ses\nbureaux;\n\n2°)\n\nles établissements publics de toute nature, en la personne de leur\nreprésentant légal, en ses bureaux ;\n\n3°)\n\nles régions en la personne du Président du Conseil Régional, au siège du\nConseil Régional ou à son domicile ;\n\n4°)\n\nles communes en la personne du maire au siège de la municipalité ou à son\ndomicile ;\n\n5°)\n\nles autres collectivités publiques, en la personne de leur représentant légal.\nSection 3 : Du délai de comparution","[CPCN] Article 438 : L’assignation doit être délivrée au moins huit (8) jours avant l’audience. Ce\ndélai est augmenté en raison des distances conformément aux dispositions de l’article 77\nde la présente loi.","[CPCN] Article 439 : Si, en raison de circonstances particulières, l’assignation ne peut être\ndélivrée dans le délai de l’article 438 ci-dessus, l’huissier doit en référer au greffier du\ntribunal qui fait fixer par le président de la juridiction une nouvelle date de comparution.","[CPCN] Article 440 : Toutes les fois que par le fait de l’huissier le délai entre l’assignation et la\ndate de comparution est inférieur au délai prévu par l’article 438 ci-dessus et qu’il en\nrésulte une nullité ou un report de l’audience, l’huissier sera condamné aux frais de l’acte\net de la procédure annulée, sans préjudice de tous autres dommages-intérêts qui lui sont\nréclamés, conformément aux dispositions de l’article 96 du présent Code.","[CPCN] Article 441 : Dans les cas qui requièrent célérité et notamment en matière commerciale,\nle président peut, par ordonnance rendue sur requête, permettre d’assigner à bref délai,\nmême de jour à jour ou d’heure à heure ; il pourra si le cas l’exige, assujettir le demandeur\nà donner caution ou à justifier d’une solvabilité suffisante.\nL’ordonnance n’est susceptible d’aucune voie de recours.","[CPCN] Article 442 : Le jour de l’audience, le président s’assure qu’il s’est écoulé un temps\nsuffisant depuis l’assignation permettant à la partie assignée de préparer sa défense.\n\nL’affaire est ensuite plaidée sur le champ, en l’état où elle se trouve, même sans\nconclusions écrites.\nLe président peut toutefois renvoyer l’affaire à une autre audience de plaidoirie s’il\nle juge utile, ou en cas de nécessité, devant le juge de la mise en état.\nAucune affaire ne peut faire l’objet de plus d’un renvoi.\nSection 4 : De l’enrôlement","[CPCN] Article 443 : Dès que l’assignation est délivrée, l’huissier effectue sans délai au greffe de\nla juridiction le dépôt de l’original de l’assignation à moins qu’il ne l’ait remis au conseil\nconstitué du demandeur, qui, en ce cas, en effectue le dépôt.","[CPCN] Article 444 : Il est tenu au greffe du tribunal un registre sur lequel sont inscrites dans\nl’ordre de leur dépôt toutes les assignations. L’instance conserve le numéro d’ordre et le\nmillésime qui lui sont donnés jusqu’à sa solution définitive, même lorsque l’affaire est\nreportée d’une année civile à l’autre.\nLe numéro d’ordre est communiqué aux conseils constitués qui le reproduisent à\nl’entête de chacune de leurs conclusions.","[CPCN] Article 445 : Chaque affaire fait l’objet de l’ouverture d’un dossier qui porte sur la première\npage les nom et prénoms des parties, leur domicile, le nom des conseils et le numéro\nd’ordre. Il est fait également mention des renvois et de leur date. Le dossier contient la\nrequête introductive ou l’original de l’assignation, les conclusions et les productions des\nparties, les pièces annexes, les décisions rendues et les récépissés des pièces.\nLe greffier dresse au verso de la première page l’inventaire des pièces du dossier,\navec leur numéro d’entrée et la date.\nSection 5 : De l’instruction du procès\nSous-section 1 : De la conciliation","[CPCN] Article 446 : Toutes les instances sont dispensées du préliminaire de conciliation sauf\ndans les cas où la loi en dispose autrement. Néanmoins en toutes matières, les parties\npeuvent comparaître volontairement aux fins de conciliation devant le juge compétent. Le\ndemandeur a également la faculté de citer le défendeur en conciliation en observant les\ndélais d’assignation.","[CPCN] Article 447 : Le juge saisi peut, en tout état de la procédure, tenter la conciliation des\nparties qui peuvent être assistées de leurs conseils.\n67","[CPCN] Article 448 : S’il y a conciliation, le juge assisté du greffier, dresse procès-verbal des\nconditions de l’arrangement.\nCe procès-verbal, dûment lu et traduit aux parties dans la langue qu’elles\ncomprennent, est signé par celles-ci.\nDans le cas où l’une ou l’autre partie ne sait pas signer, mention est faite de son\naccord au procès-verbal après qu’elle a apposé l’empreinte de son indexe gauche.\nLe procès-verbal est déposé au greffe et fait preuve jusqu’à inscription de faux vis à\nvis de tous, de sa date et des déclarations qui y sont relatées\nLes conventions des parties inscrites au procès-verbal valent titre exécutoire.\nSous-section 2 : De l’appel des causes et du renvoi à l’audience","[CPCN] Article 449 : Au jour fixé, l’affaire est obligatoirement appelée devant le président du\ntribunal ou le magistrat qu’il délègue, qui discute de l’état de la cause avec les parties\nprésentes ou leurs conseils.","[CPCN] Article 450 : Le président renvoie à l’audience les affaires qui d’après les explications des\nparties ou de leurs conseils et au vu des conclusions échangées et des pièces\ncommuniquées, lui paraissent prêtes à être jugées sur le fond.\nIl renvoie également à l’audience les affaires dans lesquelles le défendeur ne\ncomparaît pas, si elles sont en état d’être jugées sur le fond, à moins qu’il n’ordonne la\nréassignation du défendeur.\nDans tous les cas visés ci-dessus, le président déclare l’instruction close et fixe la\ndate de l’audience, celle-ci peut être tenue le même jour.","[CPCN] Article 451 : Le président peut également décider que les parties ou leurs conseils se\nprésenteront à nouveau devant lui, à une date qu’il fixe, pour conférer une dernière fois\nde l’affaire s’il estime qu’un ultime échange de conclusions ou qu’une ultime\ncommunication de pièces suffit à la mettre en état.\nDans ce cas, il impartit à chacune des parties ou à leurs conseils le délai\nnécessaire à la signification des conclusions et, s’il y a lieu, à la communication des\npièces. Sa décision fait l’objet d’une simple mention au dossier.\nÀ la date fixée par lui, le président renvoie l’affaire à l’audience si elle a été mise en\nétat dans les délais impartis ou si l’une des parties ou l’un des conseils le demande,\n\nauxquels cas il déclare l’instruction close et fixe la date de l’audience. Celle-ci peut être\ntenue le même jour.","[CPCN] Article 452 : Toutes les affaires que le président ne renvoie pas à l’audience sont mises\nen état d’être jugées conformément aux dispositions des articles 454 à 458 de la présente\nloi.","[CPCN] Article 453 : Sont obligatoirement soumises à la procédure abrégée :\n-\n\nles demandes personnelles à quelque somme qu’elles puissent monter quand il\ny a titre, pourvu qu’il ne soit pas contesté ;\n\n-\n\nles causes relatives aux incidents de saisie et aux provisions alimentaires ou\ntoutes autres mesures de pareille urgence ;\n\n-\n\nles causes qui donnent lieu à déclinatoire de compétence ou à exception ;\n\n-\n\nles demandes en paiement des effets de commerce.\nSous-section 3 : De la mise en état des causes","[CPCN] Article 454 : L’affaire est instruite sous le contrôle du président ou d’un magistrat de la\njuridiction à laquelle elle a été distribuée.\nLe juge de la mise en état a pour mission de veiller au déroulement loyal de la\nprocédure, spécialement à la ponctualité de l’échange des conclusions et de la\ncommunication des pièces.\nLes causes sont appelées à des audiences de conférence en fonction des\nexigences de leur mise en état sans qu’il puisse en résulter un quelconque retard.","[CPCN] Article 455 : Le juge de la mise en état, à compter de sa saisine, est exclusivement\ncompétent pour :\n1°)\n\nfixer, au fur et à mesure, les délais nécessaires à l’instruction de l’affaire, eu\négard à la nature, à l’urgence et à la complexité de celle-ci et après avoir\nprovoqué l’avis des parties ou des conseils ;\n\nIl peut également adresser des injonctions aux parties ou aux conseils de conclure\ndans les délais qu’il fixe.\nIl peut accorder des prorogations de délais ;\n2°)\n\ninviter les parties ou les conseils à répondre aux moyens sur lesquels ils\nn’auraient pas conclu.\n\nIl peut également les inviter à fournir les explications de fait et de droit nécessaires\nà la solution du litige.\nIl peut se faire communiquer l’original des pièces versées aux débats ou en\ndemander la remise en copie. Il exerce tous les pouvoirs nécessaires à la communication,\nà l’obtention et à la production des pièces ;\n3°)\n\nentendre les parties, même d’office.\n\nL’audition des parties a lieu contradictoirement à moins que l’une d’elles, dûment\nconvoquée, ne se présente pas ;\n4°)\n\ninviter les parties à mettre en cause tous les intéressés dont la présence lui\nparaît nécessaire à la solution du litige ;\n\n5°)\n\nprocéder aux jonctions et disjonctions d’instance ;\n\n6°)\n\nconstater la conciliation, même partielle, des parties et même l’extinction de\nl’instance ;\n\n7°)\n\nstatuer sur les exceptions dilatoires et sur les nullités pour vice de forme ;\n\n8°)\n\nordonner, même d’office, toute mesure d’instruction.\n\nLe juge de la","[CPCN] Article 456 : Les mesures d’instruction que le juge de la mise en état ordonne sont\nexécutées sous son contrôle. Il surveille notamment les expertises et connaît de leurs\ndifficultés.\nDès l’exécution de la mesure ordonnée, l’instruction de la cause reprend à la\ndemande de l’une des parties.","[CPCN] Article 457 : Lorsque la cause est en état, le juge la renvoie par ordonnance à une\naudience de jugement. Cette ordonnance est dispensée d’enregistrement.\nAprès l’ordonnance de renvoi, qui vaut clôture de la mise en état, aucune\nconclusion ne peut être déposée, ni aucune pièce communiquée ou produite.\nL’ordonnance de renvoi ne peut être rapportée par le président ou le tribunal que pour\ncause grave et par ordonnance ou jugement motivé, non susceptible de recours.\n\nToutefois, le tribunal pourra, sans rapporter l’ordonnance, retenir à l’audience la\ndemande en intervention volontaire qu’il entend joindre au principal, lorsqu’il estime qu’il\npeut immédiatement statuer sur le fond.\nLes ordonnances du juge de la mise en état ne sont pas susceptibles d’opposition.\nElles ne peuvent être frappées d’appel ou de pourvoi en cassation qu’avec le\njugement sur le fond.\nToutefois, elles sont susceptibles d’appel dans les quinze (15) jours de leur\nsignification :\n-\n\ndans les cas et conditions prévus en matière d’expertise ou de sursis à statuer ;\n\n-\n\nlorsqu’elles ont pour effet de mettre fin à l’instance ou lorsqu’elles constatent\nson extinction.","[CPCN] Article 458 : Si une partie n’exécute pas dans les délais impartis les formalités que le juge\na enjoint d’accomplir et les mesures ordonnées, la partie adverse pourra obtenir\nl’ordonnance de renvoi prévue à l’article précédent. Le tribunal statue sur le fond par\njugement contradictoire.\nCHAPITRE II – DE LA JURIDICTION DU PRÉSIDENT DU TRIBUNAL\n\nSection 1 : Des ordonnances de référé","[CPCN] Article 459 : L’ordonnance de référé est une décision provisoire, rendue à la demande\nd’une partie, l’autre présente ou appelée, dans les cas où la loi confère à un juge qui n’est\npas saisi du principal, le pouvoir d’ordonner immédiatement les mesures provisoires et\nconservatoires.\nLe président du tribunal peut :\n1°)\n\nen cas d’urgence, ordonner toutes les mesures qui ne se heurtent à aucune\ncontestation sérieuse et que justifie l’existence d’un différend ;\n\n2°)\n\nprescrire,\n\nmême\n\nen\n\ncas\n\nde\n\ncontestation\n\nsérieuse,\n\nles\n\nmesures\n\nconservatoires ou de remise en état qui s’imposent, soit pour prévenir un\ndommage imminent, soit pour faire cesser un trouble manifestement illicite ;\n3°)\n\naccorder une provision au créancier dans le cas où l’existence de l’obligation\nn’est pas sérieusement contestable.\n\nIl statue également, en la forme des référés, sur les difficultés d’exécution d’un\njugement ou d’un autre titre exécutoire.\n\nLes pouvoirs du Président visés aux points 1°, 2° et 3° ci-dessus, s’étendent à\ntoutes les matières où il n’existe pas de procédure particulière de référé.","[CPCN] Article 460 : Il en est référé au président par requête ; celui-ci fixe immédiatement par\nordonnance le jour, l’heure et le lieu de l’audience à laquelle la demande sera examinée.\nL’assignation est donnée pour cette date. Si le cas requiert célérité, le président peut\npermettre d’assigner à heure indiquée même les jours fériés ou chômés.","[CPCN] Article 461 : Le président s’assure qu’il s’est écoulé un temps suffisant qui ne saurait\nexcéder huit (8) jours entre l’assignation et l’audience pour que la partie assignée ait pu\npréparer sa défense. Il a la faculté de renvoyer l’affaire en état de référé devant la\nformation collégiale.","[CPCN] Article 462 : L’ordonnance de référé ne peut préjudicier au fond. Elle n’a pas au principal\nautorité de la chose jugée. Elle ne peut être rapportée en référé ou modifiée qu’en cas de\ncirconstances nouvelles.\nLes minutes des ordonnances sont conservées au greffe de la juridiction.","[CPCN] Article 463 : L’ordonnance de référé est exécutoire par provision sans caution à moins\nque le président n’ait ordonné qu’il en soit fourni une.\nEn cas de nécessité, le président peut ordonner l’exécution de son ordonnance sur\nminute et avant enregistrement.\nIl peut prononcer des condamnations à des astreintes et aux dépens. Il est habilité\nà liquider à titre provisoire les astreintes qu’il a prononcées.","[CPCN] Article 464 : L’ordonnance de référé n’est pas susceptible d’opposition. Elle peut être\nfrappée d’appel.\nLe délai pour interjeter appel est de quinze (15) jours. L’appel intervient par exploit\nd’huissier signifié à l’intimé ayant rendu l’ordonnance attaquée.\nSi les parties étaient présentes ou représentées à l’audience, le point de départ du\ndélai est la date du prononcé de l’ordonnance.\nÀ l’égard de la partie qui n’était ni présente, ni représentée à l’audience, le point de\ndépart est la date de signification de l’ordonnance qui lui a été faite.\nL’acte d’appel est déposé au greffe de la Cour d’Appel en même temps que\nl’ordonnance attaquée ou un extrait de son dispositif délivré par le greffe de la juridiction\nde premier degré.\n72","[CPCN] Article 465 : Le président de la Cour d’Appel est compétent pour connaître des appels\ninterjetés contre les ordonnances rendues par les juridictions de référé de premier degré ;\nà cet égard, il peut ordonner pour les cas d’urgence, toutes mesures qui ne se heurtent à\naucune contestation sérieuse et que justifie l’existence d’un différend, sans que ces\nmesures puissent préjudicier au fond du litige principal.\nSection 2 : Des ordonnances sur requête","[CPCN] Article 466 : L’ordonnance sur requête est une décision rendue non contradictoirement\npar le président dans les cas spécifiés par la loi ou lorsque les circonstances n’exigent pas\nque la partie adverse soit appelée.\nLe président peut également, dans les mêmes conditions, ordonner sur requête\ntoute mesure urgente ; la requête est présentée en double exemplaire ; elle doit être\nmotivée et indiquer, si elle est présentée à l’occasion d’une instance, la juridiction saisie.\nL’ordonnance sur requête est motivée. Elle est exécutoire au seul vu de la minute et\nest dispensée d’enregistrement. Le double de l’ordonnance est conservé au greffe.","[CPCN] Article 467 : S’il n’est pas fait droit à la requête, appel peut être interjeté de l’ordonnance\ndans le délai de quinze (15) jours à compter de son prononcé.\nS’il est fait droit à la requête, tout intéressé peut en référer au juge qui a rendu\nl’ordonnance.","[CPCN] Article 468 : Le président a la faculté de modifier ou de rétracter son ordonnance même si\nle juge du fond est saisi de l’affaire.\nCHAPITRE III – DE LA PROCÉDURE EN MATIÈRE GRACIEUSE","[CPCN] Article 469 : La demande est formée par une requête que la partie ou son conseil dépose\nou adresse au greffe de la juridiction.\nSi la juridiction est collégiale, le président désigne par ordonnance un magistrat\nrapporteur et communique la requête au ministère public.\nLe magistrat rapporteur dispose, pour instruire la demande, des mêmes pouvoirs\nque le juge de la mise en état.","[CPCN] Article 470 : Le dossier comprenant la requête, les pièces à l’appui, les conclusions du\nministère public et le rapport du magistrat rapporteur, est examiné par le tribunal en\nchambre du conseil. Le conseil du requérant est entendu, s’il se présente.\n\n73","[CPCN] Article 471 : La décision est rendue en chambre du conseil sauf s’il en est disposé\nautrement.\nTITRE II – DE LA PROCÉDURE DEVANT LE TRIBUNAL D’INSTANCE\nET LE TRIBUNAL DU FONCIER RURAL\n\nCHAPITRE 1– DE LA SAISINE ET DE LA COMPARUTION","[CPCN] Article 472 : Le Tribunal d’Instance et le tribunal du foncier rural sont saisis par\nassignation à fin de conciliation et, à défaut de conciliation, de jugement, sauf la faculté\npour le demandeur de provoquer une tentative de conciliation avant d’assigner.\nLe Tribunal d’Instance et le tribunal du foncier rural peuvent également être saisis\npar requête écrite ou verbale. Dans ce cas, le juge transcrit la requête.\nLes parties peuvent également se présenter volontairement sans requête ou par\nrequête conjointe.","[CPCN] Article 473 : La procédure peut être écrite ou orale. Dans ce dernier cas, les prétentions\net moyens des parties sont notés au dossier ou consignés dans un procès-verbal.","[CPCN] Article 474 : En cas de saisine par requête, le greffier avise le demandeur verbalement ou\npar lettre, des lieu, jour et heure de l’audience.","[CPCN] Article 475 : Le greffier convoque le défendeur par lettre simple\n\nou par tout moyen\n\nprobant laissant trace écrite.\nLa convocation, qui vaut\n\ncitation, mentionne les nom, prénoms, profession et\n\ndomicile du demandeur, l’objet de la demande ainsi que les lieu, jour et heure de\nl’audience.","[CPCN] Article 476 : L’avis et la convocation indiquent que les parties doivent se présenter en\npersonne ou se faire représenter à l’audience.","[CPCN] Article 477 : Si, au jour fixé par l’avis, le demandeur ne se présente pas, ne se fait pas\nreprésenter ou ne présente pas d’excuse valable, l’affaire est rayée du rôle ; il en est de\nmême quand, après renvoi, il ne se présente pas ou ne se fait pas représenter.\nDans ces cas, la cause ne peut être reprise qu’une seule fois et selon les formes\nimparties pour la demande primitive, à peine de déchéance.","[CPCN] Article 478 : Si le défendeur ne comparaît pas au jour fixé, ne justifie d’un cas de force\nmajeure ou ne présente pas par écrit ses moyens de défense, défaut est donné contre lui\net le tribunal statue sur le mérite de la demande.\n\nDéfaut ne peut plus être donné au défendeur qui a comparu ; en ce cas, la décision\nest réputée contradictoire et seule la voie de l’appel est ouverte après signification du\njugement.\nCHAPITRE II – DE L’AUDIENCE, DU JUGEMENT ET DES VOIES DE RECOURS","[CPCN] Article 479 : Le délai pour comparaître est de huit (8) jours à compter de la saisine du\ntribunal.\nEn cas d’urgence, les délais de comparution et de remise de l’assignation peuvent\nêtre réduits par autorisation écrite du juge.","[CPCN] Article 480 : Le juge s’efforce de concilier les parties. La tentative de conciliation peut\navoir lieu dans le cabinet du juge.","[CPCN] Article 481 : À défaut de conciliation l’affaire est immédiatement jugée ou, si elle n’est pas\nen état de l’être, renvoyée à une date ultérieure.\nAucune affaire ne peut faire l’objet que d’un seul renvoi.","[CPCN] Article 482 : La poursuite de l’instance, après l’exécution d’une mesure d’instruction ou\nl’expiration d’un délai de sursis à statuer, a lieu sur l’avis qui en est donné aux parties\nverbalement ou par simple lettre du greffier.","[CPCN] Article 483 : Le juge peut inviter les parties à fournir les explications qu’il estime\nnécessaires à la solution du litige et les mettre en demeure de produire dans le délai qu’il\ndétermine tous les documents ou les justifications propres à l’éclairer, faute de quoi, il peut\npasser outre et statuer, sauf à tirer toute conséquence de l’abstention de la partie ou de\nson refus.","[CPCN] Article 484 : Les jugements rendus contradictoirement sont susceptibles d’appel devant le\ntribunal de grande instance dans un délai de 2 mois à compter de leur prononcé. Les\njugements par défaut sont susceptibles d’opposition devant le tribunal d’instance ou du\nfoncier rural dans un délai de 15 jours à compter de leur notification.\nL’appel se fait par déclaration au greffe de la juridiction ayant rendu la décision\nattaquée ou de celui du tribunal de grande instance.\nLIVRE III : DES VOIES DE RECOURS","[CPCN] Article 485 : Les voies ordinaires de recours sont l’appel et l’opposition; les voies\nextraordinaires sont la tierce opposition, le recours en révision et le pourvoi en cassation.\n\nTITRE PREMIER – DES RÈGLES COMMUNES","[CPCN] Article 486 : La notification des jugements, même faite à partir d’une expédition, fait courir\nle délai pendant lequel les recours peuvent être exercés, à moins qu’en vertu de la loi, ce\ndélai n’ait déjà commencé à courir dès le jour de la décision.\nLe délai court même à l’encontre de celui qui notifie ; la notification, même sans\nréserve, n’emporte pas acquiescement de sa part.","[CPCN] Article 487 : Les jugements sont notifiés selon les formes prévues par la loi. Dans le\nsilence de la loi, cette notification est faite par voie de signification.\nL’acte de notification des décisions doit indiquer de manière très apparente et à\npeine de nullité le délai d’opposition, d’appel ou de pourvoi en cassation dans le cas où\nl’une de ces voies de recours est ouverte, ainsi que les modalités selon lesquelles le\nrecours doit être exercé.","[CPCN] Article 488 : Lorsqu’une partie demeure à l’étranger, la notification des jugements est\nvalablement faite au domicile élu au Niger, à défaut au Parquet.","[CPCN] Article 489 : En cas de condamnation solidaire ou indivisible de plusieurs parties, la\nnotification faite à l’une d’elles ne fait courir le délai qu’à son égard.\nDans le cas où un jugement profite solidairement ou indivisiblement à plusieurs\nparties, chacune peut se prévaloir de la notification faite par l’une d’elles.","[CPCN] Article 490 : Le délai ne court contre une personne en tutelle que du jour où le jugement a\nété notifié à son représentant légal.\nLe délai ne court contre le majeur en curatelle que du jour de la notification faite au\ncurateur.","[CPCN] Article 491 : S’il se produit au cours du délai d’opposition ou d’appel un changement dans\nla capacité d’une partie à laquelle le jugement avait été notifié, le délai est interrompu. Le\ndélai ne recommencera à courir qu’en vertu d’une notification faite à celui qui a désormais\nqualité pour la recevoir.","[CPCN] Article 492 : Le délai d’opposition, d’appel ou de cassation est interrompu par le décès de\nla partie à laquelle la décision avait été signifiée. Il ne recommence à courir qu’en vertu\nd’une notification faite au domicile du défunt. Cette notification peut être faite aux héritiers\net représentants collectivement et sans désignation de noms et qualités.\n\n76","[CPCN] Article 493 : Le délai pour faire opposition ou pour relever appel est suspensif\nd’exécution. L’opposition ou l’appel suspendent pareillement l’exécution.\nLe délai de pourvoi en cassation ainsi que le pourvoi ne sont suspensifs que dans\nles cas spécifiés par la loi.\nLes dispositions des deux alinéas qui précèdent ne font pas obstacle à l’exécution\ndes jugements lorsque l’exécution provisoire est de droit ou a été ordonnée.","[CPCN] Article 494 : La qualification inexacte d’un jugement par les juges qui l’ont rendu est sans\neffet sur le droit d’exercer un recours.","[CPCN] Article 495 : La notification d’un recours est valablement faite au domicile personnel de la\npartie mentionnée dans la signification du jugement.","[CPCN] Article 496 : Dans le cas où la partie qui a signifié le jugement est décédée, le recours\npeut être notifié au domicile du défunt, à ses héritiers et représentants collectivement et\nsans désignation de noms et qualités. Un jugement ne peut toutefois être requis contre\nles héritiers et représentants que si chacun a été cité à comparaître.","[CPCN] Article 497 : En cas de cessation de fonction d’un représentant légal d’une partie, celui-ci\npeut exercer le recours en son nom s’il y a intérêt personnel. Le recours peut pareillement\nêtre exercé contre lui.\nTITRE II – DES VOIES ORDINAIRES DE RECOURS\nCHAPITRE PREMIER – DE L’OPPOSITION","[CPCN] Article 498 : L’opposition tend à faire rétracter les jugements ou les arrêts rendus par\ndéfaut. Elle n’est ouverte qu’au défaillant.\nL’opposition remet en question devant le même juge les points jugés par défaut\npour qu’il soit à nouveau statué en fait et en droit.","[CPCN] Article 499 : Le délai pour faire opposition est de quinze (15) jours ; il est augmenté en\nraison des distances dans les conditions déterminées à l’article 77 de la présente loi. Le\ndélai d’opposition court à compter de la signification du jugement ou de l’arrêt, ou à\ncompter du jour où la partie condamnée en a eu connaissance par acte d’exécution ou\nautrement.","[CPCN] Article 500 : L’huissier de justice qui accomplit un acte comportant exécution d’un\njugement ou d’un arrêt de défaut est tenu d’avertir le défaillant, à peine de nullité de l’acte\nd’exécution, qu’il a la possibilité de faire opposition dans les formes et délais prescrits par\n\nle présent titre et que, passé ce délai, l’exécution sera continuée sans qu’il soit besoin de\nla faire ordonner.","[CPCN] Article 501 : L’opposition est formée par assignation signifiée par acte d’huissier à la\npartie adverse et déposée au greffe de la juridiction qui a rendu la décision.\nL’assignation doit contenir à peine de nullité :\n-\n\nles nom, prénoms et domicile du défaillant ;\n\n-\n\nla date de la décision frappée d’opposition ;\n\n-\n\nles nom, prénoms et adresse des parties;\n\n-\n\nles moyens du défaillant.","[CPCN] Article 502 : Le greffier donne récépissé du dépôt au greffe de l’assignation.","[CPCN] Article 503 : Il est tenu au greffe de chaque juridiction un registre spécial sur lequel sont\ninscrites les oppositions avec une mention sommaire énonçant les nom et prénoms des\nparties et s’il y a lieu de leurs conseils, les dates du jugement et de l’opposition, la date de\nla notification à la partie adverse et de celle de l’audience à laquelle l’affaire a été fixée.","[CPCN] Article 504 : L’affaire est instruite et jugée selon les règles applicables devant la juridiction\nqui a rendu la décision frappée d’opposition.","[CPCN] Article 505 : Dans l’instance qui recommencera, la recevabilité des prétentions\nrespectives du demandeur et de l’opposant s’apprécie en fonction de la demande\nprimitive, suivant les règles ordinaires.","[CPCN] Article 506 : Celui qui se laisserait juger une seconde fois par défaut n’est plus admis à\nformer une nouvelle opposition.\nCHAPITRE II – DE L’APPEL","[CPCN] Article 507 : L’appel tend à faire réformer ou annuler par la juridiction d’appel les\ndécisions rendues en premier ressort par les juridictions de premier degré.\nSection 1 : Du droit d’appel\nSous-section 1 : Des décisions susceptibles d’appel","[CPCN] Article 508 : La voie de l’appel est ouverte en toutes matières, même gracieuses. Les\nactes d’administration judiciaire ne sont pas susceptibles d’appel.","[CPCN] Article 509 : Les jugements qui tranchent dans leur dispositif une partie du principal et\nordonnent\n\nune\n\nmesure\n\nd’instruction\n\nou\n\nune\n\nmesure\n\nprovisoire,\n\npeuvent\n\nêtre\n\nimmédiatement frappés d’appel comme les jugements qui tranchent tout le principal. Il en\n\nest de même des jugements qui, statuant sur une exception de procédure, une fin de nonrecevoir ou tout autre incident, mettent fin à l’instance.","[CPCN] Article 510 : Les jugements avant-dire droit qui sont rendus pour l’instruction de la cause\nou qui tendent à mettre le procès en état de recevoir le jugement définitif, ne peuvent être\nfrappés d’appel indépendamment des jugements sur le fond, sauf dans les cas spécifiés\npar la loi.","[CPCN] Article 511 : Seront susceptibles d’appel les jugements qualifiés à tort en dernier ressort\npar les juges qui les ont rendus. Ne sont pas recevables les appels des jugements rendus\nen des matières dont la connaissance appartient en dernier ressort aux premiers juges,\nalors même qu’ils auraient omis de les qualifier ou qu’ils les auraient qualifiés en premier\nressort.\nSous-section 2 : Des parties à l’instance d’appel","[CPCN] Article 512 : Le droit d’appel appartient à toute partie qui y a intérêt si elle n’y a pas\nrenoncé. En matière contentieuse, l’appel ne peut être dirigé que contre ceux qui ont été\nparties en première instance; ils sont dits intimés.","[CPCN] Article 513 : Tout intimé peut relever appel incidemment, tant contre l’appelant que contre\nles autres intimés.\nToute personne, même non intimée, ayant été partie en première instance peut\négalement relever appel incidemment sur l’appel principal ou sur l’appel incident qui le\nprovoque.","[CPCN] Article 514 : L’appel incident ou l’appel provoqué peut être formé en tout état de cause,\nalors même que celui qui l’interjetterait serait forclos pour agir à titre principal.\nDans ce dernier cas, l’appel ne sera reçu que si l’appel principal est lui-même\nrecevable.","[CPCN] Article 515 : En cas de solidarité ou d’indivisibilité entre plusieurs parties, c’est-à-dire\nlorsque, dans un cas comme dans l’autre, celles-ci peuvent être contraintes chacune à\nexécuter l’obligation pour le tout, l’appel formé par l’une conserve le droit d’appel des\nautres, sauf à ces dernières à se joindre à l’instance.\nLa mise en cause de tous les cointéressés peut être ordonnée d’office par la\njuridiction d’appel.","[CPCN] Article 516 : En cas d’indivisibilité entre plusieurs parties, c’est-à-dire lorsque l’obligation\ndont celles-ci sont tenues n’est pas susceptible de fractionnement à raison de son objet,\n\nl’appel de l’une produit effet à l’égard des autres, même si elles ne se sont pas jointes à\nl’instance. L’appel formé contre l’une n’est recevable que si toutes sont appelées à\nl’instance.","[CPCN] Article 517 : Peuvent intervenir ou être appelées en cause d’appel, dès lors qu’elles y ont\nintérêt, les personnes qui n’ont été ni parties, ni représentées en première instance ou qui\ny ont figuré en une autre qualité.\nCes mêmes personnes peuvent être appelées, même aux fins de condamnation,\nquand l’évolution du litige implique leur mise en cause.","[CPCN] Article 518 : Les personnes capables de compromettre ne peuvent renoncer à l’appel que\npour les droits dont elles ont la libre disposition.\nLa renonciation à l’appel ne peut être antérieure à la naissance du litige.","[CPCN] Article 519 : La renonciation peut être expresse ou résulter de l’exécution sans réserve\nd’un jugement non exécutoire.\nLa renonciation ne vaut pas si, postérieurement, une autre partie interjette ellemême régulièrement appel.\nSous-section 3 : Du délai et de la forme d’appel","[CPCN] Article 520 : Le délai d’appel est d’un (1) mois et court, pour les jugements\ncontradictoires, à compter du prononcé de la décision et, pour les jugements réputés\ncontradictoires et par défaut, à compter de la notification de la décision.\nEn matière gracieuse, le délai d’appel est de quinze (15) jours et court à compter du\nprononcé de la décision.","[CPCN] Article 521 : Sauf les cas où la loi en dispose autrement, l’appel est formé par acte\nd’huissier.","[CPCN] Article 522 : Le délai d’appel est augmenté en raison des distances dans les conditions\nprévues à l’article 77 du présent Code.\nSection 2 : Des effets de l’appel\nSous-section 1 : De l’effet suspensif de l’appel","[CPCN] Article 523 : L’appel d’un jugement interjeté dans le délai a pour effet d’en suspendre\nl’exécution, à moins qu’il n’ait été assorti de l’exécution provisoire, qu’il ait été qualifié par\nerreur de jugement en dernier ressort, ou qu’il s’agisse des liens conjugaux dans le cadre\ndu divorce.\n80","[CPCN] Article 524 : L’exécution des jugements improprement qualifiés en dernier ressort peut\nêtre suspendue en vertu de défenses obtenues par l’appelant devant le président de la\njuridiction d’appel.","[CPCN] Article 525 : Le président de la juridiction d’appel peut pareillement suspendre l’exécution\ndu jugement si celle-ci a été ordonnée à titre provisoire hors les cas et les conditions\nprévus par la loi.\nIl est saisi par requête suivie d’une assignation à bref délai ou d’heure à heure, même si la\ndécision a été frappée d’appel. Il statue en la forme des référés.","[CPCN] Article 526 : Les poursuites qui seraient exercées postérieurement à l’appel sont nulles et\npeuvent motiver une condamnation à des dommages-intérêts contre celui qui les exerce.\nSous-section 2 : De l’effet dévolutif de l’appel","[CPCN] Article 527 : L’appel remet la chose jugée en question devant la juridiction du second\ndegré pour qu’il soit à nouveau statué en fait et en droit.","[CPCN] Article 528 : L’appel ne défère à la juridiction d’appel que la connaissance des chefs de\njugement qu’il critique expressément ou implicitement et de ceux qui en dépendent.\nLa dévolution s’opère pour le tout lorsque l’appel n’est pas limité à certains chefs,\nlorsqu’il tend à l’annulation du jugement ou si l’objet du litige est indivisible.","[CPCN] Article 529 : Pour justifier en appel les prétentions qu’elles avaient soumises au premier\njuge, les parties peuvent invoquer des moyens nouveaux, produire de nouvelles pièces ou\nproposer de nouvelles preuves.","[CPCN] Article 530 : Il ne peut être formé en cause d’appel aucune demande nouvelle, à moins\nqu’il ne s’agisse de compensation ou que la demande nouvelle ne tende à faire écarter les\nprétentions adverses ou à faire juger les questions nées de l’intervention d’un tiers ou de\nla révélation d’un fait.","[CPCN] Article 531 : La demande n’est pas nouvelle, dès lors qu’elle tend aux mêmes fins que\ncelle soumise au premier juge même si son fondement juridique est différent de celui des\nprétentions initiales.","[CPCN] Article 532 : Les parties peuvent aussi expliciter les prétentions qui étaient virtuellement\ncomprises dans la demande soumise au premier juge, ajouter à celle-ci les demandes qui\nen sont l’accessoire, la conséquence ou le complément, c’est-à-dire les intérêts,\narrérages, les loyers et autres accessoires, échus depuis la décision de première instance,\net les dommages-intérêts pour le préjudice souffert depuis cette décision.\n\nSous-section 3 : De l’évocation","[CPCN] Article 533 : Lorsque la juridiction d’appel est saisie d’un jugement qui a ordonné une\nmesure d’instruction ou d’une décision qui, statuant sur une exception de procédure, a mis\nfin à l’instance, elle peut évoquer les points non jugés si elle estime de bonne justice de\ndonner à l’affaire une solution définitive après avoir ordonné elle-même, le cas échéant,\ntoute mesure d’instruction utile. L’évocation ne fait pas obstacle à l’application des articles\n517, 529 à 532 de la présente loi.\nSection 3 : De la procédure devant la juridiction d’appel","[CPCN] Article 534 : Sauf dispositions contraires édictées par la loi pour certaines matières et\nsous réserve des dispositions du présent titre, la procédure d’appel est la même que la\nprocédure devant le tribunal de grande instance.\nSous-section 1 : De la procédure en matière contentieuse","[CPCN] Article 535 : Sauf dispositions légales contraires, l’appel est formé par acte d’huissier\nsignifié à l’intimé et déposé au greffe de la juridiction d’appel.\nL’acte d’appel indique :\n-\n\nles nom, prénoms et domicile de l’appelant ;\n\n-\n\nle nom du conseil constitué, s’il y a lieu ;\n\n-\n\nla date de la décision attaquée ;\n\n-\n\nles nom, prénoms et adresse de la partie contre laquelle l’appel est formé ;\n\n-\n\nles chefs de jugement auxquels l’appel est limité et les moyens d’appel.\n\nLe greffier enregistre l’acte d’appel.","[CPCN] Article 536 : L’appel est réputé formé au jour de l’établissement de l’acte d’appel par\nl’huissier qui doit le déposer au greffe de la cour dans les deux (2) mois de la signification\nsous peine de caducité.","[CPCN] Article 537 : Dans tous les cas, l’acte d’appel est enregistré sur un registre par le greffier\nde la juridiction d’appel qui procède à l’enrôlement.","[CPCN] Article 538 : L’appel incident, même provoqué, et l’intervention en cause d’appel sont\nformés par conclusions. Ils le sont par voie d’assignation contre les personnes qui ne sont\npas représentées ; les mises en cause sont faites par assignation.\n\nL’auteur de l’acte doit indiquer les moyens qu’il invoque et les pièces dont il entend\nfaire état ; l’acte est dénoncé à toutes les parties en cause; une copie est déposée au\ngreffe pour être versée au dossier.","[CPCN] Article 539 : Au jour fixé, l’affaire est appelée à l’audience devant le Président de la Cour\nou le juge qu’il délègue, qui confère de l’état de la cause avec les parties présentes ou\nleurs conseils.\nSi le Président estime, au vu du dossier, des explications et des conclusions des\nparties, que le dossier est en état d’être jugé, il renvoie l’affaire à une audience de\nplaidoirie.\nToutes les autres affaires sont renvoyées devant le conseiller de la mise en état\npour instruction.","[CPCN] Article 540 : Quelle que soit la matière, et sous réserve des règles édictées aux articles\nci-après, l’affaire est instruite et mise en état d’être jugée sous le contrôle du conseiller de\nla mise en état suivant les règles établies pour les tribunaux de grande instance.","[CPCN] Article 541 : Les ordonnances du conseiller de la mise en état ne sont susceptibles\nd’aucun recours indépendamment de l’arrêt sur le fond. Toutefois, elles peuvent être\ndéférées par simple requête à la Cour dans les quinze jours de leur date, lorsqu’elles\nconstatent l’extinction de l’instance.","[CPCN] Article 542 : En cas d’appel d’un jugement rendu sur la compétence ou qui ordonne une\nmesure d’instruction préjugeant le fond, ou une mesure provisoire, l’appel est instruit\nsuivant la procédure abrégée sans mise en état.\nLa juridiction d’appel doit statuer au plus tard dans le mois de la saisine.","[CPCN] Article 543 : En toutes matières, si les droits de l’une quelconque des parties sont en\npéril, le président de la juridiction d’appel peut, sur requête, décider que la cause sera\njugée à jour fixe.\nLa requête doit exposer la nature du péril, contenir les conclusions au fond et viser\nles pièces justificatives.\nLe président fixe par ordonnance le jour et l’heure auxquels l’affaire sera appelée et\nautorise l’assignation de l’intimé.\nL’ordonnance avec copie de la requête est signifiée sans délai à l’intimé. Celui-ci\nest invité à prendre connaissance au greffe des pièces visées à la requête et sommé de\ncommuniquer et de déposer ses conclusions avant la date de l’audience.\n\n83","[CPCN] Article 544 : Le jour de l’audience, le Président doit s’assurer qu’il s’est écoulé un temps\nsuffisant depuis l’assignation pour que l’intimé ait pu préparer sa défense. Dans le cas\ncontraire, il ordonnera sa réassignation.\nSi l’intimé assigné à personne ou à domicile élu ne comparaît pas ou n’est pas\nreprésenté, l’affaire sera jugée dans l’état où elle se trouve. La cour statue par arrêt\ncontradictoire en se fondant, au besoin sur les moyens de première instance.\nEn cas de nécessité, le président peut renvoyer l’affaire devant le conseiller de la\nmise en état.","[CPCN] Article 545 : En cas d’appel principal dilatoire ou abusif, l’appelant peut, par une\ndisposition spécialement motivée, être condamné à une amende civile de cinquante mille\n(50.000) à deux cent mille (200.000) francs CFA sans préjudice des dommages-intérêts\nqui lui seraient réclamés.\nCette amende, perçue séparément des droits d’enregistrement,\n\nne peut être\n\nréclamée aux intimés. Ceux-ci peuvent obtenir une expédition de la décision revêtue de la\nformule exécutoire, sans que le non-paiement de l’amende puisse y faire obstacle.","[CPCN] Article 546 : La péremption en cause d’appel confère au jugement force de chose jugée,\nmême s’il n’a pas été signifié.\nSous-section 2 : De la procédure gracieuse","[CPCN] Article 547 : L’appel des décisions rendues en matière gracieuse est formé par simple\nrequête.","[CPCN] Article 548 : La Cour est saisie par la remise au greffe dans le délai d’appel, de la requête\nqui peut être signée par un conseil.\nL’appel est instruit et jugé selon les règles applicables devant le tribunal de grande\ninstance en matière gracieuse.\nSection 4 : De la constitution et de la conservation du dossier","[CPCN] Article 549 : Il est constitué pour chaque affaire un dossier sur lequel sont portées les\nmentions prévues par l’article 445 de la présente loi.\nSont déposés dans ce dossier :\n-\n\nl’original de l’acte d’appel ;\n\n-\n\nl’expédition de la décision attaquée ;\n\n-\n\ntoutes les conclusions déposées par les conseils ou les mémoires des parties ;\n\n-\n\nla copie des décisions prises par le conseiller de la mise en état et des procèsverbaux ou rapports dressés en exécution de ces décisions ;\n\n-\n\nla copie des arrêts successivement rendus par la Cour.\n\nLe greffier doit au verso de la première page dresser l’inventaire des pièces du\ndossier avec leur numéro d’ordre et date d’entrée.\nLe dossier est conservé au greffe de la juridiction qui a statué pendant dix années à\npartir du prononcé de la décision.\nSi l’affaire est l’objet d’un pourvoi en cassation, le greffier de la Cour d’Appel\ntransmet le dossier au greffier en chef de la Cour de Cassation dans le délai d’un (1) mois.\nTITRE III – DES VOIES EXTRAORDINAIRES DE RECOURS\nCHAPITRE PREMIER – DE LA TIERCE OPPOSITION","[CPCN] Article 550 : La tierce opposition tend à faire rétracter un jugement qui préjudicie aux\ndroits d’une personne qui n’y a pas été partie. Elle est ouverte à tous les tiers, lorsque ni\neux, ni leurs auteurs ou ceux qu’ils représentent n’ont été appelés au procès.","[CPCN] Article 551 : Il appartient au juge du fond d’apprécier si un jugement préjudicie ou non aux\ndroits du tiers opposant.","[CPCN] Article 552 : La tierce opposition principale est portée devant la juridiction qui a rendu le\njugement attaqué, suivant les règles établies pour l’introduction des instances.\nLa décision peut être rendue par les mêmes magistrats.","[CPCN] Article 553 : La tierce opposition incidente à une contestation dont est saisie une\njuridiction est tranchée par cette dernière si elle est de degré supérieur à celle qui a rendu\nle jugement ou si, étant d’égal degré, aucune règle de compétence d’ordre public n’y fait\nobstacle. La tierce opposition est alors formée de la même manière que les demandes\nincidentes.\nDans les autres cas, la tierce opposition incidente est portée, par voie de demande\nprincipale, devant la juridiction qui a rendu le jugement.","[CPCN] Article 554 : La juridiction devant laquelle le jugement attaqué est produit peut, suivant\nles circonstances, passer outre ou surseoir.","[CPCN] Article 555 : La tierce opposition principale est recevable dans un délai de trente (30) ans\nà compter du jugement à moins que la loi n’en dispose autrement. Elle cesse cependant\n\nd’être recevable lorsque celui qui a intérêt à la former a exécuté le jugement ou l’a ratifié\nimplicitement.","[CPCN] Article 556 : Le juge saisi de la tierce opposition peut, suivant les circonstances,\nsuspendre l’exécution du jugement frappé de tierce opposition. Le sursis à exécution n’est\npas de plein droit.","[CPCN] Article 557 : Le jugement qui fait droit à la tierce opposition ne profite qu’au tiers opposant\n; il n’en est autrement que si la matière est indivisible.\nLe jugement rendu sur tierce opposition est susceptible des mêmes recours que les\ndécisions de la juridiction dont il émane.","[CPCN] Article 558 : Le tiers opposant qui succombe peut être condamné à une amende civile de\ncinq mille (5.000) à cinquante mille (50.000) francs CFA sans préjudice des dommagesintérêts s’il y a lieu.\nCHAPITRE II – DU RECOURS EN RÉVISION","[CPCN] Article 559 : Le recours en révision tend à faire rétracter une décision passée en force de\nchose jugée pour qu’il soit à nouveau statué en fait et en droit.","[CPCN] Article 560 : La révision ne peut être demandée que par les personnes qui ont été parties\nou représentées au jugement.","[CPCN] Article 561 : Le recours en révision n’est ouvert que pour l’une des causes ci-après :\n1°) s’il y a eu fraude de l’une des parties de nature à avoir déterminé la conviction\ndu juge;\n2°) s’il a été jugé sur des pièces reconnues ou judiciairement déclarées fausses\ndepuis le jugement;\n3°) si depuis le jugement il a été retrouvé des pièces décisives qui avaient été\nretenues par le fait de l’une des parties ;\n4°) s’il a été jugé sur des attestations, témoignages ou serments judiciairement\ndéclarés faux depuis le jugement.","[CPCN] Article 562 : Dans tous les cas, le recours n’est recevable que si son auteur n’a pu, sans\nfaute de sa part, faire valoir la cause qu’il invoque avant que la décision ne soit passée en\nforce de chose jugée.","[CPCN] Article 563 : Le délai de recours en révision est de deux (2) mois à compter du jour où la\npartie a eu connaissance de la cause de révision qu’elle invoque.\n86","[CPCN] Article 564 : Le recours est porté devant la même juridiction où la décision attaquée a été\nrendue ; il peut y être statué par les mêmes juges.","[CPCN] Article 565 : Toutes les parties au jugement attaqué doivent être appelées à l’instance en\nrévision par l’auteur du recours à peine d’irrecevabilité.","[CPCN] Article 566 : Le recours en révision est formé par citation.\nToutefois, si le recours est dirigé contre un jugement produit au cours d’une autre\ninstance, entre les mêmes parties et devant la même juridiction, la révision est demandée\nsuivant les formes prévues pour la présentation des moyens de défense.","[CPCN] Article 567 : La procédure se déroule selon celle prévue pour le procès ordinaire. Le\nrecours en révision est communiqué au ministère public.","[CPCN] Article 568 : Aucun moyen autre que les moyens d’ouverture énoncés dans le recours\nn’est discuté à l’audience ou par conclusions écrites.","[CPCN] Article 569 : Si une partie s’est pourvue ou déclare se pourvoir en révision contre un\njugement produit dans une instance pendante, devant une juridiction autre que celle qui l’a\nrendu, la juridiction saisie de la cause dans laquelle ce jugement est produit, peut, suivant\nles circonstances, passer outre ou surseoir jusqu’à ce que le recours en révision ait été\njugé par la juridiction compétente.","[CPCN] Article 570 : Si le juge déclare le recours recevable, il statue par le même jugement sur le\nfond du litige, sauf s’il y a lieu à complément d’instruction.","[CPCN] Article 571 : Si la révision n’est justifiée que contre un chef de jugement, ce chef est seul\nrévisé à moins que les autres n’en dépendent.","[CPCN] Article 572 : La décision rendue sur une action en révision est susceptible des mêmes\nvoies de recours que les décisions rendues par la juridiction qui l’a prononcée.","[CPCN] Article 573 : Le jugement qui rejette le recours peut condamner son auteur à une amende\ncivile de cinq mille (5 000) à cinquante mille (50 000) francs CFA, sans préjudice de\ndommages-intérêts à la partie adverse s’il y a lieu.","[CPCN] Article 574 : Aucune partie ne peut se pourvoir en révision contre un jugement déjà\nattaqué par cette voie, si ce n’est pour une cause qui se serait révélée postérieurement.\nCHAPITRE III – DU POURVOI EN CASSATION\n\nSection 1 : De l’ouverture du pourvoi en cassation\n87","[CPCN] Article 575 : Le pourvoi en cassation tend à faire censurer, par la Cour de Cassation, la\nnon conformité aux règles de droit de la décision qu’il attaque.","[CPCN] Article 576 : Le pourvoi en cassation n’est ouvert qu’à l’encontre des jugements rendus\nen dernier ressort.","[CPCN] Article 577 : Les jugements en dernier ressort qui tranchent dans leur dispositif une partie\ndu principal, et ordonnent une mesure d’instruction ou une mesure provisoire, peuvent être\nfrappés de pourvoi en cassation comme les jugements qui tranchent en dernier ressort\ntout le principal.","[CPCN] Article 578 : Peuvent également être frappés de pourvoi en cassation les jugements en\ndernier ressort qui statuent sur une exception de procédure, une fin de non-recevoir ou\ntout autre incident, mettant fin à l’instance.","[CPCN] Article 579 : Les autres jugements en dernier ressort ne peuvent être frappés de pourvoi\nen cassation indépendamment des jugements sur le fond que dans les cas spécifiés par la\nloi.","[CPCN] Article 580 : La recevabilité du pourvoi incident obéit aux règles qui gouvernent celles de\nl’appel incident prévues à l’article 538 du présent Code.","[CPCN] Article 581 : En cas d’indivisibilité à l’égard de plusieurs parties, le pourvoi de l’une produit\neffet à l’égard des autres même si celles-ci ne sont pas jointes à l’instance de cassation.\nDans le même cas, le pourvoi formé contre l’une n’est recevable que si toutes sont\nappelées à l’instance.","[CPCN] Article 582 : La contrariété de jugements peut être invoquée lorsque la fin de non-recevoir\ntirée de l’autorité de la chose jugée a en vain été opposée devant les juges du fond.\nEn ce cas, le pourvoi en cassation est dirigé contre le jugement second en date.\nLorsque la contrariété est constatée, elle se résout au profit du premier.","[CPCN] Article 583 : La contrariété de jugements peut aussi être invoquée, lorsque deux\ndécisions, même non rendues en dernier ressort, sont inconciliables et qu’aucune d’elles\nn’est susceptible d’un recours ordinaire. Le pourvoi en cassation est alors recevable,\nmême si l’une des décisions avait déjà été frappée d’un pourvoi en cassation, et que celuici avait été rejeté.\nEn cas de contrariété de jugements, le pourvoi peut être formé après l’expiration du\ndélai. Il doit être dirigé contre les deux décisions. Lorsque la contrariété est constatée, la\nCour de Cassation annule l’une des décisions ou, s’il y a lieu, les deux.\n\nSection 2 : De la procédure du pourvoi en matière civile,\ncommerciale et sociale\nSous-section 1 : De l’introduction du pourvoi","[CPCN] Article 584 : Le pourvoi est déposé au greffe de la juridiction qui a rendu la décision\nattaquée. Il est inscrit à son arrivée sur un registre d’ordre tenu par le greffier en chef de\ncette juridiction. Il est ensuite marqué ainsi que les pièces qui y sont jointes, d’un timbre\nindiquant la date de l’arrivée.","[CPCN] Article 585 : Sous peine d’irrecevabilité, le pourvoi est formé par requête écrite et signée\npar la partie, un conseil ou un fondé de pouvoir spécial, dans un délai d’un (1) mois à\ncompter du jour de la signification de la décision lorsque cette signification a été faite à\npersonne ou à domicile et du jour où l’opposition n’est plus recevable, lorsqu’il s’agit d’un\njugement de défaut.\nLa requête, préalablement affranchie d’un timbre de mille cinq cents (1.500) francs\nCFA, doit :\n1. indiquer les noms, profession et domicile des parties et, s’il s’agit d’une\npersonne morale, outre ses éléments d’identification, le nom de son\nreprésentant es qualité ;\n2. contenir un exposé des faits et un énoncé des moyens de droit invoqués contre\nla décision attaquée.\nLa signature de la requête par un conseil vaut constitution et élection de domicile à\nson étude.","[CPCN] Article 586 : Dans un délai d’un mois au plus tard à compter de la date du dépôt de la\nrequête, le greffier en chef de la juridiction qui a rendu la décision attaquée adresse au\ngreffier en chef de la Cour de Cassation :\n-\n\nla requête ainsi que les pièces qui y sont jointes ;\n\n-\n\nune expédition de la décision attaquée.\n\nLe greffier en chef de la Cour de Cassation enregistre à l’arrivée la requête et les\nautres pièces sur un registre d’ordre.","[CPCN] Article 587 : À peine de déchéance, le demandeur au pourvoi est tenu, dans un délai d’un\n(1) mois à compter du dépôt du pourvoi, de signifier sa requête au défendeur par un acte\nextra- judiciaire contenant élection de domicile.\n\nLe greffier qui reçoit un pourvoi est tenu de notifier par écrit cette obligation au\ndemandeur au pourvoi.\nLa déchéance n’est acquise que si cette formalité a été accomplie.\nSous-section 2 : De l’effet du pourvoi","[CPCN] Article 588 : Le pourvoi n’est suspensif que dans les cas suivants :\n1. en matière d’état des personnes ;\n2. quand il y a faux incident ;\n3. en matière d’immatriculation foncière ou lorsque l’acquisition ou le transfert de\nl’immeuble aura été constaté par un mode de preuve établi par la loi ;\n4. lorsqu’une disposition de la loi le prévoit ;\n5. lorsque le quantum de la condamnation est supérieur à vingt-cinq millions\n(25.000.000) de francs CFA.","[CPCN] Article 589 : Toutefois, la Chambre Civile et Commerciale ou la Chambre Sociale et des\nAffaires Coutumières de la Cour de Cassation, saisie d’un pourvoi, peut, sur requête du\ndemandeur au pourvoi, décider qu’il sera sursis à l’exécution de la décision attaquée :\n1. lorsque, saisie d’un pourvoi par l’État ou ses démembrements, elle constate que\nl’exécution de l’arrêt ou du jugement attaqué peut provoquer un préjudice\ndifficilement réparable ;\n2. lorsque, saisie d’un pourvoi par toutes parties autres que celles énumérées cidessus, elle constate que l’exécution de l’arrêt attaqué peut provoquer un\npréjudice difficilement réparable et que les moyens invoqués à l’encontre de la\ndécision attaquée paraissent sérieux en l’état de la procédure.","[CPCN] Article 590 : La requête prévue à l’article précèdent doit être signifiée par un acte\nextrajudiciaire aux parties adverses.\nCette signification doit en outre indiquer l’avis donné aux parties adverses qu’elles\ndisposent d’un délai de huit (8) jours pour déposer leurs observations au greffe de la Cour.","[CPCN] Article 591 : Si la requête aux fins de sursis à exécution est formulée par un demandeur\nau pourvoi autre que l’État ou ses démembrements, elle doit à peine d’irrecevabilité être\nassortie d’une offre de constitution de garantie.","[CPCN] Article 592 : La signification aux parties adverses de la requête aux fins de sursis à\nexécution avec constitution de garantie, suspend l’exécution de la décision attaquée\njusqu’à ce qu’il ait été statué sur ladite requête.\n90","[CPCN] Article 593 : Le sursis à l’exécution de la décision attaquée est ordonné par arrêt rendu\nen audience publique sur rapport d’un conseiller.\nLa Cour ordonne le cas échéant par le même arrêt, la constitution par le demandeur\nau pourvoi, d’une garantie suffisante dont elle fixe souverainement les modalités et le\nmontant.\nLe paiement des sommes représentant la garantie visée à l’alinéa précédent est\neffectué au Trésor Public.","[CPCN] Article 594 : Les dispositions des articles 584, 603, 605, 606 et 607 de la présente loi sont\napplicables aux requêtes aux fins de sursis à exécution.\nSection 3 : De l’instruction du pourvoi","[CPCN] Article 595 : Le défendeur au pourvoi doit transmettre au greffier en chef de la Cour,\naccompagné d’autant de copies qu’il y a de parties en cause, un mémoire en défense\nsigné par lui-même ou par un conseil ou par un fondé de pouvoir spécial, dans le mois qui\nsuit la signification de la requête.\nLa signature du conseil vaut constitution et élection de domicile à son étude.\nAprès une mise en demeure notifiée par écrit par le greffier en chef pour produire le\nmémoire dans un délai supplémentaire de quinze (15) jours, le défendeur défaillant est\ncensé avoir acquiescé la thèse du demandeur. Tout mémoire produit après ce délai est\nirrecevable et la procédure se fait sur la base du seul mémoire du demandeur.\nLe greffier en chef constate, s’il y a lieu, par un certificat, la non-production du\nmémoire en défense dans le délai prévu à l’alinéa ler ci-dessus et transmet le dossier de\nla procédure au président de la chambre concernée pour désignation d’un rapporteur.","[CPCN] Article 596 : Si le défendeur produit son mémoire dans le délai fixé, le greffier en chef de\nla Cour de Cassation en adresse copie aux autres parties en cause et les avertit qu’elles\nont un délai d’un (1) mois pour déposer au greffe leurs mémoires en réplique en autant\nd’exemplaires qu’il y a de parties en cause.","[CPCN] Article 597 : Dès réception des mémoires en réplique prévus à l’article précédent, le\ngreffier en chef de la Cour de Cassation en adresse copies aux autres parties en cause\nqui peuvent à leur tour déposer un mémoire en duplique.","[CPCN] Article 598 : À l’expiration d’un nouveau et dernier délai d’un (1) mois, à compter du dépôt\nau greffe du mémoire en duplique, le greffier en chef de la Cour de Cassation, après avoir\n\nfait coter et parapher toutes les pièces, transmet au président de la chambre concernée, le\ndossier de Cassation qui comprend :\n-\n\nune expédition de la décision attaquée ;\n\n-\n\nla requête et les mémoires déposés par les parties avec les actes qui y sont\njoints ou à défaut le certificat de non dépôt de mémoire.","[CPCN] Article 599 : Dès réception du dossier de Cassation, le président de la chambre\nconcernée désigne par ordonnance un conseiller rapporteur et lui impartit un délai pour\ndéposer son rapport. Ce délai est déterminé par le règlement intérieur de la Cour.\nLe conseiller rapporteur vérifie si le pourvoi est en état d’être jugé. Dans le cas où le\ndossier se révèlerait incomplet, il enjoint aux parties en cause de déposer au greffe dans\nun délai qu’il fixe, les mémoires complémentaires, les pièces et les documents qu’il juge\nutiles.\nLes parties ou leurs conseils peuvent prendre connaissance au greffe, sans\ndéplacement, des pièces du dossier.","[CPCN] Article 600 : Lorsqu’il estime le dossier en état, le conseiller commis rédige et dépose son\nrapport au greffe de la Cour.\nAucun mémoire ne peut être produit après le dépôt du rapport au greffe.","[CPCN] Article 601 : Dès réception du rapport, le greffier en chef transmet au Procureur Général\ntoutes les pièces de la procédure.","[CPCN] Article 602 : Dans les trente (30) jours qui suivent la réception des pièces de la\nprocédure, le Procureur Général retourne le dossier au greffe avec ses conclusions.","[CPCN] Article 603 : Le Président de la chambre fixe alors la date de l’audience à laquelle l’affaire\nsera appelée et jugée sur pièces, à moins que les parties n’aient déclaré formellement\nqu’elles entendent présenter ou faire présenter par un conseil des observations orales.","[CPCN] Article 604 : La chambre doit statuer en urgence et en priorité lorsque le pourvoi est\nformé contre un arrêt de la Cour d’Appel ayant statué en matière de référé.\n\nCHAPITRE IV – DE LA SAISINE DES CHAMBRES RÉUNIES ET DE\nL’INSTRUCTION DU POURVOI\n\nSection 1 : De la saisine\n\n92","[CPCN] Article 605 : Les chambres réunies sont saisies par ordonnance du premier Président de\nla Cour de Cassation rendue soit sur réquisition du Procureur Général près cette\njuridiction, soit sur la base d’un arrêt de renvoi rendu par une de ses chambres saisie :\n1. lorsqu’après Cassation d’un premier arrêt ou jugement, la décision rendue par la\njuridiction de renvoi est attaquée par les mêmes moyens que ceux qui avaient\nentraîné la Cassation ;\n2. lorsqu’après Cassation d’un deuxième arrêt ou jugement, la décision rendue par\nla juridiction de renvoi est attaquée quels que soient les moyens invoqués ;\n3. lorsqu’une affaire soumise à la Cour est susceptible de relever de la\ncompétence de plusieurs chambres ;\n4. lorsqu’un point de droit soumis à l’appréciation de la Cour pose une question de\nprincipe ;\n5. lorsqu’après un premier renvoi, la juridiction saisie ne se conforme pas au point\nde droit tranché, la chambre saisie à nouveau ordonne le renvoi du dossier de la\nprocédure devant les chambres réunies ;\n6. lorsqu’une disposition légale le prévoit.\n\nSection 2 : De l’instruction du recours","[CPCN] Article 606 : Le dossier de procédure est transmis par le Président de la chambre saisie\nou le Procureur Général, ensemble avec une expédition de l’arrêt de renvoi ou le\nréquisitoire aux fins de renvoi au premier Président de la Cour de Cassation à l’effet de\nsaisir les chambres réunies.","[CPCN] Article 607 : À la réception du dossier de la procédure, le premier Président de la Cour de\nCassation désigne par ordonnance un conseiller pour faire le rapport.\nIl est procédé par la suite, conformément aux dispositions des articles 599 alinéa 2,\n600 à 604 ci-dessus, relatives à l’instruction des pourvois en cassation.\nCHAPITRE V – DES PROCÉDURES SPÉCIALES\n\nSection 1 : Des règlements de juges","[CPCN] Article 608 : La requête en règlement de juges est déposée au greffe de la Cour de\nCassation par la partie intéressée. Elle est inscrite à son arrivée sur le registre d’ordre\ntenu par le greffier en chef. Elle est en outre marquée ainsi que les pièces qui y sont\njointes, d’un timbre indiquant la date de l’arrivée.\n\nLe greffier en chef avise immédiatement les parties en cause ainsi que les greffiers\ndes juridictions entre lesquelles il sera réglé de juges.\nLes dossiers de procédures sont, sous huitaine, adressés par les greffiers en chef des\njuridictions, dont il est fait règlement de juges, au greffier en chef de la Cour de Cassation\nqui les transmet dès réception au Président de la Chambre Civile, lequel commet un\nconseiller rapporteur.\nSection 2 : Du renvoi d’un tribunal à un autre","[CPCN] Article 609 : La requête aux fins de renvoi d’un tribunal à un autre est déposée et\nenregistrée au greffe de la Cour de Cassation dans les conditions prévues à l’alinéa 1er\nde l’article précèdent.\nDans un délai de trente (30) jours suivant la date du dépôt de cette requête, le\nProcureur Général doit la faire signifier aux parties en cause, lesquelles disposent\négalement du même délai pour déposer leurs mémoires au greffe de la Cour.\nDès réception des mémoires prévus à l’alinéa précédent ou à l’expiration du délai\nimparti, le greffier en chef transmet le dossier au Président de la Chambre criminelle qui\ncommet un conseiller rapporteur.\nIl est ensuite procédé comme il est dit aux articles 600 à 604 ci-dessus.\nSection 3 : De la récusation et de l’abstention","[CPCN] Article 610 : La demande en récusation d’un conseiller à la Cour de Cassation doit être\nmotivée et adressée au premier Président de la Cour qui statue par ordonnance, laquelle\nn’est susceptible d’aucune voie de recours.\nLe membre de la Cour qui suppose en sa personne une cause de récusation ou estime en\nconscience devoir s’abstenir se fait remplacer par un autre que désigne le premier\nPrésident.\nCHAPITRE VI – DES PRISES À PARTIE CONTRE UN JUGE, UNE JURIDICTION\nOU UNE DE SES FORMATIONS","[CPCN] Article 611 : La Chambre Civile et commerciale est saisie par voie de requête déposée et\nenregistrée au greffe de la Cour de Cassation dans les conditions définies à l’article 608\nci-dessus.\nCette requête est transmise sans délai au Président de la chambre qui commet un\nconseiller rapporteur. Les règles du présent Code sont applicables.\n\nL’État est civilement responsable des faits ayant motivé la prise à partie, sauf son\nrecours contre les juges.\nCHAPITRE VII – DES CONTRARIÉTÉS DE JUGEMENTS","[CPCN] Article 612 : En cas de contrariété de jugements, la saisine de la chambre civile et\ncommerciale est opérée par requête déposée et enregistrée au greffe de la Cour de\nCassation dans les conditions définies à l’article 608, alinéa 1er ci-dessus.\nLe recours peut être formé sans condition de délai.","[CPCN] Article 613 : La demande en inscription de faux contre une pièce produite devant une\nchambre de la Cour de Cassation est formée par requête déposée au greffe de ladite\nCour. Elle est transmise sans délai au Président de la chambre ayant en charge le\ndossier.\nElle ne peut être examinée que si elle est affranchie d’un timbre de dix mille\n(10.000) francs CFA.\nUne copie de la requête est transmise sans délai au Procureur Général pour ses\nobservations écrites.","[CPCN] Article 614 : Le président rend, soit une ordonnance de rejet, soit une ordonnance portant\npermission de s’inscrire en faux.","[CPCN] Article 615 : L’ordonnance portant autorisation de s’inscrire en faux et la requête y\nafférente sont notifiées par les soins du greffier en chef de la Cour de Cassation au\ndéfendeur à l’incident dans un délai de quinze (15) jours avec sommation d’avoir à\ndéclarer dans le délai prévu à l’alinéa ci-dessous s’il entend se servir de la pièce arguée\nde faux.\nLe défendeur doit répondre dans un délai de quinze (15) jours, faute de quoi la\npièce est écartée des débats, après avis du procureur général.\nLa pièce est également écartée et retirée du dossier, après avis du procureur\ngénéral, si la réponse est négative.\nDans le cas d’une réponse affirmative, celle-ci est portée dans le délai de quinze\n(15) jours à la connaissance du demandeur à l’incident.\nLa chambre saisie de l’instance peut, dans le cas visé à l’alinéa précédent, soit\nsurseoir à statuer et renvoyer alors les parties à se pourvoir devant telle juridiction qu’elle\n\ndésignera pour y procéder suivant la loi au jugement du faux, soit passer outre si elle\nconstate que la décision ne dépend pas de la pièce arguée de faux.\nCHAPITRE VIII – DE L’INTERVENTION","[CPCN] Article 616 : L’intervention est admise de la part de ceux qui ont intérêt au règlement du\nlitige, conformément aux règles du code de procédure civile.\nElle est formée par une requête distincte, déposée au greffe de la Cour de\nCassation et enregistrée dans les conditions de l’article 584, alinéa 1er du présent Code.\nLe greffier en chef transmet sans délai la requête au président de la chambre ayant\nle dossier en charge. Celui-ci, par les soins du greffier en chef, fait notifier ladite requête\naux parties en cause pour y répondre dans un délai qu’il fixe.\nCHAPITRE IX – DU POURVOI DANS L’INTÉRÊT DE LA LOI","[CPCN] Article 617 : Le pourvoi dans l’intérêt de la loi est formé par le Procureur Général près la\nCour de Cassation lorsqu’il a été rendu en toutes matières et en dernier ressort une\ndécision contraire à la loi et contre laquelle aucune des parties n’a cependant formulé de\nréclamation ou l’a fait hors délai. Il en saisit la chambre compétente de la Cour de\nCassation par voie de réquisitions ou de conclusions.\nEn cas de Cassation, les parties ne peuvent s’en prévaloir pour éluder les\ndispositions de la décision cassée, laquelle vaut transaction pour elles.","[CPCN] Article 618 : Les règles de procédure relatives à l’instruction des pourvois, édictées par la\nprésente loi, sont applicables aux pourvois visés à l’article précédent.\nCHAPITRE X – DU POURVOI INCIDENT","[CPCN] Article 619 : Le pourvoi incident doit, à peine d’irrecevabilité prononcée d’office, être fait\nsous forme de mémoire et contenir les mêmes indications que la requête du demandeur.\nLe mémoire doit, sous la même sanction :\n-\n\nêtre remis au greffe de la Cour de Cassation avant l’expiration du délai prévu\npour la remise du mémoire en défense ;\n\n-\n\nêtre notifié dans le même délai aux autres parties au pourvoi incident.\n\nLe défendeur à un tel pourvoi dispose d’un délai d’un mois, à compter de la\nnotification, pour transmettre son mémoire au greffier en chef de la Cour.\n\nCHAPITRE XI – DU JUGEMENT DU POURVOI","[CPCN] Article 620 : Les moyens nouveaux ne sont pas recevables devant la Cour de Cassation.\nPeuvent néanmoins être invoqués pour la première fois, sauf dispositions\ncontraires :\n1. les moyens de pur droit ;\n2. les moyens nés de la décision attaquée.","[CPCN] Article 621 : La Cour de Cassation peut rejeter le pourvoi en substituant un motif de pur\ndroit à un motif erroné. Elle le peut également en faisant abstraction d’un motif de droit\nerroné. Elle peut également rejeter le pourvoi en faisant abstraction d’un motif de droit\nerroné mais surabondant.\nElle peut, sauf dispositions contraires, casser la décision attaquée relavant d’office\nun moyen de pur droit.","[CPCN] Article 622 : Si le pourvoi en cassation est rejeté, la partie qui l’a formé n’est plus\nrecevable à en former un nouveau contre le même jugement, hors le cas prévu à l’article\n583 de la présente loi.\nIl en est de même lorsque la Cour de Cassation constate son dessaisissement,\ndéclare le pourvoir irrecevable ou prononce la déchéance.\nLIVRE IV : DES VOIES D’EXÉCUTION","[CPCN] Article 623 : Les dispositions relatives au présent livre sont celles prévues par l’Acte\nUniforme de l’Organisation pour l’Harmonisation en Afrique du Droit des Affaires\n(OHADA), portant organisation des procédures simplifiées de recouvrement et des voies\nd’exécution.\nLIVRE V : DES PROCÉDURES DIVERSES\nTITRE PREMIER – DE LA PROCÉDURE SIMPLIFIÉE DE RECOUVREMENT\nDE CRÉANCES : L’INJONCTION DE PAYER","[CPCN] Article 624 : Les dispositions relatives au présent titre sont celles prévues par l’Acte\nUniforme de l’Organisation pour l’Harmonisation en Afrique du Droit des Affaires\n(OHADA), portant organisation des procédures simplifiées de recouvrement de créances\net des voies d’exécution.\n\nTITRE II – DE LA PROCÉDURE SIMPLIFIÉE TENDANT À LA DÉLIVRANCE OU\nÀ LA RESTITUTION D’UN MEUBLE DÉTERMINÉ","[CPCN] Article 625 : Les dispositions relatives au présent titre sont celles prévues par l’Acte\nuniforme de l’Organisation pour l’Harmonisation en Afrique du Droit des Affaires (OHADA),\nportant organisation des procédures simplifiées de recouvrement de créances et des voies\nd’exécution.\nTITRE III – DES OFFRES DE PAIEMENT ET DE CONSIGNATION","[CPCN] Article 626 : Les offres sont faites par procès-verbal dressé par huissier qui précise l’objet\noffert et la réponse faite. Si le créancier refuse les offres, le débiteur peut pour se libérer,\nconsigner la somme ou la chose offerte en observant les formalités prescrites par l’Acte\nUniforme\n\nde l’Organisation pour l’Harmonisation en Afrique du Droit des Affaires\n\n(OHADA), portant organisation des procédures simplifiées de recouvrement de créances\net des voies d’exécution.","[CPCN] Article 627 : La validité de la consignation suppose :\n1)\n\nune sommation préalable indiquant le jour, l’heure, le lieu, où la chose offerte\nsera déposée ;\n\n2)\n\nle dessaisissement du débiteur remettant la chose dans le dépôt indiqué par\nla loi avec les intérêts jusqu’au jour du dépôt ;\n\n3°)\n\nla rédaction par huissier d’un procès-verbal de dépôt ;\n\n4°)\n\nen cas de non-comparution du créancier, la signification du procès-verbal de\ndépôt avec sommation de retirer la chose déposée.","[CPCN] Article 628 : La demande, soit en validité, soit en nullité des offres ou de la consignation\nest formée de la même manière que les autres demandes. Elle relève de la compétence\ndu juge saisi du principal lorsque la demande est soulevée incidemment.","[CPCN] Article 629 : Le jugement qui déclare les offres valables, ordonne, dans le cas où la\nconsignation n’aurait pas encore eu lieu, que, faute par le créancier de recevoir la somme\nou la chose offerte, elle sera consignée ; il prononce la cessation des intérêts du jour de la\nréalisation.","[CPCN] Article 630 : Les frais des offres réelles et de la consignation sont à la charge du débiteur\nsi les offres sont annulées et à la charge du créancier lorsque, refusées par lui, elles ont\nété déclarées valables. La consignation volontaire ou ordonnée, faite par le tiers saisi, est\nà la charge du créancier opposant.\n\nTITRE IV – DE LA RÉCEPTION DE CAUTION","[CPCN] Article 631 : Le jugement qui ordonne de fournir caution fixe le délai dans lequel elle sera\nprésentée et celui dans lequel elle sera acceptée ou contestée.","[CPCN] Article 632 : La caution est présentée par conclusions ; l’adversaire fait connaître par la\nmême voie s’il l’accepte ou non. S’il l’accepte ou ne fait pas connaître son refus dans le\ndélai fixé, la caution fait au greffe sa soumission qui est exécutoire sans jugement.","[CPCN] Article 633 : S’il y a contestation, l’audience est poursuivie sur un simple acte ; le\njugement sera exécuté par provision. Si la caution est admise, elle fait sa soumission au\ngreffe.\nTITRE V – DE LA REDDITION DE COMPTE","[CPCN] Article 634 : Les comptables commis par justice sont poursuivis devant les juges qui les\nont commis ; tous les autres comptables sont poursuivis devant les juges de leur domicile.\nEn cas d’appel d’un jugement qui a rejeté une demande en reddition de compte,\nl’arrêt infirmatif renvoie pour la reddition et le jugement de compte au tribunal où la\ndemande a été formée, ou retient la connaissance du compte.","[CPCN] Article 635 : Tout jugement portant condamnation de rendre compte fixe le délai dans\nlequel le compte sera rendu ; il peut commettre un juge.","[CPCN] Article 636 : Le compte contient les recettes et les dépenses ; il est terminé par la\nrécapitulation de la balance desdites recettes et dépenses, avec un chapitre particulier des\nobjets à recouvrer.","[CPCN] Article 637 : Celui qui doit rendre un compte, présente et affirme son compte en personne\nou par procureur spécial en le déposant au greffe, dans le délai fixé. Le délai passé, il y\nest contraint par saisie et vente de ses biens jusqu’à concurrence d’une somme que le\ntribunal fixe.","[CPCN] Article 638 : Le compte présenté et affirmé, si la recette excède la dépense, le\nbénéficiaire peut requérir du tribunal ou du juge-commissaire, exécutoire de cet excédent,\nsans approbation du compte.","[CPCN] Article 639 : Après présentation et affirmation, avis du dépôt est donné par le greffe à\ncelui auquel le compte est dû ou à son représentant, qui fait connaître par conclusions\nqu’il l’accepte ou non. Les pièces peuvent être communiquées sur récépissé après avoir\nété cotées et paraphées par le rendant ou son conseil.\n99","[CPCN] Article 640 : Les quittances des fournisseurs, des commerçants, des ouvriers et autres de\nmême nature, produites comme pièces justificatives sont dispensées de l’enregistrement.","[CPCN] Article 641 : Au jour fixé par le tribunal ou le juge commis, les parties débattent le compte\ndevant lui. Si les parties ne s’accordent pas, l’affaire est renvoyée à l’audience ; le jugecommissaire peut dresser un procès-verbal de ces opérations.","[CPCN] Article 642 : Le jugement qui intervient sur l’instance de compte, contient le calcul des\nrecettes et des dépenses et fixe le reliquat précis.","[CPCN] Article 643 : Il n’est procédé à la révision d’aucun compte sauf aux parties à en former la\ndemande devant les mêmes juges, s’il y a erreurs, omissions, faux ou doubles emplois.","[CPCN] Article 644 : Celui qui est condamné à restituer les fruits en rend compte dans les formes\nci-dessus et il est procédé comme sur les comptes rendus en justice.\nTITRE VI – DE LA LIQUIDATION ET DU RECOUVREMENT\nDES DÉPENS ET DES FRAIS","[CPCN] Article 645 : Les notaires, les conseils, les huissiers et les experts ne pourront poursuivre\nle paiement des frais s’appliquant aux actes de leur ministère qu’après avoir obtenu la\ntaxe et suivant les formes ci-après.","[CPCN] Article 646 : La demande de taxe pour les notaires est portée devant le président du\ntribunal de grande instance de leur résidence. La taxe sera arrêtée conformément au tarif,\ns’il s’agit d’actes qui y sont compris et s’il s’agit d’actes non tarifés, suivant la nature de\nces actes, les difficultés que leur rédaction a présentées et la responsabilité qu’ils peuvent\nentraîner.","[CPCN] Article 647 : La demande de taxe pour les conseils et les huissiers est portée devant le\nprésident de la juridiction où les frais ont été faits, ou à défaut, devant le magistrat qu’il\ndésigne. S’il s’agit de frais relatifs à une instance, le magistrat taxateur doit, à moins\nd’empêchement, avoir pris part au jugement ou à l’arrêt.","[CPCN] Article 648 : La demande de taxe pour les experts sera portée devant le président de la\njuridiction qui a ordonné la mesure d’expertise ou devant le juge chargé de son contrôle.","[CPCN] Article 649 : La taxe sera arrêtée conformément au tarif et ne s’appliquera pas, en ce qui\nconcerne les conseils, aux honoraires particuliers qui sont réglés à l’amiable sous le\ncontrôle du Conseil de l’Ordre.\n\n100","[CPCN] Article 650 : Les notaires, les conseils, les huissiers et les experts devront signifier à la\npartie débitrice soit à son conseil, s’il y a conseil constitué, soit à personne ou à domicile,\nl’état détaillé des frais taxés, et l’ordonnance du magistrat taxateur revêtue de la formule\nexécutoire. Cette signification contiendra à peine de nullité la réclamation\n\nque\n\nl’ordonnance devient définitive si elle n’est pas frappée d’appel dans les délais déterminés\nà l’article 651 ci-dessous.","[CPCN] Article 651 : Dans le mois de la signification, sauf augmentation à raison des distances,\nl’ordonnance de taxe sera susceptible d’appel tant de la partie débitrice que de la partie\nqui en est bénéficiaire. Cet appel est motivé et formé par déclaration au greffe de la\njuridiction.","[CPCN] Article 652 : Le délai imparti à l’article précédent est suspendu par le décès de l’une des\nparties ayant le droit d’appel. Il reprend son cours après une nouvelle signification aux\nhéritiers du défunt, collectivement et sans désignation de leurs nom et qualité.","[CPCN] Article 653 : Les débats ont lieu en chambre de conseil, sans procédure, le ministère\npublic entendu. L’arrêt est rendu en audience publique.","[CPCN] Article 654 : La signification de l’ordonnance de taxe, faite à la requête des notaires, des\nconseils, des huissiers et des experts, interrompt la prescription et fait courir les intérêts.\nL’ordonnance de taxe vaut titre exécutoire. Elle ne pourra être exécutée qu’après\nl’expiration du délai d’appel.","[CPCN] Article 655 : Les mêmes règles s’appliquent aux frais non liquidés par le jugement ou\nl’arrêt, réclamés par un conseil distractionnaire des dépens, contre la partie adverse\ncondamnée à les payer. Dans ce cas, le délai d’appel ne sera pas augmenté à raison des\ndistances si le jugement ou l’arrêt sur le fond est contradictoire.","[CPCN] Article 656 : L’ordonnance de taxe pourra être exécutée dès qu’elle aura été signifiée.\nL’exécution de l’ordonnance de taxe sera suspendue si la décision sur le fond est frappée\nd’opposition ou d’appel.\nTITRE VII – DE LA PROCÉDURED’EXÉQUATUR","[CPCN] Article 657 : L’exequatur des décisions contentieuses et gracieuses rendues en toutes\nmatières par les juridictions étrangères est accordé par le tribunal de grande instance du\nlieu où l’exécution doit être poursuivie. Le tribunal est saisi par requête. Il statue\ncontradictoirement.\n\nLa partie contre laquelle l’exécution est demandée est appelée à comparaître par le\ngreffier.\nLa demande est instruite suivant la procédure abrégée. Au cours de l’instance,\nchacune des parties peut invoquer, à l’appui de sa demande, les moyens, les exceptions\net les fins de non-recevoir postérieurs à la décision.","[CPCN] Article 658 : Le tribunal se borne à vérifier si la décision dont l’exequatur est demandé\nremplit les conditions requises.","[CPCN] Article 659 : L’exequatur peut être accordé partiellement pour l’un seulement, ou\nplusieurs des chefs de la décision invoquée. Le jugement d’exequatur n’a d’effet qu’entre\nles parties à l’instance ; il ne peut faire l’objet que d’un recours en cassation.","[CPCN] Article 660 : Les actes authentiques dressés en pays étrangers par les autorités\nétrangères qualifiées, sont déclarés exécutoires au Niger par ordonnance du président du\ntribunal de grande instance.\nLe président est saisi et statue suivant la forme prévue pour les référés ; il vérifie\nseulement si les actes réunissent les conditions nécessaires à leur authenticité dans l’État\noù ils ont été reçus et si les dispositions dont l’exécution est poursuivie n’ont rien de\ncontraire à l’ordre public ni aux principes de droit public applicables au Niger.","[CPCN] Article 661 : Les hypothèques terrestres conventionnelles consenties à l’étranger ne sont\ninscrites et ne produisent leur effet au Niger que lorsque les actes qui en contiennent la\nstipulation ont été rendus exécutoires par le président du tribunal du lieu de situation de\nl’immeuble.\nLes dispositions qui précèdent sont également applicables aux actes qui\ncomportent radiation ou réduction d’hypothèques passés dans l’un des deux pays.\n\nTITRE VIII – DE L’ARBITRAGE","[CPCN] Article 662 : Les dispositions relatives au présent titre sont celles contenues dans l’Acte\nUniforme de l’Organisation pour Harmonisation en Afrique du Droit des Affaires (OHADA)\nrelatif au droit de l’arbitrage.\n\nTITRE IX – DES DISPOSITIONS FINALES","[CPCN] Article 663 : La présente loi qui abroge toutes dispositions antérieures contraires est\npubliée au journal officiel de la République du Niger et exécutée comme loi de l’Etat.\nFait à Niamey, le 23 avril 2015\n\nSigné : Le Président de la République\nISSOUFOU MAHAMADOU\n\nLe Premier Ministre\nBRIGI RAFINI\nLe Ministre de la Justice Garde des\nSceaux, Porte Parole du Gouvernement\nMAROU AMADOU\n\nPour ampliation :\nLe Secrétaire Général\ndu Gouvernement\n\n103"];

function searchArticles(query, maxResults = 32) {
  const qLow = query.toLowerCase();
  const terms = qLow.split(/\s+/).filter(t => t.length > 2);
  const isProc  = /garde|arrest|détention|comparut|instruction|jugement|appel|enquête|plainte|audition|inculp|poursuit|tribunal|condamn|acquitt|mandat|parquet|procureur|avocat|défense|prévenu|accusé|victime|recours|cassation/.test(qLow);
  const isSubst = /vol|meurtre|viol|escroquerie|corruption|fraude|violence|agression|abus|bless|coups|homicide|faux|détourne|blanchiment|drogue/.test(qLow);
  const isCivil = /contrat|divorce|succession|mariage|propriété|bail|loyer|dette|créance|saisie|huissier|notaire|société|commercial|travail|licenciement/.test(qLow);

  const scored = ARTICLES.map(art => {
    const tl = art.toLowerCase();
    let score = 0;
    if (tl.includes(qLow.slice(0, 15))) score += 10;
    terms.forEach(term => {
      const stem = term.length > 5 ? term.slice(0, -2) : term;
      const esc = t => t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      score += (tl.match(new RegExp(esc(term), 'g')) || []).length * 2;
      score += (tl.match(new RegExp(esc(stem), 'g')) || []).length * 0.5;
    });
    if (isProc  && art.startsWith('[CPPN]')) score *= 1.8;
    if (isSubst && art.startsWith('[CPN]'))  score *= 1.5;
    if (isCivil && art.startsWith('[CPCN]')) score *= 2.0;
    return { art, score };
  });

  return scored.filter(x => x.score > 0).sort((a,b) => b.score - a.score).slice(0, maxResults).map(x => x.art);
}

const SYSTEM_PROMPT = `Tu es ALLO JUSTICE, assistant juridique en droit nigérien. Tu maîtrises trois codes :
- ⚖️ Code Pénal du Niger (2018) → articles [CPN]
- 📘 Code de Procédure Pénale du Niger → articles [CPPN]
- 📗 Code de Procédure Civile du Niger (Loi n° 2015-23) → articles [CPCN]

RÈGLES ABSOLUES :
1. Tu cites TOUJOURS les articles exacts disponibles dans ton contexte (Art. 2 CPN, Art. 50 CPPN, Article 12 CPCN)
2. Tu ne dis JAMAIS "consultez un avocat" si des articles pertinents sont disponibles
3. Tu qualifies toujours juridiquement les faits avec la peine précise pour le pénal, ou la procédure applicable pour le civil
4. Pour la procédure pénale → CPPN. Pour l'infraction → CPN. Pour le civil/commercial/social → CPCN
5. Si aucun article trouvé, tu le dis clairement
6. Réponse toujours en français, claire et structurée

FORMAT :
⚖️ QUALIFICATION : [nature juridique]
📋 ARTICLES APPLICABLES : [articles cités avec contenu clé]
⚡ PEINES / PROCÉDURE : [sanctions et/ou étapes]
💡 EN PRATIQUE : [explication concrète pour le justiciable nigérien]`;

const SUGGESTIONS = [
  { icon: "🚔", text: "Quels sont mes droits en cas de garde à vue au Niger ?" },
  { icon: "⚖️", text: "Quelles sont les peines pour vol avec violence ?" },
  { icon: "💼", text: "Comment déposer plainte pour escroquerie ?" },
  { icon: "🏠", text: "Quelle est la procédure pour un litige de bail ?" },
  { icon: "👨‍👩‍👧", text: "Quelles sont les règles de succession au Niger ?" },
  { icon: "📝", text: "Comment saisir un huissier pour une créance ?" },
  { icon: "🛡️", text: "Quelles sont les conditions de la légitime défense ?" },
  { icon: "🏛️", text: "Comment fonctionne l'action civile devant le tribunal ?" },
];

// TEST : accès direct sans code d'abonnement (endpoints Supabase désactivés le temps des tests).
// Repasser à false pour réactiver la porte d'abonnement (/api/abonnement).
const BYPASS_ABONNEMENT = true;

export default function App() {
  const [abonne, setAbonne] = useState(BYPASS_ABONNEMENT ? { code: 'TEST', questions: 9999 } : null);
  const [codeInput, setCodeInput] = useState('');
  const [codeLoading, setCodeLoading] = useState(false);
  const [codeError, setCodeError] = useState('');
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [stats, setStats] = useState(null);
  const [uploadedDoc, setUploadedDoc] = useState(null);
  const [uploadLoading, setUploadLoading] = useState(false);
  const bottomRef = useRef(null);
  const fileRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, loading]);

  useEffect(() => {
    if (messages.length > 0) {
      window.history.pushState(null, '', window.location.href);
    }
    const handlePop = () => {
      if (messages.length > 0) setMessages([]);
    };
    window.addEventListener('popstate', handlePop);
    return () => window.removeEventListener('popstate', handlePop);
  }, [messages]);

  async function handleFile(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadLoading(true);
    setUploadedDoc(null);
    try {
      const reader = new FileReader();
      reader.onload = async (ev) => {
        const base64 = ev.target.result.split(',')[1];
        setUploadedDoc({ name: file.name, base64 });
        setUploadLoading(false);
      };
      reader.readAsDataURL(file);
    } catch(err) {
      setError("Erreur lecture document : " + err.message);
      setUploadLoading(false);
    }
  }

  async function sendMessage() {
    const text = input.trim();
    if (!text || loading) return;

    const userMsg = { role: "user", content: text };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);
    setError(null);

    try {
      const relevant = searchArticles(text, 32);
      const cpnFound  = relevant.filter(a => a.startsWith('[CPN]')).length;
      const cppnFound = relevant.filter(a => a.startsWith('[CPPN]')).length;
      const cpcnFound = relevant.filter(a => a.startsWith('[CPCN]')).length;
      setStats({ cpn: cpnFound, cppn: cppnFound, cpcn: cpcnFound });

      let context = "\n\n=== ARTICLES APPLICABLES ===\n";
      const cppnArts = relevant.filter(a => a.startsWith('[CPPN]'));
      const cpnArts  = relevant.filter(a => a.startsWith('[CPN]'));
      const cpcnArts = relevant.filter(a => a.startsWith('[CPCN]'));
      if (cppnArts.length) context += "\n📘 CODE DE PROCÉDURE PÉNALE :\n" + cppnArts.join("\n\n");
      if (cpnArts.length)  context += "\n\n⚖️ CODE PÉNAL :\n" + cpnArts.join("\n\n");
      if (cpcnArts.length) context += "\n\n📗 CODE DE PROCÉDURE CIVILE :\n" + cpcnArts.join("\n\n");
      if (!relevant.length) context += "\n[Aucun article trouvé dans les codes locaux.]";

      const apiMessages = newMessages.map(m => ({ role: m.role, content: m.content }));

      const response = await fetch("/api/anthropic", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ system: SYSTEM_PROMPT + context, messages: apiMessages }),
      });

      const data = await response.json();
      if (data.error) throw new Error(data.error.message || JSON.stringify(data.error));

      const reply = data.content?.map(b => b.text || "").join("\n") || "";
      setMessages(prev => [...prev, { role: "assistant", content: reply }]);
      if (uploadedDoc) setUploadedDoc(null);

      if (!BYPASS_ABONNEMENT) {
        fetch('/api/abonnement', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'decrementer', code: abonne.code}) });
        setAbonne(prev => ({ ...prev, questions: prev.questions - 1 }));
      }
    } catch (err) {
      setError("⚠️ Le volume de demandes a dépassé nos prévisions journalières. Allô Justice sera de nouveau disponible dans quelques minutes. Merci de votre confiance !");
    } finally {
      setLoading(false);
    }
  }

  function handleKey(e) {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  }

  const gold = "#b8962e"; const blue = "#4a80c0"; const green = "#60c890";

  if (!abonne) {
    return (
      <div style={{ minHeight:"100vh", background:"#0b1929", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", fontFamily:"Georgia,serif", padding:"20px" }}>
        <div style={{ fontSize:40, marginBottom:16 }}>⚖️</div>
        <div style={{ fontSize:20, fontWeight:"bold", color:"#b8962e", marginBottom:8, letterSpacing:1 }}>ALLÔ JUSTICE</div>
        <div style={{ fontSize:12, color:"#7a9abf", marginBottom:24, textAlign:"center" }}>Assistant Juridique — Entrez votre code d'accès</div>
        <input value={codeInput} onChange={e=>setCodeInput(e.target.value.toUpperCase())} placeholder="Ex: JUST-2025-ABC123" style={{ background:"rgba(17,34,64,.6)", border:"1px solid rgba(184,150,46,.3)", borderRadius:10, padding:"12px 16px", color:"#e0d4bc", fontSize:14, width:"100%", maxWidth:320, outline:"none", marginBottom:12, fontFamily:"Georgia,serif", textAlign:"center" }} />
        {codeError && <div style={{ color:"#ff7070", fontSize:12, marginBottom:10, textAlign:"center", maxWidth:320 }}>{codeError}</div>}
        <button onClick={async()=>{
          setCodeLoading(true); setCodeError('');
          try {
            const r = await fetch('/api/abonnement', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'verifier', code:codeInput}) });
            const d = await r.json();
            if (d.valide) { setAbonne({code:codeInput, questions:d.questions_restantes}); }
            else { setCodeError(d.message || 'Code invalide'); }
          } catch(e) { setCodeError('Erreur de connexion'); }
          setCodeLoading(false);
        }} disabled={!codeInput || codeLoading} style={{ background:!codeInput||codeLoading?"rgba(80,80,80,.3)":"linear-gradient(135deg,#b8962e,#e8c84a)", border:"none", borderRadius:12, padding:"12px 32px", color:"#0b1929", fontWeight:"bold", fontSize:14, cursor:!codeInput||codeLoading?"not-allowed":"pointer" }}>
          {codeLoading ? "Vérification..." : "Accéder à Allô Justice"}
        </button>
        <div style={{ marginTop:24, fontSize:11, color:"#506070", textAlign:"center" }}>
          <div>Pour obtenir un code d'accès, déposez sur :</div>
          <div style={{ color:"#b8962e", marginTop:6, fontWeight:"bold" }}>+227 86 99 71 42</div>
          <div style={{ color:"#7a9abf", marginTop:2 }}>NITA ou AMANA</div>
          <div style={{ color:"#7a9abf", marginTop:4 }}>2 000 FCFA / 30 questions / 30 jours</div>
          <div style={{ color:"#506070", marginTop:8 }}>Envoyez la preuve de dépôt par WhatsApp ou email pour recevoir votre code</div>
          <div style={{ color:"#7a9abf", marginTop:2 }}>✉️ missessin229@gmail.com</div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight:"100vh", background:"#0b1929", display:"flex", flexDirection:"column", fontFamily:"Georgia,serif", color:"#e0d4bc" }}>

      <div style={{ background:"linear-gradient(180deg,#112240,#0d1b33)", borderBottom:`2px solid ${gold}`, padding:"13px 16px 11px", position:"sticky", top:0, zIndex:10, boxShadow:"0 4px 24px rgba(0,0,0,.6)" }}>
        <div style={{ display:"flex", alignItems:"center", gap:11 }}>
          <div style={{ width:42, height:42, background:`linear-gradient(135deg,${gold},#e8c84a)`, borderRadius:"50%", display:"flex", alignItems:"center", justifyContent:"center", fontSize:20, flexShrink:0, boxShadow:`0 2px 12px rgba(184,150,46,.4)` }}>⚖️</div>
          <div>
            <div style={{ fontSize:16, fontWeight:"bold", color:"#f0e4c8", letterSpacing:1.5 }}>ALLÔ JUSTICE</div>
            <div style={{ fontSize:9, color:"#7a9abf", letterSpacing:1, marginTop:1 }}>ASSISTANT JURIDIQUE · {abonne.questions} question{abonne.questions>1?'s':''} restante{abonne.questions>1?'s':''}</div>
          </div>
          <div style={{ marginLeft:"auto", display:"flex", flexDirection:"column", alignItems:"flex-end", gap:4 }}>
            <div style={{ display:"flex", gap:4 }}>
              {[["⚖️","CPN",gold,"rgba(184,150,46,.15)","rgba(184,150,46,.3)"],
                ["📘","CPPN",blue,"rgba(100,160,255,.1)","rgba(100,160,255,.25)"],
                ["📗","CPCN",green,"rgba(80,200,120,.1)","rgba(80,200,120,.25)"]
              ].map(([ic,lb,cl,bg,br])=>(
                <div key={lb} style={{ background:bg, border:`1px solid ${br}`, borderRadius:5, padding:"2px 6px", fontSize:8, color:cl }}>{ic} {lb}</div>
              ))}
            </div>
            {messages.length > 0 && (
              <button onClick={() => setMessages([])} style={{ background:"rgba(184,150,46,.2)", border:"1px solid rgba(184,150,46,.4)", borderRadius:8, padding:"4px 10px", fontSize:9, color:gold, cursor:"pointer", marginTop:4, letterSpacing:.5 }}>
                🏠 Accueil
              </button>
            )}
          </div>
        </div>
      </div>

      <div style={{ flex:1, overflowY:"auto", padding:"16px 14px", display:"flex", flexDirection:"column", gap:14 }}>

        {messages.length === 0 && (
          <div>
            <div style={{ background:"linear-gradient(135deg,rgba(184,150,46,.07),rgba(80,200,120,.05))", border:`1px solid rgba(184,150,46,.2)`, borderRadius:16, padding:"20px 16px", marginBottom:16, textAlign:"center" }}>
              <div style={{ fontSize:36, marginBottom:10 }}>⚖️</div>
              <div style={{ fontSize:15, fontWeight:"bold", color:"#c9a840", marginBottom:7, letterSpacing:1 }}>ALLÔ JUSTICE</div>
              <div style={{ fontSize:12, color:"#8aabcc", lineHeight:1.9 }}>
                Assistant juridique en droit pénal et civil nigérien. Je cite les articles exacts et analyse vos documents.
              </div>
              <div style={{ display:"flex", gap:6, justifyContent:"center", marginTop:12, flexWrap:"wrap" }}>
                {[["⚖️","Code Pénal","518 art.",gold,"rgba(184,150,46,.12)","rgba(184,150,46,.25)"],
                  ["📘","Proc. Pénale","907 art.",blue,"rgba(100,160,255,.08)","rgba(100,160,255,.2)"],
                  ["📗","Proc. Civile","663 art.",green,"rgba(80,200,120,.08)","rgba(80,200,120,.2)"]
                ].map(([ic,nm,ct,cl,bg,br])=>(
                  <div key={nm} style={{ background:bg, border:`1px solid ${br}`, borderRadius:8, padding:"4px 9px", fontSize:9, color:cl }}>{ic} {nm} · {ct}</div>
                ))}
              </div>
            </div>
            <div style={{ fontSize:10, color:gold, letterSpacing:2, textTransform:"uppercase", marginBottom:9, textAlign:"center" }}>Questions fréquentes</div>
            <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
              {SUGGESTIONS.map((s,i)=>(
                <button key={i} onClick={()=>setInput(s.text)} style={{ background:"rgba(17,34,64,.7)", border:"1px solid rgba(184,150,46,.15)", borderRadius:10, padding:"9px 12px", color:"#c8bca0", fontSize:12, textAlign:"left", cursor:"pointer", display:"flex", gap:8, alignItems:"flex-start", lineHeight:1.4 }}>
                  <span style={{ fontSize:14, flexShrink:0 }}>{s.icon}</span><span>{s.text}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg,i)=>(
          <div key={i} style={{ display:"flex", flexDirection:"column", alignItems: msg.role==="user"?"flex-end":"flex-start" }}>
            {msg.role==="assistant" && <div style={{ fontSize:9, color:gold, letterSpacing:1.5, marginBottom:4, paddingLeft:4 }}>⚖️ ALLÔ JUSTICE</div>}
            <div style={{ maxWidth:"93%", background: msg.role==="user"?"linear-gradient(135deg,#1a3a6e,#1e4a8a)":"rgba(17,34,64,.85)", border: msg.role==="user"?"1px solid rgba(100,160,255,.25)":`1px solid rgba(184,150,46,.22)`, borderRadius: msg.role==="user"?"16px 16px 4px 16px":"4px 16px 16px 16px", padding:"12px 14px", boxShadow:"0 2px 16px rgba(0,0,0,.35)" }}>
              <div style={{ fontSize:13, lineHeight:1.8, color: msg.role==="user"?"#dce8ff":"#d8ccb4", whiteSpace:"pre-wrap" }}>{msg.content}</div>
            </div>
          </div>
        ))}

        {loading && (
          <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-start" }}>
            <div style={{ fontSize:9, color:gold, letterSpacing:1.5, marginBottom:4, paddingLeft:4 }}>⚖️ ALLÔ JUSTICE ANALYSE...</div>
            <div style={{ background:"rgba(17,34,64,.85)", border:`1px solid rgba(184,150,46,.22)`, borderRadius:"4px 16px 16px 16px", padding:"13px 16px" }}>
              <div style={{ display:"flex", gap:5, alignItems:"center", marginBottom:5 }}>
                {[gold,blue,green,"#a0a0ff"].map((c,n)=>(
                  <div key={n} style={{ width:7, height:7, borderRadius:"50%", background:c, animation:"bounce 1.4s ease-in-out infinite", animationDelay:`${n*.2}s` }} />
                ))}
                <span style={{ fontSize:10, color:"#7a9abf", marginLeft:6 }}>Allô Justice analyse votre situation juridique, veuillez patienter...</span>
              </div>
            </div>
          </div>
        )}

        {error && <div style={{ background:"rgba(160,30,30,.2)", border:"1px solid rgba(255,80,80,.25)", borderRadius:10, padding:"10px 14px", color:"#ff7070", fontSize:12 }}>{error}</div>}
        <div ref={bottomRef} />
      </div>

      {(uploadedDoc || uploadLoading) && (
        <div style={{ background:"rgba(96,200,144,.1)", borderTop:`1px solid rgba(96,200,144,.25)`, padding:"8px 14px", display:"flex", alignItems:"center", gap:8 }}>
          {uploadLoading
            ? <span style={{ fontSize:11, color:green }}>⏳ Lecture du document en cours...</span>
            : <>
                <span style={{ fontSize:14 }}>📄</span>
                <span style={{ fontSize:11, color:green, flex:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{uploadedDoc.name} — prêt à analyser</span>
                <button onClick={()=>setUploadedDoc(null)} style={{ background:"none", border:"none", color:"#ff7070", fontSize:14, cursor:"pointer" }}>✕</button>
              </>
          }
        </div>
      )}

      <div style={{ background:"rgba(8,18,32,.97)", borderTop:`1px solid rgba(184,150,46,.2)`, padding:"10px 14px", paddingBottom:"max(10px,env(safe-area-inset-bottom))" }}>
        <div style={{ display:"flex", gap:8, alignItems:"flex-end" }}>
          <button onClick={()=>fileRef.current?.click()} disabled={uploadLoading} style={{ background:"rgba(17,34,64,.8)", border:`1px solid rgba(96,200,144,.3)`, borderRadius:12, width:46, height:46, cursor:"pointer", fontSize:18, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center", color:green }}>
            📎
          </button>
          <input ref={fileRef} type="file" accept=".pdf" onChange={handleFile} style={{ display:"none" }} />

          <textarea
            value={input} onChange={e=>setInput(e.target.value)} onKeyDown={handleKey}
            placeholder="Décrivez votre situation juridique..." rows={2}
            style={{ flex:1, background:"rgba(17,34,64,.6)", border:`1px solid rgba(184,150,46,.25)`, borderRadius:12, padding:"10px 13px", color:"#e0d4bc", fontSize:13, fontFamily:"Georgia,serif", resize:"none", outline:"none", lineHeight:1.5 }}
          />
          <button onClick={sendMessage} disabled={loading||!input.trim()} style={{ background:loading||!input.trim()?"rgba(80,80,80,.3)":`linear-gradient(135deg,${gold},#e8c84a)`, border:"none", borderRadius:12, width:46, height:46, cursor:loading||!input.trim()?"not-allowed":"pointer", fontSize:19, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center", transition:"all .2s" }}>
            {loading?"⏳":"➤"}
          </button>
        </div>
        <div style={{ display:"flex", gap:8, justifyContent:"center", marginTop:7, flexWrap:"wrap" }}>
          {[["⚖️","CPN",gold],["📘","CPPN",blue],["📗","CPCN",green]].map(([ic,lb,cl])=>(
            <span key={lb} style={{ fontSize:9, color:cl, opacity:.6 }}>{ic} {lb}</span>
          ))}
          <span style={{ fontSize:9, color:"#4a6080", opacity:.6 }}>· 📎 PDF</span>
        </div>
      </div>

      <div style={{ background:"rgba(8,18,32,.97)", borderTop:"1px solid rgba(184,150,46,.15)", padding:"12px 16px", textAlign:"center" }}>
        <div style={{ fontSize:10, color:"#b8962e", marginBottom:4, letterSpacing:1 }}>DÉVELOPPÉ PAR DONA VIGAN</div>
        <div style={{ fontSize:10, color:"#7a9abf" }}>📞 WhatsApp : (229) 01 96 04 98 00</div>
        <div style={{ fontSize:10, color:"#7a9abf" }}>✉️ missessin229@gmail.com</div>
      </div>

      <style>{`
        @keyframes bounce{0%,80%,100%{transform:translateY(0);opacity:.5}40%{transform:translateY(-6px);opacity:1}}
        textarea:focus{border-color:rgba(184,150,46,.5)!important}
        button:hover:not(:disabled){transform:scale(1.05)}
        *{box-sizing:border-box}
        ::-webkit-scrollbar{width:3px}
        ::-webkit-scrollbar-thumb{background:rgba(184,150,46,.3);border-radius:2px}
      `}</style>
    </div>
  );
}
